window.ASBAB_NUZUL_CACHE["2"] = {"asbab_nuzul":{"89":[{"ar":"عن ابن عباس رضي الله عنهما قال: (إن اليهود كانوا يستفتحون على الأوس والخزرج برسول الله ﷺ قبل مبعثه، فلما بعثه الله من العرب كفروا به، وجحدوا ما كانوا يقولون فيه.\n\nفقال لهم معاذ بن جبل، وبشر بن المعرور: يا معشر اليهود، اتقوا الله وأسلموا، فقد كنتم تستفتحون علينا بمحمد ﷺ ونحن أهل شرك، وتخبروننا أنه مبعوث، وتصفونه لنا بصفته.\n\nفقال سلام بن مشكم: ما جاءنا بشيء نعرفه، وما هو بالذي كنا نذكر لكم). فأنزل الله هذه الآية.","id":""},{"ar":"ومن حديث عاصم بن عمر بن قتادة عن رجال من قومه قالوا: (إن مما دعانا إلى الإسلام، مَعَ رحمة الله تعالى وهُداهُ لنا، لما كنا نسمع من رجال يهود، وكنا أهلَ شِرك وأوثان، وكانوا أهل كتاب، عندهم علمٌ ليس لنا، وكانت لا تزال بيننا وبينهم شرور، فإذا نلنا منهم بعض ما يكرهون، قالوا لنا: إنه قد تقارب زمانُ نبيٍ يُب��ثُ الآن نقتلكم معه قَتْلَ عادٍ وإرِم. فكنا كثيراً ما نسمع ذلكَ منهم، فلما بَعثَ الله رسوله ﷺ أجبناه، حين دعانا إلى الله تعالى وعرفنا ما كانوا يتوعدوننا به، فبادرناهم إليه، فآمنا به وكفروا به، ففينا وفيهم نَزل هؤلاء الآيات من البقرة: { وَلَمَّا جَآءَهُمْ كِتَـٰبٌ مِّنْ عِندِ ٱللَّهِ مُصَدِّقٌ لِّمَا مَعَهُمْ وَكَانُوا۟ مِن قَبْلُ يَسْتَفْتِحُونَ عَلَى ٱلَّذِينَ كَفَرُوا۟ فَلَمَّا جَآءَهُم مَّا عَرَفُوا۟ كَفَرُوا۟ بِهِۦ ۚ فَلَعْنَةُ ٱللَّهِ عَلَى ٱلْكَـٰفِرِينَ ﴿٨٩﴾ }.","id":""}],"97":[{"ar":"عن ابْنِ عَبَّاسٍ رضي الله عنهما ما قال: حَضَرَتْ عِصَابَةٌ مِنَ الْيَهُودِ نَبِيَّ اللهِ ﷺ يَوْماً، فَقَالُوا: يَا أَبَا القَاسِمِ، حَدِّثْنَا عَنْ خِلَالٍ نَسْأَلُكَ عَنْهُنَّ لَا يَعْلَمُهُنَّ إِلَّا نَبِيٌّ.\nقَالَ: سَلُونِي عَمَّا شِئْتُمْ، وَلَكِنِ اجْعَلُوا لِي ذِمَّةَ اللهِ، وَمَا أَخَذَ يَعْقُوبُ عليه السلام عَلَى بَنِيهِ: لَئِنْ حَدَّثْتُكُمْ شَيْئاً فَعَرَفْتُمُوهُ، لَتُتَابِعُنِّي عَلَى الْإِسْلَامِ.\nقَالُوا: فَذَلِكَ لَكَ، قَالَ: فَسَلُونِي عَمَّا شِئْتُم.\nقَالُوا: أَخبِرْنَا عَنْ أَرْبَعِ خِلَالٍ نَسْأَلُكَ عَنْهُنَّ: أَخْبِرْنَا أَيُّ الطَّعَامِ حَرَّمَ إِسْرَائِيلُ عَلَى نَفْسِهِ مِنْ قَبْلِ أَن تُنَزَّلَ التَّوْرَاةُ! وَأَخْبِرْنَا كَيْفَ مَاءُ الْمَرْأَةِ، وَمَاءُ الرَّجُلِ، كَيْفَ يَكُونُ الذَّكَرُ مِنْهُ وَأَخْبِرْنَا كَيْفَ هَذَا النَّبِيُّ الْأُمِّيُّ فِي النَّوْمِ؟ وَمَنْ وَلِيُّهُ مِنَ الْمَلَائِكَةِ؟.\nقَالَ: فَعَلَيْكُمْ عَهْدُ اللهِ وَمِيثَاقُهُ لَئِنْ أَنَا أَخْبَرْتُكُمْ لَتُتَابِعُنِّي ؟ قَالَ: فَأَعْطَوْهُ مَا شَاءَ مِنْ عَهْدٍ وَمِيثَاقِ. قَالَ: فَأَنْشُدُكُمْ بِالَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى هَلْ تَعْلَمُونَ أَنَّ إِسْرَائِيلَ يَعْقُوبَ عليه السلام، مَرِضَ مَرَضاً شَدِيداً، وَطَالَ سَقَمُهُ، فَنَذَرَ للَّهِ نَذْراً لَئِنْ شَفَاهُ اللَُّه تَعَالَى مِنْ سَقَمِهِ، لَيُحَرِّمَنَّ أَحَبَّ الشَّرَابِ إِلَيْهِ، وَأَحَبَّ الطَّعَام إِلَيْهِ، وَكَانَ أَحَبَّ الطَّعَامِ إِلَيْهِ لُحْمَانُ الْإِبِلِ، وَأَحَبَّ الشَّرَابِ إِلَيْهِ أَلْبَانُهَا؟ قَالُوا: اللَّهُمَّ نَعَمْ.\n قَالَ: اللَّهُمَّ اشْهَدْ عَلَيْهِمْ، فَأَنْشُدُكُمْ بِاللّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى، هَلْ تَعْلَمُونَ أَنَّ مَاءَ الرَّجُلِ أَبْيَضُ غَلِيظٌ، وَأَنَّ مَاءَ الْمَرْأَةِ أَصْفَرُ رَقِيقٌ، فَأَيُّهُمَا عَلَا كَانَ لَهُ الْوَلَدُ وَالشَّبَهُ بِإِذْنِ اللهِ، إِنْ عَلَا مَاءً الرَّجُلِ عَلَى مَاءِ الْمَرْأَةِ كَانَ ذَكَراً بِإِذْنِ اللهِ، وَإِنْ عَلَا مَاءُ الْمَرْأَةِ عَلَى مَاءِ الرَّجُلِ كَانَ أُنثَى بِإِذْنِ اللهِ ؟ قَالُوا: اللَّهُمَّ نَعَمْ.\nقَالَ: اللَّهُمَّ اشْهَدْ عَلَيْهِمْ، فَأَنْشُدُكُمْ بِالَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى هَلْ تَعْلَمُونَ أَنَّ هَذَا النَّبِيَّ الْأُمِّيَّ تَنَامُ عَيْنَاهُ وَلَا يَنَامُ قَلْبُهُ؟ قَالُوا: اللَّهُمَّ: نَعَمْ.\nقَالَ: اللَّهُمَّ اشْهَدَ.\nقَالُوا: وَأَنْتَ الْآنَ فَحَدِّثْنَا: مَنْ وَلِيُّكَ مِنَ المَلَائِكَةِ؟ فَعِنْدَهَا نُجَامِعُكَ أَوْ نُفَارِقُكَ.\nقَالَ: فَإِن وَلِيْيَ جِبْرِيلُ عليه السلام، وَلَمْ يَبْعَثِ اللَّهُ نَبِيًّا قَطُّ إِلَّا وَهُوَ وَلِيُّهُ.\nقَالُوا: فَعِنْدَهَا نُفَارِ��ُكَ، لَوْ كَانَ وَلِيكَ سِوَاهُ مِنَ الْمَلَائِكَةِ لَتَابَعْنَاكَ وَصَدَّقْنَاكَ. قَالَ: فَمَا يَمْنَعُكُمْ مِنْ أَنْ تُصَدِّقُوهُ؟ قَالُوا: إِنَّهُ عَدُونَا !\nقَالَ: فَعِنْدَ ذَلِكَ قَالَ اللهُ عز و جل: { قُلْ مَن كَانَ عَدُوًّا لِّجِبْرِيلَ فَإِنَّهُۥ نَزَّلَهُۥ عَلَىٰ قَلْبِكَ بِإِذْنِ ٱللَّهِ } إِلَى قَوْلِهِ عز و جل { كِتَـٰبَ ٱللَّهِ وَرَآءَ ظُهُورِهِمْ كَأَنَّهُمْ لَا يَعْلَمُونَ } فَعِنْدَ ذَلِكَ { فَبَآءُو بِغَضَبٍ عَلَىٰ غَضَبٍ ۚ }الآية، [البقرة: ٩٠].","id":""}],"104":[{"ar":"عن عطاء بن أبي رباح رحمه الله تعالى في قوله تعالى: { لَا تَقُولُوا۟ رَٰعِنَا } قال: كانت لغة في الأنصار في الجاهلية، فنزلت هذه الآية: { لَا تَقُولُوا۟ رَٰعِنَا وَقُولُوا۟ ٱنظُرْنَا... } إلى آخر الآية.","id":""}],"113":[{"ar":"عن ابن عباس رضي الله عنهما قال: لما قدم أهل نجران من النصاري على رسول الله ﷺ، أتتهم أحبار یهود، فتنازعوا عند رسول الله ﷺ، فقال رافع بن حُريملة: ما أنتم على شيء! وكفر بعيسى ابن مريم وبالإنجيل.\n فقال رجل من أهل نجران من النصارى ما أنتم على شيء! وجحد نبوة موسى، وكفر بالتوراة.\n فأنزل الله لك في ذلك من قولهما: { وَقَالَتِ ٱلْيَهُودُ لَيْسَتِ ٱلنَّصَٰرَىٰ عَلَىٰ شَىْءٍ وَقَالَتِ ٱلنَّصَٰرَىٰ لَيْسَتِ ٱلْيَهُودُ عَلَىٰ شَىْءٍ } إلى قوله: { فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ }.","id":""}],"115":[{"ar":"عن جابر بن عبد الله رضي الله عنهما قال: بعث رسول الله ﷺ، سرية كنت فيها، فأصابتنا ظلمة فلم نعرف القبلة.\nفقالت طائفة منا: قد عرفنا القبلة هي ها هنا قبل الشمال، فصلوا وخطوا خطوطاً، وقال بعضنا: القبلة ها هنا قبل الجنوب، وخطوا خطوطاً. ��لما أصبحوا وطلعت الشمس، أصبحت تلك الخطوط لغير القبلة.\n فلما قفلنا من سفرنا سألنا النبي عن ذلك، فسكت، وأنزل الله عز و جل: { وَلِلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ فَأَيْنَمَا تُوَلُّوا۟ فَثَمَّ وَجْهُ } أي حيث كنتم.","id":""}],"125":[{"ar":"عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه قَالَ: قَالَ عُمَرُ بْنُ الْخَطَّابِ رضي الله عنه: وَافَقْتُ رَبِّي فِي ثَلَاثٍ، فَقُلْتُ: يَا رَسُولَ اللهِ، لَوِ اتَّخَذْنَا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلَّى، فَنَزَلَتْ { وَٱتَّخِذُوا۟ مِن مَّقَامِ إِبْرَٰهِـۧمَ مُصَلًّى ۖ }، وَآيَةُ الْحِجَابِ، قُلْتُ: يَا رَسُولَ اللهِ لَوْ أَمَرْتَ نِسَاءَكَ أَنْ يَحْتَجِبْنَ فَإِنَّهُ يُكَلِّمُهُنَّ الْبَرُّ وَالْفَاجِرُ، فَنَزَلَتْ آيَةُ الْحِجَابِ، وَاجْتَمَعَ نِسَاءُ النَّبِيِّ ﷺ فِي الْغَيْرَةِ ��َلَيْهِ، فَقُلْتُ لَهُنَّ: { عَسَىٰ رَبُّهُۥٓ إِن طَلَّقَكُنَّ أَن يُبْدِلَهُۥٓ أَزْوَٰجًا خَيْرًا مِّنكُنَّ } [التحريم: ٥] فَنَزَلَتْ هَذِهِ الآية.","id":""},{"ar":"عن أنس بن مالك رضي الله عنه قال: قال عمر بن الخطاب رضي الله عنه: ( وافقني ربي في ثلاث أو وافقت ربي في ثلاث قلت: يا رسول الله لو اتخذت من مقام إبراهيم مصلى، فنزلت { وَٱتَّخِذُوا۟ مِن مَّقَامِ إِبْرَٰهِـۧمَ مُصَلًّى ۖ }، وقلت: يا رسول الله لو حجبت النساء، فنزلت آية الحجاب، والثالثة لما مات عبد الله بن أُبَيِّ جاء رسول الله ﷺ ليصلي عليه، قلت: يا رسول الله تصلي على هذا الكافر المنافق. فقال: أيها عنك يا ابن الخطاب.\nفنزلت { وَلَا تُصَلِّ عَلَىٰٓ أَحَدٍ مِّنْهُم مَّاتَ أَبَدًا وَلَا تَقُمْ عَلَىٰ قَبْرِهِۦٓ ۖ } [التوبة: ٨٤].","id":""}],"135":[{"ar":"عن ابن عباس رضي الله عنهما قال: قال عبد الله بن صوريا الأعور لرسول الله ﷺ: ما الهدى إلا ما نحن عليه، فاتبعنا يا محمد تهتد. وقالت النصارى مثل ذلك، فأنزل الله عز و جل { وَقَالُوا۟ كُونُوا۟ هُودًا أَوْ نَصَـٰرَىٰ تَهْتَدُوا۟ ۗ }.","id":""}],"142":[{"ar":"جاء من حديث البَرَاءِ بْنِ عَازِبٍ رضي الله عنهما، قَالَ:\n( كَانَ رَسُولُ اللهِ ﷺ صَلَّى نَحْوَ بَيْتِ المَقْدِسِ سِتَّةَ عَشَرَ أَوْ سَبْعَةَ عَشَرَ شَهْراً، وَكَانَ رَسُولُ اللهِ ﷺ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الكَعْبَةِ، فَأَنْزَلَ اللهُ { قَدْ نَرَىٰ تَقَلُّبَ وَجْهِكَ فِى ٱلسَّمَآءِ ۖ }، فَتَوَجَّهَ نَحْوَ الكَعْبَةِ، وَقَالَ السُّفَهَاءُ مِنَ النَّاسِ وَهُمُ اليَهُودُ: { مَا وَلَّىٰهُمْ عَن قِبْلَتِهِمُ ٱلَّتِى كَانُوا۟ عَلَيْهَا ۚ قُل لِّلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ }، فَصَلَّى مَعَ النَّبِيِّ ﷺ رَجُلٌ ثُمَّ خَرَجَ بَعْدَمَا صَلَّى، فَمَرَّ عَلَى قَوْمٍ مِنَ الأَنْصَارِ فِي صَلَاةِ العَصْرِ نَحْوَ بَيْتِ الْمَقْدِسِ، فَقَالَ: هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ رَسُولِ اللهِ ﷺ وَأَنَّهُ تَوَجَّهَ نَحْوَ الكَعْبَةِ، فَتَحَرَّفَ القَوْمُ حَتَّى تَوَجَّهُوا نَحْوَ الكَعْبَةِ ).","id":""},{"ar":"عن البراء بن عازب رضي الله عنهما قال: أن النبي ﷺ كان أول ما قدم المدينة نزل على أجداده أو قال أخواله من الأنصار، وأنه صلى قِبَلَ بيت المقدس ستة عشر شهراً أو سبعة عشر شهراً، وكان يعجبه أن تكون قبلته قبل البيت، وأنه صلى أول صلاة صلاها صلاة العصر، وصلى معه قوم، فخرج رجل ممن صلى معه فمر على أهل مسجد وهم راكعون، فقال: أشهد باللَّه  لقد صليت مع رسول الله ﷺ قبل مكة، فداروا كما هم قبل البيت.\nوكانت اليهود قد أعجبهم إذ كان يص��ي قبل بيت المقدس، وأهل الكتاب، فلما ولى وجهه قبل البيت أنكروا ذلك.\nقال زهير: حدثنا أبو إسحاق، عن البراء في حديثه هذا: أنه مات على القبلة قبل أن تحوَّل رجال وقتلوا, فلم ندر ما نقول فيهم، فأنزل الله تعالى: { وَمَا كَانَ ٱللَّهُ لِيُضِيعَ إِيمَـٰنَكُمْ ۚ }.","id":""},{"ar":"وقال علي بن أبي طلحة عن ابن عباس رضي الله عنهما: ( أن رسول الله ﷺ لما هاجر إلى المدينة، أمره الله أن يستقبل بيت المقدس، ففرحت اليهود، فاستقبلها رسول الله ﷺ بضعة عشر شهراً، وكان رسول الله ﷺ يحب قبلة إبراهيم، فكان يدعو الله وينظر إلى السماء فأنزل الله: { فَوَلُّوا۟ وُجُوهَكُمْ شَطْرَهُۥ ۗ } أي نحوه، فارتاب من ذلك اليهود، وقالوا: ما ولاهم عن قبلتهم التي كانوا عليها ؟ فأنزل الله: { قُل لِّلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ }.","id":""}],"143":[{"ar":"۱۳ - عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: لَمَّا حُرِّمَتْ الْخَمْرُ قَالَ أُنَاسُ: يَا رَسُولَ اللهِ، أَصْحَابُنَا الَّذِينَ مَاتُوا وَهُمْ يَشْرَبُونَهَا، فَأُنْزِلَتْ { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جُنَاحٌ فِيمَا طَعِمُوٓا۟ }، قَالَ: وَلَمَّا حُوِّلَتْ الْقِبْلَةُ، قَالَ أُنَاسٌ: يَا رَسُولَ اللهِ أَصْحَابُنَا الَّذِينَ مَاتُوا وَهُمْ يُصَلُّونَ إِلَى بَيْتِ الْمَقْدِسِ، فَأُنْزِلَتْ { وَمَا كَانَ ٱللَّهُ لِيُضِيعَ إِيمَـٰنَكُمْ ۚ }.","id":""}],"144":[{"ar":"جاء من حديث الْبَرَاءِ بْنِ عَازِبٍ رضي الله عنهما، قَالَ:\n( كَانَ رَسُولُ اللهِ ﷺ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ أَوْ سَبْعَةَ عَشَرَ شَهْراً، وَكَانَ رَسُولُ اللهِ ﷺ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ، فَأَنْزَلَ اللَّهُ { قَدْ نَرَىٰ تَقَلُّبَ وَجْهِكَ فِى ٱلسَّمَآءِ ۖ }، فَتَوَجَّهَ نَحْوَ الْكَعْبَةِ، وَقَالَ السُّفَهَاءُ مِنَ النَّاسِ وَهُم الْيَهُودُ: { مَا وَلَّىٰهُمْ عَن قِبْلَتِهِمُ ٱلَّتِى كَانُوا۟ عَلَيْهَا ۚ قُل لِّلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ }، فَصَلَّى مَعَ النَّبِيِّ ﷺ رَجُلٌ ثُمَّ خَرَجَ بَعْدَ مَا صَلَّى، فَمَرَّ عَلَى قَوْمٍ مِنَ الْأَنْصَارِ فِي صَلَاةِ الْعَصْرِ نَحْوَ بَيْتِ الْمَقْدِسِ، فَقَالَ: هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ رَسُولِ اللهِ ﷺ وَأَنَّهُ تَوجَّهَ نَحْوَ الْكَعْبَةِ، فَتَحَرَّفَ الْقَوْمُ حَتَّى تَوَجَّهُوا نَحْوَ الْكَعْبَةِ ).","id":""},{"ar":"عَنْ أَنَسٍ رضي الله عنه أَنَّ رَسُولَ اللهِ ﷺ كَانَ يُصَلِّي نَحْوَ بَيْتِ الْمَقْدِسِ،\nفَنَزَلَتْ { قَدْ نَرَىٰ تَقَلُّبَ وَجْهِكَ فِى ٱلسَّمَآءِ ۖ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَىٰهَا ۚ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ }، فَمَرَّ رَجُلٌ مِنْ بَنِي سَلِمَةَ، وَهُمْ رُكُوعٌ فِي صَلَاةِ الْفَجْرِ وَقَدْ صَلَّوْا رَكْعَةً، فَنَادَى أَلَا إِنَّ الْقِبْلَةَ قَدْ حُوِّلَتْ، فَمَالُوا كَمَا هُمْ نَحْوَ الْقِبْلَةِ.","id":""}],"158":[{"ar":"سبب نزول: أ: (قَالَ عُرْوَةُ رضي الله عنه: سَأَلْتُ عَائِشَةَ رضي الله عنها فَقُلْتُ لَهَا: أَرَأَيْتِ قَوْلَ اللَّهِ تَعَالَى: { إِنَّ ٱلصَّفَا وَٱلْمَرْوَةَ مِن شَعَآئِرِ ٱللَّهِ ۖ فَمَنْ حَجَّ ٱلْبَيْتَ أَوِ ٱعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَن يَطَّوَّفَ بِهِمَا ۚ }.  فَوَاللَّهِ مَا عَلَى أَحَدٍ جُنَاحٌ أَنْ لَا يَطُوفَ بِالصَّفَا وَالْمَرْوَةِ.\nقَالَتْ: بِئْسَ مَا قُلْتَ يَا ابْنَ أُخْتِي، إِنَّ هَذِهِ لَوْ كَانَتْ كَمَا أَوَّلْتَهَا عَلَيْهِ، كَانَتْ: لَا جُنَاحَ عَلَيْهِ أَنْ لَا يَتَطَوَّفَ بِهِمَا، وَلَكِنَّهَا أُنْزِلَتْ فِي الْأَنْصَارِ، كَانُوا قَبْلَ أَنْ يُسْلِمُوا يُهِلُّونَ لِمَنَاةَ الطَّاغِيَةِ الَّتِي كَانُوا يَعْبُدُونَهَا عِنْدَ الْمُشَلَّلِ، فَكَانَ مَنْ أَهَلَّ يَتَحَرَّجُ أَنْ يَطُوفَ بِالصَّفَا وَالْمَرْوَةِ، فَلَمَّا أَسْلَمُوا سَأَلُوا رَسُولَ اللهِ ﷺ عَنْ ذَلِكَ، قَالُوا: يَا رَسُولَ اللهِ، إِنَّا كُنَّا نَحَرَّجُ أَنْ نَطُوفَ بَيْنَ الصَّفَا وَالمَرْوَةِ. فَأَنْزَلَ اللهُ تَعَالَى: {   إِنَّ ٱلصَّفَا وَٱلْمَرْوَةَ مِن شَعَآئِرِ ٱللَّهِ ۖ } الآيَةَ.\nقَالَتْ عَائِشَةُ رضي الله عنها: وَقَدْ سَنَّ رَسُولُ اللهِ ﷺ الطَّوَافَ بَيْنَهُمَا فَلَيْسَ لِأَحَدٍ أَنْ يَتْرُكَ الطَّوَافَ بَيْنَهُمَا...).","id":""},{"ar":"سبب نزول: ب: (.... ثُمَّ أَخْبَرْتُ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ رضي الله عنه فَقَالَ: إِنَّ هَذَا لَعِلْمُ مَا كُنْتُ سَمِعْتُهُ، وَلَقَدْ سَمِعْتُ رِجَالاً مِنْ أَهْلِ الْعِلْمِ يَذْكُرُونَ أَنَّ النَّاسَ - إِلَّا مَنْ ذَكَرَتْ عَائِشَةُ رضي الله عنها - مِمَّنْ كَانَ يُهِلَّ بِمَنَاةَ، كَانُوا يَطُوفُونَ كُلُّهُمْ بِالصَّفَا وَالْمَرْوَةِ، فَلَمَّا ذَكَرَ اللهُ تَعَالَى الطَّوَافَ بِالْبَيْتِ وَلَمْ يَذْكُرْ الصَّفَا وَالْمَرْوَةَ فِي الْقُرْآنِ، قَالُوا يَا رَسُولَ اللهِ: كُنَّا نَطُوفُ بِالصَّفَا وَالْمَرْوَةِ، وَإِنَّ اللهَ أَنْزَلَ الطَّوَافَ بِالْبَيْتِ فَلَمْ يَذْكُر الصَّفَا، فَهَلْ عَلَيْنَا مِنْ حَرَجٍ أَنْ نَطَّوَّفَ بِالصَّفَا وَالْمَرْوَةِ، فَأَنْزَلَ اللهُ تَعَالَى { إِنَّ ٱلصَّفَا وَٱلْمَرْوَةَ مِن شَعَآئِرِ ٱللَّهِ ۖ } الآيَةَ.\nقَالَ أَبُو بَكْرٍ رضي الله عنه: فَأَسْمَعُ هَذِهِ الآيَةَ نَزَلَتْ فِي الْفَرِيقَيْنِ كِلَيْهِمَا، فِي الَّذِينَ كَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بِالْجَاهِلِيَّةِ بِالصَّفَا وَالْمَرْوَةِ، وَالَّذِينَ يَطُوفُونَ ثُمَّ تَحَرَّجُوا أَنْ يَطُوفُوا بِهِمَا فِي الْإِسْلَامِ، مِنْ أَجْلِ أَنَّ اللهَ تَعَالَى أَمَرَ بِالطَّوَافِ بِالْبَيْتِ وَلَمْ يَذْكُر الصَّفَا حَتَّى ذَكَرَ ذَلِكَ بَعدَ مَا ذَكَرَ الطواف بالبيت.","id":""},{"ar":"عَنْ عَاصِمِ بْنِ سُلَيْمَانِ رضي الله عنه قَالَ: سَأَلْتُ أَنَسَ بْنَ مَالِكٍ رضي الله عنه عَنِ الصَّفَا وَالمَرْوَةِ فَقَالَ: كُنَّا نَرَى أَنَّهُمَا مِنْ أَمْرِ الجَاهِلِيَّةِ، فَلَمَّا كَانَ الإِسْلَامُ أَمْسَكْنَا عَنْهُمَا، فَأَنْزَلَ اللهُ تَعَالَى: { إِنَّ ٱلصَّفَا وَٱلْمَرْوَةَ مِن شَعَآئِرِ ٱللَّهِ ۖ فَمَنْ حَجَّ ٱلْبَيْتَ أَوِ ٱعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَن يَطَّوَّفَ بِهِمَا ۚ }.","id":""}],"187":[{"ar":"عَنِ البَرَاءِ رضي الله عنه قَالَ : كَانَ أَصْحَابُ مُحَمَّدٍ ﷺ إِذَا كَانَ الرَّجُلُ صَائِماً فَحَضَرَ الإِفْطَارُ فَنَامَ قَبْلَ أَنْ يُفْطِرَ ، لَمْ يَأْكُلْ لَيْلَتَهُ وَلَا يَوْمَهُ حَتَّى يُمْسِيَ، وَإِنَّ قَيْسَ بْنَ صِرْمَةَ الأَنْصَارِيَّ كَانَ صَائِماً فَلَمَّا حَضَرَ الإِفْطَارَ أَتَى امْرَأَتَهُ فَقَالَ لَهَا : أَعِنْدَكِ طَعَامٌ ؟ قَالَتْ : لَا وَلِكِنْ أَنْطَلِقُ فَأَطْلُبُ لَكَ. وَكَانَ يَوْمَهُ يَعْمَلُ ، فَغَلَبَتَهُ عَيْنَاهُ ، فَجَاءَتْهُ امْرَأَتُهُ ، فَلَمَّا رَأَتْهُ قَالَتْ : خَيْبَةً لَكَ . فَلَمَّا انْتَصَفَ النَّهَارُ غُشِيَ عَلَيْهِ ، فَذُكِرَ ذَلِكَ لِلنَّبِيِّ ﷺ ، فَنَزَلَتْ هَذِهِ الْآيَةِ : { أُحِلَّ لَكُمْ لَيْلَةَ ٱلصِّيَامِ ٱلرَّفَثُ إِلَىٰ نِسَآئِكُمْ ۚ } فَفَرِحُوا بِهَا فَرَحَاً شَدِيداً، وَنَزَلَتْ { وَكُلُوا۟ وَٱشْرَبُوا۟ حَتَّىٰ يَتَبَيَّنَ لَكُمُ ٱلْخَيْطُ ٱلْأَبْيَضُ مِنَ ٱلْخَيْطِ ٱلْأَسْوَدِ }.\n\nوفي لفظ آخر للبخاري : عَنِ البَرَاءِ رضي الله عنه : لَمَّا نَزَلَ صَوْمُ رَمَضَانَ، كَانُوا لَا يَقْرَبُونَ النِّسَاءَ رَمَضَانَ كُلَّهُ ، وَكَانَ رِجَالٌ يَخُونُونَ أَنْفُسَهُمْ، فَأَنْزَلَ اللهُ { عَلِمَ ٱللَّهُ أَنَّكُمْ كُنتُمْ تَخْتَانُونَ أَنفُسَكُمْ فَتَابَ عَلَيْكُمْ وَعَفَا عَنكُمْ ۖ }.","id":""},{"ar":"عَنْ عَبْدِ اللهِ بْنِ مَالِكٍ رضي الله عنه يُحَدِّثُ عَنْ أَبِيهِ قَالَ : كَانَ النَّاسُ فِي رَمَضَانَ إِذَا صَامَ الرَّجُلُ فَأَمْسَى فَنَامَ حَرُمَ عَلَيْهِ الطَّعَامُ وَالشَّرَابُ وَالنِّسَاءُ حَتَّى يُفْطِرَ مِنَ الغَدِ، فَرَجَعَ عُمَرُ بْنُ الخَطَابِ رضي الله عنه مِنْ عِنْدِ النَّبِيِّ ﷺ ذَاتَ لَيْلَةٍ وَقَدْ سَهِرَ عِنْدَهُ، فَوَجَدَ امْرَأَتَهُ قَدْ نَامَتْ فَأَرَادَهَا ، فَقَالَتْ: إِنِّي قَدْ نِمْتُ، قَالَ : مَا نِمْتِ . ثُمَّ وَقَعَ بِهَا ، وَصَنَعَ كَعْبُ بْنُ مَالِكٍ رضي الله عنه مِثْلَ ذَلِكَ . فَغَدًا عُمَرُ إِلَى النَّبِيِّ ﷺ فَأَخْبَرَهُ. فَأَنْزَلَ اللهُ تَعَالَى : { عَلِمَ ٱللَّهُ أَنَّكُمْ كُنتُمْ تَخْتَانُونَ أَنفُسَكُمْ فَتَابَ عَلَيْكُمْ وَعَفَا عَنكُمْ ۖ } .","id":""},{"ar":"عَنْ سَهْلِ بْنِ سَعْدِ رضي الله عنه قَالَ: أُنْزِلَتْ { وَكُلُوا۟ وَٱشْرَبُوا۟ حَتَّىٰ يَتَبَيَّنَ لَكُمُ ٱلْخَيْطُ ٱلْأَبْيَضُ مِنَ ٱلْخَيْطِ ٱلْأَسْوَدِ }، وَلَمْ يَنْزِلْ مِنَ الفَجْرِ، فَكَانَ رِجَالٌ إِذَا أَرَادُوا الصَّوْمَ، رَبَطَ أَحَدُهُمْ فِي رِجْلِهِ الخَيْطَ الأَبْيَضَ وَالخَيْطَ الأَسْوَدَ، وَلَمْ يَزَلْ يَأْكُلُ حَتَّى يَتَبَيَّنَ لَهُ رُؤْيَتُهُمَا، فَأَنْزَلَ اللهُ بَعْدُ { مِنَ ٱلْفَجْرِ ۖ }، فَعَلِمُوا أَنَّهُ إِنَّمَا يَعْنِي اللَّيْلَ وَالنَّهَارِ.","id":""},{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُتِبَ عَلَيْكُمُ ٱلصِّيَامُ كَمَا كُتِبَ عَلَى ٱلَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ }، فَكَانَ النَّاسُ عَلَى عَهْدِ النَّبِيِّ ﷺ إِذَا صَلُّوا العَتَمَةَ، حَرُمَ عَلَيْهِمْ الطَّعَامُ وَالشَّرَابُ وَالنِّسَاءُ وَصَامُوا إِلَى القَابِلَةِ، فَاخْتَانَ رَجُلٌ نَفْسَهُ فَجَامَعَ امْرَأَتَهُ وَقَدْ صَلَّى العِشَاءَ وَلَمْ يُفْطِرْ، فَأَرَادَ اللَّهُ عز و جل أَنْ يَجْعَلَ ذَلِكَ يُسْراً لِمَنْ بَقِيَ وَرُخْصَةً وَمَنْفَعَةً، فَقَالَ سُبْحَانَهُ: { عَلِمَ ٱللَّهُ أَنَّكُمْ كُنتُمْ تَخْتَانُونَ أَنفُسَكُمْ } الآيَةَ، وَكَانَ هَذَا مِمَّا نَفَعَ اللَّهُ بِهِ النَّاسَ وَرَخَّصَ لَهُمْ وَيَسَّرَ.","id":""}],"189":[{"ar":"عَنْ أَبِي إِسْحَاقَ قَالَ: سَمِعْتُ الْبَرَاءَ رضي الله عنه يَقُولُ:\nنَزَلَتْ هَذِهِ الآيَةُ فِينَا، كَانَتِ الأَنْصَارُ إِذَا حَجُّوا فَجَاءُوا لَمْ يَدْخُلُوا مِنْ قِبَلِ أَبْوَابِ بُيُوتِهِمْ وَلَكِنْ مِنْ ظُهُورِهَا، فَجَاءَ رَجُلٌ مِنَ الْأَنْصَارِ فَدَخَلَ مِنْ قِبَلِ بَابِهِ، فَكَأَنَّهُ عُيْرَ بِذَلِكَ، فَنَزَلَتْ { وَلَيْسَ ٱلْبِرُّ بِأَن تَأْتُوا۟ ٱلْبُيُوتَ مِن ظُهُورِهَا وَلَـٰكِنَّ ٱلْبِرَّ مَنِ ٱتَّقَىٰ ۗ وَأْتُوا۟ ٱلْبُيُوتَ مِنْ أَبْوَٰبِهَا ۚ }.","id":""},{"ar":"عَنْ جَابِرِ بْنِ عَبْدِ اللهِ رَضِيَ ا��لهُ تَعَالَى عَنْهُمَا قَالَ: كَانَتْ قُرَيْشٌ يُدْعَونَ الحُمْسِ، وَكَانُوا يَدْخُلُونَ مِنَ الْأَبْوَابِ فِي الْإِحْرَامِ، وَكَانَتِ الأَنْصَارُ وَسَائِرُ العَرَبِ لَا يَدْخُلُونَ مِنَ الأَبْوَابِ فِي الإِحْرَامِ، فَبَيْنَمَا رَسُولُ اللهِ ﷺ فِي بُسْتَانٍ فَخَرَجَ مِنْ بَابِهِ وَخَرَجَ مَعَهُ قُطْبَةُ بْنُ عَامِرٍ الأَنْصَارِي فَقَالُوا: يَا رَسُولَ اللهِ: إِنَّ قُطْبَةَ بْنِ عَامِرٍ رَجُلٌ فَاجِرٌ، إِنَّهُ خَرَجَ مَعَكَ مِنَ البَابِ، فَقَالَ: « مَا حَمَلَكَ عَلَى ذَلِكَ » قَالَ: رَأَيْتُكَ فَعَلْتَ فَفَعَلْتُ كَمَا فَعَلْتَ، فَقَالَ: « إِنِّي أَحْمُسِي » قَالَ: إِنَّ دِينِي دِينُكَ. فَأَنْزَلَ اللهُ عز و جل { وَلَيْسَ ٱلْبِرُّ بِأَن تَأْتُوا۟ ٱلْبُيُوتَ مِن ظُهُورِهَا وَلَـٰكِنَّ ٱلْبِرَّ مَنِ ٱتَّقَىٰ ۗ وَأْتُوا۟ ٱلْبُيُوتَ مِنْ أَبْوَٰبِهَا ۚ }.","id":""}],"195":[{"ar":"عَنْ أَسْلَمَ أَبِي عِمْرَانَ التُّجِيبِيِّ قَالَ: كُنَّا بِمَدَيْنَةِ الرُّومِ فَأَخْرَجُوا إِلَيْنَا صَفَاً عَظِيماً مِنَ الرُّومِ، فَخَرَجَ إِلَيْهِمْ مِنَ المُسْلِمِينَ مِثْلُهُمْ أَوْ أَكْثَرُ، وَعَلَى أَهْلِ مِصْرَ عُقْبَةُ بْنُ عَامِرٍ، وَعَلَى الجَمَاعَةِ فَضَالَةُ بْنُ عُبَيْدٍ، فَحَمَلَ رَجُلٌ مِنَ المُسْلِمِينَ عَلَى صَفُ الرُّومِ حَتَّى دَخَلَ فِيهِمْ، فَصَاحَ النَّاسُ، وَقَالُوا: سُبْحَانَ اللهِ يُلْقِي بِيَدَيْهِ إِلَى التَّهْلُكَةِ.\n\nفَقَامَ أَبُو أَيُّوبَ الأَنْصَارِيُّ فَقَالَ: يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَتَأَوَّلُونَ هَذِهِ الْآيَةَ هَذَا التَّأْوِيلَ!! وَإِنَّمَا أُنْزِلَتْ هَذِهِ الآيَةَ فِينَا مَعْشَرَ الْأَنْصَارِ، لَمَّا أَعَزَّ اللهُ الإِسْلَامَ وَكَثُرَ نَاصِرُوهُ، فَقَالَ بَعْضُنَا لِبَعْضِ سِرًّا - دُونَ رَسُولِ اللهِ ﷺ -: إِنَّ أَمْوَالَنَا قَدْ ضَاعَتْ وَإِنَّ الله قَدْ أَعَزَّ الإِسْلَامَ وَكَثُرَ نَاصِرُوهُ فَلَوْ أَقَمْنَا فِي أَمْوَالِنَا فَأَصْلَحْنَا مَا ضَاعَ مِنْهَا، فَأَنْزَلَ اللهُ عَلَى نَبِيِّهِ ﷺ يَرُدُّ عَلَيْنَا مَا قُلْنَا: { وَأَنفِقُوا۟ فِى سَبِيلِ ٱللَّهِ وَلَا تُلْقُوا۟ بِأَيْدِيكُمْ إِلَى ٱلتَّهْلُكَةِ ۛ } فَكَانَتْ التَّهْلُكَةُ الإِقَامَةَ عَلَى الْأَمْوَالِ وَإِصْلَاحِهَا وَتَرْكَنَا الغَزْوَ، فَمَا زَالَ أَبُو أَيُّوبَ شَاخِصاً فِي سَبِيلِ اللهِ حَتَّى دُفِنَ بأَرْضِ الرُّومِ.","id":""},{"ar":"عَنْ أَبِي جَبِيرَةَ بْنِ الضَّحَّاكِ رضي الله عنه قَالَ: كَانَتْ الْأَنْصَارُ يَتَصَدَّقُونَ وَيُعْطُونَ مَا شَاءَ اللهُ، فَأَصَابَتُهُمْ مُصِيبَةٌ فَأَمْسَكُوا. فَأَنْزَلَ اللَّهُ عز و جل { وَلَا تُلْقُوا۟ بِأَيْدِيكُمْ إِلَى ٱلتَّهْلُكَةِ ۛ }.","id":""}],"196":[{"ar":"عَنْ عَبْدِ اللهِ بْنِ مَعْقِلٍ قَالَ: قَعَدْتُ إِلَى كَعْبٍ رضي الله عنه وَهُوَ فِي المَسْجِدِ، فَسَأَلْتُهُ عَنْ هَذِهِ الآيَةِ: { فَفِدْيَةٌ مِّن صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ ۚ }.\n فَقَالَ كَعْبٌ رضي الله عنه: نَزَلَتْ فِيَّ، كَانَ بِي أَذًى مِنْ رَأْسِي، فَحُمِلْتُ إِلَى رَسُولِ اللهِ ﷺ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي. فَقَالَ: « مَا كُنْتُ أَرَى أَنَّ الجَهْدَ بَلَغَ مِنْكَ مَا أَرَى، أَتَجِدُ شَاةً؟ ». فَقُلْتُ: لَا، فَنَزَلَتْ هَذِهِ الْآيَةُ { فَفِدْيَةٌ مِّن صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ ۚ }، قَالَ: صَوْمُ ثَلَاثَةِ أَيَّامٍ أَوْ إِطْعَامٌ سِتَّةِ مَسَاكِينَ نِصْفَ صَاعٍ طَعَاماً لِكُلِّ مِسْكِينٍ. قَالَ: فَنَزَلَتْ فِيَّ خَاصَّةً، وَهِيَ لَكُمْ عَامَّةٌ. اللفظ لمسلم.","id":""}],"197":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: كَانَ أَهْلُ اليَمَنِ يَحُجُّونَ وَلَا يَتَزَوَّدُونَ، وَيَقُولُونَ: نَحْنُ الْمُتَوَكِّلُونَ، فَإِذَا قَدِمُوا مَكَّةَ سَأَلُوا النَّاسَ، فَأَنْزَلَ اللَّهُ تَعَالَى: {  وَتَزَوَّدُوا۟ فَإِنَّ خَيْرَ ٱلزَّادِ ٱلتَّقْوَىٰ ۚ }.","id":""},{"ar":"عَنِ ابْنِ عُمَر رضي الله عنهما قَالَ: كَانُوا إِذَا أَحْرَمُوا وَمَعَهُمْ أَزْوَادُهُمْ رَمَوا بِهَا، وَاسْتَأْنَفُوا زَاداً آخَرَ ؛ فَأَنْزَلَ اللهُ تَعَالَى { وَتَزَوَّدُوا۟ فَإِنَّ خَيْرَ ٱلزَّادِ ٱلتَّقْوَىٰ ۚ }، فَنْهُوْا عَنْ ذَلِكَ وَأُمِرُوا أَنْ يَتَزَوَّدُوا الدَّقِيقَ وَالسَّوِيْقَ وَالكَعْكَ.","id":""}],"198":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: كَانَتْ عُكَاظٌ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقاً فِي الْجَاهِلِيَّةِ، فَلَمَّا كَانَ الْإِسْلَامُ فَكَأَنَّهُمْ تَأَتَّمُوا فِيهِ، فَنَزَلَتْ لَيْسَ { لَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَبْتَغُوا۟ فَضْلًا مِّن رَّبِّكُمْ ۚ }، فِي مَوَاسِمِ الْحَجُ.","id":""},{"ar":"وهناك سبب ثان: عَنْ أَبِي أُمَامَةَ التَّيْمِيِّ رحمه الله قَالَ: قُلْتُ لَابْنِ عُمَرَ رضي الله عنهما إِنَّا نُكْرِي فَهَلْ لَنَا مِنْ حَجِّ؟ قَالَ: أَلَيْسَ تَطُوفُونَ بِالْبَيْتِ، وَتَأْتُونَ الْمُعَرَّفَ، وَتَرْمُونَ الْجِمَارَ، وَتَحْلِقُونَ رُءُوسَكُمْ ؟ قَالَ: قُلْنَا: بَلَى، فَقَالَ ابْنُ عُمَرَ: جَاءَ رَجُلٌ إِلَى النَّبِيِّ ﷺ، فَسَأَلَهُ عَنْ الَّذِي سَأَلْتَنِي، فَلَمْ يُجِبُهُ، حَتَّى نَزَلَ عَلَيْهِ جِبْرِيلُ عليه السلام بِهَذِهِ الآيَةِ: { لَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَبْتَغُوا۟ فَضْلًا مِّن رَّبِّكُمْ ۚ } فَدَعَاهُ النَّبِيُّ ﷺ فَقَالَ: « أَنْتُمْ حُجَّاجٌ ».","id":""}],"199":[{"ar":"عَنْ هِشَامٍ عَنْ أَبِيهِ قَالَ: كَانَت الْعَرَبُ تَطُوفُ بِالْبَيْتِ عُرَاةٌ إِلَّا الْحُمْسَ، وَالْحُمْسُ قُرَيْشٌ وَمَا وَلَدَتْ، كَانُوا يَطُوفُونَ عُرَاةٌ إِلَّا أَنْ تُعْطِيَهُمْ الْحُمْسَ ثِيَاباً، فَيُعْطِي الرِّجَالُ الرِّجَالَ وَالنِّسَاءُ النِّسَاءَ، وَكَانَتْ الْحُمْسُ لَا يَخْرُجُونَ مِنَ الْمُزْدَلِفَةِ، وَكَانَ النَّاسُ كُلُّهُمْ يَبْلُغُونَ عَرَفَات.\n\nقَالَ هِشَامٌ: فَحَدَّثَنِي أَبِي، عَنْ عَائِشَةَ رضي الله عنها قَالَتْ: الْحُمْسُ هُمُ الَّذِينَ أَنْزَلَ اللهُ عز و جل فِيهِمْ: { ثُمَّ أَفِيضُوا۟ مِنْ حَيْثُ أَفَاضَ ٱلنَّاسُ }، قَالَتْ: كَانَ النَّاسُ يُفِيضُونَ مِنْ عَرَفَاتٍ، وَكَانَ الْحُمْسُ يُفِيضُونَ مِنْ الْمُزْدَلِفَةِ، يَقُولُونَ: لَا نٌفِيضُ إِلَّا مِنْ الْحَرَمِ. فَلَمَّا نَزَلَتْ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ، رَجَعُوا إِلَى عَرَفَاتٍ.","id":""}],"200":[{"ar":"وقال سعيد بن جبير عن ابن عباس رضي الله عنهما: كان أهل الجاهلية يقفون في الموسم، فيقول الرجل منهم كان أبي يطعم، ويحمل الحمالات، ويحمل الديات، ليس لهم ذكر غير فعال آبائهم. فأنزل الله على محمد ﷺ { فَٱذْكُرُوا۟ ٱللَّهَ كَذِكْرِكُمْ ءَابَآءَكُمْ أَوْ أَشَدَّ ذِكْرًا ۗ }.","id":""}],"201":[{"ar":"وقال سعيد بن جبير عن ابن عباس رضي الله عنهما: كان أهل الجاهلية يقفون في الموسم، فيقول الرجل منهم كان أبي يطعم، ويحمل الحمالات، ويحمل الديات، ليس لهم ذكر غير فعال آبائهم. فأنزل الله على محمد ﷺ { فَٱذْكُرُوا۟ ٱللَّهَ كَذِكْرِكُمْ ءَابَآءَكُمْ أَوْ أَشَدَّ ذِكْرًا ۗ }.","id":""}],"202":[{"ar":"وقال سعيد بن جبير عن ابن عباس رضي الله عنهما: كان أهل الجاهلية يقفون في الموسم، فيقول الرجل منهم كان أبي يطعم، ويحمل الحمالات، ويحمل الديات، ليس لهم ذكر غير فعال آبائهم. فأنزل الله على محمد ﷺ { فَٱذْكُرُوا۟ ٱللَّهَ كَذِكْرِكُمْ ءَابَآءَكُمْ أَوْ أَشَدَّ ذِكْرًا ۗ }.","id":""}],"207":[{"ar":"عن عكرمة رضي الله عنه قال: لما خرج صهيب رضي الله عنه مهاجراً، تبعه أهل مكة، فنثل كنانته، فأخرج منها أربعين سهماً، فقال: لا تصلون إلي حتى أضع في كل رجل منكم سهماً، ثم أصير بعد إلى السيف، فتعلمون أني رجل، وقد خلفت بمكة قينتين فهما لكم.\n\nوحدثنا حماد بن سلمة عن ثابت عن أنس رضي الله عنه نحوه، ونزلت على النبي ﷺ { وَمِنَ ٱلنَّاسِ مَن يَشْرِى نَفْسَهُ ٱبْتِغَآءَ مَرْضَاتِ ٱللَّهِ ۗ }، فلما رآه النبي ﷺ قال: « أبا يحيى ربح البيع ». قال: وتلا عليه الآية.","id":""}],"217":[{"ar":"عن جندب بن عبد الله رضي الله عنه، عن النبي ﷺ: أنه بعث رهطاً، وبعث عليهم أبا عبيدة، فلما ذهب لينطلق بكى صبابة إلى رسول الله ﷺ، فجلس، فبعث عليهم عبد الله ابن جحش مكانه، وكتب له كتاباً وأمره أن لا يقرأ الكتاب حتى يبلغ مكان كذا وكذا، وقال:: « لا تكرهن أحداً من أصحابك على المسير معك »، فلما قرأ الكتاب استرجع، وقال: سمعاً وطاعة للَّه ولرسوله، فخبرهم الخبر وقرأ عليهم الكتاب، فرجع رجلان ومضى بقيتهم فلقوا ابن الحضرمي فقتلوه، ولم يدروا أن ذلك اليوم من رجب أو جمادى؟.\n\nفقال المشركون للمسلمين: قتلتم في الشهر الحرام؟! فأنزل الله عز و جل { يَسْـَٔلُونَكَ عَنِ ٱلشَّهْرِ ٱلْحَرَامِ } الآية، فقال بعضهم: إن لم يكونوا أصابوا وزراً فليس لهم أجر، فأنزل الله عز و جل { إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَاجَرُوا۟ وَجَـٰهَدُوا۟ فِى سَبِيلِ ٱللَّهِ أُو۟لَـٰٓئِكَ يَرْجُونَ رَحْمَتَ ٱللَّهِ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ ﴿٢١٨﴾ }.","id":""},{"ar":"وعن عروة بن الزبير رضي الله عنهما - نحواً من هذا أيضاً - وفيه: فكان ابن الحضرمي أول قتيل قتل بين المسلمين والمشركين، فركب وفد من كفار قريش حتى قدموا على رسول الله ﷺ بالمدينة فقالوا: أيحل القتال في الشهر الحرام؟ فأنزل الله { يَسْـَٔلُونَكَ عَنِ ٱلشَّهْرِ ٱلْحَرَامِ } الآية.","id":""}],"218":[{"ar":"عن جندب بن عبد الله رضي الله عنه، عن النبي ﷺ: أنه بعث رهطاً، وبعث عليهم أبا عبيدة، فلما ذهب لينطلق بكى صبابة إلى رسول الله ﷺ، فجلس، فبعث عليهم عبد الله ابن جحش مكانه، وكتب له كتاباً وأمره أن لا يقرأ الكتاب حتى يبلغ مكان كذا وكذا، وقال:: « لا تكرهن أحداً من أصحابك على المسير معك »، فلما قرأ الكتاب استرجع، وقال: سمعاً وطاعة للَّه ولرسوله، فخبرهم الخبر وقرأ عليهم الكتاب، فرجع رجلان ومضى بقيتهم فلقوا ابن الحضرمي فقتلوه، ولم يدروا أن ذلك اليوم من رجب أو جمادى؟.\n\nفقال المشركون للمسلمين: قتلتم في الشهر الحرام؟! فأنزل الله عز و جل { يَسْـَٔلُونَكَ عَنِ ٱلشَّهْرِ ٱلْحَرَامِ } الآية، فقال بعضهم: إن لم يكونوا أصابوا وزراً فليس لهم أجر، فأنزل الله عز و جل { إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَاجَرُوا۟ وَجَـٰهَدُوا۟ فِى سَبِيلِ ٱللَّهِ أُو۟لَـٰٓئِكَ يَرْجُونَ رَحْمَتَ ٱللَّهِ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ ﴿٢١٨﴾ }.","id":""},{"ar":"وعن عروة بن الزبير رضي الله عنهما - نحواً من هذا أيضاً - وفيه: فكان ابن الحضرمي أول قتيل قتل بين المسلمين والمشركين، فركب وفد من كفار قريش حتى قدموا على رسول الله ﷺ بالمدينة فقالوا: أيحل القتال في الشهر الحرام؟ فأنزل الله { يَسْـَٔلُونَكَ عَنِ ٱلشَّهْرِ ٱلْحَرَامِ } الآية.","id":""}],"219":[{"ar":"عَنْ عُمَرَ بْنِ الْخَطَّابِ رضي الله عنه قَالَ: لَمَّا نَزَلَ تَحْرِيمُ الخَمْرِ قَالَ: اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَاناً شَافِياً، فَنَزَلَتْ هَذِهِ الْآيَةُ الَّتِي فِي سُورَةِ الْبَقَرَةِ {   يَسْـَٔلُونَكَ عَنِ ٱلْخَمْرِ وَٱلْمَيْسِرِ ۖ قُلْ فِيهِمَآ إِثْمٌ كَبِيرٌ }.\n\nقَالَ: فَدُعِيَ عُمَرُ رضي الله عنه فَقُرِئَتْ عَلَيْهِ فَقَالَ: اللَّهُمَّ بَيِّنُ لَنَا فِي الْخَمْرِ بَيَاناً شَافِياً، فَنَزَلَتْ الْآيَةُ الَّتِي فِي سُورَةِ النِّسَاءِ { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَقْرَبُوا۟ ٱلصَّلَوٰةَ وَأَنتُمْ سُكَـٰرَىٰ }، فَكَانَ مُنَادِي رَسُولِ الله ﷺ إِذَا أَقَامَ الصَّلَاةَ، نَادَى: أَنْ لَا يَقْرَبَنَّ الصَّلَاةَ سَكْرَانُ، فَدُعِيَ عُمَرُ رضي الله عنه فَقُرِئَتْ عَلَيْهِ.\n\nفَقَالَ: اللَّهُمَّ بَيِّنُ لَنَا فِي الْخَمْرِ بَيَاناً شَافِياً، فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْمَائِدَةِ، فَدُعِيَ عُمَرُ رضي الله عنه فَقُرِئَتْ عَلَيْهِ، فَلَمَّا بَلَغَ: { فَهَلْ أَنتُم مُّنتَهُونَ } قَالَ: فَقَالَ عُمَرُ رضي الله عنه: انْتَهَيْنَا انْتَهَيْنَا.","id":""},{"ar":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: حُرِّمَتِ الْخَمْرُ ثَلَاثَ مَرَّاتِ، قَدِمَ رَسُولُ اللهِ ﷺ الْمَدِينَةَ وَهُمْ يَشْرَبُونَ الْخَمْرَ، وَيَأْكُلُونَ الْمَيْسِرَ، فَسَأَلُوا رَسُولَ اللهِ ﷺ عَنْهُمَا، فَأَنْزَلَ اللهُ عَلَى نَبِيِّهِ ﷺ: {  يَسْـَٔلُونَكَ عَنِ ٱلْخَمْرِ وَٱلْمَيْسِرِ ۖ قُلْ فِيهِمَآ إِثْمٌ كَبِيرٌ وَمَنَـٰفِعُ لِلنَّاسِ وَإِثْمُهُمَآ أَكْبَرُ مِن نَّفْعِهِمَا ۗ } إِلَى آخِرِ الآيَةِ. فَقَالَ النَّاسُ: مَا حَرَّمَ عَلَيْنَا إِنَّمَا قَالَ { فِيهِمَآ إِثْمٌ كَبِيرٌ }، وَكَانُوا يَشْرَبُونَ الْخَمْرَ، حَتَّى إِذَا كَانَ يَوْمٌ مِنْ الْأَيَّامِ، صَلَّى رَجُلٌ مِنْ الْمُهَاجِرِينَ أَمَّ أَصْحَابَهُ فِي الْمَغْرِبِ خَلَطَ فِي قِرَاءَتِهِ، فَأَنْزَلَ اللهُ فِيهَا آيَةٌ أَغْلَظَ مِنْهَا: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَقْرَبُوا۟ ٱلصَّلَوٰةَ وَأَنتُمْ سُكَـٰرَىٰ حَتَّىٰ تَعْلَمُوا۟ مَا تَقُولُونَ }.\n\nوَكَانَ النَّاسُ يَشْرَبُونَ حَتَّى يَأْتِيَ أَحَدُهُمُ الصَّلَاةَ وَهُوَ مُفِيقٌ، ثُمَّ أُنْزِلَتْ آيَةً أَغْلَظُ مِنْ ذَلِكَ: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ فَٱجْتَنِبُوهُ لَعَلَّكُمْ تُفْلِحُونَ ﴿٩٠﴾ }. فَقَالُوا: انْتَهَيْنَا رَبَّنَا، فَقَالَ النَّاسُ: يَا رَسُولَ اللهِ نَاسٌ قُتِلُوا فِي سَبِيلِ اللهِ أَوْ مَاتُوا عَلَى فُرُشِهِمْ كَانُوا يَشْرَبُونَ الْخَمْرَ، وَيَأْكُلُونَ الْمَيْسِرَ، وَقَدْ جَعَلَهُ اللهُ رِجْسَاً وَمِنْ عَمَلِ الشَّيْطَانِ، فَأَنْزَلَ اللهُ: { لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جُنَاحٌۭ فِيمَا طَعِمُوٓا۟ إِذَا مَا ٱتَّقَوا۟ وَّءَامَنُوا۟ } إِلَى آخِرِ الآيَةِ، فَقَالَ النَّبِيُّ ﷺ: لَوْ « حُرُمَتْ عَلَيْهِمْ لَتَرَكُوهَا كَمَا تَرَكْتُمْ ».","id":""},{"ar":"عن ابن عمر رضي الله عنهما قال: نزلت في الخمر ثلاث آيات، فأول شيء نزل { يَسْـَٔلُونَكَ عَنِ ٱلْخَمْرِ وَٱلْمَيْسِرِ ۖ } الآية، فقيل: حرمت الخمر، فقيل يا رسول الله دعنا ننتفع بها كما قال الله عز و جل، فسكت عنهم، ثم نزلت هذا الآية { لَا تَقْرَبُوا۟ ٱلصَّلَوٰةَ وَأَنتُمْ سُكَـٰرَىٰ }، فقيل: حرمت، فقالوا: لا يا رسول الله إنا لا نشربها قرب الصلاة، فسكت عنهم، ثم نزلت: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ } الآية، فقال رسول الله ﷺ: « حرمت الخمر ».\n\nقال: وقدِمتْ لرجلٍ راوية من الشام أو روايا، فقام النبي ﷺ وأبو بكر وعمر، ولا أعلم عثمان إلا معهم فانتهوا إلى الرجل، فقال رسول الله ﷺ: خلِّ عنا نشُقَّها، فقال: يا رسول الله أفلا نبيعها، قال رسول الله ﷺ: « إن الله لعن الخمر، ولعن غارسها، ولعن شاربها، ولعن عاصرها، ولعن موكلها، ولعن مديرها، ولعن ساقيها، ولعن حاملها، ولعن أكل ثمنها، ولعن بايعها ».","id":""}],"220":[{"ar":"عَنِ ابْنِ عَبَّاسٍ قَالَ: لَمَّا أَنْزَلَ اللهُ عز و جل { وَلَا تَقْرَبُوا۟ مَالَ ٱلْيَتِيمِ إِلَّا بِٱلَّتِى هِىَ أَحْسَنُ }، و { إِنَّ ٱلَّذِينَ يَأْكُلُونَ أَمْوَٰلَ ٱلْيَتَـٰمَىٰ ظُلْمًا } الآية، انْطَلَقَ مَنْ كَانَ عِنْدَهُ يَتِيمٌ، فَعَزَلَ طَعَامَهُ مِنْ طَعَامِهِ، وَشَرَابَهُ مِنْ شَرَابِهِ، فَجَعَلَ يَفْضُلُ مِنْ طَعَامِهِ فَيُحْبَسُ لَهُ حَتَّى يَأْكُلَهُ أَوْ يَفْسُدَ، فَاشْتَدَّ ذَلِكَ عَلَيْهِمْ، فَذَكَرُوا ذَلِكَ لِرَسُولِ اللهِ ﷺ، فَأَنْزَلَ اللهُ عز و جل: { وَيَسْـَٔلُونَكَ عَنِ ٱلْيَتَـٰمَىٰ ۖ  قُلْ إِصْلَاحٌ لَّهُمْ خَيْرٌ ۖ وَإِن تُخَالِطُوهُمْ فَإِخْوَٰنُكُمْ ۚ }، فَخَلَطُوا طَعَامَهُمْ بِطَعَامِهِ، وَشَرَابَهُمْ بِشَرَابِهِ.","id":""},{"ar":"عن قتادة رحمه الله عنه قال: لما نزلت { وَلَا تَقْرَبُوا۟ مَالَ ٱلْيَتِيمِ إِلَّا بِٱلَّتِى هِىَ أَحْسَنُ }، اعتزل الناس اليتامى، فلم يخالطوهم في مأكل ولا مشرب ولا مال، قال: فشق ذلك على الناس، فسألوا رسول الله، فأنزل الله عز و جل: {  وَيَسْـَٔلُونَكَ عَنِ ٱلْيَتَـٰمَىٰ ۖ  قُلْ إِصْلَاحٌ لَّهُمْ خَيْرٌ ۖ وَإِن تُخَالِطُوهُمْ فَإِخْوَٰنُكُمْ ۚ }.","id":""}],"222":[{"ar":"عَنْ أَنَسٍ رضي الله عنه: أَنَّ الْيَهُودَ كَانُوا إِذَا حَاضَتِ الْمَرْأَةُ فِيهِمْ، لَمْ يُؤَاكِلُوهَا وَلَمْ يُجَامِعُوهُنَّ فِي الْبُيُوتِ، فَسَأَلَ أَصحابُ النَّبِيِّ ﷺ النَّبِيَّ ﷺ فَأَنْزَلَ اللهُ تَعَالَى { وَيَسْـَٔلُونَكَ عَنِ ٱلْمَحِيضِ ۖ قُلْ هُوَ أَذًى فَٱعْتَزِلُوا۟ ٱلنِّسَآءَ فِى ٱلْمَحِيضِ ۖ } إِلَى آخِرِ الآيَةِ، فَقَالَ رَسُولُ اللهِ ﷺ: « اصْنَعُوا كُلَّ شَيْءٍ إِلَّا النِّكَاحَ » فَبَلَغَ ذَلِكَ الْيَهُودَ فَقَالُوا: مَا يُرِيدُ هَذَا الرَّجُلُ أَنْ يَدَعَ مِنْ أَمْرِنَا شَيْئًا إِلَّا خَالَفَنَا فِيهِ، فَجَاءَ أُسَيْدُ بْنُ حُضَيْرٍ وَعَبَّادُ بْنُ بِشْرٍ فَقَالَا: يَا رَسُولَ اللهِ، إِنَّ الْيَهُودَ تَقُولُ كَذَا وَكَذَا، فَلَا نُجَامِعُهُنَّ؟ فَتَغَيَّرَ وَجْهُ رَسُولِ اللهِ ﷺ حَتَّى ظَنَنَّا أَنْ قَدْ وَجَدَ عَلَيْهِمَا، فَخَرَجَا فَاسْتَقْبَلَهُمَا هَدِيَّةٌ مِنْ لَبَنٍ إِلَى النَّبِيِّ ﷺ، فَأَرْسَلَ فِي آثَارِهِمَا، فَسَقَاهُمَا، فَعَرَفَا أَنْ لَمْ يَجِدْ عَلَيْهِمَا. واللفظ لمسلم.","id":""},{"ar":"عَنِ ابْنِ عَبَّاسِ رضي الله عنهما: أَنَّ ثَابِتَ بْنِ الدَّحْدَاحِ رضي الله عنه سَأَلَ النَّبِيَّ ﷺ فَنَزَلَتْ: { وَيَسْـَٔلُونَكَ عَنِ ٱلْمَحِيضِ ۖ } الآيَة.","id":""},{"ar":"عَنْ عِكْرِمَةَ رَحِمَهُ اللهُ تَعَالَى قَالَ: كَانَ أَهْلُ الْجَاهِلِيَّةِ يَصْنَعُونَ فِي الْحَائِضِ نَحْواً مِنْ صَنِيعِ الْمَجُوسِ، فَذُكِرَ ذَلِكَ لِلنَّبِيِّ ﷺ فَنَزَلَتْ: { وَيَسْـَٔلُونَكَ عَنِ ٱلْمَحِيضِ ۖ قُلْ هُوَ أَذًى فَٱعْتَزِلُوا۟ ٱلنِّسَآءَ فِى ٱلْمَحِيضِ ۖ وَلَا تَقْرَبُوهُنَّ حَتَّىٰ يَطْهُرْنَ ۖ  } فَلَمْ يَزْدَدُ الْأَمْرُ فِيهِنَّ إِلَّا شِدَّةٌ.","id":""},{"ar":"عَنْ مُجَاهِدٍ رحمه الله قَالَ: كَانُوا يَجْتَنِبُونَ النِّسَاءَ فِي الْمَحِيضِ وَيَأْتُونَهُنَّ فِي أَدْبَارِهِنَّ، فَسَأَلُوا رَسُولَ اللهِ ﷺ عَنْ ذَلِكَ؟ فَأَنْزَلَ اللهُ تَعَالَى { وَيَسْـَٔلُونَكَ عَنِ ٱلْمَحِيضِ ۖ قُلْ هُوَ أَذًى فَٱعْتَزِلُوا۟ ٱلنِّسَآءَ فِى ٱلْمَحِيضِ ۖ وَلَا تَقْرَبُوهُنَّ حَتَّىٰ يَطْهُرْنَ ۖ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمُ ٱللَّهُ ۚ } فِي الْفَرْجِ، وَلَا تَعْدُوهُ.","id":""}],"223":[{"ar":"عَن جابر بن عبد الله رضي الله عنه قَالَ: كَانَتْ الْيَهُودُ تَقُولُ: إِذَا جَامَعَهَا مِنْ وَرَائِهَا جَاءَ الْوَلَدُ أَحْوَلَ، فَنَزَلَتْ { نِسَآؤُكُمْ حَرْثٌ لَّكُمْ فَأْتُوا۟ حَرْثَكُمْ أَنَّىٰ شِئْتُمْ ۖ }.","id":""},{"ar":"وسبب ثان لنزول الآية: عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: جَاءَ عُمَرُ إِلَى رَسُولِ اللهِ ﷺ، فَقَالَ: يَا رَسُولَ اللهِ هَلَكْتُ. قَالَ: « وَمَا أَهْلَكَكَ »، قَالَ: حَوَّلْتُ رَحْلِي اللَّيْلَةَ، قَالَ: فَلَمْ يَرُدَّ عَلَيْهِ رَسُولُ اللهِ ﷺ شَيْئًا، قَالَ: فَأُنْزِلَتْ عَلَى رَسُولِ الله ﷺ هَذِهِ الآيَةَ { نِسَآؤُكُمْ حَرْثٌ لَّكُمْ فَأْتُوا۟ حَرْثَكُمْ أَنَّىٰ شِئْتُمْ ۖ } أَقْبِلْ وَأَدْبِرُ، وَاتَّقِ الدُّبُرَ وَالحَيْضَة.","id":""},{"ar":"وهناك سبب ثالث لنزول الآية: عَنِ ابْنِ عَبَّاسٍ قَالَ: إِنَّ ابْنَ عُمَرَ - وَاللهُ يَغْفِرُ لَهُ - أَوْهَمَ، إِنَّمَا كَانَ هَذَا الْحَيُّ مِنْ الْأَنْصَارِ - وَهُمْ أَهْلُ وَثَنٍ -، مَعَ هَذَا الحَيِّ مِنْ يَهُودَ - وَهُمْ أَهْلُ كِتَابٍ، وَكَانُوا يَرَوْنَ لَهُمْ فَضْلاً عَلَيْهِمْ فِي الْعِلْمِ، فَكَانُوا يَقْتَدُونَ بِكَثِيرٍ مِنْ فِعْلِهِمْ، وَكَانَ مِنْ أَمْرِ أَهْلِ الْكِتَابِ أَنْ لَا يَأْتُوا النِّسَاءَ إِلَّا عَلَى حَرْفٍ، وَذَلِكَ أَسْتَرُ مَا تَكُونُ الْمَرْأَةُ، فَكَانَ هَذَا الْحَيُّ مِنْ الْأَنْصَارِ قَدْ أَخَذُوا بِذَلِكَ مِنْ فِعْلِهِمْ، وَكَانَ هَذَا الْحَيُّ مِنْ قُرَيْشٍ يَشْرَحُونَ النِّسَاءَ شَرْحاً مُنْكَراً، وَيَتَلَذَّذُونَ مِنْهُنَّ مُقْبِلَاتٍ وَمُدْبِرَاتٍ وَمُسْتَلْقِيَاتٍ، فَلَمَّا قَدِمَ الْمُهَاجِرُونَ الْمَدِينَةَ، تَزَوَّجَ رَجُلٌ مِنْهُمُ امْرَأَةً مِنْ الْأَنْصَارِ، فَذَهَبَ يَصْنَعُ بِهَا ذَلِكَ، فَأَنْكَرَتْهُ عَلَيْهِ، وَقَالَتْ: إِنَّمَا كُنَّا نُؤْتَى عَلَى حَرْفٍ، فَاصْنَعْ ذَلِكَ وَإِلَّا فَاجْتَنْبني. حَتَّى شَرِيَ أَمْرُهُمَا، فَبَلَغَ ذَلِكَ رَسُولَ اللهِ ﷺ فَأَنْزَلَ اللهُ عز و جل: { نِسَآؤُكُمْ حَرْثٌ لَّكُمْ فَأْتُوا۟ حَرْثَكُمْ أَنَّىٰ شِئْتُمْ ۖ } أَيْ: مُقْبِلَاتِ وَمُدْبِرَاتٍ وَمُسْتَلْقِيَاتٍ، يَعْنِي بِذَلِكَ مَوْضِعَ الْوَلَدِ.","id":""},{"ar":"عن أبي النضر رحمه الله أنه قال لنافع مولى عبد الله بن عمر رضي الله عنهما: قد أكثر عليك القول أنك تقول عن ابن عمر إنه أفتى بأن يؤتى النساء في أدبارها، قال نافع: لقد كذبوا علي، ولكني سأخبرك كيف كان الأمر:\nإن ابن عمر عرض المصحف يوماً وأنا عنده، حتى بلغ { نِسَآؤُكُمْ حَرْثٌ لَّكُمْ فَأْتُوا۟ حَرْثَكُمْ أَنَّىٰ شِئْتُمْ ۖ }، قال: يا نافع هل تعلم ما أمر هذه الآية، إنا كنا معشر قريش نجبي النساء، فلما دخلنا المدينة ونكحنا نساء الأنصار أردنا منهن مثل ما كنا نريد من نسائنا، فإذا من قد كرهن ذلك وأعظمنه، وكانت نساء الأنصار إنما يؤتين على جنوبهن فأنزل الله تعالى { نِسَآؤُكُمْ حَرْثٌ لَّكُمْ فَأْتُوا۟ حَرْثَكُمْ أَنَّىٰ شِئْتُمْ ۖ  }.","id":""},{"ar":"عَنْ أَمِّ سَلَمَةَ رضي الله عنها قَالَتْ: لَمَّا قَدِمَ الْمُهَاجِرُونَ الْمَدِينَةَ عَلَى الْأَنْصَارِ، تَزَوَّجُوا مِنْ نِسَائِهِمْ، وَكَانَ الْمُهَاجِرُونَ يُجَبُّونَ، وَكَانَتِ الْأَنْصَارُ لَا تُجَبِّي، فَأَرَادَ رَجُلٌ مِنْ الْمُهَاجِرِينَ امْرَأَتَهُ عَلَى ذَلِكَ فَأَبَتْ عَلَيْهِ حَتَّى تَسْأَلَ رَسُولَ اللهِ ﷺ، قَالَتْ: فَأَتَتْهُ فَاسْتَحْيَتْ أَنْ تَسْأَلَهُ، فَسَأَلَتْهُ أُمُّ سَلَمَةَ، فَنَزَلَتْ { نِسَآؤُكُمْ حَرْثٌ لَّكُمْ فَأْتُوا۟ حَرْثَكُمْ أَنَّىٰ شِئْتُمْ ۖ  }، وَقَالَ: « لَا إِلاَّ فِي صِمَامٍ وَاحِدٍ ».","id":""}],"228":[{"ar":"عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ بْنِ السَّكَنِ الْأَنْصَارِيَّةِ رضي الله عنها: أَنَّهَا طُلِّقَتْ عَلَى عَهْدِ رَسُولِ اللهِ ﷺ وَلَمْ يَكُنْ لِلْمُطَلَّقَةِ عِدَّةٌ، فَأَنْزَلَ اللهُ عز و جل حِينَ طُلِّقَتْ أَسْمَاءُ بِالْعِدَّةِ لِلطَّلَاقِ: { وَٱلْمُطَلَّقَـٰتُ يَتَرَبَّصْنَ } الآية، فَكَانَتْ أَوَّلَ مَنْ أُنْزِلَتْ فِيهَا الْعِدَّةُ لِلْمُطَلَّقَاتِ.","id":""}],"229":[{"ar":"عَنْ عَائِشَةَ رضي الله عنها قَالَتْ: كَانَ النَّاسُ، وَالرَّجُلُ يُطَلِّقُ امْرَأَتَهُ مَا شَاءَ أَنْ يُطَلِّقَهَا، وَهِيَ امْرَأَتُهُ إِذَا ارْتَجَعَهَا وَهِيَ فِي الْعِدَّةِ، وَإِنْ طَلَّقَهَا مِائَةَ مَرَّةٍ أَوْ أَكْثَرَ، حَتَّى قَالَ رَجُلٌ لامْرَأَتِهِ: وَاللهِ لا أَطَلْقُكَ فَتَبِينِي مِنِّي، وَلَا آوِيكِ أَبَداً.\nقَالَتْ: وَكَيْفَ ذَاكَ؟ قَالَ: أُطَلِّقُكِ فَكُلَّمَا هَمَّتْ عِدَّتُكِ أَنْ تَنْقَضِيَ رَاجَعْتُكِ. فَذَهَبَتِ الْمَرْأَةُ حَتَّى دَخَلَتْ عَلَى عَائِشَةَ فَأَخْبَرَتْهَا، فَسَكَتَتْ عَائِشَةً حَتَّى جَاءَ النَّبِيُّ ﷺ فَأَخْبَرَتْهُ، فَسَكَتَ النَّبِيُّ ﷺ حَتَّى نَزَلَ الْقُرْآنُ: { ٱلطَّلَـٰقُ مَرَّتَانِ ۖ فَإِمْسَاكُۢ بِمَعْرُوفٍ أَوْ تَسْرِيحُۢ بِإِحْسَـٰنٍۢ ۗ }.\nقَالَتْ عَائِشَةُ: فَاسْتَأْنَفَ النَّاسُ الطَّلَاقَ مُسْتَقْبَلاً، مَنْ كَانَ طَلَّقَ وَمَنْ لَمْ يَكُنْ طَلَّقَ.","id":""},{"ar":"عن هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ: كَانَ الرَّجُلُ إِذَا طَلَّقَ امْرَأَتَهُ ثُمَّ ارْتَجَعَهَا قَبْلَ أَنْ تَنْقَضِيَ عِدَّتُهَا، كَانَ ذَلِكَ لَهُ، وَإِنْ طَلَّقَهَا أَلْفَ مَرَّةٍ، فَعَمَدَ رَجُلٌ إِلَى امْرَأَتِهِ فَطَلَّقَهَا، حَتَّى إِذَا شَارَفَتْ انْقِضَاءَ عِدَّتِهَا رَاجَعَهَا ثُمَّ طَلَّقَهَا، ثُمَّ قَالَ: لَا وَاللهِ لا آوِيكِ إِلَيَّ، وَلَا تَحِلِّينَ أَبَداً. فَأَنْزَلَ اللهُ تَبَارَكَ وَتَعَالَى { ٱلطَّلَـٰقُ مَرَّتَانِ ۖ فَإِمْسَاكُۢ بِمَعْرُوفٍ أَوْ تَسْرِيحُۢ بِإِحْسَـٰنٍۢ ۗ }، فَاسْتَقْبَلَ النَّاسُ الطلاق جَدِيداً مِنْ يَوْمِئِذٍ، مَنْ كَانَ طَلَّقَ مِنْهُمْ أَوْ لَمْ يُطَلِّقُ.","id":""}],"232":[{"ar":"عَنْ مَعْقِلِ بْنِ يَسَارٍ رضي الله عنه: أَنَّهُ زَوَّجَ أُخْتَهُ رَجُلاً مِنْ الْمُسْلِمِينَ عَلَى عَهْدِ رَسُولِ اللهِ ﷺ، فَكَانَتْ عِنْدَهُ مَا كَانَتْ، ثُمَّ طَلَّقَهَا تَطْلِيقَةً لَمْ يُرَاجِعْهَا حَتَّى انْقَضَتْ الْعِدَّةُ فَهَوِيَهَا وَهَوِيَتْهُ، ثُمَّ خَطَبَهَا مَعَ الْخُطَّابِ فَقَالَ لَهُ: يَا لُكَعُ، أَكْرَمْتُكَ بِهَا وَزَوَّجْتُكَهَا فَطَلَّقْتَهَا، وَاللهِ لَا تَرْجِعُ إِلَيْكَ أَبَداً آخِرُ مَا عَلَيْكَ، قَالَ: فَعَلِمَ اللهُ حَاجَتَهُ إِلَيْهَا، وَحَاجَتَهَا إِلَى بَعْلِهَا، فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى: { وَإِذَا طَلَّقْتُمُ ٱلنِّسَآءَ فَبَلَغْنَ أَجَلَهُنَّ }  إِلَى قَوْلِهِ { وَأَنتُمْ لَا تَعْلَمُونَ } فَلَمَّا سَمِعَهَا مَعْقِلْ قَالَ: سَمْعاً لِرَبِّي وَطَاعَةً، ثُمَّ دَعَاهُ فَقَالَ: أَزَوُجُكَ وَأُكْرِمُكَ. واللفظ للترمذي.","id":""}],"256":[{"ar":"عَنِ ابْنِ عَبَّاسٍ قَالَ: كَانَتِ الْمَرْأَةُ تَكُونُ مِقْلاتاً، فَتَجْعَلُ عَلَى نَفْسِهَا إِنْ عَاشَ لَهَا وَلَدٌ أَنْ تُهَوِّدَهُ، فَلَمَّا أُجْلِيَتْ بَنُو النَّضِيرِ كَانَ فِيهِمْ مِنْ أَبْنَاءِ الْأَنْصَارِ، فَقَالُوا: لا نَدَعُ أَبْنَاءَنَا، فَأَنْزَلَ اللهُ عز و جل { لَآ إِكْرَاهَ فِى ٱلدِّينِ ۖ قَد تَّبَيَّنَ ٱلرُّشْدُ مِنَ ٱلْغَىِّ ۚ }، قَالَ أَبُو دَاوُد: الْمِقلاتُ الَّتِي لَا يَعِيشُ لَهَا وَلَدٌ.","id":""},{"ar":"عن أبي بشر قال: سألت سعيد بن جبير عن قوله { لَآ إِكْرَاهَ فِى ٱلدِّينِ ۖ قَد تَّبَيَّنَ ٱلرُّشْدُ مِنَ ٱلْغَىِّ ۚ } قال: نزلت هذه في الأنصار، قال: قلت خاصة، قال: خاصة، قال: كانت المرأة في الجاهلية تنذر إن ولدت ولداً أن تجعله في اليهود، تلتمس بذلك طول بقائه، قال: فجاء الإسلام وفيهم منهم، فلما أجليت النضير قالوا: يا رسول الله أبناؤنا وإخواننا فيهم، قال: فسكت عنهم رسول الله، فأنزل الله تعالى ذكره: { لَآ إِكْرَاهَ فِى ٱلدِّينِ ۖ قَد تَّبَيَّنَ ٱلرُّشْدُ مِنَ ٱلْغَىِّ ۚ } قال: فقال رسول الله: « قد خير أصحابكم، فإن اختاروكم فهم منكم، وإن اختاروهم فهم » منهم قال: فأجلوهم معهم.","id":""},{"ar":"سبب ثان لنزول الآية: عن ابن عباس قوله: { لَآ إِكْرَاهَ فِى ٱلدِّينِ ۖ قَد تَّبَيَّنَ ٱلرُّشْدُ مِنَ ٱلْغَىِّ ۚ } قال: نزلت في رجل من الأنصار من بني سالم بن عوف يقال له الحصين، كان له ابنان نصرانيان، وكان هو رجلاً مسلماً، فقال للنبي: ألا أستكرههما؟ فإنهما قد أبيا إلا النصرانية. فأنزل الله فيه ذلك.","id":""}],"267":[{"ar":"عَنْ الْبَرَاءِ رضي الله عنه { وَلَا تَيَمَّمُوا۟ ٱلْخَبِيثَ مِنْهُ تُنفِقُونَ }  قَالَ: نَزَلَتْ فِينَا مَعْشَرَ الْأَنْصَارِ، كُنَّا أَصْحَابَ نَخْلٍ، فَكَانَ الرَّجُلُ يَأْتِي مِنْ نَخْلِهِ عَلَى قَدْرِ كَثْرَتِهِ وَقِلَّتِهِ، وَكَانَ الرَّجُلُ يَأْتِي بِالْقِنْوِ وَالقِنْوَيْنِ فَيُعَلِّقُهُ فِي الْمَسْجِدِ، وَكَانَ أَهْلُ الصُّفَّة لَيْسَ لَهُمْ طَعَامٌ، فَكَانَ أَحَدُهُمْ إِذَا جَاءَ أَتَى الْقِنْوَ فَضَرَبَهُ بِعَصَاهُ، فَيَسْقُطُ مِنْ الْبُسْرِ وَالتَّمْرِ فَيَأْكُلُ، وَكَانَ نَاسٌ مِمَّنْ لَا يَرْغَبُ فِي الْخَيْرِ يَأْتِي الرَّجُلُ بِالْقِنْوِ فِيهِ الشِّيصُ وَالْحَشَفُ، وَبِالْقِنْوِ قَدْ انْكَسَرَ، فَيُعَلِّقُهُ، فَأَنْزَلَ اللهُ تَبَارَكَ وَتَعَالَى { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَنفِقُوا۟ مِن طَيِّبَـٰتِ مَا كَسَبْتُمْ وَمِمَّآ أَخْرَجْنَا لَكُم مِّنَ ٱلْأَرْضِ ۖ وَلَا تَيَمَّمُوا۟ ٱلْخَبِيثَ مِنْهُ تُنفِقُونَ وَلَسْتُم بِـَٔاخِذِيهِ إِلَّآ أَن تُغْمِضُوا۟ فِيهِ ۚ }، قَالَ: « لَوْ أَنْ أَحَدَكُمْ أَهْدِي إِلَيْهِ مِثْلُ مَا أَعْطَاهُ لَمْ يَأْخُذْهُ إِلَّا عَلَى إِغْمَاضٍ أَوْ حَيَاء » قَالَ: فَكُنَّا بَعْدَ ذَلِكَ يَأْتِي أَحَدُنَا بِصَالِح مَا عِنْدَهُ.","id":""},{"ar":"عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ أَبِيهِ قَالَ: أَنَّ النَّبِيَّ ﷺ نَهَى عَنْ لَوْنَيْنٍ مِنَ التَّمْرِ الجُعْرُورِ وَلَوْنَ الحُبَيْقِ، قَالَ: وَكَانَ نَاسٌ يَتَيَمَّمُونَ شَرَّ ثِمَارِهِمْ فَيُخْرِجُونَهَا فِي الصَّدَقَةِ، فَنُهُوا عَنْ لَوْنَيْنٍ مِنَ التَّمَرِ، فَنَزَلَتْ: { وَلَا تَيَمَّمُوا۟ ٱلْخَبِيثَ مِنْهُ تُنفِقُونَ }. واللفظ للحاكم.","id":""},{"ar":"عن جابر بن عبد الله رضي الله عنهما قال: أمر النبي ﷺ بزكاة الفطر بصاع من تمر، فجاء رجل بتمر رديء، فنزل القرآن: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَنفِقُوا۟ مِن طَيِّبَـٰتِ مَا كَسَبْتُمْ وَمِمَّآ أَخْرَجْنَا لَكُم مِّنَ ٱلْأَرْضِ ۖ وَلَا تَيَمَّمُوا۟ ٱلْخَبِيثَ مِنْهُ تُنفِقُونَ }.","id":""},{"ar":"عن عبيدة السلماني رحمه الله قال: سألت علياً رضي الله عنه عن قول الله: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَنفِقُوا۟ مِن طَيِّبَـٰتِ مَا كَسَبْتُمْ وَمِمَّآ أَخْرَجْنَا لَكُم مِّنَ ٱلْأَرْضِ ۖ وَلَا تَيَمَّمُوا۟ ٱلْخَبِيثَ مِنْهُ تُنفِقُونَ }، قال: فقال علي رضي الله عنه: نزلت هذه الآية في الزكاة المفروضة، كان الرجل يعمد إلى التمر فيصرمه، فيعزل الجيد ناحية فإذا جاء صاحب الصدقة، أعطاه من الرديء، فقال عز و جل { وَلَا تَيَمَّمُوا۟ ٱلْخَبِيثَ مِنْهُ تُنفِقُونَ }.","id":""}],"272":[{"ar":"عن ابن عباس رضي الله عنهما قال: كانوا يكرهون أن يرضخوا لأنسبائهم من المشركين، فسألوا، فرخص لهم، فنزلت هذه الآية: { ۞ لَّيْسَ عَلَيْكَ هُدَىٰهُمْ وَلَٰكِنَّ ٱللَّهَ يَهْدِى مَن يَشَآءُ ۗ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍ فَلِأَنفُسِكُمْ ۚ وَمَا تُنفِقُونَ إِلَّا ٱبْتِغَآءَ وَجْهِ ٱللَّهِ ۚ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍ يُوَفَّ إِلَيْكُمْ وَأَنتُمْ لَا تُظْلَمُونَ ﴿٢٧٢﴾ }.","id":""},{"ar":"عن سعيد بن جبير رحمه الله: قال رسول الله ﷺ: « لا تَصَدَّقُوا إلا على أهل دينكم » فأنزل الله تعالى: { لَّيْسَ عَلَيْكَ هُدَىٰهُمْ }، فقال رسول الله ﷺ: « تصدقوا على أهل الأديان ».","id":""}],"284":[{"ar":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: لَمَّا نَزَلَتْ عَلَى رَسُولِ اللهِ ﷺ: { لِّلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ فَيَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ ﴿٢٨٤﴾ } قَالَ: فَاشْتَدَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللهِ ﷺ فَأَتَوْا رَسُولَ اللهِ ﷺ، ثُمَّ بَرَكُوا عَلَى الرُّكَب، فَقَالُوا: أَي رَسُولَ اللهِ، كُلِّفْنَا مِنْ الْأَعْمَالِ مَا نُطِيقُ: الصَّلاةَ، وَالصِّيَامَ، وَالْجِهَادَ، وَالصَّدَقَةَ، وَقَدْ أُنْزِلَتْ عَلَيْكَ هَذِهِ الْآيَةُ، وَلَا نُطِيقُهَا.\n\nقَالَ رَسُولُ اللهِ ﷺ: « أَتُرِيدُونَ أَنْ تَقُولُوا كَمَا قَالَ أَهْلُ الْكِتَابَيْنِ مِنْ قَبْلِكُمْ، سَمِعْنَا وَعَصَيْنَا؟ بَلْ قُولُوا: سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ ».\nقَالُوا: { سَمِعْنَا وَأَطَعْنَا ۖ غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ ٱلْمَصِيرُ } فَلَمَّا اقْتَرَأَهَا الْقَوْمُ ذَلَّتْ بِهَا أَلْسِنَتُهُمْ؟\n\nفَأَنْزَلَ اللهُ فِي إِثْرِهَا: { ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ كُلٌّ ءَامَنَ بِٱللَّهِ وَمَلَـٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِّن رُّسُلِهِۦ ۚ وَقَالُوا۟ سَمِعْنَا وَأَطَعْنَا ۖ غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ ٱلْمَصِيرُ ﴿٢٨٥﴾ }، فَلَمَّا فَعَلُوا ذَلِكَ نَسَخَهَا اللهُ تَعَالَى، فَأَنْزَلَ اللهُ عز و جل: { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ } \nقَالَ: نَعَمْ، { رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِصْرًا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ } \nقَالَ: نَعَمْ، { رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِۦ ۖ  } \nقَالَ: نَعَمْ، { ٱعْفُ عَنَّا وَٱغْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا فَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَـٰفِرِينَ } قَالَ: نَعَمْ.","id":""},{"ar":"عَنِ ابْنِ عَبَّاسِ رضي الله عنهما قَالَ: لَمَّا نَزَلَتْ هَذِهِ الْآيَةُ: { وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ }، قَالَ: دَخَلَ قُلُوبَهُمْ مِنْهَا شَيْءٌ لَمْ يَدْخُلْ قُلُوبَهُمْ مِنْ شَيْءٍ، فَقَالَ النَّبِيُّ ﷺ: « قُولُوا سَمِعْنَا وَأَطَعْنَا وَسَلَّمْنَا »، قَالَ: فَأَلْقَى اللَّهُ الْإِيمَانَ فِي قُلُوبِهِمْ، فَأَنْزَلَ اللهُ تَعَالَى: { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ } قَالَ: قَدْ فَعَلْتُ، { رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِصْرًا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ } قَالَ: قَدْ فَعَلْتُ، { وَٱ��ْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا } قَالَ: قَدْ فعلت.","id":""},{"ar":"عن سعيد بن مرجانة رحمه الله: ذكر لابن عباس رضي الله عنهما أن ابن عمر رضي الله عنهما تلا هذه الآية: { وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ } فبكى، ثم قال: والله لئن أخذنا الله بها لنهلكن، فقال ابن عباس: يرحم الله أبا عبد الرحمن، قد وجد المسلمون منها حين نزلت ما وجد، فذكروا ذلك لرسول الله ﷺ، فنزلت { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ } من القول والعمل، وكان حديث النفس مما لا يملكه أحد، ولا يقدر عليه أحد.","id":""},{"ar":"وفي لفظ آخر عند أحمد رحمه لله في المسند: عن مجاهد رحمه الله قال: دخلت على ابن عباس رضي الله عنهما فقلت: يا أبا عباس كنت عند ابن عمر رضي الله عنهما فقرأ هذه الآية فبكى قال: أية آية قلت: { وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ } قال ابن عباس رضي الله عنهما: إن هذه الآية حين أنزلت غمت أصحاب رسول الله ﷺ غما شديداً، وغاظتهم غيظاً شديداً، يعني وقالوا: يا رسول الله هلكنا، إن كنا نؤاخذ بما تكلمنا وبما تعمل، فأما قلوبنا فليست بأيدينا، فقال لهم رسول الله ﷺ: قولوا: « سمعنا وأطعنا » قالوا: سمعنا وأطعنا، قال: فنسختها هذه الآية { ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ } الي { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ }، فتجوز لهم عن حديث النفس، وأخذوا بالأعمال.","id":""}],"285":[{"ar":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: لَمَّا نَزَلَتْ عَلَى رَسُولِ اللهِ ﷺ: { لِّلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ فَيَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ ﴿٢٨٤﴾ } قَالَ: فَاشْتَدَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللهِ ﷺ فَأَتَوْا رَسُولَ اللهِ ﷺ، ثُمَّ بَرَكُوا عَلَى الرُّكَب، فَقَالُوا: أَي رَسُولَ اللهِ، كُلِّفْنَا مِنْ الْأَعْمَالِ مَا نُطِيقُ: الصَّلاةَ، وَالصِّيَامَ، وَالْجِهَادَ، وَالصَّدَقَةَ، وَقَدْ أُنْزِلَتْ عَلَيْكَ هَذِهِ الْآيَةُ، وَلَا نُطِيقُهَا.\n\nقَالَ رَسُولُ اللهِ ﷺ: « أَتُرِيدُونَ أَنْ تَقُولُوا كَمَا قَالَ أَهْلُ الْكِتَابَيْنِ مِنْ قَبْلِكُمْ، سَمِعْنَا وَعَصَيْنَا؟ بَلْ قُولُوا: سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ ».\nقَالُوا: { سَمِعْنَا وَأَطَعْنَا ۖ غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ ٱلْمَصِيرُ } فَلَمَّا اقْتَرَأَهَا الْقَوْمُ ذَلَّتْ بِهَا أَلْسِنَتُهُمْ؟\n\nفَأَنْزَلَ اللهُ فِي إِثْرِهَا: { ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ كُلٌّ ءَامَنَ بِٱللَّهِ وَمَلَـٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِّن رُّسُلِهِۦ ۚ وَقَالُوا۟ سَمِعْنَا وَأَطَعْنَا ۖ غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ ٱلْمَصِيرُ ﴿٢٨٥﴾ }، فَلَمَّا فَعَلُوا ذَلِكَ نَسَخَهَا اللهُ تَعَالَى، فَأَنْزَلَ اللهُ عز و جل: { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ } \nقَالَ: نَعَمْ، { رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِصْرًا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ } \nقَالَ: نَعَمْ، { رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِۦ ۖ  } \nقَالَ: نَعَمْ، { ٱعْفُ عَنَّا وَٱغْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا فَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَـٰفِرِينَ } قَالَ: نَعَمْ.","id":""},{"ar":"عَنِ ابْنِ عَبَّاسِ رضي الله عنهما قَالَ: لَمَّا نَزَلَتْ هَذِهِ الْآيَةُ: { وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ }، قَالَ: دَخَلَ قُلُوبَهُمْ مِنْهَا شَيْءٌ لَمْ يَدْخُلْ قُلُوبَهُمْ مِنْ شَيْءٍ، فَقَالَ النَّبِيُّ ﷺ: « قُولُوا سَمِعْنَا وَأَطَعْنَا وَسَلَّمْنَا »، قَالَ: فَأَلْقَى اللَّهُ الْإِيمَانَ فِي قُلُوبِهِمْ، فَأَنْزَلَ اللهُ تَعَالَى: { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ } قَالَ: قَدْ فَعَلْتُ، { رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِصْرًا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ } قَالَ: قَدْ فَعَلْتُ، { وَٱ��ْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا } قَالَ: قَدْ فعلت.","id":""},{"ar":"عن سعيد بن مرجانة رحمه الله: ذكر لابن عباس رضي الله عنهما أن ابن عمر رضي الله عنهما تلا هذه الآية: { وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ } فبكى، ثم قال: والله لئن أخذنا الله بها لنهلكن، فقال ابن عباس: يرحم الله أبا عبد الرحمن، قد وجد المسلمون منها حين نزلت ما وجد، فذكروا ذلك لرسول الله ﷺ، فنزلت { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ } من القول والعمل، وكان حديث النفس مما لا يملكه أحد، ولا يقدر عليه أحد.","id":""},{"ar":"وفي لفظ آخر عند أحمد رحمه لله في المسند: عن مجاهد رحمه الله قال: دخلت على ابن عباس رضي الله عنهما فقلت: يا أبا عباس كنت عند ابن عمر رضي الله عنهما فقرأ هذه الآية فبكى قال: أية آية قلت: { وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ } قال ابن عباس رضي الله عنهما: إن هذه الآية حين أنزلت غمت أصحاب رسول الله ﷺ غما شديداً، وغاظتهم غيظاً شديداً، يعني وقالوا: يا رسول الله هلكنا، إن كنا نؤاخذ بما تكلمنا وبما تعمل، فأما قلوبنا فليست بأيدينا، فقال لهم رسول الله ﷺ: قولوا: « سمعنا وأطعنا » قالوا: سمعنا وأطعنا، قال: فنسختها هذه الآية { ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ } الي { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ }، فتجوز لهم عن حديث النفس، وأخذوا بالأعمال.","id":""}],"286":[{"ar":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: لَمَّا نَزَلَتْ عَلَى رَسُولِ اللهِ ﷺ: { لِّلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ فَيَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ ﴿٢٨٤﴾ } قَالَ: فَاشْتَدَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللهِ ﷺ فَأَتَوْا رَسُولَ اللهِ ﷺ، ثُمَّ بَرَكُوا عَلَى الرُّكَب، فَقَالُوا: أَي رَسُولَ اللهِ، كُلِّفْنَا مِنْ الْأَعْمَالِ مَا نُطِيقُ: الصَّلاةَ، وَالصِّيَامَ، وَالْجِهَادَ، وَالصَّدَقَةَ، وَقَدْ أُنْزِلَتْ عَلَيْكَ هَذِهِ الْآيَةُ، وَلَا نُطِيقُهَا.\n\nقَالَ رَسُولُ اللهِ ﷺ: « أَتُرِيدُونَ أَنْ تَقُولُوا كَمَا قَالَ أَهْلُ الْكِتَابَيْنِ مِنْ قَبْلِكُمْ، سَمِعْنَا وَعَصَيْنَا؟ بَلْ قُولُوا: سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ ».\nقَالُوا: { سَمِعْنَا وَأَطَعْنَا ۖ غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ ٱلْمَصِيرُ } فَلَمَّا اقْتَرَأَهَا الْقَوْمُ ذَلَّتْ بِهَا أَلْسِنَتُهُمْ؟\n\nفَأَنْزَلَ اللهُ فِي إِثْرِهَا: { ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ كُلٌّ ءَامَنَ بِٱللَّهِ وَمَلَـٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِّن رُّسُلِهِۦ ۚ وَقَالُوا۟ سَمِعْنَا وَأَطَعْنَا ۖ غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ ٱلْمَصِيرُ ﴿٢٨٥﴾ }، فَلَمَّا فَعَلُوا ذَلِكَ نَسَخَهَا اللهُ تَعَالَى، فَأَنْزَلَ اللهُ عز و جل: { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ } \nقَالَ: نَعَمْ، { رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِصْرًا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ } \nقَالَ: نَعَمْ، { رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِۦ ۖ  } \nقَالَ: نَعَمْ، { ٱعْفُ عَنَّا وَٱغْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا فَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَـٰفِرِينَ } قَالَ: نَعَمْ.","id":""},{"ar":"عَنِ ابْنِ عَبَّاسِ رضي الله عنهما قَالَ: لَمَّا نَزَلَتْ هَذِهِ الْآيَةُ: { وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ }، قَالَ: دَخَلَ قُلُوبَهُمْ مِنْهَا شَيْءٌ لَمْ يَدْخُلْ قُلُوبَهُمْ مِنْ شَيْءٍ، فَقَالَ النَّبِيُّ ﷺ: « قُولُوا سَمِعْنَا وَأَطَعْنَا وَسَلَّمْنَا »، قَالَ: فَأَلْقَى اللَّهُ الْإِيمَانَ فِي قُلُوبِهِمْ، فَأَنْزَلَ اللهُ تَعَالَى: { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ } قَالَ: قَدْ فَعَلْتُ، { رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِصْرًا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ } قَالَ: قَدْ فَعَلْتُ، { وَٱ��ْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا } قَالَ: قَدْ فعلت.","id":""},{"ar":"عن سعيد بن مرجانة رحمه الله: ذكر لابن عباس رضي الله عنهما أن ابن عمر رضي الله عنهما تلا هذه الآية: { وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ } فبكى، ثم قال: والله لئن أخذنا الله بها لنهلكن، فقال ابن عباس: يرحم الله أبا عبد الرحمن، قد وجد المسلمون منها حين نزلت ما وجد، فذكروا ذلك لرسول الله ﷺ، فنزلت { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ } من القول والعمل، وكان حديث النفس مما لا يملكه أحد، ولا يقدر عليه أحد.","id":""},{"ar":"وفي لفظ آخر عند أحمد رحمه لله في المسند: عن مجاهد رحمه الله قال: دخلت على ابن عباس رضي الله عنهما فقلت: يا أبا عباس كنت عند ابن عمر رضي الله عنهما فقرأ هذه الآية فبكى قال: أية آية قلت: { وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ } قال ابن عباس رضي الله عنهما: إن هذه الآية حين أنزلت غمت أصحاب رسول الله ﷺ غما شديداً، وغاظتهم غيظاً شديداً، يعني وقالوا: يا رسول الله هلكنا، إن كنا نؤاخذ بما تكلمنا وبما تعمل، فأما قلوبنا فليست بأيدينا، فقال لهم رسول الله ﷺ: قولوا: « سمعنا وأطعنا » قالوا: سمعنا وأطعنا، قال: فنسختها هذه الآية { ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ } الي { لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ }، فتجوز لهم عن حديث النفس، وأخذوا بالأعمال.","id":""}]},"mapping_ayat":{"2:1":[{"p":"Nasa'i","n":3398,"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ إِلَى قَوْلِهِ إِنْ أَرَادُوا إِصْلَاحًا }وَذَلِكَ بِأَنَّ الرَّجُلَ كَانَ إِذَا طَلَّقَ امْرَأَتَهُ فَهُوَ أَحَقُّ بِرَجْعَتِهَا وَإِنْ طَلَّقَهَا ثَلَاثًا فَنَسَخَ ذَلِكَ وَقَالَ{ الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman Allah: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 1o1), dan firman Allah: '(Allah menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru'. Tidak boleh mereka menyembunyikan apa yang diciptakan Allah dalam rahimnya, jika mereka beriman kepada Allah dan hari akhirat. Dan suami-suaminya berhak merujukinya dalam masa menanti itu, jika mereka (para suami) menghendaki ishlah) ' (Qs. Al Baqarah: 228). Hal itu karena jika seorang laki-laki mencerai isterinya, maka ia lebih berhak untuk kembali kepadanya walaupun telah mencerainya tiga kali, kemudian Allah menghapus hal tersebut dan berfirman: '(Talak (yang dapat dirujuki) dua kali. Setelah itu boleh rujuk lagi dengan cara yang ma'ruf atau menceraikan dengan cara yang baik) ' (Qs. Al Baqarah: 229)."},{"p":"Tirmidzi","n":3224,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ الْقَدَّاحِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ آلِ عِمْرَانَ{ الم اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidullah bin Abu Ziyad Al Qaddah] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Nama Allah Allah yang paling agung ada dalam kedua ayat ini, yaitu: \"Dan Tuhanmu adalah Tuhan Yang Maha Esa; tidak ada Tuhan melainkan Dia Yang Maha Pemurah lagi Maha Penyayang\", (QS. Albaqarah 163) dan permulaan Surat Ali Imran; \"Alif laam miim. Allah, tidak ada Tuhan (yang berhak disembah) melainkan Dia. Yang hidup kekal lagi terus menerus mengurus makhluk-Nya.\" (QS.Ali Imran 1-2), Abu Isa berkata; hadits ini adalah hadits hasan shahih."}],"2:2":[{"p":"Ibnu Majah","n":2916,"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍأَنَّهُ لَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ طَوَافِ الْبَيْتِ أَتَى مَقَامَ إِبْرَاهِيمَ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ هَذَا مَقَامُ أَبِينَا إِبْرَاهِيمَ الَّذِي قَالَ اللَّهُ سُبْحَانَهُ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ الْوَلِيدُ فَقُلْتُ لِمَالِكٍ هَكَذَا قَرَأَهَا{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ نَعَمْ","trj":"Telah menceritakan kepada kami [Al 'Abbas bin 'Utsman Ad Dimasyqi]; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Malik bin Anas] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir] radliallahu 'anhu, ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam selesai melaksanakan Thawaf di Baitullah, maka beliau mendatangi Maqam Ibrahim. Kemudian 'Umar radliallahu 'anhu bertanya; 'Wahai Rasulullah, apakah ini maqam bapak kita (Ibrahim 'Alaihis Salam) yang Allah Subhanahu Wa Ta'ala telah sebutkan dalam firman-Nya: 'Dan jadikanlah sebagian dari Maqam Ibrahim sebagai tempat shalat.' (Qs. Al Baqarah 2:125)\" Al Walid berkata; 'Aku bertanya kepada Malik; 'Beginikah Umar membacanya; 'Dan jadikanlah sebagian dari Maqam Ibrahim sebagai tempat Shalat? ' Malik menjawab; 'Ya.'"},{"p":"Ibnu Majah","n":2974,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا الثَّوْرِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَتْ قُرَيْشٌ نَحْنُ قَوَاطِنُ الْبَيْتِ لَا نُجَاوِزُ الْحَرَمَ فَقَالَ اللَّهُ عَزَّ وَجَلَّ{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }","trj":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazaq]; telah menceritakan kepada kami [Ats Tsauri] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; \"Seseorang dari kalangan kaum Quraisy berkata; 'Kami adalah penduduk di sekitar Baitullah, dan (tinggal) tidak jauh dari daerah Haram. Allah Subhanahu Wa Ta'ala telah berfirman: 'Kemudian bertolaklah kamu dari tempat bertolaknya orang-orang banyak (Arafah) …'(Qs. Al Baqarah 2: 199) "},{"p":"Ibnu Majah","n":3035,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ قَالَقَعَدْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ فِي الْمَسْجِدِ فَسَأَلْتُهُ عَنْ هَذِهِ الْآيَةِ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ كَعْبٌ فِيَّ أُنْزِلَتْ كَانَ بِي أَذًى مِنْ رَأْسِي فَحُمِلْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي فَقَالَ مَا كُنْتُ أُرَى الْجُهْدَ بَلَغَ بِكَ مَا أَرَى أَتَجِدُ شَاةً قُلْتُ لَا قَالَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ فَالصَّوْمُ ثَلَاثَةُ أَيَّامٍ وَالصَّدَقَةُ عَلَى سِتَّةِ مَسَاكِينَ لِكُلِّ مِسْكِينٍ نِصْفُ صَاعٍ مِنْ طَعَامٍ وَالنُّسُكُ شَاةٌ","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Walid], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Ashbahani] dari [Abdullah bin Ma'qil], ia berkata; \"Aku duduk di samping [Ka'ab bin 'Ujrah] di dalam masjid, lalu kutanyai tentang firman Allah; '..maka wajiblah atasnya berfidyah, yaitu berpuasa atau bersedekah atau berkurban…' (Qs Albaqarah 2: 196), Ka'ab pun menjawab; 'Ayat itu diturunkan tentang diriku. Karena dulu aku pernah terserang penyakit di kepalaku, lalu aku dibawa kepada Rasulullah shallallahu 'alaihi wasallam sedang kutu busuk berhamburan di wajahku.' Maka beliau bersabda: 'Aku tidak seharusnya melihat keletihan yang menimpamu seperti yang kulihat ini. Apakah kamu memiliki seekor kambing? ' Aku menjawab; 'Tidak.' (Perawi berkata); 'Maka turunlah ayat ini, '..maka wajiblah atasnya berfidyah, yaitu berpuasa, atau bersedekah atau berkurban..' (Perawi) berkata; 'Puasa tiga hari, sedekah untuk enam orang miskin dan setiap satu orang miskin diberi setengah sha' makanan pokok, serta berkurban dengan seekor kambing.'"},{"p":"Nasa'i","n":2095,"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ تَعَالَى{ حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }قَالَ هُوَ سَوَادُ اللَّيْلِ وَبَيَاضُ النَّهَارِ","trj":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Jarir] dari [Mutharrif] dari [Asy Sya'bi] dari ['Adi bin Hatim] bahwa ia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang firman Allah Ta'ala: \" Hingga terang bagimu benang putih dan benang hitam.\" (Qs. Al Baqarah 2: 187) Beliau bersabda: \"Yaitu hitamnya malam dan putihnya siang.\""},{"p":"Tirmidzi","n":3224,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ الْقَدَّاحِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ آلِ عِمْرَانَ{ الم اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidullah bin Abu Ziyad Al Qaddah] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Nama Allah Allah yang paling agung ada dalam kedua ayat ini, yaitu: \"Dan Tuhanmu adalah Tuhan Yang Maha Esa; tidak ada Tuhan melainkan Dia Yang Maha Pemurah lagi Maha Penyayang\", (QS. Albaqarah 163) dan permulaan Surat Ali Imran; \"Alif laam miim. Allah, tidak ada Tuhan (yang berhak disembah) melainkan Dia. Yang hidup kekal lagi terus menerus mengurus makhluk-Nya.\" (QS.Ali Imran 1-2), Abu Isa berkata; hadits ini adalah hadits hasan shahih."}],"2:3":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}],"2:4":[{"p":"Tirmidzi","n":1493,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ عَمِّهِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَى رَجُلَيْنِ مِنْ الْمُسْلِمِينَ بِرَجُلٍ مِنْ الْمُشْرِكِينَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَمُّ أَبِي قِلَابَةَ هُوَ أَبُو الْمُهَلَّبِ وَاسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو وَيُقَالُ مُعَاوِيَةُ بْنُ عَمْرٍو وَأَبُو قِلَابَةَ اسْمُهُ عَبْدُ اللَّهِ بْنُ زَيْدٍ الْجَرْمِيُّ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ أَنَّ لِلْإِمَامِ أَنْ يَمُنَّ عَلَى مَنْ شَاءَ مِنْ الْأُسَارَى وَيَقْتُلَ مَنْ شَاءَ مِنْهُمْ وَيَفْدِي مَنْ شَاءَ وَاخْتَارَ بَعْضُ أَهْلِ الْعِلْمِ الْقَتْلَ عَلَى الْفِدَاءِ و قَالَ الْأَوْزَاعِيُّ بَلَغَنِي أَنَّ هَذِهِ الْآيَةَ مَنْسُوخَةٌ قَوْلُهُ تَعَالَى{ فَإِمَّا مَنًّا بَعْدُ وَإِمَّا فِدَاءً }نَسَخَتْهَا{ وَاقْتُلُوهُمْ حَيْثُ ثَقِفْتُمُوهُمْ }حَدَّثَنَا بِذَلِكَ هَنَّادٌ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ الْأَوْزَاعِيِّ قَالَ إِسْحَقُ بْنُ مَنْصُورٍ قُلْتُ لِأَحْمَدَ إِذَا أُسِرَ الْأَسِيرُ يُقْتَلُ أَوْ يُفَادَى أَحَبُّ إِلَيْكَ قَالَ إِنْ قَدَرُوا أَنْ يُفَادُوا فَلَيْسَ بِهِ بَأْسٌ وَإِنْ قُتِلَ فَمَا أَعْلَمُ بِهِ بَأْسًا قَالَ إِسْحَقُ الْإِثْخَانُ أَحَبُّ إِلَيَّ إِلَّا أَنْ يَكُونَ مَعْرُوفًا فَأَطْمَعُ بِهِ الْكَثِيرَ","trj":"Telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Pamannya] dari [Imran bin Khushain] berkata, \"Nabi shallallahu 'alaihi wasallam menebus dua orang laki-laki muslim dengan seorang laki-laki kafir.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Paman Abu Qilabah adalah Abul Muhallab, dan nama aslinya adalah 'Abdurrahman bin Amru, atau sering dipanggil juga dengan nama Mu'awiyah bin Amru. Sedangkan Abu Qilabah namanya adalah Abdullah bin Zaid Al Jarmi. Kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan selainnya beramal dengan hadits ini. Yaitu, seorang Imam (Khalifah) mempunyai hak untuk memberi pengampunan kepada siapa yang ia kehendaki dari orang-orang kafir yang tertawan, membunuhnya atau meminta tebusan. Tetapi sebagian ahli ilmu memilih untuk membunuh mereka daripada meminta tebusan. Al Auza'I berkata, \"Telah sampai kepadaku bahwa ayat ini: '(kamu boleh membebaskan mereka atau menerima tebusan..) -Qs. Muhammad: 4- telah dihapus oleh firman-Nya; '(Dan bunuhlah mereka di mana saja kamu jumpai mereka..) ' -Qs. Al Baqarah; 191- Seperti itulah Hannad menceritakan kepada kami, ia berkata; Ibnul Mubarak menceritakan kepada kami dari Al Auza'i. Ishaq bin Manshur berkata, \"Aku bertanya kepada Ahmad, \"Jika ada musuh yang tertawan, maka yang engkau sukai; dibunuh atau dibebaskan dengan tebusan?\" Ia menjawab, \"Jika mereka mampu memberi tebusan maka tidak apa-apa, dan jika dibunuh menurutku juga tidak apa-apa. Ishaq mengatakan; Musuh ditawan lebih aku sukai, "}],"2:5":[{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "}],"2:8":[{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "}],"2:10":[{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."},{"p":"Nasa'i","n":3510,"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عِمْرَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ كَانَ يَكُونُ فِي حَجْرِ الرَّجُلِ الْيَتِيمُ فَيَعْزِلُ لَهُ طَعَامَهُ وَشَرَابَهُ وَآنِيَتَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَإِنْ تُخَالِطُوهُمْ فَإِخْوَانُكُمْ }فِي الدِّينِ فَأَحَلَّ لَهُمْ خُلْطَتَهُمْ","trj":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Imran bin 'Uyainah] berkata; telah menceritakan kepada kami ['Atha bin As Saib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] mengenaii firman Allah: '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ia berkata, \"Dahulu terdapat seorang anak yatim dalam pemeliharaan seorang laki-laki, kemudian laki-laki tersebut menjauhi makanan serta minuman dan bejananya, sehingga hal tersebut terasa berat bagi orang-orang muslim. Kemudian Allah 'azza wajalla menurunkan ayat: '(dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu) ' (Qs. Al Baqarah: 220), yaitu seagama, maka Allah pun menghalalkan bagi mereka untuk bergaul dengan mereka.\""}],"2:16":[{"p":"Muslim","n":249,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَزُهَيْرُ بْنُ حَرْبٍ جَمِيعًا عَنْ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَلْفَاظُهُمْ مُتَقَارِبَةٌ قَالَ ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ طَلْحَةَ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتُهِيَ بِهِ إِلَى سِدْرَةِ الْمُنْتَهَى وَهِيَ فِي السَّمَاءِ السَّادِسَةِ إِلَيْهَا يَنْتَهِي مَا يُعْرَجُ بِهِ مِنْ الْأَرْضِ فَيُقْبَضُ مِنْهَا وَإِلَيْهَا يَنْتَهِي مَا يُهْبَطُ بِهِ مِنْ فَوْقِهَا فَيُقْبَضُ مِنْهَا قَالَ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ فَرَاشٌ مِنْ ذَهَبٍ قَالَ فَأُعْطِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا أُعْطِيَ الصَّلَوَاتِ الْخَمْسَ وَأُعْطِيَ خَوَاتِيمَ سُورَةِ الْبَقَرَةِ وَغُفِرَ لِمَنْ لَمْ يُشْرِكْ بِاللَّهِ مِنْ أُمَّتِهِ شَيْئًا الْمُقْحِمَاتُ","trj":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Malik bin Mighwal]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Ibnu Numair] dan [Zuhair bin Harb] semuanya dari [Abdullah bin Numair] dan lafazh mereka saling berdekatan. [Ibnu Numair] berkata, telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Malik bin Mighwal] dari [az-Zubair bin Adi] dari [Thalhah] dari [Murrah] dari [Abdullah] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam diisra'kan maka beliau dihentikan di Sidrah al-Muntaha, (yaitu tempat) yang terletak di langit keenam. Sesuatu yang naik dari bumi akan bermuara di sana dan ditahan padanya. Dan sesuatu dari atasnya berhenti padanya, lalu ditahan padanya.\" Allah berfirman: '(Muhammad melihat Jibril) ketika Sidratil Muntaha diliputi oleh sesuatu yang meliputinya) ' (Qs. An Najm: 16). Abdullah berkata lagi, \"Yaitu hamparan dari emas.\" Dia berkata lagi, \"Lalu Rasulullah shallallahu 'alaihi wasallam diberi tiga hal: shalat lima waktu, ayat-ayat penutup surat al-Baqarah, dan diampuni dosa-dosa besar milik orang yang tidak mensyirikkan Allah dengan sesuatu pun dari kalangan umat beliau.\""},{"p":"Nasa'i","n":446,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتُهِيَ بِهِ إِلَى سِدْرَةِ الْمُنْتَهَى وَهِيَ فِي السَّمَاءِ السَّادِسَةِ وَإِلَيْهَا يَنْتَهِي مَا عُرِجَ بِهِ مِنْ تَحْتِهَا وَإِلَيْهَا يَنْتَهِي مَا أُهْبِطَ بِهِ مِنْ فَوْقِهَا حَتَّى يُقْبَضَ مِنْهَا قَالَ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ فَرَاشٌ مِنْ ذَهَبٍ فَأُعْطِيَ ثَلَاثًا الصَّلَوَاتُ الْخَمْسُ وَخَوَاتِيمُ سُورَةِ الْبَقَرَةِ وَيُغْفَرُ لِمَنْ مَاتَ مِنْ أُمَّتِهِ لَا يُشْرِكُ بِاللَّهِ شَيْئًا الْمُقْحِمَاتُ","trj":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Yahya bin Adam] dia berkata; Telah menceritakan kepada kami [Malik bin Mighwal] dari [Zubair bin 'Adi] dari [Thalhah bin Musharrif] dari [Murrah] dari [Abdulah] dia berkata; \" Ketika Rasulullah shallallahu 'alaihi wasallam diisra'kan beliau sampai ke Sidratul Muntaha, yaitu satu tempat di langit yang ke enam dan sampai di situlah berakhirnya semua yang naik dari bawah dan sampai di situ pula semua yang turun dari atas hingga dapat terpegang. Nabi shallallahu 'alaihi wasallam kemudian membacakan ayat: \"Ketika Sidratul Muntaha diliputi oleh sesuatu yang meliputinya\" (Qs. An-Najm (53): 16) Rasulullah shallallahu 'alaihi wasallam bersabda: \" (Yang meliputi Sidratul Muntaha) adalah kupu-kupu dari emas, lalu aku diberi tiga hal, yaitu shalat lima waktu, akhir-akhir surat Al Baqarah, dan orang yang mati dari umatku diampuni, asalkan tidak menyekutukan Allah Azza Wa Jalla dengan sesuatupun.\" "},{"p":"Tirmidzi","n":3027,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا بَلَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِدْرَةَ الْمُنْتَهَى قَالَ انْتَهَى إِلَيْهَا مَا يَعْرُجُ مِنْ الْأَرْضِ وَمَا يَنْزِلُ مِنْ فَوْقٍ قَالَ فَأَعْطَاهُ اللَّهُ عِنْدَهَا ثَلَاثًا لَمْ يُعْطِهِنَّ نَبِيًّا كَانَ قَبْلَهُ فُرِضَتْ عَلَيْهِ الصَّلَاةُ خَمْسًا وَأُعْطِيَ خَوَاتِيمَ سُورَةِ الْبَقَرَةِ وَغُفِرَ لِأُمَّتِهِ الْمُقْحِمَاتُ مَا لَمْ يُشْرِكُوا بِاللَّهِ شَيْئًاقَالَ ابْنُ مَسْعُودٍ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ السِّدْرَةُ فِي السَّمَاءِ السَّادِسَةِ قَالَ سُفْيَانُ فَرَاشٌ مِنْ ذَهَبٍ وَأَشَارَ سُفْيَانُ بِيَدِهِ فَأَرْعَدَهَا و قَالَ غَيْرُ مَالِكِ بْنِ مِغْوَلٍ إِلَيْهَا يَنْتَهِي عِلْمُ الْخَلْقِ لَا عِلْمَ لَهُمْ بِمَا فَوْقَ ذَلِكَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Malik bin Mighwal] dari [Thalhah bin Musharrif] dari [Murrah] dari [Abdullah] berkata: Saat Rasulullah Shallallahu 'alaihi wa Salam sampai Shidratul Muntaha, beliau bersabda: \"Kesanalah berakhirnya sesuatu yang naik dari bumi dan yang turun dari atas.\" Lalu Allah memberi beliau tiga hal disana yang belum pernah diberikan kepada seorang nabi pun sebelum beliau; shalat lima waktu diwajibkan atas beliau, beiau diberi penutup-penutup surat al Baqarah dan dosa-dosa besar diampuni untuk ummatnya selama tidak menyekutukan Allah dengan sesuatu pun.\" Ibnu Mas'ud berkata: \"Ketika Sidratil Muntaha diliputi oleh sesuatu yang meliputinya.\" (An Najm: 16) ia berkata: Sidrah berada dilangit keenam. Sufyan berkata: Hamparan dari emas. Ia berisyarat dengan tangannya lalu menggoyang-goyangnya. Selain Malik bin Mighwal berkata: Disanalah berakhirnya ilmu makhluk, mereka tidak mengetahui apa yang ada diatasnya. Abu Isa berkata: Hadits ini hasan shahih."}],"2:18":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}],"2:25":[{"p":"Darimi","n":1130,"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَ حُبِسْنَا يَوْمَ الْخَنْدَقِ حَتَّى ذَهَبَ هَوِيٌّ مِنْ اللَّيْلِ حَتَّى كُفِينَا وَذَلِكَ قَوْلُ اللَّهِ تَعَالَى { وَكَفَى اللَّهُ الْمُؤْمِنِينَ الْقِتَالَ وَكَانَ اللَّهُ قَوِيًّا عَزِيزًا } فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالًا فَأَمَرَهُ فَأَقَامَ فَصَلَّى الظُّهْرَ فَأَحْسَنَ كَمَا كَانَ يُصَلِّيهَا فِي وَقْتِهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْعَصْرَ فَصَلَّاهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْمَغْرِبَ فَصَلَّاهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْعِشَاءَ فَصَلَّاهَا وَذَلِكَ قَبْلَ أَنْ يَنْزِلَ { فَإِنْ خِفْتُمْ فَرِجَالًا أَوْ رُكْبَانًا }","trj":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [Ayahnya] ia berkata, \"Kami tertahan pada saat perang Khandaq hingga berlalu sebagian malam hingga kami dihindarkan dari peperangan, dan hal tersebut sebagaimana yang Allah firmankan: '(Dan Allah menghindarkan orang-orang mukmin dari peperangan. Dan adalah Allah Maha Kuat lagi Maha Perkasa) ' (Qs.?Al Ahzab: 25). Kemudian Nabi shallallahu 'alaihi wasallam memanggil Bilal dan memerintahkannya agar mengumandangkan iqamah. Beliau lalu mengerjakan shalat Zhuhur dan melakukannya dengan baik sebagaimana biasa beliau melakukannya pada waktunya, kemudian memerintahkannya untuk mengumandangkan iqamah shalat Asar, lalu beliau mengerjakan shalat Asar. Kemudian memerintahkannya untuk mengumandangkan iqamah shalat Maghrib, lalu beliau mengerjakan shalat Maghrib, kemudian memerintahkannya untuk mengumandangkan iqamah shalat Isya, lalu beliau mengerjakan shalat Isya. Dan itu sebelum turunnya ayat: '(Jika kamu dalam keadaan takut (bahaya), maka shalatlah sambil berjalan atau berkendaraan…) ' (QS. Al Baqarah: 139)."}],"2:34":[{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."}],"2:39":[{"p":"Nasa'i","n":3350,"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ أَنْبَأَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ }وَقَالَ{ وَاللَّائِي يَئِسْنَ مِنْ الْمَحِيضِ مِنْ نِسَائِكُمْ إِنْ ارْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَاثَةُ أَشْهُرٍ }فَنُسِخَ مِنْ ذَلِكَ قَالَ تَعَالَى وَإِنْ{ طَلَّقْتُمُوهُنَّ مِنْ قَبْلِ أَنْ تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ali bin Al Husain bin Waqid] ia berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah memberitakan kepada kami [Yazid bin An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai ayat: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 101), dan firman Allah '(menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh (hapus) dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru') ', (Qs. Al Baqarah: 228). Dan firman: '(Dan perempuan-perempuan yang tidak haid lagi (monopause) di antara perempuan-perempuanmu jika kamu ragu-ragu (tentang masa iddahnya), Maka masa iddah mereka adalah tiga bulan) ' (Qs. Ath Thallaaq: 40), lalu dinasakh dari hal tersebut, firman Allah Ta'ala: '(Kemudian kamu ceraikan mereka sebelum kamu mencampurinya Maka sekali-sekali tidak wajib atas mereka 'iddah bagimu yang kamu minta menyempurnakannya) ' (Qs. Al Ahzaab: 49)."},{"p":"Nasa'i","n":3398,"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ إِلَى قَوْلِهِ إِنْ أَرَادُوا إِصْلَاحًا }وَذَلِكَ بِأَنَّ الرَّجُلَ كَانَ إِذَا طَلَّقَ امْرَأَتَهُ فَهُوَ أَحَقُّ بِرَجْعَتِهَا وَإِنْ طَلَّقَهَا ثَلَاثًا فَنَسَخَ ذَلِكَ وَقَالَ{ الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman Allah: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 1o1), dan firman Allah: '(Allah menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru'. Tidak boleh mereka menyembunyikan apa yang diciptakan Allah dalam rahimnya, jika mereka beriman kepada Allah dan hari akhirat. Dan suami-suaminya berhak merujukinya dalam masa menanti itu, jika mereka (para suami) menghendaki ishlah) ' (Qs. Al Baqarah: 228). Hal itu karena jika seorang laki-laki mencerai isterinya, maka ia lebih berhak untuk kembali kepadanya walaupun telah mencerainya tiga kali, kemudian Allah menghapus hal tersebut dan berfirman: '(Talak (yang dapat dirujuki) dua kali. Setelah itu boleh rujuk lagi dengan cara yang ma'ruf atau menceraikan dengan cara yang baik) ' (Qs. Al Baqarah: 229)."}],"2:40":[{"p":"Nasa'i","n":3350,"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ أَنْبَأَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ }وَقَالَ{ وَاللَّائِي يَئِسْنَ مِنْ الْمَحِيضِ مِنْ نِسَائِكُمْ إِنْ ارْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَاثَةُ أَشْهُرٍ }فَنُسِخَ مِنْ ذَلِكَ قَالَ تَعَالَى وَإِنْ{ طَلَّقْتُمُوهُنَّ مِنْ قَبْلِ أَنْ تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ali bin Al Husain bin Waqid] ia berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah memberitakan kepada kami [Yazid bin An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai ayat: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 101), dan firman Allah '(menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh (hapus) dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru') ', (Qs. Al Baqarah: 228). Dan firman: '(Dan perempuan-perempuan yang tidak haid lagi (monopause) di antara perempuan-perempuanmu jika kamu ragu-ragu (tentang masa iddahnya), Maka masa iddah mereka adalah tiga bulan) ' (Qs. Ath Thallaaq: 40), lalu dinasakh dari hal tersebut, firman Allah Ta'ala: '(Kemudian kamu ceraikan mereka sebelum kamu mencampurinya Maka sekali-sekali tidak wajib atas mereka 'iddah bagimu yang kamu minta menyempurnakannya) ' (Qs. Al Ahzaab: 49)."}],"2:41":[{"p":"Abu Dawud","n":3109,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيِّ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }وَ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ وَمَنَافِعُ لِلنَّاسِ }نَسَخَتْهُمَا الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا الْخَمْرُ وَالْمَيْسِرُ وَالْأَنْصَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepada kami [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia membaca: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…) ' (Qs. An Nisaa`: 41). Dan ayat: '(Mereka bertanya kepadamu tentang khamer dan judi. Katakanlah: \"Pada keduanya terdapat dosa yang besar dan beberapa manfaat bagi manusia.....) ' (Qs. Al Baqarah: 219), ia berkata, \"Kedua ayat tersebut dihapus dan digantikan oleh ayat yang terdapat dalam Surat Al Maaidah: 91: '(Sesungguhnya (meminum) khamar, berjudi, (berkorban untuk) berhala…) '. "}],"2:43":[{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."}],"2:46":[{"p":"Bukhari","n":4304,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ وَأَخْبَرَنِي يُوسُفُ بْنُ مَاهَكٍ قَالَإِنِّي عِنْدَ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا إِذْ جَاءَهَا عِرَاقِيٌّ فَقَالَ أَيُّ الْكَفَنِ خَيْرٌ قَالَتْ وَيْحَكَ وَمَا يَضُرُّكَ قَالَ يَا أُمَّ الْمُؤْمِنِينَ أَرِينِي مُصْحَفَكِ قَالَتْ لِمَ قَالَ لَعَلِّي أُوَلِّفُ الْقُرْآنَ عَلَيْهِ فَإِنَّهُ يُقْرَأُ غَيْرَ مُؤَلَّفٍ قَالَتْ وَمَا يَضُرُّكَ أَيَّهُ قَرَأْتَ قَبْلُ إِنَّمَا نَزَلَ أَوَّلَ مَا نَزَلَ مِنْهُ سُورَةٌ مِنْ الْمُفَصَّلِ فِيهَا ذِكْرُ الْجَنَّةِ وَالنَّارِ حَتَّى إِذَا ثَابَ النَّاسُ إِلَى الْإِسْلَامِ نَزَلَ الْحَلَالُ وَالْحَرَامُ وَلَوْ نَزَلَ أَوَّلَ شَيْءٍ لَا تَشْرَبُوا الْخَمْرَ لَقَالُوا لَا نَدَعُ الْخَمْرَ أَبَدًا وَلَوْ نَزَلَ لَا تَزْنُوا لَقَالُوا لَا نَدَعُ الزِّنَا أَبَدًا لَقَدْ نَزَلَ بِمَكَّةَ عَلَى مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنِّي لَجَارِيَةٌ أَلْعَبُ{ بَلْ السَّاعَةُ مَوْعِدُهُمْ وَالسَّاعَةُ أَدْهَى وَأَمَرُّ }وَمَا نَزَلَتْ سُورَةُ الْبَقَرَةِ وَالنِّسَاءِ إِلَّا وَأَنَا عِنْدَهُ قَالَ فَأَخْرَجَتْ لَهُ الْمُصْحَفَ فَأَمْلَتْ عَلَيْهِ آيَ السُّوَرِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka, ia berkata; Dan Telah mengabarkan kepadaku [Yusuf bin Mahik] ia berkata; Suatu ketika, aku berada di tempat Aisyah Ummul Mukminin radliallahu 'anha, tiba-tiba seorang dari Irak menemuinya seraya berkata, \"Kain kafan yang bagaimanakah yang lebih baik?\" Aisyah menjawab, \"Huss kamu, apakah yang menimpamu?\" laki-laki itu berkata, \"Wahai Ummul Mukminin, tunjukkanlah Mushhaf Anda padaku.\" [Aisyah] bertanya, \"Untuk apa?\" Ia menjawab, \"Agar aku dapat menyusunnya. Sebab, Al Qur`an itu dibaca secara tidak tersusun.\" Aisyah berkata, \"Lalu apa yang menghalangimu untuk membaca bagian apa saja darinya. Sesungguhnya yang pertama-tama kali turun darinya adalah surat Al Mufashshal yang di dalamnya disebutkan tentang surga dan neraka. Dan ketika manusia telah condong ke Islam, maka turunlah kemudian ayat-ayat tentang halal dan haram. Sekiranya yang pertama kali turun adalah ayat, 'Janganlah kalian minum khamer.' Niscaya mereka akan mengatakan, 'Sekali-kali kami tidak akan bisa meninggalkan khamer selama-lamanya.' Dan sekiranya juga yang pertamakali turun adalah ayat, \"Janganlah kalian berzina..' niscaya mereka akan berkomentar, 'Kami tidak akan meniggalkan zina selama-lamanya.' Ayat yang diturunkan kepada Rasulullah shallallahu 'alaihi wasallam di Makkah yang pada saat itu aku masih anak-anak adalah: 'BAL AS SAA'ATU MAU'IDUHUM WAS SAA'ATU ADHAA WA AMARR.(QS. ALqamar 46).' Dan tidaklah surat Al Baqarah dan An Nisa` kecuali aku berada di sisi beliau.\" Akhirnya, Aisyah mengeluarkan Mushhaf dan mendiktekan kepada orang Irak itu beberapa surat."}],"2:49":[{"p":"Nasa'i","n":3350,"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ أَنْبَأَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ }وَقَالَ{ وَاللَّائِي يَئِسْنَ مِنْ الْمَحِيضِ مِنْ نِسَائِكُمْ إِنْ ارْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَاثَةُ أَشْهُرٍ }فَنُسِخَ مِنْ ذَلِكَ قَالَ تَعَالَى وَإِنْ{ طَلَّقْتُمُوهُنَّ مِنْ قَبْلِ أَنْ تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ali bin Al Husain bin Waqid] ia berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah memberitakan kepada kami [Yazid bin An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai ayat: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 101), dan firman Allah '(menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh (hapus) dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru') ', (Qs. Al Baqarah: 228). Dan firman: '(Dan perempuan-perempuan yang tidak haid lagi (monopause) di antara perempuan-perempuanmu jika kamu ragu-ragu (tentang masa iddahnya), Maka masa iddah mereka adalah tiga bulan) ' (Qs. Ath Thallaaq: 40), lalu dinasakh dari hal tersebut, firman Allah Ta'ala: '(Kemudian kamu ceraikan mereka sebelum kamu mencampurinya Maka sekali-sekali tidak wajib atas mereka 'iddah bagimu yang kamu minta menyempurnakannya) ' (Qs. Al Ahzaab: 49)."}],"2:52":[{"p":"Muslim","n":1141,"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْفَزَارِيُّ يَعْنِي مَرْوَانَ بْنَ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ حَكِيمٍ الْأَنْصَارِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }الْآيَةَ الَّتِي فِي الْبَقَرَةِ وَفِي الْآخِرَةِ مِنْهُمَا{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Fazari yaitu Marwan bin Muawiyah] dari [Utsman bin Hakim Al Anshari], katanya; telah menceritakan kepadaku [Said bin Yasar] bahwa [Ibnu Abbas] mengabarinya; bahwa dalam dua raka'at fajar, tepatnya di raka'at pertama, Rasulullah shallallahu 'alaihi wasallam membaca \"Katakanlah, kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" QS. Albaqarah 136, dan pada rakaat kedua membaca \"Kami beriman kepada Allah, dan saksikanlah bahwa kami orang muslim.\" QS. Ali Imran 52."}],"2:54":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}],"2:58":[{"p":"Bukhari","n":3094,"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لِبَنِي إِسْرَائِيلَ{ ادْخُلُوا الْبَابَ سُجَّدًا وَقُولُوا حِطَّةٌ }فَبَدَّلُوا فَدَخَلُوا يَزْحَفُونَ عَلَى أَسْتَاهِهِمْ وَقَالُوا حَبَّةٌ فِي شَعْرَةٍ","trj":"Telah bercerita kepadaku [Ishaq bin Nashr] telah bercerita kepada kami ['Abdur Razzaq] dari [Ma'mar] dari [Hammam bin Munabbih] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dikatakan kepada Bani Isra'il, (\"masuklah kalian ke dalam pintu gerbang sambil bersujud dan katakanlah; bebaskanlah kami dari dosa\"), (QS al-Baqarah ayat 58). Namun mereka menukarnya dan masuk sambil merayap di atas pantat mereka sambil berkata: \"buah gandum\""}],"2:59":[{"p":"Tirmidzi","n":2811,"ar":"وَبِهَذَا الْإِسْنَادِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ فَبَدَّلَ الَّذِينَ ظَلَمُوا قَوْلًا غَيْرَ الَّذِي قِيلَ لَهُمْ }قَالَ قَالُوا حَبَّةٌ فِي شَعْرَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Dan dengan sanad ini (Yaitu; Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah]) dari Nabi shallallahu 'alaihi wasallam: \"Lalu orang-orang yang zhalim mengganti perintah dengan (mengerjakan) yang tidak diperintahkan kepada mereka.\" QS Al-Baqarah: 59, Beliau bersabda: \"Mereka berkata; biji dalam rambut.\" Abu Isa berkata; Hadits ini hasan shahih."}],"2:63":[{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "}],"2:91":[{"p":"Abu Dawud","n":3107,"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى الْخُتَّلِيُّ أَخْبَرَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرٍو عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ }الْآيَةَ قَالَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَكَانَ مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ يُنَادِي أَلَا لَا يَقْرَبَنَّ الصَّلَاةَ سَكْرَانُ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَهَلْ أَنْتُمْ مُنْتَهُونَ }قَالَ عُمَرُ انْتَهَيْنَا","trj":"Telah menceritakan kepada kami ['Abbad bin Musa Al Khuttali] telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Israil] dari [Abu Ishaq] dari ['Amru] dari [Umar bin Al Khathab] ia berkata, \"Tatkala telah turun pengharaman arak Umar berkata, \"Ya Allah, jelaskan kepada kami mengenai arak dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat dalam Surat Al Baqarah (219): '(Mereka bertanya kepadamu tentang khamer dan judi…) '. 'Ammar berkata, \"Kemudian Umar dipanggil dan dibacakan kepadanya ayat tersebut, ia berkata lagi, \"Ya Allah, jelaskan kepada kami mengenai khamer dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat pada Surat An Nisaa` (41): '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…..) ' Penyeru Rasulullah shallallahu 'alaihi wasallam apabila shalat telah ditegakkan maka ia berseru, 'ketahuilah bahwa tidak boleh orang yang mabuk mendekati shalat! ' Kemudian Umar dipanggil dan dibacakanlah ayat tersebut kepadanya, lalu ia berkata, \"Ya Allah jelaskanlah kepada kami mengenai khamer dengan penjelasan yang memuaskan!\" Maka turunlah ayat ini: '(….. apakah kalian akan berhenti?) ' (Qs. Al Maa`idah: 91) Umar berkata, \"Kami telah berhenti.\""},{"p":"Abu Dawud","n":3109,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيِّ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }وَ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ وَمَنَافِعُ لِلنَّاسِ }نَسَخَتْهُمَا الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا الْخَمْرُ وَالْمَيْسِرُ وَالْأَنْصَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepada kami [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia membaca: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…) ' (Qs. An Nisaa`: 41). Dan ayat: '(Mereka bertanya kepadamu tentang khamer dan judi. Katakanlah: \"Pada keduanya terdapat dosa yang besar dan beberapa manfaat bagi manusia.....) ' (Qs. Al Baqarah: 219), ia berkata, \"Kedua ayat tersebut dihapus dan digantikan oleh ayat yang terdapat dalam Surat Al Maaidah: 91: '(Sesungguhnya (meminum) khamar, berjudi, (berkorban untuk) berhala…) '. "},{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."}],"2:92":[{"p":"Tirmidzi","n":2822,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }أَوْ{ مَنْ ذَا الَّذِي يُقْرِضُ اللَّهَ قَرْضًا حَسَنًا }قَالَ أَبُو طَلْحَةَ وَكَانَ لَهُ حَائِطٌ فَقَالَ يَا رَسُولَ اللَّهِ حَائِطِي لِلَّهِ وَلَوْ اسْتَطَعْتُ أَنْ أُسِرَّهُ لَمْ أُعْلِنْهُ فَقَالَ اجْعَلْهُ فِي قَرَابَتِكَ أَوْ أَقْرَبِيكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكِ","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdullah bin Bakr As Sahmani] telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata; \"Ketika turun ayat Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebahagian harta yang kamu cintai.\" QS Ali 'Imran: 92 atau Siapakah yang mau memberi pinjaman kepada Allah, pinjaman yang baik (menafkahkan hartanya di jalan Allah). QS Al-Baqarah: 245, kemudian Abu Thalhah, yang memiliki kebun berkata; \"Wahai Rasulullah, saya (infakkan) kebun saya ini di jalan Allah. Dan sekiranya saya mampu untuk menyembunyikannya tentu saya tidak menyatakannya. lalu beliau mengatakan \"Berikanlah kepada kerabat atau orang yang terdekat denganmu!\" Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan [Malik bin Anas] telah meriwayatkan dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] "}],"2:101":[{"p":"Nasa'i","n":3350,"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ أَنْبَأَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ }وَقَالَ{ وَاللَّائِي يَئِسْنَ مِنْ الْمَحِيضِ مِنْ نِسَائِكُمْ إِنْ ارْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَاثَةُ أَشْهُرٍ }فَنُسِخَ مِنْ ذَلِكَ قَالَ تَعَالَى وَإِنْ{ طَلَّقْتُمُوهُنَّ مِنْ قَبْلِ أَنْ تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ali bin Al Husain bin Waqid] ia berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah memberitakan kepada kami [Yazid bin An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai ayat: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 101), dan firman Allah '(menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh (hapus) dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru') ', (Qs. Al Baqarah: 228). Dan firman: '(Dan perempuan-perempuan yang tidak haid lagi (monopause) di antara perempuan-perempuanmu jika kamu ragu-ragu (tentang masa iddahnya), Maka masa iddah mereka adalah tiga bulan) ' (Qs. Ath Thallaaq: 40), lalu dinasakh dari hal tersebut, firman Allah Ta'ala: '(Kemudian kamu ceraikan mereka sebelum kamu mencampurinya Maka sekali-sekali tidak wajib atas mereka 'iddah bagimu yang kamu minta menyempurnakannya) ' (Qs. Al Ahzaab: 49)."}],"2:106":[{"p":"Ahmad","n":2893,"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُعَلِيٌّ أَقْضَانَا وَأُبَيٌّ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ كَثِيرًا مِنْ لَحْنِ أُبَيٍّ وَأُبَيٌّ يَقُولُ سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدَعُهُ لِشَيْءٍ وَاللَّهُ تَبَارَكَ وَتَعَالَى يَقُولُ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }","trj":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \" [Umar] radliallahu 'anhu berkata, \"Ali adalah orang yang paling paham dengan hukum di antara kami dan Ubai adalah orang yang paling pandai dalam membaca Al-Qur'an di antara kami, sementara kami banyak meninggalkan qira`ah Ubay (dalam membaca Al-Qur'an). [Ubay] pernah berkata, \"Aku telah mendengar dari Rasulullah shallallahu 'alaihi wasallam, maka aku tidak akan meninggalkannya karena sesuatu. Allah Tabaraka Wa Ta'ala berfirman: '(Ayat mana saja yang kami nasakhkan, atau kami jadikan (manusia) lupa kepadanya, kami datangkan yang lebih baik daripadanya atau yang sebanding dengannya) ' (QS. Al Baqarah: 106)."},{"p":"Ahmad","n":2894,"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ حَدَّثَنِي حَبِيبٌ يَعْنِي ابْنَ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ قَالَ عُمَرُعَلِيٌّ أَقْضَانَا وَأُبَيٌّ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ مِنْ قَوْلِ أُبَيٍّ وَأُبَيٌّ يَقُولُ أَخَذْتُ مِنْ فَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدَعُهُ وَاللَّهُ يَقُولُ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا }","trj":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] telah menceritakan kepadaku [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu berkata, \" [Umar]? radliallahu 'anhu berkata, \"Ali adalah orang yang paling paham dengan hukum di antara kami dan Ubai adalah orang yang paling pandai dalam membaca Al-Qur'an di antara kami, sementara kami telah meninggalkan qira`ah (bacaan Al-Qur'an) Ubay. Dan [Ubay] berkata, \"Aku mengambilnya dari mulut Rasulullah shallallahu 'alaihi wasallam, maka aku tidak akan meninggalkanya karena sesuatu apapun, dan Allah Tabaraka Wa Ta'ala berfirman: '(Ayat mana saja yang kami nasakhkan, atau kami jadikan (manusia) lupa kepadanya..) ' (QS. Al Baqarah: 106)."},{"p":"Bukhari","n":3816,"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُأَقْرَؤُنَا أُبَيٌّ وَأَقْضَانَا عَلِيٌّ وَإِنَّا لَنَدَعُ مِنْ قَوْلِ أُبَيٍّ وَذَاكَ أَنَّ أُبَيًّا يَقُولُ لَا أَدَعُ شَيْئًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ قَالَ اللَّهُ تَعَالَى{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا }","trj":"Telah menceritakan kepada kami ['Amru bin 'Ali] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Sufyan] dari [Habib] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; ['Umar radliallahu 'anhu] berkata; \"Ubay adalah orang yang paling pandai dalam membaca Al Qur'an di antara kami, dan Ali adalah orang yang paling paham dengan hukum di antara kami. Sementara kami banyak meninggalkan qira`ah Ubay (dalam membaca Al Qur'an). Karena [Ubay] pernah berkata, \"Aku tidak akan meninggalkan sesuatu yang telah aku dengar dari Rasulullah. Sementara Allah Tabaraka Wa Ta'ala berfirman: '(Ayat mana saja yang kami nasakhkan, atau kami jadikan (manusia) lupa kepadanya, kami datangkan yang lebih baik daripadanya atau yang sebanding dengannya) ' (QS. Al Baqarah: 106)."},{"p":"Bukhari","n":4316,"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُأُبَيٌّ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ مِنْ لَحَنِ أُبَيٍّ وَأُبَيٌّ يَقُولُ أَخَذْتُهُ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَتْرُكُهُ لِشَيْءٍ قَالَ اللَّهُ تَعَالَى{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }","trj":"Telah menceritakan kepada kami [Shadaqah bin Al Fadll] Telah mengabarkan kepada kami [Yahya] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, [Umar] berkata, \"Orang yang paling baik bacaannya di antara kita adalah Ubbay, dan kita akan meninggalkan Qira`ah Ubay.\" Maka [Ubay] pun berkata, \"Aku telah mengambilnya langsung dari bibir Rasulullah shallallahu 'alaihi wasallam, karena itu aku tidak akan meninggalkannya lantaran karena suatu masalah. Allah Ta'ala berfirman: 'MAA NANSAKH MIN `AAYATIN AW NUNSIKHA NA`TI BIKHAIR MINHAA AW MITSLIHAA (Tidaklah kami menghapus suatu ayat pun, atau ayat itu dihapus, kecuali kami akan menggantinya dengan yang lebih baik darinya atau semisalnya). (QS. Albaqarah 106).'\""},{"p":"Nasa'i","n":3350,"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ أَنْبَأَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ }وَقَالَ{ وَاللَّائِي يَئِسْنَ مِنْ الْمَحِيضِ مِنْ نِسَائِكُمْ إِنْ ارْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَاثَةُ أَشْهُرٍ }فَنُسِخَ مِنْ ذَلِكَ قَالَ تَعَالَى وَإِنْ{ طَلَّقْتُمُوهُنَّ مِنْ قَبْلِ أَنْ تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ali bin Al Husain bin Waqid] ia berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah memberitakan kepada kami [Yazid bin An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai ayat: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 101), dan firman Allah '(menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh (hapus) dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru') ', (Qs. Al Baqarah: 228). Dan firman: '(Dan perempuan-perempuan yang tidak haid lagi (monopause) di antara perempuan-perempuanmu jika kamu ragu-ragu (tentang masa iddahnya), Maka masa iddah mereka adalah tiga bulan) ' (Qs. Ath Thallaaq: 40), lalu dinasakh dari hal tersebut, firman Allah Ta'ala: '(Kemudian kamu ceraikan mereka sebelum kamu mencampurinya Maka sekali-sekali tidak wajib atas mereka 'iddah bagimu yang kamu minta menyempurnakannya) ' (Qs. Al Ahzaab: 49)."},{"p":"Nasa'i","n":3398,"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ إِلَى قَوْلِهِ إِنْ أَرَادُوا إِصْلَاحًا }وَذَلِكَ بِأَنَّ الرَّجُلَ كَانَ إِذَا طَلَّقَ امْرَأَتَهُ فَهُوَ أَحَقُّ بِرَجْعَتِهَا وَإِنْ طَلَّقَهَا ثَلَاثًا فَنَسَخَ ذَلِكَ وَقَالَ{ الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman Allah: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 1o1), dan firman Allah: '(Allah menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru'. Tidak boleh mereka menyembunyikan apa yang diciptakan Allah dalam rahimnya, jika mereka beriman kepada Allah dan hari akhirat. Dan suami-suaminya berhak merujukinya dalam masa menanti itu, jika mereka (para suami) menghendaki ishlah) ' (Qs. Al Baqarah: 228). Hal itu karena jika seorang laki-laki mencerai isterinya, maka ia lebih berhak untuk kembali kepadanya walaupun telah mencerainya tiga kali, kemudian Allah menghapus hal tersebut dan berfirman: '(Talak (yang dapat dirujuki) dua kali. Setelah itu boleh rujuk lagi dengan cara yang ma'ruf atau menceraikan dengan cara yang baik) ' (Qs. Al Baqarah: 229)."}],"2:111":[{"p":"Nasa'i","n":933,"ar":"أَخْبَرَنِي عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا الْآيَةَ الَّتِي فِي الْبَقَرَةِ{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }إِلَى آخِرِ الْآيَةِ وَفِي الْأُخْرَى{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] dia berkata; Telah menceritakan kepada kami [Utsman bin Hakim] dia berkata; Telah mengabarkan kepadaku [Sa'id bin Yasar] bahwa [Ibnu Abbas] Telah mengabarkan kepadanya, Rasulullah Shallallallahu'alaihi wasallam membaca (ayat) pada dua rakaat shalat Subuh. Pada rakaat pertama beliau membaca ayat dalam surat Al Baqarah, \"Katakanlah (Hai orang-orang mukmin), 'Kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" (Qs. Al Baqarah (2): 136) sampai akhir ayat tersebut, sedangkan pada rakaat kedua beliau membaca, \"Kami telah beriman dan saksikanlah (wahai rasul) bahwa sesungguhnya kami adalah orang-orang yang patut (kepada seruanmu) (Qs. Al Maa'idah (5): 111).\""}],"2:115":[{"p":"Tirmidzi","n":2812,"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَشْعَثُ السَّمَّانُ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فِي لَيْلَةٍ مُظْلِمَةٍ فَلَمْ نَدْرِ أَيْنَ الْقِبْلَةُ فَصَلَّى كُلُّ رَجُلٍ مِنَّا عَلَى حِيَالِهِ فَلَمَّا أَصْبَحْنَا ذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَشْعَثَ السَّمَّانِ أَبِي الرَّبِيعِ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ وَأَشْعَثُ يُضَعَّفُ فِي الْحَدِيثِ","trj":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Asy'ats As Samman] dari ['Ashim bin 'Ubaidullah] dari [Abdullah bin 'Amir bin Rabi'ah] dari [Ayahnya] ia berkata; Kami bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan di malam yang gelap, kami tidak tahu mana kiblat, masing-masing dari kami shalat menghadap sesuai arahnya. Di pagi harinya, kami menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, lalu turunlah ayat: \"Maka kemanapun kamu menghadap di situlah wajah Allah.\" QS Al-Baqarah: 115"},{"p":"Tirmidzi","n":2813,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ قَال سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ تَطَوُّعًا أَيْنَمَا تَوَجَّهَتْ بِهِ وَهُوَ جَاءٍ مِنْ مَكَّةَ إِلَى الْمَدِينَةِثُمَّ قَرَأَ ابْنُ عُمَرَ هَذِهِ الْآيَةَ{ وَلِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ }الْآيَةَ فَقَالَ ابْنُ عُمَرَ فَفِي هَذَا أُنْزِلَتْ هَذِهِ الْآيَةُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى عَنْ قَتَادَةَ أَنَّهُ قَالَ فِي هَذِهِ الْآيَةِ{ وَلِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ قَتَادَةُ هِيَ مَنْسُوخَةٌ نَسَخَهَا قَوْلُهُ{ فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }أَيْ تِلْقَاءَهُ حَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ وَيُرْوَى عَنْ مُجَاهِدٍ فِي هَذِهِ الْآيَةِ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ فَثَمَّ قِبْلَةُ اللَّهِ حَدَّثَنَا بِذَلِكَ أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ النَّضْرِ بْنِ عَرَبِيٍّ عَنْ مُجَاهِدٍ بِهَذَا","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Abdul Malik bin Abu Sulaiman] ia berkata; Aku mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Umar] ia berkata; Nabi shallallahu 'alaihi wasallam pernah shalat sunnah di atas kendaraan beliau kemana pun kendaraan beliau menghadap, ketika itu beliau pergi dari Makkah menuju Madinah. Setelah itu Ibnu Umar membaca ayat ini: \"Dan kepunyaan Allah-lah timur dan barat.\" QS Al-Baqarah: 115. Ibnu Umar berkata; \"Berkenaan dengan peristiwa itulah, ayat ini turun.\" Abu Isa berkata; Hadits ini hasan shahih. Diriwayatkan dari Qatadah, ia berkata tentang ayat ini: Dan kepunyaan Allah-lah timur dan barat, maka kemanapun kamu menghadap di situlah wajah Allah.\" QS Al-Baqarah: 115 Qatadah berkata; Ayat ini mansukhah, dinasakh dengan firman Allah, \"Palingkanlah mukamu ke arah Masjidil Haram.\" QS Al-Baqarah: 144 yaitu arahnya. Telah menceritakan kepada kami yang demikian itu Muhammad bin Abdul Malik bin Abu Asy Syawarib, telah menceritakan kepada kami Yazid bin Zurai' dari Sa'id dari Qatadah. Dan diriwayatkan pula dari Mujahid tentang ayat ini: \"Maka kemanapun kamu menghadap, di situlah wajah Allah.\" QS Al-Baqarah: 115, ia berkata; \"Di sanalah kiblat Allah.\" Telah menceritakan kepada kami seperti itu Muhammad bin Al Ala` telah menceritakan kepada kami Waki' dari An Nadlr bin Arabi dari Mujahid seperti itu."}],"2:116":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}],"2:124":[{"p":"Muslim","n":797,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ شَهْرًا حَتَّى نَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ{ وَحَيْثُ مَا كُنْتُمْ فَوَلُّوا وُجُوهَكُمْ شَطْرَهُ }فَنَزَلَتْ بَعْدَمَا صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَ رَجُلٌ مِنْ الْقَوْمِ فَمَرَّ بِنَاسٍ مِنْ الْأَنْصَارِ وَهُمْ يُصَلُّونَ فَحَدَّثَهُمْ فَوَلَّوْا وُجُوهَهُمْ قِبَلَ الْبَيْتِ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] telah menceritakan kepada kami [Abu al-Ahwash] dari [Abu Ishaq] dari [al-Bara' bin 'Azib] dia berkata, \"Aku shalat bersama Nabi Shallallahu'alaihiwasallam menghadap Baitul Maqdis selama enam belas bulan hingga turun ayat tersebut yang ada dalam surat al-Baqarah, \"Dan di mana pun kamu berada maka palingkanlah wajah-wajahmu ke arahnya.\" (QS.Albaqarah 124), ayat tersebut turun setelah Nabi Shallallahu'alaihiwasallam shalat, lalu seorang laki-laki dari suatu kaum bertolak pergi, lalu dia berjalan bersama beberapa manusia dari kalangan Anshar, dan mereka shalat, lalu beliau menceritakannya kepada mereka, maka mereka menghadapkan wajah-wajah mereka ke Baitullah.\""}],"2:125":[{"p":"Abu Dawud","n":3370,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ ح و حَدَّثَنَا نَصْرُ بْنُ عَاصِمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }","trj":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Hatim bin Isma'il]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Nashr bin 'Ashim] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ja'far bin Muhammad] dari [Ayahnya] dan [Jabir] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam membaca ayat: '(Dan jadikanlah sebahagian maqam Ibrahim tempat shalat) ' (Qs. Al Baqarah: 125). "},{"p":"Bukhari","n":387,"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُوَافَقْتُ رَبِّي فِي ثَلَاثٍ فَقُلْتُ يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْنَا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى فَنَزَلَتْ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }وَآيَةُ الْحِجَابِ قُلْتُ يَا رَسُولَ الل��َهِ لَوْ أَمَرْتَ نِسَاءَكَ أَنْ يَحْتَجِبْنَ فَإِنَّهُ يُكَلِّمُهُنَّ الْبَرُّ وَالْفَاجِرُ فَنَزَلَتْ آيَةُ الْحِجَابِ وَاجْتَمَعَ نِسَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغَيْرَةِ عَلَيْهِ فَقُلْتُ لَهُنَّ{ عَسَى رَبُّهُ إِنْ طَلَّقَكُنَّ أَنْ يُبَدِّلَهُ أَزْوَاجًا خَيْرًا مِنْكُنَّ }فَنَزَلَتْ هَذِهِ الْآيَةُقَالَ أَبُو عَبْد اللَّهِ و حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ قَالَ حَدَّثَنِي حُمَيْدٌ قَالَ سَمِعْتُ أَنَسًا بِهَذَا","trj":"Telah menceritakan kepada kami ['Amru bin 'Aun] berkata, telah menceritakan kepada kami [Husyaim] dari [Humaid] dari [Anas bin Malik] berkata, ['Umar bin Al Khaththab], \"Aku memiliki pemikiran yang aku ingin jika itu dikabulkan oleh Rabbku dalam tiga persoalan. Maka aku sampaikan kepada Rasulullah shallallahu 'alaihi wasallam, 'Wahai Rasulullah, seandainya Maqam Ibrahim kita jadikan sebagai tempat shalat? Lalu turunlah ayat: '(Dan jadikanlah sebahagian maqam Ibrahim sebagai tempat shalat) ' (Qs. Al Baqarah: 125). Yang kedua tentang hijab. Aku lalu berkata, 'Wahai Rasulullah, seandainya Tuan perintahkan isteri-isteri Tuan untuk berhijab karena yang berkomunikasi dengan mereka ada orang yang shalih dan juga ada yang fajir (suka bermaksiat).' Maka turunlah ayat hijab. Dan yang ketiga, saat isteri-isteri beliau cemburu kepada beliau (sehingga banyak yang membangkang), aku katakan kepada mereka, 'Semoga bila Beliau menceraikan kalian Rabbnya akan menggantinya dengan isteri-isteri yang lebih baik dari kalian.' Maka turunlah ayat tentang masalah ini.\" Abu Abdullah berkata; telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah mengabarkan kepada kami [Yahya bin Ayyub] berkata, telah menceritakan kepadaku [Humaid] ia berkata, Aku mendengar [Anas] seperti hadits ini.\""},{"p":"Ibnu Majah","n":2916,"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍأَنَّهُ لَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ طَوَافِ الْبَيْتِ أَتَى مَقَامَ إِبْرَاهِيمَ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ هَذَا مَقَامُ أَبِينَا إِبْرَاهِيمَ الَّذِي قَالَ اللَّهُ سُبْحَانَهُ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ الْوَلِيدُ فَقُلْتُ لِمَالِكٍ هَكَذَا قَرَأَهَا{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ نَعَمْ","trj":"Telah menceritakan kepada kami [Al 'Abbas bin 'Utsman Ad Dimasyqi]; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Malik bin Anas] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir] radliallahu 'anhu, ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam selesai melaksanakan Thawaf di Baitullah, maka beliau mendatangi Maqam Ibrahim. Kemudian 'Umar radliallahu 'anhu bertanya; 'Wahai Rasulullah, apakah ini maqam bapak kita (Ibrahim 'Alaihis Salam) yang Allah Subhanahu Wa Ta'ala telah sebutkan dalam firman-Nya: 'Dan jadikanlah sebagian dari Maqam Ibrahim sebagai tempat shalat.' (Qs. Al Baqarah 2:125)\" Al Walid berkata; 'Aku bertanya kepada Malik; 'Beginikah Umar membacanya; 'Dan jadikanlah sebagian dari Maqam Ibrahim sebagai tempat Shalat? ' Malik menjawab; 'Ya.'"},{"p":"Tirmidzi","n":2814,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُقُلْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ اتَّخَذْتَ مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى فَنَزَلَتْ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Humaid Ath Thawil] dari [Anas] ia berkata; [Umar bin Al Khaththab] radliallahu 'anhu berkata; Aku berkata kepada Rasulullah shallallahu 'alaihi wasallam; \"Andai anda menjadikan sebagaian maqam untuk tempat shalat.\" Kemudian turunlah ayat: \"Dan jadikanlah sebahagian maqam Ibrahim tempat shalat.\" QS Al-Baqarah: 125. Abu Isa berkata; Hadits ini hasan shahih. Dalam hal ini, ada hadits serupa dari Ibnu Umar."}],"2:136":[{"p":"Muslim","n":1141,"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْفَزَارِيُّ يَعْنِي مَرْوَانَ بْنَ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ حَكِيمٍ الْأَنْصَارِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }الْآيَةَ الَّتِي فِي الْبَقَرَةِ وَفِي الْآخِرَةِ مِنْهُمَا{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Fazari yaitu Marwan bin Muawiyah] dari [Utsman bin Hakim Al Anshari], katanya; telah menceritakan kepadaku [Said bin Yasar] bahwa [Ibnu Abbas] mengabarinya; bahwa dalam dua raka'at fajar, tepatnya di raka'at pertama, Rasulullah shallallahu 'alaihi wasallam membaca \"Katakanlah, kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" QS. Albaqarah 136, dan pada rakaat kedua membaca \"Kami beriman kepada Allah, dan saksikanlah bahwa kami orang muslim.\" QS. Ali Imran 52."},{"p":"Nasa'i","n":933,"ar":"أَخْبَرَنِي عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا الْآيَةَ الَّتِي فِي الْبَقَرَةِ{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }إِلَى آخِرِ الْآيَةِ وَفِي الْأُخْرَى{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] dia berkata; Telah menceritakan kepada kami [Utsman bin Hakim] dia berkata; Telah mengabarkan kepadaku [Sa'id bin Yasar] bahwa [Ibnu Abbas] Telah mengabarkan kepadanya, Rasulullah Shallallallahu'alaihi wasallam membaca (ayat) pada dua rakaat shalat Subuh. Pada rakaat pertama beliau membaca ayat dalam surat Al Baqarah, \"Katakanlah (Hai orang-orang mukmin), 'Kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" (Qs. Al Baqarah (2): 136) sampai akhir ayat tersebut, sedangkan pada rakaat kedua beliau membaca, \"Kami telah beriman dan saksikanlah (wahai rasul) bahwa sesungguhnya kami adalah orang-orang yang patut (kepada seruanmu) (Qs. Al Maa'idah (5): 111).\""}],"2:139":[{"p":"Darimi","n":1130,"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَ حُبِسْنَا يَوْمَ الْخَنْدَقِ حَتَّى ذَهَبَ هَوِيٌّ مِنْ اللَّيْلِ حَتَّى كُفِينَا وَذَلِكَ قَوْلُ اللَّهِ تَعَالَى { وَكَفَى اللَّهُ الْمُؤْمِنِينَ الْقِتَالَ وَكَانَ اللَّهُ قَوِيًّا عَزِيزًا } فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالًا فَأَمَرَهُ فَأَقَامَ فَصَلَّى الظُّهْرَ فَأَحْسَنَ كَمَا كَانَ يُصَلِّيهَا فِي وَقْتِهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْعَصْرَ فَصَلَّاهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْمَغْرِبَ فَصَلَّاهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْعِشَاءَ فَصَلَّاهَا وَذَلِكَ قَبْلَ أَنْ يَنْزِلَ { فَإِنْ خِفْتُمْ فَرِجَالًا أَوْ رُكْبَانًا }","trj":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [Ayahnya] ia berkata, \"Kami tertahan pada saat perang Khandaq hingga berlalu sebagian malam hingga kami dihindarkan dari peperangan, dan hal tersebut sebagaimana yang Allah firmankan: '(Dan Allah menghindarkan orang-orang mukmin dari peperangan. Dan adalah Allah Maha Kuat lagi Maha Perkasa) ' (Qs.?Al Ahzab: 25). Kemudian Nabi shallallahu 'alaihi wasallam memanggil Bilal dan memerintahkannya agar mengumandangkan iqamah. Beliau lalu mengerjakan shalat Zhuhur dan melakukannya dengan baik sebagaimana biasa beliau melakukannya pada waktunya, kemudian memerintahkannya untuk mengumandangkan iqamah shalat Asar, lalu beliau mengerjakan shalat Asar. Kemudian memerintahkannya untuk mengumandangkan iqamah shalat Maghrib, lalu beliau mengerjakan shalat Maghrib, kemudian memerintahkannya untuk mengumandangkan iqamah shalat Isya, lalu beliau mengerjakan shalat Isya. Dan itu sebelum turunnya ayat: '(Jika kamu dalam keadaan takut (bahaya), maka shalatlah sambil berjalan atau berkendaraan…) ' (QS. Al Baqarah: 139)."}],"2:143":[{"p":"Abu Dawud","n":3916,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا تَوَجَّهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْكَعْبَةِ قَالُوا يَا رَسُولَ اللَّهِ فَكَيْفَ الَّذِينَ مَاتُوا وَهُمْ يُصَلُّونَ إِلَى بَيْتِ الْمَقْدِسِ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ }","trj":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] dan [Utsman bin Abu Syaibah] secara makna, keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam (Shalat) menghadap ke arah Ka'bah orang-orang bertanya, \"Wahai Rasulullah, bagaimana dengan orang-orang yang telah meninggal, sementara mereka (dahulu) shalat menghadap ke arah Baitul Maqdis?\" Maka Allah Azza Wa Jalla kemudian menurunkan ayat: '(dan Allah tidak akan menyia-nyiakan imanmu) ' -Qs. Al Baqarah: 143-"},{"p":"Bukhari","n":3045,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجِيءُ نُوحٌ وَأُمَّتُهُ فَيَقُولُ اللَّهُ تَعَالَى هَلْ بَلَّغْتَ فَيَقُ��لُ نَعَمْ أَيْ رَبِّ فَيَقُولُ لِأُمَّتِهِ هَلْ بَلَّغَكُمْ فَيَقُولُونَ لَا مَا جَاءَنَا مِنْ نَبِيٍّ فَيَقُولُ لِنُوحٍ مَنْ يَشْهَدُ لَكَ فَيَقُولُ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمَّتُهُ فَنَشْهَدُ أَنَّهُ قَدْ بَلَّغَوَهُوَ قَوْلُهُ جَلَّ ذِكْرُهُ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا لِتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ }وَالْوَسَطُ الْعَدْلُ","trj":"Telah bercerita kepada kami [Musa bin Isma'il] telah bercerita kepada kami ['Abdul Wahid bin Ziyad] telah bercerita kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Pada hari qiyanat) Nabi Nuh 'alaihissalam dan ummatnya datang lalu Allah Ta'ala berfirman: \"Apakah kamu telah menyampaikan (ajaran)?. Nuh 'Alaihissalam menjawab: \"Sudah, wahai Rabbku\". Kemudian Allah bertanya kepada ummatnya: \"Apakah benar dia telah menyampaikan kepada kalian?\". Mereka menjawab; \"Tidak. Tidak ada seorang Nabi pun yang datang kepada kami\". Lalu Allah berfirman kepada Nuh 'alaihissalam: \"Siapa yang menjadi saksi atasmu?\". Nabi Nuh Alaihissalam berkata; \"Muhammad shallallahu 'alaihi wasallam dan ummatnya\". Maka kami pun bersaksi bahwa Nabi Nuh 'alaihissalam telah menyampaikan risalah yang diembannya kepada ummatnya. Begitulah seperti yang difirmankan Allah Yang Maha Tinggi (QS al-Baqarah ayat 143 yang artinya), (\"Dan demikianlah kami telah menjadikan kalian sebagai ummat pertengahan untuk menjadi saksi atas manusia..\"). al-washathu artinya al-'adl (adil)."},{"p":"Bukhari","n":3822,"ar":"حَدَّثَنَا يُوسُفُ بْنُ رَاشِدٍ حَدَّثَنَا جَرِيرٌ وَأَبُو أُسَامَةَ وَاللَّفْظُ لِجَرِيرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ وَقَالَ أَبُو أُسَامَةَ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُدْعَى نُوحٌ يَوْمَ الْقِيَامَةِ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ يَا رَبِّ فَيَقُولُ هَلْ بَلَّغْتَ فَيَقُولُ نَعَمْ فَيُقَالُ لِأُمَّتِهِ هَلْ بَلَّغَكُمْ فَيَقُولُونَ مَا أَتَانَا مِنْ نَذِيرٍ فَيَقُولُ مَنْ يَشْهَدُ لَكَ فَيَقُولُ مُحَمَّدٌ وَأُمَّتُهُ فَتَشْهَدُونَ أَنَّهُ قَدْ بَلَّغَ{ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }فَذَلِكَ قَوْلُهُ جَلَّ ذِكْرُهُ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا لِتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }وَالْوَسَطُ الْعَدْلُ","trj":"Telah menceritakan kepada kami [Yusuf bin Rasyid] Telah menceritakan kepada kami [Jarir] dan [Abu Usamah] dan lafazh ini milik Jarir dari [Al A'masy] dari [Abu Shalih], Abu Usamah berkata; Telah menceritakan kepada kami Abu Shalih dari [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Pada hari kiamat, Nuh akan dipanggil (Allah) dan ia akan menjawab: 'Labbaik dan Sa'daik, wahai TuhanKu! ' lalu Allah bertanya: 'Apakah telah kau sampaikan pesan Kami? ' Nuh menjawab: 'Ya'. Kemudian Allah akan bertanya kepada bangsa (umat) Nuh: 'Apakah ia telah menyampaikan pesan kami kepadamu sekalian? ' Mereka akan berkata; 'Tidak ada yang memberikan peringatan kepada kami.' Maka Allah bertanya: 'Siapa yang menjadi saksimu? ' Nuh menjawab: 'Muhammad shallallahu 'alaihi wasallam dan para pengikutnya.' Maka mereka (umat muslim) akan bersaksi bahwa Nuh telah menyampaikan pesan (Allah). Kemudian Rasul (Muhammad shallallahu 'alaihi wasallam) akan menjadi saksi untukmu sekalian dan itulah maksud dari firman Allah: 'Demikianlah kami jadikan kalian sebagai umat yang adil supaya kamu menjadi saksi atas manusia. Dan Rasul menjadi saksi atas kalian.\" (QS. Al Baqarah (2): 143)."},{"p":"Bukhari","n":6450,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجَاءُ بِنُوحٍ يَوْمَ الْقِيَامَةِ فَيُقَالُ لَهُ هَلْ بَلَّغْتَ فَيَقُولُ نَعَمْ يَا رَبِّ فَتُسْأَلُ أُمَّتُهُ هَلْ بَلَّغَكُمْ فَيَقُولُونَ مَا جَاءَنَا مِنْ نَذِيرٍ فَيَقُولُ مَنْ شُهُودُكَ فَيَقُولُ مُحَمَّدٌ وَأُمَّتُهُ فَيُجَاءُ بِكُمْ فَتَشْهَدُونَ ثُمَّ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا }قَالَ عَدْلًا{ لِتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }وَعَنْ جَعْفَرِ بْنِ عَوْنٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Abu Shalih] dari [Abu Sa'id alkhudzri] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nabi Nuh didatangkan pada hari kiamat lantas ditanya, 'Sudahkah kamu menyampaikan? ' ia menjawab, 'Benar ya Rabbi'. Ummatnya kemudian ditanya, 'Apakah dia memang benar telah menyampaikan kepada kalian? ' Mereka menjawab, 'Belum ada seorang pemberi peringatan kepada kita.' Lantas Allah bertanya lagi: 'Siapa yang menjadi saksimu? ' Nuh menjawab, 'Muhammad dan umatnya.' Lantas kalian didatangkan dan kalian bersaksi.\" Kemudian Rasulullah Shallallahu'alaihiwasallam membaca ayat: '(Dan demikianlah Kami jadikan kalian umat yang wasath) ' (Qs. Albaqarah 143). Kata Al A'masy, wasath artinya adil '(Agar kalian menjadi saksi atas semua manusia dan agar rasul sebagai saksi atas kalian) ' (Qs. Albaqarah 143). Dan dari [Ja'far bin Aun] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id alkhudzri] dari Nabi shallallahu 'alaihi wasallam dengan ini.\""},{"p":"Tirmidzi","n":2815,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا }قَالَ عَدْلًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abu Muawiyah] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam tentang firman Allah: \"Dan demikian (pula) Kami telah menjadikan kamu (umat Islam), umat yang adil dan pilihan agar kamu menjadi saksi atas (perbuatan) manusia.\" QS Al-Baqarah: 143, beliau bersabda: \"Adil.\" Abu Isa berkata; Hadits ini hasan shahih."},{"p":"Tirmidzi","n":2818,"ar":"حَدَّثَنَا هَنَّادٌ وَأَبُو عَمَّارٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا وُجِّهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْكَعْبَةِ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ بِإِخْوَانِنَا الَّذِينَ مَاتُوا وَهُمْ يُصَلُّونَ إِلَى بَيْتِ الْمَقْدِسِ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Hannad] dan [Abu 'Ammar] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Isra'il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Saat Nabi shallallahu 'alaihi wasallam dialihkan ke arah Ka'bah, orang-orang berkata; \"Wahai Rasulullah, bagaimana dengan saudara-saudara kami yang telah meninggal, sementara mereka shalat menghadap Baitul Maqdis?\" Maka turunlah ayat: \"Dan Allah tidaklah menyia-nyiakan keimananmu.\" QS Al-Baqarah: 143. Abu Isa berkata; Hadits ini hasan shahih."}],"2:144":[{"p":"Bukhari","n":384,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ }فَتَوَجَّهَ نَحْوَ الْكَعْبَةِ وَقَالَ السُّفَهَاءُ مِنْ النَّاسِ وَهُمْ الْيَهُودُ{ مَا وَلَّاهُمْ عَنْ قِبْلَتِهِمْ الَّتِي كَانُوا عَلَيْهَا قُلْ لِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ يَهْدِي مَنْ يَشَاءُ إِلَى صِرَاطٍ مُسْتَقِيمٍ }فَصَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ ثُمَّ خَرَجَ بَعْدَ مَا صَلَّى فَمَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ فِي صَلَاةِ الْعَصْرِ نَحْوَ بَيْتِ الْمَقْدِسِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ تَوَجَّهَ نَحْوَ الْكَعْبَةِ فَتَحَرَّفَ الْقَوْمُ حَتَّى تَوَجَّهُوا نَحْوَ الْكَعْبَةِ","trj":"Telah menceritakan kepada kami ['Abdullah bin Raja'] berkata, telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Bara' bin 'Azib? radliallahu 'anhuma] berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat mengahdap Baitul Maqdis selama enam belas atau tujuh belas bulan, dan Rasulullah shallallahu 'alaihi wasallam menginginkan kiblat tersebut dialihkan ke arah Ka'bah. Maka Allah menurunkan ayat: (\"Sungguh Kami (sering) melihat mukamu menengadah ke langit) ' (Qs. Al Baqarah: 144). Maka kemudian Nabi shallallahu 'alaihi wasallam menghadap ke Ka'bah. Lalu berkatalah orang-orang yang kurang akal, yaitu orang-orang Yahudi: '(Apakah yang memalingkan mereka (umat Islam) dari kiblatnya (Baitul Maqdis) yang dahulu mereka telah berkiblat kepadanya?\" Katakanlah: \"Kepunyaan Allah-lah timur dan barat. Dia memberi petunjuk kepada siapa yang dikehendaki-Nya ke jalan yang lurus) ' (As. Al Baqarah: 144). Kemudian ada seseorang yang ikut shalat bersama Nabi shallallahu 'alaihi wasallam, orang itu kemudian keluar setelah menyelesikan shalatnya. Kemudian orang itu melewati Kaum Anshar yang sedang melaksanakan shalat 'Ashar dengan menghadap Baitul Maqdis. Lalu orang itu bersaksi bahwa dia telah shalat bersama Rasulullah shallallahu 'alaihi wasallam dengan menghadap Ka'bah. Maka orang-orang itu pun berputar dan menghadap Ka'bah.\""},{"p":"Bukhari","n":6377,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَاهَا }فَوُجِّهَ نَحْوَ الْكَعْبَةِ وَصَلَّى مَعَهُ رَجُلٌ الْعَصْرَ ثُمَّ خَرَجَ فَمَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ قَدْ وُجِّهَ إِلَى الْكَعْبَةِ فَانْحَرَفُوا وَهُمْ رُكُوعٌ فِي صَلَاةِ الْعَصْرِ","trj":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari [Al Bara'] ia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam tiba di Madinah, beliau shalat menghadap Baitul Maqdis selama enam belas atau tujuh belas bulan, padahal beliau amat senang jika disuruh menghadap Ka'bah. Maka Allah pun menurunkan ayat: '(Kami telah melihat penglihatan wajahmu di langit, maka kami palingkan kamu ke kiblat yang kamu ridhai) ' (Qs. Al Baqarah: 144), maka beliau dihadapkan wajahnya ke Ka'bah, ketika itu seseorang shalat 'ashar bersama beliau, lantas keluar dan melewati sekelompok orang-orang Anshar, lalu ia katakan kepada mereka sekaligus bersaksi bahwa ia telah shalat bersama nabi shallallahu 'alaihi wasallam, dan kiblat beliau telah di hadapkan ke Ka'bah, maka mereka pun menggeser kiblatnya yang ketika itu mereka sedang rukuk pada shalat 'ashar.\""},{"p":"Muslim","n":800,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي نَحْوَ بَيْتِ الْمَقْدِسِ فَنَزَلَتْ{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَاهَا فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }فَمَرَّ رَجُلٌ مِنْ بَنِي سَلِمَةَ وَهُمْ رُكُوعٌ فِي صَلَاةِ الْفَجْرِ وَقَدْ صَلَّوْا رَكْعَةً فَنَادَى أَلَا إِنَّ الْقِبْلَةَ قَدْ حُوِّلَتْ فَمَالُوا كَمَا هُمْ نَحْوَ الْقِبْلَةِ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] \"Bahwa Rasulullah shallallahu'alaihiwasallam dahulu shalat menghadap Baitul Maqdis, lalu turunlah ayat, 'Sungguh kami telah melihat wajahmu menengadah ke langit, maka sungguh kami palingkan wajahmu ke kiblat yang kamu ridhai, maka palingkanlah wajahmu ke arah masjid al-Haram.' (QS. Albaqarah 144), Lalu seorang laki-laki dari Bani Salimah berjalan, sedangkan mereka dalam keadaan rukuk dalam shalat shubuh, dan mereka telah melakukan shalat satu raka'at, lalu dia memanggil, 'Ketahuilah, sesungguhnya kiblat telah diganti, maka mereka berpaling sebagaimana mereka menghadap kiblat'.\""},{"p":"Tirmidzi","n":2813,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ قَال سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ تَطَوُّعًا أَيْنَمَا تَوَجَّهَتْ بِهِ وَهُوَ جَاءٍ مِنْ مَكَّةَ إِلَى الْمَدِينَةِثُمَّ قَرَأَ ابْنُ عُمَرَ هَذِهِ الْآيَةَ{ وَلِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ }الْآيَةَ فَقَالَ ابْنُ عُمَرَ فَفِي هَذَا أُنْزِلَتْ هَذِهِ الْآيَةُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى عَنْ قَتَادَةَ أَنَّهُ قَالَ فِي هَذِهِ الْآيَةِ{ وَلِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ قَتَادَةُ هِيَ مَنْسُوخَةٌ نَسَخَهَا قَوْلُهُ{ فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }أَيْ تِلْقَاءَهُ حَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ وَيُرْوَى عَنْ مُجَاهِدٍ فِي هَذِهِ الْآيَةِ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ فَثَمَّ قِبْلَةُ اللَّهِ حَدَّثَنَا بِذَلِكَ أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ النَّضْرِ بْنِ عَرَبِيٍّ عَنْ مُجَاهِدٍ بِهَذَا","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Abdul Malik bin Abu Sulaiman] ia berkata; Aku mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Umar] ia berkata; Nabi shallallahu 'alaihi wasallam pernah shalat sunnah di atas kendaraan beliau kemana pun kendaraan beliau menghadap, ketika itu beliau pergi dari Makkah menuju Madinah. Setelah itu Ibnu Umar membaca ayat ini: \"Dan kepunyaan Allah-lah timur dan barat.\" QS Al-Baqarah: 115. Ibnu Umar berkata; \"Berkenaan dengan peristiwa itulah, ayat ini turun.\" Abu Isa berkata; Hadits ini hasan shahih. Diriwayatkan dari Qatadah, ia berkata tentang ayat ini: Dan kepunyaan Allah-lah timur dan barat, maka kemanapun kamu menghadap di situlah wajah Allah.\" QS Al-Baqarah: 115 Qatadah berkata; Ayat ini mansukhah, dinasakh dengan firman Allah, \"Palingkanlah mukamu ke arah Masjidil Haram.\" QS Al-Baqarah: 144 yaitu arahnya. Telah menceritakan kepada kami yang demikian itu Muhammad bin Abdul Malik bin Abu Asy Syawarib, telah menceritakan kepada kami Yazid bin Zurai' dari Sa'id dari Qatadah. Dan diriwayatkan pula dari Mujahid tentang ayat ini: \"Maka kemanapun kamu menghadap, di situlah wajah Allah.\" QS Al-Baqarah: 115, ia berkata; \"Di sanalah kiblat Allah.\" Telah menceritakan kepada kami seperti itu Muhammad bin Al Ala` telah menceritakan kepada kami Waki' dari An Nadlr bin Arabi dari Mujahid seperti itu."},{"p":"Tirmidzi","n":2816,"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَاهَا فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }فَوُجِّهَ نَحْوَ الْكَعْبَةِ وَكَانَ يُحِبُّ ذَلِكَ فَصَلَّى رَجُلٌ مَعَهُ الْعَصْرَ قَالَ ثُمَّ مَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ وَهُمْ رُكُوعٌ فِي صَلَاةِ الْعَصْرِ نَحْوَ بَيْتِ الْمَقْدِسِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ قَدْ وُجِّهَ إِلَى الْكَعْبَةِ قَالَ فَانْحَرَفُوا وَهُمْ رُكُوعٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ","trj":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari [Al Bara` bin Azib] ia berkata; \"Setibanya Rasulullah shallallahu 'alaihi wasallam di Madinah, beliau shalat menghadap ke Baitul Maqdis selama enam belas atau tujuh belas bulan, namun Rasulullah shallallahu 'alaihi wasallam ingin menghadap ka'bah, maka Allah menurunkan ayat: \"Sungguh Kami (sering) melihat mukamu menengadah ke langit, maka sungguh kami akan memalingkan kamu ke kiblat yang kamu sukai. Palingkanlah mukamu ke arah Masjidil Haram.\" QS Al-Baqarah: 144. Kemudian beliau menghadapkan mukanya ke arah Ka'bah, dan beliau sangat menyukainya, lalu seseorang shalat ashar bersama beliau. Setelah itu ia melintasi suatu kaum dari sahabat Anshar, mereka tengah ruku' dalam shalat ashar sambil menghadap Baitul Maqdis.\" Barra` berkata; Sahabat tersebut bersaksi bahwa ia pernah shalat ashar bersama Rasulullah shallallahu 'alaihi wasallam dan beliau telah dihadapkan ke Ka'bah. Barra` berkata; \"Mereka pun mengalihkan wajahnya dalam keadaan ruku'.\" Abu Isa berkata; Hadits ini hasan shahih. [Sufyan Ats Tsauri] juga meriwayatkannya dari [Abu Ishaq]."}],"2:156":[{"p":"Malik","n":728,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ قُلْتُ لِعَائِشَةَ أُمِّ الْمُؤْمِنِينَ وَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّأَرَأَيْتِ قَوْلَ اللَّهِ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَمَا عَلَى الرَّجُلِ شَيْءٌ أَنْ لَا يَطَّوَّفَ بِهِمَا فَقَالَتْ عَائِشَةُ كَلَّا لَوْ كَانَ كَمَا تَقُولُ لَكَانَتْ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي الْأَنْصَارِ كَانُوا يُهِلُّونَ لِمَنَاةَ وَكَانَتْ مَنَاةُ حَذْوَ قُدَيْدٍ وَكَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا جَاءَ الْإِسْلَامُ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Hisyam bin Urwah] dari [Bapaknya] ia berkata; \"Aku pernah bertanya kepada [Aisyah Ummul Mukminin], saat saya masih muda: 'Apakah anda tahu tentang firman Allah Tabaraka Wa Ta'ala: 'Sesungguhnya Shafaa dan Marwa adalah sebahagian dari syi'ar Allah. Barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.' -Qs. Al Baqarah: 156- Maka tidak apa-apa bagi seseorang untuk meninggalkan sa'i.\" Aisyah menjawab; \"Bukan begitu, kalau seperti yang kamu katakan, tentu tidak ada dosa bagi orang yang tidak melakukan sa'i. Ayat ini turun pada orang-orang Anshar, dahulu mereka melakukan talbiyah untuk Manat, yang letaknya di depan Qudaid. Mereka menjauhi untuk tidak melaksanakan sa'i antara Shafaa dan Marwa. Maka tatkala datang Islam, mereka bertanya pada Rasulullah shallallahu 'alaihi wasallam tentang hal itu. Allah Tabaraka Wa Ta'ala menurunkan ayat: 'Sesungguhnya Shafa dan Marwa adalah sebagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya'. -Qs. Al Baqarah: 156-."}],"2:158":[{"p":"Bukhari","n":1534,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ عُرْوَةُ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقُلْتُ لَهَاأَرَأَيْتِ قَوْلَ اللَّهِ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَوَاللَّهِ مَا عَلَى أَحَدٍ جُنَاحٌ أَنْ لَا يَطُوفَ بِالصَّفَا وَالْمَرْوَةِ قَالَتْ بِئْسَ مَا قُلْتَ يَا ابْنَ أُخْتِي إِنَّ هَذِهِ لَوْ كَانَتْ كَمَا أَوَّلْتَهَا عَلَيْهِ كَانَتْ لَا جُنَاحَ عَلَيْهِ أَنْ لَا يَتَطَوَّفَ بِهِمَا وَلَكِنَّهَا أُنْزِلَتْ فِي الْأَنْصَارِ كَانُوا قَبْلَ أَنْ يُسْلِمُوا يُهِلُّونَ لِمَنَاةَ الطَّاغِيَةِ الَّتِي كَانُوا يَعْبُدُونَهَا عِنْدَ الْمُشَلَّلِ فَكَانَ مَنْ أَهَلَّ يَتَحَرَّجُ أَنْ يَطُوفَ بِالصَّفَا وَالْمَرْوَةِ فَلَمَّا أَسْلَمُوا سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ قَالُوا يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَتَحَرَّجُ أَنْ نَطُوفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }الْآيَةَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا وَقَدْ سَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّوَافَ بَيْنَهُمَا فَلَيْسَ لِأَحَدٍ أَنْ يَتْرُكَ الطَّوَافَ بَيْنَهُمَا ثُمَّ أَخْبَرْتُ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ فَقَالَ إِنَّ هَذَا لَعِلْمٌ مَا كُنْتُ سَمِعْتُهُ وَلَقَدْ سَمِعْتُ رِجَالًا مِنْ أَهْلِ الْعِلْمِ يَذْكُرُونَ أَنَّ النَّاسَ إِلَّا مَنْ ذَكَرَتْ عَائِشَةُ مِمَّنْ كَانَ يُهِلُّ بِمَنَاةَ كَانُوا يَطُوفُونَ كُلُّهُمْ بِالصَّفَا وَالْمَرْوَةِ فَلَمَّا ذَكَرَ اللَّهُ تَعَالَى الطَّوَافَ بِالْبَيْتِ وَلَمْ يَذْكُرْ الصَّفَا وَالْمَرْوَةَ فِي الْقُرْآنِ قَالُوا يَا رَسُولَ اللَّهِ كُنَّا نَطُوفُ بِالصَّفَا وَالْمَرْوَةِ وَإِنَّ اللَّهَ أَنْزَلَ الطَّوَافَ بِالْبَيْتِ فَلَمْ يَذْكُرْ الصَّفَا فَهَلْ عَلَيْنَا مِنْ حَرَجٍ أَنْ نَطَّوَّفَ بِالصَّفَا وَالْمَرْوَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }الْآيَةَ قَالَ أَبُو بَكْرٍ فَأَسْمَعُ هَذِهِ الْآيَةَ نَزَلَتْ فِي الْفَرِيقَيْنِ كِلَيْهِمَا فِي الَّذِينَ كَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بِالْجَاهِلِيَّةِ بِالصَّفَا وَالْمَرْوَةِ وَالَّذِينَ يَطُوفُونَ ثُمَّ تَحَرَّجُوا أَنْ يَطُوفُوا بِهِمَا فِي الْإِسْلَامِ مِنْ أَجْلِ أَنَّ اللَّهَ تَعَالَى أَمَرَ بِالطَّوَافِ بِالْبَيْتِ وَلَمْ يَذْكُرْ الصَّفَا حَتَّى ذَكَرَ ذَلِكَ بَعْدَ مَا ذَكَرَ الطَّوَافَ بِالْبَيْتِ","trj":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy], berkata, ['Urwah]: Aku bertanya kepada ['Aisyah radliallahu 'anha], kataku kepadanya: \"Bagaimana pendapatmu tentang firman Allah Ta'ala (QS Al Baqarah 158) yang artinya: (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah, maka barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\"), dan demi Allah tidak ada dosa bagi seseorang untuk tidak ber thawaf (sa'iy) antara bukit Ash-Shafaa dan Al Marwah\". 'Aisyah radliallahu 'anha berkata: \"Buruk sekali apa yang kamu katakan itu wahai putra saudariku. Sesungguhnya ayat ini bila tafsirannya menurut pendapatmu tadi berarti tidak berdosa bila ada orang yang tidak melaksanakan sa'iy antara keduanya. Akan tetapi ayat ini turun berkenaan dengan Kaum Anshar, yang ketika mereka belum masuk Islam, mereka berniat hajji untuk patung Manat Sang Thoghut yang mereka sembah di daerah Al Musyallal. Waktu itu, barangsiapa yang berniat hajji, dia merasa berdosa bila harus sa'iy antara bukit Ash-Shafaa dan Al Marwah (karena demi menghormatii patung mereka itu). Setelah mereka masuk Islam, mereka bertanya kepada Rasulullah Shallallahu'alaihiwasallam tentang masalah itu, mereka berkata: \"Wahai Rasulullah, kami merasa berdosa bila melaksanakan sa'iy antara bukit Ash-Shafaa dan Al Marwah\". Maka kemudian Allah Ta'ala menurunkan ayat (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah\"). 'Aisyah radliallahu 'anha berkata: \"Sungguh Rasulullah Shallallahu'alaihiwasallam telah mencontohkan sa'iy antara kedua bukit tersebut dan tidak boleh seorangpun untuk meninggalkannya\". Kemudian aku kabarkan hal ini kepada Abu Bakar bin 'Abdurrahman, maka katanya: \"Sungguh ini suatu ilmu yang aku belum pernah mendengar sebelumnya, padahal aku sudah mendengar dari orang-orang ahli ilmu yang menyebutkan bahwa diantara manusia, selain orang-orang yang diterangkan oleh 'Aisyah radliallahu 'anha itu, ada yang dahulu melaksanakan ihram untuk Manat, mereka juga melaksanakan sa'iy antara bukit Ash-Shafaa dan Al Marwah. Ketika Allah menyebutkan thawaf di Ka'bah Baitullah tapi tidak menyebut sa'iy antara bukit Ash-Shafaa dan Al Marwah dalam Al Qur'an, mereka bertanya kepada: \"Wahai Rasulullah, dahulu kami melaksanakan thawaf (sa'iy) antara bukit Ash-Shafaa dan Al Marwah dan Allah telah menurunkan ayat tentang thawaf di Ka'bah Baitullah tanpa menyebut Ash-Shafaa, apakah berdosa bagi kami bila kami sa'iy antara bukit Ash-Shafaa dan Al Marwah?\". Maka Allah Ta'ala menurunkan ayat (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar Allah\"). Abu Bakar bin 'Abdurrahman berkata: \"Maka aku mendengar bahwa ayat ini turun untuk dua golongan orang yaitu golongan orang-orang yang merasa berdosa karena pernah melaksanakan sa'i antara bukit Ash-Shafaa dan Al Marwah saat mereka masih jahiliyyah (karena pernah melaksanakan untuk patung Manat), dan golongan orang-orang yang pernah melaksanakannya namun merasa berdosa bila melaksanakannya kembali setelah masuk Islam karena Allah pada mulanya hanya menyebutkan thawaf di Ka'bah Baitullah dan tidak menyebut Ash-Shafaa hingga kemudian Dia menyebutkannya setelah memerintahkan thawaf di Ka'bah Baitullah\"."},{"p":"Bukhari","n":1538,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَاصِمٌ قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَكُنْتُمْ تَكْرَهُونَ السَّعْيَ بَيْنَ الصَّفَا وَالْمَرْوَةِ قَالَ نَعَمْ لِأَنَّهَا كَانَتْ مِنْ شَعَائِرِ الْجَاهِلِيَّةِ حَتَّى أَنْزَلَ اللَّهُ{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami ['Ashim] berkata; Aku berkata, kepada [Anas bin Malik radliallahu 'anhu]: \"Apakah kalian tidak menyukai melaksanakan sa'iy antara bukit Shafaa dan Marwah? '. Dia menjawab: \"Ya benar, karena itu bagian dari syi'ar-syi'ar jahiliyyah hingga kemudian Allah menurunkan (QS Al Baqarah ayat 158) yang artinya (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah bahagian dari syi'ar-syi'ar Allah, barangsiapa yang beribadah haji ke Baitullah atau ber-'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\")."},{"p":"Bukhari","n":1665,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ قُلْتُ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّأَرَأَيْتِ قَوْلَ اللَّهِ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَلَا أُرَى عَلَى أَحَدٍ شَيْئًا أَنْ لَا يَطَّوَّفَ بِهِمَا فَقَالَتْ عَائِشَةُ كَلَّا لَوْ كَانَتْ كَمَا تَقُولُ كَانَتْ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي الْأَنْصَارِ كَانُوا يُهِلُّونَ لِمَنَاةَ وَكَانَتْ مَنَاةُ حَذْوَ قُدَيْدٍ وَكَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا جَاءَ الْإِسْلَامُ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }زَادَ سُفْيَانُ وَأَبُو مُعَاوِيَةَ عَنْ هِشَامٍ مَا أَتَمَّ اللَّهُ حَجَّ امْرِئٍ وَلَا عُمْرَتَهُ لَمْ يَطُفْ بَيْنَ الصَّفَا وَالْمَرْوَةِ","trj":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] bahwa dia berkata; Aku pernah bertanya kepada ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam saat itu aku masih muda: \"Bagaimana pendapatmu tentang firman Allah Ta'ala (QS Al Baqarah 158) yang artinya: (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\"), kalau aku berpendapat bahwa seseorang tidak mengapa untuk tidak berthawaf (sa'iy) antara kedua bukit itu. 'Aisyah radliallahu 'anha berkata: \"Bukanlah begitu. Seandainya ayat ini maksudnya sebagaimana yang kamu katakan itu, berarti tidak berdosa bila ada orang yang tidak melaksanakan sa'iy antara keduanya. Sesungguhnya ayat ini turun berkenaan dengan Kaum Anshar yang dahulu mereka berniat haji untuk patung Manat (yang mereka sembah) di daerah sekitar Qudaid. Lantas mereka merasa berdosa bila harus sa'iy antara bukit Ash-Shafaa dan Al Marwah. Setelah Islam datang, mereka bertanya kepada Rasulullah shallallahu 'alaihi wasallam masalah itu, maka kemudian Allah Ta'ala menurunkan ayat (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah. Barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\"). [Sufyan] dan [Abu Mu'awiyah] menambahkan dari [Hisyam] (yakni dari bapaknya dari 'Aisyah radliallahu 'anha): \"Allah tidak akan menerima haji atau 'umrah seseorang yang tidak melakukan sa'iy antara bukit Ash-Shafaa dan Al Marwah\"."},{"p":"Bukhari","n":3830,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ قُلْتُ لِعَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّ أَرَأَيْتِ قَوْلَ اللَّهِ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَمَا أُرَى عَلَى أَحَدٍ شَيْئًا أَنْ لَا يَطَّوَّفَ بِهِمَا فَقَالَتْ عَائِشَةُ كَلَّا لَوْ كَانَتْ كَمَا تَقُولُ كَانَتْ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي الْأَنْصَارِ كَانُوا يُهِلُّونَ لِمَنَاةَ وَكَانَتْ مَنَاةُ حَذْوَ قُدَيْدٍ وَكَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا جَاءَ الْإِسْلَامُ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","trj":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dia berkata; Aku bertanya kepada [Aisyah] istri Rasulullah shallallahu 'alaihi wasallam, -Saat itu saya masih muda-: 'Apakah anda tahu tentang firman Allah Tabaraka Wa Ta'ala: 'Sesungguhnya Shafaa dan Marwa adalah sebahagian dari syi'ar Allah. Barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.' Sebab sepengetahuanku nggak masalah bagi seseorang untuk meninggalkan Sa'i antara keduanya. Aisyah menjawab; \"Bukan begitu, kalau seperti yang kamu katakan, maka jadinya tidak ada dosa orang tidak melakukan sa'i. Ayat ini turun pada orang-orang Anshar, yang dahulu mereka melakukan talbiyah karena Manat, yang letaknya di depan Qadid. Yang mereka berkeharusan berthawaf antara Shofa dan Marwa. Tatkala Islam datang, mereka bertanya pada Rasulullah shallallahu 'alaihi wasallam tentang hal itu. Maka Allah Tabaraka Wa Ta'ala menurunkan ayat: 'Sesungguhnya Shafa dan Marwa adalah sebagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber-'umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya'.\" (QS. Albaqarah 158)."},{"p":"Bukhari","n":3831,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ الصَّفَا وَالْمَرْوَةِ فَقَالَ كُنَّا نَرَى أَنَّهُمَا مِنْ أَمْرِ الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ أَمْسَكْنَا عَنْهُمَا فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari ['Ashim bin Sulaiman] dia berkata; Aku bertanya kepada [Anas bin Malik radliallahu 'anhu] tentang Shafa dan Marwa. Maka dia menjawab; Aku menganggap keduanya sebagai perkara jahiliyah, tatkala Islam datang, keduanya kami tinggalkan lalu turunlah firman Allah; \"Sesungguhnya Shafa dan Marwa adalah sebagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber-'umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.\" (QS. Albaqarah 158)."},{"p":"Tirmidzi","n":2819,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ عَنْ سُفْيَانَ عَنْ عَاصِمٍ الْأَحْوَلِ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ عَنْ الصَّفَا وَالْمَرْوَةِ فَقَالَكَانَا مِنْ شَعَائِرِ الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ أَمْسَكْنَا عَنْهُمَا فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }قَالَ هُمَا تَطَوُّعٌ{ وَمَنْ تَطَوَّعَ خَيْرًا فَإِنَّ اللَّهَ شَاكِرٌ عَلِيمٌ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Yazid bin Abu Hakim] dari [Sufyan] dari ['Ashim Al Ahwal] ia berkata; Aku bertanya kepada [Anas bin Malik] tentang Shafa dan Marwah, ia menjawab: \"Keduanya termasuk syi'ar jahiliyah. Saat Islam datang, kami menahan diri dari keduanya, namun Allah Tabaraka wa Ta'ala menurunkan ayat: \"Sesungguhnya Shafaa dan Marwa adalah sebahagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.\" QS Al-Baqarah: 158, ia berkata; \"Keduanya sunnah.\"Dan barangsiapa yang mengerjakan suatu kebajikan dengan kerelaan hati, maka Sesungguhnya Allah Maha mensyukuri kebaikan lagi Maha Mengetahui.\" Abu Isa berkata; Hadits ini hasan shahih."}],"2:159":[{"p":"Bukhari","n":115,"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَإِنَّ النَّاسَ يَقُولُونَ أَكْثَرَ أَبُو هُرَيْرَةَ وَلَوْلَا آيَتَانِ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُ حَدِيثًا ثُمَّ يَتْلُو{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى إِلَى قَوْلِهِ الرَّحِيمُ }إِنَّ إِخْوَانَنَا مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَإِنَّ إِخْوَانَنَا مِنْ الْأَنْصَارِ كَانَ يَشْغَلُهُمْ الْعَمَلُ فِي أَمْوَالِهِمْ وَإِنَّ أَبَا هُرَيْرَةَ كَانَ يَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشِبَعِ بَطْنِهِ وَيَحْضُرُ مَا لَا يَحْضُرُونَ وَيَحْفَظُ مَا لَا يَحْفَظُونَ","trj":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Sesungguhnya orang-orang mengatakan, \"Abu Hurairah adalah yang paling banyak (menyampaikan hadits dari Rasulullah shallallahu 'alaihi wasallam), kalau bukan karena dua ayat dalam Kitabullah aku tidak akan menyampaikannya.\" Lalu dia membaca ayat: '(Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa penjelasan dan petunjuk) ' ……hingga akhir ayat.. '(Allah Maha Penyayang) ' (Qs. Al Baqarah: 159-160). Sesungguhnya saudara-saudara kita dari kalangan Muhajirin, mereka disibukkan dengan perdagangan di pasar-pasar, dan saudara-saudara kita dari kalangan Anshar, mereka disibukkan dengan pekerjaan mereka dalam mengurus harta mereka. sementara Abu Hurairah selalu menyertai Rasulullah shallallahu 'alaihi wasallam dalam keadaan lapar, ia selalu hadir saat orang-orang tidak bosa hadir, dan ia dapat menghafal saat orang-orang tidak bisa menghafalnya.\""},{"p":"Bukhari","n":155,"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّ عَطَاءَ بْنَ يَزِيدَ أَخْبَرَهُ أَنَّ حُمْرَانَ مَوْلَى عُثْمَانَ أَخْبَرَهُ أَنَّهُ رَأَى عُثْمَانَ بْنَ عَفَّانَدَعَا بِإِنَاءٍ فَأَفْرَغَ عَلَى كَفَّيْهِ ثَلَاثَ مِرَارٍ فَغَسَلَهُمَا ثُمَّ أَدْخَلَ يَمِينَهُ فِي الْإِنَاءِ فَمَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ ثَلَاثَ مِرَارٍ ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ رِجْلَيْهِ ثَلَاثَ مِرَارٍ إِلَى الْكَعْبَيْنِ ثُمَّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ نَحْوَ وُضُوئِي هَذَا ثُمَّ صَلَّى رَكْعَتَيْنِ لَا يُحَدِّثُ فِيهِمَا نَفْسَهُ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِوَعَنْ إِبْرَاهِيمَ قَالَ قَالَ صَالِحُ بْنُ كَيْسَانَ قَالَ ابْنُ شِهَابٍ وَلَكِنْ عُرْوَةُ يُحَدِّثُ عَنْ حُمْرَانَ فَلَمَّا تَوَضَّأَ عُثْمَانُ قَالَ أَلَا أُحَدِّثُكُمْ حَدِيثًا لَوْلَا آيَةٌ مَا حَدَّثْتُكُمُوهُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَتَوَضَّأُ رَجُلٌ يُحْسِنُ وُضُوءَهُ وَيُصَلِّي الصَّلَاةَ إِلَّا غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الصَّلَاةِ حَتَّى يُصَلِّيَهَا قَالَ عُرْوَةُ الْآيَةَ{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ }","trj":"Telah menceritakan kepada kami [Abdul 'Aziz bin 'Abdullah Al Uwaisy] berkata, telah menceritakan kepadaku [Ibrahim bin Sa'd] dari [Syihab] bahwa ['Atha' bin Yazid] mengabarkan kepadanya bahwa [Humran] mantan budan 'Utsman mengabarkan kepadanya, bahwa ia telah melihat ['Utsman bin 'Affan] minta untuk diambilkan bejana (berisi air). Lalu dia menuangkan pada telapak tangannya tiga kali lalu membasuh keduanya, lalu ia memasukkan tangan kanannya ke dalam bejana lalu berkumur-kumur dan memasukkan air ke dalam hidung, kemudian membasuh wajahnya tiga kali, kemudian membasuh kedua tangan hingga siku tiga kali, kemudian mengusap kepala, kemudian membasuh kedua kakinya tiga kali hingga kedua mata kaki. Setelah itu ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu seperti wudluku ini, kemudian dia shalat dua rakaat dan tidak berbicara antara keduanya, maka dosanya yang telah lalu akan diampuni.\" Dan dari [Ibrahim] berkata, [Shalih bin Kaisan] berkata, [Ibnu Syihab] berkata. Tetapi ['Urwah] menceritakan dari [Humran], \"Ketika ['Utsman] berwudlu, dia berkata, \"Maukah aku sampaikan kepada kalian sebuah hadits yang kalau bukan karena ada satu ayat tentu aku tidak akan menyampaikannya? Aku pernah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki berwudlu dengan membaguskan wudlunya kemudian mengerjakan shalat, kecuali akan diampuni (dosa) antara wudlunya dan shalatnya itu hingga selesai shalatnya.\" 'Urwah berkata, \"Ayat yang dimaksud adalah: '(Sesungguhnya orang-orang yang menyembunyikan apa yang telah kami turunkan…) ' (Qs. Al Baqarah: 159)."},{"p":"Bukhari","n":2179,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَيَقُولُونَ إِنَّ أَبَا هُرَيْرَةَ يُكْثِرُ الْحَدِيثَ وَاللَّهُ الْمَوْعِدُ وَيَقُولُونَ مَا لِلْمُهَاجِرِينَ وَالْأَنْصَارِ لَا يُحَدِّثُونَ مِثْلَ أَحَادِيثِهِ وَإِنَّ إِخْوَتِي مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَإِنَّ إِخْوَتِي مِنْ الْأَنْصَارِ كَانَ يَشْغَلُهُمْ عَمَلُ أَمْوَالِهِمْ وَكُنْتُ امْرَأً مِسْكِينًا أَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مِلْءِ بَطْنِي فَأَحْضُرُ حِينَ يَغِيبُونَ وَأَعِي حِينَ يَنْسَوْنَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا لَنْ يَبْسُطَ أَحَدٌ مِنْكُمْ ثَوْبَهُ حَتَّى أَقْضِيَ مَقَالَتِي هَذِهِ ثُمَّ يَجْمَعَهُ إِلَى صَدْرِهِ فَيَنْسَى مِنْ مَقَالَتِي شَيْئًا أَبَدًا فَبَسَطْتُ نَمِرَةً لَيْسَ عَلَيَّ ثَوْبٌ غَيْرُهَا حَتَّى قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَالَتَهُ ثُمَّ جَمَعْتُهَا إِلَى صَدْرِي فَوَالَّذِي بَعَثَهُ بِالْحَقِّ مَا نَسِيتُ مِنْ مَقَالَتِهِ تِلْكَ إِلَى يَوْمِي هَذَا وَاللَّهِ لَوْلَا آيَتَانِ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُكُمْ شَيْئًا أَبَدًا{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى إِلَى قَوْلِهِ الرَّحِيمُ }","trj":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] berkata: Sesungguhgnya orang-orang mengatakan: \"Abu Hurairah adalah yang paling banyak menyampaikan hadits dan Allah Maha Memenuhi janji. Dan mereka berkata: \"Mengapa Muhajirin dan Anshar menampaikan hadits tidak sebanyak yang aku sampaikan?\" Sesungguhnya saudara-saudaraku dari kalangan Muhajirin mereka disibukkan dengan berdagang di pasar-pasar dan saudara-saudaraku dari kalangan Anshar mereka disibukkan dengan pekerjaan mereka dalam mengurus harta mereka (bercocok tanam). Adapun aku adalah seorang yang miskin, aku selalu bermulazamah (mendampingi) Rasulullah shallallahu 'alaihi wasallam dengan isi perut sekedar kebutuhan pokok, dan aku selalu hadir (dalam majelis) saat mereka tidak bisa hadir dan dapat menjaga hafalan saat mereka lupa\". Dan pada suatu hari Nabi shallallahu 'alaihi wasallam bersabda: \"Sekali-kali janganlah seorang dari kalian menghamparkan kainnya sebelum aku selesai menyampaikan sabdaku ini lalu dia mengumpulkannya dalam dadanya yang akhirnya dia melupakan sesuatu dari sabdaku untuk selamanya\". Maka aku hamparkan kainku yang bermotif karena aku tidak memiliki kain yang lain hingga Nabi shallallahu 'alaihi wasallam selesai menyampaikan sabda Beliau lalu aku kumpulkan dalam dadaku\". Maka demi Dzat yang mengutus Beliau dengan haq, tidaklah aku lupa satupun dari sabda Beliau hingga hari ini dan demi Allah, kalau bukan karena dua ayat dalam Kitabulloh maka aku tidak akan menyampaikannya sesuatu haditspun kepada kalian selamanya\". (Lalu dia membaca ayat 159 dan 160 dari surah Al Baqarah yang artinya: ('Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa penjelasan dan petunjuk ……hingga akhir ayat.. Allah Maha Penyayang) "},{"p":"Muslim","n":327,"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ ابْنُ شِهَابٍ وَلَكِنْ عُرْوَةُ يُحَدِّثُ عَنْ حُمْرَانَ أَنَّهُ قَالَ فَلَمَّا تَوَضَّأَ عُثْمَانُ قَالَوَاللَّهِ لَأُحَدِّثَنَّكُمْ حَدِيثًا وَاللَّهِ لَوْلَا آيَةٌ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُكُمُوهُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَتَوَضَّأُ رَجُلٌ فَيُحْسِنُ وُضُوءَهُ ثُمَّ يُصَلِّي الصَّلَاةَ إِلَّا غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الصَّلَاةِ الَّتِي تَلِيهَاقَالَ عُرْوَةُ الْآيَةُ{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى إِلَى قَوْلِهِ اللَّاعِنُونَ }","trj":"Dan telah menceritakan kepada kami [Zuhair bin harb] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [bapakku] dari [Shalih], [Ibnu Syihab] berkata, \"Akan tetapi [Urwah] menceritakan dari [Humran] bahwa dia berkata, 'Ketika [Utsman] berwudlu, maka dia berkata, 'Demi Allah, sungguh aku akan menceritakan kepada kalian sebuah hadits. Demi Allah, kalau bukan suatu ayat dalam Kitabullah niscaya aku tidak akan menceritakannya kepada kalian. Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki berwudlu, lalu memperbagus wudlunya kemudian melakukan shalat melainkan pasti diampuni dosanya antara dia dan shalat setelahnya'.\" Urwah berkata, \"Ayat tersebut adalah: '(Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa keterangan-keterangan (yang jelas) dan petunjuk, setelah Kami menerangkan-Nya kepada manusia dalam Al-Kitab, mereka itu dila'nati Allah dan dila'nati (pula) oleh semua (makhluk) yang dapat melaknati…) ' (Qs. Al-Baqarah: 159)."},{"p":"Muslim","n":4210,"ar":"قَالَ ابْنُ شِهَابٍ وَقَالَ ابْنُ الْمُسَيَّبِ إِنَّ أَبَا هُرَيْرَةَ قَالَ يَقُولُونَ إِنَّ أَبَا هُرَيْرَةَ قَدْ أَكْثَرَ وَاللَّهُ الْمَوْعِدُ وَيَقُولُونَ مَا بَالُ الْمُهَاجِرِينَ وَالْأَنْصَارِ لَا يَتَحَدَّثُونَ مِثْلَ أَحَادِيثِهِ وَسَأُخْبِرُكُمْ عَنْ ذَلِكَ إِنَّ إِخْوَانِي مِنْ الْأَنْصَارِ كَانَ يَشْغَلُهُمْ عَمَلُ أَرَضِيهِمْ وَإِنَّ إِخْوَانِي مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَكُنْتُ أَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مِلْءِ بَطْنِي فَأَشْهَدُ إِذَا غَابُوا وَأَحْفَظُ إِذَا نَسُوا وَلَقَدْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا أَيُّكُمْ يَبْسُطُ ثَوْبَهُ فَيَأْخُذُ مِنْ حَدِيثِي هَذَا ثُمَّ يَجْمَعُهُ إِلَى صَدْرِهِ فَإِنَّهُ لَمْ يَنْسَ شَيْئًا سَمِعَهُ فَبَسَطْتُ بُرْدَةً عَلَيَّ حَتَّى فَرَغَ مِنْ حَدِيثِهِ ثُمَّ جَمَعْتُهَا إِلَى صَدْرِي فَمَا نَسِيتُ بَعْدَ ذَلِكَ الْيَوْمِ شَيْئًا حَدَّثَنِي بِهِ وَلَوْلَا آيَتَانِ أَنْزَلَهُمَا اللَّهُ فِي كِتَابِهِ مَا حَدَّثْتُ شَيْئًا أَبَدًا{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى }إِلَى آخِرِ الْآيَتَيْنِو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا أَبُو الْيَمَانِ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَ إِنَّكُمْ تَقُولُونَ إِنَّ أَبَا هُرَيْرَةَ يُكْثِرُ الْحَدِيثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِهِمْ","trj":"Berkata [Ibnu Syihab]; dan berkata [Ibnu Al Musayyab] bahwa [Abu Hurairah] pernah berkata; 'Orang-orang mengatakan bahwasanya Abu Hurairah banyak meriwayatkan hadits. Allah Subhanahu wa Ta'ala memberinya kesempatan bersama Rasulullah Shallallahu'alaihiwasallam.' Orang-orang berkata; 'Mengapa orang-orang Muhajirin dan Anshar tidak meniwayatkan hadits sebanyak riwayat Abu Hurairah?\" Saya (Abu Hurairah) akan memberitahu kalian tentang hal ini: Saudara-saudara saya dan kaum Anshar sibuk bertani dan saudara-saudara saya dan kaum Muhajirin sibuk berjual beli di pasar. Sementara saya senantiasa menyertai Rasulullah shallallahu 'alaihi wasallam, hingga saya lebih banyak mendengar sabda beliau. Saya hadir ketika mereka, para sahabat dari kaum Anshar dan Muhajirin, tidak hadir dan saya hapal ketika mereka lupa.\" Pada suatu hari, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah di antara kalian yang sudi membentangkan bajunya untuk menampung sabdaku ini? Setelah itu, ia tempelkan bajunya itu ke dadanya, karena dengan begitu ia tidak akan pernah melupakan satu hadits pun yang pernah ia dengar dariku.\" Mendengar pernyataan Rasulullah itu, maka saya bentangkan kain selendang saya hingga Rasulullah selesai bersabda, Kemudian saya tempelkan selendang tersebut ke dada saya. Semenjak itu, saya tidak pernah melupakan satu hadits pun yang beliau sabdakan kepada saya. Seandainya tidak ada dua ayat Al Qur an yang diturunkan Allah, tentu saya tidak akan pernah menyampaikan satu hadits pun yang pernah saya dengar. Kedua ayat tersebut adalah: 'Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa keterangan-keterangan yang jelas dan petunjuk setelah Kami menerangkannya kepada manusia dalam Al Qur'an, maka, mereka itu akan dilaknat Allah dan dilaknat pula oleh semua makhluk yang bisa melaknat, kecuali mereka yang bertaubat dan mengadakan perbaikan serta menerangkan kebenaran, maka terhadap mereka itulah aku menerima taubatnya dan Aku Maha Penerima taubat lagi Maha penyayang' (QS. Albaqarah 159). Dan telah menceritakan kepada kami ['Abdullah bin 'Abdur Rahman Ad Darimi]; Telah mengabarkan kepada kami [Abu Yaman] dari [Syu'aib] dari [Az Zuhri]; Telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdur Rahman] bahwa [Abu Hurairah] berkata; Sesungguhnya kalian mengatakan, mengapa Abu Hurairah banyak mengafal Hadits dari Rasulullah shallallahu 'alaihi wasallam..dan seterusnya dengan Hadits yang serupa."}],"2:160":[{"p":"Bukhari","n":115,"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَإِنَّ النَّاسَ يَقُولُونَ أَكْثَرَ أَبُو هُرَيْرَةَ وَلَوْلَا آيَتَانِ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُ حَدِيثًا ثُمَّ يَتْلُو{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى إِلَى قَوْلِهِ الرَّحِيمُ }إِنَّ إِخْوَانَنَا مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَإِنَّ إِخْوَانَنَا مِنْ الْأَنْصَارِ كَانَ يَشْغَلُهُمْ الْعَمَلُ فِي أَمْوَالِهِمْ وَإِنَّ أَبَا هُرَيْرَةَ كَانَ يَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشِبَعِ بَطْنِهِ وَيَحْضُرُ مَا لَا يَحْضُرُونَ وَيَحْفَظُ مَا لَا يَحْفَظُونَ","trj":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Sesungguhnya orang-orang mengatakan, \"Abu Hurairah adalah yang paling banyak (menyampaikan hadits dari Rasulullah shallallahu 'alaihi wasallam), kalau bukan karena dua ayat dalam Kitabullah aku tidak akan menyampaikannya.\" Lalu dia membaca ayat: '(Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa penjelasan dan petunjuk) ' ……hingga akhir ayat.. '(Allah Maha Penyayang) ' (Qs. Al Baqarah: 159-160). Sesungguhnya saudara-saudara kita dari kalangan Muhajirin, mereka disibukkan dengan perdagangan di pasar-pasar, dan saudara-saudara kita dari kalangan Anshar, mereka disibukkan dengan pekerjaan mereka dalam mengurus harta mereka. sementara Abu Hurairah selalu menyertai Rasulullah shallallahu 'alaihi wasallam dalam keadaan lapar, ia selalu hadir saat orang-orang tidak bosa hadir, dan ia dapat menghafal saat orang-orang tidak bisa menghafalnya.\""}],"2:163":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""},{"p":"Tirmidzi","n":3224,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ الْقَدَّاحِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ آلِ عِمْرَانَ{ الم اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidullah bin Abu Ziyad Al Qaddah] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Nama Allah Allah yang paling agung ada dalam kedua ayat ini, yaitu: \"Dan Tuhanmu adalah Tuhan Yang Maha Esa; tidak ada Tuhan melainkan Dia Yang Maha Pemurah lagi Maha Penyayang\", (QS. Albaqarah 163) dan permulaan Surat Ali Imran; \"Alif laam miim. Allah, tidak ada Tuhan (yang berhak disembah) melainkan Dia. Yang hidup kekal lagi terus menerus mengurus makhluk-Nya.\" (QS.Ali Imran 1-2), Abu Isa berkata; hadits ini adalah hadits hasan shahih."}],"2:178":[{"p":"Bukhari","n":3833,"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو قَالَ سَمِعْتُ مُجَاهِدًا قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُكَانَ فِي بَنِي إِسْرَائِيلَ الْقِصَاصُ وَلَمْ تَكُنْ فِيهِمْ الدِّيَةُ فَقَالَ اللَّهُ تَعَالَى لِهَذِهِ الْأُمَّةِ{ كُتِبَ عَلَيْكُمْ الْقِصَاصُ فِي الْقَتْلَى الْحُرُّ بِالْحُرِّ وَالْعَبْدُ بِالْعَبْدِ وَالْأُنْثَى بِالْأُنْثَى فَمَنْ عُفِيَ لَهُ مِنْ أَخِيهِ شَيْءٌ }فَالْعَفْوُ أَنْ يَقْبَلَ الدِّيَةَ فِي الْعَمْدِ{ فَاتِّبَاعٌ بِالْمَعْرُوفِ وَأَدَاءٌ إِلَيْهِ بِإِحْسَانٍ }يَتَّبِعُ بِالْمَعْرُوفِ وَيُؤَدِّي بِإِحْسَانٍ{ ذَلِكَ تَخْفِيفٌ مِنْ رَبِّكُمْ وَرَحْمَةٌ }مِمَّا كُتِبَ عَلَى مَنْ كَانَ قَبْلَكُمْ{ فَمَنْ اعْتَدَى بَعْدَ ذَلِكَ فَلَهُ عَذَابٌ أَلِيمٌ }قَتَلَ بَعْدَ قَبُولِ الدِّيَةِ","trj":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Amru] dia berkata; Aku mendengar [Mujahid] berkata; Aku mendengar [Ibnu Abbas radliallahu 'anhuma] berkata; \"Dahulu pada Bani Israil terdapat hukum qishas namun tidak ada diyah pada mereka, lalu Allah Azza wa jalla menurunkan ayat: \"Hai orang-orang yang beriman, diwajibkan atas kamu qishaash berkenaan dengan orang-orang yang dibunuh; orang merdeka dengan orang merdeka, hamba dengan hamba, dan wanita dengan wanita. Maka barangsiapa yang mendapat suatu pema'afan dari saudaranya, hendaklah (yang mema'afkan) mengikuti dengan cara yang baik, dan hendaklah (yang diberi ma'af) membayar (diat) kepada yang memberi ma'af dengan cara yang baik (pula). (QS. Albaqarah 178). Pemberian maaf itu maksudnya adalah menerima diyat pada pembunuhan dengan sengaja. mengikuti dengan cara yang baik yaitu ia mengikuti ini dengan cara yang ma'ruf, dan membayar dengan cara yang baik serta melaksanakan ini dengan kebaikan. Yang demikian itu adalah suatu keringanan dari Tuhan kamu dan suatu rahmat (QS. Albaqarah 178) dari apa yang telah diwajibkan atas kaum sebelum kalian, sesungguhnya hal tersebut adalah qishas bukan diyah. Barang siapa yang melampui batas setelah itu, maka baginya Adzab yang pedih.' Yaitu membunuh setelah menerima diyah."},{"p":"Bukhari","n":6039,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ فِي بَنِي إِسْرَائِيلَ قِصَاصٌ وَلَمْ تَكُنْ فِيهِمْ الدِّيَةُ فَقَالَ اللَّهُ لِهَذِهِ الْأُمَّةِ{ كُتِبَ عَلَيْكُمْ الْقِصَاصُ فِي الْقَتْلَى }إِلَى هَذِهِ الْآيَةِ{ فَمَنْ عُفِيَ لَهُ مِنْ أَخِيهِ شَيْءٌ }قَالَ ابْنُ عَبَّاسٍ فَالْعَفْوُ أَنْ يَقْبَلَ الدِّيَةَ فِي الْعَمْدِ قَالَ{ فَاتِّبَاعٌ بِالْمَعْرُوفِ }أَنْ يَطْلُبَ بِمَعْرُوفٍ وَيُؤَدِّيَ بِإِحْسَانٍ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Mujahid] dari [Ibnu 'Abbas] radliallahu 'anhuma mengatakan; 'Di kalangan bani israil hanya berlaku hukum qisas dan tidak ada hukum tebusan (diyat), sehingga Allah menurunkan ayat ini 'Diwajibkan atas kalian qisas dalam pembunuhan (QS. ALbaqarah 178) Hingga ayat ini; kecuali jika ia mendapat pemaafan dari saudara (QS. Albaqarah 178), kata Ibn Abbas; istilah maaf maksudnya menerima diyat secara tulus. Dan Ibnu Abbas berkata perihal kutipan ayat; 'fattibaa'un bil ma'ruuf (Maka hendaklah ia mengikutinya dengan baik), ' maksudnya hendaklah betu-betul meminta maaf dan melakukannya dengan sebaik-baiknya."}],"2:180":[{"p":"Darimi","n":2744,"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ { إِذَا حَضَرَ أَحَدَكُمْ الْمَوْتُ إِنْ تَرَكَ خَيْرًا الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ } فَأَمَرَ أَنْ يُوصِيَ لِوَالِدَيْهِ وَأَقَارِبِهِ ثُمَّ نُسِخَ بَعْدَ ذَلِكَ فِي سُورَةِ النِّسَاءِ فَجَعَلَ لِلْوَالِدَيْنِ نَصِيبًا مَعْلُومًا وَأَلْحَقَ لِكُلِّ ذِي مِيرَاثٍ نَصِيبَهُ مِنْهُ وَلَيْسَتْ لَهُمْ وَصِيَّةٌ فَصَارَتْ الْوَصِيَّةُ لِمَنْ لَا يَرِثُ مِنْ قَرِيبٍ وَغَيْرِهِ","trj":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] dari [Qatadah] ia berkata tentang firman-Nya: '(Apabila seorang di antara kamu kedatangan (tanda-tanda) maut, jika ia meninggalkan harta yang banyak, berwasiat untuk ibu-bapak dan karib kerabatnya) '. (Qs. Al Baqarah: 180), Allah memerintahkan agar berwasiat kepada kedua orang tua dan karib kerabatnya. Kemudian hukum ini dihapus dengan ayat di dalam surat An Nisaa`. Dia menetapkan bahwa kedua orang tua telah mendapatkan bagian yang telah ditentukan, dan memberikan warisan kepada setiap orang yang berhak mendapat warisan dari harta warisannya, dan tidak ada lagi wasiat bagi mereka. Wasiat hanya diberikan kepada orang-orang yang tidak berhak mewarisi baik dari kerabat maupun lainnya.\""},{"p":"Darimi","n":2746,"ar":" حَدَّثَنَا أَحْمَدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ يَزِيدَ عَنْ عِكْرِمَةَ وَالْحَسَنِ { إِنْ تَرَكَ خَيْرًا الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ } وَكَانَتْ الْوَصِيَّةُ كَذَلِكَ حَتَّى نَسَخَتْهَا آيَةُ الْمِيرَاثِ","trj":"Telah menceritakan kepada kami [Ahmad bin Isma'il] telah menceritakan kepada kami [Abu Tumailah] dari [Al Husain bin Waqid] dari [Yazid] dari [Ikrimah] dan [Al Hasan] tentang ayat: '(Jika ia meninggalkan harta yang banyak, berwasiat untuk ibu-bapak dan karib kerabatnya) ' (Qs. Al Baqarah: 180), begitulah wasiat dahulu hingga dihapus oleh ayat tentang harta warisan.\""}],"2:184":[{"p":"Bukhari","n":3840,"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا رَوْحٌ حَدَّثَنَا زَكَرِيَّاءُ بْنُ إِسْحَاقَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عَطَاءٍ سَمِعَ ابْنَ عَبَّاسٍيَقْرَأُ وَعَلَى الَّذِينَ يُطَوَّقُونَهُ فَلَا يُطِيقُونَهُ{ فِدْيَةٌ طَعَامُ مِسْكِينٍ }قَالَ ابْنُ عَبَّاسٍ لَيْسَتْ بِمَنْسُوخَةٍ هُوَ الشَّيْخُ الْكَبِيرُ وَالْمَرْأَةُ الْكَبِيرَةُ لَا يَسْتَطِيعَانِ أَنْ يَصُومَا فَيُطْعِمَانِ مَكَانَ كُلِّ يَوْمٍ مِسْكِينًا","trj":"Telah menceritakan kepadaku [Ishaq] Telah mengabarkan kepada kami [Rauh] Telah menceritakan kepada kami [Zakaria bin Ishaq] Telah menceritakan kepada kami [Amru bin Dinar] dari [Atha] dia mendengar [Ibnu Abbas] membaca ayat; \"Dan bagi orang-orang yang berat menjalankannya maka wajib membayar fidya yaitu memberi makan orang miskin, \"(QS. Albaqarah 184), Ibnu Abbas berkata; Ayat ini tidak dimanshukh, namun ayat ini hanya untuk orang yang sudah sangat tua dan nenek tua, yang tidak mampu menjalankannya, maka hendaklah mereka memberi makan setiap hari kepada orang miskin.'"},{"p":"Muslim","n":1825,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بَكْرٌ يَعْنِي ابْنَ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَعَلَى الَّذِينَ يُطِيقُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ }كَانَ مَنْ أَرَادَ أَنْ يُفْطِرَ وَيَفْتَدِيَ حَتَّى نَزَلَتْ الْآيَةُ الَّتِي بَعْدَهَا فَنَسَخَتْهَا","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Bakr bin Manshur] dari [Amru bin Harits] dari [Bukair] dari [Yazid] Maula Salamah, dari [Salamah bin Al Akwa'] ia berkata; Ketika turun ayat; \"…dan wajib bagi orang-orang yang berat menjalankannya (jika mereka tidak berpuasa) membayar fidyah, (yaitu): memberi makan seorang miskin…\". (QS. Albaqarah 184), banyak orang yang menginginkan untuk tetap makan (tidak berpuasa) dan hanya membayar fidyah, sampai turun ayat setelahnya dan iapun saya me-nasakh-nya."}],"2:185":[{"p":"Abu Dawud","n":414,"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ سَمِعْتُ ابْنَ أَبِي لَيْلَى قَالَ أُحِيلَتْ الصَّلَاةُ ثَلَاثَةَ أَحْوَالٍ قَالَ وَحَدَّثَنَا أَصْحَابُنَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ أَعْجَبَنِي أَنْ تَكُونَ صَلَاةُ الْمُسْلِمِينَ أَوْ قَالَ الْمُؤْمِنِينَ وَاحِدَةً حَتَّى لَقَدْ هَمَمْتُ أَنْ أَبُثَّ رِجَالًا فِي الدُّورِ يُنَادُونَ النَّاسَ بِحِينِ الصَّلَاةِ وَحَتَّى هَمَمْتُ أَنْ آمُرَ رِجَالًا يَقُومُونَ عَلَى الْآطَامِ يُنَادُونَ الْمُسْلِمِينَ بِحِينِ الصَّلَاةِ حَتَّى نَقَسُوا أَوْ كَادُوا أَنْ يَنْقُسُوا قَالَ فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَمَّا رَجَعْتُ لِمَا رَأَيْتُ مِنْ اهْتِمَامِكَ رَأَيْتُ رَجُلًا كَأَنَّ عَلَيْهِ ثَوْبَيْنِ أَخْضَرَيْنِ فَقَامَ عَلَى الْمَسْجِدِ فَأَذَّنَ ثُمَّ قَعَدَ قَعْدَةً ثُمَّ قَامَ فَقَالَ مِثْلَهَا إِلَّا أَنَّهُ يَقُولُ قَدْ قَامَتْ الصَّلَاةُ وَلَوْلَا أَنْ يَقُولَ النَّاسُ قَالَ ابْنُ الْمُثَنَّى أَنْ تَقُولُوا لَقُلْتُ إِنِّي كُنْتُ يَقْظَانَ غَيْرَ نَائِمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ ابْنُ الْمُثَنَّى لَقَدْ أَرَاكَ اللَّهُ عَزَّ وَجَلَّ خَيْرًا وَلَمْ يَقُلْ عَمْرٌو لَقَدْ أَرَاكَ اللَّهُ خَيْرًا فَمُرْ بِلَالًا فَلْيُؤَذِّنْ قَالَ فَقَالَ عُمَرُ أَمَا إِنِّي قَدْ رَأَيْتُ مِثْلَ الَّذِي رَأَى وَلَكِنِّي لَمَّا سُبِقْتُ اسْتَحْيَيْتُ قَالَ وَحَدَّثَنَا أَصْحَابُنَا قَالَ وَكَانَ الرَّجُلُ إِذَا جَاءَ يَسْأَلُ فَيُخْبَرُ بِمَا سُبِقَ مِنْ صَلَاتِهِ وَإِنَّهُمْ قَامُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَيْنِ قَائِمٍ وَرَاكِعٍ وَقَاعِدٍ وَمُصَلٍّ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ ابْنُ الْمُثَنَّى قَالَ عَمْرٌو وَحَدَّثَنِي بِهَا حُصَيْنٌ عَنْ ابْنِ أَبِي لَيْلَى حَتَّى جَاءَ مُعَاذٌ قَالَ شُعْبَةُ وَقَدْ سَمِعْتُهَا مِنْ حُصَيْنٍ فَقَالَ لَا أَرَاهُ عَلَى حَالٍ إِلَى قَوْلِهِ كَذَلِكَ فَافْعَلُوا قَالَ أَبُو دَاوُد ثُمَّ رَجَعْتُ إِلَى حَدِيثِ عَمْرِو بْنِ مَرْزُوقٍ قَالَ فَجَاءَ مُعَاذٌ فَأَشَارُوا إِلَيْهِ قَالَ شُعْبَةُ وَهَذِهِ سَمِعْتُهَا مِنْ حُصَيْنٍ قَالَ فَقَالَ مُعَاذٌ لَا أَرَاهُ عَلَى حَالٍ إِلَّا كُنْتُ عَلَيْهَا قَالَ فَقَالَ إِنَّ مُعَاذًا قَدْ سَنَّ لَكُمْ سُنَّةً كَذَلِكَ فَافْعَلُوا قَالَ و حَدَّثَنَا أَصْحَابُنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَدِمَ الْمَدِينَةَ أَمَرَهُمْ بِصِيَامِ ثَلَاثَةِ أَيَّامٍ ثُمَّ أُنْزِلَ رَمَضَانُ وَكَانُوا قَوْمًا لَمْ يَتَعَوَّدُوا الصِّيَامَ وَكَانَ الصِّيَامُ عَلَيْهِمْ شَدِيدًا فَكَانَ مَنْ لَمْ يَصُمْ أَطْعَمَ مِسْكِينًا فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَمَنْ شَهِدَ مِنْكُمْ الشَّهْرَ فَلْيَصُمْهُ }فَكَانَتْ الرُّخْصَةُ لِلْمَرِيضِ وَالْمُسَافِرِ فَأُمِرُوا بِالصِّيَامِ قَالَ و حَدَّثَنَا أَصْحَابُنَا قَالَ وَكَانَ الرَّجُلُ إِذَا أَفْطَرَ فَنَامَ قَبْلَ أَنْ يَأْكُلَ لَمْ يَأْكُلْ حَتَّى يُصْبِحَ قَالَ فَجَاءَ عُمَرُ بْنُ الْخَطَّابِ فَأَرَادَ امْرَأَتَهُ فَقَالَتْ إِنِّي قَدْ نِمْتُ فَظَنَّ أَنَّهَا تَعْتَلُّ فَأَتَاهَا فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَأَرَادَ الطَّعَامَ فَقَالُوا حَتَّى نُسَخِّنَ لَكَ شَيْئًا فَنَامَ فَلَمَّا أَصْبَحُوا أُنْزِلَتْ عَلَيْهِ هَذِهِ الْآيَةُ{ أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ }","trj":"Telah menceritakan kepada kami [Amru bin Marzuq] telah mengabarkan kepada kami [Syu'bah] dari [Amru bin Murrah] dia berkata; Saya telah mendengar [Ibnu Abi Laila] -dari jalur lainnya- Dan telah menceritakan kepada kami [Ibnu Al-Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Amru bin Murrah] saya telah mendengar [Ibnu Abi Laila] berkata; Pelaksanaan shalat itu telah mengalami tiga kali perubahan. Dia berkata; Telah menceritakan kepada kami [Sahabat sahabat kami], bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh saya sangat senang, sekiranya pelaksanaan shalat kaum Muslimin atau Mukminin dapat dijadikan satu (Jama'ah), sehingga saya mempunyai keinginan yang besar untuk menyebarkan orang orang ke kampung-kampung menyerukan waktu shalat kepada orang banyak. Dan saya mempunyai keinginan besar untuk memerintahkan beberapa orang berdiri di atas bangunan bangunan tinggi menyerukan waktu shalat kepada kaum Muslimin, sehingga mereka memukul atau hampir saja memukul kentongan.\" Dia berkata; Maka datang seorang laki laki dari kaum Anshar, lalu berkata; Wahai Rasulullah, sesungguhnya ketika saya pulang, karena sedemikian besar perhatianku terhadap perhatianmu (tentang cara pelaksanaan shalat), saya melihat seorang laki laki seakan akan memakai dua kain hijau. Lalu orang tersebut berdiri di atas masjid dan mengumandangkan adzan. Kemudian dia duduk sebentar, lalu berdiri lagi mengucapkan yang diucapkan sebelumnya, hanya saja dia mengucapkan (untuk yang kedua kalinya) Qad qaamatis shalaah (sholat telah di kerjakan), seandianya bukan karena takut nanti orang-orang akan mengatakan (saya berdusta), Ibnu Al-Mutsanna menyebutkan; seandainya bukan karena takut nanti kalian akan mengatakan (saya berdusta), tentu saya mengatakan bahwa sungguh saya ketika itu dalam keadaan terjaga, tidak tidur. Maka Rasulullah shallallahu 'alaihi wasallam bersabda, -Ibnu Al-Mutsanna menyebutkan; beliau bersabda: - \"Sungguh Allah telah memperlihatkan kepadamu suatu kebaikan -Sedangkan Amru tidak menyebutkan sabda beliau: Allah telah memperlihatkan kepadamu suatu kebaikan-, maka suruhlah Bilal untuk mengumandangkan adzan itu. Katanya; Lalu Umar berkata; Sungguh saya telah bermimpi seperti yang diimpikannya, tetapi karena saya didahului (untuk melaporkan kepada Rasulullah), maka saya merasa malu. Dan telah menceritakan kepada kami para sahabat kami; Biasanya seseorang jika dia datang (terlambat), bertanya kepada sebagian jama'ah itu, maka beritahukan kepadanya raka'at yang telah lewat (tertinggal). Sedangkan waktu itu, jama'ah yang bersama Rasulullah, ada yang berdiri, ada yang ruku, ada yang duduk, dan ada pula yang shalat bersama Rasulullah. Berkata [Ibnu Al-Mutssanna] berkata [Amru] telah menceritakan kepadaku [Hushain] dari [Ibnu Abi Laila] hingga datang Mu'adz. Berkata [Syu'bah] saya telah mendengarnya dari [Hushain], lalu perawi berkata; Saya tidak melihatnya pada keadaan… hingga ucapan: Demikian, maka lakukanlah itu. Abu Dawud berkata; Kemudian saya kembali pada hadits Amru bin Marzuq dia berkata; Mu'adz datang, kemudian mereka mengisyaratkan kepadanya. Syu'bah berkata; Ini saya dengar dari Hushain, dia berkata; Mu'adz berkata; Saya tidak melihatnya dalam satu kedaan melainkan saya padanya. Mu'adz berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Mu'adz telah menunjukkan satu sunnah kepada kalian, maka lakukanlah yang demikian.\" Dia Ibnu Abi Lailah berkata; Sahabat-sahabat kami telah menceritakan kepada kami, bahwasanya ketika Rasulullah shallallahu 'alaihi wasallam datang ke Madinah, beliau memerintahkan berpuasa tiga hari (tiap bulan), lalu turun perintah puasa pada bulan Ramadhan, sedangkan mereka adalah kaum yang tidak terbiasa berpuasa, sehingga puasa terasa amat berat bagi mereka. Maka mereka yang tidak berpuasa memberi makan orang miskin. Lalu turunlah ayat ini (yang artinya): (Karena itu, barangsiapa di antara kamu hadir (di negeri tempat tinggalnya) pada bulan itu, maka hendaklah dia berpuasa pada bulan itu). (Al-Baqarah: 185). Di dalam ayat ini disebutkan bahwa keringanan itu untuk orang sakit dan musafir. Karena itu, mereka diwajibkan berpuasa. Kata Ibnu Abi Lahi'ah; para sahabat kami telah menceritakan kepada kami, katanya; Kebiasaan saat itu, apabila seseorang memasuki waktu berbuka, lalu tidur sebelum makan, maka dia tidak makan malam itu sampai pagi. Dia berkata; Lalu Umar bin Khaththab datang kepada istrinya hendak mengumpulinya, namun istrinya berkata; Sesungguhnya saya telah tidur sebelum makan (berbuka), namun Umar menyangka bahwa istrinya itu hanya beralasan untuk menghindar darinya, karena itu Umar tetap mengumpulinya. Kemudian datang pula seorang laki laki yang berpuasa dari golongan Anshar, lalu dia hendak makan (berbuka), maka keluarganya berkata; Tunggu, kami akan menghangatkan makanan untukmu, Ialu laki laki itu tidur. Maka ketika pagi harinya, turunlah ayat kepada beliau shallallahu 'alaihi wasallam tentang peristiwa ini, ayat tersebut (artinya): \"Dihalalkan bagi kamu pada malam puasa mengumpuli istri istri kamu\". (QS. Albaqarah 187). "},{"p":"Muslim","n":1826,"ar":"حَدَّثَنِي عَمْرُو بْنُ سَوَّادٍ الْعَامِرِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَكُنَّا فِي رَمَضَانَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَاءَ صَامَ وَمَنْ شَاءَ أَفْطَرَ فَافْتَدَى بِطَعَامِ مِسْكِينٍ حَتَّى أُنْزِلَتْ هَذِهِ الْآيَةُ{ فَمَنْ شَهِدَ مِنْكُمْ الشَّهْرَ فَلْيَصُمْهُ }","trj":"Telah menceritakan kepadaku [Amru bin Sawwad Al 'Amiri] telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepada kami [Amru bin Harits] dari [Bukair bin Al Asyajj] dari [Yazid] Maula Salamah bin Al Akwa', dari [Salamah Al Akwa'] radliallahu 'anhu, bahwa ia berkata; Dulu, ketika kami memasuki bulan Ramadlan pada masa Rasulullah shallallahu 'alaihi wasallam siapa saja yang ingin, maka ia berpuasa dan siapa yang tidak suka, maka ia akan berbuka dengan syarat membayar fidyah, peritstiwa itu terus terjadi hingga turunnya ayat: \"Karena itu, barangsiapa di antara kamu hadir (di negeri tempat tinggalnya) di bulan itu, Maka hendaklah ia berpuasa pada bulan itu.\" (QS. Albaqarah 185)."}],"2:187":[{"p":"Abu Dawud","n":414,"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ سَمِعْتُ ابْنَ أَبِي لَيْلَى قَالَ أُحِيلَتْ الصَّلَاةُ ثَلَاثَةَ أَحْوَالٍ قَالَ وَحَدَّثَنَا أَصْحَابُنَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ أَعْجَبَنِي أَنْ تَكُونَ صَلَاةُ الْمُسْلِمِينَ أَوْ قَالَ الْمُؤْمِنِينَ وَاحِدَةً حَتَّى لَقَدْ هَمَمْتُ أَنْ أَبُثَّ رِجَالًا فِي الدُّورِ يُنَادُونَ النَّاسَ بِحِينِ الصَّلَاةِ وَحَتَّى هَمَمْتُ أَنْ آمُرَ رِجَالًا يَقُومُونَ عَلَى الْآطَامِ يُنَادُونَ الْمُسْلِمِينَ بِحِينِ الصَّلَاةِ حَتَّى نَقَسُوا أَوْ كَادُوا أَنْ يَنْقُسُوا قَالَ فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَمَّا رَجَعْتُ لِمَا رَأَيْتُ مِنْ اهْتِمَامِكَ رَأَيْتُ رَجُلًا كَأَنَّ عَلَيْهِ ثَوْبَيْنِ أَخْضَرَيْنِ فَقَامَ عَلَى الْمَسْجِدِ فَأَذَّنَ ثُمَّ قَعَدَ قَعْدَةً ثُمَّ قَامَ فَقَالَ مِثْلَهَا إِلَّا أَنَّهُ يَقُولُ قَدْ قَامَتْ الصَّلَاةُ وَلَوْلَا أَنْ يَقُولَ النَّاسُ قَالَ ابْنُ الْمُثَنَّى أَنْ تَقُولُوا لَقُلْتُ إِنِّي كُنْتُ يَقْظَانَ غَيْرَ نَائِمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ ابْنُ الْمُثَنَّى لَقَدْ أَرَاكَ اللَّهُ عَزَّ وَجَلَّ خَيْرًا وَلَمْ يَقُلْ عَمْرٌو لَقَدْ أَرَاكَ اللَّهُ خَيْرًا فَمُرْ بِلَالًا فَلْيُؤَذِّنْ قَالَ فَقَالَ عُمَرُ أَمَا إِنِّي قَدْ رَأَيْتُ مِثْلَ الَّذِي رَأَى وَلَكِنِّي لَمَّا سُبِقْتُ اسْتَحْيَيْتُ قَالَ وَحَدَّثَنَا أَصْحَابُنَا قَالَ وَكَانَ الرَّجُلُ إِذَا جَاءَ يَسْأَلُ فَيُخْبَرُ بِمَا سُبِقَ مِنْ صَلَاتِهِ وَإِنَّهُمْ قَامُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَيْنِ قَائِمٍ وَرَاكِعٍ وَقَاعِدٍ وَمُصَلٍّ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ ابْنُ الْمُثَنَّى قَالَ عَمْرٌو وَحَدَّثَنِي بِهَا حُصَيْنٌ عَنْ ابْنِ أَبِي لَيْلَى حَتَّى جَاءَ مُعَاذٌ قَالَ شُعْبَةُ وَقَدْ سَمِعْتُهَا مِنْ حُصَيْنٍ فَقَالَ لَا أَرَاهُ عَلَى حَالٍ إِلَى قَوْلِهِ كَذَلِكَ فَافْعَلُوا قَالَ أَبُو دَاوُد ثُمَّ رَجَعْتُ إِلَى حَدِيثِ عَمْرِو بْنِ مَرْزُوقٍ قَالَ فَجَاءَ مُعَاذٌ فَأَشَارُوا إِلَيْهِ قَالَ شُعْبَةُ وَهَذِهِ سَمِعْتُهَا مِنْ حُصَيْنٍ قَالَ فَقَالَ مُعَاذٌ لَا أَرَاهُ عَلَى حَالٍ إِلَّا كُنْتُ عَلَيْهَا قَالَ فَقَالَ إِنَّ مُعَاذًا قَدْ سَنَّ لَكُمْ سُنَّةً كَذَلِكَ فَافْعَلُوا قَالَ و حَدَّثَنَا أَصْحَابُنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَدِمَ الْمَدِينَةَ أَمَرَهُمْ بِصِيَامِ ثَلَاثَةِ أَيَّامٍ ثُمَّ أُنْزِلَ رَمَضَانُ وَكَانُوا قَوْمًا لَمْ يَتَعَوَّدُوا الصِّيَامَ وَكَانَ الصِّيَامُ عَلَيْهِمْ شَدِيدًا فَكَانَ مَنْ لَمْ يَصُمْ أَطْعَمَ مِسْكِينًا فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَمَنْ شَهِدَ مِنْكُمْ الشَّهْرَ فَلْيَصُمْهُ }فَكَانَتْ الرُّخْصَةُ لِلْمَرِيضِ وَالْمُسَافِرِ فَأُمِرُوا بِالصِّيَامِ قَالَ و حَدَّثَنَا أَصْحَابُنَا قَالَ وَكَانَ الرَّجُلُ إِذَا أَفْطَرَ فَنَامَ قَبْلَ أَنْ يَأْكُلَ لَمْ يَأْكُلْ حَتَّى يُصْبِحَ قَالَ فَجَاءَ عُمَرُ بْنُ الْخَطَّابِ فَأَرَادَ امْرَأَتَهُ فَقَالَتْ إِنِّي قَدْ نِمْتُ فَظَنَّ أَنَّهَا تَعْتَلُّ فَأَتَاهَا فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَأَرَادَ الطَّعَامَ فَقَالُوا حَتَّى نُسَخِّنَ لَكَ شَيْئًا فَنَامَ فَلَمَّا أَصْبَحُوا أُنْزِلَتْ عَلَيْهِ هَذِهِ الْآيَةُ{ أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ }","trj":"Telah menceritakan kepada kami [Amru bin Marzuq] telah mengabarkan kepada kami [Syu'bah] dari [Amru bin Murrah] dia berkata; Saya telah mendengar [Ibnu Abi Laila] -dari jalur lainnya- Dan telah menceritakan kepada kami [Ibnu Al-Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Amru bin Murrah] saya telah mendengar [Ibnu Abi Laila] berkata; Pelaksanaan shalat itu telah mengalami tiga kali perubahan. Dia berkata; Telah menceritakan kepada kami [Sahabat sahabat kami], bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh saya sangat senang, sekiranya pelaksanaan shalat kaum Muslimin atau Mukminin dapat dijadikan satu (Jama'ah), sehingga saya mempunyai keinginan yang besar untuk menyebarkan orang orang ke kampung-kampung menyerukan waktu shalat kepada orang banyak. Dan saya mempunyai keinginan besar untuk memerintahkan beberapa orang berdiri di atas bangunan bangunan tinggi menyerukan waktu shalat kepada kaum Muslimin, sehingga mereka memukul atau hampir saja memukul kentongan.\" Dia berkata; Maka datang seorang laki laki dari kaum Anshar, lalu berkata; Wahai Rasulullah, sesungguhnya ketika saya pulang, karena sedemikian besar perhatianku terhadap perhatianmu (tentang cara pelaksanaan shalat), saya melihat seorang laki laki seakan akan memakai dua kain hijau. Lalu orang tersebut berdiri di atas masjid dan mengumandangkan adzan. Kemudian dia duduk sebentar, lalu berdiri lagi mengucapkan yang diucapkan sebelumnya, hanya saja dia mengucapkan (untuk yang kedua kalinya) Qad qaamatis shalaah (sholat telah di kerjakan), seandianya bukan karena takut nanti orang-orang akan mengatakan (saya berdusta), Ibnu Al-Mutsanna menyebutkan; seandainya bukan karena takut nanti kalian akan mengatakan (saya berdusta), tentu saya mengatakan bahwa sungguh saya ketika itu dalam keadaan terjaga, tidak tidur. Maka Rasulullah shallallahu 'alaihi wasallam bersabda, -Ibnu Al-Mutsanna menyebutkan; beliau bersabda: - \"Sungguh Allah telah memperlihatkan kepadamu suatu kebaikan -Sedangkan Amru tidak menyebutkan sabda beliau: Allah telah memperlihatkan kepadamu suatu kebaikan-, maka suruhlah Bilal untuk mengumandangkan adzan itu. Katanya; Lalu Umar berkata; Sungguh saya telah bermimpi seperti yang diimpikannya, tetapi karena saya didahului (untuk melaporkan kepada Rasulullah), maka saya merasa malu. Dan telah menceritakan kepada kami para sahabat kami; Biasanya seseorang jika dia datang (terlambat), bertanya kepada sebagian jama'ah itu, maka beritahukan kepadanya raka'at yang telah lewat (tertinggal). Sedangkan waktu itu, jama'ah yang bersama Rasulullah, ada yang berdiri, ada yang ruku, ada yang duduk, dan ada pula yang shalat bersama Rasulullah. Berkata [Ibnu Al-Mutssanna] berkata [Amru] telah menceritakan kepadaku [Hushain] dari [Ibnu Abi Laila] hingga datang Mu'adz. Berkata [Syu'bah] saya telah mendengarnya dari [Hushain], lalu perawi berkata; Saya tidak melihatnya pada keadaan… hingga ucapan: Demikian, maka lakukanlah itu. Abu Dawud berkata; Kemudian saya kembali pada hadits Amru bin Marzuq dia berkata; Mu'adz datang, kemudian mereka mengisyaratkan kepadanya. Syu'bah berkata; Ini saya dengar dari Hushain, dia berkata; Mu'adz berkata; Saya tidak melihatnya dalam satu kedaan melainkan saya padanya. Mu'adz berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Mu'adz telah menunjukkan satu sunnah kepada kalian, maka lakukanlah yang demikian.\" Dia Ibnu Abi Lailah berkata; Sahabat-sahabat kami telah menceritakan kepada kami, bahwasanya ketika Rasulullah shallallahu 'alaihi wasallam datang ke Madinah, beliau memerintahkan berpuasa tiga hari (tiap bulan), lalu turun perintah puasa pada bulan Ramadhan, sedangkan mereka adalah kaum yang tidak terbiasa berpuasa, sehingga puasa terasa amat berat bagi mereka. Maka mereka yang tidak berpuasa memberi makan orang miskin. Lalu turunlah ayat ini (yang artinya): (Karena itu, barangsiapa di antara kamu hadir (di negeri tempat tinggalnya) pada bulan itu, maka hendaklah dia berpuasa pada bulan itu). (Al-Baqarah: 185). Di dalam ayat ini disebutkan bahwa keringanan itu untuk orang sakit dan musafir. Karena itu, mereka diwajibkan berpuasa. Kata Ibnu Abi Lahi'ah; para sahabat kami telah menceritakan kepada kami, katanya; Kebiasaan saat itu, apabila seseorang memasuki waktu berbuka, lalu tidur sebelum makan, maka dia tidak makan malam itu sampai pagi. Dia berkata; Lalu Umar bin Khaththab datang kepada istrinya hendak mengumpulinya, namun istrinya berkata; Sesungguhnya saya telah tidur sebelum makan (berbuka), namun Umar menyangka bahwa istrinya itu hanya beralasan untuk menghindar darinya, karena itu Umar tetap mengumpulinya. Kemudian datang pula seorang laki laki yang berpuasa dari golongan Anshar, lalu dia hendak makan (berbuka), maka keluarganya berkata; Tunggu, kami akan menghangatkan makanan untukmu, Ialu laki laki itu tidur. Maka ketika pagi harinya, turunlah ayat kepada beliau shallallahu 'alaihi wasallam tentang peristiwa ini, ayat tersebut (artinya): \"Dihalalkan bagi kamu pada malam puasa mengumpuli istri istri kamu\". (QS. Albaqarah 187). "},{"p":"Ahmad","n":2431,"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ عَنِ الشَّعْبِيِّ أَخْبَرَنَا عَدِيُّ بْنُ حَاتِمٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }قَالَ عَمَدْتُ إِلَى عِقَالَيْنِ أَحَدُهُمَا أَسْوَدُ وَالْآخَرُ أَبْيَضُ فَجَعَلْتُهُمَا تَحْتَ وِسَادِي قَالَ ثُمَّ جَعَلْتُ أَنْظُرُ إِلَيْهِمَا فَلَا تُبِينُ لِي الْأَسْوَدَ مِنْ الْأَبْيَضِ وَلَا الْأَبْيَضَ مِنْ الْأَسْوَدِ فَلَمَّا أَصْبَحْتُ غَدَوْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِالَّذِي صَنَعْتُ فَقَالَ إِنْ كَانَ وِسَادُكَ إِذًا لَعَرِيضٌ إِنَّمَا ذَلِكَ بَيَاضُ النَّهَارِ مِنْ سَوَادِ اللَّيْلِ","trj":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Hushain] dari [Asy Sya'bi] telah mengabarkan kepada kami [Adi bin Hatim] ia berkata; Ketika ayat ini turun: \"Dan makan minumlah hingga terang bagimu benang putih dari benang hitam, yaitu fajar.\" (QS. Albaqarah 187), Saya pun pergi mengambil dua benang yang satu berwarna putih sedang yang satunya lagi berwarna hitam. Lalu saya meletakkan di bawah bantalku, kemudian saya mencoba melihatnya, namun bagiku tidak tampak jelas antara yang putih dan hitam atau pun sebaliknya. Pada pagi harinya, saya mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengabarkan hal apa yang telah saya perbuat. Maka beliau bersabda: \"Kalau begitu, bantalmu panjang sekali. Hanyasanya maksudnya adalah putihnya siang daripada kegelapan malam.\""},{"p":"Darimi","n":1278,"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَ كَانَ أَصْحَابُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الرَّجُلُ صَائِمًا فَحَضَرَ الْإِفْطَارُ فَنَامَ قَبْلَ أَنْ يُفْطِرَ لَمْ يَأْكُلْ لَيْلَتَهُ وَلَا يَوْمَهُ حَتَّى يُمْسِيَ وَإِنَّ قَيْسَ بْنَ صِرْمَةَ الْأَنْصَارِيَّ كَانَ صَائِمًا فَلَمَّا حَضَرَ الْإِفْطَارُ أَتَى امْرَأَتَهُ فَقَالَ عِنْدَكِ طَعَامٌ فَقَالَتْ لَا وَلَكِنْ أَنْطَلِقُ فَأَطْلُبُ لَكَ وَكَانَ يَوْمَهُ يَعْمَلُ فَغَلَبَتْهُ عَيْنُهُ وَجَاءَتْ امْرَأَتُهُ فَلَمَّا رَأَتْهُ قَالَتْ خَيْبَةً لَكَ فَلَمَّا انْتَصَفَ النَّهَارُ غُشِيَ عَلَيْهِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ هَذِهِ الْآيَةُ { أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ } فَفَرِحُوا بِهَا فَرَحًا شَدِيدًا { وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }","trj":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Bara`] ia berkata, \"Para sahabat Muhammad shallallahu 'alaihi wasallam; apabila seseorang berpuasa kemudian datang waktu berbuka, maka ia tidur sebelum berbuka, sehingga ia tidak berbuka sehari semalam hingga masuk pada waktu sore. Sesungguhnya Qais bin Shirmah Al Anshari pernah berpuasa, saat waktu berbuka tiba ia menemui isterinya dan bertanya, \"Apakah engkau memiliki makanan?\" Lalu isterinya mengatakan, \"Tidak, akan tetapi aku akan pergi dan mencari untukmu.\" Karena seharian ia lelah bekerja, maka ia pun tertidur. Maka saat isterinya melihatnya, ia berkata, \"Duhai, merugilah engkau.\" Kemudian tatkala pada pertengahan siang hari Qais bin Shirmah pingsan. Lalu hal itu diceritakan kepada Nabi shallallahu 'alaihi wasallam, kemudian turunlah ayat ini: '(Dihalalkan bagi kamu pada malam hari bulan puasa bercampur dengan isteri-isteri kamu) ' maka mereka sangat senang sekali '(dan makan minumlah hingga terang bagimu benang putih dari benang hitam) ' (Qs. Al Baqarah: 187)."},{"p":"Nasa'i","n":2095,"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ تَعَالَى{ حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }قَالَ هُوَ سَوَادُ اللَّيْلِ وَبَيَاضُ النَّهَارِ","trj":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Jarir] dari [Mutharrif] dari [Asy Sya'bi] dari ['Adi bin Hatim] bahwa ia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang firman Allah Ta'ala: \" Hingga terang bagimu benang putih dan benang hitam.\" (Qs. Al Baqarah 2: 187) Beliau bersabda: \"Yaitu hitamnya malam dan putihnya siang.\""}],"2:189":[{"p":"Bukhari","n":1676,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ يَقُولُنَزَلَتْ هَذِهِ الْآيَةُ فِينَا كَانَتْ الْأَنْصَارُ إِذَا حَجُّوا فَجَاءُوا لَمْ يَدْخُلُوا مِنْ قِبَلِ أَبْوَابِ بُيُوتِهِمْ وَلَكِنْ مِنْ ظُهُورِهَا فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَدَخَلَ مِنْ قِبَلِ بَابِهِ فَكَأَنَّهُ عُيِّرَ بِذَلِكَ فَنَزَلَتْ{ وَلَيْسَ الْبِرُّ بِأَنْ تَأْتُوا الْبُيُوتَ مِنْ ظُهُورِهَا وَلَكِنَّ الْبِرَّ مَنْ اتَّقَى وَأْتُوا الْبُيُوتَ مِنْ أَبْوَابِهَا }","trj":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata; Aku mendengar [Al Bara' radliallahu 'anhu] berkata: \"Ayat ini turun kepada kami, yaitu Kaum Anshar jika mereka menunaikan haji lalu kembali pulang, mereka tidak memasuki rumah-rumah mereka dari pintu depannya namun mereka masuk dari belakang. Kemudian datanglah seseorang dari Kaum Anshar yang ia masuk dari pintu depan seakan-akan ia merubah kebiasaan tadi. Maka kemudian turunlah firman Allah QS Al Baqarah ayat 189 yang artinya: (\"Dan bukanlah kebajikan memasuki rumah-rumah dari belakangnya, akan tetapi kebajikan itu ialah kebajikan orang yang bertakwa. Dan masuklah ke rumah-rumah itu dari pintu-pintunya\")."}],"2:195":[{"p":"Bukhari","n":1648,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ الْهَيْثَمِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ عَمْرُو بْنُ دِينَارٍ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاكَانَ ذُو الْمَجَازِ وَعُكَاظٌ مَتْجَرَ النَّاسِ فِي الْجَاهِلِيَّةِ فَلَمَّا جَاءَ الْإِسْلَامُ كَأَنَّهُمْ كَرِهُوا ذَلِكَ حَتَّى نَزَلَتْ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ","trj":"Telah menceritakan kepada kami ['Utsman bin Al Haitsam] telah mengabarkan kepada kami [Ibnu Juraij] telah berkata, ['Amru bin Dinar] berkata, [Ibnu 'Abbas radliallahu 'anhuma]: \"Dzul Majaz dan Ukazh adalah tempat berdagang orang-orang pada masa jahiliyah. Ketika Islam datang seakan-akan mereka membenci tempat itu, hingga turunlah QS AL Baqarah ayat 195 yang artinya: (\"Tidak ada dosa bagi kalian jika kalian mencari karunia(rezeqi hasil perniagaan) dari Rabb kalian\"), yaitu pada musim haji."}],"2:196":[{"p":"Ahmad","n":1987,"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحُدَيْبِيَةِ وَنَحْنُ مُحْرِمُونَ وَقَدْ حَصَرَنَا الْمُشْرِكُونَ وَكَانَتْ لِي وَفْرَةٌ فَجَعَلَتْ الْهَوَامُّ تَسَّاقَطُ عَلَى وَجْهِي فَمَرَّ بِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُؤْذِيكَ هَوَامُّ رَأْسِكَ قُلْتُ نَعَمْ فَأَمَرَهُ أَنْ يَحْلِقَ قَالَ وَنَزَلَتْ هَذِهِ الْآيَةُ{ فَمَنْ كَانَ مِنْكُمْ مَرِيضًا أَوْ بِهِ أَذًى مِنْ رَأْسِهِ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }","trj":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Bisyr] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Ka'ab bin Ujrah] ia berkata, \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam di Hudaibiyah dalam keadaan telah memakai pakaian ihram, lalu orang-orang musyrik mengepung kami. Aku adalah seorang yang mempunyai rambut panjang (hingga ujung telinga), lalu ada binatang-binatang kecil (semacam kutu) yang jatuh ke mukaku. Dan ketika Nabi shallallahu 'alaihi wasallam lewat di tempatku, beliau lalu bertanya: \"Apakah binatang-binatang kecil itu melukai kepalamu?\" Aku menjawab, \"Benar.\" Maka beliau pun memerintahkan agar ia mencukur rambutnya. Kemudian turunlah ayat ini: '(jika ada di antaramu yang sakit atau ada gangguan di kepalanya (lalu ia bercukur), Maka wajiblah atasnya berfidyah, yaitu; berpuasa atau bersedekah atau berkorban) ' (Qs. Al Baqarah: 196)."},{"p":"Ahmad","n":1992,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ قَالَقَعَدْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ وَهُوَ فِي الْمَسْجِدِ فَسَأَلْتُهُ عَنْ هَذِهِ الْآيَةِ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ فَقَالَ كَعْبٌ نَزَلَتْ فِيَّ كَانَ بِي أَذًى مِنْ رَأْسِي فَحُمِلْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي فَقَالَ مَا كُنْتُ أَرَى أَنَّ الْجَهْدَ بَلَغَ بِكَ مَا أَرَى أَتَجِدُ شَاةً فَقُلْتُ لَا فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ صَوْمُ ثَلَاثَةِ أَيَّامٍ أَوْ إِطْعَامُ سِتَّةِ مَسَاكِينَ نِصْفَ صَاعِ طَعَامٍ لِكُلِّ مِسْكِينٍ قَالَ فَنَزَلَتْ فِيَّ خَاصَّةً وَهِيَ لَكُمْ عَامَّةًحَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَ��ُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَصْبَهَانِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَعْقِلٍ يَقُولُ قَعَدْتُ إِلَى كَعْبٍ فِي هَذَا الْمَسْجِدِ فَذَكَرَ مَعْنَاهُ حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَصْبَهَانِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَعْقِلٍ قَالَ قَعَدْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ فِي هَذَا الْمَسْجِدِ فَسَأَلْتُهُ عَنْ هَذِهِ الْآيَةِ فَذَكَرَ الْحَدِيثَ وَقَالَ أَطْعِمْ سِتَّةَ مَسَاكِينَ كُلَّ مِسْكِينٍ نِصْفَ صَاعٍ مِنْ طَعَامٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Ashbahani] dari [Abdullah bin Ma'qil] ia berkata, \"Saya duduk bersama [Ka'ab bin Ujrah] di dalam Masjid, lalu saya bertanya kepadanya tentang ayat ini: '(Maka wajiblah atasnya berfidyah, yaitu: berpuasa atau bersedekah atau berkorban…) '. (Qs. Al Baqarah: 196). Ka'ab kemudian memberi penjelasan, \"Ayat ini turun berkenaan dengan diriku. Saat itu kepalaku terserang penyakit, lalu saya dibawa menghadap Rasulullah shallallahu 'alaihi wasallam, sementara kutu-kutu telah bertebaran di wajahku. Maka beliau berkata: \"Saya lihat penyakitmu sudah demikian parah, namun saya tidak memiliki pendapat lain. Apakah kamu mempunyai seekor kambing?\" saya menjawab, \"Tidak.\" Maka turunlah ayat ini: '(Maka wajiblah atasnya berfidyah, yaitu: berpuasa atau bersedekah atau berkorban) '. Beliau lantas bersabda: \"(Silahkan kamu) berpuasa tiga hari atau memberi makan kepada enam orang miskin, yakni setengah sha' untuk setiap orangnya.\" Ka'ab berkata, \"Maka ayat ini turun berkenaan dengan diriku secara khusus, dan bersifat umum bagi kalian.\" Telah menceritakan kepada kami [Affan] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abdurrahman bin Al Ashbahani] ia berkata, saya mendengar [Abdullah bin Ma'qil] berkata, \"Saya duduk bersama [Ka'ab] di dalam Masjid ini…lalu ia menyebutkan makna hadits tersebut.\" Telah menceritakan kepada kami [Bahz] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abdurrahman bin Al Ashbahani] ia berkata, \"Saya mendengar [Abdullah bin Ma'qil] berkata, \"Saya pernah duduk bersama [Ka'ab bin Ujrah] di dalam masjid ini, lalu saya bertanya kepadanya tentang ayat ini…lalu ia menyebutkan makna hadits tersebut.\" Beliau bersabda: \"Berilah makan kepada enam orang Miskin. Setiap orang miskin adalah setengah sha' makanan.\""},{"p":"Bukhari","n":1457,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَوْمٍ بِالْيَمَنِ فَجِئْتُ وَهُوَ بِالْبَطْحَاءِ فَقَالَ بِمَا أَهْلَلْتَ قُلْتُ أَهْلَلْتُ كَإِهْلَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَلْ مَعَكَ مِنْ هَدْيٍ قُلْتُ لَا فَأَمَرَنِي فَطُفْتُ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ أَمَرَنِي فَأَحْلَلْتُ فَأَتَيْتُ امْرَأَةً مِنْ قَوْمِي فَمَشَطَتْنِي أَوْ غَسَلَتْ رَأْسِي فَقَدِمَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَ إِنْ نَأْخُذْ بِكِتَابِ اللَّهِ فَإِنَّهُ يَأْمُرُنَا بِالتَّمَامِ قَالَ اللَّهُ{ وَأَتِمُّوا الْحَجَّ وَالْعُمْرَةَ لِلَّهِ }وَإِنْ نَأْخُذْ بِسُنَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّهُ لَمْ يَحِلَّ حَتَّى نَحَرَ الْهَدْيَ","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Qais bin Muslim] dari [Thoriq bin Syihab] dari [Abu Musa radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam mengutusku kepada suatu kaum di negeri Yaman. Ketika aku sudah kembali aku menemui Beliau ketika Beliau berada di Batha'. Beliau berkata, kepadaku: \"Bagaimana cara kamu berihram (memulai hajji)?\". Aku menjawab: \"Aku berihram sebagaimana Nabi shallallahu 'alaihi wasallam berihram\". Beliau bertanya lagi: \"Apakah kamu ada membawa hewan qurban?. Aku menjawab: \"Tidak\". Maka Beliau memerintahkan aku agar aku melakukan thowaf di Baitulloh dan sa'iy antara bukit Ash-Shafa dan Al Marwah lalu memerintahkan aku pula agar aku bertahallul. Lalu aku temui seorang wanita dari keluargaku lalu dia menyisir rambutku atau membasuh kepalaku. Lalu 'Umar radliallahu 'anhu datang dan berkata: \"Jika kita mengambil pedoman dari Kitab Allah, sesungguhnya Dia memerintahkan kita agar kita menyempurnakannya (hajji dan 'umrah). Allah subhanahu wata'ala berfirman (Qs Al Baqarah ayat 196) yang artinya: (\"Dan semprurnakanlah 'ibadah hajji dan 'umrah kalian karena Allah) \", dan seandainya kita mengambil pedoman dari sunnah Rasulullah Shallallahu'alaihiwasallam, sesungguhnya Beliau tidak bertahallul kecuali setelah menyembelih hewan qurban\". "},{"p":"Bukhari","n":1687,"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَيْفٌ قَالَ حَدَّثَنِي مُجَاهِدٌ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى أَنَّ كَعْبَ بْنَ عُجْرَةَ حَدَّثَهُ قَالَوَقَفَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحُدَيْبِيَةِ وَرَأْسِي يَتَهَافَتُ قَمْلًا فَقَالَ يُؤْذِيكَ هَوَامُّكَ قُلْتُ نَعَمْ قَالَ فَاحْلِقْ رَأْسَكَ أَوْ قَالَ احْلِقْ قَالَ فِيَّ نَزَلَتْ هَذِهِ الْآيَةُ{ فَمَنْ كَانَ مِنْكُمْ مَرِيضًا أَوْ بِهِ أَذًى مِنْ رَأْسِهِ }إِلَى آخِرِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ ثَلَاثَةَ أَيَّامٍ أَوْ تَصَدَّقْ بِفَرَقٍ بَيْنَ سِتَّةٍ أَوْ انْسُكْ بِمَا تَيَسَّرَ","trj":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sayf] berkata, telah menceritakan kepada saya [Mujahid] berkata, aku mendengar ['Abdurrahman bin Abu Laila] bahwa [Ka'ab bin 'Ujrah radliallahu 'anhu] berkata: \"Rasulullah shallallahu 'alaihi wasallam menghampiriku di Hudaibiyah ketika kepalaku dipenuhi kutu, Beliau berkata: \"Barangkali kamu terkena serangga (kutu di kepala)?\". Aku jawab: \"Benar, wahai Rasulullah\". Maka Beliau berkata: \"Cukurlah rambutnu\". Atau dia berkata: \"Ayat ini turun untukku\" (QS Al Baqarah ayat 196 yang artinya): (\"....Maka barangsiapa dari kalian yang sakit atau tertimpa sesuatu pada kepalanya...) hingga akhir ayat. Maka Nabi shallallahu 'alaihi wasallam berkata: \"Laksanakanlah shaum tiga hari atau bershadaqah sebanyak faraq (tiga sha') terhadap enam orang atau berqurban dengan yang mudah buatmu\". "},{"p":"Ibnu Majah","n":3035,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ قَالَقَعَدْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ فِي الْمَسْجِدِ فَسَأَلْتُهُ عَنْ هَذِهِ الْآيَةِ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ كَعْبٌ فِيَّ أُنْزِلَتْ كَانَ بِي أَذًى مِنْ رَأْسِي فَحُمِلْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي فَقَالَ مَا كُنْتُ أُرَى الْجُهْدَ بَلَغَ بِكَ مَا أَرَى أَتَجِدُ شَاةً قُلْتُ لَا قَالَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ فَالصَّوْمُ ثَلَاثَةُ أَيَّامٍ وَالصَّدَقَةُ عَلَى سِتَّةِ مَسَاكِينَ لِكُلِّ مِسْكِينٍ نِصْفُ صَاعٍ مِنْ طَعَامٍ وَالنُّسُكُ شَاةٌ","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Walid], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Ashbahani] dari [Abdullah bin Ma'qil], ia berkata; \"Aku duduk di samping [Ka'ab bin 'Ujrah] di dalam masjid, lalu kutanyai tentang firman Allah; '..maka wajiblah atasnya berfidyah, yaitu berpuasa atau bersedekah atau berkurban…' (Qs Albaqarah 2: 196), Ka'ab pun menjawab; 'Ayat itu diturunkan tentang diriku. Karena dulu aku pernah terserang penyakit di kepalaku, lalu aku dibawa kepada Rasulullah shallallahu 'alaihi wasallam sedang kutu busuk berhamburan di wajahku.' Maka beliau bersabda: 'Aku tidak seharusnya melihat keletihan yang menimpamu seperti yang kulihat ini. Apakah kamu memiliki seekor kambing? ' Aku menjawab; 'Tidak.' (Perawi berkata); 'Maka turunlah ayat ini, '..maka wajiblah atasnya berfidyah, yaitu berpuasa, atau bersedekah atau berkurban..' (Perawi) berkata; 'Puasa tiga hari, sedekah untuk enam orang miskin dan setiap satu orang miskin diberi setengah sha' makanan pokok, serta berkurban dengan seekor kambing.'"},{"p":"Malik","n":761,"ar":"و حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ كَانَ يَقُولُ{ مَا اسْتَيْسَرَ مِنْ الْهَدْيِ }شَاةٌ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Ali bin Abu Thalib] berkata; \"'Binatang sembelihan yang paling mudah (didapat) ..-Qs. Al Baqarah: 196- adalah kambing.\""}],"2:197":[{"p":"Bukhari","n":1426,"ar":"حَدَّثَنَا يَحْيَى بْنُ بِشْرٍ حَدَّثَنَا شَبَابَةُ عَنْ وَرْقَاءَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ أَهْلُ الْيَمَنِ يَحُجُّونَ وَلَا يَتَزَوَّدُونَ وَيَقُولُونَ نَحْنُ الْمُتَوَكِّلُونَ فَإِذَا قَدِمُوا مَكَّةَ سَأَلُوا النَّاسَ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَتَزَوَّدُوا فَإِنَّ خَيْرَ الزَّادِ التَّقْوَى }رَوَاهُ ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ عِكْرِمَةَ مُرْسَلًا","trj":"Telah menceritakan kepada kami [Yahya bin Bisir] telah menceritakan kepada kami [Syababah] dari [Warqa'] dari ['Amru bin Dinar] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] ia berkata; \"Dahulu para penduduk Yaman berhajji namun mereka tidak membawa bekal dan mereka berkata, kami adalah orang-orang yang bertawakal. Ketika mereka tiba di Makkah, mereka meminta-minta kepada manusia. Maka Allah Ta'ala menurunkan ayat 197 dari QS Al Baqarah) yang artinya (\"Berbekallah, dan sesungguhnya sebaik-baik bekal adalah takwa\".) Dan diriwayatkan pula oleh [Ibnu 'Uyainah] dari ['Amru] dari ['Ikrimah] secara mursal."},{"p":"Bukhari","n":1782,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِس��رَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ أَصْحَابُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الرَّجُلُ صَائِمًا فَحَضَرَ الْإِفْطَارُ فَنَامَ قَبْلَ أَنْ يُفْطِرَ لَمْ يَأْكُلْ لَيْلَتَهُ وَلَا يَوْمَهُ حَتَّى يُمْسِيَ وَإِنَّ قَيْسَ بْنَ صِرْمَةَ الْأَنْصَارِيَّ كَانَ صَائِمًا فَلَمَّا حَضَرَ الْإِفْطَارُ أَتَى امْرَأَتَهُ فَقَالَ لَهَا أَعِنْدَكِ طَعَامٌ قَالَتْ لَا وَلَكِنْ أَنْطَلِقُ فَأَطْلُبُ لَكَ وَكَانَ يَوْمَهُ يَعْمَلُ فَغَلَبَتْهُ عَيْنَاهُ فَجَاءَتْهُ امْرَأَتُهُ فَلَمَّا رَأَتْهُ قَالَتْ خَيْبَةً لَكَ فَلَمَّا انْتَصَفَ النَّهَارُ غُشِيَ عَلَيْهِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ }فَفَرِحُوا بِهَا فَرَحًا شَدِيدًا وَنَزَلَتْ{ وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }","trj":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Isra'il] dari [Abu Ishaq] dari [Al Bara' radliallahu 'anhu] berkata; \"Diantara para sahabat Muhammad shallallahu 'alaihi wasallam ada seseorang apabila sedang shaum lalu tiba waktu berbuka dia pergi tidur sebelum berbuka sehingga dia tidak memakan sesuatu pada malam dan siang hari hingga petang hari. Dan pada suatu ketika Qais bin Shirmah Al Anshariy ketika sedang melaksanakan shaum lalu tiba waktu berbuka dia mendatangi isterinya seraya berkata, kepada isterinya: \"Apakah kamu punya makanan?\" Isterinya berkata: \"Tidak, namun aku akan keluar mencari makanan buatmu\". Kemudian di siang harinya dia bekerja keras hingga mengantuk lalu tertidur. Kemudian isterinya datang. Ketika isterinya melihat dia (sedang tertidur), isterinya berkata: \"Rugilah kamu\". Kemudian pada tengah harinya Qais jatuh pingsan. Lalu persoalan ini diadukan kepada Nabi shallallahu 'alaihi wasallam, maka turunlah firman Allah Ta'ala QS Al Baqarah ayat 197 yang artinya: (\"Dihalalkan bagi kalian pada malam bulan puasa bercampur dengan isttri-isteri kalian\"). Dengan turunnya ayat ini para sahabat merasa sangat senang, hingga kemudian turun sambungan ayatnya: (\"Dan makan minumlah kalian hingga terang bagi kalian benang putih dari benang hitam yaitu di waktu fajar\")."},{"p":"Bukhari","n":1783,"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنِي حُصَيْنُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ{ حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }عَمَدْتُ إِلَى عِقَالٍ أَسْوَدَ وَإِلَى عِقَالٍ أَبْيَضَ فَجَعَلْتُهُمَا تَحْتَ ��ِسَادَتِي فَجَعَلْتُ أَنْظُرُ فِي اللَّيْلِ فَلَا يَسْتَبِينُ لِي فَغَدَوْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ ذَلِكَ فَقَالَ إِنَّمَا ذَلِكَ سَوَادُ اللَّيْلِ وَبَيَاضُ النَّهَارِ","trj":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada saya [Hushain bin 'Abdurrahman] dari [Asy-Sya'biy] dari ['Adi bin Hatim radliallahu 'anhu] berkata: Ketika turun QS Al Baqarah ayat 197 (\"… hingga terang bagi kalian benang putih dari benang hitam yaitu di waktu fajar\"), maka aku mengambil benang hitam dan benang putih lalu aku letakkan di bawah bantalku untuk aku lihat pada sebagian malam namun tidak tampak olehku. Maka di pagi harinya aku menemui Rasulullah shallallahu 'alaihi wasallam lalu aku ceritakan hal tadi. Maka Beliau bersabda: \"Sesungguhnya yang dimaksud dengan ayat itu adalah gelapnya malam dan terangya siang\". "}],"2:198":[{"p":"Bukhari","n":1909,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ عُكَاظٌ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقًا فِي الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ فَكَأَنَّهُمْ تَأَثَّمُوا فِيهِ فَنَزَلَتْ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ قَرَأَهَا ابْنُ عَبَّاسٍ","trj":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"'Ukazh, Majannah dan Dzul Majaz adalah nama-nama pasar di zaman Jahiliyyah. Ketika Islam datang mereka seakan-akan merasa berdosa bila tetap berdagang di pasar-pasar tersebut. Maka turunlah firman Allah Ta'ala QS Al Baqarah ayat 198 yang artinya: (\"Tidak ada dosa bagi kalian jika mencari karunia rezeqi Rabb kalian…..\"). Ini dilakukan selama musim hajji, menurut pendapat Ibnu 'Abbas radliallahu 'anhuma."},{"p":"Bukhari","n":1956,"ar":"حَدَّثَنَا عَلِيُّ بْن�� عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ عُكَاظٌ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقًا فِي الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ تَأَثَّمُوا مِنْ التِّجَارَةِ فِيهَا فَأَنْزَلَ اللَّهُ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ قَرَأَ ابْنُ عَبَّاسٍ كَذَا","trj":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"'Ukazh, Majannah dan Dzul Majaz adalah nama-nama pasar di zaman Jahiliyyah. Ketika Islam datang mereka seakan merasa berdosa bila tetap berdagang di pasar-pasar tersebut. Maka turunlah firman Allah Ta'ala QS Al Baqarah ayat 198 yang artinya: (\"Tidak ada dosa bagi kalian jika mencari karunia rezeqi Rabb kalian…..\"). Ini dilakukan selama musim hajji, menurut pendapat Ibnu 'Abbas radliallahu 'anhuma."},{"p":"Bukhari","n":3852,"ar":"حَدَّثَنِي مُحَمَّدٌ قَالَ أَخْبَرَنِي ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ عُكَاظُ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقًا فِي الْجَاهِلِيَّةِ فَتَأَثَّمُوا أَنْ يَتَّجِرُوا فِي الْمَوَاسِمِ فَنَزَلَتْ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ","trj":"Telah menceritakan kepadaku [Muhammad] dia berkata; Telah mengabarkan kepadaku [Ibnu Uyainah] dari [Amru] dari [Ibnu Abbas radliallahu 'anhuma] dia berkata; Ukazh, Majanah, Dzul Majaz adalah pasar-pasar yang ada pada masa jahiliyah. Mereka merasa takut berdosa bila berjualan pada musim haji. Maka turunlah ayat; Bukanlah suatu dosa bagimu sekalian mencari karunia dari Rabb kalian. (QS. Albaqarah 198). Yaitu pada musim haji."}],"2:199":[{"p":"Bukhari","n":1554,"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ عُرْوَةُ كَانَ النَّاسُ يَطُوفُونَ فِي الْجَاهِلِيَّةِ عُرَاةً إِلَّا الْحُمْسَ وَالْحُمْسُ قُرَيْشٌ وَمَا وَلَدَتْ وَكَانَتْ الْحُمْسُ يَحْتَسِبُونَ عَلَى النَّاسِ يُعْطِي الرَّجُلُ الرَّجُلَ الثِّيَابَ يَطُوفُ فِيهَا وَتُعْطِي الْمَرْأَةُ الْمَرْأَةَ الثِّيَابَ تَطُوفُ فِيهَا فَمَنْ لَمْ يُعْطِهِ الْحُمْسُ طَافَ بِالْبَيْتِ عُرْيَانًا وَكَانَ يُفِيضُ جَمَاعَةُ النَّاسِ مِنْ عَرَفَاتٍ وَيُفِيضُ الْحُمْسُ مِنْ جَمْعٍ قَالَ وَأَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ هَذِهِ الْآيَةَ نَزَلَتْ فِي الْحُمْسِ{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }قَالَ كَانُوا يُفِيضُونَ مِنْ جَمْعٍ فَدُفِعُوا إِلَى عَرَفَاتٍ","trj":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra'] telah menceritakan kepada kami ['Ali bin Mushir] dari [Hisyam bin 'Urwah], ['Urwah] berkata: \"Pada masa Jahiliyah orang-orang melakukan thawaf dengan telanjang kecuali Al Humus dan istilah Al Humus adalah orang-orang Quraisy dan keturunan mereka. Dahulu Al Humus membeda-bedakan manusia, diantara kaum lelakinya ada yang memberi pakaian kepada kaum lelaki sehingga dia thawaf mengenakan pakaian, begitu juga diantara wanitanya memberi pakaian kepada para wanita sehingga dia thawaf dengan pakaian itu. Sedangkan bagi orang yang tidak diberi pakaian oleh Al Humus (quraisy) maka dia thawaf dengan telanjang. Rambongan orang-orang biasanya bertolak dari 'Arafah sedangkan Al Humus (quraisy) dari Jama', atau Muzdalifah. Dia berkata; bapakku telah mengabarkan kepada saya dari ['Aisyah radliallahu 'anha] bahwa ayat ini (QS Al Baqarah ayat 199) turun tentang Al Humus (yang artinya): (\"Kemudian bertolaklah kamu dari tempat bertolaknya orang banyak\"). 'Urwah berkata: \"Awalnya mereka selalu bertolak dari Jama', kemudian diperintahkan bertolak dari 'Arafah\". "},{"p":"Bukhari","n":3853,"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ خَازِمٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَانَتْ قُرَيْشٌ وَمَنْ دَانَ دِينَهَا يَقِفُونَ بِالْمُزْدَلِفَةِ وَكَانُوا يُسَمَّوْنَ الْحُمْسَ وَكَانَ سَائِرُ الْعَرَبِ يَقِفُونَ بِعَرَفَاتٍ فَلَمَّا جَاءَ الْإِسْلَامُ أَمَرَ اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْتِيَ عَرَفَاتٍ ثُمَّ يَقِفَ بِهَا ثُمَّ يُفِيضَ مِنْهَا فَذَلِكَ قَوْلُهُ تَعَالَى{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }","trj":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Muhammad bin Hazim] Telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari [Aisyah radliallahu 'anha], Suku Quraisy dan orang-orang yang memeluk agama mereka, biasa tinggal di Muzdalifah dan memanggil diri mereka sendiri dengan Al Hums, sementara orang-orang Arab lainnya biasa tinggal di Arafah. Ketika Islam datang, Allah memerintahkan Nabi shallallahu 'alaihi wasallam untuk tinggal di sana (dengan waktu yang telah ditentukan) dan kemudian berangkat dari sana. Itulah yang dimaksud firman Allah; \"Kemudian berangkatlah beramai-ramai dari tempat bertolaknya orang banyak\". (QS. Albaqarah 199)."},{"p":"Bukhari","n":3854,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي كُرَيْبٌ عَنْ ابْنِ عَبَّاسٍ قَالَيَطَّوَّفُ الرَّجُلُ بِالْبَيْتِ مَا كَانَ حَلَالًا حَتَّى يُهِلَّ بِالْحَجِّ فَإِذَا رَكِبَ إِلَى عَرَفَةَ فَمَنْ تَيَسَّرَ لَهُ هَدِيَّةٌ مِنْ الْإِبِلِ أَوْ الْبَقَرِ أَوْ الْغَنَمِ مَا تَيَسَّرَ لَهُ مِنْ ذَلِكَ أَيَّ ذَلِكَ شَاءَ غَيْرَ أَنَّهُ إِنْ لَمْ يَتَيَسَّرْ لَهُ فَعَلَيْهِ ثَلَاثَةُ أَيَّامٍ فِي الْحَجِّ وَذَلِكَ قَبْلَ يَوْمِ عَرَفَةَ فَإِنْ كَانَ آخِرُ يَوْمٍ مِنْ الْأَيَّامِ الثَّلَاثَةِ يَوْمَ عَرَفَةَ فَلَا جُنَاحَ عَلَيْهِ ثُمَّ لِيَنْطَلِقْ حَتَّى يَقِفَ بِعَرَفَاتٍ مِنْ صَلَاةِ الْعَصْرِ إِلَى أَنْ يَكُونَ الظَّلَامُ ثُمَّ لِيَدْفَعُوا مِنْ عَرَفَاتٍ إِذَا أَفَاضُوا مِنْهَا حَتَّى يَبْلُغُوا جَمْعًا الَّذِي يَبِيتُونَ بِهِ ثُمَّ لِيَذْكُرُوا اللَّهَ كَثِيرًا وَأَكْثِرُوا التَّكْبِيرَ وَالتَّهْلِيلَ قَبْلَ أَنْ تُصْبِحُوا ثُمَّ أَفِيضُوا فَإِنَّ النَّاسَ كَانُوا يُفِيضُونَ وَقَالَ اللَّهُ تَعَالَى{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ وَاسْتَغْفِرُوا اللَّهَ إِنَّ اللَّهَ غَفُورٌ رَحِيمٌ }حَتَّى تَرْمُوا الْجَمْرَةَ","trj":"Telah menceritakan kepadaku [Muhammad bin Abu Bakr] Telah menceritakan kepada kami [Fudlail bin Sulaiman] Telah menceritakan kepada kami [Musa bin 'Uqbah] Telah mengabarkan kepadaku [Kuraib] dari [Ibnu 'Abbas] dia berkata; seseorang berthawaf di ka'bah setelah bertahalul hingga dia bertalbiyah untuk haji. Apabila dia hendak pergi ke Arafah, maka hendaklah dia menyembelih unta, atau sapi, atau kambing kapan saja dia kehendaki jika hal itu mudah baginya. Jika hal itu terasa sulit, maka hendaklah dia berpuasa selama tiga hari pada waktu haji, yaitu sebelum hari Arafah. Jika ternyata hari terakhirnya dari tiga hari tersebut adalah hari Arafah, maka hal itu tidak mengapa baginya. Kemudian hendaklah dia berangkat untuk wukuf di Arafah dari waktu Ashar hingga menjelang malam. Lalu berangkat dari Arafah ketika orang-orang keluar darinya hingga sampai di Muzdalifah tempat mereka bermalam. setelah itu hendaklah mereka berdzikir kepada Allah dengan memperbanyak takbir, dan tahlil sebelum subuh tiba. Kemudian bertolaklah kalian dari Arafah karena orang-orang telah bertolak. Allah Ta'ala berfirman: \"Kemudian bertolaklah dari tempat bertolaknya orang-orang banyak ('Arafah) dan mohonlah ampun kepada Allah sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.\" (QS. Albaqarah 199). Hingga kalian melempar Jumrah."},{"p":"Ibnu Majah","n":2974,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا الثَّوْرِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَتْ قُرَيْشٌ نَحْنُ قَوَاطِنُ الْبَيْتِ لَا نُجَاوِزُ الْحَرَمَ فَقَالَ اللَّهُ عَزَّ وَجَلَّ{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }","trj":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazaq]; telah menceritakan kepada kami [Ats Tsauri] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; \"Seseorang dari kalangan kaum Quraisy berkata; 'Kami adalah penduduk di sekitar Baitullah, dan (tinggal) tidak jauh dari daerah Haram. Allah Subhanahu Wa Ta'ala telah berfirman: 'Kemudian bertolaklah kamu dari tempat bertolaknya orang-orang banyak (Arafah) …'(Qs. Al Baqarah 2: 199) "}],"2:217":[{"p":"Darimi","n":107,"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عَطَاءٍ عَنْ سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ مَا رَأَيْتُ قَوْمًا كَانُوا خَيْرًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا سَأَلُوهُ إِلَّا عَنْ ثَلَاثَ عَشْرَةَ مَسْأَلَةً حَتَّى قُبِضَ كُلُّهُنَّ فِي الْقُرْآنِ مِنْهُنَّ { يَسْأَلُونَكَ عَنْ الشَّهْرِ الْحَرَامِ } { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ } قَالَ مَا كَانُوا يَسْأَلُونَ إِلَّا عَمَّا يَنْفَعُهُمْ","trj":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Fudlail] dari ['Atho`] dari [Sa'id] dari [Ibnu 'Abbas] radliallahu 'anhu ia berkata: \" Aku tidak pernah melihat suatu kaum yang lebih baik dari pada para sahabat Rasulullah shallallahu 'alaihi wasallam, mereka tidak pernah menanyakan (kepada Nabi shallallahu 'alaihi wasallam) sampai beliau wafat kecuali tentang tiga belas masalah, semuanya ada dalam Al Qur`an. Diantara yang ditanyakan itu adalah: \"YAS`ALUUNAKA ANISSYAHRIL HARAAM\" (Mereka bertanya kepadamu tentang bulan-bulan haram) -Qs. Al Baqarah: 217-, dan \"WA YAS`ALUNAKA ANIL MAHIDL\" (Mereka bertanya kepada kamu tentang haidl) -Qs. Al Baqarah: 222-\"."}],"2:219":[{"p":"Abu Dawud","n":3109,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيِّ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }وَ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ وَمَنَافِعُ لِلنَّاسِ }نَسَخَتْهُمَا الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا الْخَمْرُ وَالْمَيْسِرُ وَالْأَنْصَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepada kami [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia membaca: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…) ' (Qs. An Nisaa`: 41). Dan ayat: '(Mereka bertanya kepadamu tentang khamer dan judi. Katakanlah: \"Pada keduanya terdapat dosa yang besar dan beberapa manfaat bagi manusia.....) ' (Qs. Al Baqarah: 219), ia berkata, \"Kedua ayat tersebut dihapus dan digantikan oleh ayat yang terdapat dalam Surat Al Maaidah: 91: '(Sesungguhnya (meminum) khamar, berjudi, (berkorban untuk) berhala…) '. "},{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."}],"2:220":[{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."},{"p":"Nasa'i","n":3510,"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عِمْرَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ كَانَ يَكُونُ فِي حَجْرِ الرَّجُلِ الْيَتِيمُ فَيَعْزِلُ لَهُ طَعَامَهُ وَشَرَابَهُ وَآنِيَتَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَإِنْ تُخَالِطُوهُمْ فَإِخْوَانُكُمْ }فِي الدِّينِ فَأَحَلَّ لَهُمْ خُلْطَتَهُمْ","trj":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Imran bin 'Uyainah] berkata; telah menceritakan kepada kami ['Atha bin As Saib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] mengenaii firman Allah: '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ia berkata, \"Dahulu terdapat seorang anak yatim dalam pemeliharaan seorang laki-laki, kemudian laki-laki tersebut menjauhi makanan serta minuman dan bejananya, sehingga hal tersebut terasa berat bagi orang-orang muslim. Kemudian Allah 'azza wajalla menurunkan ayat: '(dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu) ' (Qs. Al Baqarah: 220), yaitu seagama, maka Allah pun menghalalkan bagi mereka untuk bergaul dengan mereka.\""}],"2:222":[{"p":"Abu Dawud","n":214,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ الْيَهُودَ كَانَتْ إِذَا حَاضَتْ مِنْهُمْ الْمَرْأَةُ أَخْرَجُوهَا مِنْ الْبَيْتِ وَلَمْ يُؤَاكِلُوهَا وَلَمْ يُشَارِبُوهَا وَلَمْ يُجَامِعُوهَا فِي الْبَيْتِ فَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ سُبْحَانَهُ{ وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ }إِلَى آخِرِ الْآيَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَامِعُوهُنَّ فِي الْبُيُوتِ وَاصْنَعُوا كُلَّ شَيْءٍ غَيْرَ النِّكَاحِ فَقَالَتْ الْيَهُودُ مَا يُرِيدُ هَذَا الرَّجُلُ أَنْ يَدَعَ شَيْئًا مِنْ أَمْرِنَا إِلَّا خَالَفَنَا فِيهِ فَجَاءَ أُسَيْدُ بْنُ حُضَيْرٍ وَعَبَّادُ بْنُ بِشْرٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَا يَا رَسُولَ اللَّهِ إِنَّ الْيَهُودَ تَقُولُ كَذَا وَكَذَا أَفَلَا نَنْكِحُهُنَّ فِي الْمَحِيضِ فَتَمَعَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى ظَنَنَّا أَنْ قَدْ وَجَدَ عَلَيْهِمَا فَخَرَجَا فَاسْتَقْبَلَتْهُمَا هَدِيَّةٌ مِنْ لَبَنٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ فِي آثَارِهِمَا فَسَقَاهُمَا فَظَنَنَّا أَنَّهُ لَمْ يَجِدْ عَلَيْهِمَا","trj":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Tsabit Al-Bunani] dari [Anas bin Malik] bahwasanya orang-orang Yahudi, apabila istri-istri mereka datang haidl, maka mereka mengusirnya dari rumah. Mereka tidak makan, tidak minum, dan tidak berkumpul dengannya di rumah. Lalu Rasulullah shallallahu 'alaihi wasallam ditanya tentang hal tersebut, maka Allah Subhanahu wa Ta'ala menurunkan ayat (yang artinya): \"Dan mereka bertanya kepadamu tentang haidl. Katakanlah, 'Haidl itu adalah kotoran, oleh sebab itu hendaklah kamu menjauhkan diri dari wanita di waktu haidl... sampai akhir ayat'.\" (QS. Albaqarah 222), Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergaulilah mereka di rumah, dan lakukanlah segala sesuatu selain bersetubuh\". Lalu orang-orang Yahudi berkata; Orang ini (Muhammad) tidak meninggalkan sesuatu dari perkara kita kecuali dia menyelisihi kita dalam perkara itu. Lalu Usaid bin Hudlair dan Abbad bin Bisyr datang kepada Nabi shallallahu 'alaihi wasallam, keduanya berkata; Wahai Rasulullah, sesungguhnya orang-orang Yahudi berkata begini dan begini. Apakah kita tidak menggauli mereka saja dalam masa haidl? Maka raut muka Rasulullah shallallahu 'alaihi wasallam berubah, sehingga kami menyangka bahwa beliau marah kepada keduanya, lalu mereka berdua keluar. Setelah itu datang hadiah berupa susu kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau memerintahkan untuk memanggil kembali keduanya, lalu keduanya diberi minum. Karena itu kami tahu bahwa beliau tidak memarahi keduanya. "},{"p":"Darimi","n":107,"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عَطَاءٍ عَنْ سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ مَا رَأَيْتُ قَوْمًا كَانُوا خَيْرًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا سَأَلُوهُ إِلَّا عَنْ ثَلَاثَ عَشْرَةَ مَسْأَلَةً حَتَّى قُبِضَ كُلُّهُنَّ فِي الْقُرْآنِ مِنْهُنَّ { يَسْأَلُونَكَ عَنْ الشَّهْرِ الْحَرَامِ } { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ } قَالَ مَا كَانُوا يَسْأَلُونَ إِلَّا عَمَّا يَنْفَعُهُمْ","trj":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Fudlail] dari ['Atho`] dari [Sa'id] dari [Ibnu 'Abbas] radliallahu 'anhu ia berkata: \" Aku tidak pernah melihat suatu kaum yang lebih baik dari pada para sahabat Rasulullah shallallahu 'alaihi wasallam, mereka tidak pernah menanyakan (kepada Nabi shallallahu 'alaihi wasallam) sampai beliau wafat kecuali tentang tiga belas masalah, semuanya ada dalam Al Qur`an. Diantara yang ditanyakan itu adalah: \"YAS`ALUUNAKA ANISSYAHRIL HARAAM\" (Mereka bertanya kepadamu tentang bulan-bulan haram) -Qs. Al Baqarah: 217-, dan \"WA YAS`ALUNAKA ANIL MAHIDL\" (Mereka bertanya kepada kamu tentang haidl) -Qs. Al Baqarah: 222-\"."},{"p":"Darimi","n":729,"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَمَّنْ حَدَّثَهُ عَنْ مُجَاهِدٍ { وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ } قَالَ حَتَّى يَنْقَطِعَ الدَّمُ { فَإِذَا تَطَهَّرْنَ } قَالَ إِذَا اغْتَسَلْنَ","trj":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [seseorang yang menceritakan kepadanya] dari [Mujahid]: (Tentang ayat) \"WA LAA TAQRABUUHUNNA HATTAA YATHURNA\" (Dan janganlah kalian dekati mereka (wanita yang sedang haid) hingga ia suci) -Qs. Al Baqarah: 222-, ia berkata: \"(Maksudnya adalah) hingga darah (haidnya) berhenti\", dan \"FAIDZAA TATHAHHARNA\" (Dan apabila mereka telah suci) -Qs. Al Baqarah: 222-, ia berkata: \"(maksudnya adalah) jika mereka telah mandi.\""},{"p":"Darimi","n":730,"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ { حَتَّى يَطْهُرْنَ } قَالَ إِذَا انْقَطَعَ الدَّمُ { فَإِذَا تَطَهَّرْنَ } قَالَ اغْتَسَلْنَ","trj":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] \"HATTAA YATHHURNA\" (Hingga mereka suci) -Qs. Al Baqarah: 222-, ia berkata (makksudnya adalah): \"Jika darahnya benar-benar telah berhenti\", (sedang firman-Nya) \"FA IDZAA TATHAHHARNA\" (Dan apabila mereka telah bersuci) -Qs. Al Baqarah: 222-, ia berkata (maksudnya adalah): \"(jika) mereka telah mandi.\" "},{"p":"Darimi","n":761,"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَبَانَ بْنِ صَالِحٍ عَنْ مُجَاهِدٍ قَالَ لَقَدْ عَرَضْتُ الْقُرْآنَ عَلَى ابْنِ عَبَّاسٍ ثَلَاثَ عَرَضَاتٍ أَقِفُ عِنْدَ كُلِّ آيَةٍ أَسْأَلُهُ فِيمَ أُنْزِلَتْ وَفِيمَ كَانَتْ فَقُلْتُ يَا ابْنَ عَبَّاسٍ أَرَأَيْتَ قَوْلَ اللَّهِ تَعَالَى { فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } قَالَ مِنْ حَيْثُ أَمَرَكُمْ أَنْ تَعْتَزِلُوهُنَّ","trj":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah memberitakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Aban bin Shalih] dari [Mujahid] ia berkata: \"Aku telah menunjukkan hafalan Al Qur`an kepada Ibnu Abbas radliallahu 'anhu sebanyak tiga kali, aku berhenti di setiap ayat dan aku menanyakan kepadanya tentang apa ayat tersebut turun? Dan dan di mana ia diturunkan?, aku bertanya: \"Wahai [Ibnu Abbas] radliallahu 'anhu, Bagaimana pendapatmu tentang firman Allah subhanallahu wa ta'ala: \"FAIDZAA TATHAHHARNA FA`TUHUNNA MIN HAITSU `AMARAKUMULLAHU\" (Maka apabila mereka telah suci, maka datangilah mereka dari arah yang perintahkan kepada kalian) -Qs. Al Baqarah: 222-, ia menjawab: \"Di tempat yang Ia perintahkan kepada kalian untuk dijauhi (ketika mereka sedang haid, yaitu kemaluan) \"."},{"p":"Darimi","n":762,"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُجَاهِدٍ { فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } قَالَ أُمِرُوا أَنْ يَأْتُوا مِنْ حَيْثُ نُهُوا","trj":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Utsman bin Al Aswad] dari [Mujahid] ketika menafsirkan ayat: '(Maka datangilah mereka di tempat yang Allah subhanallahu wa ta'ala perintahkan kepada kalian) ' (Qs. Al Baqarah: 222), ia berkata: \"Mereka diperintahkan untuk mendatangi (isteri mereka) di tempat yang mereka dilarang untuk melakukannya (disaat haid) \"."},{"p":"Darimi","n":766,"ar":" أَخْبَرَنَا خَلِيفَةُ بْنُ خَيَّاطٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ قَالَ كَانَ أَهْلُ الْجَاهِلِيَّةِ يَصْنَعُونَ فِي الْحَائِضِ نَحْوًا مِنْ صَنِيعِ الْمَجُوسِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ } فَلَمْ يَزْدَدْ الْأَمْرُ فِيهِنَّ إِلَّا شِدَّةً","trj":"Telah mengabarkan kepada kami [Khalifah bin Khayyath] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] ia berkata: \"Dahulu orang-orang jahiliyah berbuat terhadap wanita haid seperti yang dilakukan oleh orang-orang Majusi, hal itu kemudian disebutkan kepada Rasulullah shallallahu 'alaihi wasallam, maka turunlah ayat: '(Dan mereka bertanya tentang haid, katakanlah haid itu adalah kotoran, maka jauhilah isteri-isteri kalian di saat haid dan janganlah kalian dekati mereka hingga mereka suci) ' (Qs. Al Baqarah: 222), tidaklah urusan tentang mereka itu kecuali semakin tegas.\""},{"p":"Darimi","n":767,"ar":" أَخْبَرَنَا خَلِيفَةُ حَدَّثَنَا مُؤَمَّلٌ عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ { قُلْ هُوَ أَذًى } قَالَ هُوَ الدَّمُ","trj":"Telah mengabarkan kepada kami [Khalifah] telah menceritakan kepada kami [Mu`ammal] dari [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] ketika mentafsirkan firman Allah: '(katakanlah haid itu adalah kotoran…) ' (Qs. Al Baqarah: 222), ia berkata, \"Maksudnya adalah darah.\""},{"p":"Nasa'i","n":285,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِثٍ عَنْ أَنَسٍقَالَ كَانَتْ الْيَهُودُ إِذَا حَاضَتْ الْمَرْأَةُ مِنْهُمْ لَمْ يُؤَاكِلُوهُنَّ وَلَمْ يُشَارِبُوهُنَّ وَلَمْ يُجَامِعُوهُنَّ فِي الْبُيُوتِ فَسَأَلُوا نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى }الْآيَةَ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُؤَاكِلُوهُنَّ وَيُشَارِبُوهُنَّ وَيُجَامِعُوهُنَّ فِي الْبُيُوتِ وَأَنْ يَصْنَعُوا بِهِنَّ كُلَّ شَيْءٍ مَا خَلَا الْجِمَاعَ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Sulaiman bin Harb] dia berkata; Telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] dia berkata; Bahwa orang Yahudi apabila ada istri mereka sedang haid, maka mereka tidak mengajak makan bersama, tidak mempergaulinya, dan tidak berkumpul bersamanya di rumah. Mereka bertanya kepada Nabi Allah shallallahu 'alaihi wasallam tentang hal itu? Lalu Allah Azza wa Jalla menurunkan ayat \" Mereka bertanya kepadamu tentang haid. Katakanlah, (Hai Muhammad) bahwa itu adalah penyakit… (Qs. Al-Baqarah (2): 222) lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan mereka untuk ikut makan bersama, mempergaulinya, berkumpul dengan mereka di rumah, dan untuk berbuat apa saja selain bersetubuh. "}],"2:223":[{"p":"Bukhari","n":3858,"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ نَافِعٍ قَالَ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاإِذَا قَرَأَ الْقُرْآنَ لَمْ يَتَكَلَّمْ حَتَّى يَفْرُغَ مِنْهُ فَأَخَذْتُ عَلَيْهِ يَوْمًا فَقَرَأَ سُورَةَ الْبَقَرَةِ حَتَّى انْتَهَى إِلَى مَكَانٍ قَالَ تَدْرِي فِيمَ أُنْزِلَتْ قُلْتُ لَا قَالَ أُنْزِلَتْ فِي كَذَا وَكَذَا ثُمَّ مَضَىوَعَنْ عَبْدِ الصَّمَدِ حَدَّثَنِي أَبِي حَدَّثَنِي أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ{ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }قَالَ يَأْتِيهَا فِي رَوَاهُ مُحَمَّدُ بْنُ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ","trj":"Telah menceritakan kepada kami [Ishaq] Telah mengabarkan kepada kami [An Nadlr bin Syumail] Telah mengabarkan kepada kami [Ibnu Aun] dari [Nafi'] dia berkata; [Ibnu Umar radliallahu 'anhuma] apabila membaca Al Qur'an, beliau tidak berbicara hingga selesai membacanya. Pada suatu hari aku mengambil mushaf-nya, maka membaca surat Al Baqarah hingga selesai dengan hafalannya. Lalu dia berkata; tahukah kamu tentang apa surat ini turun? Aku menjawab; 'Tidak.' Dia berkata; surat ini turun tentang ini dan itu kemudian dia pergi.' Dan dari [Abdus Shamad] Telah menceritakan kepadaku [ayahku] telah menceritakan kepadaku [Ayyub] dari [Nafi] dari [Ibnu Umar] mengenai ayat; \"istri-istrimu adalah ladang bagimu maka datangilah ladang-ladangmu kapan saja sesuai yang kamu sukai\".(QS. Albaqarah 223), Ibnu Umar berkata; yaitu mendatanginya dari kemaluannya. Diriwayatkan oleh [Muhammad bin Yahyan bin Sa'id] dari [Bapaknya] dari [Ubaidullah] dari [Nafi] dari [Ibnu Umar]."},{"p":"Bukhari","n":3859,"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ سَمِعْتُ جَابِرًا رَضِيَ اللَّهُ عَنْهُ قَالَكَانَتْ الْيَهُودُ تَقُولُ إِذَا جَامَعَهَا مِنْ وَرَائِهَا جَاءَ الْوَلَدُ أَحْوَلَ فَنَزَلَتْ{ نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }","trj":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Ibnu Al Munkadir] aku mendengar [Jabir radliallahu 'anhu] berkata; Orang-orang Yahudi berkata; Apabila menggauli wanita melalui belakang maka mata anaknya akan menjadi juling'. Lalu Allah Subhaanahu menurunkan ayat; Isteri-isteri kalian adalah ladang kalian, maka datangilah ladang kalian dari mana engkau kehendaki.\" (QS. Albaqarah 223)."},{"p":"Darimi","n":760,"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ ابْنِ سَابِطٍ قَالَ سَأَلْتُ حَفْصَةَ بِنْتَ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ أَبِي بَكْرٍ قُلْتُ لَهَا إِنِّي أُرِيدُ أَنْ أَسْأَلَكِ عَنْ شَيْءٍ وَأَنَا أَسْتَحْيِي أَنْ أَسْأَلَكِ عَنْهُ قَالَتْ سَلْ يَا ابْنَ أَخِي عَمَّا بَدَا لَكَ قَالَ أَسْأَلُكِ عَنْ إِتْيَانِ النِّسَاءِ فِي أَدْبَارِهِنَّ فَقَالَتْ حَدَّثَتْنِي أُمُّ سَلَمَةَ قَالَتْ كَانَتْ الْأَنْصَارُ لَا تُجَبِّي وَكَانَتْ الْمُهَاجِرُونَ تُجَبِّي فَتَزَوَّجَ رَجُلٌ مِنْ الْمُهَاجِرِينَ امْرَأَةً مِنْ الْأَنْصَارِ فَجَبَّاهَا فَأَبَتْ الْأَنْصَارِيَّةُ فَأَتَتْ أُمَّ سَلَمَةَ فَذَكَرَتْ ذَلِكَ لَهَا فَلَمَّا أَنْ جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَحْيَتْ الْأَنْصَارِيَّةُ وَخَرَجَتْ فَذَكَرَتْ ذَلِكَ أُمُّ سَلَمَةَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ادْعُوهَا لِي فَدُعِيَتْ لَهُ فَقَالَ لَهَا { نِسَاؤُكُمْ حَرْثٌ لَكَمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } سِمَامًا وَاحِدًا وَالسِّمَامُ السَّبِيلُ الْوَاحِدُ","trj":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Ibnu Sabith] ia berkata: \"Aku pernah bertanya kepada [Hafshah binti Abdur Rahman Ibnu Abu Bakar], aku berkata kepadanya: Aku ingin bertanya kepada kamu perihal sesuatu yang sebenarnya aku malu menanyakannya kepadamu, ia berkata: \"Bertanyalah wahai keponakanku tentang hal yang mengganjal (di hatimu) \", ia bertanya: \"Aku bertanya kepada kamu tentang menggauli isteri-isteri dari dubur mereka?\", maka ia menjawab: \" [Ummu Salamah] radliallahu 'anha pernah menceritakan kepadaku, ia berkata: \"Dahulu orang-orang Anshar tidak pernah menggauli (isteri mereka) dari arah belakang, sedang orang-orang muhajirin biasa menggauli (isteri mereka) dari arah belakang, maka ada seorang laki-laki dari kaum muhajirin menikahi seorang wanita dari kaum anshar, ia menggaulinya dari arah belakang, maka wanita itu menolak, dan ia datang menemui Ummu Salamah radliallahu 'anha, ia menceritakan hal tersebut, maka tatkala Rasulullah shallallahu 'alaihi wasallam datang, wanita anshar itu malu dan keluar, maka Ummu Salamah radliallahu 'anha menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Panggillah wanita tadi untuk menemuiku\", maka dipanggillah ia untuk menemui beliau, kemudian beliau berkata: \"NISAA`UKUM HARTSUN LAKUM FA`TUU HARTSAKUM `ANNA SYI`TUM\" (Isteri-isteri kalian adalah sawah ladang kalian, maka datangilah sawah ladangmu itu bagaimana saja kamu kehendaki) -Qs. Al Baqarah: 223-, yaitu satu arah, maksud dari satu arah adalah dari arah mana saja kamu datangi asalkan sasarannya satu, yaitu kemaluan.\""},{"p":"Darimi","n":764,"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا خَالِدُ بْنُ رَبَاحٍ عَنْ عِكْرِمَةَ { نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَالَ إِنَّمَا هُوَ الْفَرْجُ","trj":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Khalid bin Rabah] dari ['Ikrimah] (Ketika menafsirkan ayat): '(Isteri-isteri kalian (bagaikan) sawah ladang kalian, maka datangilah sawah ladang kalian sesuai kehendak kalian) ' (Qs. Al Baqarah: 223), ia berkata: \"Itu adalah kemaluan\"."},{"p":"Darimi","n":765,"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ { فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَالَ ائْتِهَا مِنْ بَيْنِ يَدَيْهَا وَمِنْ خَلْفِهَا بَعْدَ أَنْ يَكُونَ فِي الْمَأْتَى","trj":"Telah mengabarkan kepada kami ['Amru bin 'Aun] dari [Khalid bin Abdullah] dari ['Atha bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] (ketika menafsirkan ayat): '(Maka datangilah sawah ladang kalian sesuai kehendak kalian) ' (Qs. Al Baqarah: 223), ia berkata: \"Datangilah ia dari arah depan dan arah belakangnya selama masih di tempat kedatangan (kemaluan).\""},{"p":"Darimi","n":768,"ar":" أَخْبَرَنَا خَلِيفَةُ بْنُ خَيَّاطٍ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ لَيْثًا حَدَّثَ عَنْ عِيسَى بْنِ قَيْسٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ { نِسَاؤُكُم�� حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَالَ إِنْ شِئْتَ فَاعْزِلْ وَإِنْ شِئْتَ فَلَا تَعْزِلْ","trj":"Telah mengabarkan kepada kami [Khalifah bin Khayyath] telah menceritakan kepada kami [Al Mu'tamir] ia berkata: Aku pernah mendengar [Laits] menceritakan dari ['Isa bin Qais] dari [Sa'id bin Musayyib] firman Allah: '(Isteri-isteri kalian bagaikan sawah ladang kalian, maka datangilah sawah ladang kalian sesuai kehendak kalian) ', (Qs. Al Baqarah: 223), ia berkata: \"Jika kamu berkehendak, maka jauhilah dia, dan jika kamu kehendaki, maka jangan kamu jauhi dia.\" "},{"p":"Darimi","n":770,"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُجَاهِدٍ قَالَ مَنْ أَتَى امْرَأَتَهُ فِي دُبُرِهَا فَهُوَ مِنْ الْمَرْأَةِ مِثْلُهُ مِنْ الرَّجُلِ ثُمَّ تَلَا { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } أَنْ تَعْتَزِلُوهُنَّ فِي الْمَحِيضِ الْفَرْجَ ثُمَّ تَلَا { نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَائِمَةً وَقَاعِدَةً وَمُقْبِلَةً وَمُدْبِرَةً فِي الْفَرْجِ","trj":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Utsman bin Al Aswad] dari [Mujahid] ia berkata: \"Barangsiapa menggauli isterinya pada duburnya, maka ia termasuk wanita yang semisalnya dari kalangan laki-laki, kemudian ia membaca ayat: '(Dan mereka bertanya kepada kamu tentang haid, maka katakanlah ia itu kotoran, maka jauhilah wanita-wanita yang tengah haid, dan jangan kalian dekati mereka hingga mereka suci, dan apabila mereka telah suci, maka datangilah mereka dari arah yang Allah subhanallahu wa ta'ala perintahkan kepada kalian) ' (Qs. Al Baqarah: 223), yakni hendaklah kalian jauhi kemaluan mereka ketika sedang haid. Kemudian ia membaca ayat: '(Isteri-isteri kalian bagaikan sawah ladang kalian, maka datangilah sawah ladang kalian sesuai kehendak kalian) ' (Qs. Al Baqarah: 223), yaitu baik berdiri, duduk, dari arah depan atau dari arah depan (tetapi tetap pada) kemaluannya.\""},{"p":"Darimi","n":778,"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا خُصَيْفٌ عَنْ مُجَاهِدٍ قَالَ كَانُوا يَجْتَنِبُونَ النِّسَاءَ فِي الْمَحِيضِ وَيَأْتُونَهُنَّ فِي أَدْبَارِهِنَّ فَسَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ تَعَالَى { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } فِي الْفَرْجِ وَلَا تَعْدُوهُ","trj":"Telah menghabarkan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Khushaif] dari [Mujahid] ia berkata, \"Dahulu mereka menjauhi para wanita di saat haid, dan menggauli mereka pada dubur-dubur mereka, lalu mereka bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal itu, maka Allah subhanallahu wa ta'ala menurunkan ayat: '(Dan mereka bertanya kepada kamu tentang haid, katakanlah ia itu kotor, maka jauhilah wanita yang tengah haid dan jangan kalian dekati mereka hingga mereka suci, dan jika mereka telah suci, maka datangilah mereka sesuai dengan yang Allah perintahkan) ' (Qs. Al Baqarah: 223), yakni pada lubang kemaluannya dan janganlah kalian menyimpang darinya.\""}],"2:228":[{"p":"Darimi","n":589,"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ { وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ } قَالَ الْحَيْضُ قِيلَ لِأَبِي مُحَمَّدٍ أَتَقُولُ بِهَذَا قَالَ لَا سُئِلَ عَبْد اللَّهِ عَنْ حَدِيثِ شُرَيْحٍ تَقُولُ بِهِ قَالَ لَا وَقَالَ ثَلَاثُ حِيَضٍ فِي الشَّهْرِ كَيْفَ يَكُونُ","trj":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [khalid bin Abdullah] dari [Khalid Al Hadzdza`] dari ['Ikrimah] (dalam penafsiran ayat) \"WA LAA YAHILLU LAHUNNA AN YAKTUMNA MAA KHALAQALLAHU FII ARHAAMIHINNA\" (Dan tidak boleh mereka menyembunyikan apa yang diciptakan Allah subhanallahu wa ta'ala dalam rahimnya) -Qs. Al Baqarah: 228-,: 'Maksudnya adalah haid', Dikatakan kepada Abu Muhammad: 'Apakah kamu mengatakan hal itu juga? ', ia menjawab: 'Tidak', dan Abdullah ditanya perihal tentang hadits Syuraih, apakah kamu mengatakan hal itu? ', ia menjawab: 'Tidak', dan ia berkata: 'Bagaimana bisa terjadi tiga kali haid dalam satu bulan? ' \"."},{"p":"Malik","n":1049,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّهَا انْتَقَلَتْ حَفْصَةَ بِنْتَ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ حِينَ دَخَلَتْ فِي الدَّمِ مِنْ الْحَيْضَةِ الثَّالِثَةِ قَالَ ابْنُ شِهَابٍ فَذُكِرَ ذَلِكَ لِعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ فَقَالَتْ صَدَقَ عُرْوَةُ وَقَدْ جَادَلَهَا فِي ذَلِكَ نَاسٌ فَقَالُوا إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ فِي كِتَابِهِ{ ثَلَاثَةَ قُرُوءٍ }فَقَالَتْ عَائِشَةُ صَدَقْتُمْ تَدْرُونَ مَا الْأَقْرَاءُ إِنَّمَا الْأَقْرَاءُ الْأَطْهَارُو حَدَّثَنِي عَنْ مَالِك عَنْ ابْنِ شِهَابٍ أَنَّهُ قَالَ سَمِعْتُ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ يَقُولُ مَا أَدْرَكْتُ أَحَدًا مِنْ فُقَهَائِنَا إِلَّا وَهُوَ يَقُولُ هَذَا يُرِيدُ قَوْلَ عَائِشَةَ","trj":"Telah menceritakan kepadaku dari Malik dari [Ibnu Syihab] dari [Urwah bin Zubair] dari ['Aisyah] Ummul Mukminin, bahwa dia menyuruh Hafshah binti Abdurrahman bin Abu Bakar Ash Shiddiq pindah tempat tinggal ketika memasuki masa haid yang ketiga. Ibnu Syihab berkata; \"Hal itu lalu diadukan kepada 'Amrah binti Abdurrahman. [Amrah] berkata, \"Urwah benar.\" Waktu itu banyak orang yang mendebatnya. [Mereka mengatakan], \"Sungguh Allah Ta'ala telah berfirman dalam kitab-Nya: \"Tiga kali quru' (Qs. Al Baqarah: 228) 'Aisyah lalu menjawab; \"Kalian benar, dan tahukah kalian apa itu quru`? Quru` adalah suci.\" Telah menceritakan kepadaku dari Malik dari Ibnu Syihab berkata; Aku mendengar [Abu Bakar bin Abdurrahman] berkata; \"Aku tidak mendapati seorang ahli fikih pun dari kalangan kita kecuali dia sependapat dengan hal itu.\" maksudnya pendapat 'Aisyah."},{"p":"Nasa'i","n":3350,"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ أَنْبَأَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ }وَقَالَ{ وَاللَّائِي يَئِسْنَ مِنْ الْمَحِيضِ مِنْ نِسَائِكُمْ إِنْ ارْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَاثَةُ أَشْهُرٍ }فَنُسِخَ مِنْ ذَلِكَ قَالَ تَعَالَى وَإِنْ{ طَلَّقْتُمُوهُنَّ مِنْ قَبْلِ أَنْ تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ali bin Al Husain bin Waqid] ia berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah memberitakan kepada kami [Yazid bin An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai ayat: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 101), dan firman Allah '(menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh (hapus) dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru') ', (Qs. Al Baqarah: 228). Dan firman: '(Dan perempuan-perempuan yang tidak haid lagi (monopause) di antara perempuan-perempuanmu jika kamu ragu-ragu (tentang masa iddahnya), Maka masa iddah mereka adalah tiga bulan) ' (Qs. Ath Thallaaq: 40), lalu dinasakh dari hal tersebut, firman Allah Ta'ala: '(Kemudian kamu ceraikan mereka sebelum kamu mencampurinya Maka sekali-sekali tidak wajib atas mereka 'iddah bagimu yang kamu minta menyempurnakannya) ' (Qs. Al Ahzaab: 49)."},{"p":"Nasa'i","n":3398,"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ إِلَى قَوْلِهِ إِنْ أَرَادُوا إِصْلَاحًا }وَذَلِكَ بِأَنَّ الرَّجُلَ كَانَ إِذَا طَلَّقَ امْرَأَتَهُ فَهُوَ أَحَقُّ بِرَجْعَتِهَا وَإِنْ طَلَّقَهَا ثَلَاثًا فَنَسَخَ ذَلِكَ وَقَالَ{ الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman Allah: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 1o1), dan firman Allah: '(Allah menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru'. Tidak boleh mereka menyembunyikan apa yang diciptakan Allah dalam rahimnya, jika mereka beriman kepada Allah dan hari akhirat. Dan suami-suaminya berhak merujukinya dalam masa menanti itu, jika mereka (para suami) menghendaki ishlah) ' (Qs. Al Baqarah: 228). Hal itu karena jika seorang laki-laki mencerai isterinya, maka ia lebih berhak untuk kembali kepadanya walaupun telah mencerainya tiga kali, kemudian Allah menghapus hal tersebut dan berfirman: '(Talak (yang dapat dirujuki) dua kali. Setelah itu boleh rujuk lagi dengan cara yang ma'ruf atau menceraikan dengan cara yang baik) ' (Qs. Al Baqarah: 229)."}],"2:229":[{"p":"Nasa'i","n":3398,"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ إِلَى قَوْلِهِ إِنْ أَرَادُوا إِصْلَاحًا }وَذَلِكَ بِأَنَّ الرَّجُلَ كَانَ إِذَا طَلَّقَ امْرَأَتَهُ فَهُوَ أَحَقُّ بِرَجْعَتِهَا وَإِنْ طَلَّقَهَا ثَلَاثًا فَنَسَخَ ذَلِكَ وَقَالَ{ الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman Allah: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 1o1), dan firman Allah: '(Allah menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru'. Tidak boleh mereka menyembunyikan apa yang diciptakan Allah dalam rahimnya, jika mereka beriman kepada Allah dan hari akhirat. Dan suami-suaminya berhak merujukinya dalam masa menanti itu, jika mereka (para suami) menghendaki ishlah) ' (Qs. Al Baqarah: 228). Hal itu karena jika seorang laki-laki mencerai isterinya, maka ia lebih berhak untuk kembali kepadanya walaupun telah mencerainya tiga kali, kemudian Allah menghapus hal tersebut dan berfirman: '(Talak (yang dapat dirujuki) dua kali. Setelah itu boleh rujuk lagi dengan cara yang ma'ruf atau menceraikan dengan cara yang baik) ' (Qs. Al Baqarah: 229)."}],"2:231":[{"p":"Malik","n":1070,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَكَانَ الرَّجُلُ إِذَا طَلَّقَ امْرَأَتَهُ ثُمَّ ارْتَجَعَهَا قَبْلَ أَنْ تَنْقَضِيَ عِدَّتُهَا كَانَ ذَلِكَ لَهُ وَإِنْ طَلَّقَهَا أَلْفَ مَرَّةٍ فَعَمَدَ رَجُلٌ إِلَى امْرَأَتِهِ فَطَلَّقَهَا حَتَّى إِذَا شَارَفَتْ انْقِضَاءَ عِدَّتِهَا رَاجَعَهَا ثُمَّ طَلَّقَهَا ثُمَّ قَالَ لَا وَاللَّهِ لَا آوِيكِ إِلَيَّ وَلَا تَحِلِّينَ أَبَدًا فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ }فَاسْتَقْبَلَ النَّاسُ الطَّلَاقَ جَدِيدًا مِنْ يَوْمِئِذٍ مَنْ كَانَ طَلَّقَ مِنْهُمْ أَوْ لَمْ يُطَلِّقْ","trj":"Telah menceritakan kepada kami dari Malik dari [Hisyam bin Urwah] dari [Bapaknya] berkata; \"Jika seorang laki-laki menceraikan isterinya, dia berhak ruju' lagi kepadanya selagi masa iddahnya belum habis, meski dia menceraikannya sampai seribu kali. Seorang laki-laki sengaja menceraikan isterinya, hingga ketika masa iddahnya akan selesai ia kembali meruju'nya, lalu kembali menceraikannya. Setelah itu ia berkata, \"Tidak, demi Allah, aku tidak akan menggaulimu dan kamu selamanya tidak akan menjadi halal (tidak pernah habis masa iddahnya karena selalu diruju') .\" Kemudian Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Talak (yang dapat dirujuki) dua kali. Setelah itu, boleh ruju' lagi dengan cara yang ma'ruf atau menceraikan dengan cara yang baik) ' (Qs. Al Baqarah: 231) Semenjak turunnya ayat ini, orang-orang menghitung talak dari awal lagi, baik yang sudah pernah mentalak ataupun yang belum pernah.\""},{"p":"Malik","n":1071,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيلِيِّأَنَّ الرَّجُلَ كَانَ يُطَلِّقُ امْرَأَتَهُ ثُمَّ يُرَاجِعُهَا وَلَا حَاجَةَ لَهُ بِهَا وَلَا يُرِيدُ إِمْسَاكَهَا كَيْمَا يُطَوِّلُ بِذَلِكَ عَلَيْهَا الْعِدَّةَ لِيُضَارَّهَا فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ وَلَا تُمْسِكُوهُنَّ ضِرَارًا لِتَعْتَدُوا وَمَنْ يَفْعَلْ ذَلِكَ فَقَدْ ظَلَمَ نَفْسَهُ }يَعِظُهُمْ اللَّهُ بِذَلِكَ","trj":"Telah menceritakan kepadaku dari Malik dari [Tsaur bin Zaid Ad Dili] berkata, \"Seorang lelaki menceraikan isterinya kemudian meruju'nya lagi padahal ia sudah tidak membutuhkannya dan tidak ingin menjadikannya isteri lagi. Ia hanya ingin memperpanjang masa iddahnya sehingga isteri merasakan penderitaan. Kemudian Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Janganlah kamu rujuki mereka untuk memberi kemudharatan, Karena dengan demikian kamu menganiaya mereka) ' (Qs. Al Baqarah: 231) Allah menasehatkan demikian kepada mereka."}],"2:232":[{"p":"Bukhari","n":3860,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ حَدَّثَنَا الْحَسَنُ قَالَ حَدَّثَنِي مَعْقِلُ بْنُ يَسَارٍ قَالَ كَانَتْ لِي أُخْتٌ تُخْطَبُ إِلَيَّ وَقَالَ إِبْرَاهِيمُ عَنْ يُونُسَ عَنْ الْحَسَنِ حَدَّثَنِي مَعْقِلُ بْنُ يَسَارٍ ح حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِأَنَّ أُخْتَ مَعْقِلِ بْنِ يَسَارٍ طَلَّقَهَا زَوْجُهَا فَتَرَكَهَا حَتَّى انْقَضَتْ عِدَّتُهَا فَخَطَبَهَا فَأَبَى مَعْقِلٌ فَنَزَلَتْ{ فَلَا تَعْضُلُوهُنَّ أَنْ يَنْكِحْنَ أَزْوَاجَهُنَّ }","trj":"Telah menceritakan kepada kami [Ubaidullah bin Sa'id] Telah menceritakan kepada kami [Abu Amir Al 'Aqidi] Telah menceritakan kepada kami [Abbad bin Rasyid] Telah menceritakan kepada kami [Al Hasan] dia berkata; Telah menceritakan kepadaku [Ma'qil bin Yasar] berkata; aku mempunyai saudara perempuan yang dilamar kepadaku. Dan [Ibrahim] berkata; dari [Yunus] dari [Al Hasan] telah menceritakan kepadaku [Ma'qil bin Yasar]. -diriwayatkan dari jalur lainnya- Telah menceritakan kepada kami [Abu Ma'mar] Telah menceritakan kepada kami [Abdul Warits] Telah menceritakan kepada kami [Yunus] dari [Al Hasan] bahwa saudara perempuan Ma'qil ditalak suaminya dan meninggalkannya hingga habis masa iddahnya. Kemudian dia meminangnya lagi, namun Ma'qil menolaknya. Maka turunlah ayat; Jangalah kamu halangi mereka untuk menikah lagi dengan suaminya. (QS. Albaqarah 232)."},{"p":"Bukhari","n":4610,"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ حَدَّثَنَا الْحَسَنُأَنَّ مَعْقِلَ بْنَ يَسَارٍ كَانَتْ أُخْتُهُ تَحْتَ رَجُلٍ فَطَلَّقَهَا ثُمَّ خَلَّى عَنْهَا حَتَّى انْقَضَتْ عِدَّتُهَا ثُمَّ خَطَبَهَا فَحَمِيَ مَعْقِلٌ مِنْ ذَلِكَ أَنَفًا فَقَالَ خَلَّى عَنْهَا وَهُوَ يَقْدِرُ عَلَيْهَا ثُمَّ يَخْطُبُهَا فَحَالَ بَيْنَهُ وَبَيْنَهَا فَأَنْزَلَ اللَّهُ{ وَإِذَا طَلَّقْتُمْ النِّسَاءَ فَبَلَغْنَ أَجَلَهُنَّ فَلَا تَعْضُلُوهُنَّ }إِلَى آخِرِ الْآيَةِ فَدَعَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ عَلَيْهِ فَتَرَكَ الْحَمِيَّةَ وَاسْتَقَادَ لِأَمْرِ اللَّهِ","trj":"Dan Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Abdul A'la] Telah menceritakan kepada kami [Sa'id] dari [Qatadah] Telah menceritakan kepada kami [Al Hasan] bahwa saudara perempuan Ma'qil bin Yasar berada di bawah seorang laki-laki, lalu laki-laki itu pun menceraikannya dan berpisah dengannya hingga masa iddahnya habis. Kemudian laki-laki itu meminangnya kembali. Maka Ma'qil pun marah dan menolak pinangan itu dan berkata, \"Ia menceraikannya padahal ia mampu. Lalu ia mengkhithbahnya kembali.\" Akhirnya ia menghalangi ruju' antara keduanya. Maka Allah menurunkan ayat: \"WA IDZAA THALLAQTUMUN NISAA` FABALAGHNA AJALAHUNNA FALAA TA'DLULUUHUNNA..\" (QS. Albaqarah 232), hingga akhir ayat. Lalu Rasulullah shallallahu 'alaihi wasallam pun memanggilnya dan membacakan ayat itu kepadanya. Akhirnya ia pun meninggalkan keangkuhannya dan meneriman ketentuan Allah."}],"2:234":[{"p":"Malik","n":1081,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّهُ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ مُحَمَّدٍ يَقُولُإِنَّ يَزِيدَ بْنَ عَبْدِ الْمَلِكِ فَرَّقَ بَيْنَ رِجَالٍ وَبَيْنَ نِسَائِهِمْ وَكُنَّ أُمَّهَاتِ أَوْلَادِ رِجَالٍ هَلَكُوا فَتَزَوَّجُوهُنَّ بَعْدَ حَيْضَةٍ أَوْ حَيْضَتَيْنِ فَفَرَّقَ بَيْنَهُمْ حَتَّى يَعْتَدِدْنَ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا فَقَالَ الْقَاسِمُ بْنُ مُحَمَّدٍ سُبْحَانَ اللَّهِ يَقُولُ اللَّهُ فِي كِتَابِهِ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا }مَا هُنَّ مِنْ الْأَزْوَاجِ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Yahya bin Sa'id] ia berkata; Aku mendengar [Al Qasim bin Muhammad] berkata; \"Suatu ketika Yazid bin Abdul Malik memisahkan para suami dari isteri-isteri mereka. Para wanita itu adalah para ibu dari anak-anak yang ditinggal mati bapaknya, lalu mereka menikahinya wanita-wanita itu ketika baru berlalu satu atau dua kali haid. Kemudian Yazid memisahkan mereka sampai para wanita itu menjalani masa 'iddah selama empat bulan sepuluh hari.\" Al Qasim bin Muhammad berkata; \"SUBHANALLAH, Allah berfirman dalam kitab-Nya: \"Orang-orang yang meninggal dunia di antaramu dengan meninggalkan isteri-isteri (hendaklah para isteri itu) ...\" (Qs. Al Baqarah: 234) padahal mereka itu tidak mempunyai suami sebelumnya?\""},{"p":"Nasa'i","n":3388,"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ }قَالَ نَسَخَتْهَا{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا }","trj":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari ['Ikrimah] mengenai firman Allah 'azza wajalla: '(Dan orang-orang yang akan meninggal dunia di antara kamu dan meninggalkan isteri, hendaklah berwasiat untuk isteri-isterinya, (yaitu) diberi nafkah hingga setahun lamanya dan tidak disuruh pindah (dari rumahnya) ' (Qs. Al Baqarah: 240). 'Ikrimah berkata, \"Ayat tersebut dihapus oleh ayat: '(Orang-orang yang meninggal dunia di antaramu dengan meninggalkan isteri-isteri (hendaklah para isteri itu) menangguhkan dirinya (ber'iddah) empat bulan sepuluh hari) ' (Qs. Al Baqarah: 234)."}],"2:235":[{"p":"Malik","n":961,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِأَنَّهُ كَانَ يَقُولُ فِي قَوْلِ اللَّهِ تَبَارَكَ وَتَعَالَى{ وَلَا جُنَاحَ عَلَيْكُمْ فِيمَا عَرَّضْتُمْ بِهِ مِنْ خِطْبَةِ النِّسَاءِ أَوْ أَكْنَنْتُمْ فِي أَنْفُسِكُمْ عَلِمَ اللَّهُ أَنَّكُمْ سَتَذْكُرُونَهُنَّ وَلَكِنْ لَا تُوَاعِدُوهُنَّ سِرًّا إِلَّا أَنْ تَقُولُوا قَوْلًا مَعْرُوفًا }أَنْ يَقُولَ الرَّجُلُ لِلْمَرْأَةِ وَهِيَ فِي عِدَّتِهَا مِنْ وَفَاةِ زَوْجِهَا إِنَّكِ عَلَيَّ لَكَرِيمَةٌ وَإِنِّي فِيكِ لَرَاغِبٌ وَإِنَّ اللَّهَ لَسَائِقٌ إِلَيْكِ خَيْرًا وَرِزْقًا وَنَحْوَ هَذَا مِنْ الْقَوْلِ","trj":"Telah menceritakan kepadaku dari Malik dari [Abdurrahman bin Qasim] dari [Bapaknya] bahwa dia berkata mengenai firman Allah Ta'ala: '(Dan tidak ada dosa bagi kamu meminang wanita-wanita itu dengan sindiran atau kamu menyembunyikan (keinginan mengawini mereka) dalam hatimu. Allah mengetahui bahwa kamu akan menyebut-nyebut mereka, dalam pada itu janganlah kamu mengadakan janji kawin dengan mereka secara rahasia, kecuali sekedar mengucapkan (kepada mereka) perkataan yang ma'ruf) ' (Qs. Al Baqarah: 235) yaitu seorang laki-laki yang berkata kepada seorang wanita yang masih berada pada masa iddah dari kematian suaminya, 'Kamu begitu mulia bagiku, saya ada rasa cinta terhadapmu, semoga Allah menuntunmu kepada kebaikan dan jalan rezki', atau ucapan lain yang semisalnya."}],"2:238":[{"p":"Malik","n":287,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي يُونُسَ مَوْلَى عَائِشَةَ أُمِّ الْمُؤْمِنِينَ أَنَّهُ قَالَ أَمَرَتْنِي عَائِشَةُأَنْ أَكْتُبَ لَهَا مُصْحَفًا ثُمَّ قَالَتْ إِذَا بَلَغْتَ هَذِهِ الْآيَةَ فَآذِنِّي{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَقُومُوا لِلَّهِ قَانِتِينَ }فَلَمَّا بَلَغْتُهَا آذَنْتُهَا فَأَمْلَتْ عَلَيَّ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَصَلَاةِ الْعَصْرِ وَقُومُوا لِلَّهِ قَانِتِينَ قَالَتْ عَائِشَةُ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Zaid bin Aslam] dari [Al-Qa'qa' bin Hakim] dari [Abu Yunus] mantan budak Aisyah Ummul Mukminin, dia berkata; \" [Aisyah] menyuruhku menulis mushaf untuknya, kemudian ia berkata, \"Apabila kamu telah sampai pada ayat ini, maka kabarkanlah saya: '(Peliharalah semua shalat(mu), dan (peliharalah) shalat wusthaa. Berdirilah untuk Allah (dalam shalatmu) dengan khusyu') ' (Qs. Al Baqarah: 238) Tatkala saya sampai pada ayat itu, saya pun menyampaikan hal itu kepdanya. Lalu ia mendiktekan kepadaku; '(Peliharalah semua shalat(mu), dan (peliharalah) shalat wusthaa dan shalat asar. Kerjakanlah shalat dengan khusyu' karena Allah) ' Aisyah lantas berkata, \"Saya mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},{"p":"Muslim","n":967,"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي يُونُسَ مَوْلَى عَائِشَةَ أَنَّهُ قَالَ أَمَرَتْنِي عَائِشَةُ أَنْ أَكْتُبَ لَهَا مُصْحَفًا وَقَالَتْ إِذَا بَلَغْتَ هَذِهِ الْآيَةَ فَآذِنِّي{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى }فَلَمَّا بَلَغْتُهَا آذَنْتُهَافَأَمْلَتْ عَلَيَّ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى }وَصَلَاةِ الْعَصْرِ{ وَقُومُوا لِلَّهِ قَانِتِينَ }قَالَتْ عَائِشَةُ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] katanya; aku menyetorkan hapalanku kepada [Malik] dari [Zaid bin Aslam] dari [Alqa'qa' bin Hakim] dari [Abu Yunus] mantan budak Aisyah, katanya; [Aisyah] pernah memrintahkanku untuk menulis mushaf. Lalu dia berpesan; \"Jika sampai ayat ini \"Jagalah oleh kalian seluruh shalat yang ada dan shalat wustha\" (QS. Albaqarah 238), maka beritahukanlah kepadaku, \" Ketika aku sampai ayat itu, aku lalu memberitahukan kepadanya, seketika itu pula dia mendiktekan kepadaku \"Jagalah oleh kalian seluruh shalat yang ada dan shalat wustha, \" yatiu shalat ashar, \"Dan berdirilah kepada Allah dengan penuh kepatuhan\" (QS. Albaqarah 283), kata Aisyah; aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam."},{"p":"Muslim","n":968,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا الْفُضَيْلُ بْنُ مَرْزُوقٍ عَنْ شَقِيقِ بْنِ عُقْبَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَنَزَلَتْ هَذِهِ الْآيَةُ{ حَافِظُوا عَلَى الصَّلَوَاتِ }وَصَلَاةِ الْعَصْرِ فَقَرَأْنَاهَا مَا شَاءَ اللَّهُ ثُمَّ نَسَخَهَا اللَّهُ فَنَزَلَتْ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى }فَقَالَ رَجُلٌ كَانَ جَالِسًا عِنْدَ شَقِيقٍ لَهُ هِيَ إِذَنْ صَلَاةُ الْعَصْرِ فَقَالَ الْبَرَاءُ قَدْ أَخْبَرْتُكَ كَيْفَ نَزَلَتْ وَكَيْفَ نَسَخَهَا اللَّهُ وَاللَّهُ أَعْلَمُقَالَ مُسْلِم وَرَوَاهُ الْأَشْجَعِيُّ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ شَقِيقِ بْنِ عُقْبَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ قَرَأْنَاهَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَانًا بِمِثْلِ حَدِيثِ فُضَيْلِ بْنِ مَرْزُوقٍ","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] telah mengabarkan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Al Fudlail bin Marzuq] dari [Syaqiq bin 'Uqbah] dari [Al Barra` bin 'Azib] katanya; \"Jagalah oleh kalian seluruh shalat yang ada\" ayat ini turun ketika shalat ashar, maka kami membacanya sekehendak Allah beberapa lama, kemudian Allah memansukhkannya hingga turun ayat \"Jagalah oleh kalian seluruh shalat yang ada dan shalat wustha\" (QS. Albaqarah 238), Maka seseorang yang ketika itu duduk bersama Fudlail bin Marzuq berkata pada Syaqiq \"Shalat wustha yang dimaksud adalah shalat ashar, \" Lalu Al Barra` berkomentar; aku telah mengabarkan kepadamu bagaimana ayat itu turun dan bagaimana Allah memansukhkannya, dan Allah dzat yang lebih tahu.\" Muslim mengatakan; Dan hadis itu diriwayatkan pula oleh [Al Asyja'i] dari [Sufyan Ats Tsauri] dari [Al Aswad bin Qais] dari [Syaqiq bin 'Uqbah] dari [Al Barra` bin 'Azib], kata Al Barra`, kami membacanya bersama Nabi shallallahu 'alaihi wasallam, beberapa lama semisal hadis Fudlail bin Marzuq."},{"p":"Nasa'i","n":1199,"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ قَالَ حَدَّثَنِي الْحَارِثُ بْنُ شُبَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكَانَ الرَّجُلُ يُكَلِّمُ صَاحِبَهُ فِي الصَّلَاةِ بِالْحَاجَةِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نَزَلَتْ هَذِهِ الْآيَةُ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَقُومُوا لِلَّهِ قَانِتِينَ }فَأُمِرْنَا بِالسُّكُوتِ","trj":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dia berkata; telah menceritakan kepada kami [Al Harits bin Syubail] dari [Abu 'Amr Asy Syaibani] dari [Zaid bin Arqam] dia berkata; \"Pada masa Rasulullah Shalallah 'Alaihi Wa Sallam ada seorang laki-laki yang berbicara dalam shalat dengan temannya untuk suatu keperluan, lalu turunlah ayat ini, 'Peliharalah segala shalat(mu), dan (peliharalah) shalat wustha. Berdirilah karena Allah (dalam shalatmu) dengan khusyu'. (Qs. Al Baqarah (2): 238) Lalu kami disuruh diam (saat) shalat.\""}],"2:240":[{"p":"Bukhari","n":3862,"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا رَوْحٌ حَدَّثَنَا شِبْلٌ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا }قَالَ كَانَتْ هَذِهِ الْعِدَّةُ تَعْتَدُّ عِنْدَ أَهْلِ زَوْجِهَا وَاجِبٌ فَأَنْزَلَ اللَّهُ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِي أَنْفُسِهِنَّ مِنْ مَعْرُوفٍ }قَالَ جَعَلَ اللَّهُ لَهَا تَمَامَ السَّنَةِ سَبْعَةَ أَشْهُرٍ وَعِشْرِينَ لَيْلَةً وَصِيَّةً إِنْ شَاءَتْ سَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ وَهْوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ }فَالْعِدَّةُ كَمَا هِيَ وَاجِبٌ عَلَيْهَا زَعَمَ ذَلِكَ عَنْ مُجَاهِدٍ وَقَالَ عَطَاءٌ قَالَ ابْنُ عَبَّاسٍنَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا عِنْدَ أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ وَهْوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ }قَالَ عَطَاءٌ إِنْ شَاءَتْ اعْتَدَّتْ عِنْدَ أَهْلِهِ وَسَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ لِقَوْلِ اللَّهِ تَعَالَى{ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ }قَالَ عَطَاءٌ ثُمَّ جَاءَ الْمِيرَاثُ فَنَسَخَ السُّكْنَى فَتَعْتَدُّ حَيْثُ شَاءَتْ وَلَا سُكْنَى لَهَا وَعَنْ مُحَمَّدِ بْنِ يُوسُفَ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ بِهَذَا وَعَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ نَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا فِي أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ لِقَوْلِ اللَّهِ{ غَيْرَ إِخْرَاجٍ }نَحْوَهُ","trj":"Telah menceritakan kepada kami [Ishaq] Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Syibl] dari [Ibnu Abu Najih] dari Mujahid mengenai firman Allah: Dan orang-orang yang mati di antara kamu serta meninggalkan istri-istri (Al Baqarah; 234). Ayat ini menerangkan wajibnya iddah di rumah keluarganya. Lalu Allah menurunkan ayat; Dan orang-orang yang akan mati di antara kami dan meninggalkan istri-istri, hendaklah membuat wasiat untuk istri-istrinya yaitu nafkah sampai setahun tanpa mengeluarkannya dari rumah. Tetapi jika mereka keluar sendiri, maka tidak ada dosa bagimu mengenai apa yang mereka lakukan terhadap diri mereka sendiri dalam hal-hal yang baik. Mujahid berkata; Allah telah menjadikannya sebagai penyempurna dalam hitungan setahun yaitu tujuh bulan dan dua puluh malam sebagai wasiat. Apabila dia ingin, maka dia menempati sesuai wasiat tersebut. Namun jika ia ingin keluar, maka itu sudah menjadi kehendaknya. Itulah yang dimaksud firman Allah Ta'ala: Tetapi jika mereka keluar sendiri, maka tidak ada dosa bagimu. Maka Iddah adalah perkara yang wajib. Perawi mengaku itu dari Mujahid. [Atha] berkata; [Ibnu Abbas] berkata; \"Ayat ini telah menghapus 'iddah di rumah keluarganya sehingga ia ber'iddah di tempat yang ia kehendaki, yaitu firman Allah Azza wa Jalla: 'Tanpa keluar rumah.' Atha berkata; 'Jika dia berkehendak, maka dia beriddah di rumah keluarganya dan tinggal sesuai wasiatnya.' Namun jika dia berkehendak, ia keluar darinya. Sebagaimana firman Allah Ta'ala: \"Maka tidak ada dosa bagimu mengenai apa yang mereka lakukan terhadap diri mereka senidiri.\" (QS. Albaqarah 240), Atha berkata; kemudian turun ayat mirats (mengenai warisan) yang menghapus mengenai tempat tinggal, maka dia boleh beriddah sesuai kehendaknya tanpa harus tinggal dirumahnya. Dan dari [Muhammad bin Yusuf] Telah menceritakan kepada kami [Warqa] dari [Ibnu Abu Najih] dari Mujahid dengan redaksi yang serupa. Dan dari Ibnu Abu Najih dari [Atha] dari [Ibnu Abbas] dia berkata; 'ayat ini telah menghapus 'iddahnya di rumah keluarganya sehingga ia ber'iddah di tempat yang ia kehendaki, yaitu firman Allah Azza wa Jalla: 'Tanpa keluar rumah.'"},{"p":"Bukhari","n":4620,"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا شِبْلٌ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا }قَالَ كَانَتْ هَذِهِ الْعِدَّةُ تَعْتَدُّ عِنْدَ أَهْلِ زَوْجِهَا وَاجِبًا فَأَنْزَلَ اللَّهُ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِي أَنْفُسِهِنَّ مِنْ مَعْرُوفٍ }قَالَ جَعَلَ اللَّهُ لَهَا تَمَامَ السَّنَةِ سَبْعَةَ أَشْهُرٍ وَعِشْرِينَ لَيْلَةً وَصِيَّةً إِنْ شَاءَتْ سَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ وَهُوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ }فَالْعِدَّةُ كَمَا هِيَ وَاجِبٌ عَلَيْهَا زَعَمَ ذَلِكَ عَنْ مُجَاهِدٍ وَقَالَ عَطَاءٌ قَالَ ابْنُ عَبَّاسٍنَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا عِنْدَ أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ وَقَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ }وَقَالَ عَطَاءٌ إِنْ شَاءَتْ اعْتَدَّتْ عِنْدَ أَهْلِهَا وَسَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ لِقَوْلِ اللَّهِ{ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِي أَنْفُسِهِنَّ }قَالَ عَطَاءٌ ثُمَّ جَاءَ الْمِيرَاثُ فَنَسَخَ السُّكْنَى فَتَعْتَدُّ حَيْثُ شَاءَتْ وَلَا سُكْنَى لَهَا","trj":"Telah menceritakan kepadaku [Ishaq bin Manshur] Telah mengabarkan kepada kami [Rauh bin Ubadah] Telah menceritakan kepada kami [Syibl] dari [Ibnu Najih] dari [Mujahid] terkait dengan firman Allah: Dan orang-orang yang meninggal diantara kalian dan meninggalkan isteri (QS. Albaqarah 240), dahulu iddah yang dilakukan seorang isteri di rumah suaminya adalah wajib, lantas Allah menurunkan ayat; \"WALLADZI YUTAFFAUNA MINKUM WA YADZARUUNA AZWAAJAW WASHIYYATAL LIAZWAAJIHIM MATAA'AN ILAL HAULI GHAIRA IKHRAAJ FAIN KHARAJNA FALAA JUNAAHA 'ALAIKUM FIIMAA FA'ALNAA FII ANFUSIHINNA MIM MA'RUUF.\" \"Dan orang-orang yang meninggal diantara kalian dan meninggalkan isteri, hendaklah menyampaikan wasiat kediaman isteri dan nafkah kepada isterinya selama setahun dengan tidak menyuruh mereka agar keluar, namun jika para isteri yang ditinggal suaminya itu keluar rumah, maka tiada ada dosa bagimu atas perbuatan yang mereka lakukan' (QS. Albaqarah 240). Ia menjelaskan, \"Allah menjadikan kesempurnaan sunnah adalah selama empat bulan dua puluh hari, sebagai wasiat. Bila ia mau, maka oleh boleh tetap pada wasiatnya. Dan jika tidak, ia boleh keluar. Itulah yang dimaksud dengan firman Allah, 'GHAIRA IKHRAAJ, FA`IN KHARAJNA FALAA JUNAHA 'ALAIKUM (dengan tidak menyuruh si isteri untuk pergi, jika isteri itu pergi, maka tidak ada dosa atas kalian), Yakni, masa 'Iddah sebagaimana yang diwajibkan atasnya. ['Atha`] berkata; [Ibnu Abbas] berkata; Ayat ini dinasakh (dihapus) bahwa ia melalui masa iddahnya di rumah suaminya. Karena itu, ia boleh melalui masa iddahnya di mana pun ia mau.\" Dan firman Allah Ta'ala: \"Ghaira Ikharaaj\" Ahta` berkata; Bila ia mau, maka ia boleh melalui masa iddahnya di rumah suaminya atau berdiam pada washiyatnya. Dan bila ia mau, ia boleh keluar karena firman Allah: \"FALAA JUNAAHA 'ALAIKUM FIIMAA FA'ALNA FII ANFUSIHINNA.\" (Maka tak ada dosa atasmu atas perbuatan yang mereka lakukan) Atha` berkata; Kemudian turunlah ayat warisan dan terhapuslah As Sukna (tempat wanita berdiam), hingga ia pun boleh beriddah di mana pun ia suka, dan tidak ada tempat tinggal baginya."},{"p":"Nasa'i","n":3387,"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى السِّجْزِيُّ خَيَّاطُ السُّنَّةِ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ أَخْبَرَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ }نُسِخَ ذَلِكَ بِآيَةِ الْمِيرَاثِ مِمَّا فُرِضَ لَهَا مِنْ الرُّبُعِ وَالثُّمُنِ وَنَسَخَ أَجَلَ الْحَوْلِ أَنْ جُعِلَ أَجَلُهَا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya As Sijzi Khayyath As Sunnah] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah memberitakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(Dan orang-orang yang akan meninggal dunia di antara kamu dan meninggalkan isteri, hendaklah berwasiat untuk isteri-isterinya, (yaitu) diberi nafkah hingga setahun lamanya dan tidak disuruh pindah (dari rumahnya) ' (Qs. Al Baqarah: 240), telah dihapus dengan ayat mengenai ayat warisan di antara yang ditetapkan baginya dari seperempat dan seperdelapan, dan Allah juga menghapus masa 'iddah satu tahun dan dijadikan empat bulan sepuluh hari.\""},{"p":"Nasa'i","n":3388,"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ }قَالَ نَسَخَتْهَا{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا }","trj":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari ['Ikrimah] mengenai firman Allah 'azza wajalla: '(Dan orang-orang yang akan meninggal dunia di antara kamu dan meninggalkan isteri, hendaklah berwasiat untuk isteri-isterinya, (yaitu) diberi nafkah hingga setahun lamanya dan tidak disuruh pindah (dari rumahnya) ' (Qs. Al Baqarah: 240). 'Ikrimah berkata, \"Ayat tersebut dihapus oleh ayat: '(Orang-orang yang meninggal dunia di antaramu dengan meninggalkan isteri-isteri (hendaklah para isteri itu) menangguhkan dirinya (ber'iddah) empat bulan sepuluh hari) ' (Qs. Al Baqarah: 234)."}],"2:245":[{"p":"Tirmidzi","n":2822,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }أَوْ{ مَنْ ذَا الَّذِي يُقْرِضُ اللَّهَ قَرْضًا حَسَنًا }قَالَ أَبُو طَلْحَةَ وَكَانَ لَهُ حَائِطٌ فَقَالَ يَا رَسُولَ اللَّهِ حَائِطِي لِلَّهِ وَلَوْ اسْتَطَعْتُ أَنْ أُسِرَّهُ لَمْ أُعْلِنْهُ فَقَالَ اجْعَلْهُ فِي قَرَابَتِكَ أَوْ أَقْرَبِيكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكِ","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdullah bin Bakr As Sahmani] telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata; \"Ketika turun ayat Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebahagian harta yang kamu cintai.\" QS Ali 'Imran: 92 atau Siapakah yang mau memberi pinjaman kepada Allah, pinjaman yang baik (menafkahkan hartanya di jalan Allah). QS Al-Baqarah: 245, kemudian Abu Thalhah, yang memiliki kebun berkata; \"Wahai Rasulullah, saya (infakkan) kebun saya ini di jalan Allah. Dan sekiranya saya mampu untuk menyembunyikannya tentu saya tidak menyatakannya. lalu beliau mengatakan \"Berikanlah kepada kerabat atau orang yang terdekat denganmu!\" Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan [Malik bin Anas] telah meriwayatkan dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] "}],"2:260":[{"p":"Bukhari","n":3064,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَحْنُ أَحَقُّ بِالشَّكِّ مِنْ إِبْرَاهِيمَ إِذْ قَالَ{ رَبِّ أَرِنِي كَيْفَ تُحْيِي الْمَوْتَى قَالَ أَوْ لَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي }وَيَرْحَمُ اللَّهُ لُوطًا لَقَدْ كَانَ يَأْوِي إِلَى رُكْنٍ شَدِيدٍ وَلَوْ لَبِثْتُ فِي السِّجْنِ طُولَ مَا لَبِثَ يُوسُفُ لَأَجَبْتُ الدَّاعِيَ","trj":"Telah bercerita kepada kami [Ahmad bin Shalih] telah bercerita kepada kami [Ibnu Wahb] berkata telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah bin 'Abdur Rahman] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami lebih patut untuk ragu dibanding Ibrahim ketika dia berkata; (Ya Rabbku, tunjukkan kepadaku bagaimana caranya Engkau menghidupkan makhluq yang sudah mati. Allah berfirman; \"Apakah kamu tidak beriman (belum yakin)?\" Ibrahim berkata; \"Aku telah meyakininya akan tetapi untuk memantapkan hatiku\"). Dan semoga Allah merahmati Nabi Luth 'Alaihissalam yang telah berlindung kepada keluarga yang kuat. Dan seandainya aku dipenjara dan mendekam didalamnya dalam masa tertentu sebagaimana Nabi Yusuf 'Alaihissalam mengalaminya tentu aku sudah bersegera memenuhi permintaan (orang yang akan membebaskan aku) \". (QS. Albaqarah 260)."},{"p":"Ibnu Majah","n":3980,"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى وَيُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ أَحَقُّ بِالشَّكِّ مِنْ إِبْرَاهِيمَ إِذْ قَالَ رَبِّ أَرِنِي كَيْفَ تُحْيِي الْمَوْتَى قَالَ أَوَلَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي وَيَرْحَمُ اللَّهُ لُوطًا لَقَدْ كَانَ يَأْوِي إِلَى رُكْنٍ شَدِيدٍ وَلَوْ لَبِثْتُ فِي السِّجْنِ طُولَ مَا لَبِثَ يُوسُفُ لَأَجَبْتُ الدَّاعِيَ","trj":"Telah menceritakan kepada kami [Harmalah bin Yahya] dan [Yunus bin Abdul A'la] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman bin 'Auf] dan [Sa'id bin Al Musayyab] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami lebih berhak ragu daripada Ibrahim, ketika dia berkata, '(Dan (Ingatlah) ketika Ibrahim berkata: \"Ya Tuhanku, perlihatkanlah kepadaku bagaimana Engkau menghidupkan orang-orang mati.\" Allah berfirman: \"Belum yakinkah kamu?\" Ibrahim menjawab: \"Aku telah meyakinkannya, akan tetapi agar hatiku tetap mantap (dengan imanku) ' (Qs. Al Baqarah: 260). Dan Allah telah merahmati Nabi Luth karena beliau telah berlindung kepada keluarga yang kuat. Dan sekiranya aku dipenjara selama Nabi Yusuf dipenjara, pastilah aku tetap menunaikan panggilan.\""},{"p":"Muslim","n":215,"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَحْنُ أَحَقُّ بِالشَّكِّ مِنْ إِبْرَاهِيمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ قَالَ{ رَبِّ أَرِنِي كَيْفَ تُحْيِي الْمَوْتَى قَالَ أَوَ لَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي }قَالَ وَيَرْحَمُ اللَّهُ لُوطًا لَقَدْ كَانَ يَأْوِي إِلَى رُكْنٍ شَدِيدٍ وَلَوْ لَبِثْتُ فِي السِّجْنِ طُولَ لَبْثِ يُوسُفَ لَأَجَبْتُ الدَّاعِيَو حَدَّثَنِي بِهِ إِنْ شَاءَ اللَّهُ عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ الضُّبَعِيُّ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ أَنَّ سَعِيدَ بْنَ الْمُسَيَّبِ وَأَبَا عُبَيْدٍ أَخْبَرَاهُ عَنْ أَبِي هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ يُونُسَ عَنْ الزُّهْرِيِّ وَفِي حَدِيثِ مَالِكٍ{ وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي }قَالَ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ حَتَّى جَازَهَا حَدَّثَنَاه عَبْدُ بْنُ حُمَيْدٍ قَالَ حَدَّثَنِي يَعْقُوبُ يَعْنِي ابْنَ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبُو أُوَيْسٍ عَنْ الزُّهْرِيِّ كَرِوَايَةِ مَالِكٍ بِإِسْنَادِهِ وَقَالَ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ حَتَّى أَنْجَزَهَا","trj":"Dan telah menceritakan kepada kami [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahab] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dan [Sa'id bin al-Musayyab] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami lebih berhak merasa ragu daripada Nabi Ibrahim Alaihissalam ketika dia berkata: '(Wahai Tuhanku, tunjukkanlah kepadaku bagaimana Kamu menghidupkan orang mati? ' Allah berfirman, 'Apakah kamu tidak percaya kepada kekuasaanKu? ' Nabi Ibrahim menjawab, 'Aku tetap percaya dan yakin, tetapi agar hatiku tenteram) ' (Qs. Al Baqarah: 260). Rasulullah shallallahu 'alaihi wasallam terus bersabda: \"Semoga Allah memberikan rahmat kepada Nabi Lut'. Dia benar-benar telah berlindung kepada suatu kuasa yang kuat (Allah subhanahu wata'ala). Andaikata aku tinggal di penjara selama masa yang dilalui Nabi Yusuf berada di dalamnya niscaya aku akan memenuhi keinginan orang yang meminta'.\" Dan telah menceritakan kepada kami insya Allah [Abdullah bin Muhammad bin Asma' adl-Dluba'i] telah menceritakan kepada kami [Juwairiyah] dari [Malik] dari [az-Zuhri] bahwa [Sa'id bin al-Musayyab] dan [Abu Ubaid] telah mengabarkan kepadanya, dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam dengan semisal hadits Yunus dari az-Zuhri. Dan dalam hadits Malik disebutkan, '(Akan tetapi agar hatiku menjadi tenang) ' (Qs. Al Baqarah: 260). Perawi berkata, \"Kemudian beliau membaca ayat ini hingga selesai.\" Dan telah menceritakan kepada kami [Abd bin Humaid] dia berkata, telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Ibrahim bin Sa'd- telah menceritakan kepada kami [Abu Uwais] dari [az-Zuhri] seperti riwayat Malik dengan sanadnya, dia menyebutkan, 'Kemudian beliau membaca ayat ini hingga menyelesaikan-Nya.\""}],"2:283":[{"p":"Muslim","n":967,"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي يُونُسَ مَوْلَى عَائِشَةَ أَنَّهُ قَالَ أَمَرَتْنِي عَائِشَةُ أَنْ أَكْتُبَ لَهَا مُصْحَفًا وَقَالَتْ إِذَا بَلَغْتَ هَذِهِ الْآيَةَ فَآذِنِّي{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى }فَلَمَّا بَلَغْتُهَا آذَنْتُهَافَأَمْلَتْ عَلَيَّ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى }وَصَلَاةِ الْعَصْرِ{ وَقُومُوا لِلَّهِ قَانِتِينَ }قَالَتْ عَائِشَةُ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] katanya; aku menyetorkan hapalanku kepada [Malik] dari [Zaid bin Aslam] dari [Alqa'qa' bin Hakim] dari [Abu Yunus] mantan budak Aisyah, katanya; [Aisyah] pernah memrintahkanku untuk menulis mushaf. Lalu dia berpesan; \"Jika sampai ayat ini \"Jagalah oleh kalian seluruh shalat yang ada dan shalat wustha\" (QS. Albaqarah 238), maka beritahukanlah kepadaku, \" Ketika aku sampai ayat itu, aku lalu memberitahukan kepadanya, seketika itu pula dia mendiktekan kepadaku \"Jagalah oleh kalian seluruh shalat yang ada dan shalat wustha, \" yatiu shalat ashar, \"Dan berdirilah kepada Allah dengan penuh kepatuhan\" (QS. Albaqarah 283), kata Aisyah; aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam."}],"2:284":[{"p":"Muslim","n":178,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ مِنْهَالٍ الضَّرِيرُ وَأُمَيَّةُ بْنُ بِسْطَامَ الْعَيْشِيُّ وَاللَّفْظُ لِأُمَيَّةَ قَالَا حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا رَوْحٌ وَهُوَ ابْنُ الْقَاسِمِ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا نَزَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لِلَّهِ مَا فِي السَّمَوَاتِ وَمَا فِي الْأَرْضِ وَإِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُمْ بِهِ اللَّهُ فَيَغْفِرُ لِمَنْ يَشَاءُ وَيُعَذِّبُ مَنْ يَشَاءُ وَاللَّهُ عَلَى كُلِّ شَيْءٍ قَدِيرٌ }قَالَ فَاشْتَدَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ بَرَكُوا عَلَى الرُّكَبِ فَقَالُوا أَيْ رَسُولَ اللَّهِ كُلِّفْنَا مِنْ الْأَعْمَالِ مَا نُطِيقُ الصَّلَاةَ وَالصِّيَامَ وَالْجِهَادَ وَالصَّدَقَةَ وَقَدْ أُنْزِلَتْ عَلَيْكَ هَذِهِ الْآيَةُ وَلَا نُطِيقُهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُرِيدُونَ أَنْ تَقُولُوا كَمَا قَالَ أَهْلُ الْكِتَابَيْنِ مِنْ قَبْلِكُمْ سَمِعْنَا وَعَصَيْنَا بَلْ قُولُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ قَالُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ فَلَمَّا اقْتَرَأَهَا الْقَوْمُ ذَلَّتْ بِهَا أَلْسِنَتُهُمْ فَأَنْزَلَ اللَّهُ فِي إِثْرِهَا{ آمَنَ الرَّسُولُ بِمَا أُنْزِلَ إِلَيْهِ مِنْ رَبِّهِ وَالْمُؤْمِنُونَ كُلٌّ آمَنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِنْ رُسُلِهِ وَقَالُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ }فَلَمَّا فَعَلُوا ذَلِكَ نَسَخَهَا اللَّهُ تَعَالَى فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا اكْتَسَبَتْ رَبَّنَا لَا تُؤَاخِذْنَا إِنْ نَسِينَا أَوْ أَخْطَأْنَا }قَالَ نَعَمْ{ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَا إِصْرًا كَمَا حَمَلْتَهُ عَلَى الَّذِينَ مِنْ قَبْلِنَا }قَالَ نَعَمْ{ رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِ }قَالَ نَعَمْ{ وَاعْفُ عَنَّا وَاغْفِرْ لَنَا وَارْحَمْنَا أَنْتَ مَوْلَانَا فَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِينَ }قَالَ نَعَمْ","trj":"Telah menceritakan kepadaku [Muhammad bin Minhal adl-Dlarir] dan [Umayyah bin Bistham al-Aisyi] dan lafazh tersebut milik Umayyah, keduanya berkata, telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Rauh] -yaitu Ibnu al-Qasim- dari [al-Ala'] dari [bapaknya] dari [Abu Hurairah] dia berkata, \"Ketika turun ayat pada Rasulullah shallallahu 'alaihi wasallam: '(Kepunyaan Allah-lah segala apa yang ada di langit dan di bumi. Dan jika kamu melahirkan apa yang ada di dalam hatimu atau kamu menyembunyikannya, niscaya Allah akan membuat perhitungan dengan kamu tentang perbuatanmu itu. Maka Allah mengampuni siapa yang dikehendaki-Nya dan menyiksa siapa yang dikehendaki-Nya; dan Allah Maha Kuasa atas segala sesuatu) ' (Qs. al-Baqarah: 284) ' Abu Hurairah berkata, 'Maka hal tersebut terasa berat atas para sahabat Rasulullah shallallahu 'alaihi wasallam, lalu mereka mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengucapkan salam di atas kendaraan seraya berkata, 'Wahai Rasulullah, kami diberi beban amalan yang mana kami tidak mampu melakukan shalat, puasa, jihad, dan sedekah. Sungguh telah diturunkan ayat ini kepadamu, dan kami tidak mampu melakukannya! Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kamu ingin mengucapkan sebagaimana ahli kitab sebelum kalian mengucapkan, 'Kami mendengar dan kami mendurhakai', akan tetapi katakanlah, 'Kami mendengar dan kami menaati, Ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali'. Mereka menjawab, 'Kami mendengar dan kami menaatinya, ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali.' Ketika kaum tersebut membacanya, maka lisan-lisan mereka tunduk dengannya, lalu Allah menurunkan sesudahnya: '(Rasul telah beriman kepada al-Qur'an yang diturunkan kepadanya dari Rabbnya, demikian pula orang-orang yang beriman. Semuanya beriman kepada Allah, malaikat-malaikat-Nya, kitab-kitab-Nya dan rasul-rasul-Nya. (Mereka mengatakan), 'Kami tidak membeda-bedakan antara seorang pun (dengan yang lain) dari rasul-rasul-Nya', dan mereka mengatakan, 'Kami dengar dan kami taat'. (Mereka berdoa), 'Ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali'. (Qs. al-Baqarah: 285). Ketika mereka melakukan hal tersebut, maka Allah menghapusnya, lalu menurunkan: '(Allah tidak membebani seseorang melainkan sesuai dengan kesanggupannya. Ia mendapat pahala (dari kebajikan) yang diusahakannya dan mendapat siksa (dari kejahatan) yang dikerjakannya. (Mereka berdoa): \"Ya Rabb kami, janganlah Engkau hukum kami jika kami lupa atau kami bersalah) ' Allah menjawab: \"Ya.\" '(Ya Rabb kami, janganlah Engkau bebankan kepada kami beban yang berat sebagaimana Engkau bebankan kepada orang-orang yang sebelum kami) ' Allah menjawab: \"Ya.\" '(Wahai Rabb kami, janganlah Engkau pikulkan kepada kami apa yang tak sanggup kami memikulnya) ' Allah menjawab: \"Ya.\" '(Beri maaflah kami; ampunilah kami; dan rahmatilah kami. Engkaulah Penolong kami, maka tolonglah kami terhadap kaum yang kafir'. (Qs. al-Baqarah: 286). Allah menjawab: \"Ya.\""},{"p":"Muslim","n":179,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِأَبِي بَكْرٍ قَالَ إِسْحَقُ أَخْبَرَنَا وَقَالَ الْآخَرَانِ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ آدَمَ بْنِ سُلَيْمَانَ مَوْلَى خَالِدٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَإِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُمْ بِهِ اللَّهُ }قَالَ دَخَلَ قُلُوبَهُمْ مِنْهَا شَيْءٌ لَمْ يَدْخُلْ قُلُوبَهُمْ مِنْ شَيْءٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُولُوا سَمِعْنَا وَأَطَعْنَا وَسَلَّمْنَا قَالَ فَأَلْقَى اللَّهُ الْإِيمَانَ فِي قُلُوبِهِمْ فَأَنْزَلَ اللَّهُ تَعَالَى{ لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا اكْتَسَبَتْ رَبَّنَا لَا تُؤَاخِذْنَا إِنْ نَسِينَا أَوْ أَخْطَأْنَا }قَالَ قَدْ فَعَلْتُ{ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَا إِصْرًا كَمَا حَمَلْتَهُ عَلَى الَّذِينَ مِنْ قَبْلِنَا }قَالَ قَدْ فَعَلْتُ{ وَاغْفِرْ لَنَا وَارْحَمْنَا أَنْتَ مَوْلَانَا }قَالَ قَدْ فَعَلْتُ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] serta [Ishaq bin Ibrahim] dan lafazh tersebut milik Abu Bakar, berkata [Ishaq] telah mengabarkan kepada kami, sedangkan dua orang lainnya berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Adam bin Sulaiman] mantan budak Khalid, dia berkata, saya mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Abbas] dia berkata, \"Ketika turun ayat: '(Dan jika kamu melahirkan sesuatu yang ada di dalam hatimu atau kamu menyembunyikannya, niscaya Allah akan membuat perhitungan dengan kamu tentang perbuatanmu itu) ' (Qs. Albaqarah: 284). Ibnu Abbas berkata, \"Maka masuklah suatu kesedihan darinya ke dalam hati mereka yang mana tidak pernah masuk ke dalam hati mereka sedikit pun.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Katakanlah, 'Saya mendengar dan saya menaati serta saya menyerahkan diri'.\" Ibnu Abbas berkata, \"Lalu Allah meletakkan iman pada hati mereka, yang kemudian menurunkan ayat: '(Allah tidak membebani seseorang melainkan sesuai dengan kesanggupannya. Ia mendapat pahala (dari kebajikan) yang diusahakannya dan mendapat siksa (dari kejahatan) yang dikerjakannya. (Mereka berdoa), 'Ya Rabb kami, janganlah Engkau hukum kami jika kami lupa atau kami bersalah) ' (Qs. Al Baqarah: 286), Allah berfirman: \"Sungguh aku telah melakukannya.\" '(Wahai Rabb kami, dan janganlah Engkau bebankan kepada kami beban yang berat sebagaimana Engkau bebankan kepada orang-orang yang sebelum kami) ' (Qs. Al baqarah: 286), Allah berfirman: \"Aku telah melakukanya.\" '(Wahai Rabb kami, Beri maaflah kami; ampunilah kami; dan rahmatilah kami. Engkaulah Penolong kami) ' Allah berfiraman: \"Aku telah lakukan.\""}],"2:285":[{"p":"Muslim","n":178,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ مِنْهَالٍ الضَّرِيرُ وَأُمَيَّةُ بْنُ بِسْطَامَ الْعَيْشِيُّ وَاللَّفْظُ لِأُمَيَّةَ قَالَا حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا رَوْحٌ وَهُوَ ابْنُ الْقَاسِمِ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا نَزَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لِلَّهِ مَا فِي السَّمَوَاتِ وَمَا فِي الْأَرْضِ وَإِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُمْ بِهِ اللَّهُ فَيَغْفِرُ لِمَنْ يَشَاءُ وَيُعَذِّبُ مَنْ يَشَاءُ وَاللَّهُ عَلَى كُلِّ شَيْءٍ قَدِيرٌ }قَالَ فَاشْتَدَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ بَرَكُوا عَلَى الرُّكَبِ فَقَالُوا أَيْ رَسُولَ اللَّهِ كُلِّفْنَا مِنْ الْأَعْمَالِ مَا نُطِيقُ الصَّلَاةَ وَالصِّيَامَ وَالْجِهَادَ وَالصَّدَقَةَ وَقَدْ أُنْزِلَتْ عَلَيْكَ هَذِهِ الْآيَةُ وَلَا نُطِيقُهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُرِيدُونَ أَنْ تَقُولُوا كَمَا قَالَ أَهْلُ الْكِتَابَيْنِ مِنْ قَبْلِكُمْ سَمِعْنَا وَعَصَيْنَا بَلْ قُولُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ قَالُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ فَلَمَّا اقْتَرَأَهَا الْقَوْمُ ذَلَّتْ بِهَا أَلْسِنَتُهُمْ فَأَنْزَلَ اللَّهُ فِي إِثْرِهَا{ آمَنَ الرَّسُولُ بِمَا أُنْزِلَ إِلَيْهِ مِنْ رَبِّهِ وَالْمُؤْمِنُونَ كُلٌّ آمَنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِنْ رُسُلِهِ وَقَالُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ }فَلَمَّا فَعَلُوا ذَلِكَ نَسَخَهَا اللَّهُ تَعَالَى فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا اكْتَسَبَتْ رَبَّنَا لَا تُؤَاخِذْنَا إِنْ نَسِينَا أَوْ أَخْطَأْنَا }قَالَ نَعَمْ{ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَا إِصْرًا كَمَا حَمَلْتَهُ عَلَى الَّذِينَ مِنْ قَبْلِنَا }قَالَ نَعَمْ{ رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِ }قَالَ نَعَمْ{ وَاعْفُ عَنَّا وَاغْفِرْ لَنَا وَارْحَمْنَا أَنْتَ مَوْلَانَا فَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِينَ }قَالَ نَعَمْ","trj":"Telah menceritakan kepadaku [Muhammad bin Minhal adl-Dlarir] dan [Umayyah bin Bistham al-Aisyi] dan lafazh tersebut milik Umayyah, keduanya berkata, telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Rauh] -yaitu Ibnu al-Qasim- dari [al-Ala'] dari [bapaknya] dari [Abu Hurairah] dia berkata, \"Ketika turun ayat pada Rasulullah shallallahu 'alaihi wasallam: '(Kepunyaan Allah-lah segala apa yang ada di langit dan di bumi. Dan jika kamu melahirkan apa yang ada di dalam hatimu atau kamu menyembunyikannya, niscaya Allah akan membuat perhitungan dengan kamu tentang perbuatanmu itu. Maka Allah mengampuni siapa yang dikehendaki-Nya dan menyiksa siapa yang dikehendaki-Nya; dan Allah Maha Kuasa atas segala sesuatu) ' (Qs. al-Baqarah: 284) ' Abu Hurairah berkata, 'Maka hal tersebut terasa berat atas para sahabat Rasulullah shallallahu 'alaihi wasallam, lalu mereka mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengucapkan salam di atas kendaraan seraya berkata, 'Wahai Rasulullah, kami diberi beban amalan yang mana kami tidak mampu melakukan shalat, puasa, jihad, dan sedekah. Sungguh telah diturunkan ayat ini kepadamu, dan kami tidak mampu melakukannya! Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kamu ingin mengucapkan sebagaimana ahli kitab sebelum kalian mengucapkan, 'Kami mendengar dan kami mendurhakai', akan tetapi katakanlah, 'Kami mendengar dan kami menaati, Ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali'. Mereka menjawab, 'Kami mendengar dan kami menaatinya, ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali.' Ketika kaum tersebut membacanya, maka lisan-lisan mereka tunduk dengannya, lalu Allah menurunkan sesudahnya: '(Rasul telah beriman kepada al-Qur'an yang diturunkan kepadanya dari Rabbnya, demikian pula orang-orang yang beriman. Semuanya beriman kepada Allah, malaikat-malaikat-Nya, kitab-kitab-Nya dan rasul-rasul-Nya. (Mereka mengatakan), 'Kami tidak membeda-bedakan antara seorang pun (dengan yang lain) dari rasul-rasul-Nya', dan mereka mengatakan, 'Kami dengar dan kami taat'. (Mereka berdoa), 'Ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali'. (Qs. al-Baqarah: 285). Ketika mereka melakukan hal tersebut, maka Allah menghapusnya, lalu menurunkan: '(Allah tidak membebani seseorang melainkan sesuai dengan kesanggupannya. Ia mendapat pahala (dari kebajikan) yang diusahakannya dan mendapat siksa (dari kejahatan) yang dikerjakannya. (Mereka berdoa): \"Ya Rabb kami, janganlah Engkau hukum kami jika kami lupa atau kami bersalah) ' Allah menjawab: \"Ya.\" '(Ya Rabb kami, janganlah Engkau bebankan kepada kami beban yang berat sebagaimana Engkau bebankan kepada orang-orang yang sebelum kami) ' Allah menjawab: \"Ya.\" '(Wahai Rabb kami, janganlah Engkau pikulkan kepada kami apa yang tak sanggup kami memikulnya) ' Allah menjawab: \"Ya.\" '(Beri maaflah kami; ampunilah kami; dan rahmatilah kami. Engkaulah Penolong kami, maka tolonglah kami terhadap kaum yang kafir'. (Qs. al-Baqarah: 286). Allah menjawab: \"Ya.\""}],"2:286":[{"p":"Muslim","n":178,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ مِنْهَالٍ الضَّرِيرُ وَأُمَيَّةُ بْنُ بِسْطَامَ الْعَيْشِيُّ وَاللَّفْظُ لِأُمَيَّةَ قَالَا حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا رَوْحٌ وَهُوَ ابْنُ الْقَاسِمِ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا نَزَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لِلَّهِ مَا فِي السَّمَوَاتِ وَمَا فِي الْأَرْضِ وَإِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُمْ بِهِ اللَّهُ فَيَغْفِرُ لِمَنْ يَشَاءُ وَيُعَذِّبُ مَنْ يَشَاءُ وَاللَّهُ عَلَى كُلِّ شَيْءٍ قَدِيرٌ }قَالَ فَاشْتَدَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ بَرَكُوا عَلَى الرُّكَبِ فَقَالُوا أَيْ رَسُولَ اللَّهِ كُلِّفْنَا مِنْ الْأَعْمَالِ مَا نُطِيقُ الصَّلَاةَ وَالصِّيَامَ وَالْجِهَادَ وَالصَّدَقَةَ وَقَدْ أُنْزِلَتْ عَلَيْكَ هَذِهِ الْآيَةُ وَلَا نُطِيقُهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُرِيدُونَ أَنْ تَقُولُوا كَمَا قَالَ أَهْلُ الْكِتَابَيْنِ مِنْ قَبْلِكُمْ سَمِعْنَا وَعَصَيْنَا بَلْ قُولُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ قَالُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ فَلَمَّا اقْتَرَأَهَا الْقَوْمُ ذَلَّتْ بِهَا أَلْسِنَتُهُمْ فَأَنْزَلَ اللَّهُ فِي إِثْرِهَا{ آمَنَ الرَّسُولُ بِمَا أُنْزِلَ إِلَيْهِ مِنْ رَبِّهِ وَالْمُؤْمِنُونَ كُلٌّ آمَنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِنْ رُسُلِهِ وَقَالُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ }فَلَمَّا فَعَلُوا ذَلِكَ نَسَخَهَا اللَّهُ تَعَالَى فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا اكْتَسَبَتْ رَبَّنَا لَا تُؤَاخِذْنَا إِنْ نَسِينَا أَوْ أَخْطَأْنَا }قَالَ نَعَمْ{ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَا إِصْرًا كَمَا حَمَلْتَهُ عَلَى الَّذِينَ مِنْ قَبْلِنَا }قَالَ نَعَمْ{ رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِ }قَالَ نَعَمْ{ وَاعْفُ عَنَّا وَاغْفِرْ لَنَا وَارْحَمْنَا أَنْتَ مَوْلَانَا فَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِينَ }قَالَ نَعَمْ","trj":"Telah menceritakan kepadaku [Muhammad bin Minhal adl-Dlarir] dan [Umayyah bin Bistham al-Aisyi] dan lafazh tersebut milik Umayyah, keduanya berkata, telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Rauh] -yaitu Ibnu al-Qasim- dari [al-Ala'] dari [bapaknya] dari [Abu Hurairah] dia berkata, \"Ketika turun ayat pada Rasulullah shallallahu 'alaihi wasallam: '(Kepunyaan Allah-lah segala apa yang ada di langit dan di bumi. Dan jika kamu melahirkan apa yang ada di dalam hatimu atau kamu menyembunyikannya, niscaya Allah akan membuat perhitungan dengan kamu tentang perbuatanmu itu. Maka Allah mengampuni siapa yang dikehendaki-Nya dan menyiksa siapa yang dikehendaki-Nya; dan Allah Maha Kuasa atas segala sesuatu) ' (Qs. al-Baqarah: 284) ' Abu Hurairah berkata, 'Maka hal tersebut terasa berat atas para sahabat Rasulullah shallallahu 'alaihi wasallam, lalu mereka mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengucapkan salam di atas kendaraan seraya berkata, 'Wahai Rasulullah, kami diberi beban amalan yang mana kami tidak mampu melakukan shalat, puasa, jihad, dan sedekah. Sungguh telah diturunkan ayat ini kepadamu, dan kami tidak mampu melakukannya! Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kamu ingin mengucapkan sebagaimana ahli kitab sebelum kalian mengucapkan, 'Kami mendengar dan kami mendurhakai', akan tetapi katakanlah, 'Kami mendengar dan kami menaati, Ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali'. Mereka menjawab, 'Kami mendengar dan kami menaatinya, ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali.' Ketika kaum tersebut membacanya, maka lisan-lisan mereka tunduk dengannya, lalu Allah menurunkan sesudahnya: '(Rasul telah beriman kepada al-Qur'an yang diturunkan kepadanya dari Rabbnya, demikian pula orang-orang yang beriman. Semuanya beriman kepada Allah, malaikat-malaikat-Nya, kitab-kitab-Nya dan rasul-rasul-Nya. (Mereka mengatakan), 'Kami tidak membeda-bedakan antara seorang pun (dengan yang lain) dari rasul-rasul-Nya', dan mereka mengatakan, 'Kami dengar dan kami taat'. (Mereka berdoa), 'Ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali'. (Qs. al-Baqarah: 285). Ketika mereka melakukan hal tersebut, maka Allah menghapusnya, lalu menurunkan: '(Allah tidak membebani seseorang melainkan sesuai dengan kesanggupannya. Ia mendapat pahala (dari kebajikan) yang diusahakannya dan mendapat siksa (dari kejahatan) yang dikerjakannya. (Mereka berdoa): \"Ya Rabb kami, janganlah Engkau hukum kami jika kami lupa atau kami bersalah) ' Allah menjawab: \"Ya.\" '(Ya Rabb kami, janganlah Engkau bebankan kepada kami beban yang berat sebagaimana Engkau bebankan kepada orang-orang yang sebelum kami) ' Allah menjawab: \"Ya.\" '(Wahai Rabb kami, janganlah Engkau pikulkan kepada kami apa yang tak sanggup kami memikulnya) ' Allah menjawab: \"Ya.\" '(Beri maaflah kami; ampunilah kami; dan rahmatilah kami. Engkaulah Penolong kami, maka tolonglah kami terhadap kaum yang kafir'. (Qs. al-Baqarah: 286). Allah menjawab: \"Ya.\""},{"p":"Muslim","n":179,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِأَبِي بَكْرٍ قَالَ إِسْحَقُ أَخْبَرَنَا وَقَالَ الْآخَرَانِ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ آدَمَ بْنِ سُلَيْمَانَ مَوْلَى خَالِدٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَإِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُمْ بِهِ اللَّهُ }قَالَ دَخَلَ قُلُوبَهُمْ مِنْهَا شَيْءٌ لَمْ يَدْخُلْ قُلُوبَهُمْ مِنْ شَيْءٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُولُوا سَمِعْنَا وَأَطَعْنَا وَسَلَّمْنَا قَالَ فَأَلْقَى اللَّهُ الْإِيمَانَ فِي قُلُوبِهِمْ فَأَنْزَلَ اللَّهُ تَعَالَى{ لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا اكْتَسَبَتْ رَبَّنَا لَا تُؤَاخِذْنَا إِنْ نَسِينَا أَوْ أَخْطَأْنَا }قَالَ قَدْ فَعَلْتُ{ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَا إِصْرًا كَمَا حَمَلْتَهُ عَلَى الَّذِينَ مِنْ قَبْلِنَا }قَالَ قَدْ فَعَلْتُ{ وَاغْفِرْ لَنَا وَارْحَمْنَا أَنْتَ مَوْلَانَا }قَالَ قَدْ فَعَلْتُ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] serta [Ishaq bin Ibrahim] dan lafazh tersebut milik Abu Bakar, berkata [Ishaq] telah mengabarkan kepada kami, sedangkan dua orang lainnya berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Adam bin Sulaiman] mantan budak Khalid, dia berkata, saya mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Abbas] dia berkata, \"Ketika turun ayat: '(Dan jika kamu melahirkan sesuatu yang ada di dalam hatimu atau kamu menyembunyikannya, niscaya Allah akan membuat perhitungan dengan kamu tentang perbuatanmu itu) ' (Qs. Albaqarah: 284). Ibnu Abbas berkata, \"Maka masuklah suatu kesedihan darinya ke dalam hati mereka yang mana tidak pernah masuk ke dalam hati mereka sedikit pun.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Katakanlah, 'Saya mendengar dan saya menaati serta saya menyerahkan diri'.\" Ibnu Abbas berkata, \"Lalu Allah meletakkan iman pada hati mereka, yang kemudian menurunkan ayat: '(Allah tidak membebani seseorang melainkan sesuai dengan kesanggupannya. Ia mendapat pahala (dari kebajikan) yang diusahakannya dan mendapat siksa (dari kejahatan) yang dikerjakannya. (Mereka berdoa), 'Ya Rabb kami, janganlah Engkau hukum kami jika kami lupa atau kami bersalah) ' (Qs. Al Baqarah: 286), Allah berfirman: \"Sungguh aku telah melakukannya.\" '(Wahai Rabb kami, dan janganlah Engkau bebankan kepada kami beban yang berat sebagaimana Engkau bebankan kepada orang-orang yang sebelum kami) ' (Qs. Al baqarah: 286), Allah berfirman: \"Aku telah melakukanya.\" '(Wahai Rabb kami, Beri maaflah kami; ampunilah kami; dan rahmatilah kami. Engkaulah Penolong kami) ' Allah berfiraman: \"Aku telah lakukan.\""}]},"mapping_surah":[{"p":"Abu Dawud","n":214,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ الْيَهُودَ كَانَتْ إِذَا حَاضَتْ مِنْهُمْ الْمَرْأَةُ أَخْرَجُوهَا مِنْ الْبَيْتِ وَلَمْ يُؤَاكِلُوهَا وَلَمْ يُشَارِبُوهَا وَلَمْ يُجَامِعُوهَا فِي الْبَيْتِ فَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ سُبْحَانَهُ{ وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ }إِلَى آخِرِ الْآيَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَامِعُوهُنَّ فِي الْبُيُوتِ وَاصْنَعُوا كُلَّ شَيْءٍ غَيْرَ النِّكَاحِ فَقَالَتْ الْيَهُودُ مَا يُرِيدُ هَذَا الرَّجُلُ أَنْ يَدَعَ شَيْئًا مِنْ أَمْرِنَا إِلَّا خَالَفَنَا فِيهِ فَجَاءَ أُسَيْدُ بْنُ حُضَيْرٍ وَعَبَّادُ بْنُ بِشْرٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَا يَا رَسُولَ اللَّهِ إِنَّ الْيَهُودَ تَقُولُ كَذَا وَكَذَا أَفَلَا نَنْكِحُهُنَّ فِي الْمَحِيضِ فَتَمَعَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى ظَنَنَّا أَنْ قَدْ وَجَدَ عَلَيْهِمَا فَخَرَجَا فَاسْتَقْبَلَتْهُمَا هَدِيَّةٌ مِنْ لَبَنٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ فِي آثَارِهِمَا فَسَقَاهُمَا فَظَنَنَّا أَنَّهُ لَمْ يَجِدْ عَلَيْهِمَا","trj":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Tsabit Al-Bunani] dari [Anas bin Malik] bahwasanya orang-orang Yahudi, apabila istri-istri mereka datang haidl, maka mereka mengusirnya dari rumah. Mereka tidak makan, tidak minum, dan tidak berkumpul dengannya di rumah. Lalu Rasulullah shallallahu 'alaihi wasallam ditanya tentang hal tersebut, maka Allah Subhanahu wa Ta'ala menurunkan ayat (yang artinya): \"Dan mereka bertanya kepadamu tentang haidl. Katakanlah, 'Haidl itu adalah kotoran, oleh sebab itu hendaklah kamu menjauhkan diri dari wanita di waktu haidl... sampai akhir ayat'.\" (QS. Albaqarah 222), Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergaulilah mereka di rumah, dan lakukanlah segala sesuatu selain bersetubuh\". Lalu orang-orang Yahudi berkata; Orang ini (Muhammad) tidak meninggalkan sesuatu dari perkara kita kecuali dia menyelisihi kita dalam perkara itu. Lalu Usaid bin Hudlair dan Abbad bin Bisyr datang kepada Nabi shallallahu 'alaihi wasallam, keduanya berkata; Wahai Rasulullah, sesungguhnya orang-orang Yahudi berkata begini dan begini. Apakah kita tidak menggauli mereka saja dalam masa haidl? Maka raut muka Rasulullah shallallahu 'alaihi wasallam berubah, sehingga kami menyangka bahwa beliau marah kepada keduanya, lalu mereka berdua keluar. Setelah itu datang hadiah berupa susu kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau memerintahkan untuk memanggil kembali keduanya, lalu keduanya diberi minum. Karena itu kami tahu bahwa beliau tidak memarahi keduanya. "},{"p":"Abu Dawud","n":414,"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ مُرَّةَ سَمِعْتُ ابْنَ أَبِي لَيْلَى قَالَ أُحِيلَتْ الصَّلَاةُ ثَلَاثَةَ أَحْوَالٍ قَالَ وَحَدَّثَنَا أَصْحَابُنَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ أَعْجَبَنِي أَنْ تَكُونَ صَلَاةُ الْمُسْلِمِينَ أَوْ قَالَ الْمُؤْمِنِينَ وَاحِدَةً حَتَّى لَقَدْ هَمَمْتُ أَنْ أَبُثَّ رِجَالًا فِي الدُّورِ يُنَادُونَ النَّاسَ بِحِينِ الصَّلَاةِ وَحَتَّى هَمَمْتُ أَنْ آمُرَ رِجَالًا يَقُومُونَ عَلَى الْآطَامِ يُنَادُونَ الْمُسْلِمِينَ بِحِينِ الصَّلَاةِ حَتَّى نَقَسُوا أَوْ كَادُوا أَنْ يَنْقُسُوا قَالَ فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَمَّا رَجَعْتُ لِمَا رَأَيْتُ مِنْ اهْتِمَامِكَ رَأَيْتُ رَجُلًا كَأَنَّ عَلَيْهِ ثَوْبَيْنِ أَخْضَرَيْنِ فَقَامَ عَلَى الْمَسْجِدِ فَأَذَّنَ ثُمَّ قَعَدَ قَعْدَةً ثُمَّ قَامَ فَقَالَ مِثْلَهَا إِلَّا أَنَّهُ يَقُولُ قَدْ قَامَتْ الصَّلَاةُ وَلَوْلَا أَنْ يَقُولَ النَّاسُ قَالَ ابْنُ الْمُثَنَّى أَنْ تَقُولُوا لَقُلْتُ إِنِّي كُنْتُ يَقْظَانَ غَيْرَ نَائِمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ ابْنُ الْمُثَنَّى لَقَدْ أَرَاكَ اللَّهُ عَزَّ وَجَلَّ خَيْرًا وَلَمْ يَقُلْ عَمْرٌو لَقَدْ أَرَاكَ اللَّهُ خَيْرًا فَمُرْ بِلَالًا فَلْيُؤَذِّنْ قَالَ فَقَالَ عُمَرُ أَمَا إِنِّي قَدْ رَأَيْتُ مِثْلَ الَّذِي رَأَى وَلَكِنِّي لَمَّا سُبِقْتُ اسْتَحْيَيْتُ قَالَ وَحَدَّثَنَا أَصْحَابُنَا قَالَ وَكَانَ الرَّجُلُ إِذَا جَاءَ يَسْأَلُ فَيُخْبَرُ بِمَا سُبِقَ مِنْ صَلَاتِهِ وَإِنَّهُمْ قَامُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَيْنِ قَائِمٍ وَرَاكِعٍ وَقَاعِدٍ وَمُصَلٍّ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ ابْنُ الْمُثَنَّى قَالَ عَمْرٌو وَحَدَّثَنِي بِهَا حُصَيْنٌ عَنْ ابْنِ أَبِي لَيْلَى حَتَّى جَاءَ مُعَاذٌ قَالَ شُعْبَةُ وَقَدْ سَمِعْتُهَا مِنْ حُصَيْنٍ فَقَالَ لَا أَرَاهُ عَلَى حَالٍ إِلَى قَوْلِهِ كَذَلِكَ فَافْعَلُوا قَالَ أَبُو دَاوُد ثُمَّ رَجَعْتُ إِلَى حَدِيثِ عَمْرِو بْنِ مَرْزُوقٍ قَالَ فَجَاءَ مُعَاذٌ فَأَشَارُوا إِلَيْهِ قَالَ شُعْبَةُ وَهَذِهِ سَمِعْتُهَا مِنْ حُصَيْنٍ قَالَ فَقَالَ مُعَاذٌ لَا أَرَاهُ عَلَى حَالٍ إِلَّا كُنْتُ عَلَيْهَا قَالَ فَقَالَ إِنَّ مُعَاذًا قَدْ سَنَّ لَكُمْ سُنَّةً كَذَلِكَ فَافْعَلُوا قَالَ و حَدَّثَنَا أَصْحَابُنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَدِمَ الْمَدِينَةَ أَمَرَهُمْ بِصِيَامِ ثَلَاثَةِ أَيَّامٍ ثُمَّ أُنْزِلَ رَمَضَانُ وَكَانُوا قَوْمًا لَمْ يَتَعَوَّدُوا الصِّيَامَ وَكَانَ الصِّيَامُ عَلَيْهِمْ شَدِيدًا فَكَانَ مَنْ لَمْ يَصُمْ أَطْعَمَ مِسْكِينًا فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَمَنْ شَهِدَ مِنْكُمْ الشَّهْرَ فَلْيَصُمْهُ }فَكَانَتْ الرُّخْصَةُ لِلْمَرِيضِ وَالْمُسَافِرِ فَأُمِرُوا بِالصِّيَامِ قَالَ و حَدَّثَنَا أَصْحَابُنَا قَالَ وَكَانَ الرَّجُلُ إِذَا أَفْطَرَ فَنَامَ قَبْلَ أَنْ يَأْكُلَ لَمْ يَأْكُلْ حَتَّى يُصْبِحَ قَالَ فَجَاءَ عُمَرُ بْنُ الْخَطَّابِ فَأَرَادَ امْرَأَتَهُ فَقَالَتْ إِنِّي قَدْ نِمْتُ فَظَنَّ أَنَّهَا تَعْتَلُّ فَأَتَاهَا فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَأَرَادَ الطَّعَامَ فَقَالُوا حَتَّى نُسَخِّنَ لَكَ شَيْئًا فَنَامَ فَلَمَّا أَصْبَحُوا أُنْزِلَتْ عَلَيْهِ هَذِهِ الْآيَةُ{ أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ }","trj":"Telah menceritakan kepada kami [Amru bin Marzuq] telah mengabarkan kepada kami [Syu'bah] dari [Amru bin Murrah] dia berkata; Saya telah mendengar [Ibnu Abi Laila] -dari jalur lainnya- Dan telah menceritakan kepada kami [Ibnu Al-Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Amru bin Murrah] saya telah mendengar [Ibnu Abi Laila] berkata; Pelaksanaan shalat itu telah mengalami tiga kali perubahan. Dia berkata; Telah menceritakan kepada kami [Sahabat sahabat kami], bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh saya sangat senang, sekiranya pelaksanaan shalat kaum Muslimin atau Mukminin dapat dijadikan satu (Jama'ah), sehingga saya mempunyai keinginan yang besar untuk menyebarkan orang orang ke kampung-kampung menyerukan waktu shalat kepada orang banyak. Dan saya mempunyai keinginan besar untuk memerintahkan beberapa orang berdiri di atas bangunan bangunan tinggi menyerukan waktu shalat kepada kaum Muslimin, sehingga mereka memukul atau hampir saja memukul kentongan.\" Dia berkata; Maka datang seorang laki laki dari kaum Anshar, lalu berkata; Wahai Rasulullah, sesungguhnya ketika saya pulang, karena sedemikian besar perhatianku terhadap perhatianmu (tentang cara pelaksanaan shalat), saya melihat seorang laki laki seakan akan memakai dua kain hijau. Lalu orang tersebut berdiri di atas masjid dan mengumandangkan adzan. Kemudian dia duduk sebentar, lalu berdiri lagi mengucapkan yang diucapkan sebelumnya, hanya saja dia mengucapkan (untuk yang kedua kalinya) Qad qaamatis shalaah (sholat telah di kerjakan), seandianya bukan karena takut nanti orang-orang akan mengatakan (saya berdusta), Ibnu Al-Mutsanna menyebutkan; seandainya bukan karena takut nanti kalian akan mengatakan (saya berdusta), tentu saya mengatakan bahwa sungguh saya ketika itu dalam keadaan terjaga, tidak tidur. Maka Rasulullah shallallahu 'alaihi wasallam bersabda, -Ibnu Al-Mutsanna menyebutkan; beliau bersabda: - \"Sungguh Allah telah memperlihatkan kepadamu suatu kebaikan -Sedangkan Amru tidak menyebutkan sabda beliau: Allah telah memperlihatkan kepadamu suatu kebaikan-, maka suruhlah Bilal untuk mengumandangkan adzan itu. Katanya; Lalu Umar berkata; Sungguh saya telah bermimpi seperti yang diimpikannya, tetapi karena saya didahului (untuk melaporkan kepada Rasulullah), maka saya merasa malu. Dan telah menceritakan kepada kami para sahabat kami; Biasanya seseorang jika dia datang (terlambat), bertanya kepada sebagian jama'ah itu, maka beritahukan kepadanya raka'at yang telah lewat (tertinggal). Sedangkan waktu itu, jama'ah yang bersama Rasulullah, ada yang berdiri, ada yang ruku, ada yang duduk, dan ada pula yang shalat bersama Rasulullah. Berkata [Ibnu Al-Mutssanna] berkata [Amru] telah menceritakan kepadaku [Hushain] dari [Ibnu Abi Laila] hingga datang Mu'adz. Berkata [Syu'bah] saya telah mendengarnya dari [Hushain], lalu perawi berkata; Saya tidak melihatnya pada keadaan… hingga ucapan: Demikian, maka lakukanlah itu. Abu Dawud berkata; Kemudian saya kembali pada hadits Amru bin Marzuq dia berkata; Mu'adz datang, kemudian mereka mengisyaratkan kepadanya. Syu'bah berkata; Ini saya dengar dari Hushain, dia berkata; Mu'adz berkata; Saya tidak melihatnya dalam satu kedaan melainkan saya padanya. Mu'adz berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Mu'adz telah menunjukkan satu sunnah kepada kalian, maka lakukanlah yang demikian.\" Dia Ibnu Abi Lailah berkata; Sahabat-sahabat kami telah menceritakan kepada kami, bahwasanya ketika Rasulullah shallallahu 'alaihi wasallam datang ke Madinah, beliau memerintahkan berpuasa tiga hari (tiap bulan), lalu turun perintah puasa pada bulan Ramadhan, sedangkan mereka adalah kaum yang tidak terbiasa berpuasa, sehingga puasa terasa amat berat bagi mereka. Maka mereka yang tidak berpuasa memberi makan orang miskin. Lalu turunlah ayat ini (yang artinya): (Karena itu, barangsiapa di antara kamu hadir (di negeri tempat tinggalnya) pada bulan itu, maka hendaklah dia berpuasa pada bulan itu). (Al-Baqarah: 185). Di dalam ayat ini disebutkan bahwa keringanan itu untuk orang sakit dan musafir. Karena itu, mereka diwajibkan berpuasa. Kata Ibnu Abi Lahi'ah; para sahabat kami telah menceritakan kepada kami, katanya; Kebiasaan saat itu, apabila seseorang memasuki waktu berbuka, lalu tidur sebelum makan, maka dia tidak makan malam itu sampai pagi. Dia berkata; Lalu Umar bin Khaththab datang kepada istrinya hendak mengumpulinya, namun istrinya berkata; Sesungguhnya saya telah tidur sebelum makan (berbuka), namun Umar menyangka bahwa istrinya itu hanya beralasan untuk menghindar darinya, karena itu Umar tetap mengumpulinya. Kemudian datang pula seorang laki laki yang berpuasa dari golongan Anshar, lalu dia hendak makan (berbuka), maka keluarganya berkata; Tunggu, kami akan menghangatkan makanan untukmu, Ialu laki laki itu tidur. Maka ketika pagi harinya, turunlah ayat kepada beliau shallallahu 'alaihi wasallam tentang peristiwa ini, ayat tersebut (artinya): \"Dihalalkan bagi kamu pada malam puasa mengumpuli istri istri kamu\". (QS. Albaqarah 187). "},{"p":"Abu Dawud","n":658,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو وَسَمِعَهُ مِنْ جَابِرٍ قَالَكَانَ مُعَاذٌ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَرْجِعُ فَيَؤُمُّنَا قَالَ مَرَّةً ثُمَّ يَرْجِعُ فَيُصَلِّي بِقَوْمِهِ فَأَخَّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً الصَّلَاةَ وَقَالَ مَرَّةً الْعِشَاءَ فَصَلَّى مُعَاذٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَاءَ يَؤُمُّ قَوْمَهُ فَقَرَأَ الْبَقَرَةَ فَاعْتَزَلَ رَجُلٌ مِنْ الْقَوْمِ فَصَلَّى فَقِيلَ نَافَقْتَ يَا فُلَانُ فَقَالَ مَا نَافَقْتُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ مُعَاذًا يُصَلِّي مَعَكَ ثُمَّ يَرْجِعُ فَيَؤُمُّنَا يَا رَسُولَ اللَّهِ وَإِنَّمَا نَحْنُ أَصْحَابُ نَوَاضِحَ وَنَعْمَلُ بِأَيْدِينَا وَإِنَّهُ جَاءَ يَؤُمُّنَا فَقَرَأَ بِسُورَةِ الْبَقَرَةِ فَقَالَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ أَفَتَّانٌ أَنْتَ اقْرَأْ بِكَذَا اقْرَأْ بِكَذَا قَالَ أَبُو الزُّبَيْرِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَاللَّيْلِ إِذَا يَغْشَىفَذَكَرْنَا لِعَمْرٍو فَقَالَ أُرَاهُ قَدْ ذَكَرَهُ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا طَالِبُ بْنُ حَبِيبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ جَابِرٍ يُحَدِّثُ عَنْ حَزْمِ بْنِ أُبَيِّ بْنِ كَعْبٍ أَنَّهُ أَتَى مُعَاذَ بْنَ جَبَلٍ وَهُوَ يُصَلِّي بِقَوْمٍ صَلَاةَ الْمَغْرِبِ فِي هَذَا الْخَبَرِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ لَا تَكُنْ فَتَّانًا فَإِنَّهُ يُصَلِّي وَرَاءَكَ الْكَبِيرُ وَالضَّعِيفُ وَذُو الْحَاجَةِ وَالْمُسَافِرُ","trj":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Sufyan] dari ['Amru] dan dia mendengarnya dari [Jabir] dia berkata; \"Mu'adz biasa shalat bersama Nabi shallallahu 'alaihi wasallam, kemudian dia kembali dan menjadi imam (shalat) bagi kami' -di lain kali Jabir mengatakan; kemudian dia kembali dan menjadi imam (shalat) bagi kaumnya-, pada suatu malam, Nabi shallallahu 'alaihi wasallam mengakhirkan shalat -di lain kali Jabir mengatakan; shalat Isya'- Mu'adz mengerjakan shalat bersama Nabi shallallahu 'alaihi wasallam, lalu kembali (ke kaumnya) menjadi imam (shalat) bagi kaumnya dengan membaca surat Al Baqarah, (karena panjangnya) maka salah seorang laki-laki memisahkan diri dari Jama'ah dan mengerjakan shalat sendirian, hingga di katakan kepadanya; \"kamu telah berbuat nifak wahai fulan.\" Laki-laki itu menimpali; \"aku tidak munafik.\" Lantas laki-laki itu pergi menghadap Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Sesungguhnya Mu'adz biasa mengerjakan shalat bersama anda, kemudian ia kembali (ke kaumnya) dan menjadi imam (shalat) bagi kami, wahai Rasulullah, kami hanya pemilik unta pengangkut air dan kami harus bekerja keras, sesungguhnya dia datang mengimami kami dengan membaca surat Al Baqarah.\" Maka beliau bersabda: \"Wahai Mu'adz, apakah kamu hendak menyebarkan fitnah, apakah kamu hendak menyebarkan fitnah, bacalah surat ini, bacalah surat ini.\" Abu Zubair mengatakan; \"(cukup) dengan membaca 'sabbihisma rabbikal a'la dan wallaili idzaa yaghsyaa.\" Kemudian aku sebutkan perkara itu kepada 'amru, maka dia berkata; \"Aku telah melihat Jabir telah menyebutkan hadits tersebut.\" Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Thalib bin Habib] telah menceritakan kepada kami [Abdurrahman bin Jabir] dia menceritakan dari [Hazm bin Ubay bin Ka'b] bahwa dia menemui Mu'adz bin Jabal yang sedang mengerjakan shalat maghrib (menjadi imam) bersama kaumnya…\" dalam hadits ini perawi mengatakan; \"Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Mu'adz, janganlah kamu menjadi penyebar fitnah, karena yang mengerjakan shalat di belakangmu terdapat orang tua, orang yang lemah, orang yang memiliki keperluan dan musafir.\" "},{"p":"Abu Dawud","n":726,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ عَاصِمِ بْنِ حُمَيْدٍ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَقُمْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَقَامَ فَقَرَأَ سُورَةَ الْبَقَرَةِ لَا يَمُرُّ بِآيَةِ رَحْمَةٍ إِلَّا وَقَفَ فَسَأَلَ وَلَا يَمُرُّ بِآيَةِ عَذَابٍ إِلَّا وَقَفَ فَتَعَوَّذَ قَالَ ثُمَّ رَكَعَ بِقَدْرِ قِيَامِهِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ سَجَدَ بِقَدْرِ قِيَامِهِ ثُمَّ قَالَ فِي سُجُودِهِ مِثْلَ ذَلِكَ ثُمَّ قَامَ فَقَرَأَ بِآلِ عِمْرَانَ ثُمَّ قَرَأَ سُورَةً سُورَةً","trj":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari ['Amru bin Qais] dari ['Ashim bin Humaid] dari ['Auf bin Malik Al Asyja'i] dia berkata; \"Di suatu malam, aku mengerjakan shalat bersama Rasulullah shallallahu 'alaihi wasallam, beliau kemudian berdiri dan membaca surat Al Baqarah, tidaklah beliau melewati ayat tentang rahmat, pasti beliau berhenti dan memohon kepada-Nya, dan tidaklah melewati ayat tentang adzab, melainkan beliau berhenti dan meminta perlindungan darinya.\" katanya melanjutkan; \"Kemudian beliau ruku' yang lamanya seperti beliau berdiri, dalam ruku'nya beliau mengucapkan: \"subahaana dzil jabaruuti wal malakuuti wal kibriyaa`i wal 'azhamati (Maha suci dzat yang memiliki sifat kekuasaan, kerajaan, kebesaran dan keagungan).\" Kemudian beliau sujud yang lamanya seperti beliau berdiri, dalam sujudnya beliau mengucapkan seperti itu juga, sesudah itu beliau berdiri, lalu membaca surat Ali Imran, kemudian membaca surat demi surat.\""},{"p":"Abu Dawud","n":727,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَعَلِيُّ بْنُ الْجَعْدِ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي حَمْزَةَ مَوْلَى الْأَنْصَارِ عَنْ رَجُلٍ مِنْ بَنِي عَبْسٍ عَنْ حُذَيْفَةَأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ فَكَانَ يَقُولُ اللَّهُ أَكْبَرُ ثَلَاثًا ذُو الْمَلَكُوتِ وَالْجَبَرُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ اسْتَفْتَحَ فَقَرَأَ الْبَقَرَةَ ثُمَّ رَكَعَ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ وَكَانَ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ سُبْحَانَ رَبِّيَ الْعَظِيمِ ثُمَّ رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَكَانَ قِيَامُهُ نَحْوًا مِنْ رُكُوعِهِ يَقُولُ لِرَبِّيَ الْحَمْدُ ثُمَّ سَجَدَ فَكَانَ سُجُودُهُ نَحْوًا مِنْ قِيَامِهِ فَكَانَ يَقُولُ فِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى ثُمَّ رَفَعَ رَأْسَهُ مِنْ السُّجُودِ وَكَانَ يَقْعُدُ فِيمَا بَيْنَ السَّجْدَتَيْنِ نَحْوًا مِنْ سُجُودِهِ وَكَانَ يَقُولُ رَبِّ اغْفِرْ لِي رَبِّ اغْفِرْ لِي فَصَلَّى أَرْبَعَ رَكَعَاتٍ فَقَرَأَ فِيهِنَّ الْبَقَرَةَ وَآلَ عِمْرَانَ وَالنِّسَاءَ وَالْمَائِدَةَ أَوْ الْأَنْعَامَ شَكَّ شُعْبَةُ","trj":"Telah menceritakan kepada kami [Abu Walid Ath Thayalisi] dan [Ali bin Al Ja'd] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Abu Hamzah bekas budak Al Anshari] dari [seorang laki-laki dari Bani 'Absi] dari [Hudzaifah] bahwa dia melihat Rasulullah shallallahu 'alaihi wasallam shalat malam, dalam shalatnya beliau mengucapkan; \"Allahu Akbar\" tiga kali dzul malakuuti wal Jabaruuri wal kibriyaa`i wal 'adzamati (Maha suci dzat yang memiliki kerajaan, kekuasaan, kebesaran dan keagungan).\" Kemudian beliau membaca do'a iftitah, lalu membaca surat Al Baqarah, kemudian beliau ruku, lama beliau ruku' hampir sama ketika beliau berdiri, dalam ruku'nya beliau mengucapkan; \"Subhaana rabbiyal 'azhiimi, Subhaana rabbiyal 'azhiimi (Maha suci Rabbku yang Maha Agung, Maha suci Rabbku yang Maha Agung).\" Kemudian beliau mengangkat kepalanya dari ruku', sedangkan lamanya beliau berdiri (i'tidal) seperti ketika beliau ruku', beliau mengucapkan; \"Lirabbiyal hamdu (Bagi rabbku segala puji-pujian).\" Kemudian beliau sujud, sedangkan lamanya beliau sujud seperti ketika beliau berdiri, dalam sujudnya beliau mengucapkan; \"Subhaana rabbiyal a'la (Maha suci Rabbku yang Maha tinggi).\" Kemudian beliau mengangkat kepalanya dari sujud, lama beliau duduk di antara dua sujud seperti ketika beliau sujud, dan dalam duduk di antara dua sujudnya beliau mengucapkan: \"Rabbighfirlii, Rabbighfirlii\" kemudian beliau shalat empat raka'at, dalam shalatnya itu beliau membaca surat Al Baqarah, Ali Imran, An Nisa', Al Maidah atau Al An'am -Syu'bah ragu (dalam lafadznya).\""},{"p":"Abu Dawud","n":799,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ الْحَارِثِ بْنِ شُبَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكَانَ أَحَدُنَا يُكَلِّمُ الرَّجُلَ إِلَى جَنْبِهِ فِي الصَّلَاةِ فَنَزَلَتْ{ وَقُومُوا لِلَّهِ قَانِتِينَ }فَأُمِرْنَا بِالسُّكُوتِ وَنُهِينَا عَنْ الْكَلَامِ","trj":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Isma'il bin Abu Khalid] dari [Al Harits bin Syubail] dari [Abu 'Amru As Syaibani] dari [Zaid bin Arqam] dia berkata; \"Salah seorang dari kami pernah mengajak bicara kepada orang yang ada di sampingnya ketika shalat, lalu turunlah ayat; \"WA QUUMUU LILLAAHI QAANITIIN (berdirilah karena Allah (dalam shalatmu) dengan khusyu') QS Al Baqarah; 238. maka kami di perintahkan untuk diam dan di larang untuk berbicara.\""},{"p":"Abu Dawud","n":868,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ وَحُمَيْدٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ كَانُوا يُصَلُّونَ نَحْوَ بَيْتِ الْمَقْدِسِ فَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ وَحَيْثُ مَا كُنْتُمْ فَوَلُّوا وُجُوهَكُمْ شَطْرَهُ }فَمَرَّ رَجُلٌ مِنْ بَنِي سَلَمَةَ فَنَادَاهُمْ وَهُمْ رُكُوعٌ فِي صَلَاةِ الْفَجْرِ نَحْوَ بَيْتِ الْمَقْدِسِ أَلَا إِنَّ الْقِبْلَةَ قَدْ حُوِّلَتْ إِلَى الْكَعْبَةِ مَرَّتَيْنِ فَمَالُوا كَمَا هُمْ رُكُوعٌ إِلَى الْكَعْبَةِ","trj":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Tsabit] dan [Humaid] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam dan para sahabatnya shalat menghadap ke arah Baitul Maqdis, ketika turun ayat; \"Palingkanlah mukamu ke arah Masjidil Haram. dan dimana saja kamu berada, palingkanlah mukamu ke arahnya.\" (QS Al Baqarah; 144), lalu seorang laki-laki dari Bani Salamah lewat dan berseru kepada kaumnya ketika mereka sedang ruku' dalam shalat dengan menghadap Baitul Maqdis; \"Ketahuilah, bahwa kiblat telah di alihkan ke Ka'bah -ia berseru dua kali- akhirnya mereka beralih ke Ka'bah dalam posisi ruku'.\""},{"p":"Abu Dawud","n":989,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ حَدَّثَنَا عَمِّي حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي هِشَامُ بْنُ عُرْوَةَ وَعَبْدُ اللَّهِ بْنُ أَبِي سَلَمَةَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ كُلُّهُمْ قَدْ حَدَّثَنِي عَنْ عُرْوَةَ عَنْ عَائِش��ةَ قَالَتْكُسِفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ فَقَامَ فَحَزَرْتُ قِرَاءَتَهُ فَرَأَيْتُ أَنَّهُ قَرَأَ بِسُورَةِ الْبَقَرَةِ وَسَاقَ الْحَدِيثَ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَأَطَالَ الْقِرَاءَةَ فَحَزَرْتُ قِرَاءَتَهُ أَنَّهُ قَرَأَ بِسُورَةِ آلِ عِمْرَانَ","trj":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'd] telah menceritakan kepada kami [pamanku] telah menceritakan kepada kami [ayahku] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Hisyam bin 'Urwah] dan [Abdullah bin Abu Salamah] dari [Sulaiman bin Yasar], semuanya telah menceritakan kepadaku, dari ['Urwah] dari [Aisyah] dia berkata; \"Terjadi gerhana Matahari pada masa Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam keluar untuk mengerjakan shalat bersama orang-orang, setelah itu beliau berdiri. Maka aku memperkirakan bacaan beliau, bahwa beliau membaca surat Al Baqarah …\" kemudian dia melanjutkan hadits tersebut -\"lalu beliau sujud dua kali, kemudian beliau berdiri dan memanjangkan bacaannya, maka aku memperkirakan bacaan beliau, bahwa beliau membaca surat Ali Imran.\""},{"p":"Abu Dawud","n":991,"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَخُسِفَتْ الشَّمْسُ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَامَ قِيَامًا طَوِيلًا بِنَحْوٍ مِنْ سُورَةِ الْبَقَرَةِ ثُمَّ رَكَعَ وَسَاقَ الْحَدِيثَ","trj":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Ibnu Abbas] dia berkata; \"Telah terjadi gerhana Matahari, lalu Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat bersama orang-orang, beliau berdiri lama (dalam shalat) kira-kira membaca surat Al Baqarah, kemudian beliau ruku'…\" kemudian (perawi) melanjutkan hadits tersebut.\""},{"p":"Abu Dawud","n":1053,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ كَثِيرًا مِمَّا كَانَ يَقْرَأُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَكْعَتَيْ الْفَجْرِ بِ{ آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }هَذِهِ الْآيَةُ قَالَ هَذِهِ فِي الرَّكْعَةِ الْأُولَى وَفِي الرَّكْعَةِ الْآخِرَةِ بِ{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Utsman bin Hakim] telah menceritakan kepadaku [Sa'id bin Yasar] dari [Abdullah bin Abbas] bahwa kebanyakan yang di baca Rasulullah shallallahu 'alaihi wasallam dalam dua raka'at fajar adalah \"Kami beriman kepada Allah dan apa yang diturunkan kepada kami\" (QS Al Baqarah; 136). Kata Ibnu Abbas; \"ayat ini di baca beliau di raka'at pertama, sedangkan di raka'at terakhir beliau membaca \"……kami beriman kepada Allah; dan saksikanlah bahwa Sesungguhnya kami adalah orang-orang yang berserah diri.\" (QS Ali Imran; 52). "},{"p":"Abu Dawud","n":1054,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عُثْمَانَ بْنِ عُمَرَ يَعْنِي ابْنَ مُوسَى عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ{ قُلْ آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ عَلَيْنَا }فِي الرَّكْعَةِ الْأُولَى وَفِي الرَّكْعَةِ الْأُخْرَى بِهَذِهِ الْآيَةِ{ رَبَّنَا آمَنَّا بِمَا أَنْزَلْتَ وَاتَّبَعْنَا الرَّسُولَ فَاكْتُبْنَا مَعَ الشَّاهِدِينَ }أَوْ{ إِنَّا أَرْسَلْنَاكَ بِالْحَقِّ بَشِيرًا وَنَذِيرًا وَلَا تُسْأَلُ عَنْ أَصْحَابِ الْجَحِيمِ }شَكَّ الدَّارَوَرْدِيُّ","trj":"Telah menceritakan kepada kami [Muhammad bin As Shabbah bin Sufyan] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Utsman bin Umar yaitu Ibnu Musa] dari [Abu Al Ghaits] dari [Abu Hurairah] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam membaca dalam dua raka'at fajar dengan; \"Katakanlah: \"Kami beriman kepada Allah dan kepada apa yang diturunkan kepada kami…\" QS Ali Imran; 84, ayat ini beliau baca di raka'at pertama, sedangkan di raka'at kedua, beliau membaca dengan ayat ini; \"Ya Tuhan kami, kami Telah beriman kepada apa yang Telah Engkau turunkan dan Telah kami ikuti rasul, Karena itu masukanlah kami ke dalam golongan orang-orang yang menjadi saksi (tentang keesaan Allah) \" (QS Ali Imran; 53) atau membaca; \"Sesungguhnya kami Telah mengutusmu (Muhammad) dengan kebenaran; sebagai pembawa berita gembira dan pemberi peringatan, dan kamu tidak akan diminta (pertanggungan jawab) tentang penghuni-penghuni neraka Jahannam.\" (QS Al Baqarah; 119) -Ad Darawardi ragu mengenai redaksi hadits ini-.\""},{"p":"Abu Dawud","n":1160,"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ أَخْبَرَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَقَالَ سَأَلْتُ أَبَا مَسْعُودٍ وَهُوَ يَطُوفُ بِالْبَيْتِ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ الْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","trj":"Telah menceritakan kepada kami [Hafsh bin Umar] telah mengabarkan kepada kami [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] dia berkata; aku pernah bertanya kepada [Abu Mas'ud] ketika dia sedang Thawaf di Ka'bah, dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca dua ayat dari akhir surat Al Baqarah pada malam harinya, maka dianggap cukup.\" "},{"p":"Abu Dawud","n":1620,"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ الْمَعْنَى قَالَا حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ ابْنِ مَسْعُودٍ قَالَلَمَّا انْتَهَى إِلَى الْجَمْرَةِ الْكُبْرَى جَعَلَ الْبَيْتَ عَنْ يَسَارِهِ وَمِنًى عَنْ يَمِينِهِ وَرَمَى الْجَمْرَةَ بِسَبْعِ حَصَيَاتٍ وَقَالَ هَكَذَا رَمَى الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","trj":"Telah menceritakan kepada Kami [Hafsh bin Umar], serta [Muslim bin Ibrahim] secara makna. Mereka berkata; telah menceritakan kepada Kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Ibnu Mas'ud], ia berkata; tatkala beliau telah sampai pada jumrah kubra beliau menjadikan Ka'bar berada di sisi kirinya dan Mina di sisi kanannya, beliau melempar jumrah dengan tujuh kerikil. Ibnu Mas'ud berkata; demikianlah orang yang kepadanya diturunkan Surat Al Baqarah melempar. "},{"p":"Abu Dawud","n":1741,"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي حَازِمِ بْنِ دِينَارٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَتْهُ امْرَأَةٌ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي قَدْ وَهَبْتُ نَفْسِي لَكَ فَقَامَتْ قِيَامًا طَوِيلًا فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ زَوِّجْنِيهَا إِنْ لَمْ يَكُنْ لَكَ بِهَا حَاجَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ عِنْدَكَ مِنْ شَيْءٍ تُصْدِقُهَا إِيَّاهُ فَقَالَ مَا عِنْدِي إِلَّا إِزَارِي هَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ إِنْ أَعْطَيْتَهَا إِزَارَكَ جَلَسْتَ وَلَا إِزَارَ لَكَ فَالْتَمِسْ شَيْئًا قَالَ لَا أَجِدُ شَيْئًا قَالَ فَالْتَمِسْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَالْتَمَسَ فَلَمْ يَجِدْ شَيْئًا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلْ مَعَكَ مِنْ الْقُرْآنِ شَيْءٌ قَالَ نَعَمْ سُورَةُ كَذَا وَسُورَةُ كَذَا لِسُوَرٍ سَمَّاهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ زَوَّجْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِحَدَّثَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ حَدَّثَنِي أَبِي حَفْصُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ الْحَجَّاجِ بْنِ الْحَجَّاجِ الْبَاهِلِيِّ عَنْ عِسْلٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ أَبِي هُرَيْرَةَ نَحْوَ هَذِهِ الْقِصَّةِ لَمْ يَذْكُرْ الْإِزَارَ وَالْخَاتَمَ فَقَالَ مَا تَحْفَظُ مِنْ الْقُرْآنِ قَالَ سُورَةَ الْبَقَرَةِ أَوْ الَّتِي تَلِيهَا قَالَ فَقُمْ فَعَلِّمْهَا عِشْرِينَ آيَةً وَهِيَ امْرَأَتُكَ حَدَّثَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ مَكْحُولٍ نَحْوَ خَبَرِ سَهْلٍ قَالَ وَكَانَ مَكْحُولٌ يَقُولُ لَيْسَ ذَلِكَ لِأَحَدٍ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Abu Hazim bin Dinar] dari [Sahl bin Sa'd As Sa'idi] bahwa Rasulullah shallallahu 'alaihi wasallam didatangi oleh seorang wanita seraya berkata; wahai Rasulullah, aku menghibahkan diriku kepadamu. Kemudian wanita tersebut berdiri lama, lalu terdapat seorang laki-laki yang berdiri dan berkata; wahai Rasulullah, nikahkan aku dengannya apabila engkau tidak butuh kepadanya. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Apakah kamu memiliki sesuatu yang dapat kamu berikan kepadanya sebagai mahar?\" Orang tersebut berkata; aku tidak memiliki sesuatu kecuali sarungku ini. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu memberikan sarungmu, maka kamu akan telanjang dan kamu tidak memiliki sarung, carilah sesuatu!\" Orang tersebut berkata; aku tidak mendapatkan sesuatu. Beliau berkata: \"Carilah (yang lain) walaupun hanya sebuah cincin besi!\" Kemudian orang tersebut mencari dan tidak mendapatkan sesuatu pun. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Apakah engkau hafal sebagian dari Al Qur'an?\" Orang tersebut berkata; ya, surat ini dan surat ini. Ia menyebutkan surat yang telah ia hafal. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Aku telah menikahkanmu dengan apa yang engkau miliki (hafal) dari Al Qur'an.\" Telah menceritakan kepada kami [Ahmad bin Hafsh bin Abdullah], telah menceritakan kepadaku [Abu Hafsh bin Abdullah], telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Al Hajjaj bin Al Hajjaj Al Bahili] dari ['Asl] dari ['Atha` bin Abu Rabah] dari [Abu Hurairah] seperti kisah ini, namun ia tidak menyebutkan sarung dan cincin. Beliau berkata: \"Surat apakah yang engkau hafal dari Al Qur'an?\" Orang tersebut berkata; Surat Al Baqarah, atau surat yang setelahnya. Beliau berkata: \"Berdirilah dan ajarkanlah dua puluh ayat kepadanya! Ia adalah isterimu.\" Telah menceritakan kepada kami [Harun bin Zaid bin Abu Az Zarqa`], telah menceritakan kepada kami [ayahku], telah menceritakan kepada kami [Muhammad bin Rasyid] dari [Makhul] seperti hadits Sahl. Ia berkata; dan Makhul pernah berkata; hal tersebut bukan hal bagi seseorang setelah Rasulullah shallallahu 'alaihi wasallam. "},{"p":"Abu Dawud","n":2950,"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَتْ الْآيَاتُ الْأَوَاخِرُ مِنْ سُورَةِ الْبَقَرَةِ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهُنَّ عَلَيْنَا وَقَالَ حُرِّمَتْ التِّجَارَةُ فِي الْخَمْرِحَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ الْآيَاتُ الْأَوَاخِرُ فِي الرِّبَا","trj":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Adl Dluha] dari [Masruq] dari [Aisyah] ia berkata, \"Tatkala beberapa ayat terakhir Surat Al Baqarah turun Rasulullah shallallahu 'alaihi wasallam keluar dan membacakannya kepada kami. Beliau bersabda: \"Perdagangan arak telah diharamkan.\" Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dengan sanad dan maknanya, ia berkata, \"Yaitu ayat-ayat terakhir mengenai riba.\""},{"p":"Abu Dawud","n":3107,"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى الْخُتَّلِيُّ أَخْبَرَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرٍو عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ }الْآيَةَ قَالَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَكَانَ مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ يُنَادِي أَلَا لَا يَقْرَبَنَّ الصَّلَاةَ سَكْرَانُ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَهَلْ أَنْتُمْ مُنْتَهُونَ }قَالَ عُمَرُ انْتَهَيْنَا","trj":"Telah menceritakan kepada kami ['Abbad bin Musa Al Khuttali] telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Israil] dari [Abu Ishaq] dari ['Amru] dari [Umar bin Al Khathab] ia berkata, \"Tatkala telah turun pengharaman arak Umar berkata, \"Ya Allah, jelaskan kepada kami mengenai arak dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat dalam Surat Al Baqarah (219): '(Mereka bertanya kepadamu tentang khamer dan judi…) '. 'Ammar berkata, \"Kemudian Umar dipanggil dan dibacakan kepadanya ayat tersebut, ia berkata lagi, \"Ya Allah, jelaskan kepada kami mengenai khamer dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat pada Surat An Nisaa` (41): '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…..) ' Penyeru Rasulullah shallallahu 'alaihi wasallam apabila shalat telah ditegakkan maka ia berseru, 'ketahuilah bahwa tidak boleh orang yang mabuk mendekati shalat! ' Kemudian Umar dipanggil dan dibacakanlah ayat tersebut kepadanya, lalu ia berkata, \"Ya Allah jelaskanlah kepada kami mengenai khamer dengan penjelasan yang memuaskan!\" Maka turunlah ayat ini: '(….. apakah kalian akan berhenti?) ' (Qs. Al Maa`idah: 91) Umar berkata, \"Kami telah berhenti.\""},{"p":"Abu Dawud","n":3109,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيِّ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }وَ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ وَمَنَافِعُ لِلنَّاسِ }نَسَخَتْهُمَا الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا الْخَمْرُ وَالْمَيْسِرُ وَالْأَنْصَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepada kami [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia membaca: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…) ' (Qs. An Nisaa`: 41). Dan ayat: '(Mereka bertanya kepadamu tentang khamer dan judi. Katakanlah: \"Pada keduanya terdapat dosa yang besar dan beberapa manfaat bagi manusia.....) ' (Qs. Al Baqarah: 219), ia berkata, \"Kedua ayat tersebut dihapus dan digantikan oleh ayat yang terdapat dalam Surat Al Maaidah: 91: '(Sesungguhnya (meminum) khamar, berjudi, (berkorban untuk) berhala…) '. "},{"p":"Abu Dawud","n":3370,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ ح و حَدَّثَنَا نَصْرُ بْنُ عَاصِمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }","trj":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Hatim bin Isma'il]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Nashr bin 'Ashim] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ja'far bin Muhammad] dari [Ayahnya] dan [Jabir] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam membaca ayat: '(Dan jadikanlah sebahagian maqam Ibrahim tempat shalat) ' (Qs. Al Baqarah: 125). "},{"p":"Abu Dawud","n":3916,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا تَوَجَّهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْكَعْبَةِ قَالُوا يَا رَسُولَ اللَّهِ فَكَيْفَ الَّذِينَ مَاتُوا وَهُمْ يُصَلُّونَ إِلَى بَيْتِ الْمَقْدِسِ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ }","trj":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] dan [Utsman bin Abu Syaibah] secara makna, keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam (Shalat) menghadap ke arah Ka'bah orang-orang bertanya, \"Wahai Rasulullah, bagaimana dengan orang-orang yang telah meninggal, sementara mereka (dahulu) shalat menghadap ke arah Baitul Maqdis?\" Maka Allah Azza Wa Jalla kemudian menurunkan ayat: '(dan Allah tidak akan menyia-nyiakan imanmu) ' -Qs. Al Baqarah: 143-"},{"p":"Ahmad","n":151,"ar":"حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ مَرَّةً أَوْ مَرَّتَيْنِ فَلَمْ أَحْفَظْهُ عَنْ كَثِيرِ بْنِ عَبَّاسٍ قَالَكَانَ عَبَّاسٌ وَأَبُو سُفْيَانَ مَعَهُ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَخَطَبَهُمْ وَقَالَ الْآنَ حَمِيَ الْوَطِيسُ وَقَالَ نَادِ يَا أَصْحَابَ سُورَةِ الْبَقَرَةِ","trj":"Telah menceritakan kepada kami [Sufyan] berkata; saya mendengar [Az Zuhri] sekali atau dua kali, namun saya tidak dapat mengingatnya, dari [Katsir bin Abbas] berkata; Abbas dan Abu Sufyan bersama Nabi shallallahu 'alaihi wasallam, beliau berkhutbah di hadapan mereka: \"Sekarang peperangan sudah semakin sengit!\" lalu beliau bersabda (kepada Abbas dan Abu Sufyan): \"serulah; 'Wahai orang-orang yang kepadanya diturunkan surat Al Baqarah.\""},{"p":"Ahmad","n":1415,"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا شَرِيكٌ عَنْ عَاصِمٍ عَنِ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ عَلْقَمَةَ عَنْ أَبِي مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ الْآيَتَيْنِ مِنْ آخِرِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","trj":"Telah menceritakan kepada kami [Yahya bin Adam] Telah menceritakan kepada kami [Syarik] dari ['Ashim] dari [Musayyab bin Rafi'] dari ['Alqomah] dari [Abu Mas'ud] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang membaca dua ayat dari akhir surat Al Baqarah pada waktu malam maka itu telah cukup (untuk melindunginya dari kejahatan yang dibenci).\""},{"p":"Ahmad","n":1665,"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مُحَمَّدِ بْنِ مُهَاجِرٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْجُرَشِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ قَالَ سَمِعْتُ النَّوَّاسَ بْنَ سَمْعَانَ الْكِلَابِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُؤْتَى بِالْقُرْآنِ يَوْمَ الْقِيَامَةِ وَأَهْلِهِ الَّذِينَ كَانُوا يَعْمَلُونَ بِهِ تَقَدَّمُهُمْ سُورَةُ الْبَقَرَةِ وَآلِ عِمْرَانَ وَضَرَبَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَمْثَالٍ مَا نَسِيتُهُنَّ بَعْدُ قَالَ كَأَنَّهُمَا غَمَامَتَانِ أَوْ ظُلَّتَانِ أَوْ سَوْدَاوَانِ بَيْنَهُمَا شَرْقٌ كَأَنَّهُمَا فِرْقَانِ مِنْ طَيْرٍ صَوَافَّ يُحَاجَّانِ عَنْ صَاحِبِهِمَا","trj":"Telah menceritakan kepada kami [Yazid bin Abdu Rabbih] ia berkata, Telah menceritakan kepada kami [Al Walid bin Muslim] dari [Muhammad bin Muhajir] dari [Walid bin Abdurrahman Al Jurasyi] dari [Jubair bin Nufair] ia berkata, aku mendengar [Nawwas bin Sam'an Al Kilabi] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Qur`an akan didatangkan pada hari kiamat bersama ahlinya, yaitu mereka yang beramal dengannya. Dan yang akan didahulukan dari mereka adalah surat Al Baqarah dan Ali Imran.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan tiga permisalan terhadap keduanya, yang tidak pernah melupakannya setelah itu. Beliau mengatakan: \"Kedua surat itu seperti awan kelabu yang menaungi atau mendung yang di antara keduanya terdapat cahaya, keduanya laksana dua kelompok burung yang membentangkan sayapnya membela orang yang membacanya.\""},{"p":"Ahmad","n":1987,"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحُدَيْبِيَةِ وَنَحْنُ مُحْرِمُونَ وَقَدْ حَصَرَنَا الْمُشْرِكُونَ وَكَانَتْ لِي وَفْرَةٌ فَجَعَلَتْ الْهَوَامُّ تَسَّاقَطُ عَلَى وَجْهِي فَمَرَّ بِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُؤْذِيكَ هَوَامُّ رَأْسِكَ قُلْتُ نَعَمْ فَأَمَرَهُ أَنْ يَحْلِقَ قَالَ وَنَزَلَتْ هَذِهِ الْآيَةُ{ فَمَنْ كَانَ مِنْكُمْ مَرِيضًا أَوْ بِهِ أَذًى مِنْ رَأْسِهِ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }","trj":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Bisyr] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Ka'ab bin Ujrah] ia berkata, \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam di Hudaibiyah dalam keadaan telah memakai pakaian ihram, lalu orang-orang musyrik mengepung kami. Aku adalah seorang yang mempunyai rambut panjang (hingga ujung telinga), lalu ada binatang-binatang kecil (semacam kutu) yang jatuh ke mukaku. Dan ketika Nabi shallallahu 'alaihi wasallam lewat di tempatku, beliau lalu bertanya: \"Apakah binatang-binatang kecil itu melukai kepalamu?\" Aku menjawab, \"Benar.\" Maka beliau pun memerintahkan agar ia mencukur rambutnya. Kemudian turunlah ayat ini: '(jika ada di antaramu yang sakit atau ada gangguan di kepalanya (lalu ia bercukur), Maka wajiblah atasnya berfidyah, yaitu; berpuasa atau bersedekah atau berkorban) ' (Qs. Al Baqarah: 196)."},{"p":"Ahmad","n":1992,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ قَالَقَعَدْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ وَهُوَ فِي الْمَسْجِدِ فَسَأَلْتُهُ عَنْ هَذِهِ الْآيَةِ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ فَقَالَ كَعْبٌ نَزَلَتْ فِيَّ كَانَ بِي أَذًى مِنْ رَأْسِي فَحُمِلْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي فَقَالَ مَا كُنْتُ أَرَى أَنَّ الْجَهْدَ بَلَغَ بِكَ مَا أَرَى أَتَجِدُ شَاةً فَقُلْتُ لَا فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ صَوْمُ ثَلَاثَةِ أَيَّامٍ أَوْ إِطْعَامُ سِتَّةِ مَسَاكِينَ نِصْفَ صَاعِ طَعَامٍ لِكُلِّ مِسْكِينٍ قَالَ فَنَزَلَتْ فِيَّ خَاصَّةً وَهِيَ لَكُمْ عَامَّةًحَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَ��ُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَصْبَهَانِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَعْقِلٍ يَقُولُ قَعَدْتُ إِلَى كَعْبٍ فِي هَذَا الْمَسْجِدِ فَذَكَرَ مَعْنَاهُ حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَصْبَهَانِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَعْقِلٍ قَالَ قَعَدْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ فِي هَذَا الْمَسْجِدِ فَسَأَلْتُهُ عَنْ هَذِهِ الْآيَةِ فَذَكَرَ الْحَدِيثَ وَقَالَ أَطْعِمْ سِتَّةَ مَسَاكِينَ كُلَّ مِسْكِينٍ نِصْفَ صَاعٍ مِنْ طَعَامٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Ashbahani] dari [Abdullah bin Ma'qil] ia berkata, \"Saya duduk bersama [Ka'ab bin Ujrah] di dalam Masjid, lalu saya bertanya kepadanya tentang ayat ini: '(Maka wajiblah atasnya berfidyah, yaitu: berpuasa atau bersedekah atau berkorban…) '. (Qs. Al Baqarah: 196). Ka'ab kemudian memberi penjelasan, \"Ayat ini turun berkenaan dengan diriku. Saat itu kepalaku terserang penyakit, lalu saya dibawa menghadap Rasulullah shallallahu 'alaihi wasallam, sementara kutu-kutu telah bertebaran di wajahku. Maka beliau berkata: \"Saya lihat penyakitmu sudah demikian parah, namun saya tidak memiliki pendapat lain. Apakah kamu mempunyai seekor kambing?\" saya menjawab, \"Tidak.\" Maka turunlah ayat ini: '(Maka wajiblah atasnya berfidyah, yaitu: berpuasa atau bersedekah atau berkorban) '. Beliau lantas bersabda: \"(Silahkan kamu) berpuasa tiga hari atau memberi makan kepada enam orang miskin, yakni setengah sha' untuk setiap orangnya.\" Ka'ab berkata, \"Maka ayat ini turun berkenaan dengan diriku secara khusus, dan bersifat umum bagi kalian.\" Telah menceritakan kepada kami [Affan] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abdurrahman bin Al Ashbahani] ia berkata, saya mendengar [Abdullah bin Ma'qil] berkata, \"Saya duduk bersama [Ka'ab] di dalam Masjid ini…lalu ia menyebutkan makna hadits tersebut.\" Telah menceritakan kepada kami [Bahz] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abdurrahman bin Al Ashbahani] ia berkata, \"Saya mendengar [Abdullah bin Ma'qil] berkata, \"Saya pernah duduk bersama [Ka'ab bin Ujrah] di dalam masjid ini, lalu saya bertanya kepadanya tentang ayat ini…lalu ia menyebutkan makna hadits tersebut.\" Beliau bersabda: \"Berilah makan kepada enam orang Miskin. Setiap orang miskin adalah setengah sha' makanan.\""},{"p":"Ahmad","n":2431,"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ عَنِ الشَّعْبِيِّ أَخْبَرَنَا عَدِيُّ بْنُ حَاتِمٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }قَالَ عَمَدْتُ إِلَى عِقَالَيْنِ أَحَدُهُمَا أَسْوَدُ وَالْآخَرُ أَبْيَضُ فَجَعَلْتُهُمَا تَحْتَ وِسَادِي قَالَ ثُمَّ جَعَلْتُ أَنْظُرُ إِلَيْهِمَا فَلَا تُبِينُ لِي الْأَسْوَدَ مِنْ الْأَبْيَضِ وَلَا الْأَبْيَضَ مِنْ الْأَسْوَدِ فَلَمَّا أَصْبَحْتُ غَدَوْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِالَّذِي صَنَعْتُ فَقَالَ إِنْ كَانَ وِسَادُكَ إِذًا لَعَرِيضٌ إِنَّمَا ذَلِكَ بَيَاضُ النَّهَارِ مِنْ سَوَادِ اللَّيْلِ","trj":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Hushain] dari [Asy Sya'bi] telah mengabarkan kepada kami [Adi bin Hatim] ia berkata; Ketika ayat ini turun: \"Dan makan minumlah hingga terang bagimu benang putih dari benang hitam, yaitu fajar.\" (QS. Albaqarah 187), Saya pun pergi mengambil dua benang yang satu berwarna putih sedang yang satunya lagi berwarna hitam. Lalu saya meletakkan di bawah bantalku, kemudian saya mencoba melihatnya, namun bagiku tidak tampak jelas antara yang putih dan hitam atau pun sebaliknya. Pada pagi harinya, saya mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengabarkan hal apa yang telah saya perbuat. Maka beliau bersabda: \"Kalau begitu, bantalmu panjang sekali. Hanyasanya maksudnya adalah putihnya siang daripada kegelapan malam.\""},{"p":"Ahmad","n":2596,"ar":"حَدَّثَنَا عَارِمٌ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ عَنْ رَجُلٍ عَنْ أَبِيهِ عَنْ مَعْقِلِ بْنِ يَسَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَقَرَةُ سَنَامُ الْقُرْآنِ وَذُرْوَتُهُ نَزَلَ مَعَ كُلِّ آيَةٍ مِنْهَا ثَمَانُونَ مَلَكًا وَاسْتُخْرِجَتْ{ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }مِنْ تَحْتِ الْعَرْشِ فَوُصِلَتْ بِهَا أَوْ فَوُصِلَتْ بِسُورَةِ الْبَقَرَةِ وَيس قَلْبُ الْقُرْآنِ لَا يَقْرَؤُهَا رَجُلٌ يُرِيدُ اللَّهَ تَبَارَكَ وَتَعَالَى وَالدَّارَ الْآخِرَةَ إِلَّا غُفِرَ لَهُ وَاقْرَءُوهَا عَلَى مَوْتَاكُمْ","trj":"Telah menceritakan kepada kami ['Arim], telah menceritakan kepada kami [Mu'tamir] dari [Ayahnya] dari [Seseorang] dari Ayahnya dari [Ma'qil bin Yasar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Baqarah adalah Al Qur'an kedudukan yang tertinggi dan puncaknya. Delapan puluh Malaikat turun menyertai masing-masing ayatnya. Laa ilaaha illaahu wal hayyul qayyuum di bawah 'Arsy, lalu ia digabungkan dengannya, atau digabungkan dengan surat Al Baqarah. Sedangkan Yasin adalah hati Al Qur'an. Tidaklah seseorang membacanya, sedang ia mengharap (ridla) Allah Tabaraka wa Ta'ala dan akhirat, melainkan dosanya akan di ampuni. Bacakanlah surat tersebut terhadap orang-orang yang mati di antara kalian.\""},{"p":"Ahmad","n":2893,"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُعَلِيٌّ أَقْضَانَا وَأُبَيٌّ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ كَثِيرًا مِنْ لَحْنِ أُبَيٍّ وَأُبَيٌّ يَقُولُ سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدَعُهُ لِشَيْءٍ وَاللَّهُ تَبَارَكَ وَتَعَالَى يَقُولُ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }","trj":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \" [Umar] radliallahu 'anhu berkata, \"Ali adalah orang yang paling paham dengan hukum di antara kami dan Ubai adalah orang yang paling pandai dalam membaca Al-Qur'an di antara kami, sementara kami banyak meninggalkan qira`ah Ubay (dalam membaca Al-Qur'an). [Ubay] pernah berkata, \"Aku telah mendengar dari Rasulullah shallallahu 'alaihi wasallam, maka aku tidak akan meninggalkannya karena sesuatu. Allah Tabaraka Wa Ta'ala berfirman: '(Ayat mana saja yang kami nasakhkan, atau kami jadikan (manusia) lupa kepadanya, kami datangkan yang lebih baik daripadanya atau yang sebanding dengannya) ' (QS. Al Baqarah: 106)."},{"p":"Ahmad","n":2894,"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ حَدَّثَنِي حَبِيبٌ يَعْنِي ابْنَ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ قَالَ عُمَرُعَلِيٌّ أَقْضَانَا وَأُبَيٌّ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ مِنْ قَوْلِ أُبَيٍّ وَأُبَيٌّ يَقُولُ أَخَذْتُ مِنْ فَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدَعُهُ وَاللَّهُ يَقُولُ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا }","trj":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] telah menceritakan kepadaku [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu berkata, \" [Umar]? radliallahu 'anhu berkata, \"Ali adalah orang yang paling paham dengan hukum di antara kami dan Ubai adalah orang yang paling pandai dalam membaca Al-Qur'an di antara kami, sementara kami telah meninggalkan qira`ah (bacaan Al-Qur'an) Ubay. Dan [Ubay] berkata, \"Aku mengambilnya dari mulut Rasulullah shallallahu 'alaihi wasallam, maka aku tidak akan meninggalkanya karena sesuatu apapun, dan Allah Tabaraka Wa Ta'ala berfirman: '(Ayat mana saja yang kami nasakhkan, atau kami jadikan (manusia) lupa kepadanya..) ' (QS. Al Baqarah: 106)."},{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""},{"p":"Bukhari","n":115,"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَإِنَّ النَّاسَ يَقُولُونَ أَكْثَرَ أَبُو هُرَيْرَةَ وَلَوْلَا آيَتَانِ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُ حَدِيثًا ثُمَّ يَتْلُو{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى إِلَى قَوْلِهِ الرَّحِيمُ }إِنَّ إِخْوَانَنَا مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَإِنَّ إِخْوَانَنَا مِنْ الْأَنْصَارِ كَانَ يَشْغَلُهُمْ الْعَمَلُ فِي أَمْوَالِهِمْ وَإِنَّ أَبَا هُرَيْرَةَ كَانَ يَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشِبَعِ بَطْنِهِ وَيَحْضُرُ مَا لَا يَحْضُرُونَ وَيَحْفَظُ مَا لَا يَحْفَظُونَ","trj":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah] berkata, \"Sesungguhnya orang-orang mengatakan, \"Abu Hurairah adalah yang paling banyak (menyampaikan hadits dari Rasulullah shallallahu 'alaihi wasallam), kalau bukan karena dua ayat dalam Kitabullah aku tidak akan menyampaikannya.\" Lalu dia membaca ayat: '(Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa penjelasan dan petunjuk) ' ……hingga akhir ayat.. '(Allah Maha Penyayang) ' (Qs. Al Baqarah: 159-160). Sesungguhnya saudara-saudara kita dari kalangan Muhajirin, mereka disibukkan dengan perdagangan di pasar-pasar, dan saudara-saudara kita dari kalangan Anshar, mereka disibukkan dengan pekerjaan mereka dalam mengurus harta mereka. sementara Abu Hurairah selalu menyertai Rasulullah shallallahu 'alaihi wasallam dalam keadaan lapar, ia selalu hadir saat orang-orang tidak bosa hadir, dan ia dapat menghafal saat orang-orang tidak bisa menghafalnya.\""},{"p":"Bukhari","n":155,"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ أَنَّ عَطَاءَ بْنَ يَزِيدَ أَخْبَرَهُ أَنَّ حُمْرَانَ مَوْلَى عُثْمَانَ أَخْبَرَهُ أَنَّهُ رَأَى عُثْمَانَ بْنَ عَفَّانَدَعَا بِإِنَاءٍ فَأَفْرَغَ عَلَى كَفَّيْهِ ثَلَاثَ مِرَارٍ فَغَسَلَهُمَا ثُمَّ أَدْخَلَ يَمِينَهُ فِي الْإِنَاءِ فَمَضْمَضَ وَاسْتَنْشَقَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ ثَلَاثَ مِرَارٍ ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ رِجْلَيْهِ ثَلَاثَ مِرَارٍ إِلَى الْكَعْبَيْنِ ثُمَّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ نَحْوَ وُضُوئِي هَذَا ثُمَّ صَلَّى رَكْعَتَيْنِ لَا يُحَدِّثُ فِيهِمَا نَفْسَهُ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِوَعَنْ إِبْرَاهِيمَ قَالَ قَالَ صَالِحُ بْنُ كَيْسَانَ قَالَ ابْنُ شِهَابٍ وَلَكِنْ عُرْوَةُ يُحَدِّثُ عَنْ حُمْرَانَ فَلَمَّا تَوَضَّأَ عُثْمَانُ قَالَ أَلَا أُحَدِّثُكُمْ حَدِيثًا لَوْلَا آيَةٌ مَا حَدَّثْتُكُمُوهُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَتَوَضَّأُ رَجُلٌ يُحْسِنُ وُضُوءَهُ وَيُصَلِّي الصَّلَاةَ إِلَّا غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الصَّلَاةِ حَتَّى يُصَلِّيَهَا قَالَ عُرْوَةُ الْآيَةَ{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ }","trj":"Telah menceritakan kepada kami [Abdul 'Aziz bin 'Abdullah Al Uwaisy] berkata, telah menceritakan kepadaku [Ibrahim bin Sa'd] dari [Syihab] bahwa ['Atha' bin Yazid] mengabarkan kepadanya bahwa [Humran] mantan budan 'Utsman mengabarkan kepadanya, bahwa ia telah melihat ['Utsman bin 'Affan] minta untuk diambilkan bejana (berisi air). Lalu dia menuangkan pada telapak tangannya tiga kali lalu membasuh keduanya, lalu ia memasukkan tangan kanannya ke dalam bejana lalu berkumur-kumur dan memasukkan air ke dalam hidung, kemudian membasuh wajahnya tiga kali, kemudian membasuh kedua tangan hingga siku tiga kali, kemudian mengusap kepala, kemudian membasuh kedua kakinya tiga kali hingga kedua mata kaki. Setelah itu ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu seperti wudluku ini, kemudian dia shalat dua rakaat dan tidak berbicara antara keduanya, maka dosanya yang telah lalu akan diampuni.\" Dan dari [Ibrahim] berkata, [Shalih bin Kaisan] berkata, [Ibnu Syihab] berkata. Tetapi ['Urwah] menceritakan dari [Humran], \"Ketika ['Utsman] berwudlu, dia berkata, \"Maukah aku sampaikan kepada kalian sebuah hadits yang kalau bukan karena ada satu ayat tentu aku tidak akan menyampaikannya? Aku pernah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki berwudlu dengan membaguskan wudlunya kemudian mengerjakan shalat, kecuali akan diampuni (dosa) antara wudlunya dan shalatnya itu hingga selesai shalatnya.\" 'Urwah berkata, \"Ayat yang dimaksud adalah: '(Sesungguhnya orang-orang yang menyembunyikan apa yang telah kami turunkan…) ' (Qs. Al Baqarah: 159)."},{"p":"Bukhari","n":384,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ }فَتَوَجَّهَ نَحْوَ الْكَعْبَةِ وَقَالَ السُّفَهَاءُ مِنْ النَّاسِ وَهُمْ الْيَهُودُ{ مَا وَلَّاهُمْ عَنْ قِبْلَتِهِمْ الَّتِي كَانُوا عَلَيْهَا قُلْ لِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ يَهْدِي مَنْ يَشَاءُ إِلَى صِرَاطٍ مُسْتَقِيمٍ }فَصَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ ثُمَّ خَرَجَ بَعْدَ مَا صَلَّى فَمَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ فِي صَلَاةِ الْعَصْرِ نَحْوَ بَيْتِ الْمَقْدِسِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ تَوَجَّهَ نَحْوَ الْكَعْبَةِ فَتَحَرَّفَ الْقَوْمُ حَتَّى تَوَجَّهُوا نَحْوَ الْكَعْبَةِ","trj":"Telah menceritakan kepada kami ['Abdullah bin Raja'] berkata, telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Bara' bin 'Azib? radliallahu 'anhuma] berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat mengahdap Baitul Maqdis selama enam belas atau tujuh belas bulan, dan Rasulullah shallallahu 'alaihi wasallam menginginkan kiblat tersebut dialihkan ke arah Ka'bah. Maka Allah menurunkan ayat: (\"Sungguh Kami (sering) melihat mukamu menengadah ke langit) ' (Qs. Al Baqarah: 144). Maka kemudian Nabi shallallahu 'alaihi wasallam menghadap ke Ka'bah. Lalu berkatalah orang-orang yang kurang akal, yaitu orang-orang Yahudi: '(Apakah yang memalingkan mereka (umat Islam) dari kiblatnya (Baitul Maqdis) yang dahulu mereka telah berkiblat kepadanya?\" Katakanlah: \"Kepunyaan Allah-lah timur dan barat. Dia memberi petunjuk kepada siapa yang dikehendaki-Nya ke jalan yang lurus) ' (As. Al Baqarah: 144). Kemudian ada seseorang yang ikut shalat bersama Nabi shallallahu 'alaihi wasallam, orang itu kemudian keluar setelah menyelesikan shalatnya. Kemudian orang itu melewati Kaum Anshar yang sedang melaksanakan shalat 'Ashar dengan menghadap Baitul Maqdis. Lalu orang itu bersaksi bahwa dia telah shalat bersama Rasulullah shallallahu 'alaihi wasallam dengan menghadap Ka'bah. Maka orang-orang itu pun berputar dan menghadap Ka'bah.\""},{"p":"Bukhari","n":387,"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُوَافَقْتُ رَبِّي فِي ثَلَاثٍ فَقُلْتُ يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْنَا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى فَنَزَلَتْ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }وَآيَةُ الْحِجَابِ قُلْتُ يَا رَسُولَ الل��َهِ لَوْ أَمَرْتَ نِسَاءَكَ أَنْ يَحْتَجِبْنَ فَإِنَّهُ يُكَلِّمُهُنَّ الْبَرُّ وَالْفَاجِرُ فَنَزَلَتْ آيَةُ الْحِجَابِ وَاجْتَمَعَ نِسَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغَيْرَةِ عَلَيْهِ فَقُلْتُ لَهُنَّ{ عَسَى رَبُّهُ إِنْ طَلَّقَكُنَّ أَنْ يُبَدِّلَهُ أَزْوَاجًا خَيْرًا مِنْكُنَّ }فَنَزَلَتْ هَذِهِ الْآيَةُقَالَ أَبُو عَبْد اللَّهِ و حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ قَالَ حَدَّثَنِي حُمَيْدٌ قَالَ سَمِعْتُ أَنَسًا بِهَذَا","trj":"Telah menceritakan kepada kami ['Amru bin 'Aun] berkata, telah menceritakan kepada kami [Husyaim] dari [Humaid] dari [Anas bin Malik] berkata, ['Umar bin Al Khaththab], \"Aku memiliki pemikiran yang aku ingin jika itu dikabulkan oleh Rabbku dalam tiga persoalan. Maka aku sampaikan kepada Rasulullah shallallahu 'alaihi wasallam, 'Wahai Rasulullah, seandainya Maqam Ibrahim kita jadikan sebagai tempat shalat? Lalu turunlah ayat: '(Dan jadikanlah sebahagian maqam Ibrahim sebagai tempat shalat) ' (Qs. Al Baqarah: 125). Yang kedua tentang hijab. Aku lalu berkata, 'Wahai Rasulullah, seandainya Tuan perintahkan isteri-isteri Tuan untuk berhijab karena yang berkomunikasi dengan mereka ada orang yang shalih dan juga ada yang fajir (suka bermaksiat).' Maka turunlah ayat hijab. Dan yang ketiga, saat isteri-isteri beliau cemburu kepada beliau (sehingga banyak yang membangkang), aku katakan kepada mereka, 'Semoga bila Beliau menceraikan kalian Rabbnya akan menggantinya dengan isteri-isteri yang lebih baik dari kalian.' Maka turunlah ayat tentang masalah ini.\" Abu Abdullah berkata; telah menceritakan kepada kami [Ibnu Abu Maryam] berkata, telah mengabarkan kepada kami [Yahya bin Ayyub] berkata, telah menceritakan kepadaku [Humaid] ia berkata, Aku mendengar [Anas] seperti hadits ini.\""},{"p":"Bukhari","n":439,"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا أُنْزِلَتْ الْآيَاتُ مِنْ سُورَةِ الْبَقَرَةِ فِي الرِّبَا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَسْجِدِ فَقَرَأَهُنَّ عَلَى النَّاسِ ثُمَّ حَرَّمَ تِجَارَةَ الْخَمْرِ","trj":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari ['Aisyah] berkata, \"Ketika turun ayat-ayat dalam Surah Al Baqarah tentang masalah riba, Nabi shallallahu 'alaihi wasallam keluar ke masjid lalu membacakan ayat-ayat tersebut kepada manusia. Kemudian beliau mengharamkan perdagangan khamer.\""},{"p":"Bukhari","n":660,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَكَانَ مُعَاذُ بْنُ جَبَلٍ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَرْجِعُ فَيَؤُمُّ قَوْمَهُ فَصَلَّى الْعِشَاءَ فَقَرَأَ بِالْبَقَرَةِ فَانْصَرَفَ الرَّجُلُ فَكَأَنَّ مُعَاذًا تَنَاوَلَ مِنْهُ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ فَتَّانٌ فَتَّانٌ فَتَّانٌ ثَلَاثَ مِرَارٍ أَوْ قَالَ فَاتِنًا فَاتِنًا فَاتِنًا وَأَمَرَهُ بِسُورَتَيْنِ مِنْ أَوْسَطِ الْمُفَصَّلِقَالَ عَمْرٌو لَا أَحْفَظُهُمَا","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Ghundar] berkata, telah menceritakan kepada kami [Syu'bah] dari ['Amru] berkata, Aku mendengar [Jabir bin 'Abdullah] berkata, \"Mu'adz bin Jabal pernah shalat bersama Nabi shallallahu 'alaihi wasallam, dia lalu kembali pulang dan mengimami kaumnya shalat 'Isya dengan membaca surah Al Baqarah. Kemudian ada seorang laki-laki keluar dan pergi, Mu'adz seakan menyebut orang tersebut dengan keburukan. Kejadian ini kemudian sampai kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Apa engkau akan membuat fitnah? Apa engkau akan membuat fitnah? Apa engkau akan membuat membuat fitnah?\" Beliau ucapkanhingga tiga kali. Atau kata beliau: \"Apakah kamu menjadi pembuat fitnah? Apakah kamu menjadi pembuat fitnah? Apakah kamu menjadi pembuat fitnah?\" Lalu beliau memerintahkannya (Mu'adz) untuk membaca dua surah saja dari pertengahan Al Mufashshal.\" Amru berkata, 'Namun aku tidak hafal kedua surat tersebut.\" "},{"p":"Bukhari","n":664,"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا مُحَارِبُ بْنُ دِثَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ الْأَنْصَارِيَّ قَالَأَقْبَلَ رَجُلٌ بِنَاضِحَيْنِ وَقَدْ جَنَحَ اللَّيْلُ فَوَافَقَ مُعَاذًا يُصَلِّي فَتَرَكَ نَاضِحَهُ وَأَقْبَلَ إِلَى مُعَاذٍ فَقَرَأَ بِسُورَةِ الْبَقَرَةِ أَوْ النِّسَاءِ فَانْطَلَقَ الرَّجُلُ وَبَلَغَهُ أَنَّ مُعَاذًا نَالَ مِنْهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَا إِلَيْهِ مُعَاذًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ أَوْ أَفَاتِنٌ ثَلَاثَ مِرَارٍ فَلَوْلَا صَلَّيْتَ بِسَبِّحِ اسْمَ رَبِّكَ وَالشَّمْسِ وَضُحَاهَا وَاللَّيْلِ إِذَا يَغْشَى فَإِنَّهُ يُصَلِّي وَرَاءَكَ الْكَبِيرُ وَالضَّعِيفُ وَذُو الْحَاجَةِأَحْسِبُ هَذَا فِي الْحَدِيثِ قَالَ أَبُو عَبْد اللَّهِ وَتَابَعَهُ سَعِيدُ بْنُ مَسْرُوقٍ وَمِسْعَرٌ وَالشَّيْبَانِيُّ قَالَ عَمْرٌو وَعُبَيْدُ اللَّهِ بْنُ مِقْسَمٍ وَأَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَرَأَ مُعَاذٌ فِي الْعِشَاءِ بِالْبَقَرَةِ وَتَابَعَهُ الْأَعْمَشُ عَنْ مُحَارِبٍ","trj":"Telah menceritakan kepada kami [Adam bin Abu Iyas] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Muharib bin Ditsar] berkata, Aku mendengar [Jabir bin 'Abdullah Al Anshari] berkata, \"Seoranglaki-laki datang dengan membawa dua unta yang baru saja diberinya minum saat malam sudah gelap gulita. Laki-laki itu kemudian tinggalkan untanya dan ikut shalat bersama Mu'adz. Dalam shalatnya Mu'adz membaca surah Al Baqarah atau surah An Nisaa' sehingga laki-laki tersebut meninggalkan Mu'adz. Maka sampailah kepadanya berita bahwa Mu'adz mengecam tindakannya. Akhirnya laki-laki tersebut mendatangi Nabi shallallahu 'alaihi wasallam dan mengadukan persoalannya kepada beliau. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Mu'adz, apakah kamu membuat fitnah?\" Atau kata Beliau: \"Apakah kamu menjadi pembuat fitnah? -Beliau ulangi perkataannya tersebut hingga tiga kali- \"Mengapa kamu tidak membaca saja surat 'Sabbihisma rabbika', atau dengan 'Wasysyamsi wa dluhaahaa' atau 'Wallaili idzaa yaghsyaa'? Karena yang ikut shalat di belakangmu mungkin ada orang yang lanjut usia, orang yang lemah atau orang yang punya keperluan.\" Perawi berkata, \"Menurutku sampai inilah kalimat hadits ini.\" Abu 'Abdullah berkata; hadits ini dikuatkan oleh [Sa'id bin Masruq] dan [Mis'ar] dan [Asy Syaibani]. [Amru] dan [Ubaidullah bin Miqsam] dan [Abu Az Zubair] dari [Jabir] bahwa dalam shalat Isya Mu'adz membaca surat Al Baqarah. Dan hadits ini dikuatkan oleh [Al A'masy] dari [Muharib].\""},{"p":"Bukhari","n":993,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَانْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ قِيَامًا طَوِيلًا نَحْوًا مِنْ قِرَاءَةِ سُورَةِ الْبَقَرَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَاذْكُرُوا اللَّهَ قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ ثُمَّ رَأَيْنَاكَ كَعْكَعْتَ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي رَأَيْتُ الْجَنَّةَ فَتَنَاوَلْتُ عُنْقُودًا وَلَوْ أَصَبْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا وَأُرِيتُ النَّارَ فَلَمْ أَرَ مَنْظَرًا كَالْيَوْمِ قَطُّ أَفْظَعَ وَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ قَالُوا بِمَ يَا رَسُولَ اللَّهِ قَالَ بِكُفْرِهِنَّ قِيلَ يَكْفُرْنَ بِاللَّهِ قَالَ يَكْفُرْنَ الْعَشِيرَ وَيَكْفُرْنَ الْإِحْسَانَ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ كُلَّهُ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّ","trj":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari ['Abdullah bin 'Abbas] ia berkata, \"Telah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam kemudian melaksanakan shalat, beliau berdiri dengan sangat panjang (lama) sekadar bacaan surah Al Baqarah. Lalu beliau rukuk dengan rukuk yang panjang, lalu mengangkat (kepala) berdiri dengan panjang namun tidak sepanjang yang pertama. Kemudian rukuk kembali dengan panjang namun tidak sepanjang rukuk yang pertama. Kemudian sujud. Kemudian beliau kembali berdiri dengan panjang namun tidak sepanjang yang pertama, lalu rukuk dengan rukuk yang panjang namun tidak sepanjang rukuk yang pertama, lalu mengangkat (kepala) berdiri dengan panjang namun tidak sepanjang yang pertama. Kemudian beliau rukuk kembali dengan panjang namun tidak sepanjang rukuk yang pertama. Kemudian sujud. Kemudian beliau berlalu pergi sementara matahari sudah nampak kembali. Beliau kemudian bersabda: \"Sesungguhnya matahari dan bulan adalah dua tanda dari tanda-tanda kebesaran Allah, dan keduanya tidak akan mengalami gerhana disebabkan karena mati atau hidupnya seseorang. Jika kalian melihatnya maka banyaklah mengingat Allah.\" Para sahabat bertanya, \"Wahai Rasulullah, kami melihat tuan merasakan sesuatu pada posisi tuan dan kami melihat seakan tuan menahan perasaan takut?\" Beliau menjawab: \"Sungguh aku melihat surga, dan didalamnya aku memperoleh setandan anggur. Seandainya aku mengambilnya tentu kalian akan memakannya sehingga urusan dunia akan terabaikan. Kemudian aku melihat neraka, dan aku belum pernah melihat suatu pemandangan yang lebih mengerikan dibanding hari ini, dan aku melihat kebanyakan penghuninya adalah kaum wanita.\" Para sahabat bertanya lagi, \"Mengapa begitu wahai Rasulullah?\" Beliau menjawab: \"Karena mereka sering kufur (mengingkari).\" Ditanyakan kepada beliau, \"Apakah mereka mengingkari Allah?\" Beliau menjawab: \"Mereka mengingkari pemberian suami, mengingkari kebaikan. Seandainya kamu berbuat baik terhadap salah seorang dari mereka sepanjang masa, lalu dia melihat satu saja kejelekan darimu maka dia akan berkata, 'Aku belum pernah melihat kebaikan darimu sedikitpun'.\""},{"p":"Bukhari","n":1125,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عِيسَى هُوَ ابْنُ يُونُسَ عَنْ إِسْمَاعِيلَ عَنْ الْحَارِثِ بْنِ شُبَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ قَالَ قَالَ لِي زَيْدُ بْنُ أَرْقَمَإِنْ كُنَّا لَنَتَكَلَّمُ فِي الصَّلَاةِ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَلِّمُ أَحَدُنَا صَاحِبَهُ بِحَاجَتِهِ حَتَّى نَزَلَتْ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَقُومُوا لِلَّهِ قَانِتِينَ }فَأُمِرْنَا بِالسُّكُوتِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami ['Isa] dia adalah putra Yunus dari [Isma'il] dari [Al Harits bin Syubail] dari [Abu 'Amru Asy Syaibaniy] berkata; [Zaid bin Arqam] berkata, kepadaku: \"Sungguh kami pernah berbicara ketika sedang shalat hingga ada seorang diantara kami yang berbicara dengan temannya tentang kebutuhannya sampai kemudian turun firman Allah Ta'ala (dalam surah Al Baqarah) \"Peliharalah seluruh shalat kalian dan shalat Al Wustha dan berdirilah (dalam shalat) untuk Allah dengan khusyu'\". (QS. Albaqarah, 238), Maka kami diperintah untuk diam\"."},{"p":"Bukhari","n":1426,"ar":"حَدَّثَنَا يَحْيَى بْنُ بِشْرٍ حَدَّثَنَا شَبَابَةُ عَنْ وَرْقَاءَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ أَهْلُ الْيَمَنِ يَحُجُّونَ وَلَا يَتَزَوَّدُونَ وَيَقُولُونَ نَحْنُ الْمُتَوَكِّلُونَ فَإِذَا قَدِمُوا مَكَّةَ سَأَلُوا النَّاسَ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَتَزَوَّدُوا فَإِنَّ خَيْرَ الزَّادِ التَّقْوَى }رَوَاهُ ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ عِكْرِمَةَ مُرْسَلًا","trj":"Telah menceritakan kepada kami [Yahya bin Bisir] telah menceritakan kepada kami [Syababah] dari [Warqa'] dari ['Amru bin Dinar] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] ia berkata; \"Dahulu para penduduk Yaman berhajji namun mereka tidak membawa bekal dan mereka berkata, kami adalah orang-orang yang bertawakal. Ketika mereka tiba di Makkah, mereka meminta-minta kepada manusia. Maka Allah Ta'ala menurunkan ayat 197 dari QS Al Baqarah) yang artinya (\"Berbekallah, dan sesungguhnya sebaik-baik bekal adalah takwa\".) Dan diriwayatkan pula oleh [Ibnu 'Uyainah] dari ['Amru] dari ['Ikrimah] secara mursal."},{"p":"Bukhari","n":1457,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَوْمٍ بِالْيَمَنِ فَجِئْتُ وَهُوَ بِالْبَطْحَاءِ فَقَالَ بِمَا أَهْلَلْتَ قُلْتُ أَهْلَلْتُ كَإِهْلَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَلْ مَعَكَ مِنْ هَدْيٍ قُلْتُ لَا فَأَمَرَنِي فَطُفْتُ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ أَمَرَنِي فَأَحْلَلْتُ فَأَتَيْتُ امْرَأَةً مِنْ قَوْمِي فَمَشَطَتْنِي أَوْ غَسَلَتْ رَأْسِي فَقَدِمَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَ إِنْ نَأْخُذْ بِكِتَابِ اللَّهِ فَإِنَّهُ يَأْمُرُنَا بِالتَّمَامِ قَالَ اللَّهُ{ وَأَتِمُّوا الْحَجَّ وَالْعُمْرَةَ لِلَّهِ }وَإِنْ نَأْخُذْ بِسُنَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّهُ لَمْ يَحِلَّ حَتَّى نَحَرَ الْهَدْيَ","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Qais bin Muslim] dari [Thoriq bin Syihab] dari [Abu Musa radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam mengutusku kepada suatu kaum di negeri Yaman. Ketika aku sudah kembali aku menemui Beliau ketika Beliau berada di Batha'. Beliau berkata, kepadaku: \"Bagaimana cara kamu berihram (memulai hajji)?\". Aku menjawab: \"Aku berihram sebagaimana Nabi shallallahu 'alaihi wasallam berihram\". Beliau bertanya lagi: \"Apakah kamu ada membawa hewan qurban?. Aku menjawab: \"Tidak\". Maka Beliau memerintahkan aku agar aku melakukan thowaf di Baitulloh dan sa'iy antara bukit Ash-Shafa dan Al Marwah lalu memerintahkan aku pula agar aku bertahallul. Lalu aku temui seorang wanita dari keluargaku lalu dia menyisir rambutku atau membasuh kepalaku. Lalu 'Umar radliallahu 'anhu datang dan berkata: \"Jika kita mengambil pedoman dari Kitab Allah, sesungguhnya Dia memerintahkan kita agar kita menyempurnakannya (hajji dan 'umrah). Allah subhanahu wata'ala berfirman (Qs Al Baqarah ayat 196) yang artinya: (\"Dan semprurnakanlah 'ibadah hajji dan 'umrah kalian karena Allah) \", dan seandainya kita mengambil pedoman dari sunnah Rasulullah Shallallahu'alaihiwasallam, sesungguhnya Beliau tidak bertahallul kecuali setelah menyembelih hewan qurban\". "},{"p":"Bukhari","n":1534,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ عُرْوَةُ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقُلْتُ لَهَاأَرَأَيْتِ قَوْلَ اللَّهِ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَوَاللَّهِ مَا عَلَى أَحَدٍ جُنَاحٌ أَنْ لَا يَطُوفَ بِالصَّفَا وَالْمَرْوَةِ قَالَتْ بِئْسَ مَا قُلْتَ يَا ابْنَ أُخْتِي إِنَّ هَذِهِ لَوْ كَانَتْ كَمَا أَوَّلْتَهَا عَلَيْهِ كَانَتْ لَا جُنَاحَ عَلَيْهِ أَنْ لَا يَتَطَوَّفَ بِهِمَا وَلَكِنَّهَا أُنْزِلَتْ فِي الْأَنْصَارِ كَانُوا قَبْلَ أَنْ يُسْلِمُوا يُهِلُّونَ لِمَنَاةَ الطَّاغِيَةِ الَّتِي كَانُوا يَعْبُدُونَهَا عِنْدَ الْمُشَلَّلِ فَكَانَ مَنْ أَهَلَّ يَتَحَرَّجُ أَنْ يَطُوفَ بِالصَّفَا وَالْمَرْوَةِ فَلَمَّا أَسْلَمُوا سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ قَالُوا يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَتَحَرَّجُ أَنْ نَطُوفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }الْآيَةَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا وَقَدْ سَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّوَافَ بَيْنَهُمَا فَلَيْسَ لِأَحَدٍ أَنْ يَتْرُكَ الطَّوَافَ بَيْنَهُمَا ثُمَّ أَخْبَرْتُ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ فَقَالَ إِنَّ هَذَا لَعِلْمٌ مَا كُنْتُ سَمِعْتُهُ وَلَقَدْ سَمِعْتُ رِجَالًا مِنْ أَهْلِ الْعِلْمِ يَذْكُرُونَ أَنَّ النَّاسَ إِلَّا مَنْ ذَكَرَتْ عَائِشَةُ مِمَّنْ كَانَ يُهِلُّ بِمَنَاةَ كَانُوا يَطُوفُونَ كُلُّهُمْ بِالصَّفَا وَالْمَرْوَةِ فَلَمَّا ذَكَرَ اللَّهُ تَعَالَى الطَّوَافَ بِالْبَيْتِ وَلَمْ يَذْكُرْ الصَّفَا وَالْمَرْوَةَ فِي الْقُرْآنِ قَالُوا يَا رَسُولَ اللَّهِ كُنَّا نَطُوفُ بِالصَّفَا وَالْمَرْوَةِ وَإِنَّ اللَّهَ أَنْزَلَ الطَّوَافَ بِالْبَيْتِ فَلَمْ يَذْكُرْ الصَّفَا فَهَلْ عَلَيْنَا مِنْ حَرَجٍ أَنْ نَطَّوَّفَ بِالصَّفَا وَالْمَرْوَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }الْآيَةَ قَالَ أَبُو بَكْرٍ فَأَسْمَعُ هَذِهِ الْآيَةَ نَزَلَتْ فِي الْفَرِيقَيْنِ كِلَيْهِمَا فِي الَّذِينَ كَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بِالْجَاهِلِيَّةِ بِالصَّفَا وَالْمَرْوَةِ وَالَّذِينَ يَطُوفُونَ ثُمَّ تَحَرَّجُوا أَنْ يَطُوفُوا بِهِمَا فِي الْإِسْلَامِ مِنْ أَجْلِ أَنَّ اللَّهَ تَعَالَى أَمَرَ بِالطَّوَافِ بِالْبَيْتِ وَلَمْ يَذْكُرْ الصَّفَا حَتَّى ذَكَرَ ذَلِكَ بَعْدَ مَا ذَكَرَ الطَّوَافَ بِالْبَيْتِ","trj":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy], berkata, ['Urwah]: Aku bertanya kepada ['Aisyah radliallahu 'anha], kataku kepadanya: \"Bagaimana pendapatmu tentang firman Allah Ta'ala (QS Al Baqarah 158) yang artinya: (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah, maka barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\"), dan demi Allah tidak ada dosa bagi seseorang untuk tidak ber thawaf (sa'iy) antara bukit Ash-Shafaa dan Al Marwah\". 'Aisyah radliallahu 'anha berkata: \"Buruk sekali apa yang kamu katakan itu wahai putra saudariku. Sesungguhnya ayat ini bila tafsirannya menurut pendapatmu tadi berarti tidak berdosa bila ada orang yang tidak melaksanakan sa'iy antara keduanya. Akan tetapi ayat ini turun berkenaan dengan Kaum Anshar, yang ketika mereka belum masuk Islam, mereka berniat hajji untuk patung Manat Sang Thoghut yang mereka sembah di daerah Al Musyallal. Waktu itu, barangsiapa yang berniat hajji, dia merasa berdosa bila harus sa'iy antara bukit Ash-Shafaa dan Al Marwah (karena demi menghormatii patung mereka itu). Setelah mereka masuk Islam, mereka bertanya kepada Rasulullah Shallallahu'alaihiwasallam tentang masalah itu, mereka berkata: \"Wahai Rasulullah, kami merasa berdosa bila melaksanakan sa'iy antara bukit Ash-Shafaa dan Al Marwah\". Maka kemudian Allah Ta'ala menurunkan ayat (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah\"). 'Aisyah radliallahu 'anha berkata: \"Sungguh Rasulullah Shallallahu'alaihiwasallam telah mencontohkan sa'iy antara kedua bukit tersebut dan tidak boleh seorangpun untuk meninggalkannya\". Kemudian aku kabarkan hal ini kepada Abu Bakar bin 'Abdurrahman, maka katanya: \"Sungguh ini suatu ilmu yang aku belum pernah mendengar sebelumnya, padahal aku sudah mendengar dari orang-orang ahli ilmu yang menyebutkan bahwa diantara manusia, selain orang-orang yang diterangkan oleh 'Aisyah radliallahu 'anha itu, ada yang dahulu melaksanakan ihram untuk Manat, mereka juga melaksanakan sa'iy antara bukit Ash-Shafaa dan Al Marwah. Ketika Allah menyebutkan thawaf di Ka'bah Baitullah tapi tidak menyebut sa'iy antara bukit Ash-Shafaa dan Al Marwah dalam Al Qur'an, mereka bertanya kepada: \"Wahai Rasulullah, dahulu kami melaksanakan thawaf (sa'iy) antara bukit Ash-Shafaa dan Al Marwah dan Allah telah menurunkan ayat tentang thawaf di Ka'bah Baitullah tanpa menyebut Ash-Shafaa, apakah berdosa bagi kami bila kami sa'iy antara bukit Ash-Shafaa dan Al Marwah?\". Maka Allah Ta'ala menurunkan ayat (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar Allah\"). Abu Bakar bin 'Abdurrahman berkata: \"Maka aku mendengar bahwa ayat ini turun untuk dua golongan orang yaitu golongan orang-orang yang merasa berdosa karena pernah melaksanakan sa'i antara bukit Ash-Shafaa dan Al Marwah saat mereka masih jahiliyyah (karena pernah melaksanakan untuk patung Manat), dan golongan orang-orang yang pernah melaksanakannya namun merasa berdosa bila melaksanakannya kembali setelah masuk Islam karena Allah pada mulanya hanya menyebutkan thawaf di Ka'bah Baitullah dan tidak menyebut Ash-Shafaa hingga kemudian Dia menyebutkannya setelah memerintahkan thawaf di Ka'bah Baitullah\"."},{"p":"Bukhari","n":1538,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَاصِمٌ قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَكُنْتُمْ تَكْرَهُونَ السَّعْيَ بَيْنَ الصَّفَا وَالْمَرْوَةِ قَالَ نَعَمْ لِأَنَّهَا كَانَتْ مِنْ شَعَائِرِ الْجَاهِلِيَّةِ حَتَّى أَنْزَلَ اللَّهُ{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami ['Ashim] berkata; Aku berkata, kepada [Anas bin Malik radliallahu 'anhu]: \"Apakah kalian tidak menyukai melaksanakan sa'iy antara bukit Shafaa dan Marwah? '. Dia menjawab: \"Ya benar, karena itu bagian dari syi'ar-syi'ar jahiliyyah hingga kemudian Allah menurunkan (QS Al Baqarah ayat 158) yang artinya (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah bahagian dari syi'ar-syi'ar Allah, barangsiapa yang beribadah haji ke Baitullah atau ber-'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\")."},{"p":"Bukhari","n":1554,"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ عُرْوَةُ كَانَ النَّاسُ يَطُوفُونَ فِي الْجَاهِلِيَّةِ عُرَاةً إِلَّا الْحُمْسَ وَالْحُمْسُ قُرَيْشٌ وَمَا وَلَدَتْ وَكَانَتْ الْحُمْسُ يَحْتَسِبُونَ عَلَى النَّاسِ يُعْطِي الرَّجُلُ الرَّجُلَ الثِّيَابَ يَطُوفُ فِيهَا وَتُعْطِي الْمَرْأَةُ الْمَرْأَةَ الثِّيَابَ تَطُوفُ فِيهَا فَمَنْ لَمْ يُعْطِهِ الْحُمْسُ طَافَ بِالْبَيْتِ عُرْيَانًا وَكَانَ يُفِيضُ جَمَاعَةُ النَّاسِ مِنْ عَرَفَاتٍ وَيُفِيضُ الْحُمْسُ مِنْ جَمْعٍ قَالَ وَأَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ هَذِهِ الْآيَةَ نَزَلَتْ فِي الْحُمْسِ{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }قَالَ كَانُوا يُفِيضُونَ مِنْ جَمْعٍ فَدُفِعُوا إِلَى عَرَفَاتٍ","trj":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra'] telah menceritakan kepada kami ['Ali bin Mushir] dari [Hisyam bin 'Urwah], ['Urwah] berkata: \"Pada masa Jahiliyah orang-orang melakukan thawaf dengan telanjang kecuali Al Humus dan istilah Al Humus adalah orang-orang Quraisy dan keturunan mereka. Dahulu Al Humus membeda-bedakan manusia, diantara kaum lelakinya ada yang memberi pakaian kepada kaum lelaki sehingga dia thawaf mengenakan pakaian, begitu juga diantara wanitanya memberi pakaian kepada para wanita sehingga dia thawaf dengan pakaian itu. Sedangkan bagi orang yang tidak diberi pakaian oleh Al Humus (quraisy) maka dia thawaf dengan telanjang. Rambongan orang-orang biasanya bertolak dari 'Arafah sedangkan Al Humus (quraisy) dari Jama', atau Muzdalifah. Dia berkata; bapakku telah mengabarkan kepada saya dari ['Aisyah radliallahu 'anha] bahwa ayat ini (QS Al Baqarah ayat 199) turun tentang Al Humus (yang artinya): (\"Kemudian bertolaklah kamu dari tempat bertolaknya orang banyak\"). 'Urwah berkata: \"Awalnya mereka selalu bertolak dari Jama', kemudian diperintahkan bertolak dari 'Arafah\". "},{"p":"Bukhari","n":1629,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ رَمَى عَبْدُ اللَّهِمِنْ بَطْنِ الْوَادِي فَقُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنَّ نَاسًا يَرْمُونَهَا مِنْ فَوْقِهَا فَقَالَ وَالَّذِي لَا إِلَهَ غَيْرُهُ هَذَا مَقَامُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ عَبْدُ اللَّهِ بْنُ الْوَلِيدِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ بِهَذَا","trj":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Abdurrahman bin Yazid] berkata: \" ['Abdullah] melempar jumrah dari dasar lembah, lalu aku bertanya: \"Wahai 'Abdurrahman, orang-orang melempar dari atas (lembah)?\". Maka dia berkata: \"Demi Dzat yang tidak ada ilah selain Dia, tempat ini adalah tempat seseorang yang diturunkan kepadanya surah Al Baqarah, yaitu Muhammad shallallahu 'alaihi wasallam\". Dan berkata, ['Abdullah bin Al Walid] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Al A'masy] sepeti hadits ini\". "},{"p":"Bukhari","n":1630,"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّهُ انْتَهَى إِلَى الْجَمْرَةِ الْكُبْرَى جَعَلَ الْبَيْتَ عَنْ يَسَارِهِ وَمِنًى عَنْ يَمِينِهِ وَرَمَى بِسَبْعٍ وَقَالَ هَكَذَا رَمَى الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari ['Abdurrahman bin Yazid] dari ['Abdullah radliallahu 'anhu] bahwa dia berhenti hingga Al Jumrah Al Kubra (Al 'Aqabah), yang Ka'bah Baitullah berada disisi kirinya sedangkan Mina disisi kanannya lalu dia melempar dengan tujuh (batu), lalu berkata; \"Beginilah cara melempar seseorang yang telah diturunkan kepadanya surah Al Baqarah, yaitu Muhammad shallallahu 'alaihi wasallam\"."},{"p":"Bukhari","n":1631,"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ أَنَّهُ حَجَّ مَعَ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُفَرَآهُ يَرْمِي الْجَمْرَةَ الْكُبْرَى بِسَبْعِ حَصَيَاتٍ فَجَعَلَ الْبَيْتَ عَنْ يَسَارِهِ وَمِنًى عَنْ يَمِينِهِ ثُمَّ قَالَ هَذَا مَقَامُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","trj":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Hakam] dari [Ibrahim] dari ['Abdurrahman bin Yazid] bahwa dia menunaikan haji bersama [Ibnu Mas'ud radliallahu 'anhu] lalu dia melihat Ibnu Mas'ud radliallahu 'anhu melempar Al Jumrah Al Kubra dengan tujuh kerikil yang posisi Ka'bah Baitullah berada disisi kirinya sedangkan Mina disisi kanannya lalu dia berkata; \"Inilah tempat melempar seseorang yang telah diturunkan kepadanya surah Al Baqarah, yaitu Muhammad shallallahu 'alaihi wasallam\"."},{"p":"Bukhari","n":1632,"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ عَبْدِ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ الْحَجَّاجَ يَقُولُ عَلَى الْمِنْبَرِ السُّورَةُ الَّتِي يُذْكَرُ فِيهَا الْبَقَرَةُ وَالسُّورَةُ الَّتِي يُذْكَرُ فِيهَا آلُ عِمْرَانَ وَالسُّورَةُ الَّتِي يُذْكَرُ فِيهَا النِّسَاءُ قَالَ فَذَكَرْتُ ذَلِكَ لِإِبْرَاهِيمَ فَقَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ أَنَّهُ كَانَ مَعَ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُحِينَ رَمَى جَمْرَةَ الْعَقَبَةِ فَاسْتَبْطَنَ الْوَادِيَ حَتَّى إِذَا حَاذَى بِالشَّجَرَةِ اعْتَرَضَهَا فَرَمَى بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ ثُمَّ قَالَ مِنْ هَا هُنَا وَالَّذِي لَا إِلَهَ غَيْرُهُ قَامَ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Musaddad] dari ['Abdul Wahid] telah menceritakan kepada kami [Al A'masy] berkata; Aku mendengar Al Hajjaj berkata, dari atas mimbar: \"Surah yang disebut didalamnya Al Baqarah dan surah yang disebut didalamnya Ali 'Imran dan surah yang didalamnya disebut tentang para wanita\". Dia (Al A'masy) berkata: \"Lalu aku sampaikan hal ini kepada [Ibrahim], maka dia berkata; telah menceritakan kepada saya ['Abdurrahman bin Yazid] bahwa dia pernah bersama [Ibnu Mas'ud radliallahu 'anhu] ketika melempar jumrah Al 'Aqabah, dia menuruni lembah hingga ketika sampai di sebuah pohon, dia berhenti dan dari situ melempar dengan tujuh kerikil dengan bertakbir pada setiap kerikil lemparannya lalu berkata: \"Demi Dzat yang tidak ada ilah selain Dia, dari sinilah berdiri melempar seseorang yang diturunkan kepadanya surah Al Baqarah, yaitu Muhammad shallallahu 'alaihi wasallam\"."},{"p":"Bukhari","n":1648,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ الْهَيْثَمِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ عَمْرُو بْنُ دِينَارٍ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاكَانَ ذُو الْمَجَازِ وَعُكَاظٌ مَتْجَرَ النَّاسِ فِي الْجَاهِلِيَّةِ فَلَمَّا جَاءَ الْإِسْلَامُ كَأَنَّهُمْ كَرِهُوا ذَلِكَ حَتَّى نَزَلَتْ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ","trj":"Telah menceritakan kepada kami ['Utsman bin Al Haitsam] telah mengabarkan kepada kami [Ibnu Juraij] telah berkata, ['Amru bin Dinar] berkata, [Ibnu 'Abbas radliallahu 'anhuma]: \"Dzul Majaz dan Ukazh adalah tempat berdagang orang-orang pada masa jahiliyah. Ketika Islam datang seakan-akan mereka membenci tempat itu, hingga turunlah QS AL Baqarah ayat 195 yang artinya: (\"Tidak ada dosa bagi kalian jika kalian mencari karunia(rezeqi hasil perniagaan) dari Rabb kalian\"), yaitu pada musim haji."},{"p":"Bukhari","n":1665,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ قُلْتُ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّأَرَأَيْتِ قَوْلَ اللَّهِ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَلَا أُرَى عَلَى أَحَدٍ شَيْئًا أَنْ لَا يَطَّوَّفَ بِهِمَا فَقَالَتْ عَائِشَةُ كَلَّا لَوْ كَانَتْ كَمَا تَقُولُ كَانَتْ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي الْأَنْصَارِ كَانُوا يُهِلُّونَ لِمَنَاةَ وَكَانَتْ مَنَاةُ حَذْوَ قُدَيْدٍ وَكَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا جَاءَ الْإِسْلَامُ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }زَادَ سُفْيَانُ وَأَبُو مُعَاوِيَةَ عَنْ هِشَامٍ مَا أَتَمَّ اللَّهُ حَجَّ امْرِئٍ وَلَا عُمْرَتَهُ لَمْ يَطُفْ بَيْنَ الصَّفَا وَالْمَرْوَةِ","trj":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] bahwa dia berkata; Aku pernah bertanya kepada ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam saat itu aku masih muda: \"Bagaimana pendapatmu tentang firman Allah Ta'ala (QS Al Baqarah 158) yang artinya: (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\"), kalau aku berpendapat bahwa seseorang tidak mengapa untuk tidak berthawaf (sa'iy) antara kedua bukit itu. 'Aisyah radliallahu 'anha berkata: \"Bukanlah begitu. Seandainya ayat ini maksudnya sebagaimana yang kamu katakan itu, berarti tidak berdosa bila ada orang yang tidak melaksanakan sa'iy antara keduanya. Sesungguhnya ayat ini turun berkenaan dengan Kaum Anshar yang dahulu mereka berniat haji untuk patung Manat (yang mereka sembah) di daerah sekitar Qudaid. Lantas mereka merasa berdosa bila harus sa'iy antara bukit Ash-Shafaa dan Al Marwah. Setelah Islam datang, mereka bertanya kepada Rasulullah shallallahu 'alaihi wasallam masalah itu, maka kemudian Allah Ta'ala menurunkan ayat (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah. Barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\"). [Sufyan] dan [Abu Mu'awiyah] menambahkan dari [Hisyam] (yakni dari bapaknya dari 'Aisyah radliallahu 'anha): \"Allah tidak akan menerima haji atau 'umrah seseorang yang tidak melakukan sa'iy antara bukit Ash-Shafaa dan Al Marwah\"."},{"p":"Bukhari","n":1676,"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ يَقُولُنَزَلَتْ هَذِهِ الْآيَةُ فِينَا كَانَتْ الْأَنْصَارُ إِذَا حَجُّوا فَجَاءُوا لَمْ يَدْخُلُوا مِنْ قِبَلِ أَبْوَابِ بُيُوتِهِمْ وَلَكِنْ مِنْ ظُهُورِهَا فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَدَخَلَ مِنْ قِبَلِ بَابِهِ فَكَأَنَّهُ عُيِّرَ بِذَلِكَ فَنَزَلَتْ{ وَلَيْسَ الْبِرُّ بِأَنْ تَأْتُوا الْبُيُوتَ مِنْ ظُهُورِهَا وَلَكِنَّ الْبِرَّ مَنْ اتَّقَى وَأْتُوا الْبُيُوتَ مِنْ أَبْوَابِهَا }","trj":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata; Aku mendengar [Al Bara' radliallahu 'anhu] berkata: \"Ayat ini turun kepada kami, yaitu Kaum Anshar jika mereka menunaikan haji lalu kembali pulang, mereka tidak memasuki rumah-rumah mereka dari pintu depannya namun mereka masuk dari belakang. Kemudian datanglah seseorang dari Kaum Anshar yang ia masuk dari pintu depan seakan-akan ia merubah kebiasaan tadi. Maka kemudian turunlah firman Allah QS Al Baqarah ayat 189 yang artinya: (\"Dan bukanlah kebajikan memasuki rumah-rumah dari belakangnya, akan tetapi kebajikan itu ialah kebajikan orang yang bertakwa. Dan masuklah ke rumah-rumah itu dari pintu-pintunya\")."},{"p":"Bukhari","n":1687,"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَيْفٌ قَالَ حَدَّثَنِي مُجَاهِدٌ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى أَنَّ كَعْبَ بْنَ عُجْرَةَ حَدَّثَهُ قَالَوَقَفَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحُدَيْبِيَةِ وَرَأْسِي يَتَهَافَتُ قَمْلًا فَقَالَ يُؤْذِيكَ هَوَامُّكَ قُلْتُ نَعَمْ قَالَ فَاحْلِقْ رَأْسَكَ أَوْ قَالَ احْلِقْ قَالَ فِيَّ نَزَلَتْ هَذِهِ الْآيَةُ{ فَمَنْ كَانَ مِنْكُمْ مَرِيضًا أَوْ بِهِ أَذًى مِنْ رَأْسِهِ }إِلَى آخِرِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ ثَلَاثَةَ أَيَّامٍ أَوْ تَصَدَّقْ بِفَرَقٍ بَيْنَ سِتَّةٍ أَوْ انْسُكْ بِمَا تَيَسَّرَ","trj":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sayf] berkata, telah menceritakan kepada saya [Mujahid] berkata, aku mendengar ['Abdurrahman bin Abu Laila] bahwa [Ka'ab bin 'Ujrah radliallahu 'anhu] berkata: \"Rasulullah shallallahu 'alaihi wasallam menghampiriku di Hudaibiyah ketika kepalaku dipenuhi kutu, Beliau berkata: \"Barangkali kamu terkena serangga (kutu di kepala)?\". Aku jawab: \"Benar, wahai Rasulullah\". Maka Beliau berkata: \"Cukurlah rambutnu\". Atau dia berkata: \"Ayat ini turun untukku\" (QS Al Baqarah ayat 196 yang artinya): (\"....Maka barangsiapa dari kalian yang sakit atau tertimpa sesuatu pada kepalanya...) hingga akhir ayat. Maka Nabi shallallahu 'alaihi wasallam berkata: \"Laksanakanlah shaum tiga hari atau bershadaqah sebanyak faraq (tiga sha') terhadap enam orang atau berqurban dengan yang mudah buatmu\". "},{"p":"Bukhari","n":1782,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِس��رَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ أَصْحَابُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الرَّجُلُ صَائِمًا فَحَضَرَ الْإِفْطَارُ فَنَامَ قَبْلَ أَنْ يُفْطِرَ لَمْ يَأْكُلْ لَيْلَتَهُ وَلَا يَوْمَهُ حَتَّى يُمْسِيَ وَإِنَّ قَيْسَ بْنَ صِرْمَةَ الْأَنْصَارِيَّ كَانَ صَائِمًا فَلَمَّا حَضَرَ الْإِفْطَارُ أَتَى امْرَأَتَهُ فَقَالَ لَهَا أَعِنْدَكِ طَعَامٌ قَالَتْ لَا وَلَكِنْ أَنْطَلِقُ فَأَطْلُبُ لَكَ وَكَانَ يَوْمَهُ يَعْمَلُ فَغَلَبَتْهُ عَيْنَاهُ فَجَاءَتْهُ امْرَأَتُهُ فَلَمَّا رَأَتْهُ قَالَتْ خَيْبَةً لَكَ فَلَمَّا انْتَصَفَ النَّهَارُ غُشِيَ عَلَيْهِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ }فَفَرِحُوا بِهَا فَرَحًا شَدِيدًا وَنَزَلَتْ{ وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }","trj":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Isra'il] dari [Abu Ishaq] dari [Al Bara' radliallahu 'anhu] berkata; \"Diantara para sahabat Muhammad shallallahu 'alaihi wasallam ada seseorang apabila sedang shaum lalu tiba waktu berbuka dia pergi tidur sebelum berbuka sehingga dia tidak memakan sesuatu pada malam dan siang hari hingga petang hari. Dan pada suatu ketika Qais bin Shirmah Al Anshariy ketika sedang melaksanakan shaum lalu tiba waktu berbuka dia mendatangi isterinya seraya berkata, kepada isterinya: \"Apakah kamu punya makanan?\" Isterinya berkata: \"Tidak, namun aku akan keluar mencari makanan buatmu\". Kemudian di siang harinya dia bekerja keras hingga mengantuk lalu tertidur. Kemudian isterinya datang. Ketika isterinya melihat dia (sedang tertidur), isterinya berkata: \"Rugilah kamu\". Kemudian pada tengah harinya Qais jatuh pingsan. Lalu persoalan ini diadukan kepada Nabi shallallahu 'alaihi wasallam, maka turunlah firman Allah Ta'ala QS Al Baqarah ayat 197 yang artinya: (\"Dihalalkan bagi kalian pada malam bulan puasa bercampur dengan isttri-isteri kalian\"). Dengan turunnya ayat ini para sahabat merasa sangat senang, hingga kemudian turun sambungan ayatnya: (\"Dan makan minumlah kalian hingga terang bagi kalian benang putih dari benang hitam yaitu di waktu fajar\")."},{"p":"Bukhari","n":1783,"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنِي حُصَيْنُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ{ حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }عَمَدْتُ إِلَى عِقَالٍ أَسْوَدَ وَإِلَى عِقَالٍ أَبْيَضَ فَجَعَلْتُهُمَا تَحْتَ ��ِسَادَتِي فَجَعَلْتُ أَنْظُرُ فِي اللَّيْلِ فَلَا يَسْتَبِينُ لِي فَغَدَوْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ ذَلِكَ فَقَالَ إِنَّمَا ذَلِكَ سَوَادُ اللَّيْلِ وَبَيَاضُ النَّهَارِ","trj":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada saya [Hushain bin 'Abdurrahman] dari [Asy-Sya'biy] dari ['Adi bin Hatim radliallahu 'anhu] berkata: Ketika turun QS Al Baqarah ayat 197 (\"… hingga terang bagi kalian benang putih dari benang hitam yaitu di waktu fajar\"), maka aku mengambil benang hitam dan benang putih lalu aku letakkan di bawah bantalku untuk aku lihat pada sebagian malam namun tidak tampak olehku. Maka di pagi harinya aku menemui Rasulullah shallallahu 'alaihi wasallam lalu aku ceritakan hal tadi. Maka Beliau bersabda: \"Sesungguhnya yang dimaksud dengan ayat itu adalah gelapnya malam dan terangya siang\". "},{"p":"Bukhari","n":1909,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ عُكَاظٌ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقًا فِي الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ فَكَأَنَّهُمْ تَأَثَّمُوا فِيهِ فَنَزَلَتْ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ قَرَأَهَا ابْنُ عَبَّاسٍ","trj":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"'Ukazh, Majannah dan Dzul Majaz adalah nama-nama pasar di zaman Jahiliyyah. Ketika Islam datang mereka seakan-akan merasa berdosa bila tetap berdagang di pasar-pasar tersebut. Maka turunlah firman Allah Ta'ala QS Al Baqarah ayat 198 yang artinya: (\"Tidak ada dosa bagi kalian jika mencari karunia rezeqi Rabb kalian…..\"). Ini dilakukan selama musim hajji, menurut pendapat Ibnu 'Abbas radliallahu 'anhuma."},{"p":"Bukhari","n":1942,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا نَزَلَتْ آخِرُ الْبَقَرَةِ قَرَأَهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ فِي الْمَسْجِدِ ثُمَّ حَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","trj":"Telah menceritakan kepada kami [Muhammad bion Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Adh-Dhuha] dari [Masruq] dari ['Aisyah radliallahu 'anha] berkata: \"Ketika turun ayat-ayat terakhir dari surah Al Baqarah, Nabi shallallahu 'alaihi wasallam menerima ayat-ayat tersebut ketika sedang berada di masjid maka kemudian Beliau mengharamkan jual beli didalam masjid\"."},{"p":"Bukhari","n":1956,"ar":"حَدَّثَنَا عَلِيُّ بْن�� عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ عُكَاظٌ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقًا فِي الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ تَأَثَّمُوا مِنْ التِّجَارَةِ فِيهَا فَأَنْزَلَ اللَّهُ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ قَرَأَ ابْنُ عَبَّاسٍ كَذَا","trj":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"'Ukazh, Majannah dan Dzul Majaz adalah nama-nama pasar di zaman Jahiliyyah. Ketika Islam datang mereka seakan merasa berdosa bila tetap berdagang di pasar-pasar tersebut. Maka turunlah firman Allah Ta'ala QS Al Baqarah ayat 198 yang artinya: (\"Tidak ada dosa bagi kalian jika mencari karunia rezeqi Rabb kalian…..\"). Ini dilakukan selama musim hajji, menurut pendapat Ibnu 'Abbas radliallahu 'anhuma."},{"p":"Bukhari","n":2074,"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَالَمَّا نَزَلَتْ آيَاتُ سُورَةِ الْبَقَرَةِ عَنْ آخِرِهَا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ حُرِّمَتْ التِّجَارَةُ فِي الْخَمْرِ","trj":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Adh-Dhuhaa] dari [Masruq] dari ['Aisyah radliallahu 'anha]; Ketika turun ayat-ayat akhir dari Surah Al Baqarah, Nabi shallallahu 'alaihi wasallam keluar lalu bersabda: \"Telah diharamkan perdagangan khamar (minuman keras) \"."},{"p":"Bukhari","n":2179,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَيَقُولُونَ إِنَّ أَبَا هُرَيْرَةَ يُكْثِرُ الْحَدِيثَ وَاللَّهُ الْمَوْعِدُ وَيَقُولُونَ مَا لِلْمُهَاجِرِينَ وَالْأَنْصَارِ لَا يُحَدِّثُونَ مِثْلَ أَحَادِيثِهِ وَإِنَّ إِخْوَتِي مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَإِنَّ إِخْوَتِي مِنْ الْأَنْصَارِ كَانَ يَشْغَلُهُمْ عَمَلُ أَمْوَالِهِمْ وَكُنْتُ امْرَأً مِسْكِينًا أَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مِلْءِ بَطْنِي فَأَحْضُرُ حِينَ يَغِيبُونَ وَأَعِي حِينَ يَنْسَوْنَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا لَنْ يَبْسُطَ أَحَدٌ مِنْكُمْ ثَوْبَهُ حَتَّى أَقْضِيَ مَقَالَتِي هَذِهِ ثُمَّ يَجْمَعَهُ إِلَى صَدْرِهِ فَيَنْسَى مِنْ مَقَالَتِي شَيْئًا أَبَدًا فَبَسَطْتُ نَمِرَةً لَيْسَ عَلَيَّ ثَوْبٌ غَيْرُهَا حَتَّى قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَالَتَهُ ثُمَّ جَمَعْتُهَا إِلَى صَدْرِي فَوَالَّذِي بَعَثَهُ بِالْحَقِّ مَا نَسِيتُ مِنْ مَقَالَتِهِ تِلْكَ إِلَى يَوْمِي هَذَا وَاللَّهِ لَوْلَا آيَتَانِ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُكُمْ شَيْئًا أَبَدًا{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى إِلَى قَوْلِهِ الرَّحِيمُ }","trj":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] berkata: Sesungguhgnya orang-orang mengatakan: \"Abu Hurairah adalah yang paling banyak menyampaikan hadits dan Allah Maha Memenuhi janji. Dan mereka berkata: \"Mengapa Muhajirin dan Anshar menampaikan hadits tidak sebanyak yang aku sampaikan?\" Sesungguhnya saudara-saudaraku dari kalangan Muhajirin mereka disibukkan dengan berdagang di pasar-pasar dan saudara-saudaraku dari kalangan Anshar mereka disibukkan dengan pekerjaan mereka dalam mengurus harta mereka (bercocok tanam). Adapun aku adalah seorang yang miskin, aku selalu bermulazamah (mendampingi) Rasulullah shallallahu 'alaihi wasallam dengan isi perut sekedar kebutuhan pokok, dan aku selalu hadir (dalam majelis) saat mereka tidak bisa hadir dan dapat menjaga hafalan saat mereka lupa\". Dan pada suatu hari Nabi shallallahu 'alaihi wasallam bersabda: \"Sekali-kali janganlah seorang dari kalian menghamparkan kainnya sebelum aku selesai menyampaikan sabdaku ini lalu dia mengumpulkannya dalam dadanya yang akhirnya dia melupakan sesuatu dari sabdaku untuk selamanya\". Maka aku hamparkan kainku yang bermotif karena aku tidak memiliki kain yang lain hingga Nabi shallallahu 'alaihi wasallam selesai menyampaikan sabda Beliau lalu aku kumpulkan dalam dadaku\". Maka demi Dzat yang mengutus Beliau dengan haq, tidaklah aku lupa satupun dari sabda Beliau hingga hari ini dan demi Allah, kalau bukan karena dua ayat dalam Kitabulloh maka aku tidak akan menyampaikannya sesuatu haditspun kepada kalian selamanya\". (Lalu dia membaca ayat 159 dan 160 dari surah Al Baqarah yang artinya: ('Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa penjelasan dan petunjuk ……hingga akhir ayat.. Allah Maha Penyayang) "},{"p":"Bukhari","n":3045,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجِيءُ نُوحٌ وَأُمَّتُهُ فَيَقُولُ اللَّهُ تَعَالَى هَلْ بَلَّغْتَ فَيَقُ��لُ نَعَمْ أَيْ رَبِّ فَيَقُولُ لِأُمَّتِهِ هَلْ بَلَّغَكُمْ فَيَقُولُونَ لَا مَا جَاءَنَا مِنْ نَبِيٍّ فَيَقُولُ لِنُوحٍ مَنْ يَشْهَدُ لَكَ فَيَقُولُ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمَّتُهُ فَنَشْهَدُ أَنَّهُ قَدْ بَلَّغَوَهُوَ قَوْلُهُ جَلَّ ذِكْرُهُ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا لِتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ }وَالْوَسَطُ الْعَدْلُ","trj":"Telah bercerita kepada kami [Musa bin Isma'il] telah bercerita kepada kami ['Abdul Wahid bin Ziyad] telah bercerita kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Pada hari qiyanat) Nabi Nuh 'alaihissalam dan ummatnya datang lalu Allah Ta'ala berfirman: \"Apakah kamu telah menyampaikan (ajaran)?. Nuh 'Alaihissalam menjawab: \"Sudah, wahai Rabbku\". Kemudian Allah bertanya kepada ummatnya: \"Apakah benar dia telah menyampaikan kepada kalian?\". Mereka menjawab; \"Tidak. Tidak ada seorang Nabi pun yang datang kepada kami\". Lalu Allah berfirman kepada Nuh 'alaihissalam: \"Siapa yang menjadi saksi atasmu?\". Nabi Nuh Alaihissalam berkata; \"Muhammad shallallahu 'alaihi wasallam dan ummatnya\". Maka kami pun bersaksi bahwa Nabi Nuh 'alaihissalam telah menyampaikan risalah yang diembannya kepada ummatnya. Begitulah seperti yang difirmankan Allah Yang Maha Tinggi (QS al-Baqarah ayat 143 yang artinya), (\"Dan demikianlah kami telah menjadikan kalian sebagai ummat pertengahan untuk menjadi saksi atas manusia..\"). al-washathu artinya al-'adl (adil)."},{"p":"Bukhari","n":3064,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَحْنُ أَحَقُّ بِالشَّكِّ مِنْ إِبْرَاهِيمَ إِذْ قَالَ{ رَبِّ أَرِنِي كَيْفَ تُحْيِي الْمَوْتَى قَالَ أَوْ لَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي }وَيَرْحَمُ اللَّهُ لُوطًا لَقَدْ كَانَ يَأْوِي إِلَى رُكْنٍ شَدِيدٍ وَلَوْ لَبِثْتُ فِي السِّجْنِ طُولَ مَا لَبِثَ يُوسُفُ لَأَجَبْتُ الدَّاعِيَ","trj":"Telah bercerita kepada kami [Ahmad bin Shalih] telah bercerita kepada kami [Ibnu Wahb] berkata telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah bin 'Abdur Rahman] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami lebih patut untuk ragu dibanding Ibrahim ketika dia berkata; (Ya Rabbku, tunjukkan kepadaku bagaimana caranya Engkau menghidupkan makhluq yang sudah mati. Allah berfirman; \"Apakah kamu tidak beriman (belum yakin)?\" Ibrahim berkata; \"Aku telah meyakininya akan tetapi untuk memantapkan hatiku\"). Dan semoga Allah merahmati Nabi Luth 'Alaihissalam yang telah berlindung kepada keluarga yang kuat. Dan seandainya aku dipenjara dan mendekam didalamnya dalam masa tertentu sebagaimana Nabi Yusuf 'Alaihissalam mengalaminya tentu aku sudah bersegera memenuhi permintaan (orang yang akan membebaskan aku) \". (QS. Albaqarah 260)."},{"p":"Bukhari","n":3094,"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لِبَنِي إِسْرَائِيلَ{ ادْخُلُوا الْبَابَ سُجَّدًا وَقُولُوا حِطَّةٌ }فَبَدَّلُوا فَدَخَلُوا يَزْحَفُونَ عَلَى أَسْتَاهِهِمْ وَقَالُوا حَبَّةٌ فِي شَعْرَةٍ","trj":"Telah bercerita kepadaku [Ishaq bin Nashr] telah bercerita kepada kami ['Abdur Razzaq] dari [Ma'mar] dari [Hammam bin Munabbih] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dikatakan kepada Bani Isra'il, (\"masuklah kalian ke dalam pintu gerbang sambil bersujud dan katakanlah; bebaskanlah kami dari dosa\"), (QS al-Baqarah ayat 58). Namun mereka menukarnya dan masuk sambil merayap di atas pantat mereka sambil berkata: \"buah gandum\""},{"p":"Bukhari","n":3816,"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُأَقْرَؤُنَا أُبَيٌّ وَأَقْضَانَا عَلِيٌّ وَإِنَّا لَنَدَعُ مِنْ قَوْلِ أُبَيٍّ وَذَاكَ أَنَّ أُبَيًّا يَقُولُ لَا أَدَعُ شَيْئًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ قَالَ اللَّهُ تَعَالَى{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا }","trj":"Telah menceritakan kepada kami ['Amru bin 'Ali] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Sufyan] dari [Habib] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; ['Umar radliallahu 'anhu] berkata; \"Ubay adalah orang yang paling pandai dalam membaca Al Qur'an di antara kami, dan Ali adalah orang yang paling paham dengan hukum di antara kami. Sementara kami banyak meninggalkan qira`ah Ubay (dalam membaca Al Qur'an). Karena [Ubay] pernah berkata, \"Aku tidak akan meninggalkan sesuatu yang telah aku dengar dari Rasulullah. Sementara Allah Tabaraka Wa Ta'ala berfirman: '(Ayat mana saja yang kami nasakhkan, atau kami jadikan (manusia) lupa kepadanya, kami datangkan yang lebih baik daripadanya atau yang sebanding dengannya) ' (QS. Al Baqarah: 106)."},{"p":"Bukhari","n":3822,"ar":"حَدَّثَنَا يُوسُفُ بْنُ رَاشِدٍ حَدَّثَنَا جَرِيرٌ وَأَبُو أُسَامَةَ وَاللَّفْظُ لِجَرِيرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ وَقَالَ أَبُو أُسَامَةَ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُدْعَى نُوحٌ يَوْمَ الْقِيَامَةِ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ يَا رَبِّ فَيَقُولُ هَلْ بَلَّغْتَ فَيَقُولُ نَعَمْ فَيُقَالُ لِأُمَّتِهِ هَلْ بَلَّغَكُمْ فَيَقُولُونَ مَا أَتَانَا مِنْ نَذِيرٍ فَيَقُولُ مَنْ يَشْهَدُ لَكَ فَيَقُولُ مُحَمَّدٌ وَأُمَّتُهُ فَتَشْهَدُونَ أَنَّهُ قَدْ بَلَّغَ{ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }فَذَلِكَ قَوْلُهُ جَلَّ ذِكْرُهُ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا لِتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }وَالْوَسَطُ الْعَدْلُ","trj":"Telah menceritakan kepada kami [Yusuf bin Rasyid] Telah menceritakan kepada kami [Jarir] dan [Abu Usamah] dan lafazh ini milik Jarir dari [Al A'masy] dari [Abu Shalih], Abu Usamah berkata; Telah menceritakan kepada kami Abu Shalih dari [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Pada hari kiamat, Nuh akan dipanggil (Allah) dan ia akan menjawab: 'Labbaik dan Sa'daik, wahai TuhanKu! ' lalu Allah bertanya: 'Apakah telah kau sampaikan pesan Kami? ' Nuh menjawab: 'Ya'. Kemudian Allah akan bertanya kepada bangsa (umat) Nuh: 'Apakah ia telah menyampaikan pesan kami kepadamu sekalian? ' Mereka akan berkata; 'Tidak ada yang memberikan peringatan kepada kami.' Maka Allah bertanya: 'Siapa yang menjadi saksimu? ' Nuh menjawab: 'Muhammad shallallahu 'alaihi wasallam dan para pengikutnya.' Maka mereka (umat muslim) akan bersaksi bahwa Nuh telah menyampaikan pesan (Allah). Kemudian Rasul (Muhammad shallallahu 'alaihi wasallam) akan menjadi saksi untukmu sekalian dan itulah maksud dari firman Allah: 'Demikianlah kami jadikan kalian sebagai umat yang adil supaya kamu menjadi saksi atas manusia. Dan Rasul menjadi saksi atas kalian.\" (QS. Al Baqarah (2): 143)."},{"p":"Bukhari","n":3830,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ قُلْتُ لِعَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّ أَرَأَيْتِ قَوْلَ اللَّهِ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَمَا أُرَى عَلَى أَحَدٍ شَيْئًا أَنْ لَا يَطَّوَّفَ بِهِمَا فَقَالَتْ عَائِشَةُ كَلَّا لَوْ كَانَتْ كَمَا تَقُولُ كَانَتْ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي الْأَنْصَارِ كَانُوا يُهِلُّونَ لِمَنَاةَ وَكَانَتْ مَنَاةُ حَذْوَ قُدَيْدٍ وَكَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا جَاءَ الْإِسْلَامُ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","trj":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Hisyam bin Urwah] dari [Bapaknya] dia berkata; Aku bertanya kepada [Aisyah] istri Rasulullah shallallahu 'alaihi wasallam, -Saat itu saya masih muda-: 'Apakah anda tahu tentang firman Allah Tabaraka Wa Ta'ala: 'Sesungguhnya Shafaa dan Marwa adalah sebahagian dari syi'ar Allah. Barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.' Sebab sepengetahuanku nggak masalah bagi seseorang untuk meninggalkan Sa'i antara keduanya. Aisyah menjawab; \"Bukan begitu, kalau seperti yang kamu katakan, maka jadinya tidak ada dosa orang tidak melakukan sa'i. Ayat ini turun pada orang-orang Anshar, yang dahulu mereka melakukan talbiyah karena Manat, yang letaknya di depan Qadid. Yang mereka berkeharusan berthawaf antara Shofa dan Marwa. Tatkala Islam datang, mereka bertanya pada Rasulullah shallallahu 'alaihi wasallam tentang hal itu. Maka Allah Tabaraka Wa Ta'ala menurunkan ayat: 'Sesungguhnya Shafa dan Marwa adalah sebagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber-'umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya'.\" (QS. Albaqarah 158)."},{"p":"Bukhari","n":3831,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ الصَّفَا وَالْمَرْوَةِ فَقَالَ كُنَّا نَرَى أَنَّهُمَا مِنْ أَمْرِ الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ أَمْسَكْنَا عَنْهُمَا فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari ['Ashim bin Sulaiman] dia berkata; Aku bertanya kepada [Anas bin Malik radliallahu 'anhu] tentang Shafa dan Marwa. Maka dia menjawab; Aku menganggap keduanya sebagai perkara jahiliyah, tatkala Islam datang, keduanya kami tinggalkan lalu turunlah firman Allah; \"Sesungguhnya Shafa dan Marwa adalah sebagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber-'umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.\" (QS. Albaqarah 158)."},{"p":"Bukhari","n":3833,"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو قَالَ سَمِعْتُ مُجَاهِدًا قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُكَانَ فِي بَنِي إِسْرَائِيلَ الْقِصَاصُ وَلَمْ تَكُنْ فِيهِمْ الدِّيَةُ فَقَالَ اللَّهُ تَعَالَى لِهَذِهِ الْأُمَّةِ{ كُتِبَ عَلَيْكُمْ الْقِصَاصُ فِي الْقَتْلَى الْحُرُّ بِالْحُرِّ وَالْعَبْدُ بِالْعَبْدِ وَالْأُنْثَى بِالْأُنْثَى فَمَنْ عُفِيَ لَهُ مِنْ أَخِيهِ شَيْءٌ }فَالْعَفْوُ أَنْ يَقْبَلَ الدِّيَةَ فِي الْعَمْدِ{ فَاتِّبَاعٌ بِالْمَعْرُوفِ وَأَدَاءٌ إِلَيْهِ بِإِحْسَانٍ }يَتَّبِعُ بِالْمَعْرُوفِ وَيُؤَدِّي بِإِحْسَانٍ{ ذَلِكَ تَخْفِيفٌ مِنْ رَبِّكُمْ وَرَحْمَةٌ }مِمَّا كُتِبَ عَلَى مَنْ كَانَ قَبْلَكُمْ{ فَمَنْ اعْتَدَى بَعْدَ ذَلِكَ فَلَهُ عَذَابٌ أَلِيمٌ }قَتَلَ بَعْدَ قَبُولِ الدِّيَةِ","trj":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Amru] dia berkata; Aku mendengar [Mujahid] berkata; Aku mendengar [Ibnu Abbas radliallahu 'anhuma] berkata; \"Dahulu pada Bani Israil terdapat hukum qishas namun tidak ada diyah pada mereka, lalu Allah Azza wa jalla menurunkan ayat: \"Hai orang-orang yang beriman, diwajibkan atas kamu qishaash berkenaan dengan orang-orang yang dibunuh; orang merdeka dengan orang merdeka, hamba dengan hamba, dan wanita dengan wanita. Maka barangsiapa yang mendapat suatu pema'afan dari saudaranya, hendaklah (yang mema'afkan) mengikuti dengan cara yang baik, dan hendaklah (yang diberi ma'af) membayar (diat) kepada yang memberi ma'af dengan cara yang baik (pula). (QS. Albaqarah 178). Pemberian maaf itu maksudnya adalah menerima diyat pada pembunuhan dengan sengaja. mengikuti dengan cara yang baik yaitu ia mengikuti ini dengan cara yang ma'ruf, dan membayar dengan cara yang baik serta melaksanakan ini dengan kebaikan. Yang demikian itu adalah suatu keringanan dari Tuhan kamu dan suatu rahmat (QS. Albaqarah 178) dari apa yang telah diwajibkan atas kaum sebelum kalian, sesungguhnya hal tersebut adalah qishas bukan diyah. Barang siapa yang melampui batas setelah itu, maka baginya Adzab yang pedih.' Yaitu membunuh setelah menerima diyah."},{"p":"Bukhari","n":3840,"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا رَوْحٌ حَدَّثَنَا زَكَرِيَّاءُ بْنُ إِسْحَاقَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عَطَاءٍ سَمِعَ ابْنَ عَبَّاسٍيَقْرَأُ وَعَلَى الَّذِينَ يُطَوَّقُونَهُ فَلَا يُطِيقُونَهُ{ فِدْيَةٌ طَعَامُ مِسْكِينٍ }قَالَ ابْنُ عَبَّاسٍ لَيْسَتْ بِمَنْسُوخَةٍ هُوَ الشَّيْخُ الْكَبِيرُ وَالْمَرْأَةُ الْكَبِيرَةُ لَا يَسْتَطِيعَانِ أَنْ يَصُومَا فَيُطْعِمَانِ مَكَانَ كُلِّ يَوْمٍ مِسْكِينًا","trj":"Telah menceritakan kepadaku [Ishaq] Telah mengabarkan kepada kami [Rauh] Telah menceritakan kepada kami [Zakaria bin Ishaq] Telah menceritakan kepada kami [Amru bin Dinar] dari [Atha] dia mendengar [Ibnu Abbas] membaca ayat; \"Dan bagi orang-orang yang berat menjalankannya maka wajib membayar fidya yaitu memberi makan orang miskin, \"(QS. Albaqarah 184), Ibnu Abbas berkata; Ayat ini tidak dimanshukh, namun ayat ini hanya untuk orang yang sudah sangat tua dan nenek tua, yang tidak mampu menjalankannya, maka hendaklah mereka memberi makan setiap hari kepada orang miskin.'"},{"p":"Bukhari","n":3852,"ar":"حَدَّثَنِي مُحَمَّدٌ قَالَ أَخْبَرَنِي ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ عُكَاظُ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقًا فِي الْجَاهِلِيَّةِ فَتَأَثَّمُوا أَنْ يَتَّجِرُوا فِي الْمَوَاسِمِ فَنَزَلَتْ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ","trj":"Telah menceritakan kepadaku [Muhammad] dia berkata; Telah mengabarkan kepadaku [Ibnu Uyainah] dari [Amru] dari [Ibnu Abbas radliallahu 'anhuma] dia berkata; Ukazh, Majanah, Dzul Majaz adalah pasar-pasar yang ada pada masa jahiliyah. Mereka merasa takut berdosa bila berjualan pada musim haji. Maka turunlah ayat; Bukanlah suatu dosa bagimu sekalian mencari karunia dari Rabb kalian. (QS. Albaqarah 198). Yaitu pada musim haji."},{"p":"Bukhari","n":3853,"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ خَازِمٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَانَتْ قُرَيْشٌ وَمَنْ دَانَ دِينَهَا يَقِفُونَ بِالْمُزْدَلِفَةِ وَكَانُوا يُسَمَّوْنَ الْحُمْسَ وَكَانَ سَائِرُ الْعَرَبِ يَقِفُونَ بِعَرَفَاتٍ فَلَمَّا جَاءَ الْإِسْلَامُ أَمَرَ اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْتِيَ عَرَفَاتٍ ثُمَّ يَقِفَ بِهَا ثُمَّ يُفِيضَ مِنْهَا فَذَلِكَ قَوْلُهُ تَعَالَى{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }","trj":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Muhammad bin Hazim] Telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari [Aisyah radliallahu 'anha], Suku Quraisy dan orang-orang yang memeluk agama mereka, biasa tinggal di Muzdalifah dan memanggil diri mereka sendiri dengan Al Hums, sementara orang-orang Arab lainnya biasa tinggal di Arafah. Ketika Islam datang, Allah memerintahkan Nabi shallallahu 'alaihi wasallam untuk tinggal di sana (dengan waktu yang telah ditentukan) dan kemudian berangkat dari sana. Itulah yang dimaksud firman Allah; \"Kemudian berangkatlah beramai-ramai dari tempat bertolaknya orang banyak\". (QS. Albaqarah 199)."},{"p":"Bukhari","n":3854,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي كُرَيْبٌ عَنْ ابْنِ عَبَّاسٍ قَالَيَطَّوَّفُ الرَّجُلُ بِالْبَيْتِ مَا كَانَ حَلَالًا حَتَّى يُهِلَّ بِالْحَجِّ فَإِذَا رَكِبَ إِلَى عَرَفَةَ فَمَنْ تَيَسَّرَ لَهُ هَدِيَّةٌ مِنْ الْإِبِلِ أَوْ الْبَقَرِ أَوْ الْغَنَمِ مَا تَيَسَّرَ لَهُ مِنْ ذَلِكَ أَيَّ ذَلِكَ شَاءَ غَيْرَ أَنَّهُ إِنْ لَمْ يَتَيَسَّرْ لَهُ فَعَلَيْهِ ثَلَاثَةُ أَيَّامٍ فِي الْحَجِّ وَذَلِكَ قَبْلَ يَوْمِ عَرَفَةَ فَإِنْ كَانَ آخِرُ يَوْمٍ مِنْ الْأَيَّامِ الثَّلَاثَةِ يَوْمَ عَرَفَةَ فَلَا جُنَاحَ عَلَيْهِ ثُمَّ لِيَنْطَلِقْ حَتَّى يَقِفَ بِعَرَفَاتٍ مِنْ صَلَاةِ الْعَصْرِ إِلَى أَنْ يَكُونَ الظَّلَامُ ثُمَّ لِيَدْفَعُوا مِنْ عَرَفَاتٍ إِذَا أَفَاضُوا مِنْهَا حَتَّى يَبْلُغُوا جَمْعًا الَّذِي يَبِيتُونَ بِهِ ثُمَّ لِيَذْكُرُوا اللَّهَ كَثِيرًا وَأَكْثِرُوا التَّكْبِيرَ وَالتَّهْلِيلَ قَبْلَ أَنْ تُصْبِحُوا ثُمَّ أَفِيضُوا فَإِنَّ النَّاسَ كَانُوا يُفِيضُونَ وَقَالَ اللَّهُ تَعَالَى{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ وَاسْتَغْفِرُوا اللَّهَ إِنَّ اللَّهَ غَفُورٌ رَحِيمٌ }حَتَّى تَرْمُوا الْجَمْرَةَ","trj":"Telah menceritakan kepadaku [Muhammad bin Abu Bakr] Telah menceritakan kepada kami [Fudlail bin Sulaiman] Telah menceritakan kepada kami [Musa bin 'Uqbah] Telah mengabarkan kepadaku [Kuraib] dari [Ibnu 'Abbas] dia berkata; seseorang berthawaf di ka'bah setelah bertahalul hingga dia bertalbiyah untuk haji. Apabila dia hendak pergi ke Arafah, maka hendaklah dia menyembelih unta, atau sapi, atau kambing kapan saja dia kehendaki jika hal itu mudah baginya. Jika hal itu terasa sulit, maka hendaklah dia berpuasa selama tiga hari pada waktu haji, yaitu sebelum hari Arafah. Jika ternyata hari terakhirnya dari tiga hari tersebut adalah hari Arafah, maka hal itu tidak mengapa baginya. Kemudian hendaklah dia berangkat untuk wukuf di Arafah dari waktu Ashar hingga menjelang malam. Lalu berangkat dari Arafah ketika orang-orang keluar darinya hingga sampai di Muzdalifah tempat mereka bermalam. setelah itu hendaklah mereka berdzikir kepada Allah dengan memperbanyak takbir, dan tahlil sebelum subuh tiba. Kemudian bertolaklah kalian dari Arafah karena orang-orang telah bertolak. Allah Ta'ala berfirman: \"Kemudian bertolaklah dari tempat bertolaknya orang-orang banyak ('Arafah) dan mohonlah ampun kepada Allah sesungguhnya Allah Maha Pengampun lagi Maha Penyayang.\" (QS. Albaqarah 199). Hingga kalian melempar Jumrah."},{"p":"Bukhari","n":3858,"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ نَافِعٍ قَالَ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاإِذَا قَرَأَ الْقُرْآنَ لَمْ يَتَكَلَّمْ حَتَّى يَفْرُغَ مِنْهُ فَأَخَذْتُ عَلَيْهِ يَوْمًا فَقَرَأَ سُورَةَ الْبَقَرَةِ حَتَّى انْتَهَى إِلَى مَكَانٍ قَالَ تَدْرِي فِيمَ أُنْزِلَتْ قُلْتُ لَا قَالَ أُنْزِلَتْ فِي كَذَا وَكَذَا ثُمَّ مَضَىوَعَنْ عَبْدِ الصَّمَدِ حَدَّثَنِي أَبِي حَدَّثَنِي أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ{ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }قَالَ يَأْتِيهَا فِي رَوَاهُ مُحَمَّدُ بْنُ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ","trj":"Telah menceritakan kepada kami [Ishaq] Telah mengabarkan kepada kami [An Nadlr bin Syumail] Telah mengabarkan kepada kami [Ibnu Aun] dari [Nafi'] dia berkata; [Ibnu Umar radliallahu 'anhuma] apabila membaca Al Qur'an, beliau tidak berbicara hingga selesai membacanya. Pada suatu hari aku mengambil mushaf-nya, maka membaca surat Al Baqarah hingga selesai dengan hafalannya. Lalu dia berkata; tahukah kamu tentang apa surat ini turun? Aku menjawab; 'Tidak.' Dia berkata; surat ini turun tentang ini dan itu kemudian dia pergi.' Dan dari [Abdus Shamad] Telah menceritakan kepadaku [ayahku] telah menceritakan kepadaku [Ayyub] dari [Nafi] dari [Ibnu Umar] mengenai ayat; \"istri-istrimu adalah ladang bagimu maka datangilah ladang-ladangmu kapan saja sesuai yang kamu sukai\".(QS. Albaqarah 223), Ibnu Umar berkata; yaitu mendatanginya dari kemaluannya. Diriwayatkan oleh [Muhammad bin Yahyan bin Sa'id] dari [Bapaknya] dari [Ubaidullah] dari [Nafi] dari [Ibnu Umar]."},{"p":"Bukhari","n":3859,"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ سَمِعْتُ جَابِرًا رَضِيَ اللَّهُ عَنْهُ قَالَكَانَتْ الْيَهُودُ تَقُولُ إِذَا جَامَعَهَا مِنْ وَرَائِهَا جَاءَ الْوَلَدُ أَحْوَلَ فَنَزَلَتْ{ نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }","trj":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Ibnu Al Munkadir] aku mendengar [Jabir radliallahu 'anhu] berkata; Orang-orang Yahudi berkata; Apabila menggauli wanita melalui belakang maka mata anaknya akan menjadi juling'. Lalu Allah Subhaanahu menurunkan ayat; Isteri-isteri kalian adalah ladang kalian, maka datangilah ladang kalian dari mana engkau kehendaki.\" (QS. Albaqarah 223)."},{"p":"Bukhari","n":3860,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ حَدَّثَنَا الْحَسَنُ قَالَ حَدَّثَنِي مَعْقِلُ بْنُ يَسَارٍ قَالَ كَانَتْ لِي أُخْتٌ تُخْطَبُ إِلَيَّ وَقَالَ إِبْرَاهِيمُ عَنْ يُونُسَ عَنْ الْحَسَنِ حَدَّثَنِي مَعْقِلُ بْنُ يَسَارٍ ح حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِأَنَّ أُخْتَ مَعْقِلِ بْنِ يَسَارٍ طَلَّقَهَا زَوْجُهَا فَتَرَكَهَا حَتَّى انْقَضَتْ عِدَّتُهَا فَخَطَبَهَا فَأَبَى مَعْقِلٌ فَنَزَلَتْ{ فَلَا تَعْضُلُوهُنَّ أَنْ يَنْكِحْنَ أَزْوَاجَهُنَّ }","trj":"Telah menceritakan kepada kami [Ubaidullah bin Sa'id] Telah menceritakan kepada kami [Abu Amir Al 'Aqidi] Telah menceritakan kepada kami [Abbad bin Rasyid] Telah menceritakan kepada kami [Al Hasan] dia berkata; Telah menceritakan kepadaku [Ma'qil bin Yasar] berkata; aku mempunyai saudara perempuan yang dilamar kepadaku. Dan [Ibrahim] berkata; dari [Yunus] dari [Al Hasan] telah menceritakan kepadaku [Ma'qil bin Yasar]. -diriwayatkan dari jalur lainnya- Telah menceritakan kepada kami [Abu Ma'mar] Telah menceritakan kepada kami [Abdul Warits] Telah menceritakan kepada kami [Yunus] dari [Al Hasan] bahwa saudara perempuan Ma'qil ditalak suaminya dan meninggalkannya hingga habis masa iddahnya. Kemudian dia meminangnya lagi, namun Ma'qil menolaknya. Maka turunlah ayat; Jangalah kamu halangi mereka untuk menikah lagi dengan suaminya. (QS. Albaqarah 232)."},{"p":"Bukhari","n":3862,"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا رَوْحٌ حَدَّثَنَا شِبْلٌ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا }قَالَ كَانَتْ هَذِهِ الْعِدَّةُ تَعْتَدُّ عِنْدَ أَهْلِ زَوْجِهَا وَاجِبٌ فَأَنْزَلَ اللَّهُ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِي أَنْفُسِهِنَّ مِنْ مَعْرُوفٍ }قَالَ جَعَلَ اللَّهُ لَهَا تَمَامَ السَّنَةِ سَبْعَةَ أَشْهُرٍ وَعِشْرِينَ لَيْلَةً وَصِيَّةً إِنْ شَاءَتْ سَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ وَهْوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ }فَالْعِدَّةُ كَمَا هِيَ وَاجِبٌ عَلَيْهَا زَعَمَ ذَلِكَ عَنْ مُجَاهِدٍ وَقَالَ عَطَاءٌ قَالَ ابْنُ عَبَّاسٍنَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا عِنْدَ أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ وَهْوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ }قَالَ عَطَاءٌ إِنْ شَاءَتْ اعْتَدَّتْ عِنْدَ أَهْلِهِ وَسَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ لِقَوْلِ اللَّهِ تَعَالَى{ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ }قَالَ عَطَاءٌ ثُمَّ جَاءَ الْمِيرَاثُ فَنَسَخَ السُّكْنَى فَتَعْتَدُّ حَيْثُ شَاءَتْ وَلَا سُكْنَى لَهَا وَعَنْ مُحَمَّدِ بْنِ يُوسُفَ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ بِهَذَا وَعَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ نَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا فِي أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ لِقَوْلِ اللَّهِ{ غَيْرَ إِخْرَاجٍ }نَحْوَهُ","trj":"Telah menceritakan kepada kami [Ishaq] Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Syibl] dari [Ibnu Abu Najih] dari Mujahid mengenai firman Allah: Dan orang-orang yang mati di antara kamu serta meninggalkan istri-istri (Al Baqarah; 234). Ayat ini menerangkan wajibnya iddah di rumah keluarganya. Lalu Allah menurunkan ayat; Dan orang-orang yang akan mati di antara kami dan meninggalkan istri-istri, hendaklah membuat wasiat untuk istri-istrinya yaitu nafkah sampai setahun tanpa mengeluarkannya dari rumah. Tetapi jika mereka keluar sendiri, maka tidak ada dosa bagimu mengenai apa yang mereka lakukan terhadap diri mereka sendiri dalam hal-hal yang baik. Mujahid berkata; Allah telah menjadikannya sebagai penyempurna dalam hitungan setahun yaitu tujuh bulan dan dua puluh malam sebagai wasiat. Apabila dia ingin, maka dia menempati sesuai wasiat tersebut. Namun jika ia ingin keluar, maka itu sudah menjadi kehendaknya. Itulah yang dimaksud firman Allah Ta'ala: Tetapi jika mereka keluar sendiri, maka tidak ada dosa bagimu. Maka Iddah adalah perkara yang wajib. Perawi mengaku itu dari Mujahid. [Atha] berkata; [Ibnu Abbas] berkata; \"Ayat ini telah menghapus 'iddah di rumah keluarganya sehingga ia ber'iddah di tempat yang ia kehendaki, yaitu firman Allah Azza wa Jalla: 'Tanpa keluar rumah.' Atha berkata; 'Jika dia berkehendak, maka dia beriddah di rumah keluarganya dan tinggal sesuai wasiatnya.' Namun jika dia berkehendak, ia keluar darinya. Sebagaimana firman Allah Ta'ala: \"Maka tidak ada dosa bagimu mengenai apa yang mereka lakukan terhadap diri mereka senidiri.\" (QS. Albaqarah 240), Atha berkata; kemudian turun ayat mirats (mengenai warisan) yang menghapus mengenai tempat tinggal, maka dia boleh beriddah sesuai kehendaknya tanpa harus tinggal dirumahnya. Dan dari [Muhammad bin Yusuf] Telah menceritakan kepada kami [Warqa] dari [Ibnu Abu Najih] dari Mujahid dengan redaksi yang serupa. Dan dari Ibnu Abu Najih dari [Atha] dari [Ibnu Abbas] dia berkata; 'ayat ini telah menghapus 'iddahnya di rumah keluarganya sehingga ia ber'iddah di tempat yang ia kehendaki, yaitu firman Allah Azza wa Jalla: 'Tanpa keluar rumah.'"},{"p":"Bukhari","n":3867,"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا حُمَيْدُ بْنُ الْأَسْوَدِ وَيَزِيدُ بْنُ زُرَيْعٍ قَالَا حَدَّثَنَا حَبِيبُ بْنُ الشَّهِيدِ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ قَالَ ابْنُ الزُّبَيْرِقُلْتُ لِعُثْمَانَ هَذِهِ الْآيَةُ الَّتِي فِي الْبَقَرَةِ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا إِلَى قَوْلِهِ غَيْرَ إِخْرَاجٍ }قَدْ نَسَخَتْهَا الْأُخْرَى فَلِمَ تَكْتُبُهَا قَالَ تَدَعُهَا يَا ابْنَ أَخِي لَا أُغَيِّرُ شَيْئًا مِنْهُ مِنْ مَكَانِهِقَالَ حُمَيْدٌ أَوْ نَحْوَ هَذَا","trj":"Telah menceritakan kepadaku [Abdullah bin Abu Al Aswad] Telah menceritakan kepada kami [Humaid bin Al Aswad] dan [Yazid bin Zurai'i] keduanya berkata; Telah menceritakan kepada kami [Habib bin Syahid] dari [Ibnu Abu Mulaikah] dia berkata; [Ibnu Zubair] berkata; Aku bertanya kepada [Utsman] tentang ayat yang terdapat dalam surah Al Baqarah yaitu: Dan orang-orang yang mati di antara kamu serta meninggalkan istri-istri, -hingga ayat-; 'tanpa keluar rumah. (Al Baqarah; 234). Dia menjawab; Ayat itu telah dinasakh dengan ayat yang lain. Lalu aku bertanya; kenapa kamu menulisnya? Dia menjawab; Wahai anak saudaraku, apakah kamu akan meninggalkannya? aku tidak akan merubahnya sedikitpun dari tempatnya. Humaid berkata; atau perkataan yang serupa dengan ini."},{"p":"Bukhari","n":3871,"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا مُسْلِمٌ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا نَزَلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي الرِّبَا قَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النَّاسِ ثُمَّ حَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","trj":"Telah menceritakan kepada kami [Umar bin Hafsh bin Giyats] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Muslim] dari [Masruq] dari [Aisyah radliallahu 'anha] dia berkata; 'Beberapa ayat terakhir dari surat al Baqarah turun mengenai riba. Rasulullah shallallahu 'alaihi wasallam membacakannya kepada orang-orang, kemudian beliau mengharamkan jual beli khamr (minuman keras)."},{"p":"Bukhari","n":3872,"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ الْأَعْمَشِ سَمِعْتُ أَبَا الضُّحَى يُحَدِّثُ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ أَنَّهَا قَالَتْلَمَّا أُنْزِلَتْ الْآيَاتُ الْأَوَاخِرُ مِنْ سُورَةِ الْبَقَرَةِ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَلَاهُنَّ فِي الْمَسْجِدِ فَحَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","trj":"Telah menceritakan kepada kami [Bisyr bin Khalid] Telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman Al A'masy] Aku mendengar [Abu ADluha] bercerita dari [Masruq] dari [Aisyah] dia berkata; Tatkala turun beberapa ayat terakhir dari surat Al Baqarah, Rasulullah shallallahu 'alaihi wasallam keluar lalu membacakannya di masjid. Kemudian beliau mengharamkan jual beli minuman keras.'"},{"p":"Bukhari","n":3873,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا أُنْزِلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ قَرَأَهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ فِي الْمَسْجِدِ وَحَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","trj":"Telah menceritakan kepadaku [Muhammad bin Basyar] Telah menceritakan kepada kami [Gundar] Telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Dluha] dari [Masruq] dari [Aisyah] dia berkata; Tatkala beberapa ayat terakhir dari surat Al Baqarah diturunkan, Rasulullah shallallahu 'alaihi wasallam membacakannya di masjid dan beliau mengharamkan jual beli minuman keras.'"},{"p":"Bukhari","n":3874,"ar":"وَ قَالَ لَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا أُنْزِلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهُنَّ عَلَيْنَا ثُمَّ حَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","trj":"Dan [Muhammad bin Yusuf] berkata kepada kami; dari [Sufyan] dari [Manshur] dan [Al A'masy] dari [Abu Ad Dluha] dari [Masruq] dari [Aisyah] dia berkata; Tatkala beberapa ayat terakhir dari surat Al Baqarah diturunkan, Rasulullah shallallahu 'alaihi wasallam berdiri membacakannya kepada kami kemudian beliau mengharamkan jual beli minuman keras.'"},{"p":"Bukhari","n":4224,"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ قَالَ جَاءَ رَجُلٌ إِلَى ابْنِ عَبَّاسٍ وَأَبُو هُرَيْرَةَ جَالِسٌ عِنْدَهُ فَقَالَ أَفْتِنِي فِي امْرَأَةٍ وَلَدَتْ بَعْدَ زَوْجِهَا بِأَرْبَعِينَ لَيْلَةً فَقَالَ ابْنُ عَبَّاسٍ آخِرُ الْأَجَلَيْنِ قُلْتُ أَنَا{ وَأُولَاتُ الْأَحْمَالِ أَجَلُهُنَّ أَنْ يَضَعْنَ حَمْلَهُنَّ }قَالَ أَبُو هُرَيْرَةَ أَنَا مَعَ ابْنِ أَخِي يَعْنِي أَبَا سَلَمَةَ فَأَرْسَلَ ابْنُ عَبَّاسٍ غُلَامَهُ كُرَيْبًا إِلَى أُمِّ سَلَمَةَ يَسْأَلُهَا فَقَالَتْقُتِلَ زَوْجُ سُبَيْعَةَ الْأَسْلَمِيَّةِ وَهِيَ حُبْلَى فَوَضَعَتْ بَعْدَ مَوْتِهِ بِأَرْبَعِينَ لَيْلَةً فَخُطِبَتْ فَأَنْكَحَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ أَبُو السَّنَابِلِ فِيمَنْ خَطَبَهَاوَقَالَ سُلَيْمَانُ بْنُ حَرْبٍ وَأَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ كُنْتُ فِي حَلْقَةٍ فِيهَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى وَكَانَ أَصْحَابُهُ يُعَظِّمُونَهُ فَذَكَرُوا لَهُ فَذَكَرَ آخِرَ الْأَجَلَيْنِ فَحَدَّثْتُ بِحَدِيثِ سُبَيْعَةَ بِنْتِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ فَضَمَّزَ لِي بَعْضُ أَصْحَابِهِ قَالَ مُحَمَّدٌ فَفَطِنْتُ لَهُ فَقُلْتُ إِنِّي إِذًا لَجَرِيءٌ إِنْ كَذَبْتُ عَلَى عَبْدِ اللَّهِ بْنِ عُتْبَةَ وَهُوَ فِي نَاحِيَةِ الْكُوفَةِ فَاسْتَحْيَا وَقَالَ لَكِنْ عَمُّهُ لَمْ يَقُلْ ذَاكَ فَلَقِيتُ أَبَا عَطِيَّةَ مَالِكَ بْنَ عَامِرٍ فَسَأَلْتُهُ فَذَهَبَ يُحَدِّثُنِي حَدِيثَ سُبَيْعَةَ فَقُلْتُ هَلْ سَمِعْتَ عَنْ عَبْدِ اللَّهِ فِيهَا شَيْئًا فَقَالَ كُنَّا عِنْدَ عَبْدِ اللَّهِ فَقَالَ أَتَجْعَلُونَ عَلَيْهَا التَّغْلِيظَ وَلَا تَجْعَلُونَ عَلَيْهَا الرُّخْصَةَ لَنَزَلَتْ سُورَةُ النِّسَاءِ الْقُصْرَى بَعْدَ الطُّولَى{ وَأُولَاتُ الْأَحْمَالِ أَجَلُهُنَّ أَنْ يَضَعْنَ حَمْلَهُنَّ }","trj":"Telah menceritakan kepada kami [Sa'd bin Hafsh] Telah menceritakan kepada kami [Syaiban] dari [Yahya] ia berkata; Telah mengabarkan kepadaku [Abu Salamah] ia berkata; Seorang laki-laki datang kepada Ibnu Abbas sementara Abu Hurairah sedang duduk. Laki-laki itu berkata, \"Berilah fatwa kepadaku, terhadap seorang wanita yang melahirkan setelah kematian suaminya selang empat puluh malam.\" Maka [Ibnu Abbas] berkata, \"Masa Iddahnya adalah batasan yang paling terakhir (maksudnya empat bulan sepuluh hari, meskipun ia melahirkan sebelum itu).\" [Abu Hurairah] berkata; \"Kalau aku, maka aku sependapat dengan anak saudaraku, yakni Abu Salamah.\" Lalu Ibnu Abbas mengutus pembantunya, [Kuraib], kepada [Ummu Salamah] untuk bertanya kepadanya. Ummu Salamah menjawab, \"Ketika suami Subai'ah Al Aslamiyyah meninggal sementara ia dalam keadaan hamil, lalu melahirkan setelah kematian suaminya selang empat puluh malam. Ia kemudian dikhithbah, dan Rasulullah shallallahu 'alaihi wasallam menikahinya. Abu As Sanabil adalah termasuk salah seorang yang mengkhithbahnya. Dan [Sulaiman bin Harb] dan [Abu Nu'man] berkata; Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] ia berkata; Suatu ketika, aku berada dalam halaqah, dan disitu terdapat Abdurrahman bin Abu Laila, sedangkan para sahabatnya mengagungkannya. Mereka mengadukan permasalahan itu, lalu ia menyebutkan bahwa masa iddahnya adalah yang paling terakhir habis (maksudnya empat bulan sepuluh hari, meskipun ia melahirkan sebelum itu). Maka aku pun menceritakan hadits dengan hadits [Subai'ah binti Al Harits] dari [Abdullah bin Utbah]. Akhirnya sebagian sahabatnya mengerutkan dahi padaku. Muhammad berkata; Aku pun mengerti apa maksudnya. Kukatakan, \"Kalau begitu, aku adalah seorang yang nekat, bila aku berdusta atas nama Abdullah bin Utbah. Sekarang ia berada di Kufah. Maka keduanya pun malu dan berkata, \"Akan tetapi pamannya, tidak berkata demikian.\" Kemudian aku menemui [Abu 'Athiyyah Malik bin Amir] dan bertanya padanya, lalu ia pun menceritakan kepadaku hadits [Subai'ah]. Aku bertanya padanya, \"Apakah Anda mendengar sesuatu tentangnya dari Abdullah?\" Ia menjawab, \"Suatu ketika, kami berada di sisi [Abdullah], dan ia pun berkata, 'Apakah kalian akan memberatkan wanita itu, dan kalian tidak memberikan rukhshah untuknya?. Sungguh, surat An Nisa yang pendek itu turun setelah surat Albaqarah yang panjang. 'Bahwa wanita-wanita yang hamil, maka masa iddah mereka adalah ketika mereka melahirkan.'\""},{"p":"Bukhari","n":4304,"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ وَأَخْبَرَنِي يُوسُفُ بْنُ مَاهَكٍ قَالَإِنِّي عِنْدَ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا إِذْ جَاءَهَا عِرَاقِيٌّ فَقَالَ أَيُّ الْكَفَنِ خَيْرٌ قَالَتْ وَيْحَكَ وَمَا يَضُرُّكَ قَالَ يَا أُمَّ الْمُؤْمِنِينَ أَرِينِي مُصْحَفَكِ قَالَتْ لِمَ قَالَ لَعَلِّي أُوَلِّفُ الْقُرْآنَ عَلَيْهِ فَإِنَّهُ يُقْرَأُ غَيْرَ مُؤَلَّفٍ قَالَتْ وَمَا يَضُرُّكَ أَيَّهُ قَرَأْتَ قَبْلُ إِنَّمَا نَزَلَ أَوَّلَ مَا نَزَلَ مِنْهُ سُورَةٌ مِنْ الْمُفَصَّلِ فِيهَا ذِكْرُ الْجَنَّةِ وَالنَّارِ حَتَّى إِذَا ثَابَ النَّاسُ إِلَى الْإِسْلَامِ نَزَلَ الْحَلَالُ وَالْحَرَامُ وَلَوْ نَزَلَ أَوَّلَ شَيْءٍ لَا تَشْرَبُوا الْخَمْرَ لَقَالُوا لَا نَدَعُ الْخَمْرَ أَبَدًا وَلَوْ نَزَلَ لَا تَزْنُوا لَقَالُوا لَا نَدَعُ الزِّنَا أَبَدًا لَقَدْ نَزَلَ بِمَكَّةَ عَلَى مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنِّي لَجَارِيَةٌ أَلْعَبُ{ بَلْ السَّاعَةُ مَوْعِدُهُمْ وَالسَّاعَةُ أَدْهَى وَأَمَرُّ }وَمَا نَزَلَتْ سُورَةُ الْبَقَرَةِ وَالنِّسَاءِ إِلَّا وَأَنَا عِنْدَهُ قَالَ فَأَخْرَجَتْ لَهُ الْمُصْحَفَ فَأَمْلَتْ عَلَيْهِ آيَ السُّوَرِ","trj":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka, ia berkata; Dan Telah mengabarkan kepadaku [Yusuf bin Mahik] ia berkata; Suatu ketika, aku berada di tempat Aisyah Ummul Mukminin radliallahu 'anha, tiba-tiba seorang dari Irak menemuinya seraya berkata, \"Kain kafan yang bagaimanakah yang lebih baik?\" Aisyah menjawab, \"Huss kamu, apakah yang menimpamu?\" laki-laki itu berkata, \"Wahai Ummul Mukminin, tunjukkanlah Mushhaf Anda padaku.\" [Aisyah] bertanya, \"Untuk apa?\" Ia menjawab, \"Agar aku dapat menyusunnya. Sebab, Al Qur`an itu dibaca secara tidak tersusun.\" Aisyah berkata, \"Lalu apa yang menghalangimu untuk membaca bagian apa saja darinya. Sesungguhnya yang pertama-tama kali turun darinya adalah surat Al Mufashshal yang di dalamnya disebutkan tentang surga dan neraka. Dan ketika manusia telah condong ke Islam, maka turunlah kemudian ayat-ayat tentang halal dan haram. Sekiranya yang pertama kali turun adalah ayat, 'Janganlah kalian minum khamer.' Niscaya mereka akan mengatakan, 'Sekali-kali kami tidak akan bisa meninggalkan khamer selama-lamanya.' Dan sekiranya juga yang pertamakali turun adalah ayat, \"Janganlah kalian berzina..' niscaya mereka akan berkomentar, 'Kami tidak akan meniggalkan zina selama-lamanya.' Ayat yang diturunkan kepada Rasulullah shallallahu 'alaihi wasallam di Makkah yang pada saat itu aku masih anak-anak adalah: 'BAL AS SAA'ATU MAU'IDUHUM WAS SAA'ATU ADHAA WA AMARR.(QS. ALqamar 46).' Dan tidaklah surat Al Baqarah dan An Nisa` kecuali aku berada di sisi beliau.\" Akhirnya, Aisyah mengeluarkan Mushhaf dan mendiktekan kepada orang Irak itu beberapa surat."},{"p":"Bukhari","n":4316,"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُأُبَيٌّ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ مِنْ لَحَنِ أُبَيٍّ وَأُبَيٌّ يَقُولُ أَخَذْتُهُ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَتْرُكُهُ لِشَيْءٍ قَالَ اللَّهُ تَعَالَى{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }","trj":"Telah menceritakan kepada kami [Shadaqah bin Al Fadll] Telah mengabarkan kepada kami [Yahya] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, [Umar] berkata, \"Orang yang paling baik bacaannya di antara kita adalah Ubbay, dan kita akan meninggalkan Qira`ah Ubay.\" Maka [Ubay] pun berkata, \"Aku telah mengambilnya langsung dari bibir Rasulullah shallallahu 'alaihi wasallam, karena itu aku tidak akan meninggalkannya lantaran karena suatu masalah. Allah Ta'ala berfirman: 'MAA NANSAKH MIN `AAYATIN AW NUNSIKHA NA`TI BIKHAIR MINHAA AW MITSLIHAA (Tidaklah kami menghapus suatu ayat pun, atau ayat itu dihapus, kecuali kami akan menggantinya dengan yang lebih baik darinya atau semisalnya). (QS. Albaqarah 106).'\""},{"p":"Bukhari","n":4319,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ بِالْآيَتَيْنِ و حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَمَنْ قَرَأَ بِالْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُوَقَالَ عُثْمَانُ بْنُ الْهَيْثَمِ حَدَّثَنَا عَوْفٌ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ وَكَّلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحِفْظِ زَكَاةِ رَمَضَانَ فَأَتَانِي آتٍ فَجَعَلَ يَحْثُو مِنْ الطَّعَامِ فَأَخَذْتُهُ فَقُلْتُ لَأَرْفَعَنَّكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَصَّ الْحَدِيثَ فَقَالَ إِذَا أَوَيْتَ إِلَى فِرَاشِكَ فَاقْرَأْ آيَةَ الْكُرْسِيِّ لَنْ يَزَالَ مَعَكَ مِنْ اللَّهِ حَافِظٌ وَلَا يَقْرَبُكَ شَيْطَانٌ حَتَّى تُصْبِحَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَكَ وَهُوَ كَذُوبٌ ذَاكَ شَيْطَانٌ","trj":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari [Abdurrahman] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang membaca dua ayat..\" Dan Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud] radliallahu 'anhu ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca dua ayat terakhir dari surat Al Baqarah pada suatu malam, niscaya kedua ayat itu akan mencukupinya.\" Utsmana bin Al Haitsam berkata; Telah menceritakan kepada kami 'Auf dari Muhammad bin Sirin dari Abu Hurairah radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam menugaskanku untuk menjaga harta zakat. Lalu pada suatu hari ada seseorang yang menyusup hendak mengambil makanan, maka aku pun menyergapnya seraya berkata, \"Aku benar-benar akan menyerahkanmu kepada Rasulullah shallallahu 'alaihi wasallam..\" lalu ia bercerita dan berkata, \"Jika kamu hendak beranjak ke tempat tidur maka bacalah ayat kursi, niscaya Allah akan senantiasa menjagamu dan syetan tidak akan mendekatimu hingga pagi.\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Ia telah berkata benar padamu, padahal ia adalah pendusta. Si penyusup tadi sebenarnya adalah syetan.\""},{"p":"Bukhari","n":4347,"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ عَلْقَمَةَ وَعَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآيَتَانِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ مَنْ قَرَأَ بِهِمَا فِي لَيْلَةٍ كَفَتَاهُ","trj":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] ia berkata; Telah menceritakan kepadaku [Ibrahim] dari ['Alqamah] dan [Abdurrahman bin Yazid] dari [Abu Mas'ud Al Anshar] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Dua ayat terakhir dari surat Al Baqarah, siapa yang membacanya pada suatu malam, niscaya kedua ayat itu akan mencukupinya.\""},{"p":"Bukhari","n":4358,"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُقَالَ لِي ابْنُ شُبْرُمَةَ نَظَرْتُ كَمْ يَكْفِي الرَّجُلَ مِنْ الْقُرْآنِ فَلَمْ أَجِدْ سُورَةً أَقَلَّ مِنْ ثَلَاثِ آيَاتٍ فَقُلْتُ لَا يَنْبَغِي لِأَحَدٍ أَنْ يَقْرَأَ أَقَلَّ مِنْ ثَلَاثِ آيَاتٍ قَالَ عَلِيٌّ حَدَّثَنَا سُفْيَانُ أَخْبَرَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ أَخْبَرَهُ عَلْقَمَةُ عَنْ أَبِي مَسْعُودٍ وَلَقِيتُهُ وَهُوَ يَطُوفُ بِالْبَيْتِ فَذَكَرَ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَنْ قَرَأَ بِالْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","trj":"Telah menceritakan kepada kami Ali Telah menceritakan kepada kami Sufyan bahwa Ibnu Syubrumah berkata kepadaku, \"Aku berfikir, berapa ayatkah yang paling minimal dibaca oleh seseorang, namun aku tidak mendapatkan satu suratpun yang kurang dari tiga ayat. Karena itu aku pun berkata, bahwa tidak selayaknya bagi seorang pun untuk membaca Al Qur`an kurang dari tiga ayat.\" [Ali] berkata; Telah menceritakan kepada kami [Sufyan] Telah mengabarkan kepada kami [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] bahwa [Alqamah] telah mengabarkan kepadanya dari [Abu Mas'ud] dan saya pun menemuinya saat ia melakukan thawaf di Baitullah. Lalu ia menyebutkan sabda Nabi shallallahu 'alaihi wasallam, bahwasanya: \"Barangsiapa yang membaca dua ayat terakhir dari surat Al Baqarah pada suatu malam, maka kedua ayat itu akan mencukupinya.\""},{"p":"Bukhari","n":4493,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّهُ قَالَخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَامَ قِيَامًا طَوِيلًا نَحْوًا مِنْ سُورَةِ الْبَقَرَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَاذْكُرُوا اللَّهَ قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ هَذَا ثُمَّ رَأَيْنَاكَ تَكَعْكَعْتَ فَقَالَ إِنِّي رَأَيْتُ الْجَنَّةَ أَوْ أُرِيتُ الْجَنَّةَ فَتَنَاوَلْتُ مِنْهَا عُنْقُودًا وَلَوْ أَخَذْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا وَرَأَيْتُ النَّارَ فَلَمْ أَرَ كَالْيَوْمِ مَنْظَرًا قَطُّ وَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ قَالُوا لِمَ يَا رَسُولَ اللَّهِ قَالَ بِكُفْرِهِنَّ قِيلَ يَكْفُرْنَ بِاللَّهِ قَالَ يَكْفُرْنَ الْعَشِيرَ وَيَكْفُرْنَ الْإِحْسَانَ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّ","trj":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Abdullah bin Abbas] bahwa ia berkata; Pernah terjadi gerhana matahari di masa Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat bersama kaum muslimin. Beliau berdiri dengan berdiri yang sangat panjang sebagaimana panjangnya bacaan surat Al Baqarah. Kemudian beliau ruku' dengan ruku' yang panjang pula. Sesudah itu beliau bangkit dari ruku' lalu berdiri lagi dengan sangat panjang namun tidak sebagaimana panjangnya berdiri beliau yang pertama. Kemudian beliau ruku' dengan panjang, namun tidak sepanjang ruku'nya yang pertama. Lalu beliau teruskan dengan sujud. Setelah itu, beliau bangkit kembali dan berdiri dengan panjang, namun tidak sepanjang berdirinya pertama kali. Kemudian ruku' dengan panjang, tetapi tidak sebagaimana ruku'nya yang pertama. Kemudian beliau bangkit lagi dan berdiri dengan lama, namun tidak selama berdirinya yang pertama. Lalu beliau ruku' kembali dengan lama, tetapi tidak seperti ruku'nya yang pertama. Kemudian beliau bangkit lalu sujud. Setelah beliau selesai shalat matahari pun kembali menampakkan cahaya. Maka beliau pun bersabda: \"Sesungguhnya matahari dan bulan adalah dua tanda dari tanda-tanda Allah, tidaklah terjadi gerhana pada keduanya karena kematian seseorang atau pun karena kehidupannya. Jika kalian melihat hal itu, maka berdzikirlah kepada Allah.\" Para sahabat berkata, \"Wahai Rasulullah, kamu melihat bahwa Anda sepertinya mendapatkan sesuatu di tempat Anda berdiri, lalu kami melihat bahwa Anda tertahan.\" Maka beliau pun bersabda: \"Sesungguhnya aku melihat surga -atau- surga telah diperlihatkan padaku, lalu aku pun hendak mengambil seranting darinya, sekiranya kau dapat mengambilnya niscaya kalian akan memakannya selama dunia masih ada. Kemudian aku melihat neraka, maka aku tidak pernah melihat pemandangan seperti yang terjadi pada hari ini. Aku melihat kebanyakan penghuninya adalah wanita.\" Mereka bertanya lagi, \"Kenapa wahai Rasulullah.\" Beliau menjawab: \"Karena kekufuran mereka.\" Para sahabat bertanya lagi, \"Apakah lantaran kekafiran mereka kepada Allah?\" beliau menjawab: \"Mereka mengkufuri perlakuan dan kebaikan suaminya. Sekiranya kamu berbuat baik kepada salah seorang dari mereka selama setahun penuh, lalu ia melihat sesuatu yang tidak baik darimu, ia pun akan berkata, 'Aku tidak melihat kebaikan sedikit pun darimu.'\""},{"p":"Bukhari","n":4610,"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ حَدَّثَنَا الْحَسَنُأَنَّ مَعْقِلَ بْنَ يَسَارٍ كَانَتْ أُخْتُهُ تَحْتَ رَجُلٍ فَطَلَّقَهَا ثُمَّ خَلَّى عَنْهَا حَتَّى انْقَضَتْ عِدَّتُهَا ثُمَّ خَطَبَهَا فَحَمِيَ مَعْقِلٌ مِنْ ذَلِكَ أَنَفًا فَقَالَ خَلَّى عَنْهَا وَهُوَ يَقْدِرُ عَلَيْهَا ثُمَّ يَخْطُبُهَا فَحَالَ بَيْنَهُ وَبَيْنَهَا فَأَنْزَلَ اللَّهُ{ وَإِذَا طَلَّقْتُمْ النِّسَاءَ فَبَلَغْنَ أَجَلَهُنَّ فَلَا تَعْضُلُوهُنَّ }إِلَى آخِرِ الْآيَةِ فَدَعَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ عَلَيْهِ فَتَرَكَ الْحَمِيَّةَ وَاسْتَقَادَ لِأَمْرِ اللَّهِ","trj":"Dan Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Abdul A'la] Telah menceritakan kepada kami [Sa'id] dari [Qatadah] Telah menceritakan kepada kami [Al Hasan] bahwa saudara perempuan Ma'qil bin Yasar berada di bawah seorang laki-laki, lalu laki-laki itu pun menceraikannya dan berpisah dengannya hingga masa iddahnya habis. Kemudian laki-laki itu meminangnya kembali. Maka Ma'qil pun marah dan menolak pinangan itu dan berkata, \"Ia menceraikannya padahal ia mampu. Lalu ia mengkhithbahnya kembali.\" Akhirnya ia menghalangi ruju' antara keduanya. Maka Allah menurunkan ayat: \"WA IDZAA THALLAQTUMUN NISAA` FABALAGHNA AJALAHUNNA FALAA TA'DLULUUHUNNA..\" (QS. Albaqarah 232), hingga akhir ayat. Lalu Rasulullah shallallahu 'alaihi wasallam pun memanggilnya dan membacakan ayat itu kepadanya. Akhirnya ia pun meninggalkan keangkuhannya dan meneriman ketentuan Allah."},{"p":"Bukhari","n":4620,"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا شِبْلٌ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا }قَالَ كَانَتْ هَذِهِ الْعِدَّةُ تَعْتَدُّ عِنْدَ أَهْلِ زَوْجِهَا وَاجِبًا فَأَنْزَلَ اللَّهُ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِي أَنْفُسِهِنَّ مِنْ مَعْرُوفٍ }قَالَ جَعَلَ اللَّهُ لَهَا تَمَامَ السَّنَةِ سَبْعَةَ أَشْهُرٍ وَعِشْرِينَ لَيْلَةً وَصِيَّةً إِنْ شَاءَتْ سَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ وَهُوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ }فَالْعِدَّةُ كَمَا هِيَ وَاجِبٌ عَلَيْهَا زَعَمَ ذَلِكَ عَنْ مُجَاهِدٍ وَقَالَ عَطَاءٌ قَالَ ابْنُ عَبَّاسٍنَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا عِنْدَ أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ وَقَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ }وَقَالَ عَطَاءٌ إِنْ شَاءَتْ اعْتَدَّتْ عِنْدَ أَهْلِهَا وَسَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ لِقَوْلِ اللَّهِ{ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِي أَنْفُسِهِنَّ }قَالَ عَطَاءٌ ثُمَّ جَاءَ الْمِيرَاثُ فَنَسَخَ السُّكْنَى فَتَعْتَدُّ حَيْثُ شَاءَتْ وَلَا سُكْنَى لَهَا","trj":"Telah menceritakan kepadaku [Ishaq bin Manshur] Telah mengabarkan kepada kami [Rauh bin Ubadah] Telah menceritakan kepada kami [Syibl] dari [Ibnu Najih] dari [Mujahid] terkait dengan firman Allah: Dan orang-orang yang meninggal diantara kalian dan meninggalkan isteri (QS. Albaqarah 240), dahulu iddah yang dilakukan seorang isteri di rumah suaminya adalah wajib, lantas Allah menurunkan ayat; \"WALLADZI YUTAFFAUNA MINKUM WA YADZARUUNA AZWAAJAW WASHIYYATAL LIAZWAAJIHIM MATAA'AN ILAL HAULI GHAIRA IKHRAAJ FAIN KHARAJNA FALAA JUNAAHA 'ALAIKUM FIIMAA FA'ALNAA FII ANFUSIHINNA MIM MA'RUUF.\" \"Dan orang-orang yang meninggal diantara kalian dan meninggalkan isteri, hendaklah menyampaikan wasiat kediaman isteri dan nafkah kepada isterinya selama setahun dengan tidak menyuruh mereka agar keluar, namun jika para isteri yang ditinggal suaminya itu keluar rumah, maka tiada ada dosa bagimu atas perbuatan yang mereka lakukan' (QS. Albaqarah 240). Ia menjelaskan, \"Allah menjadikan kesempurnaan sunnah adalah selama empat bulan dua puluh hari, sebagai wasiat. Bila ia mau, maka oleh boleh tetap pada wasiatnya. Dan jika tidak, ia boleh keluar. Itulah yang dimaksud dengan firman Allah, 'GHAIRA IKHRAAJ, FA`IN KHARAJNA FALAA JUNAHA 'ALAIKUM (dengan tidak menyuruh si isteri untuk pergi, jika isteri itu pergi, maka tidak ada dosa atas kalian), Yakni, masa 'Iddah sebagaimana yang diwajibkan atasnya. ['Atha`] berkata; [Ibnu Abbas] berkata; Ayat ini dinasakh (dihapus) bahwa ia melalui masa iddahnya di rumah suaminya. Karena itu, ia boleh melalui masa iddahnya di mana pun ia mau.\" Dan firman Allah Ta'ala: \"Ghaira Ikharaaj\" Ahta` berkata; Bila ia mau, maka ia boleh melalui masa iddahnya di rumah suaminya atau berdiam pada washiyatnya. Dan bila ia mau, ia boleh keluar karena firman Allah: \"FALAA JUNAAHA 'ALAIKUM FIIMAA FA'ALNA FII ANFUSIHINNA.\" (Maka tak ada dosa atasmu atas perbuatan yang mereka lakukan) Atha` berkata; Kemudian turunlah ayat warisan dan terhapuslah As Sukna (tempat wanita berdiam), hingga ia pun boleh beriddah di mana pun ia suka, dan tidak ada tempat tinggal baginya."},{"p":"Bukhari","n":5336,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَادَةَ أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا سَلِيمٌ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ مُعَاذَ بْنَ جَبَلٍ رَضِيَ اللَّهُ عَنْهُ كَانَ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَأْتِي قَوْمَهُ فَيُصَلِّي بِهِمْ الصَّلَاةَ فَقَرَأَ بِهِمْ الْبَقَرَةَ قَالَ فَتَجَوَّزَ رَجُلٌ فَصَلَّى صَلَاةً خَفِيفَةً فَبَلَغَ ذَلِكَ مُعَاذًا فَقَالَ إِنَّهُ مُنَافِقٌ فَبَلَغَ ذَلِكَ الرَّجُلَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ نَعْمَلُ بِأَيْدِينَا وَنَسْقِي بِنَوَاضِحِنَا وَإِنَّ مُعَاذًا صَلَّى بِنَا الْبَارِحَةَ فَقَرَأَ الْبَقَرَةَ فَتَجَوَّزْتُ فَزَعَمَ أَنِّي مُنَافِقٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ ثَلَاثًا اقْرَأْ وَالشَّمْسِ وَضُحَاهَا وَسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَنَحْوَهَا","trj":"Telah menceritakan kepada kami [Muhammad bin Abdah] telah mengabarkan kepada kami [Yazid] telah mengabarkan kepada kami [Salim] telah menceritakan kepada kami ['Amru bin Dinar] telah menceritakan kepada kami [Jabir bin Abdullah] bahwa Mu'adz bin Jabal radliallahu 'anhu pernah shalat (dibelakang) Rasulullah shallallahu 'alaihi wasallam, kemudian dia kembali ke kaumnya untuk mengimami shalat bersama mereka dengan membaca surat Al Baqarah, Jabir melanjutkan; \"Maka seorang laki-laki pun keluar (dari shaf) lalu ia shalat dengan shalat yang agak ringan, ternyata hal itu sampai kepada Mu'adz, ia pun berkata; \"Sesungguhnya dia adalah seorang munafik.\" Ketika ucapan Mu'adz sampai ke laki-laki tersebut, laki-laki itu langsung mendatangi Nabi shallallahu 'alaihi wasallam sambil berkata; \"Wahai Rasulullah, sesungguhnya kami adalah kaum yang memiliki pekerjaan untuk menyiram ladang, sementara semalam Mu'adz shalat mengimami kami dengan membaca surat Al Baqarah, hingga saya keluar dari shaf, lalu dia mengiraku seorang munafik.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Mu'adz, apakah kamu hendak membuat fitnah.\" -Beliau mengucapkannya hingga tiga kali- bacalah Was syamsi wadluhaaha dan wasabbih bismirabbikal a'la atau yang serupa dengannya.\""},{"p":"Bukhari","n":5402,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ أَخْبَرَهُأَنَّ عُمَرَ بْنَ الْخَطَّابِ انْطَلَقَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ أَصْحَابِهِ قِبَلَ ابْنِ صَيَّادٍ حَتَّى وَجَدَهُ يَلْعَبُ مَعَ الْغِلْمَانِ فِي أُطُمِ بَنِي مَغَالَةَ وَقَدْ قَارَبَ ابْنُ صَيَّادٍ يَوْمَئِذٍ الْحُلُمَ فَلَمْ يَشْعُرْ حَتَّى ضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ظَهْرَهُ بِيَدِهِ ثُمَّ قَالَ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَنَظَرَ إِلَيْهِ فَقَالَ أَشْهَدُ أَنَّكَ رَسُولُ الْأُمِّيِّينَ ثُمَّ قَالَ ابْنُ صَيَّادٍ أَتَشْهَدُ أَنِّي رَسُولُ اللَّهِ فَرَضَّهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ آمَنْتُ بِاللَّهِ وَرُسُلِهِ ثُمَّ قَالَ لِابْنِ صَيَّادٍ مَاذَا تَرَى قَالَ يَأْتِينِي صَادِقٌ وَكَاذِبٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُلِّطَ عَلَيْكَ الْأَمْرُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي خَبَأْتُ لَكَ خَبِيئًا قَالَ هُوَ الدُّخُّ قَالَ اخْسَأْ فَلَنْ تَعْدُوَ قَدْرَكَ قَالَ عُمَرُ يَا رَسُولَ اللَّهِ أَتَأْذَنُ لِي فِيهِ أَضْرِبْ عُنُقَهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ يَكُنْ هُوَ لَا تُسَلَّطُ عَلَيْهِ وَإِنْ لَمْ يَكُنْ هُوَ فَلَا خَيْرَ لَكَ فِي قَتْلِهِ قَالَ سَالِمٌ فَسَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُ انْطَلَقَ بَعْدَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُبَيُّ بْنُ كَعْبٍ الْأَنْصَارِيُّ يَؤُمَّانِ النَّخْلَ الَّتِي فِيهَا ابْنُ صَيَّادٍ حَتَّى إِذَا دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَفِقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَّقِي بِجُذُوعِ النَّخْلِ وَهُوَ يَخْتِلُ أَنْ يَسْمَعَ مِنْ ابْنِ صَيَّادٍ شَيْئًا قَبْلَ أَنْ يَرَاهُ وَابْنُ صَيَّادٍ مُضْطَجِعٌ عَلَى فِرَاشِهِ فِي قَطِيفَةٍ لَهُ فِيهَا رَمْرَمَةٌ أَوْ زَمْزَمَةٌ فَرَأَتْ أُمُّ ابْنِ صَيَّادٍ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَّقِي بِجُذُوعِ النَّخْلِ فَقَالَتْ لِابْنِ صَيَّادٍ أَيْ صَافِ وَهُوَ اسْمُهُ هَذَا مُحَمَّدٌ فَتَنَاهَى ابْنُ صَيَّادٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَرَكَتْهُ بَيَّنَقَالَ سَالِمٌ قَالَ عَبْدُ اللَّهِ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّاسِ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ ذَكَرَ الدَّجَّالَ فَقَالَ إِنِّي أُنْذِرُكُمُوهُ وَمَا مِنْ نَبِيٍّ إِلَّا وَقَدْ أَنْذَرَهُ قَوْمَهُ لَقَدْ أَنْذَرَهُ نُوحٌ قَوْمَهُ وَلَكِنِّي سَأَقُولُ لَكُمْ فِيهِ قَوْلًا لَمْ يَقُلْهُ نَبِيٌّ لِقَوْمِهِ تَعْلَمُونَ أَنَّهُ أَعْوَرُ وَأَنَّ اللَّهَ لَيْسَ بِأَعْوَرَ قَالَ أَبُو عَبْد اللَّهِ خَسَأْتُ الْكَلْبَ بَعَّدْتُهُ{ خَاسِئِينَ }مُبْعَدِينَ","trj":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Salim bin Abdullah] bahwa [Abdullah bin Umar] telah mengabarkan kepadanya, bahwa Umar bin Khatthab pernah pergi bersama Rasulullah shallallahu 'alaihi wasallam dengan beberapa orang dari para sahabat beliau untuk menemui Ibnu Shayyad. Beliau mendapatinya tengah bermain bersama dua anak kecil di dekat benteng Bani Maghalah. Ibnu Shayyad waktu itu sudah hampir baligh namun dia tidak menyadari sesuatupun (kedatangan rombongan) hingga Nabi shallallahu 'alaihi wasallam memukul punggungnya dengan tangan beliau, kemudian beliau bersabda: \"Apakah kamu bersaksi bahwa aku ini utusan Allah?\". Maka Ibnu Shayyad memandang beliau lalu berkata; \"Aku bersaksi bahwa engkau utusan bagi ummat yang ummiy\" (khusus bangsa 'Arab). Kemudian Ibnu Shayyad berkata; \"Apakah kamu bersaksi bahwa aku ini utusan Allah?\" Nabi shallallahu 'alaihi wasallam pun menolaknya sambil bersabda: \"Aku beriman kepada Allah dan Rasul-rasul-Nya.\" Setelah itu beliau bersabda kepada Ibnu Shayyad: \"Bagaimana pendapatmu?\". Ibnu Shayyad menjawab; \"Telah datang kepadaku orang yang jujur dan pendusta\". Rasulullah shallallahu 'alaihi wasallam bersabda: \"Urusanmu kacau balau.\" Rasulullah shallallahu 'alaihi wasallam juga bersabda: \"Sungguh aku meminta kepadamu agar mengira (apa yang aku sembunyikan dalam hatiku) \". Ibnu Shayyad berkata; \"Aku kira asap.\" Beliau bersabda: \"Celaka kamu. Kamu tidak akan mempunyai kemampuan (untuk mengetahuinya) \". Spontanitas Umar berkata; \"Wahai Rasulullah, biarkanlah aku memenggal lehernya\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dia benar (Dajjal), maka kamu tidak akan dapat menguasainya dan jika dia bukan (Dajjal) maka tidak ada kebaikannya membunuhnya\". Salim berkata; \"Aku mendengar Abdullah bin Umar berkata; \"Setelah itu Rasulullah shallallahu 'alaihi wasallam beranjak meninggalkannya, Salim berkata: Aku mendengar Abdullah bin Umar bekata: \"Setelah itu Rasulullah shallallahu 'alaihi wasallam dan Ubai bin Ka'ab Al Anshari pergi menuju kebun kurma dimana Ibnu Shayyad berada, dan ketika Rasulullah shallallahu 'alaihi wasallam memasuki kebun, Rasulullah shallallahu 'alaihi wasallam segera menjaga dirinya dengan pelepah kurma agar tidak mendengar apa pun yang dikatakan Ibnu Shayyad sebelum ia melihat beliau. Sementara Ibnu Shayyad tengah berbaring di atas hamparan kain beludru miliknya, yang terdengar suara tikar bila diduduki. Ketika Ibu Ibnu Shayyad melihat Nabi shallallahu 'alaihi wasallam tengah menjaga diri dengan pelepah kurma, maka ibunya berkata pada Ibnu Shayyad: Hai Shaf -nama Ibnu Shayyad- ini Muhammad.\" Ibnu Shayyad langsung terbangun, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Andai dia (ibu Ibnu Shayyad) membiarkannya maka akan tampak jelas olehnya.\" Salim berkata: Abdullah bin Umar berkata: Rasulullah shallallahu 'alaihi wasallam berdiri ditengah orang-orang, beliau memuja dan memuji dengan pujian yang layak baginya, setelah itu beliau menyebut Dajjal, beliau bersabda: \"Sesungguhnya aku mengingatkan kalian darinya. Dan tidak ada seorang nabi pun melainkan ia akan mengingatkan kaumnya dari Dajjal. Nuh telah mengingatkan kaumnya, namun aku akan menyebutkan suatu hal pada kalian yang belum pernah dikemukakan oleh seorang nabi pun kepada kaumnya, ketahuilah oleh kalian bahwa ia (Dajjal) buta sebelah matanya sedangkan Allah tidak buta sebelah mata-Nya.\" Abu Abdullah mengatakan; \"Aku menghalau anjing maksudnya menjauhkannya, sedangkan kata \"Khasi`iin\" QS Al Baqarah; 65, maknanya adalah terusirlah dengan hina."},{"p":"Bukhari","n":5434,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ أُسَامَةَ بْنَ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ عَلَى حِمَارٍ عَلَيْهِ قَطِيفَةٌ فَدَكِيَّةٌ وَأُسَامَةُ وَرَاءَهُ يَعُودُ سَعْدَ بْنَ عُبَادَةَ فِي بَنِي حَارِثِ بْنِ الْخَزْرَجِ قَبْلَ وَقْعَةِ بَدْرٍ فَسَارَا حَتَّى مَرَّا بِمَجْلِسٍ فِيهِ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ وَذَلِكَ قَبْلَ أَنْ يُسْلِمَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ فَإِذَا فِي الْمَجْلِسِ أَخْلَاطٌ مِنْ الْمُسْلِمِينَ وَالْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ وَالْيَهُودِ وَفِي الْمُسْلِمِينَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَلَمَّا غَشِيَتْ الْمَجْلِسَ عَجَاجَةُ الدَّابَّةِ خَمَّرَ ابْنُ أُبَيٍّ أَنْفَهُ بِرِدَائِهِ وَقَالَ لَا تُغَبِّرُوا عَلَيْنَا فَسَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ ثُمَّ وَقَفَ فَنَزَلَ فَدَعَاهُمْ إِلَى اللَّهِ وَقَرَأَ عَلَيْهِمْ الْقُرْآنَ فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ أَيُّهَا الْمَرْءُ لَا أَحْسَنَ مِمَّا تَقُولُ إِنْ كَانَ حَقًّا فَلَا تُؤْذِنَا بِهِ فِي مَجَالِسِنَا فَمَنْ جَاءَكَ فَاقْصُصْ عَلَيْهِ قَالَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ بَلَى يَا رَسُولَ اللَّهِ فَاغْشَنَا فِي مَجَالِسِنَا فَإِنَّا نُحِبُّ ذَلِكَ فَاسْتَبَّ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْيَهُودُ حَتَّى كَادُوا يَتَثَاوَرُونَ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّضُهُمْ حَتَّى سَكَتُوا ثُمَّ رَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَابَّتَهُ فَسَارَ حَتَّى دَخَلَ عَلَى سَعْدِ بْنِ عُبَادَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ سَعْدُ أَلَمْ تَسْمَعْ مَا قَالَ أَبُو حُبَابٍ يُرِيدُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ قَالَ كَذَا وَكَذَا فَقَالَ سَعْدُ بْنُ عُبَادَةَ أَيْ رَسُولَ اللَّهِ بِأَبِي أَنْتَ اعْفُ عَنْهُ وَاصْفَحْ فَوَالَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ لَقَدْ جَاءَ اللَّهُ بِالْحَقِّ الَّذِي أَنْزَلَ عَلَيْكَ وَلَقَدْ اصْطَلَحَ أَهْلُ هَذِهِ الْبَحْرَةِ عَلَى أَنْ يُتَوِّجُوهُ وَيُعَصِّبُوهُ بِالْعِصَابَةِ فَلَمَّا رَدَّ اللَّهُ ذَلِكَ بِالْحَقِّ الَّذِي أَعْطَاكَ شَرِقَ بِذَلِكَ فَذَلِكَ فَعَلَ بِهِ مَا رَأَيْتَ فَعَفَا عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ يَعْفُونَ عَنْ الْمُشْرِكِينَ وَأَهْلِ الْكِتَابِ كَمَا أَمَرَهُمْ اللَّهُ وَيَصْبِرُونَ عَلَى الْأَذَى قَالَ اللَّهُ تَعَالَى{ وَلَتَسْمَعُنَّ مِنْ الَّذِينَ أُوتُوا الْكِتَابَ }الْآيَةَ وَقَالَ{ وَدَّ كَثِيرٌ مِنْ أَهْلِ الْكِتَابِ }فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَأَوَّلُ فِي الْعَفْوِ عَنْهُمْ مَا أَمَرَهُ اللَّهُ بِهِ حَتَّى أَذِنَ لَهُ فِيهِمْ فَلَمَّا غَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدْرًا فَقَتَلَ اللَّهُ بِهَا مَنْ قَتَلَ مِنْ صَنَادِيدِ الْكُفَّارِ وَسَادَةِ قُرَيْشٍ فَقَفَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ مَنْصُورِينَ غَانِمِينَ مَعَهُمْ أُسَارَى مِنْ صَنَادِيدِ الْكُفَّارِ وَسَادَةِ قُرَيْشٍ قَالَ ابْنُ أُبَيٍّ ابْنُ سَلُولَ وَمَنْ مَعَهُ مِنْ الْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ هَذَا أَمْرٌ قَدْ تَوَجَّهَ فَبَايِعُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْإِسْلَامِ فَأَسْلَمُوا","trj":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Muhammad bin Abu 'Atiq] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] bahwa [Usamah bin Zaid] radliallahu 'anhuma telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengendarai seekor keledai, dilengkapi dengan pelana yang terbuat dari kain Fadak, sementara Usamah berada di belakang beliau. Beliau pergi untuk menjenguk Sa'ad bin 'Ubadah di Bani Al Harits bin Al Khazraj; kejadian ini berlangsung sebelum perang Badar. Kemudian beliau berangkat hingga melewati suatu majlis, yang di dalamnya terdapat 'Abdullah bin 'Ubay bin Salul. Itu terjadi sebelum 'Abdullah bin 'Ubay masuk Islam. Di dalam majlis itu berkumpul pula orang-orang dari kaum Muslimin, orang-orang Musyrik, para penyembah berhala, dan orang-orang Yahudi. Di kalangan kaum Muslimin terdapat 'Abdullah bin Rawahah. Ketika majlis tersebut di kepuli oleh debu yang ditimbulkan dari hewan tunggangan, 'Abdullah bin 'Ubay langsung menutup hidungnya sambil berkata; \"Hei, jangan kamu kepuli kami dengan debu.\" Rasulullah shallallahu 'alaihi wasallam mengucapkan salam kepada mereka, lalu beliau berhenti, turun dan mengajak mereka kepada Allah (memeluk agama Islam) dan membacakan kepada mereka Al Qur'an. Mendengar hal itu 'Abdullah bin 'Ubay berkata; 'Hei..! apa tak ada yang lebih baik dari yang engkau ucapkan! jika itu benar, jangan ganggu di pertemuan kami. Kembalilah! Dan bacakan saja kepada orang-orang yang datang kepadamu! ' Mendengar itu 'Abdullah bin Rawahah berkata; 'Ya Rasulullah! sampaikan saja kepada kami dalam pertemuan ini, karena kami menyukai hal itu.' Maka Kaum Muslimin, orang-orang kafir, dan Yahudi saling mencaci-maki satu sama lain hingga hampir saja mereka berkelahi. Nabi shallallahu 'alaihi wasallam tidak henti-hentinya menenangkan mereka hingga mereka semua kembali tenang. Setelah itu Rasulullah shallallahu 'alaihi wasallam menaiki kembali keledainya dan melanjutkan perjalanan hingga sampai di kediaman Sa'ad bin 'Ubadah. Lalu Rasulullah shallallahu 'alaihi wasallam berkata kepada Sa'ad: 'Wahai Sa'd, tidakkah engkau mendengar apa yang diucapkan Abu Hubab? ' -yang beliau maksudkan adalah 'Abdullah bin 'Ubay- 'Dia telah berkata ini dan itu.' Mendengar itu Sa'ad bin 'Ubadah berkata; Demi ayahku, maafkan dia wahai Rasulullah dan berlapang dadalah kepadanya. Demi dzat yang menurunkan kitab kepada anda, Allah telah datang dengan kebenaran yang diturunkan kepada anda. (dahulu) Penduduk telaga ini (penduduk Madinah -red) bersepakat untuk memilihnya dan mengangkatnya, namun karena kebenaran yang diberikan kepada anda itu muncul, sehingga menghalanginya (Abdullah bin Ubay) menjabat sebagai pemimpin, maka seperti itulah perbuatannya sebagaimana yang anda lihat.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam memaafkannya, karena itu Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya memaafkan orang-orang kafir dan para Ahli Kitab sebagaimana yang diperintahkan Allah, dan mereka bersabar terhadap gangguan mereka. Allah Ta'ala berfirman: (…kamu sungguh-sungguh akan mendengar dari orang-orang yang diberi Kitab…) QS Ali Imran; 186. dan firman Allah (…Sebahagian besar ahli Kitab menginginkan agar mereka dapat mengembalikan kamu…) QS Al Baqarah; 109. Dan Nabi shallallahu 'alaihi wasallam menafsirkan (ayat di atas) suatu prinsip memberikan ampunan kepada mereka selama Allah memerintahkannya demikian hingga Allah memberikan izin untuk memerangi mereka. Maka ketika Rasulullah shallallahu 'alaihi wasallam memerangi mereka dalam Perang Badar dan Allah membinasakan orang-orang terkemuka Quraisy, maka Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya pun kembali dengan membawa kemenangan, baik harta ghanimah maupun para tawanan dari pembesar-pembesar Qurasy, Abdullah bin Ubay bin Salul dan orang-orang kafir dari para penyembah berhala yang bersamanya berkata; 'Perkara ini (Islam) telah muncul.' Lalu mereka berbaiat atas Islam kepada Rasulullah shallallahu 'alaihi wasallam, akhirnya mereka masuk Islam."},{"p":"Bukhari","n":6039,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ فِي بَنِي إِسْرَائِيلَ قِصَاصٌ وَلَمْ تَكُنْ فِيهِمْ الدِّيَةُ فَقَالَ اللَّهُ لِهَذِهِ الْأُمَّةِ{ كُتِبَ عَلَيْكُمْ الْقِصَاصُ فِي الْقَتْلَى }إِلَى هَذِهِ الْآيَةِ{ فَمَنْ عُفِيَ لَهُ مِنْ أَخِيهِ شَيْءٌ }قَالَ ابْنُ عَبَّاسٍ فَالْعَفْوُ أَنْ يَقْبَلَ الدِّيَةَ فِي الْعَمْدِ قَالَ{ فَاتِّبَاعٌ بِالْمَعْرُوفِ }أَنْ يَطْلُبَ بِمَعْرُوفٍ وَيُؤَدِّيَ بِإِحْسَانٍ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Mujahid] dari [Ibnu 'Abbas] radliallahu 'anhuma mengatakan; 'Di kalangan bani israil hanya berlaku hukum qisas dan tidak ada hukum tebusan (diyat), sehingga Allah menurunkan ayat ini 'Diwajibkan atas kalian qisas dalam pembunuhan (QS. ALbaqarah 178) Hingga ayat ini; kecuali jika ia mendapat pemaafan dari saudara (QS. Albaqarah 178), kata Ibn Abbas; istilah maaf maksudnya menerima diyat secara tulus. Dan Ibnu Abbas berkata perihal kutipan ayat; 'fattibaa'un bil ma'ruuf (Maka hendaklah ia mengikutinya dengan baik), ' maksudnya hendaklah betu-betul meminta maaf dan melakukannya dengan sebaik-baiknya."},{"p":"Bukhari","n":6232,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ شَاهِينَ الْوَاسِطِيُّ حَدَّثَنَا خَالِدٌ عَنْ بَيَانٍ عَنْ وَبَرَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ خَرَجَ عَلَيْنَا عَبْدُ اللَّهِ بْنُ عُمَرَفَرَجَوْنَا أَنْ يُحَدِّثَنَا حَدِيثًا حَسَنًا قَالَ فَبَادَرَنَا إِلَيْهِ رَجُلٌ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ حَدِّثْنَا عَنْ الْقِتَالِ فِي الْفِتْنَةِ وَاللَّهُ يَقُولُ{ وَقَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ }فَقَالَ هَلْ تَدْرِي مَا الْفِتْنَةُ ثَكِلَتْكَ أُمُّكَ إِنَّمَا كَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَاتِلُ الْمُشْرِكِينَ وَكَانَ الدُّخُولُ فِي دِينِهِمْ فِتْنَةً وَلَيْسَ كَقِتَالِكُمْ عَلَى الْمُلْكِ","trj":"Telah menceritakan kepada kami [Ishaq bin Syahin Al Wasithi] telah menceritakan kepada kami [Khalid] dari [Bayan] dari [Wabarah bin Abdurrahman] dari [Sa'id bin Jubair] mengatakan, [Abdullah bin Umar] menemui kami, kami sangat berharap agar ia menceritakan kepada kami sebuah pembicaraan yang baik. Tiba-tiba ada seorang laki-laki yang mendahului kami menemuinya dan berujar; 'ya Abu Abdurrahman, ceritakanlah kepada kami sebuah cerita tentang peperangan dalam fitnah yang telah Allah firmankan: 'Dan perangilah mereka hingga tak ada lagi fitnah di muka bumi' (QS. Albaqarah; 193). Maka Abdullah bin Umar bertanya; 'Apakah kamu tahu apa fitnah itu, duhai malangnya ibumu kehilangan dirimu, Dahulu Muhammad Shallallahu'alaihiwasallam memerangi orang-orang musyrik dan siapa saja yang memasuki agama mereka (pindah agama) itulah yang dimaksud fitnah, dan fitnah maksudnya bukanlah peperangan kalian terhadap para raja (penguasa)."},{"p":"Bukhari","n":6377,"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَاهَا }فَوُجِّهَ نَحْوَ الْكَعْبَةِ وَصَلَّى مَعَهُ رَجُلٌ الْعَصْرَ ثُمَّ خَرَجَ فَمَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ قَدْ وُجِّهَ إِلَى الْكَعْبَةِ فَانْحَرَفُوا وَهُمْ رُكُوعٌ فِي صَلَاةِ الْعَصْرِ","trj":"Telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari [Al Bara'] ia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam tiba di Madinah, beliau shalat menghadap Baitul Maqdis selama enam belas atau tujuh belas bulan, padahal beliau amat senang jika disuruh menghadap Ka'bah. Maka Allah pun menurunkan ayat: '(Kami telah melihat penglihatan wajahmu di langit, maka kami palingkan kamu ke kiblat yang kamu ridhai) ' (Qs. Al Baqarah: 144), maka beliau dihadapkan wajahnya ke Ka'bah, ketika itu seseorang shalat 'ashar bersama beliau, lantas keluar dan melewati sekelompok orang-orang Anshar, lalu ia katakan kepada mereka sekaligus bersaksi bahwa ia telah shalat bersama nabi shallallahu 'alaihi wasallam, dan kiblat beliau telah di hadapkan ke Ka'bah, maka mereka pun menggeser kiblatnya yang ketika itu mereka sedang rukuk pada shalat 'ashar.\""},{"p":"Bukhari","n":6450,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجَاءُ بِنُوحٍ يَوْمَ الْقِيَامَةِ فَيُقَالُ لَهُ هَلْ بَلَّغْتَ فَيَقُولُ نَعَمْ يَا رَبِّ فَتُسْأَلُ أُمَّتُهُ هَلْ بَلَّغَكُمْ فَيَقُولُونَ مَا جَاءَنَا مِنْ نَذِيرٍ فَيَقُولُ مَنْ شُهُودُكَ فَيَقُولُ مُحَمَّدٌ وَأُمَّتُهُ فَيُجَاءُ بِكُمْ فَتَشْهَدُونَ ثُمَّ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا }قَالَ عَدْلًا{ لِتَكُونُوا شُهَدَاءَ عَلَى النَّاسِ وَيَكُونَ الرَّسُولُ عَلَيْكُمْ شَهِيدًا }وَعَنْ جَعْفَرِ بْنِ عَوْنٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Abu Shalih] dari [Abu Sa'id alkhudzri] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nabi Nuh didatangkan pada hari kiamat lantas ditanya, 'Sudahkah kamu menyampaikan? ' ia menjawab, 'Benar ya Rabbi'. Ummatnya kemudian ditanya, 'Apakah dia memang benar telah menyampaikan kepada kalian? ' Mereka menjawab, 'Belum ada seorang pemberi peringatan kepada kita.' Lantas Allah bertanya lagi: 'Siapa yang menjadi saksimu? ' Nuh menjawab, 'Muhammad dan umatnya.' Lantas kalian didatangkan dan kalian bersaksi.\" Kemudian Rasulullah Shallallahu'alaihiwasallam membaca ayat: '(Dan demikianlah Kami jadikan kalian umat yang wasath) ' (Qs. Albaqarah 143). Kata Al A'masy, wasath artinya adil '(Agar kalian menjadi saksi atas semua manusia dan agar rasul sebagai saksi atas kalian) ' (Qs. Albaqarah 143). Dan dari [Ja'far bin Aun] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id alkhudzri] dari Nabi shallallahu 'alaihi wasallam dengan ini.\""},{"p":"Darimi","n":107,"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عَطَاءٍ عَنْ سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ مَا رَأَيْتُ قَوْمًا كَانُوا خَيْرًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا سَأَلُوهُ إِلَّا عَنْ ثَلَاثَ عَشْرَةَ مَسْأَلَةً حَتَّى قُبِضَ كُلُّهُنَّ فِي الْقُرْآنِ مِنْهُنَّ { يَسْأَلُونَكَ عَنْ الشَّهْرِ الْحَرَامِ } { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ } قَالَ مَا كَانُوا يَسْأَلُونَ إِلَّا عَمَّا يَنْفَعُهُمْ","trj":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Fudlail] dari ['Atho`] dari [Sa'id] dari [Ibnu 'Abbas] radliallahu 'anhu ia berkata: \" Aku tidak pernah melihat suatu kaum yang lebih baik dari pada para sahabat Rasulullah shallallahu 'alaihi wasallam, mereka tidak pernah menanyakan (kepada Nabi shallallahu 'alaihi wasallam) sampai beliau wafat kecuali tentang tiga belas masalah, semuanya ada dalam Al Qur`an. Diantara yang ditanyakan itu adalah: \"YAS`ALUUNAKA ANISSYAHRIL HARAAM\" (Mereka bertanya kepadamu tentang bulan-bulan haram) -Qs. Al Baqarah: 217-, dan \"WA YAS`ALUNAKA ANIL MAHIDL\" (Mereka bertanya kepada kamu tentang haidl) -Qs. Al Baqarah: 222-\"."},{"p":"Darimi","n":414,"ar":" أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ سُلَيْمَانَ أَبُو عَبْدِ الرَّحْمَنِ الْأَنْطَاكِيُّ عَنْ عَبَّادِ بْنِ عَبَّادٍ الْخَوَّاصِ الشَّامِيِّ أَبِي عُتْبَةَ قَالَ أَمَّا بَعْدُ اعْقِلُوا وَالْعَقْلُ نِعْمَةٌ فَرُبَّ ذِي عَقْلٍ قَدْ شُغِلَ قَلْبُهُ بِالتَّعَمُّقِ عَمَّا هُوَ عَلَيْهِ ضَرَرٌ عَنْ الِانْتِفَاعِ بِمَا يَحْتَاجُ إِلَيْهِ حَتَّى صَارَ عَنْ ذَلِكَ سَاهِيًا وَمِنْ فَضْلِ عَقْلِ الْمَرْءِ تَرْكُ النَّظَرِ فِيمَا لَا نَظَرَ فِيهِ حَتَّى لَا يَكُونَ فَضْلُ عَقْلِهِ وَبَالًا عَلَيْهِ فِي تَرْكِ مُنَافَسَةِ مَنْ هُوَ دُونَهُ فِي الْأَعْمَالِ الصَّالِحَةِ أَوْ رَجُلٍ شُغِلَ قَلْبُهُ بِبِدْعَةٍ قَلَّدَ فِيهَا دِينَهُ رِجَالًا دُونَ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ اكْتَفَى بِرَأْيِهِ فِيمَا لَا يَرَى الْهُدَى إِلَّا فِيهَا وَلَا يَرَى الضَّلَالَةَ إِلَّا بِتَرْكِهَا يَزْعُمُ أَنَّهُ أَخَذَهَا مِنْ الْقُرْآنِ وَهُوَ يَدْعُو إِلَى فِرَاقِ الْقُرْآنِ أَفَمَا كَانَ لِلْقُرْآنِ حَمَلَةٌ قَبْلَهُ وَقَبْلَ أَصْحَابِهِ يَعْمَلُونَ بِمُحْكَمِهِ وَيُؤْمِنُونَ بِمُتَشَابِهِهِ وَكَانُوا مِنْهُ عَلَى مَنَارٍ كَوَضَحِ الطَّرِيقِ فَكَانَ الْقُرْآنُ إِمَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ إِمَامًا لِأَصْحَابِهِ وَكَانَ أَصْحَابُهُ أَئِمَّةً لِمَنْ بَعْدَهُمْ رِجَالٌ مَعْرُوفُونَ مَنْسُوبُونَ فِي الْبُلْدَانِ مُتَّفِقُونَ فِي الرَّدِّ عَلَى أَصْحَابِ الْأَهْوَاءِ مَعَ مَا كَانَ بَيْنَهُمْ مِنْ الِاخْتِلَافِ وَتَسَكَّعَ أَصْحَابُ الْأَهْوَاءِ بِرَأْيِهِمْ فِي سُبُلٍ مُخْتَلِفَةٍ جَائِرَةٍ عَنْ الْقَصْدِ مُفَارِقَةٍ لِلصِّرَاطِ الْمُسْتَقِيمِ فَتَوَّهَتْ بِهِمْ أَدِلَّاؤُهُمْ فِي مَهَامِهَ مُضِلَّةٍ فَأَمْعَنُوا فِيهَا مُتَعَسِّفِينَ فِي تِيهِهِمْ كُلَّمَا أَحْدَثَ لَهُمْ الشَّيْطَانُ بِدْعَةً فِي ضَلَالَتِهِمْ انْتَقَلُوا مِنْهَا إِلَى غَيْرِهَا لِأَنَّهُمْ لَمْ يَطْلُبُوا أَثَرَ السَّالِفِينَ وَلَمْ يَقْتَدُوا بِالْمُهَاجِرِينَ وَقَدْ ذُكِرَ عَنْ عُمَرَ أَنَّهُ قَالَ لِزِيَادٍ هَلْ تَدْرِي مَا يَهْدِمُ الْإِسْلَامَ زَلَّةُ عَالِمٍ وَجِدَالُ مُنَافِقٍ بِالْقُرْآنِ وَأَئِمَّةٌ مُضِلُّونَ اتَّقُوا اللَّهَ وَمَا حَدَثَ فِي قُرَّائِكُمْ وَأَهْلِ مَسَاجِدِكُمْ مِنْ الْغِيبَةِ وَالنَّمِيمَةِ وَالْمَشْيِ بَيْنَ النَّاسِ بِوَجْهَيْنِ وَلِسَانَيْنِ وَقَدْ ذُكِرَ أَنَّ مَنْ كَانَ ذَا وَجْهَيْنِ فِي الدُّنْيَا كَانَ ذَا وَجْهَيْنِ فِي النَّارِ يَلْقَاكَ صَاحِبُ الْغِيبَةِ فَيَغْتَابُ عِنْدَكَ مَنْ يَرَى أَنَّكَ تُحِبُّ غِيبَتَهُ وَيُخَالِفُكَ إِلَى صَاحِبِكَ فَيَأْتِيهِ عَنْكَ بِمِثْلِهِ فَإِذَا هُوَ قَدْ أَصَابَ عِنْدَ كُلِّ وَاحِدٍ مِنْكُمَا حَاجَتَهُ وَخَفِيَ عَلَى كُلِّ وَاحِدٍ مِنْكُمَا مَا أُتِيَ بِهِ عِنْدَ صَاحِبِهِ حُضُورُهُ عِنْدَ مَنْ حَضَرَهُ حُضُورُ الْإِخْوَانِ وَغَيْبَتُهُ عَلَى مَنْ غَابَ عَنْهُ غَيْبَةُ الْأَعْدَاءِ مَنْ حَضَرَ مِنْهُمْ كَانَتْ لَهُ الْأَثَرَةُ وَمَنْ غَابَ مِنْهُمْ لَمْ تَكُنْ لَهُ حُرْمَةٌ يَفْتِنُ مَنْ حَضَرَهُ بِالتَّزْكِيَةِ وَيَغْتَابُ مَنْ غَابَ عَنْهُ بِالْغِيبَةِ فَيَا لَعِبَادَ اللَّهِ أَمَا فِي الْقَوْمِ مِنْ رَشِيدٍ وَلَا مُصْلِحٍ يَقْمَعُ هَذَا عَنْ مَكِيدَتِهِ وَيَرُدُّهُ عَنْ عِرْضِ أَخِيهِ الْمُسْلِمِ بَلْ عَرَفَ هَوَاهُمْ فِيمَا مَشَى بِهِ إِلَيْهِمْ فَاسْتَمْكَنَ مِنْهُمْ وَأَمْكَنُوهُ مِنْ حَاجَتِهِ فَأَكَلَ بِدِينِهِ مَعَ أَدْيَانِهِمْ فَاللَّهَ اللَّهَ ذُبُّوا عَنْ حُرَمِ أَغْيَابِكُمْ وَكُفُّوا أَلْسِنَتَكُمْ عَنْهُمْ إِلَّا مِنْ خَيْرٍ وَنَاصِحُوا اللَّهَ فِي أُمَّتِكُمْ إِذْ كُنْتُمْ حَمَلَةَ الْكِتَابِ وَالسُّنَّةِ فَإِنَّ الْكِتَابَ لَا يَنْطِقُ حَتَّى يُنْطَقَ بِهِ وَإِنَّ السُّنَّةَ لَا تَعْمَلُ حَتَّى يُعْمَلَ بِهَا فَمَتَى يَتَعَلَّمُ الْجَاهِلُ إِذَا سَكَتَ الْعَالِمُ فَلَمْ يُنْكِرْ مَا ظَهَرَ وَلَمْ يَأْمُرْ بِمَا تُرِكَ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } اتَّقُوا اللَّهَ فَإِنَّكُمْ فِي زَمَانٍ رَقَّ فِيهِ الْوَرَعُ وَقَلَّ فِيهِ الْخُشُوعُ وَحَمَلَ الْعِلْمَ مُفْسِدُوهُ فَأَحَبُّوا أَنْ يُعْرَفُوا بِحَمْلِهِ وَكَرِهُوا أَنْ يُعْرَفُوا بِإِضَاعَتِهِ فَنَطَقُوا فِيهِ بِالْهَوَى لَمَّا أَدْخَلُوا فِيهِ مِنْ الْخَطَإِ وَحَرَّفُوا الْكَلِمَ عَمَّا تَرَكُوا مِنْ الْحَقِّ إِلَى مَا عَمِلُوا بِهِ مِنْ بَاطِلٍ فَذُنُوبُهُمْ ذُنُوبٌ لَا يُسْتَغْفَرُ مِنْهَا وَتَقْصِيرُهُمْ تَقْصِيرٌ لَا يُعْتَرَفُ بِهِ كَيْفَ يَهْتَدِي الْمُسْتَدِلُّ الْمُسْتَرْشِدُ إِذَا كَانَ الدَّلِيلُ حَائِرًا أَحَبُّوا الدُّنْيَا وَكَرِهُوا مَنْزِلَةَ أَهْلِهَا فَشَارَكُوهُمْ فِي الْعَيْشِ وَزَايَلُوهُمْ بِالْقَوْلِ وَدَافَعُوا بِالْقَوْلِ عَنْ أَنْفُسِهِمْ أَنْ يُنْسَبُوا إِلَى عَمَلِهِمْ فَلَمْ يَتَبَرَّءُوا مِمَّا انْتَفَوْا مِنْهُ وَلَمْ يَدْخُلُوا فِيمَا نَسَبُوا إِلَيْهِ أَنْفُسَهُمْ لِأَنَّ الْعَامِلَ بِالْحَقِّ مُتَكَلِّمٌ وَإِنْ سَكَتَ وَقَدْ ذُكِرَ أَنَّ اللَّهَ تَعَالَى يَقُولُ إِنِّي لَسْتُ كُلَّ كَلَامِ الْحَكِيمِ أَتَقَبَّلُ وَلَكِنِّي أَنْظُرُ إِلَى هَمِّهِ وَهَوَاهُ فَإِنْ كَانَ هَمُّهُ وَهَوَاهُ لِي جَعَلْتُ صَمْتَهُ حَمْدًا وَوَقَارًا لِي وَإِنْ لَمْ يَتَكَلَّمْ وَقَالَ اللَّهُ تَعَالَى { مَثَلُ الَّذِينَ حُمِّلُوا التَّوْرَاةَ ثُمَّ لَمْ يَحْمِلُوهَا } لَمْ يَعْمَلُوا بِهَا { كَمَثَلِ الْحِمَارِ يَحْمِلُ أَسْفَارًا } كُتُبًا وَقَالَ { خُذُوا مَا آتَيْنَاكُمْ بِقُوَّةٍ } قَالَ الْعَمَلُ بِمَا فِيهِ وَلَا تَكْتَفُوا مِنْ السُّنَّةِ بِانْتِحَالِهَا بِالْقَوْلِ دُونَ الْعَمَلِ بِهَا فَإِنَّ انْتِحَالَ السُّنَّةِ دُونَ الْعَمَلِ بِهَا كَذِبٌ بِالْقَوْلِ مَعَ إِضَاعَةِ الْعَمَلِ وَلَا تَعِيبُوا بِالْبِدَعِ تَزَيُّنًا بِعَيْبِهَا فَإِنَّ فَسَادَ أَهْلِ الْبِدَعِ لَيْسَ بِزَائِدٍ فِي صَلَاحِكُمْ وَلَا تَعِيبُوهَا بَغْيًا عَلَى أَهْلِهَا فَإِنَّ الْبَغْيَ مِنْ فَسَادِ أَنْفُسِكُمْ وَلَيْسَ يَنْبَغِي لِلطَّبِيبِ أَنْ يُدَاوِيَ الْمَرْضَى بِمَا يُبَرِّئُهُمْ وَيُمْرِضُهُ فَإِنَّهُ إِذَا مَرِضَ اشْتَغَلَ بِمَرَضِهِ عَنْ مُدَاوَاتِهِمْ وَلَكِنْ يَنْبَغِي أَنْ يَلْتَمِسَ لِنَفْسِهِ الصِّحَّةَ لِيَقْوَى بِهِ عَلَى عِلَاجِ الْمَرْضَى فَلْيَكُنْ أَمْرُكُمْ فِيمَا تُنْكِرُونَ عَلَى إِخْوَانِكُمْ نَظَرًا مِنْكُمْ لِأَنْفُسِكُمْ وَنَصِيحَةً مِنْكُمْ لِرَبِّكُمْ وَشَفَقَةً مِنْكُمْ عَلَى إِخْوَانِكُمْ وَأَنْ تَكُونُوا مَعَ ذَلِكَ بِعُيُوبِ أَنْفُسِكُمْ أَعْنَى مِنْكُمْ بِعُيُوبِ غَيْرِكُمْ وَأَنْ يَسْتَطْعِمَ بَعْضُكُمْ بَعْضًا النَّصِيحَةَ وَأَنْ يَحْظَى عِنْدَكُمْ مَنْ بَذَلَهَا لَكُمْ وَقَبِلَهَا مِنْكُمْ وَقَدْ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَحِمَ اللَّهُ مَنْ أَهْدَى إِلَيَّ عُيُوبِي تُحِبُّونَ أَنْ تَقُولُوا فَيُحْتَمَلَ لَكُمْ وَإِنْ قِيلَ لَكُمْ مِثْلُ الَّذِي قُلْتُمْ غَضِبْتُمْ تَجِدُونَ عَلَى النَّاسِ فِيمَا تُنْكِرُونَ مِنْ ��ُمُورِهِمْ وَتَأْتُونَ مِثْلَ ذَلِكَ فَلَا تُحِبُّونَ أَنْ يُوجَدَ عَلَيْكُمْ اتَّهِمُوا رَأْيَكُمْ وَرَأْيَ أَهْلِ زَمَانِكُمْ وَتَثَبَّتُوا قَبْلَ أَنْ تَكَلَّمُوا وَتَعَلَّمُوا قَبْلَ أَنْ تَعْمَلُوا فَإِنَّهُ يَأْتِي زَمَانٌ يَشْتَبِهُ فِيهِ الْحَقُّ وَالْبَاطِلُ وَيَكُونُ الْمَعْرُوفُ فِيهِ مُنْكَرًا وَالْمُنْكَرُ فِيهِ مَعْرُوفًا فَكَمْ مِنْ مُتَقَرِّبٍ إِلَى اللَّهِ بِمَا يُبَاعِدُهُ وَمُتَحَبِّبٍ إِلَيْهِ بِمَا يُغْضِبُهُ عَلَيْهِ قَالَ اللَّهُ تَعَالَى { أَفَمَنْ زُيِّنَ لَهُ سُوءُ عَمَلِهِ فَرَآهُ حَسَنًا } الْآيَةَ فَعَلَيْكُمْ بِالْوُقُوفِ عِنْدَ الشُّبُهَاتِ حَتَّى يَبْرُزَ لَكُمْ وَاضِحُ الْحَقِّ بِالْبَيِّنَةِ فَإِنَّ الدَّاخِلَ فِيمَا لَا يَعْلَمُ بِغَيْرِ عِلْمٍ آثِمٌ وَمَنْ نَظَرَ لِلَّهِ نَظَرَ اللَّهُ لَهُ عَلَيْكُمْ بِالْقُرْآنِ فَأْتَمُّوا بِهِ وَأُمُّوا بِهِ وَعَلَيْكُمْ بِطَلَبِ أَثَرِ الْمَاضِينَ فِيهِ وَلَوْ أَنَّ الْأَحْبَارَ وَالرُّهْبَانَ لَمْ يَتَّقُوا زَوَالَ مَرَاتِبِهِمْ وَفَسَادَ مَنْزِلَتِهِمْ بِإِقَامَةِ الْكِتَابِ وَتِبْيَانِهِ مَا حَرَّفُوهُ وَلَا كَتَمُوهُ وَلَكِنَّهُمْ لَمَّا خَالَفُوا الْكِتَابَ بِأَعْمَالِهِمْ الْتَمَسُوا أَنْ يَخْدَعُوا قَوْمَهُمْ عَمَّا صَنَعُوا مَخَافَةَ أَنْ تَفْسُدَ مَنَازِلُهُمْ وَأَنْ يَتَبَيَّنَ لِلنَّاسِ فَسَادُهُمْ فَحَرَّفُوا الْكِتَابَ بِالتَّفْسِيرِ وَمَا لَمْ يَسْتَطِيعُوا تَحْرِيفَهُ كَتَمُوهُ فَسَكَتُوا عَنْ صَنِيعِ أَنْفُسِهِمْ إِبْقَاءً عَلَى مَنَازِلِهِمْ وَسَكَتُوا عَمَّا صَنَعَ قَوْمُهُمْ مُصَانَعَةً لَهُمْ وَقَدْ { أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ } بَلْ مَالَئُوا عَلَيْهِ وَرَقَّقُوا لَهُمْ فِيهِ","trj":"Telah mengabarkan kepada kami [Abdul Malik bin Sulaiman Abu Abdur Rahman Al `Anthaki] dari ['Abbad bin 'Abbad Al Khawwash As Syami Abu 'Utbah] ia berkata: \"Perhatian, gunakanlah akal, karena akal sebuah nikmat. Berapa banyak orang berakal menyibukkan hatinya untuk memperdalam hal-hal yang membahayakan dirinya daripada memanfaatkan apa yang dibutuhkannya, sehingga ia lupa hal itu. Diantara keutamaan akal seseorang adalah meninggalkan perhatian terhadap hal-hal yang tidak perlu sehingga keutamaan akalnya tidak menjadi bencana baginya, yaitu ia meninggalkan persaingan dengan orang yang lebih rendah amal shalihnya, atau seseorang yang menyibukkan hatinya dengan bid'ah, yang ia sekedar mengikuti orang dalam urusan agamanya tanpa mengikuti para sahabat Rasulullah shalallahu 'alahi wa sallam, atau ia hanya merasa cukup dengan pendapatnya sendiri, yang ia tidak melihat petunjuk kecuali kepada akalnya, dan tidak melihat kesesatan kecuali meninggalkannya dengan anggapan bahwa ia mengambilnya dari Al qur`an, padahal ia menyerukan untuk meninggalkan Al qur`an. Bukankah Al qur`an mempunyai pengemban-pengemban sebelumnya, yaitu para pembelanya yang mengamalkan ayat-ayat yang muhkam dan mengimani ayat-ayat yang mutasyabih? Mereka berada di menara layaknya cahaya jalan, Al Quran imam Rasulullah shalallahu'alahi wa sallam, sedang Rasulullah shallahu 'alaihi wa sallam imam para sahabatnya, dan para sahabat adalah imam orang-orang setelah mereka, yaitu orang-orang yang sudah dikenal kebaikannya, mereka menjadi barometer di negeri-negeri mereka yang sepakat menolak para pengagung hawa nafsu walaupun diantara mereka terdapat perselisihan pendapat. Para pengagum hawa nafsu meraba-raba dengan pendapat mereka, yaitu dengan cara yang bermacam-macam, yang melenceng dari tujuan karena memisahkan diri dari jalan yang lurus. Petunjuk mereka menyesatkan mereka sendiri dalam misteri padang pasir yang menyesatkan. Mereka konsentrasi melihat petunjuk jalan dengan penuh kebingungan dalam kesesatannya. Setiap kali setan membuat satu bid'ah dalam kesesatan, mereka berpindah dari satu bid'ah ke bid'ah lain, karena mereka tidak mencari petunjuk para pendahulu dan juga tidak mengikuti jejak kaum muhajirin. Telah disebutkan dalam satu riwayat dari Umar radliallahu 'anhu bahwa ia berkata kepada Ziad: 'Tahukah kamu apa yang (menyebabkan) kehancuran Islam? ', Jawabnya karena kesalahan orang berilmu, perdebatan orang munafik terhadap Al Qur`an dan para imam yang sesat'. Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan waspadailah apa yang terjadi pada ulama kamu dan pengisi masjid-masjid kamu dari perbuatan ghibah, namimah dan berjalan diantara manusia dengan dua wajah dan dua lisan. Dalam satu riwayat disebutkan barangsiapa mempunyai dua wajah di dunia, ia mempunyai dua wajah di neraka. Jika tukang ghibah menemuimu, ia menggunjing orang yang kamu senangi untuk di gunjing, lalu ia berpaling darimu untuk mendatangi temanmu dan melakukan hal yang sama. Jika ia telah memperoleh apa yang ia butuhkan dari setiap kalian, dan menyembunyikan sesuatu dari salah satu (dari) kalian, ia tidak memberi kabar kepada sahabatmu yang lain. Kedatangannya kepada orang yang didatanginya adalah seperti datangnya seorang teman, namun kepergiannya dari teman yang ditinggalkan bagaikan kepergian dari seorang musuh. Siapa saja yang menemuinya, ia dapatkan kemuliaan, sebaliknya siapa yang tidak ditemuinya, tidak ia dapatkan kehormatan, ia menipu orang yang didatanginya dengan penghargaan-penghargaan, dan menggunjing orang yang tidak ditemuinya dengan ghibah mematikan. Wahai hamba-hamba Allah subhanallahu wa ta'ala, tidakkah suatu kaum muncul penunjuk jalan dan reformis, yang ia sanggup mengekang orang seperti ini dari tipu dayanya, dan mengajaknya untuk mempertahankan kehormatan saudaranya semuslim?, bahkan kalau bisa memberitahu mereka niyat orang seperti ini saat datang menemui mereka, yang ia bertindak sekedar ingin memperoleh keperluannya sehingga mereka mempersilahkan, yang ujungnya ia mencaplok agamanya sekaligus agama mereka? Ya Allah, Ya Allah! Pertahankanlah kehormatan kamu, hentikanlah lisanmu (dari menggunjing) mereka kecuali kebaikan semata. Tolong kalian saling mengingatkan untuk berbakti kepada Allah khususnya terhadap umatmu, karena kamu adalah pengemban Al Kitab (Al Qur`an) dan sunah,. Al Kitab tidak berbicara hingga ia dibicarakan, dan sunnah tidak sanggup mengejawantahkan hingga ia diejawantahkan. Bilamana orang bodoh belajar, namun orang alim diam tidak memungkiri apa yang nampak dan tidak memerintahkan apa yang ditinggalkan', bukankah Allah subhanallahu wa ta'ala telah mengambil perjanjian dari orang-orang yang diberikan Al Kitab kepada mereka untuk menjelaskannya kepada manusia dan tidak menyembunyikannya?. Bertakwalah kepada Allah subhanallahu wa ta'ala, karena kamu berada pada zaman menipisnya sifat wara' dan kurangnya kekhusyu'an, dan para pengemban ilmu adalah para perusaknya. Mereka begitu marah jika dikenal sebagai orang-orang yang menghilangkannya, mereka membicarakannya dengan hawa nafsu ketika mengikutsertakan kesalahan dalam ilmu, dan memutarbalikkan perkataan dari kebenaran yang mereka tinggalkan, lantas mereka belokkan menuju kebatilan yang mereka kerjakan. Dosa mereka adalah dosa yang tidak diampuni dan kelalaian mereka adalah kelalaian yang tidak bisa dibenarkan, bagaimana orang yang mencari petunjuk dan tuntunan mendapatkan petunjuk apabila petunjuknya sendiri membingungkan, mereka cinta dunia dan benci terhadap kebahagiaan penduduknya yang memperoleh kedudukan tinggi, lantas mereka menyertai dalam kehidupan dan menyelisihi mereka dengan perkataan, dan mempertahankan diri mereka dengan perkataan, agar mereka dihubung-hubungkan dengan kebaikan mereka. Mereka sama sekali tidak bersih dari kotoran yang mereka hilangkan, dan belum memenuhi kriteria untuk dihargai amal mereka, sebab orang yang benar-benar beramal shalih secara tidak langsung ia ia telah bicara sekalipun dia diam. Dan telah diberitakan bahwa Allah Ta'ala berfirman; Aku tidak menerima semua semua perkataan orang bijak, akan tetapi Aku melihat kepada kecenderungan dan niyat baiknya untuk-Ku. Sebab siapa yang hasrat dan niyatnya untuk-Ku, Aku jadikan diamnya terpuji dan berwibawa, walaupun ia tidak berbicara. Allah subhanallahu wa ta'ala berfirman: \"MATSALULLADZINA HUMMILUT TAURATA TSUMMA LAM YAHMILUUHA KAMATSALIL HIMARI YAHMILUL ASFARA\" (Perumpamaan orang-orang yang dipikulkan kepadanya Taurat, kemudian mereka tidak memikulnya (tidak mengerjakannya) adalah seperti keledai yang membawa kitab-kitab yang tebal) -Qs. Al Jumu'ah: 5-, Allah subhanallahu wa ta'ala juga berfirman: \"KHUDZU MAA ATAINAAKUM BI QUWWAH\" (Peganglah teguh-teguh apa yang telah kami berikan kepadamu) -Qs. Al Baqarah: 63, 93, 171-, ia berkata: 'Maksudnya mengerjakan isi yang terkandung padanya, dan tidak mencukupkan sunnah hanya dengan ucapan tanpa pengalaman. Karena pensifatan sunnah dengan perkataan tanpa perbuatan adalah dusta dengan perkataan, yang sekaligus menghilangkan ilmu. Dan janganlah kamu mencela bid`ah sekedar untuk bungkus keindahanmu dengan meneropong aib-aibnya, karena kerusakan penganut bid`ah tidak menambah kesalehanmu, dan janganlah kamu mencelanya karena dorongan diskriminatif terhadap penganutnya, karena diskriminasi adalah kerusakan dirimu sendiri, sebab tidak selayaknya dokter mengobati pasien dengan obat yang berpotensi menyembuhkan penyakit namun obat itu juga berpotensi mendatangkan penyakit baru. Karena apabila dokter itu sakit, ia sibuk dengan penyakitnya dan lupa mengobati mereka. Akan tetapi selayaknya ia mencari kesehatan untuk dirinya agar ia dapat mengobati para pasien. Hendaklah saat engkau melihat masalah yang menimpa saudara-saudaramu dan hatimu \"kurang sreg\", sebagaimana engkau melihat jika terjadi pada dirimu sendiri dan sebagai \"peringatan\" Tuhanmu terhadapmu, serta rasa kasihanmu kepada saudara-saudara kamu. Walaupun dalam hal itu lebih baik kamu lebih peduli terhadap aib diri kamu sendiri dari pada aib orang lain, dan lakukan saling menasehati satu sama lain diantara kamu, dan hendaklah yang mengorbankan nasehat itu merasa beruntung dan kamu menerimanya. Umar bin Al Khatthab radliallahu 'anhu berkata: 'Semoga Allah subhanallahu wa ta'ala melimpahkan rahmat kepada orang yang menunjukkan aib-aibku kepadaku'. Kamu suka berkata dan orang yang mendengarmu menahan diri demi kebaikanmu, padahal jika dikatakan kepada kamu perkataan yang sama seperti yang kamu katakan, kamu jengkel. Kamu mendapatkan hal-hal yang menjengkelkanmu, sebaliknya kamu mengerjakan apa yang mereka kerjakan, apakah kamu tidak suka dipersalahkan? ', Pikir ulanglah pendapatmu dan pendapat orang-orang yang sezaman denganmu, Selidikilah dahulu sebuah berita sebelum kalian berbicara dan belajarlah sebelum kalian beramal. Karena nanti akan datang suatu zaman yang saat itu yang benar bercampur dengan yang batil, dan yang ma'ruf (baik) menjadi mungkar dan yang mungkar menjadi ma'ruf. Betapa banyak orang yang mendekatkan diri kepada Allah subhanallahu w ta'ala namun dengan hal-hal yang justru menjauhkan dariNya, dan mencari cintaNya dengan hal-hal yang membuatNya murka. Allah subhanallahu wa ta'ala berfirman: \"AFAMAN ZUYYINA LAHU SUU`U 'MALIHI FA RA`AHU HASANA\" (Maka apabila orang yang dijadikan (syaitan) menganggap baik pekerjaannya yang buruk lalu ia meyakini pekerjaan itu baik (sama dengan orang yang tidak ditipu syaitan)? -Qs. Al Fathir: 8-, hendaklah kamu berhenti dari hal-hal yang syubhat sehingga nampak bagi kamu kebenaran yang jelas disertai keterangan, karena orang yang mengintervensi perkara yang ia tidak tahu tanpa ilmu, ia berdosa, dan barangsiapa yang menyelidiki dengan niat ikhlash karena Allah, Allah subhanallahu wa ta'ala akan melihatnya. Hendaklah kamu berpegang teguh dengan Al Qur`an, jadikanlah ia imam dan ajaklah (manusia) untuk menjadikan Al Qur`an sebagai imam. Hendaknya kamu mencari jejak-jejak para pendahulu padanya. Seandainya para ahbar (pendeta yahudi) dan para rahib (pendeta Nashrani) tidak takut kehilangan martabat mereka dan kerusakan kedudukannya dengan menegakkan Al Kitab dan penjelasannya, niscaya mereka tidak akan menyelewengkan dan menyembunyikannya, akan tetapi mereka ketika menentang Al Kitab dengan perbuatan mereka, mereka berusaha mencari cara menipu kaumnya karena perbuatan yang mereka lakukan sendiri, karena mereka khawatir kedudukan mereka dirobohkan, dan manusia memperoleh kejelasan kerusakan mereka, lalu mereka selewengkan Al Kitab dengan tafsir menyeleweng, dan apa yang mereka tidak bisa selewengkan, mereka sembunyikan, lalu mereka diam terhadap perbuatan mereka sendiri karena dorongan untuk mempertahankan kedudukan mereka, dan diam terhadap apa yang diperbuat oleh kaumnya sambil berpura-pura. Sedang Allah subhanallahu wa ta'ala telah mengambil perjanjian dengan orang-orang yang di berikan Al Kitab agar mereka menjelaskannya kepada manusia dan tidak menyembunyikannya, akan tetapi mereka justru cenderung kepadanya dan mengajak manusia menganggap enteng masalah itu. "},{"p":"Darimi","n":589,"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ { وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ } قَالَ الْحَيْضُ قِيلَ لِأَبِي مُحَمَّدٍ أَتَقُولُ بِهَذَا قَالَ لَا سُئِلَ عَبْد اللَّهِ عَنْ حَدِيثِ شُرَيْحٍ تَقُولُ بِهِ قَالَ لَا وَقَالَ ثَلَاثُ حِيَضٍ فِي الشَّهْرِ كَيْفَ يَكُونُ","trj":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [khalid bin Abdullah] dari [Khalid Al Hadzdza`] dari ['Ikrimah] (dalam penafsiran ayat) \"WA LAA YAHILLU LAHUNNA AN YAKTUMNA MAA KHALAQALLAHU FII ARHAAMIHINNA\" (Dan tidak boleh mereka menyembunyikan apa yang diciptakan Allah subhanallahu wa ta'ala dalam rahimnya) -Qs. Al Baqarah: 228-,: 'Maksudnya adalah haid', Dikatakan kepada Abu Muhammad: 'Apakah kamu mengatakan hal itu juga? ', ia menjawab: 'Tidak', dan Abdullah ditanya perihal tentang hadits Syuraih, apakah kamu mengatakan hal itu? ', ia menjawab: 'Tidak', dan ia berkata: 'Bagaimana bisa terjadi tiga kali haid dalam satu bulan? ' \"."},{"p":"Darimi","n":729,"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَمَّنْ حَدَّثَهُ عَنْ مُجَاهِدٍ { وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ } قَالَ حَتَّى يَنْقَطِعَ الدَّمُ { فَإِذَا تَطَهَّرْنَ } قَالَ إِذَا اغْتَسَلْنَ","trj":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [seseorang yang menceritakan kepadanya] dari [Mujahid]: (Tentang ayat) \"WA LAA TAQRABUUHUNNA HATTAA YATHURNA\" (Dan janganlah kalian dekati mereka (wanita yang sedang haid) hingga ia suci) -Qs. Al Baqarah: 222-, ia berkata: \"(Maksudnya adalah) hingga darah (haidnya) berhenti\", dan \"FAIDZAA TATHAHHARNA\" (Dan apabila mereka telah suci) -Qs. Al Baqarah: 222-, ia berkata: \"(maksudnya adalah) jika mereka telah mandi.\""},{"p":"Darimi","n":730,"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ { حَتَّى يَطْهُرْنَ } قَالَ إِذَا انْقَطَعَ الدَّمُ { فَإِذَا تَطَهَّرْنَ } قَالَ اغْتَسَلْنَ","trj":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] \"HATTAA YATHHURNA\" (Hingga mereka suci) -Qs. Al Baqarah: 222-, ia berkata (makksudnya adalah): \"Jika darahnya benar-benar telah berhenti\", (sedang firman-Nya) \"FA IDZAA TATHAHHARNA\" (Dan apabila mereka telah bersuci) -Qs. Al Baqarah: 222-, ia berkata (maksudnya adalah): \"(jika) mereka telah mandi.\" "},{"p":"Darimi","n":760,"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ ابْنِ سَابِطٍ قَالَ سَأَلْتُ حَفْصَةَ بِنْتَ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ أَبِي بَكْرٍ قُلْتُ لَهَا إِنِّي أُرِيدُ أَنْ أَسْأَلَكِ عَنْ شَيْءٍ وَأَنَا أَسْتَحْيِي أَنْ أَسْأَلَكِ عَنْهُ قَالَتْ سَلْ يَا ابْنَ أَخِي عَمَّا بَدَا لَكَ قَالَ أَسْأَلُكِ عَنْ إِتْيَانِ النِّسَاءِ فِي أَدْبَارِهِنَّ فَقَالَتْ حَدَّثَتْنِي أُمُّ سَلَمَةَ قَالَتْ كَانَتْ الْأَنْصَارُ لَا تُجَبِّي وَكَانَتْ الْمُهَاجِرُونَ تُجَبِّي فَتَزَوَّجَ رَجُلٌ مِنْ الْمُهَاجِرِينَ امْرَأَةً مِنْ الْأَنْصَارِ فَجَبَّاهَا فَأَبَتْ الْأَنْصَارِيَّةُ فَأَتَتْ أُمَّ سَلَمَةَ فَذَكَرَتْ ذَلِكَ لَهَا فَلَمَّا أَنْ جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَحْيَتْ الْأَنْصَارِيَّةُ وَخَرَجَتْ فَذَكَرَتْ ذَلِكَ أُمُّ سَلَمَةَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ادْعُوهَا لِي فَدُعِيَتْ لَهُ فَقَالَ لَهَا { نِسَاؤُكُمْ حَرْثٌ لَكَمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } سِمَامًا وَاحِدًا وَالسِّمَامُ السَّبِيلُ الْوَاحِدُ","trj":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Ibnu Sabith] ia berkata: \"Aku pernah bertanya kepada [Hafshah binti Abdur Rahman Ibnu Abu Bakar], aku berkata kepadanya: Aku ingin bertanya kepada kamu perihal sesuatu yang sebenarnya aku malu menanyakannya kepadamu, ia berkata: \"Bertanyalah wahai keponakanku tentang hal yang mengganjal (di hatimu) \", ia bertanya: \"Aku bertanya kepada kamu tentang menggauli isteri-isteri dari dubur mereka?\", maka ia menjawab: \" [Ummu Salamah] radliallahu 'anha pernah menceritakan kepadaku, ia berkata: \"Dahulu orang-orang Anshar tidak pernah menggauli (isteri mereka) dari arah belakang, sedang orang-orang muhajirin biasa menggauli (isteri mereka) dari arah belakang, maka ada seorang laki-laki dari kaum muhajirin menikahi seorang wanita dari kaum anshar, ia menggaulinya dari arah belakang, maka wanita itu menolak, dan ia datang menemui Ummu Salamah radliallahu 'anha, ia menceritakan hal tersebut, maka tatkala Rasulullah shallallahu 'alaihi wasallam datang, wanita anshar itu malu dan keluar, maka Ummu Salamah radliallahu 'anha menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Panggillah wanita tadi untuk menemuiku\", maka dipanggillah ia untuk menemui beliau, kemudian beliau berkata: \"NISAA`UKUM HARTSUN LAKUM FA`TUU HARTSAKUM `ANNA SYI`TUM\" (Isteri-isteri kalian adalah sawah ladang kalian, maka datangilah sawah ladangmu itu bagaimana saja kamu kehendaki) -Qs. Al Baqarah: 223-, yaitu satu arah, maksud dari satu arah adalah dari arah mana saja kamu datangi asalkan sasarannya satu, yaitu kemaluan.\""},{"p":"Darimi","n":761,"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَبَانَ بْنِ صَالِحٍ عَنْ مُجَاهِدٍ قَالَ لَقَدْ عَرَضْتُ الْقُرْآنَ عَلَى ابْنِ عَبَّاسٍ ثَلَاثَ عَرَضَاتٍ أَقِفُ عِنْدَ كُلِّ آيَةٍ أَسْأَلُهُ فِيمَ أُنْزِلَتْ وَفِيمَ كَانَتْ فَقُلْتُ يَا ابْنَ عَبَّاسٍ أَرَأَيْتَ قَوْلَ اللَّهِ تَعَالَى { فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } قَالَ مِنْ حَيْثُ أَمَرَكُمْ أَنْ تَعْتَزِلُوهُنَّ","trj":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah memberitakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Aban bin Shalih] dari [Mujahid] ia berkata: \"Aku telah menunjukkan hafalan Al Qur`an kepada Ibnu Abbas radliallahu 'anhu sebanyak tiga kali, aku berhenti di setiap ayat dan aku menanyakan kepadanya tentang apa ayat tersebut turun? Dan dan di mana ia diturunkan?, aku bertanya: \"Wahai [Ibnu Abbas] radliallahu 'anhu, Bagaimana pendapatmu tentang firman Allah subhanallahu wa ta'ala: \"FAIDZAA TATHAHHARNA FA`TUHUNNA MIN HAITSU `AMARAKUMULLAHU\" (Maka apabila mereka telah suci, maka datangilah mereka dari arah yang perintahkan kepada kalian) -Qs. Al Baqarah: 222-, ia menjawab: \"Di tempat yang Ia perintahkan kepada kalian untuk dijauhi (ketika mereka sedang haid, yaitu kemaluan) \"."},{"p":"Darimi","n":762,"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُجَاهِدٍ { فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } قَالَ أُمِرُوا أَنْ يَأْتُوا مِنْ حَيْثُ نُهُوا","trj":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Utsman bin Al Aswad] dari [Mujahid] ketika menafsirkan ayat: '(Maka datangilah mereka di tempat yang Allah subhanallahu wa ta'ala perintahkan kepada kalian) ' (Qs. Al Baqarah: 222), ia berkata: \"Mereka diperintahkan untuk mendatangi (isteri mereka) di tempat yang mereka dilarang untuk melakukannya (disaat haid) \"."},{"p":"Darimi","n":764,"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا خَالِدُ بْنُ رَبَاحٍ عَنْ عِكْرِمَةَ { نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَالَ إِنَّمَا هُوَ الْفَرْجُ","trj":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Khalid bin Rabah] dari ['Ikrimah] (Ketika menafsirkan ayat): '(Isteri-isteri kalian (bagaikan) sawah ladang kalian, maka datangilah sawah ladang kalian sesuai kehendak kalian) ' (Qs. Al Baqarah: 223), ia berkata: \"Itu adalah kemaluan\"."},{"p":"Darimi","n":765,"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ { فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَالَ ائْتِهَا مِنْ بَيْنِ يَدَيْهَا وَمِنْ خَلْفِهَا بَعْدَ أَنْ يَكُونَ فِي الْمَأْتَى","trj":"Telah mengabarkan kepada kami ['Amru bin 'Aun] dari [Khalid bin Abdullah] dari ['Atha bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] (ketika menafsirkan ayat): '(Maka datangilah sawah ladang kalian sesuai kehendak kalian) ' (Qs. Al Baqarah: 223), ia berkata: \"Datangilah ia dari arah depan dan arah belakangnya selama masih di tempat kedatangan (kemaluan).\""},{"p":"Darimi","n":766,"ar":" أَخْبَرَنَا خَلِيفَةُ بْنُ خَيَّاطٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ قَالَ كَانَ أَهْلُ الْجَاهِلِيَّةِ يَصْنَعُونَ فِي الْحَائِضِ نَحْوًا مِنْ صَنِيعِ الْمَجُوسِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ } فَلَمْ يَزْدَدْ الْأَمْرُ فِيهِنَّ إِلَّا شِدَّةً","trj":"Telah mengabarkan kepada kami [Khalifah bin Khayyath] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] ia berkata: \"Dahulu orang-orang jahiliyah berbuat terhadap wanita haid seperti yang dilakukan oleh orang-orang Majusi, hal itu kemudian disebutkan kepada Rasulullah shallallahu 'alaihi wasallam, maka turunlah ayat: '(Dan mereka bertanya tentang haid, katakanlah haid itu adalah kotoran, maka jauhilah isteri-isteri kalian di saat haid dan janganlah kalian dekati mereka hingga mereka suci) ' (Qs. Al Baqarah: 222), tidaklah urusan tentang mereka itu kecuali semakin tegas.\""},{"p":"Darimi","n":767,"ar":" أَخْبَرَنَا خَلِيفَةُ حَدَّثَنَا مُؤَمَّلٌ عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ { قُلْ هُوَ أَذًى } قَالَ هُوَ الدَّمُ","trj":"Telah mengabarkan kepada kami [Khalifah] telah menceritakan kepada kami [Mu`ammal] dari [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] ketika mentafsirkan firman Allah: '(katakanlah haid itu adalah kotoran…) ' (Qs. Al Baqarah: 222), ia berkata, \"Maksudnya adalah darah.\""},{"p":"Darimi","n":768,"ar":" أَخْبَرَنَا خَلِيفَةُ بْنُ خَيَّاطٍ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ لَيْثًا حَدَّثَ عَنْ عِيسَى بْنِ قَيْسٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ { نِسَاؤُكُم�� حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَالَ إِنْ شِئْتَ فَاعْزِلْ وَإِنْ شِئْتَ فَلَا تَعْزِلْ","trj":"Telah mengabarkan kepada kami [Khalifah bin Khayyath] telah menceritakan kepada kami [Al Mu'tamir] ia berkata: Aku pernah mendengar [Laits] menceritakan dari ['Isa bin Qais] dari [Sa'id bin Musayyib] firman Allah: '(Isteri-isteri kalian bagaikan sawah ladang kalian, maka datangilah sawah ladang kalian sesuai kehendak kalian) ', (Qs. Al Baqarah: 223), ia berkata: \"Jika kamu berkehendak, maka jauhilah dia, dan jika kamu kehendaki, maka jangan kamu jauhi dia.\" "},{"p":"Darimi","n":770,"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُجَاهِدٍ قَالَ مَنْ أَتَى امْرَأَتَهُ فِي دُبُرِهَا فَهُوَ مِنْ الْمَرْأَةِ مِثْلُهُ مِنْ الرَّجُلِ ثُمَّ تَلَا { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } أَنْ تَعْتَزِلُوهُنَّ فِي الْمَحِيضِ الْفَرْجَ ثُمَّ تَلَا { نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَائِمَةً وَقَاعِدَةً وَمُقْبِلَةً وَمُدْبِرَةً فِي الْفَرْجِ","trj":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Utsman bin Al Aswad] dari [Mujahid] ia berkata: \"Barangsiapa menggauli isterinya pada duburnya, maka ia termasuk wanita yang semisalnya dari kalangan laki-laki, kemudian ia membaca ayat: '(Dan mereka bertanya kepada kamu tentang haid, maka katakanlah ia itu kotoran, maka jauhilah wanita-wanita yang tengah haid, dan jangan kalian dekati mereka hingga mereka suci, dan apabila mereka telah suci, maka datangilah mereka dari arah yang Allah subhanallahu wa ta'ala perintahkan kepada kalian) ' (Qs. Al Baqarah: 223), yakni hendaklah kalian jauhi kemaluan mereka ketika sedang haid. Kemudian ia membaca ayat: '(Isteri-isteri kalian bagaikan sawah ladang kalian, maka datangilah sawah ladang kalian sesuai kehendak kalian) ' (Qs. Al Baqarah: 223), yaitu baik berdiri, duduk, dari arah depan atau dari arah depan (tetapi tetap pada) kemaluannya.\""},{"p":"Darimi","n":778,"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا خُصَيْفٌ عَنْ مُجَاهِدٍ قَالَ كَانُوا يَجْتَنِبُونَ النِّسَاءَ فِي الْمَحِيضِ وَيَأْتُونَهُنَّ فِي أَدْبَارِهِنَّ فَسَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ تَعَالَى { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } فِي الْفَرْجِ وَلَا تَعْدُوهُ","trj":"Telah menghabarkan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Khushaif] dari [Mujahid] ia berkata, \"Dahulu mereka menjauhi para wanita di saat haid, dan menggauli mereka pada dubur-dubur mereka, lalu mereka bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal itu, maka Allah subhanallahu wa ta'ala menurunkan ayat: '(Dan mereka bertanya kepada kamu tentang haid, katakanlah ia itu kotor, maka jauhilah wanita yang tengah haid dan jangan kalian dekati mereka hingga mereka suci, dan jika mereka telah suci, maka datangilah mereka sesuai dengan yang Allah perintahkan) ' (Qs. Al Baqarah: 223), yakni pada lubang kemaluannya dan janganlah kalian menyimpang darinya.\""},{"p":"Darimi","n":910,"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ مُعَاذًا كَانَ يُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَأْتِي قَوْمَهُ فَيُصَلِّي بِهِمْ فَجَاءَ ذَاتَ لَيْلَةٍ فَصَلَّى الْعَتَمَةَ وَقَرَأَ الْبَقَرَةَ فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَصَلَّى ثُمَّ ذَهَبَ فَبَلَغَهُ أَنَّ مُعَاذًا يَنَالُ مِنْهُ فَشَكَا ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمُعَاذٍ فَاتِنًا فَاتِنًا فَاتِنًا أَوْ فَتَّانًا فَتَّانًا فَتَّانًا ثُمَّ أَمَرَهُ بِسُورَتَيْنِ مِنْ وَسَطِ الْمُفَصَّلِ قَالَ أَبُو مُحَمَّد نَأْخُذُ بِهَذَا","trj":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari ['Amru bin Dinar] dari [Jabir bin Abdullah], bahwa Mu'adz pernah melakukan shalat bersama Rasulullah shallallahu 'alaihi wasallam, kemudian ia datang kepada kaumnya dan melakukan shalat bersama mereka. Pada suatu malam ia datang dan melakukan shalat Isya` dengan membaca Surat Al Baqarah, kemudian seorang laki-laki Anshar datang melaksanakan shalat dan langsung pergi. Maka sampailah kepadanya kabar bahwa Mu'adz telah mencelanya, maka ia mengadukan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda kepada Mu'adz: \"Apakah engkau akan menjadi tukang fitnah? Apakah engkau akan menjadi tukang fitnah? Apakah engkau akan menjadi tukang fitnah?\" Kemudian beliau memerintahkan agar ia membaca dua surat yang sedang.\" Abu Muhammad berkata, \"Kami mengambil pendapat ini.\" "},{"p":"Darimi","n":1096,"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ قَرَأَ الْآيَتَيْنِ الْآخِرَتَيْنِ مِنْ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","trj":"Telah menceritakan kepada kami [Sa'id? bin 'Amir] dari [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa membaca dua ayat terakhir dari surat Al Baqarah pada malam hari, maka keduanya akan memberikan perlindungan kepadanya.\""},{"p":"Darimi","n":1130,"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَ حُبِسْنَا يَوْمَ الْخَنْدَقِ حَتَّى ذَهَبَ هَوِيٌّ مِنْ اللَّيْلِ حَتَّى كُفِينَا وَذَلِكَ قَوْلُ اللَّهِ تَعَالَى { وَكَفَى اللَّهُ الْمُؤْمِنِينَ الْقِتَالَ وَكَانَ اللَّهُ قَوِيًّا عَزِيزًا } فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالًا فَأَمَرَهُ فَأَقَامَ فَصَلَّى الظُّهْرَ فَأَحْسَنَ كَمَا كَانَ يُصَلِّيهَا فِي وَقْتِهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْعَصْرَ فَصَلَّاهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْمَغْرِبَ فَصَلَّاهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْعِشَاءَ فَصَلَّاهَا وَذَلِكَ قَبْلَ أَنْ يَنْزِلَ { فَإِنْ خِفْتُمْ فَرِجَالًا أَوْ رُكْبَانًا }","trj":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [Ayahnya] ia berkata, \"Kami tertahan pada saat perang Khandaq hingga berlalu sebagian malam hingga kami dihindarkan dari peperangan, dan hal tersebut sebagaimana yang Allah firmankan: '(Dan Allah menghindarkan orang-orang mukmin dari peperangan. Dan adalah Allah Maha Kuat lagi Maha Perkasa) ' (Qs.?Al Ahzab: 25). Kemudian Nabi shallallahu 'alaihi wasallam memanggil Bilal dan memerintahkannya agar mengumandangkan iqamah. Beliau lalu mengerjakan shalat Zhuhur dan melakukannya dengan baik sebagaimana biasa beliau melakukannya pada waktunya, kemudian memerintahkannya untuk mengumandangkan iqamah shalat Asar, lalu beliau mengerjakan shalat Asar. Kemudian memerintahkannya untuk mengumandangkan iqamah shalat Maghrib, lalu beliau mengerjakan shalat Maghrib, kemudian memerintahkannya untuk mengumandangkan iqamah shalat Isya, lalu beliau mengerjakan shalat Isya. Dan itu sebelum turunnya ayat: '(Jika kamu dalam keadaan takut (bahaya), maka shalatlah sambil berjalan atau berkendaraan…) ' (QS. Al Baqarah: 139)."},{"p":"Darimi","n":1278,"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَ كَانَ أَصْحَابُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الرَّجُلُ صَائِمًا فَحَضَرَ الْإِفْطَارُ فَنَامَ قَبْلَ أَنْ يُفْطِرَ لَمْ يَأْكُلْ لَيْلَتَهُ وَلَا يَوْمَهُ حَتَّى يُمْسِيَ وَإِنَّ قَيْسَ بْنَ صِرْمَةَ الْأَنْصَارِيَّ كَانَ صَائِمًا فَلَمَّا حَضَرَ الْإِفْطَارُ أَتَى امْرَأَتَهُ فَقَالَ عِنْدَكِ طَعَامٌ فَقَالَتْ لَا وَلَكِنْ أَنْطَلِقُ فَأَطْلُبُ لَكَ وَكَانَ يَوْمَهُ يَعْمَلُ فَغَلَبَتْهُ عَيْنُهُ وَجَاءَتْ امْرَأَتُهُ فَلَمَّا رَأَتْهُ قَالَتْ خَيْبَةً لَكَ فَلَمَّا انْتَصَفَ النَّهَارُ غُشِيَ عَلَيْهِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ هَذِهِ الْآيَةُ { أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ } فَفَرِحُوا بِهَا فَرَحًا شَدِيدًا { وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }","trj":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Bara`] ia berkata, \"Para sahabat Muhammad shallallahu 'alaihi wasallam; apabila seseorang berpuasa kemudian datang waktu berbuka, maka ia tidur sebelum berbuka, sehingga ia tidak berbuka sehari semalam hingga masuk pada waktu sore. Sesungguhnya Qais bin Shirmah Al Anshari pernah berpuasa, saat waktu berbuka tiba ia menemui isterinya dan bertanya, \"Apakah engkau memiliki makanan?\" Lalu isterinya mengatakan, \"Tidak, akan tetapi aku akan pergi dan mencari untukmu.\" Karena seharian ia lelah bekerja, maka ia pun tertidur. Maka saat isterinya melihatnya, ia berkata, \"Duhai, merugilah engkau.\" Kemudian tatkala pada pertengahan siang hari Qais bin Shirmah pingsan. Lalu hal itu diceritakan kepada Nabi shallallahu 'alaihi wasallam, kemudian turunlah ayat ini: '(Dihalalkan bagi kamu pada malam hari bulan puasa bercampur dengan isteri-isteri kamu) ' maka mereka sangat senang sekali '(dan makan minumlah hingga terang bagimu benang putih dari benang hitam) ' (Qs. Al Baqarah: 187)."},{"p":"Darimi","n":1424,"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ وَافَقْتُ رَبِّي فِي ثَلَاثٍ قُلْتُ يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْتَ مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى فَأَنْزَلَ اللَّهُ تَعَالَى { وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }","trj":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Humaid] dari [Anas], ia berkata; [Umar bin Al Khathab] berkata; \"Rabbku menyepakatiku dalam tiga perkara, yaitu; ketika saya mengatakan; \"Wahai Rasulullah, seandainya anda menjadikan Maqam Ibrahim sebagai tempat shalat maka itu akan lebih baik, kemudian Allah Ta'ala menurunkan ayat: WATTAKHIDZUU MIN MAQAAMI IBRAAHIIMA MUSHALLAA (Dan jadikanlah sebahagian maqam Ibrahim tempat shalat). QS Al Baqarah; 125."},{"p":"Darimi","n":1458,"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا بُكَيْرُ بْنُ عَطَاءٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَعْمُرَ الدِّيلِيَّ يَقُولُ سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَجِّ فَقَالَ الْحَجُّ عَرَفَاتٌ أَوْ يَوْمُ عَرَفَةَ وَمَنْ أَدْرَكَ لَيْلَةَ جَمْعٍ قَبْلَ صَلَاةِ الصُّبْحِ فَقَدْ أَدْرَكَ وَقَالَ أَيَّامُ مِنًى ثَلَاثَةُ أَيَّامٍ { فَمَنْ تَعَجَّلَ فِي يَوْمَيْنِ فَلَا إِثْمَ عَلَيْهِ وَمَنْ تَأَخَّرَ فَلَا إِثْمَ عَلَيْهِ }","trj":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Bukair bin 'Atha`], ia berkata; saya mendengar [Abdurrahman bin Ya'mur Ad Dili] ia berkata; Nabi shallallahu 'alaihi wasallam ditanya mengenai haji, beliau menjawab: \"Haji itu (wukuf) di Arafah, atau pada hari Arafah, barangsiapa menjumpai malam di Muzdalifah sebelum shalat Subuh, berarti ia telah mendapatkan haji.\" Beliau bersabda: \"Hari-hari di Mina adalah tiga hari, barangsiapa mempercepat dalam dua hari maka tidak ada dosa baginya dan barangsiapa yang memperlambat maka tidak ada dosa baginya.\" QS Al Baqarah; 203."},{"p":"Darimi","n":1762,"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ الْيَهُودَ قَالُوا لِلْمُسْلِمِينَ مَنْ أَتَى امْرَأَتَهُ وَهِيَ مُدْبِرَةٌ جَاءَ وَلَدُهُ أَحْوَلَ فَأَنْزَلَ اللَّهُ تَعَالَى { نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }","trj":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] bahwa orang-orang Yahudi berkata kepada kaum Muslimin; \"Barangsiapa mendatangi isterinya dari arah belakang, maka anaknya akan terlahir dalam keadaan juling.\" Maka Allah Ta'ala menurunkan ayat Isteri-isterimu adalah (seperti) Tanah tempat kamu bercocok tanam, maka datangilah tanah tempat bercocok-tanammu itu bagaimana saja kamu kehendaki.\" QS Al Baqarah; 223."},{"p":"Darimi","n":2101,"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْ لَمَّا نَزَلَتْ الْآيَةُ فِي آخِرِ سُورَةِ الْبَقَرَةِ فِي الرِّبَا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَلَاهُنَّ عَلَى النَّاسِ ثُمَّ حَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","trj":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] dari ['Aisyah], ia berkata; \"Ketika turun ayat akhir Surat Al Baqarah tentang riba, Rasulullah shallallahu 'alaihi wasallam keluar dan membacakannya kepada para sahabat, setelah itu beliau mengharamkan bisnis khamer."},{"p":"Darimi","n":2102,"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْ لَمَّا نَزَلَتْ الْآيَاتُ مِنْ أَوَاخِرِ سُورَةِ الْبَقَرَةِ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاقْتَرَأَهُنَّ عَلَى النَّاسِ ثُمَّ نَهَى عَنْ التِّجَارَةِ فِي الْخَمْرِ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Adh Dhuha] dari [Masruq] dari ['Aisyah], ia berkata; \"Ketika turun ayat akhir dari Surat Al Baqarah, Rasulullah shallallahu 'alaihi wasallam keluar dan membacakannya kepada para sahabat, kemudian beliau melarang dari bisnis khamer.\""},{"p":"Darimi","n":2744,"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ { إِذَا حَضَرَ أَحَدَكُمْ الْمَوْتُ إِنْ تَرَكَ خَيْرًا الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ } فَأَمَرَ أَنْ يُوصِيَ لِوَالِدَيْهِ وَأَقَارِبِهِ ثُمَّ نُسِخَ بَعْدَ ذَلِكَ فِي سُورَةِ النِّسَاءِ فَجَعَلَ لِلْوَالِدَيْنِ نَصِيبًا مَعْلُومًا وَأَلْحَقَ لِكُلِّ ذِي مِيرَاثٍ نَصِيبَهُ مِنْهُ وَلَيْسَتْ لَهُمْ وَصِيَّةٌ فَصَارَتْ الْوَصِيَّةُ لِمَنْ لَا يَرِثُ مِنْ قَرِيبٍ وَغَيْرِهِ","trj":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] dari [Qatadah] ia berkata tentang firman-Nya: '(Apabila seorang di antara kamu kedatangan (tanda-tanda) maut, jika ia meninggalkan harta yang banyak, berwasiat untuk ibu-bapak dan karib kerabatnya) '. (Qs. Al Baqarah: 180), Allah memerintahkan agar berwasiat kepada kedua orang tua dan karib kerabatnya. Kemudian hukum ini dihapus dengan ayat di dalam surat An Nisaa`. Dia menetapkan bahwa kedua orang tua telah mendapatkan bagian yang telah ditentukan, dan memberikan warisan kepada setiap orang yang berhak mendapat warisan dari harta warisannya, dan tidak ada lagi wasiat bagi mereka. Wasiat hanya diberikan kepada orang-orang yang tidak berhak mewarisi baik dari kerabat maupun lainnya.\""},{"p":"Darimi","n":2746,"ar":" حَدَّثَنَا أَحْمَدُ بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ يَزِيدَ عَنْ عِكْرِمَةَ وَالْحَسَنِ { إِنْ تَرَكَ خَيْرًا الْوَصِيَّةُ لِلْوَالِدَيْنِ وَالْأَقْرَبِينَ } وَكَانَتْ الْوَصِيَّةُ كَذَلِكَ حَتَّى نَسَخَتْهَا آيَةُ الْمِيرَاثِ","trj":"Telah menceritakan kepada kami [Ahmad bin Isma'il] telah menceritakan kepada kami [Abu Tumailah] dari [Al Husain bin Waqid] dari [Yazid] dari [Ikrimah] dan [Al Hasan] tentang ayat: '(Jika ia meninggalkan harta yang banyak, berwasiat untuk ibu-bapak dan karib kerabatnya) ' (Qs. Al Baqarah: 180), begitulah wasiat dahulu hingga dihapus oleh ayat tentang harta warisan.\""},{"p":"Darimi","n":2834,"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا فِطْرٌ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ مَا مِنْ بَيْتٍ يُقْرَأُ فِيهِ سُورَةُ الْبَقَرَةِ إِلَّا خَرَجَ مِنْهُ الشَّيْطَانُ وَلَهُ ضَرِيطٌ","trj":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Fithr] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] ia berkata; Tidak ada satu rumah pun yang di dalamnya dibaca surat Al Baqarah kecuali setan keluar darinya dengan terkentut-kentut."},{"p":"Darimi","n":2835,"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا عَبْدَةُ عَنْ خَالِدِ بْنِ مَعْدَانَ قَالَ سُورَةُ الْبَقَرَةِ تَعْلِيمُهَا بَرَكَةٌ وَتَرْكُهَا حَسْرَةٌ وَلَا يَسْتَطِيعُهَا الْبَطَلَةُ وَهِيَ فُسْطَاطُ الْقُرْآنِ","trj":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Abdah] dari [Khalid bin Ma'dan] ia berkata; Mengajarkan surat Al Baqarah adalah keberkahan dan meninggalkannya adalah kerugian. Para penyihir pun tidak akan sanggup menghadapinya. Ia adalah penyempurna Al Qur'an."},{"p":"Darimi","n":2836,"ar":" حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ أَنَّهُ قَالَ إِنَّ لِكُلِّ شَيْءٍ سَنَامًا وَإِنَّ سَنَامَ الْقُرْآنِ سُورَةُ الْبَقَرَةِ وَإِنَّ لِكُلِّ شَيْءٍ لُبَابًا وَإِنَّ لُبَابَ الْقُرْآنِ الْمُفَصَّلُ قَالَ أَبُو مُحَمَّد اللُّبَابُ الْخَالِصُ","trj":"Telah menceritakan kepada kami [Amr bin 'Ashim] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ashim] dari [Abu Al Ahwash] dari [Abdullah] bahwa ia berkata; Sesungguhnya setiap sesuatu memiliki pemimpin, sesungguhnya pemimpin Al Qur'an adalah surat Al Baqarah. Dan sesungguhnya setiap sesuatu memiliki inti dan inti Al Qur'an adalah Al Mufashshal. [Abu Muhammad] berkata; Lubab berarti inti. "},{"p":"Darimi","n":2837,"ar":" حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبَانَ عَنْ مُحَمَّدِ بْنِ طَلْحَةَ عَنْ زُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ قَالَ مَنْ قَرَأَ سُورَةَ الْبَقَرَةِ تُوِّجَ بِهَا تَاجًا فِي الْجَنَّةِ","trj":"Telah menceritakan kepada kami [Isma'il bin Aban] dari [Muhammad bin Thalhah] dari [Zubaid] dari [Abdurrahman bin Al Aswad] ia berkata; Barangsiapa yang membaca surat Al Baqarah, maka ia akan diberi mahkota kelak di dalam surga."},{"p":"Darimi","n":2838,"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي الْأَحْوَصِ قَالَ قَالَ عَبْدُ اللَّهِ إِنَّ الشَّيْطَانَ إِذَا سَمِعَ سُورَةَ الْبَقَرَةِ تُقْرَأُ فِي بَيْتٍ خَرَجَ مِنْهُ","trj":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syu'bah] dari dari [Salamah bin Kuhail] dari [Abu Al Ahwash] ia berkata; [Abdullah] berkata; Sesungguhnya jika setan mendengar surat Al Baqarah dibaca di dalam sebuah rumah, ia pasti akan keluar darinya."},{"p":"Darimi","n":2839,"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ حَدَّثَنِي أَيْفَعُ بْنُ عَبْدٍ الْكَلَاعِيُّ قَالَ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ سُورَةِ الْقُرْآنِ أَعْظَمُ قَالَ قُلْ هُوَ اللَّهُ أَحَدٌ قَالَ فَأَيُّ آيَةٍ فِي الْقُرْآنِ أَعْظَمُ قَالَ آيَةُ الْكُرْسِيِّ { اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ } قَالَ فَأَيُّ آيَةٍ يَا نَبِيَّ اللَّهِ تُحِبُّ أَنْ تُصِيبَكَ وَأُمَّتَكَ قَالَ خَاتِمَةُ سُورَةِ الْبَقَرَةِ فَإِنَّهَا مِنْ خَزَائِنِ رَحْمَةِ اللَّهِ مِنْ تَحْتِ عَرْشِهِ أَعْطَاهَا هَذِهِ الْأُمَّةَ لَمْ تَتْرُكْ خَيْرًا مِنْ خَيْرِ الدُّنْيَا وَالْآخِرَةِ إِلَّا اشْتَمَلَتْ عَلَيْهِ","trj":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shafwan] telah menceritakan kepadaku [Aifa' bin Abdul Kala'i] ia berkata; Ada seorang bertanya; Wahai Rasulullah, surat Al Qur'an mana yang paling agung? Beliau menjawab: \"QUL HUWALLAHU AHAD (surat Al Ikhlas).\" Ia bertanya lagi; Lalu ayat apa lagi yang paling agung di dalam Al Qur'an? Beliau menjawab: \"Ayat Kursi: ALLAHU LAAILAAHA ILLA HUWAL HAYYUL QAYYUM (Allah tidak ada Ilah melainkan Dia Yang Hidup kekal lagi terus menerus mengurus (makhlukNya)).\" Ia bertanya lagi; Ayat mana wahai Nabiyullah, yang engkau dan juga umatmu inginkan untuk mendapatkannya? Beliau menjawab: \"Ayat penutup surat Al Baqarah, sebab sesungguhnya ia termasuk perbendaharaan rahmat Allah dari bawah ArasyNya. Dia memberikannya kepada umat ini. Tidak ada satu kebaikan pun dari pada kebaikan dunia dan akhirat kecuali telah dikandung olehnya.\" "},{"p":"Darimi","n":2841,"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا أَبُو الْعُمَيْسِ عَنْ الشَّعْبِيِّ قَالَ قَالَ عَبْدُ اللَّهِ مَنْ قَرَأَ عَشْرَ آيَاتٍ مِنْ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ لَمْ يَدْخُلْ ذَلِكَ الْبَيْتَ شَيْطَانٌ تِلْكَ اللَّيْلَةَ حَتَّى يُصْبِحَ أَرْبَعًا مِنْ أَوَّلِهَا وَآيَةُ الْكُرْسِيِّ وَآيَتَانِ بَعْدَهَا وَثَلَاثٌ خَوَاتِيمُهَا أَوَّلُهَا { لِلَّهِ مَا فِي السَّمَوَاتِ }","trj":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Abu Al 'Umais] dari [Asy Sya'bi] ia berkata; [Abdullah] berkata; Barangsiapa yang membaca sepuluh ayat dari surat Al Baqarah pada malam hari, niscaya setan tidak akan masuk ke dalam rumahnya pada malam itu hingga pagi hari. Yaitu empat ayat dari awal surat, ayat kursi dan dua ayat setelahnya, serta tiga ayat penutup surat, yaitu mulai dari ayat: LILLAAHI MAA FIS SAMAAWAATI… (Kepunyaan Allahlah segala apa yang ada di langit…) "},{"p":"Darimi","n":2842,"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادٌ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ ابْنِ مَسْعُودٍ قَالَ مَنْ قَرَأَ أَرْبَعَ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَآيَةَ الْكُرْسِيِّ وَآيَتَانِ بَعْدَ آيَةِ الْكُرْسِيِّ وَثَلَاثًا مِنْ آخِرِ سُورَةِ الْبَقَرَةِ لَمْ يَقْرَبْهُ وَلَا أَهْلَهُ يَوْمَئِذٍ شَيْطَانٌ وَلَا شَيْءٌ يَكْرَهُهُ وَلَا يُقْرَأْنَ عَلَى مَجْنُونٍ إِلَّا أَفَاقَ","trj":"Telah mengabarkan kepada kami [Amr bin 'Ashim] telah menceritakan kepada kami [Hammad] dari ['Ashim] dari [Asy Sya'bi] dari [Ibnu Mas'ud] ia berkata; Barangsiapa yang membaca empat ayat dari awal surat Al Baqarah, ayat kursi, dua ayat setelahnya dan tiga ayat terakhir dari surat al Baqarah, maka tidak ada satu setan pun yang mendekati dirinya dan keluarganya pada hari itu, serta tidak ada pula sesuatu pun yang ia benci (mendatangkan madharat baginya). Tidaklah dibacakan ayat-ayat tersebut kepada orang gila, kecuali ia pasti sadar."},{"p":"Darimi","n":2843,"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ عَمَّنْ سَمِعَ عَلِيًّا يَقُولُ مَا كُنْتُ أَرَى أَنَّ أَحَدًا يَعْقِلُ يَنَامُ حَتَّى يَقْرَأَ هَؤُلَاءِ الْآيَاتِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَإِنَّهُنَّ لَمِنْ كَنْزٍ تَحْتَ الْعَرْشِ","trj":"Telah menceritakan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari [Abu Ishaq] dari [orang yang mendengar] [Ali] berkata; Aku tidak melihat seorang berakal tidur hingga ia membaca ayat-ayat terakhir surat Al Baqarah. Sesungguhnya ayat-ayat tersebut termasuk perbendaharaan (rahmat Allah) di bawah 'Arasy."},{"p":"Darimi","n":2844,"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِي سِنَانٍ عَنْ الْمُغِيرَةِ بْنِ سُبَيْعٍ وَكَانَ مِنْ أَصْحَابِ عَبْدِ اللَّهِ قَالَ مَنْ قَرَأَ عَشْرَ آيَاتٍ مِنْ الْبَقَرَةِ عِنْدَ مَنَامِهِ لَمْ يَنْسَ الْقُرْآنَ أَرْبَعُ آيَاتٍ مِنْ أَوَّلِهَا وَآيَةُ الْكُرْسِيِّ وَآيَتَانِ بَعْدَهَا وَثَلَاثٌ مِنْ آخِرِهَا قَالَ إِسْحَقُ لَمْ يَنْسَ مَا قَدْ حَفِظَ قَالَ أَبُو مُحَمَّد مِنْهُمْ مَنْ يَقُولُ الْمُغِيرَةُ بْنُ سُمَيْعٍ","trj":"Telah menceritakan kepada kami [Ishaq bin Isa] dari [Abu Al Ahwash] dari [Abu Sinan] dari [Al Mughirah bin Subai'], ia termasuk sahabat Abdullah, ia berkata; Barangsiapa yang membaca sepuluh ayat dari surat Al Baqarah ketika hendak tidur, maka ia tidak akan lupa Al Qur'an. Yaitu empat ayat dari awal surat, ayat kursi, dua ayat setelahnya dan tiga ayat terakhir. Ishaq berkata; Ia tidak akan lupa ayat-ayat Al Qur'an yang telah dihafalnya. Abu Muhammad berkata; Di antara mereka yang mengatakan adalah Al Mughirah bin Sumai'."},{"p":"Darimi","n":2846,"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا أَشْعَثُ بْنُ عَبْدِ الرَّحْمَنِ الْجَرْمِيُّ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ كَتَبَ كِتَابًا قَبْلَ أَنْ يَخْلُقَ السَّمَوَاتِ وَالْأَرْضَ بِأَلْفَيْ عَامٍ فَأَنْزَلَ مِنْهُ آيَتَيْنِ خَتَمَ بِهِمَا سُورَةَ الْبَقَرَةِ وَلَا تُقْرَأَانِ فِي دَارٍ ثَلَاثَ لَيَالٍ فَيَقْرَبُهَا شَيْطَانٌ","trj":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Asy'ats bin Abdurrahman Al Jarmi] dari [Abu Qilabah] dari [Abu Al Asy'ats Ash Shan'ani] dari [An Nu'man bin Basyir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah menulis sebuah kitab dua ribu tahun sebelum Dia menciptakan langit dan bumi. Lalu Dia menurunkan dua ayat dari kitab tersebut, Dia menutup surat Al Baqarah dengan kedua ayat itu. Dan jika dua ayat itu dibaca di sebuah rumah selama tiga malam, maka setan tidak dapat mendekatinya.\""},{"p":"Darimi","n":2847,"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ الْآيَتَيْنِ الْآخِرَتَيْنِ مِنْ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","trj":"Telah menceritakan kepada kami [Sa'id bin Amir] dari [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang membaca dua ayat terakhir dari surat Al Baqarah pada malam hari, maka kedua ayat itu telah mencukupinya.\""},{"p":"Darimi","n":2849,"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا بَشِيرٌ هُوَ ابْنُ الْمُهَاجِرِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ يَقُولُ تَعَلَّمُوا سُورَةَ الْبَقَرَةِ فَإِنَّ أَخْذَهَا بَرَكَةٌ وَتَرْكَهَا حَسْرَةٌ وَلَا يَسْتَطِيعُهَا الْبَطَلَةُ ثُمَّ سَكَتَ سَاعَةً ثُمَّ قَالَ تَعَلَّمُوا سُورَةَ الْبَقَرَةِ وَآلِ عِمْرَانَ فَإِنَّهُمَا الزَّهْرَاوَانِ وَإِنَّهُمَا تُظِلَّانِ صَاحِبَهُمَا يَوْمَ الْقِيَامَةِ كَأَنَّهُمَا غَمَامَتَانِ أَوْ غَيَايَتَانِ أَوْ فِرْقَانِ مِنْ طَيْرٍ صَوَافَّ وَإِنَّ الْقُرْآنَ يَلْقَى صَاحِبَهُ يَوْمَ الْقِيَامَةِ حِينَ يَنْشَقُّ عَنْهُ الْقَبْرُ كَالرَّجُلِ الشَّاحِبِ فَيَقُولُ لَهُ هَلْ تَعْرِفُنِي فَيَقُولُ مَا أَعْرِفُكَ فَيَقُولُ أَنَا صَاحِبُكَ الْقُرْآنُ الَّذِي أَظْمَأْتُكَ فِي الْهَوَاجِرِ وَأَسْهَرْتُ لَيْلَكَ وَإِنَّ كُلَّ تَاجِرٍ مِنْ وَرَاءِ تِجَارَتِهِ وَإِنَّكَ الْيَوْمَ مِنْ وَرَاءِ كُلِّ تِجَارَةٍ فَيُعْطَى الْمُلْكَ بِيَمِينِهِ وَالْخُلْدَ بِشِمَالِهِ وَيُوضَعُ عَلَى رَأْسِهِ تَاجُ الْوَقَارِ وَيُكْسَى وَالِدَاهُ حُلَّتَيْنِ لَا يُقَوَّمُ لَهُمَا الدُّنْيَا فَيَقُولَانِ بِمَ كُسِينَا هَذَا وَيُقَالُ لَهُمَا بِأَخْذِ وَلَدِكُمَا الْقُرْآنَ ثُمَّ يُقَالُ لَهُ اقْرَأْ وَاصْعَدْ فِي دَرَجِ الْجَنَّةِ وَغُرَفِهَا فَهُوَ فِي صُعُودٍ مَا دَامَ يَقْرَأُ هَذًّا كَانَ أَوْ تَرْتِيلًا","trj":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Basyir] ia adalah Ibnu Al Muhajir telah menceritakan kepadaku [Abdullah bin Buraidah] dari [ayahnya] ia berkata; Aku pernah duduk di sebelah Nabi shallallahu 'alaihi wasallam, aku mendengar beliau bersabda: \"Pelajarilah surat Al Baqarah sebab mempelajarinya adalah keberkahan dan meninggalkannya adalah kerugian. Para penyihir tidak mampu mengalahkannya.\" Kemudian beliau diam sesaat, lalu bersabda: \"Pelajarilah surah Al Baqarah dan surah Ali Imran, sesungguhnya kedua surat itu dinamakan 'az zahrawan' dan kedua surat itu juga akan menaungi pembacanya pada hari kiamat. Seakan-akan kedua surat itu seperti dua buah awan atau dua benda yang biasa menaungi manusia atau dua kelompok burung yang membentangkan sayapnya. Sesungguhnya Al Qur'an akan menemui pembacanya pada hari kiamat ketika kubur terbelah seperti seorang laki-laki pucat karena takut. Ia berkata kepada pembacanya; Apakah engkau mengenalku? Ia menjawab; Aku tidak mengenalmu. Ia berkata; Aku adalah temanmu, Al Qur'an, yang menghilangkan haus pada siang hari yang panas dan membuatmu begadang di malam hari. Sesungguhnya setiap pedagang akan mendapatkan laba dari perdagangannya. Sesungguhnya hari ini engkau mendapatkan pahala dari setiap perdagangan (yang telah engkau lakukan). Lalu kerajaan diberikan di tangan kanan pembaca Al Qur'an itu dan keabadian di tangan kirinya, serta diletakkan mahkota ketenangan di kepalanya. Sementara kedua orang tuanya diberi dua perhiasan yang tidak ternilai harganya di dunia. Kedua orang tuanya berkata; Karena apa kami diberi perhiasan ini? Dikatakan kepada keduanya; Karena anak kalian mempelajari Al Qur'an. Kemudian dikatakan kepadanya; Bacalah dan naiklah ke tangga-tangga surga dan kamar-kamarnya. Maka ia pun terus naik selama ia membaca, baik secara cepat maupun secara lambat.\" "},{"p":"Darimi","n":2850,"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي مُعَاوِيَةُ عَنْ أَبِي يَحْيَى سُلَيْمِ بْنِ عَامِرٍ أَنَّهُ سَمِعَ أَبَا أُمَامَةَ يَقُولُ إِنَّ أَخًا لَكُمْ أُرِيَ فِي الْمَنَامِ أَنَّ النَّاسَ يَسْلُكُونَ فِي صَدْعِ جَبَلٍ وَعْرٍ طَوِيلٍ وَعَلَى رَأْسِ الْجَبَلِ شَجَرَتَانِ خَضْرَاوَانِ تَهْتِفَانِ هَلْ فِيكُمْ مَنْ يَقْرَأُ سُورَةَ الْبَقَرَةِ هَلْ فِيكُمْ مَنْ يَقْرَأُ سُورَةَ آلِ عِمْرَانَ فَإِذَا قَالَ الرَّجُلُ نَعَمْ دَنَتَا بِأَعْذَاقِهِمَا ��َتَّى يَتَعَلَّقَ بِهِمَا فَتَخْطِرَانِ بِهِ الْجَبَلَ قَالَ أَبُو مُحَمَّد الْأَعْذَاقُ الْأَغْصَانُ","trj":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Mu'awiyah] dari [Abu Yahya Sulaim bin Amir] bahwa ia mendengar [Abu Umamah] berkata; Sesungguhnya ada seorang saudara kalian yang diperlihatkan dalam mimpi bahwa manusia berjalan di jalan setapak sebuah gunung yang tidak rata lagi panjang. Di puncak gunung itu ada dua batang pohon hijau yang bersuara; Apakah di antara kalian ada orang yang membaca surah Al Baqarah? Apakah di antara kalian ada orang yang membaca surah Ali Imran? Tiba-tiba ada seseorang menjawab; Ya, maka kedua pohon itu mendekatkan dahannya hingga orang itu dapat meraihnya. Lalu kedua pohon itu membawanya melewati gunung. Abu Muhammad berkata; Al A'dzaq berarti dahan pohon."},{"p":"Darimi","n":2851,"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ زَيْدٍ عَنْ جَابِرٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَ قَرَأَ رَجُلٌ عِنْدَ عَبْدِ اللَّهِ الْبَقَرَةَ وَآلَ عِمْرَانَ فَقَالَ قَرَأْتَ سُورَتَيْنِ فِيهِمَا اسْمُ اللَّهِ الْأَعْظَمُ الَّذِي إِذَا دُعِيَ بِهِ أَجَابَ وَإِذَا سُئِلَ بِهِ أَعْطَى","trj":"Telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqqi] dari [Ubaidullah bin Amr] dari [Zaid] dari [Jabir] dari [Abu Adl Dluha] dari [Masruq] dari [Abdullah] ia berkata; Ada seseorang membaca surat Al Baqarah dan surat Ali Imran di samping Abdullah, lalu ia pun berkata; Engkau telah membaca dua surat yang di dalamnya terdapat nama Allah yang paling agung, yang apabila digunakan ketika berdoa pasti diperkenankan dan apabila digunakan ketika meminta pasti dikabulkan."},{"p":"Darimi","n":2852,"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي عَطَّافٍ عَنْ كَعْبٍ قَالَ مَنْ قَرَأَ الْبَقَرَةَ وَآلَ عِمْرَانَ جَاءَتَا يَوْمَ الْقِيَامَةِ تَقُولَانِ رَبَّنَا لَا سَبِيلَ عَلَيْهِ","trj":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abdus Salam bin Harb] dari [Al Jurairi] dari [Abu 'Aththaf] dari [Ka'b] ia berkata; Barangsiapa yang membaca surat Al Baqarah dan surat Ali Imran, maka kedua surat itu akan datang pada hari kiamat seraya berkata; Wahai Rabb kami, tidak ada alasan untuk mencelakainya."},{"p":"Darimi","n":2942,"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا إِبْرَاهِيمُ الْهَجَرِيُّ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ لَا أُلْفِيَنَّ أَحَدَكُمْ يَضَعُ إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَى يَتَغَنَّى وَيَدَعُ أَنْ يَقْرَأَ سُورَةَ الْبَقَرَةِ فَإِنَّ الشَّيْطَانَ يَفِرُّ مِنْ الْبَيْتِ يُقْرَأُ فِيهِ سُورَةُ الْبَقَرَةِ وَإِنَّ أَصْفَرَ الْبُيُوتِ الْجَوْفُ يَصْفَرُ مِنْ كِتَابِ اللَّهِ","trj":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Ibrahim Al Hajari] dari [Abu Al Ahwash] dari [Abdullah] berkata; Sungguh, aku tidak akan menemui salah seorang dari kalian yang meletakkan salah satu kaki di atas kaki lainnya sambil melantunkan Al Qur'an namun ia meninggalkan membaca surat Al Baqarah, karena sesungguhnya setan akan lari dari rumah yang dibacakan surat Al Baqarah di dalamnya. Dan sesungguhnya rumah yang paling kosong adalah rumah yang kosong dari (bacaan) kitab Allah."},{"p":"Ibnu Majah","n":1325,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ وَأَسْبَاطُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَلْقَمَةَ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآيَتَانِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ مَنْ قَرَأَهُمَا فِي لَيْلَةٍ كَفَتَاهُقَالَ حَفْصٌ فِي حَدِيثِهِ قَالَ عَبْدُ الرَّحْمَنِ فَلَقِيتُ أَبَا مَسْعُودٍ وَهُوَ يَطُوفُ فَحَدَّثَنِي بِهِ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dan [Asbath bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari ['Abdurrahman bin Yazid] dari [Alqamah] dari [Abu Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca dua ayat terakhir dari surat Al Baqarah pada suatu malam, maka itu telah mencukupi. \" Hafsh menyebutkan dalam haditsnya, \"'Abdurrahman berkata, \"Aku bertemu Abu Mas'ud ketika thawaf, lalu ia menceritakan hadits itu kepadaku. \""},{"p":"Ibnu Majah","n":1326,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ الْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","trj":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Abdurrahman bin Yazid] dari [Abu Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca dua ayat terakhir dari surat Al Baqarah dalam satu malam, maka itu telah cukup. \""},{"p":"Ibnu Majah","n":2916,"ar":"حَدَّثَنَا الْعَبَّاسُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍأَنَّهُ لَمَّا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ طَوَافِ الْبَيْتِ أَتَى مَقَامَ إِبْرَاهِيمَ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ هَذَا مَقَامُ أَبِينَا إِبْرَاهِيمَ الَّذِي قَالَ اللَّهُ سُبْحَانَهُ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ الْوَلِيدُ فَقُلْتُ لِمَالِكٍ هَكَذَا قَرَأَهَا{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ نَعَمْ","trj":"Telah menceritakan kepada kami [Al 'Abbas bin 'Utsman Ad Dimasyqi]; telah menceritakan kepada kami [Al Walid bin Muslim] dari [Malik bin Anas] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir] radliallahu 'anhu, ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam selesai melaksanakan Thawaf di Baitullah, maka beliau mendatangi Maqam Ibrahim. Kemudian 'Umar radliallahu 'anhu bertanya; 'Wahai Rasulullah, apakah ini maqam bapak kita (Ibrahim 'Alaihis Salam) yang Allah Subhanahu Wa Ta'ala telah sebutkan dalam firman-Nya: 'Dan jadikanlah sebagian dari Maqam Ibrahim sebagai tempat shalat.' (Qs. Al Baqarah 2:125)\" Al Walid berkata; 'Aku bertanya kepada Malik; 'Beginikah Umar membacanya; 'Dan jadikanlah sebagian dari Maqam Ibrahim sebagai tempat Shalat? ' Malik menjawab; 'Ya.'"},{"p":"Ibnu Majah","n":2974,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا الثَّوْرِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَتْ قُرَيْشٌ نَحْنُ قَوَاطِنُ الْبَيْتِ لَا نُجَاوِزُ الْحَرَمَ فَقَالَ اللَّهُ عَزَّ وَجَلَّ{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }","trj":"Telah menceritakan kepada kami [Muhammad bin Yahya]; telah menceritakan kepada kami [Abdurrazaq]; telah menceritakan kepada kami [Ats Tsauri] dari [Hisyam bin Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; \"Seseorang dari kalangan kaum Quraisy berkata; 'Kami adalah penduduk di sekitar Baitullah, dan (tinggal) tidak jauh dari daerah Haram. Allah Subhanahu Wa Ta'ala telah berfirman: 'Kemudian bertolaklah kamu dari tempat bertolaknya orang-orang banyak (Arafah) …'(Qs. Al Baqarah 2: 199) "},{"p":"Ibnu Majah","n":2986,"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُحَمَّدٍ حَدَّثَنَا وَكِيعٌ عَنْ الْمَسْعُودِيِّ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَلَمَّا أَتَى عَبْدُ اللَّهِ بْنُ مَسْعُودٍ جَمْرَةَ الْعَقَبَةِ اسْتَبْطَنَ الْوَادِيَ وَاسْتَقْبَلَ الْكَعْبَةَ وَجَعَلَ الْجَمْرَةَ عَلَى حَاجِبِهِ الْأَيْمَنِ ثُمَّ رَمَى بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ ثُمَّ قَالَ مِنْ هَاهُنَا وَالَّذِي لَا إِلَهَ غَيْرُهُ رَمَى الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","trj":"Telah menceritakan kepada kami [Ali bin Muhammad]; telah menceritakan kepada kami [Waki'] dari [Al Mas'udi] dari [Jami' bin Syaddad] dari [Abdurrahman bin Yazid], ia berkata; \"Ketika [Abdullah bin Mas'ud] datang (hendak melontar) jumrah Aqabah, ia masuk ke tengah lembah, menghadap kiblat dan memposisikan tempat jumrah di sebelah kanan. Kemudian ia melontar tujuh kerikil, bertakbir pada tiap lontaran, kemudian ia berkata; 'Demi Dzat yang tidak ada tuhan selain Dia, yang di turunkan kepadanya surat Al Baqarah (Rasulullah shallallahu 'alaihi wasallam), 'dari sebelah sinilah (melontar jumrah Aqabah) beliau melakukannya'.\""},{"p":"Ibnu Majah","n":3035,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْوَلِيدِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ قَالَقَعَدْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ فِي الْمَسْجِدِ فَسَأَلْتُهُ عَنْ هَذِهِ الْآيَةِ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ كَعْبٌ فِيَّ أُنْزِلَتْ كَانَ بِي أَذًى مِنْ رَأْسِي فَحُمِلْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي فَقَالَ مَا كُنْتُ أُرَى الْجُهْدَ بَلَغَ بِكَ مَا أَرَى أَتَجِدُ شَاةً قُلْتُ لَا قَالَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ فَالصَّوْمُ ثَلَاثَةُ أَيَّامٍ وَالصَّدَقَةُ عَلَى سِتَّةِ مَسَاكِينَ لِكُلِّ مِسْكِينٍ نِصْفُ صَاعٍ مِنْ طَعَامٍ وَالنُّسُكُ شَاةٌ","trj":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Al Walid], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Ashbahani] dari [Abdullah bin Ma'qil], ia berkata; \"Aku duduk di samping [Ka'ab bin 'Ujrah] di dalam masjid, lalu kutanyai tentang firman Allah; '..maka wajiblah atasnya berfidyah, yaitu berpuasa atau bersedekah atau berkurban…' (Qs Albaqarah 2: 196), Ka'ab pun menjawab; 'Ayat itu diturunkan tentang diriku. Karena dulu aku pernah terserang penyakit di kepalaku, lalu aku dibawa kepada Rasulullah shallallahu 'alaihi wasallam sedang kutu busuk berhamburan di wajahku.' Maka beliau bersabda: 'Aku tidak seharusnya melihat keletihan yang menimpamu seperti yang kulihat ini. Apakah kamu memiliki seekor kambing? ' Aku menjawab; 'Tidak.' (Perawi berkata); 'Maka turunlah ayat ini, '..maka wajiblah atasnya berfidyah, yaitu berpuasa, atau bersedekah atau berkurban..' (Perawi) berkata; 'Puasa tiga hari, sedekah untuk enam orang miskin dan setiap satu orang miskin diberi setengah sha' makanan pokok, serta berkurban dengan seekor kambing.'"},{"p":"Ibnu Majah","n":3338,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَلِيُّ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا نَزَلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي الرِّبَا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ali bin Muhammad] keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] dari [Aisyah] radliallahu 'anha, dia berkata, \"Ketika turun beberapa ayat dari penutup surat Al Baqarah tentang riba, Rasulullah shallallahu 'alaihi wasallam keluar dan mengharamkan jual beli khamer, \""},{"p":"Ibnu Majah","n":3504,"ar":"حَدَّثَنَا هَارُونُ بْنُ حَيَّانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَنْبَأَنَا عَبْدَةُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو جَنَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ أَبِي لَيْلَى قَالَكُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ أَعْرَابِيٌّ فَقَالَ إِنَّ لِي أَخًا وَجِعًا قَالَ مَا وَجَعُ أَخِيكَ قَالَ بِهِ لَمَمٌ قَالَ اذْهَبْ فَأْتِنِي بِهِ قَالَ فَذَهَبَ فَجَاءَ بِهِ فَأَجْلَسَهُ بَيْنَ يَدَيْهِ فَسَمِعْتُهُ عَوَّذَهُ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ الْبَقَرَةِ وَآيَتَيْنِ مِنْ وَسَطِهَا{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ خَاتِمَتِهَا وَآيَةٍ مِنْ آلِ عِمْرَانَ أَحْسِبُهُ قَالَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ }الْآيَةَ وَآيَةٍ مِنْ الْمُؤْمِنِينَ{ وَمَنْ يَدْعُ مَعَ اللَّهِ إِلَهًا آخَرَ لَا بُرْهَانَ لَهُ بِهِ }وَآيَةٍ مِنْ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا مَا اتَّخَذَ صَاحِبَةً وَلَا وَلَدًا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الْأَعْرَابِيُّ قَدْ بَرَأَ لَيْسَ بِهِ بَأْسٌ","trj":"Telah menceritakan kepada kami [Harun bin Hayyan] telah menceritakan kepada kami [Ibrahim bin Musa] telah memberitakan kepada kami ['Abdah bin Sulaiman] telah menceritakan kepada kami [Abu Janab] dari [Abdurrahman bin Abu Laila] dari ayahnya [Abu Laila] dia berkata, \"Ketika aku sedang duduk di samping Nabi shallallahu 'alaihi wasallam, tiba-tiba datang seorang Arab Badui seraya berkata, 'Sesungguhnya aku mempunyai saudara yang menderita sakit.\" Beliau bertanya: \"Apa sakit yang meninmpa saudaramu?\" Dia menjawab, \"Dia terserang ayan.\" Beliau bersabda: \"Pergi dan bawalah dia kesini.\" Maka dia pergi dan kembali (kepada beliau) bersama saudaranya dan mendudukkannya di depan beliau, maka aku mendengar beliau memberikan perlindungan kepadanya dengan Al Fatihah, empat ayat dari permulaan surat Al Baqarah, dua ayat dari tengahnya dan (ayat) WA ILAAHUKUM ILAAHUWWAAHID (dan tuhan kalian adalah tuhan yang satu), ayat kursi, tiga ayat dari penghujung surat Al Baqarah, dan satu ayat dari surat Ali 'Imran. Aku yakin beliau mengucapkan: \"SYAHIDALLAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah bersaksi bahwa tidak ada ilah yang berhak disembah kecuali Dia) '. Beliau juga membaca satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAHULLADZI KHALAQ (sesungguhnya Rabb kalian adalah yang menciptakan) ', satu ayat dari surat Al MuKminun: WA MAN YADA'U MA'ALLAHI ILAAHNA AAKHAR LAA BURHAANA LAHU BIHI '(Dan barang siapa yang menyeru bersama dengan Allah yaitu ilah yang lain, maka tidak ada petunjuk baginya), satu ayat dari surat Al Jin: WA ANNAHU TA'ALA JADDU RABBINAA MATTAKHADZA SHAAHIBATAN WA LAA WALADA (Dan bahwasannya Maha Tinggi kebesaran Rabb kami, Dia tidak beristeri dan tidak (pula) beranak) '. Sepuluh ayat dari surat Ash Shaffaat, tiga ayat dari akhir surat Al Hasyr, dan QULHUWALLAHU AHAD, dan dua mu'awidzatain. Kemudian orang Arab Badui itu bangun dan sembuh seakan-akan tidak menderita sakit.\""},{"p":"Ibnu Majah","n":3809,"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ سُورَةِ آلِ عِمْرَانَ","trj":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidillah bin Abu Ziyad] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: Nama Allah yang Agung terdapat di dalam dua ayat ini; Dan Rabbmu adalah Rabb yang Maha Esa, tidak ada ilah (yang berhak di sembah) selain Dia, yang Maha pemurah lagi Maha penyayang.\" Qs Al Baqarah; 163, dan pembukaan surat Ali Imran.\""},{"p":"Ibnu Majah","n":3980,"ar":"حَدَّثَنَا حَرْمَلَةُ بْنُ يَحْيَى وَيُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ أَحَقُّ بِالشَّكِّ مِنْ إِبْرَاهِيمَ إِذْ قَالَ رَبِّ أَرِنِي كَيْفَ تُحْيِي الْمَوْتَى قَالَ أَوَلَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي وَيَرْحَمُ اللَّهُ لُوطًا لَقَدْ كَانَ يَأْوِي إِلَى رُكْنٍ شَدِيدٍ وَلَوْ لَبِثْتُ فِي السِّجْنِ طُولَ مَا لَبِثَ يُوسُفُ لَأَجَبْتُ الدَّاعِيَ","trj":"Telah menceritakan kepada kami [Harmalah bin Yahya] dan [Yunus bin Abdul A'la] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman bin 'Auf] dan [Sa'id bin Al Musayyab] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami lebih berhak ragu daripada Ibrahim, ketika dia berkata, '(Dan (Ingatlah) ketika Ibrahim berkata: \"Ya Tuhanku, perlihatkanlah kepadaku bagaimana Engkau menghidupkan orang-orang mati.\" Allah berfirman: \"Belum yakinkah kamu?\" Ibrahim menjawab: \"Aku telah meyakinkannya, akan tetapi agar hatiku tetap mantap (dengan imanku) ' (Qs. Al Baqarah: 260). Dan Allah telah merahmati Nabi Luth karena beliau telah berlindung kepada keluarga yang kuat. Dan sekiranya aku dipenjara selama Nabi Yusuf dipenjara, pastilah aku tetap menunaikan panggilan.\""},{"p":"Malik","n":167,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّ أَبَا بَكْرٍ الصِّدِّيقَصَلَّى الصُّبْحَ فَقَرَأَ فِيهَا سُورَةَ الْبَقَرَةِ فِي الرَّكْعَتَيْنِ كِلْتَيْهِمَا","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Hisyam bin Urwah] dari [Bapaknya], bahwa [Abu Bakar As Shidiq] shalat subuh. Dia membaca surat Al Baqarah dalam dua rakaat tersebut."},{"p":"Malik","n":233,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ دَاوُدَ بْنِ الْحُصَيْنِ أَنَّهُ سَمِعَ الْأَعْرَجَ يَقُولُمَا أَدْرَكْتُ النَّاسَ إِلَّا وَهُمْ يَلْعَنُونَ الْكَفَرَةَ فِي رَمَضَانَ قَالَ وَكَانَ الْقَارِئُ يَقْرَأُ سُورَةَ الْبَقَرَةِ فِي ثَمَانِ رَكَعَاتٍ فَإِذَا قَامَ بِهَا فِي اثْنَتَيْ عَشْرَةَ رَكْعَةً رَأَى النَّاسُ أَنَّهُ قَدْ خَفَّفَ","trj":"Telah menceritakan kepadaku dari Malik dari [Daud bin Al Hushain] Bahwasanya ia mendengar [Al A'raj] berkata; \"Saya tidak mendapatkan orang-orang melainkan mereka melaknat orang-orang kafir pada bulan Ramadlan.\" Al A'raj berkata; \"Imamnya membaca surat Al Baqarah dalam delapan rakaat. Jika imam membacanya untuk dua belas rakaat, maka orang-orang akan mengatakan bahwa imam telah memeringan bacaan.\""},{"p":"Malik","n":287,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي يُونُسَ مَوْلَى عَائِشَةَ أُمِّ الْمُؤْمِنِينَ أَنَّهُ قَالَ أَمَرَتْنِي عَائِشَةُأَنْ أَكْتُبَ لَهَا مُصْحَفًا ثُمَّ قَالَتْ إِذَا بَلَغْتَ هَذِهِ الْآيَةَ فَآذِنِّي{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَقُومُوا لِلَّهِ قَانِتِينَ }فَلَمَّا بَلَغْتُهَا آذَنْتُهَا فَأَمْلَتْ عَلَيَّ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَصَلَاةِ الْعَصْرِ وَقُومُوا لِلَّهِ قَانِتِينَ قَالَتْ عَائِشَةُ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Zaid bin Aslam] dari [Al-Qa'qa' bin Hakim] dari [Abu Yunus] mantan budak Aisyah Ummul Mukminin, dia berkata; \" [Aisyah] menyuruhku menulis mushaf untuknya, kemudian ia berkata, \"Apabila kamu telah sampai pada ayat ini, maka kabarkanlah saya: '(Peliharalah semua shalat(mu), dan (peliharalah) shalat wusthaa. Berdirilah untuk Allah (dalam shalatmu) dengan khusyu') ' (Qs. Al Baqarah: 238) Tatkala saya sampai pada ayat itu, saya pun menyampaikan hal itu kepdanya. Lalu ia mendiktekan kepadaku; '(Peliharalah semua shalat(mu), dan (peliharalah) shalat wusthaa dan shalat asar. Kerjakanlah shalat dengan khusyu' karena Allah) ' Aisyah lantas berkata, \"Saya mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},{"p":"Malik","n":396,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّهُ قَالَخَسَفَتْ الشَّمْسُ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَامَ قِيَامًا طَوِيلًا نَحْوًا مِنْ سُورَةِ الْبَقَرَةِ قَالَ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَاذْكُرُوا اللَّهَ قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ هَذَا ثُمَّ رَأَيْنَاكَ تَكَعْكَعْتَ فَقَالَ إِنِّي رَأَيْتُ الْجَنَّةَ فَتَنَاوَلْتُ مِنْهَا عُنْقُودًا وَلَوْ أَخَذْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا وَرَأَيْتُ النَّارَ فَلَمْ أَرَ كَالْيَوْمِ مَنْظَرًا قَطُّ وَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ قَالُوا لِمَ يَا رَسُولَ اللَّهِ قَالَ لِكُفْرِهِنَّ قِيلَ أَيَكْفُرْنَ بِاللَّهِ قَالَ وَيَكْفُرْنَ الْعَشِيرَ وَيَكْفُرْنَ الْإِحْسَانَ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ كُلَّهُ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّ","trj":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Abdullah bin Abbas] bahwa dia berkata; \"Telah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam. Beliau lalu shalat dan orang-orang ikut bersamanya. Beliau berdiri dalam waktu yang panjang seperti panjangnya bacaan surat Al Baqarah.\" Ibnu Abbas berkata; \"Kemudian beliau rukuk dengan rukuk yang panjang, lalu beliau bangkit dari rukuk. Beliau berdir bangun dengan berdiri yang panjang, namun tidak sepanjang yang pertama. Kemudian beliau rukuk dengan rukuk yang panjang, namun tidak sepanjang rukuk yang sebelumnya. Kemudian beliau bersujud, lalu berdiri lama namun tidak selama berdirinya yang pertama. Kemudian beliau rukuk dengan panjang namun tidak selama rukuk yang pertama. Beliau bangkit dari rukuk dan berdiri dengan panjang, namun tidak sepanjang yang pertama. Kemudian rukuk dengan rukuk yang panjang, namun tidak sepanjang rukuk yang sebelumnya. Setelah itu sujud dan berlalu pergi (selesai) . Sementara matahari sudah mulai nampak, beliau kemudian bersabda: \"Matahari dan bulan adalah dua tanda dari tanda-tanda Kebesaran Allah. Terjadinya gerhana pada keduanya bukan karena kematian atau hidupnya seseorang. Jika kalian melihat itu, maka berdzikirlah kepada Allah\" Mereka bertanya; \"Wahai Rasulullah! kami melihat anda menjulurkan tangan kepada sesuatu di tempat anda berdiri. Lalu kami melihat anda mundur ke belakang.\" Beliau menjawab: \"Saya telah melihat surga. Lalu saya meraih buah dari surga, sekiranya aku mengambilnya, niscaya kalian akan memakannya selama dunia masih ada. Saya juga melihat neraka, saya tidak pernah melihat pemandangan seperti itu. Dan saya lihat paling banyak penghuninya adalah para wanita.\" Mereka bertanya; \"Kenapa wahai Rasulullah! \" beliau menjawab: \"Karena keingkaran mereka.\" Mereka bertanya: \"Apakah karena mereka ingkar terhadap Allah?\" beliau menjawab; \"Mereka ingkar terhadap suami dan ingkar terhadap kebaikan. Jika kamu berbuat kepadanya dalam waktu yang lama, lalu mereka melihat sesuatu darimu, dia berkata; 'Saya tidak pernah melihat kebaikanmu sedikitpun'.\""},{"p":"Malik","n":425,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَعِيدٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَخْرُجُ فِيكُمْ قَوْمٌ تَحْقِرُونَ صَلَاتَكُمْ مَعَ صَلَاتِهِمْ وَصِيَامَكُمْ مَعَ صِيَامِهِمْ وَأَعْمَالَكُمْ مَعَ أَعْمَالِهِمْ يَقْرَءُونَ الْقُرْآنَ وَلَا يُجَاوِزُ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الدِّينِ مُرُوقَ السَّهْمِ مِنْ الرَّمِيَّةِ تَنْظُرُ فِي النَّصْلِ فَلَا تَرَى شَيْئًا وَتَنْظُرُ فِي الْقِدْحِ فَلَا تَرَى شَيْئًا وَتَنْظُرُ فِي الرِّيشِ فَلَا تَرَى شَيْئًا وَتَتَمَارَى فِي الْفُوقِو حَدَّثَنِي عَنْ مَالِك أَنَّهُ بَلَغَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ مَكَثَ عَلَى سُورَةِ الْبَقَرَةِ ثَمَانِيَ سِنِينَ يَتَعَلَّمُهَا","trj":"Telah menceritakan kepadaku dari Malik dari [Yahya bin Said] dari [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Abu Salamah bin Abdurrahman] dari [Abu Sa'id] dia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan keluar dari kalian suatu kaum, yang shalat kalian tidak ada apa-apanya dibanding shalat mereka. Juga puasa kalian dibanding puasa mereka. Amalan kalian dibanding amalan mereka. Mereka membaca Qur'an, namun bacaannya tidak melampaui kerongkongan mereka. Mereka keluar dari agama ini sebagaimana anak panah yang melesat dari busurnya. Kamu melihat ke ujung anak panahnya namun kamu tidak melihatnya. Kamu melihat ke busurnya namun kamu tidak melihatnya. Kamu lihat ke pangkal anak panah dan kamu tidak dapat melihatnya. Kamu saling mendustakan dalam pangkal anak panah.\" Telah menceritakan kepadaku dari Malik telah sampai kepadanya, bahwa Abdullah bin 'Umar tetap mempelajari surat Al Baqarah selama delapan tahun.\""},{"p":"Malik","n":728,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ قُلْتُ لِعَائِشَةَ أُمِّ الْمُؤْمِنِينَ وَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّأَرَأَيْتِ قَوْلَ اللَّهِ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَمَا عَلَى الرَّجُلِ شَيْءٌ أَنْ لَا يَطَّوَّفَ بِهِمَا فَقَالَتْ عَائِشَةُ كَلَّا لَوْ كَانَ كَمَا تَقُولُ لَكَانَتْ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي الْأَنْصَارِ كَانُوا يُهِلُّونَ لِمَنَاةَ وَكَانَتْ مَنَاةُ حَذْوَ قُدَيْدٍ وَكَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا جَاءَ الْإِسْلَامُ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Hisyam bin Urwah] dari [Bapaknya] ia berkata; \"Aku pernah bertanya kepada [Aisyah Ummul Mukminin], saat saya masih muda: 'Apakah anda tahu tentang firman Allah Tabaraka Wa Ta'ala: 'Sesungguhnya Shafaa dan Marwa adalah sebahagian dari syi'ar Allah. Barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.' -Qs. Al Baqarah: 156- Maka tidak apa-apa bagi seseorang untuk meninggalkan sa'i.\" Aisyah menjawab; \"Bukan begitu, kalau seperti yang kamu katakan, tentu tidak ada dosa bagi orang yang tidak melakukan sa'i. Ayat ini turun pada orang-orang Anshar, dahulu mereka melakukan talbiyah untuk Manat, yang letaknya di depan Qudaid. Mereka menjauhi untuk tidak melaksanakan sa'i antara Shafaa dan Marwa. Maka tatkala datang Islam, mereka bertanya pada Rasulullah shallallahu 'alaihi wasallam tentang hal itu. Allah Tabaraka Wa Ta'ala menurunkan ayat: 'Sesungguhnya Shafa dan Marwa adalah sebagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau umrah, Maka tidak ada dosa baginya mengerjakan sa'i antara keduanya'. -Qs. Al Baqarah: 156-."},{"p":"Malik","n":761,"ar":"و حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ كَانَ يَقُولُ{ مَا اسْتَيْسَرَ مِنْ الْهَدْيِ }شَاةٌ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Ali bin Abu Thalib] berkata; \"'Binatang sembelihan yang paling mudah (didapat) ..-Qs. Al Baqarah: 196- adalah kambing.\""},{"p":"Malik","n":961,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِأَنَّهُ كَانَ يَقُولُ فِي قَوْلِ اللَّهِ تَبَارَكَ وَتَعَالَى{ وَلَا جُنَاحَ عَلَيْكُمْ فِيمَا عَرَّضْتُمْ بِهِ مِنْ خِطْبَةِ النِّسَاءِ أَوْ أَكْنَنْتُمْ فِي أَنْفُسِكُمْ عَلِمَ اللَّهُ أَنَّكُمْ سَتَذْكُرُونَهُنَّ وَلَكِنْ لَا تُوَاعِدُوهُنَّ سِرًّا إِلَّا أَنْ تَقُولُوا قَوْلًا مَعْرُوفًا }أَنْ يَقُولَ الرَّجُلُ لِلْمَرْأَةِ وَهِيَ فِي عِدَّتِهَا مِنْ وَفَاةِ زَوْجِهَا إِنَّكِ عَلَيَّ لَكَرِيمَةٌ وَإِنِّي فِيكِ لَرَاغِبٌ وَإِنَّ اللَّهَ لَسَائِقٌ إِلَيْكِ خَيْرًا وَرِزْقًا وَنَحْوَ هَذَا مِنْ الْقَوْلِ","trj":"Telah menceritakan kepadaku dari Malik dari [Abdurrahman bin Qasim] dari [Bapaknya] bahwa dia berkata mengenai firman Allah Ta'ala: '(Dan tidak ada dosa bagi kamu meminang wanita-wanita itu dengan sindiran atau kamu menyembunyikan (keinginan mengawini mereka) dalam hatimu. Allah mengetahui bahwa kamu akan menyebut-nyebut mereka, dalam pada itu janganlah kamu mengadakan janji kawin dengan mereka secara rahasia, kecuali sekedar mengucapkan (kepada mereka) perkataan yang ma'ruf) ' (Qs. Al Baqarah: 235) yaitu seorang laki-laki yang berkata kepada seorang wanita yang masih berada pada masa iddah dari kematian suaminya, 'Kamu begitu mulia bagiku, saya ada rasa cinta terhadapmu, semoga Allah menuntunmu kepada kebaikan dan jalan rezki', atau ucapan lain yang semisalnya."},{"p":"Malik","n":1049,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَأَنَّهَا انْتَقَلَتْ حَفْصَةَ بِنْتَ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ حِينَ دَخَلَتْ فِي الدَّمِ مِنْ الْحَيْضَةِ الثَّالِثَةِ قَالَ ابْنُ شِهَابٍ فَذُكِرَ ذَلِكَ لِعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ فَقَالَتْ صَدَقَ عُرْوَةُ وَقَدْ جَادَلَهَا فِي ذَلِكَ نَاسٌ فَقَالُوا إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ فِي كِتَابِهِ{ ثَلَاثَةَ قُرُوءٍ }فَقَالَتْ عَائِشَةُ صَدَقْتُمْ تَدْرُونَ مَا الْأَقْرَاءُ إِنَّمَا الْأَقْرَاءُ الْأَطْهَارُو حَدَّثَنِي عَنْ مَالِك عَنْ ابْنِ شِهَابٍ أَنَّهُ قَالَ سَمِعْتُ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ يَقُولُ مَا أَدْرَكْتُ أَحَدًا مِنْ فُقَهَائِنَا إِلَّا وَهُوَ يَقُولُ هَذَا يُرِيدُ قَوْلَ عَائِشَةَ","trj":"Telah menceritakan kepadaku dari Malik dari [Ibnu Syihab] dari [Urwah bin Zubair] dari ['Aisyah] Ummul Mukminin, bahwa dia menyuruh Hafshah binti Abdurrahman bin Abu Bakar Ash Shiddiq pindah tempat tinggal ketika memasuki masa haid yang ketiga. Ibnu Syihab berkata; \"Hal itu lalu diadukan kepada 'Amrah binti Abdurrahman. [Amrah] berkata, \"Urwah benar.\" Waktu itu banyak orang yang mendebatnya. [Mereka mengatakan], \"Sungguh Allah Ta'ala telah berfirman dalam kitab-Nya: \"Tiga kali quru' (Qs. Al Baqarah: 228) 'Aisyah lalu menjawab; \"Kalian benar, dan tahukah kalian apa itu quru`? Quru` adalah suci.\" Telah menceritakan kepadaku dari Malik dari Ibnu Syihab berkata; Aku mendengar [Abu Bakar bin Abdurrahman] berkata; \"Aku tidak mendapati seorang ahli fikih pun dari kalangan kita kecuali dia sependapat dengan hal itu.\" maksudnya pendapat 'Aisyah."},{"p":"Malik","n":1070,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَكَانَ الرَّجُلُ إِذَا طَلَّقَ امْرَأَتَهُ ثُمَّ ارْتَجَعَهَا قَبْلَ أَنْ تَنْقَضِيَ عِدَّتُهَا كَانَ ذَلِكَ لَهُ وَإِنْ طَلَّقَهَا أَلْفَ مَرَّةٍ فَعَمَدَ رَجُلٌ إِلَى امْرَأَتِهِ فَطَلَّقَهَا حَتَّى إِذَا شَارَفَتْ انْقِضَاءَ عِدَّتِهَا رَاجَعَهَا ثُمَّ طَلَّقَهَا ثُمَّ قَالَ لَا وَاللَّهِ لَا آوِيكِ إِلَيَّ وَلَا تَحِلِّينَ أَبَدًا فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ }فَاسْتَقْبَلَ النَّاسُ الطَّلَاقَ جَدِيدًا مِنْ يَوْمِئِذٍ مَنْ كَانَ طَلَّقَ مِنْهُمْ أَوْ لَمْ يُطَلِّقْ","trj":"Telah menceritakan kepada kami dari Malik dari [Hisyam bin Urwah] dari [Bapaknya] berkata; \"Jika seorang laki-laki menceraikan isterinya, dia berhak ruju' lagi kepadanya selagi masa iddahnya belum habis, meski dia menceraikannya sampai seribu kali. Seorang laki-laki sengaja menceraikan isterinya, hingga ketika masa iddahnya akan selesai ia kembali meruju'nya, lalu kembali menceraikannya. Setelah itu ia berkata, \"Tidak, demi Allah, aku tidak akan menggaulimu dan kamu selamanya tidak akan menjadi halal (tidak pernah habis masa iddahnya karena selalu diruju') .\" Kemudian Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Talak (yang dapat dirujuki) dua kali. Setelah itu, boleh ruju' lagi dengan cara yang ma'ruf atau menceraikan dengan cara yang baik) ' (Qs. Al Baqarah: 231) Semenjak turunnya ayat ini, orang-orang menghitung talak dari awal lagi, baik yang sudah pernah mentalak ataupun yang belum pernah.\""},{"p":"Malik","n":1071,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيلِيِّأَنَّ الرَّجُلَ كَانَ يُطَلِّقُ امْرَأَتَهُ ثُمَّ يُرَاجِعُهَا وَلَا حَاجَةَ لَهُ بِهَا وَلَا يُرِيدُ إِمْسَاكَهَا كَيْمَا يُطَوِّلُ بِذَلِكَ عَلَيْهَا الْعِدَّةَ لِيُضَارَّهَا فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ وَلَا تُمْسِكُوهُنَّ ضِرَارًا لِتَعْتَدُوا وَمَنْ يَفْعَلْ ذَلِكَ فَقَدْ ظَلَمَ نَفْسَهُ }يَعِظُهُمْ اللَّهُ بِذَلِكَ","trj":"Telah menceritakan kepadaku dari Malik dari [Tsaur bin Zaid Ad Dili] berkata, \"Seorang lelaki menceraikan isterinya kemudian meruju'nya lagi padahal ia sudah tidak membutuhkannya dan tidak ingin menjadikannya isteri lagi. Ia hanya ingin memperpanjang masa iddahnya sehingga isteri merasakan penderitaan. Kemudian Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Janganlah kamu rujuki mereka untuk memberi kemudharatan, Karena dengan demikian kamu menganiaya mereka) ' (Qs. Al Baqarah: 231) Allah menasehatkan demikian kepada mereka."},{"p":"Malik","n":1081,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّهُ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ مُحَمَّدٍ يَقُولُإِنَّ يَزِيدَ بْنَ عَبْدِ الْمَلِكِ فَرَّقَ بَيْنَ رِجَالٍ وَبَيْنَ نِسَائِهِمْ وَكُنَّ أُمَّهَاتِ أَوْلَادِ رِجَالٍ هَلَكُوا فَتَزَوَّجُوهُنَّ بَعْدَ حَيْضَةٍ أَوْ حَيْضَتَيْنِ فَفَرَّقَ بَيْنَهُمْ حَتَّى يَعْتَدِدْنَ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا فَقَالَ الْقَاسِمُ بْنُ مُحَمَّدٍ سُبْحَانَ اللَّهِ يَقُولُ اللَّهُ فِي كِتَابِهِ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا }مَا هُنَّ مِنْ الْأَزْوَاجِ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Yahya bin Sa'id] ia berkata; Aku mendengar [Al Qasim bin Muhammad] berkata; \"Suatu ketika Yazid bin Abdul Malik memisahkan para suami dari isteri-isteri mereka. Para wanita itu adalah para ibu dari anak-anak yang ditinggal mati bapaknya, lalu mereka menikahinya wanita-wanita itu ketika baru berlalu satu atau dua kali haid. Kemudian Yazid memisahkan mereka sampai para wanita itu menjalani masa 'iddah selama empat bulan sepuluh hari.\" Al Qasim bin Muhammad berkata; \"SUBHANALLAH, Allah berfirman dalam kitab-Nya: \"Orang-orang yang meninggal dunia di antaramu dengan meninggalkan isteri-isteri (hendaklah para isteri itu) ...\" (Qs. Al Baqarah: 234) padahal mereka itu tidak mempunyai suami sebelumnya?\""},{"p":"Muslim","n":178,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ مِنْهَالٍ الضَّرِيرُ وَأُمَيَّةُ بْنُ بِسْطَامَ الْعَيْشِيُّ وَاللَّفْظُ لِأُمَيَّةَ قَالَا حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا رَوْحٌ وَهُوَ ابْنُ الْقَاسِمِ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا نَزَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لِلَّهِ مَا فِي السَّمَوَاتِ وَمَا فِي الْأَرْضِ وَإِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُمْ بِهِ اللَّهُ فَيَغْفِرُ لِمَنْ يَشَاءُ وَيُعَذِّبُ مَنْ يَشَاءُ وَاللَّهُ عَلَى كُلِّ شَيْءٍ قَدِيرٌ }قَالَ فَاشْتَدَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ بَرَكُوا عَلَى الرُّكَبِ فَقَالُوا أَيْ رَسُولَ اللَّهِ كُلِّفْنَا مِنْ الْأَعْمَالِ مَا نُطِيقُ الصَّلَاةَ وَالصِّيَامَ وَالْجِهَادَ وَالصَّدَقَةَ وَقَدْ أُنْزِلَتْ عَلَيْكَ هَذِهِ الْآيَةُ وَلَا نُطِيقُهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُرِيدُونَ أَنْ تَقُولُوا كَمَا قَالَ أَهْلُ الْكِتَابَيْنِ مِنْ قَبْلِكُمْ سَمِعْنَا وَعَصَيْنَا بَلْ قُولُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ قَالُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ فَلَمَّا اقْتَرَأَهَا الْقَوْمُ ذَلَّتْ بِهَا أَلْسِنَتُهُمْ فَأَنْزَلَ اللَّهُ فِي إِثْرِهَا{ آمَنَ الرَّسُولُ بِمَا أُنْزِلَ إِلَيْهِ مِنْ رَبِّهِ وَالْمُؤْمِنُونَ كُلٌّ آمَنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِنْ رُسُلِهِ وَقَالُوا سَمِعْنَا وَأَطَعْنَا غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ الْمَصِيرُ }فَلَمَّا فَعَلُوا ذَلِكَ نَسَخَهَا اللَّهُ تَعَالَى فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا اكْتَسَبَتْ رَبَّنَا لَا تُؤَاخِذْنَا إِنْ نَسِينَا أَوْ أَخْطَأْنَا }قَالَ نَعَمْ{ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَا إِصْرًا كَمَا حَمَلْتَهُ عَلَى الَّذِينَ مِنْ قَبْلِنَا }قَالَ نَعَمْ{ رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِ }قَالَ نَعَمْ{ وَاعْفُ عَنَّا وَاغْفِرْ لَنَا وَارْحَمْنَا أَنْتَ مَوْلَانَا فَانْصُرْنَا عَلَى الْقَوْمِ الْكَافِرِينَ }قَالَ نَعَمْ","trj":"Telah menceritakan kepadaku [Muhammad bin Minhal adl-Dlarir] dan [Umayyah bin Bistham al-Aisyi] dan lafazh tersebut milik Umayyah, keduanya berkata, telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Rauh] -yaitu Ibnu al-Qasim- dari [al-Ala'] dari [bapaknya] dari [Abu Hurairah] dia berkata, \"Ketika turun ayat pada Rasulullah shallallahu 'alaihi wasallam: '(Kepunyaan Allah-lah segala apa yang ada di langit dan di bumi. Dan jika kamu melahirkan apa yang ada di dalam hatimu atau kamu menyembunyikannya, niscaya Allah akan membuat perhitungan dengan kamu tentang perbuatanmu itu. Maka Allah mengampuni siapa yang dikehendaki-Nya dan menyiksa siapa yang dikehendaki-Nya; dan Allah Maha Kuasa atas segala sesuatu) ' (Qs. al-Baqarah: 284) ' Abu Hurairah berkata, 'Maka hal tersebut terasa berat atas para sahabat Rasulullah shallallahu 'alaihi wasallam, lalu mereka mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengucapkan salam di atas kendaraan seraya berkata, 'Wahai Rasulullah, kami diberi beban amalan yang mana kami tidak mampu melakukan shalat, puasa, jihad, dan sedekah. Sungguh telah diturunkan ayat ini kepadamu, dan kami tidak mampu melakukannya! Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kamu ingin mengucapkan sebagaimana ahli kitab sebelum kalian mengucapkan, 'Kami mendengar dan kami mendurhakai', akan tetapi katakanlah, 'Kami mendengar dan kami menaati, Ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali'. Mereka menjawab, 'Kami mendengar dan kami menaatinya, ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali.' Ketika kaum tersebut membacanya, maka lisan-lisan mereka tunduk dengannya, lalu Allah menurunkan sesudahnya: '(Rasul telah beriman kepada al-Qur'an yang diturunkan kepadanya dari Rabbnya, demikian pula orang-orang yang beriman. Semuanya beriman kepada Allah, malaikat-malaikat-Nya, kitab-kitab-Nya dan rasul-rasul-Nya. (Mereka mengatakan), 'Kami tidak membeda-bedakan antara seorang pun (dengan yang lain) dari rasul-rasul-Nya', dan mereka mengatakan, 'Kami dengar dan kami taat'. (Mereka berdoa), 'Ampunilah kami ya Rabb kami dan kepada Engkaulah tempat kembali'. (Qs. al-Baqarah: 285). Ketika mereka melakukan hal tersebut, maka Allah menghapusnya, lalu menurunkan: '(Allah tidak membebani seseorang melainkan sesuai dengan kesanggupannya. Ia mendapat pahala (dari kebajikan) yang diusahakannya dan mendapat siksa (dari kejahatan) yang dikerjakannya. (Mereka berdoa): \"Ya Rabb kami, janganlah Engkau hukum kami jika kami lupa atau kami bersalah) ' Allah menjawab: \"Ya.\" '(Ya Rabb kami, janganlah Engkau bebankan kepada kami beban yang berat sebagaimana Engkau bebankan kepada orang-orang yang sebelum kami) ' Allah menjawab: \"Ya.\" '(Wahai Rabb kami, janganlah Engkau pikulkan kepada kami apa yang tak sanggup kami memikulnya) ' Allah menjawab: \"Ya.\" '(Beri maaflah kami; ampunilah kami; dan rahmatilah kami. Engkaulah Penolong kami, maka tolonglah kami terhadap kaum yang kafir'. (Qs. al-Baqarah: 286). Allah menjawab: \"Ya.\""},{"p":"Muslim","n":179,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِأَبِي بَكْرٍ قَالَ إِسْحَقُ أَخْبَرَنَا وَقَالَ الْآخَرَانِ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ آدَمَ بْنِ سُلَيْمَانَ مَوْلَى خَالِدٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَإِنْ تُبْدُوا مَا فِي أَنْفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُمْ بِهِ اللَّهُ }قَالَ دَخَلَ قُلُوبَهُمْ مِنْهَا شَيْءٌ لَمْ يَدْخُلْ قُلُوبَهُمْ مِنْ شَيْءٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُولُوا سَمِعْنَا وَأَطَعْنَا وَسَلَّمْنَا قَالَ فَأَلْقَى اللَّهُ الْإِيمَانَ فِي قُلُوبِهِمْ فَأَنْزَلَ اللَّهُ تَعَالَى{ لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا اكْتَسَبَتْ رَبَّنَا لَا تُؤَاخِذْنَا إِنْ نَسِينَا أَوْ أَخْطَأْنَا }قَالَ قَدْ فَعَلْتُ{ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَا إِصْرًا كَمَا حَمَلْتَهُ عَلَى الَّذِينَ مِنْ قَبْلِنَا }قَالَ قَدْ فَعَلْتُ{ وَاغْفِرْ لَنَا وَارْحَمْنَا أَنْتَ مَوْلَانَا }قَالَ قَدْ فَعَلْتُ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] serta [Ishaq bin Ibrahim] dan lafazh tersebut milik Abu Bakar, berkata [Ishaq] telah mengabarkan kepada kami, sedangkan dua orang lainnya berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Adam bin Sulaiman] mantan budak Khalid, dia berkata, saya mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Abbas] dia berkata, \"Ketika turun ayat: '(Dan jika kamu melahirkan sesuatu yang ada di dalam hatimu atau kamu menyembunyikannya, niscaya Allah akan membuat perhitungan dengan kamu tentang perbuatanmu itu) ' (Qs. Albaqarah: 284). Ibnu Abbas berkata, \"Maka masuklah suatu kesedihan darinya ke dalam hati mereka yang mana tidak pernah masuk ke dalam hati mereka sedikit pun.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Katakanlah, 'Saya mendengar dan saya menaati serta saya menyerahkan diri'.\" Ibnu Abbas berkata, \"Lalu Allah meletakkan iman pada hati mereka, yang kemudian menurunkan ayat: '(Allah tidak membebani seseorang melainkan sesuai dengan kesanggupannya. Ia mendapat pahala (dari kebajikan) yang diusahakannya dan mendapat siksa (dari kejahatan) yang dikerjakannya. (Mereka berdoa), 'Ya Rabb kami, janganlah Engkau hukum kami jika kami lupa atau kami bersalah) ' (Qs. Al Baqarah: 286), Allah berfirman: \"Sungguh aku telah melakukannya.\" '(Wahai Rabb kami, dan janganlah Engkau bebankan kepada kami beban yang berat sebagaimana Engkau bebankan kepada orang-orang yang sebelum kami) ' (Qs. Al baqarah: 286), Allah berfirman: \"Aku telah melakukanya.\" '(Wahai Rabb kami, Beri maaflah kami; ampunilah kami; dan rahmatilah kami. Engkaulah Penolong kami) ' Allah berfiraman: \"Aku telah lakukan.\""},{"p":"Muslim","n":215,"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَحْنُ أَحَقُّ بِالشَّكِّ مِنْ إِبْرَاهِيمَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ قَالَ{ رَبِّ أَرِنِي كَيْفَ تُحْيِي الْمَوْتَى قَالَ أَوَ لَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي }قَالَ وَيَرْحَمُ اللَّهُ لُوطًا لَقَدْ كَانَ يَأْوِي إِلَى رُكْنٍ شَدِيدٍ وَلَوْ لَبِثْتُ فِي السِّجْنِ طُولَ لَبْثِ يُوسُفَ لَأَجَبْتُ الدَّاعِيَو حَدَّثَنِي بِهِ إِنْ شَاءَ اللَّهُ عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ الضُّبَعِيُّ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ أَنَّ سَعِيدَ بْنَ الْمُسَيَّبِ وَأَبَا عُبَيْدٍ أَخْبَرَاهُ عَنْ أَبِي هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ يُونُسَ عَنْ الزُّهْرِيِّ وَفِي حَدِيثِ مَالِكٍ{ وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي }قَالَ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ حَتَّى جَازَهَا حَدَّثَنَاه عَبْدُ بْنُ حُمَيْدٍ قَالَ حَدَّثَنِي يَعْقُوبُ يَعْنِي ابْنَ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبُو أُوَيْسٍ عَنْ الزُّهْرِيِّ كَرِوَايَةِ مَالِكٍ بِإِسْنَادِهِ وَقَالَ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ حَتَّى أَنْجَزَهَا","trj":"Dan telah menceritakan kepada kami [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahab] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dan [Sa'id bin al-Musayyab] dari [Abu Hurairah] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami lebih berhak merasa ragu daripada Nabi Ibrahim Alaihissalam ketika dia berkata: '(Wahai Tuhanku, tunjukkanlah kepadaku bagaimana Kamu menghidupkan orang mati? ' Allah berfirman, 'Apakah kamu tidak percaya kepada kekuasaanKu? ' Nabi Ibrahim menjawab, 'Aku tetap percaya dan yakin, tetapi agar hatiku tenteram) ' (Qs. Al Baqarah: 260). Rasulullah shallallahu 'alaihi wasallam terus bersabda: \"Semoga Allah memberikan rahmat kepada Nabi Lut'. Dia benar-benar telah berlindung kepada suatu kuasa yang kuat (Allah subhanahu wata'ala). Andaikata aku tinggal di penjara selama masa yang dilalui Nabi Yusuf berada di dalamnya niscaya aku akan memenuhi keinginan orang yang meminta'.\" Dan telah menceritakan kepada kami insya Allah [Abdullah bin Muhammad bin Asma' adl-Dluba'i] telah menceritakan kepada kami [Juwairiyah] dari [Malik] dari [az-Zuhri] bahwa [Sa'id bin al-Musayyab] dan [Abu Ubaid] telah mengabarkan kepadanya, dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam dengan semisal hadits Yunus dari az-Zuhri. Dan dalam hadits Malik disebutkan, '(Akan tetapi agar hatiku menjadi tenang) ' (Qs. Al Baqarah: 260). Perawi berkata, \"Kemudian beliau membaca ayat ini hingga selesai.\" Dan telah menceritakan kepada kami [Abd bin Humaid] dia berkata, telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Ibrahim bin Sa'd- telah menceritakan kepada kami [Abu Uwais] dari [az-Zuhri] seperti riwayat Malik dengan sanadnya, dia menyebutkan, 'Kemudian beliau membaca ayat ini hingga menyelesaikan-Nya.\""},{"p":"Muslim","n":249,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَزُهَيْرُ بْنُ حَرْبٍ جَمِيعًا عَنْ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَلْفَاظُهُمْ مُتَقَارِبَةٌ قَالَ ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ طَلْحَةَ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتُهِيَ بِهِ إِلَى سِدْرَةِ الْمُنْتَهَى وَهِيَ فِي السَّمَاءِ السَّادِسَةِ إِلَيْهَا يَنْتَهِي مَا يُعْرَجُ بِهِ مِنْ الْأَرْضِ فَيُقْبَضُ مِنْهَا وَإِلَيْهَا يَنْتَهِي مَا يُهْبَطُ بِهِ مِنْ فَوْقِهَا فَيُقْبَضُ مِنْهَا قَالَ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ فَرَاشٌ مِنْ ذَهَبٍ قَالَ فَأُعْطِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثًا أُعْطِيَ الصَّلَوَاتِ الْخَمْسَ وَأُعْطِيَ خَوَاتِيمَ سُورَةِ الْبَقَرَةِ وَغُفِرَ لِمَنْ لَمْ يُشْرِكْ بِاللَّهِ مِنْ أُمَّتِهِ شَيْئًا الْمُقْحِمَاتُ","trj":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Malik bin Mighwal]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Ibnu Numair] dan [Zuhair bin Harb] semuanya dari [Abdullah bin Numair] dan lafazh mereka saling berdekatan. [Ibnu Numair] berkata, telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Malik bin Mighwal] dari [az-Zubair bin Adi] dari [Thalhah] dari [Murrah] dari [Abdullah] dia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam diisra'kan maka beliau dihentikan di Sidrah al-Muntaha, (yaitu tempat) yang terletak di langit keenam. Sesuatu yang naik dari bumi akan bermuara di sana dan ditahan padanya. Dan sesuatu dari atasnya berhenti padanya, lalu ditahan padanya.\" Allah berfirman: '(Muhammad melihat Jibril) ketika Sidratil Muntaha diliputi oleh sesuatu yang meliputinya) ' (Qs. An Najm: 16). Abdullah berkata lagi, \"Yaitu hamparan dari emas.\" Dia berkata lagi, \"Lalu Rasulullah shallallahu 'alaihi wasallam diberi tiga hal: shalat lima waktu, ayat-ayat penutup surat al-Baqarah, dan diampuni dosa-dosa besar milik orang yang tidak mensyirikkan Allah dengan sesuatu pun dari kalangan umat beliau.\""},{"p":"Muslim","n":327,"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ ابْنُ شِهَابٍ وَلَكِنْ عُرْوَةُ يُحَدِّثُ عَنْ حُمْرَانَ أَنَّهُ قَالَ فَلَمَّا تَوَضَّأَ عُثْمَانُ قَالَوَاللَّهِ لَأُحَدِّثَنَّكُمْ حَدِيثًا وَاللَّهِ لَوْلَا آيَةٌ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُكُمُوهُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَتَوَضَّأُ رَجُلٌ فَيُحْسِنُ وُضُوءَهُ ثُمَّ يُصَلِّي الصَّلَاةَ إِلَّا غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الصَّلَاةِ الَّتِي تَلِيهَاقَالَ عُرْوَةُ الْآيَةُ{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى إِلَى قَوْلِهِ اللَّاعِنُونَ }","trj":"Dan telah menceritakan kepada kami [Zuhair bin harb] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [bapakku] dari [Shalih], [Ibnu Syihab] berkata, \"Akan tetapi [Urwah] menceritakan dari [Humran] bahwa dia berkata, 'Ketika [Utsman] berwudlu, maka dia berkata, 'Demi Allah, sungguh aku akan menceritakan kepada kalian sebuah hadits. Demi Allah, kalau bukan suatu ayat dalam Kitabullah niscaya aku tidak akan menceritakannya kepada kalian. Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki berwudlu, lalu memperbagus wudlunya kemudian melakukan shalat melainkan pasti diampuni dosanya antara dia dan shalat setelahnya'.\" Urwah berkata, \"Ayat tersebut adalah: '(Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa keterangan-keterangan (yang jelas) dan petunjuk, setelah Kami menerangkan-Nya kepada manusia dalam Al-Kitab, mereka itu dila'nati Allah dan dila'nati (pula) oleh semua (makhluk) yang dapat melaknati…) ' (Qs. Al-Baqarah: 159)."},{"p":"Muslim","n":692,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبَّادٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ جَابِرٍ قَالَكَانَ مُعَاذٌ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَأْتِي فَيَؤُمُّ قَوْمَهُ فَصَلَّى لَيْلَةً مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ ثُمَّ أَتَى قَوْمَهُ فَأَمَّهُمْ فَافْتَتَحَ بِسُورَةِ الْبَقَرَةِ فَانْحَرَفَ رَجُلٌ فَسَلَّمَ ثُمَّ صَلَّى وَحْدَهُ وَانْصَرَفَ فَقَالُوا لَهُ أَنَافَقْتَ يَا فُلَانُ قَالَ لَا وَاللَّهِ وَلَآتِيَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَأُخْبِرَنَّهُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا أَصْحَابُ نَوَاضِحَ نَعْمَلُ بِالنَّهَارِ وَإِنَّ مُعَاذًا صَلَّى مَعَكَ الْعِشَاءَ ثُمَّ أَتَى فَافْتَتَحَ بِسُورَةِ الْبَقَرَةِ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مُعَاذٍ فَقَالَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ اقْرَأْ بِكَذَا وَاقْرَأْ بِكَذَا قَالَ سُفْيَانُ فَقُلْتُ لِعَمْرٍو إِنَّ أَبَا الزُّبَيْرِ حَدَّثَنَا عَنْ جَابِرٍ أَنَّهُ قَالَ اقْرَأْ وَالشَّمْسِ وَضُحَاهَا وَالضُّحَى وَاللَّيْلِ إِذَا يَغْشَى وَسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى فَقَالَ عَمْرٌو نَحْوَ هَذَا","trj":"Telah menceritakan kepadaku [Muhammad bin 'Abbad] telah menceritakan kepada kami [Sufyan] dari [Amru] dari [Jabir] dia berkata, \"Muadz shalat bersama Nabi Shallallahu'alaihiwasallam, kemudian dia datang, lalu mengimami kaumnya. Maka dia melakukan shalat Isya' pada malam tersebut bersama Nabi Shallallahu'alaihiwasallam, kemudian mendatangi kaumnya, lalu mengimami mereka. Lalu dia membuka dengan surat al-Baqarah, maka seorang laki-laki berpaling lalu salam, kemudian shalat sendirian, lalu berpaling pergi. Maka mereka berkata kepadanya, 'Apakah kamu berlaku munafik wahai fulan? ' Dia menjawab, 'Tidak, demi Allah, aku akan mendatangi Rasulullah Shallallahu'alaihiwasallam, lalu aku akan mengabarkan kepada beliau. Lalu dia mendatangi Rasulullah Shallallahu'alaihiwasallam seraya berkata, 'Wahai Rasulullah, sesungguhnya para pekerja penyiram (tanaman) bekerja pada siang hari (sehingga kecapekan), dan sesungguhnya Mu'adz shalat Isya' bersamamu, kemudian dia datang kepada kami lalu shalat dengan membukanya dengan surat al-Baqarah.' Maka Rasulullah Shallallahu'alaihiwasallam menghadap Mu'adz seraya bersabda, 'Wahai Mu'adz, apakah kamu pemfitnah (yang membuat orang lari dari agama), bacalah dengan surat ini dan bacalah dengan ini' -maksudnya surat yang ringkas dan pendek--.\" Berkata Sufyan, maka saya berkata kepada Amru sesungguhnya [Abu az-Zubair] telah menceritakan kepada kami, dari [Jabir] bahwa dia berkata, \"Bacalah 'Iqra dan asy-Syams wa Dhuhaha, serta Wa adh-dhuha wa al-Laili Idza Yaghsya dan Sabbihisma Rabbika al-A'la\". Maka Amru berkata semisal ini."},{"p":"Muslim","n":797,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ شَهْرًا حَتَّى نَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ{ وَحَيْثُ مَا كُنْتُمْ فَوَلُّوا وُجُوهَكُمْ شَطْرَهُ }فَنَزَلَتْ بَعْدَمَا صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَ رَجُلٌ مِنْ الْقَوْمِ فَمَرَّ بِنَاسٍ مِنْ الْأَنْصَارِ وَهُمْ يُصَلُّونَ فَحَدَّثَهُمْ فَوَلَّوْا وُجُوهَهُمْ قِبَلَ الْبَيْتِ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] telah menceritakan kepada kami [Abu al-Ahwash] dari [Abu Ishaq] dari [al-Bara' bin 'Azib] dia berkata, \"Aku shalat bersama Nabi Shallallahu'alaihiwasallam menghadap Baitul Maqdis selama enam belas bulan hingga turun ayat tersebut yang ada dalam surat al-Baqarah, \"Dan di mana pun kamu berada maka palingkanlah wajah-wajahmu ke arahnya.\" (QS.Albaqarah 124), ayat tersebut turun setelah Nabi Shallallahu'alaihiwasallam shalat, lalu seorang laki-laki dari suatu kaum bertolak pergi, lalu dia berjalan bersama beberapa manusia dari kalangan Anshar, dan mereka shalat, lalu beliau menceritakannya kepada mereka, maka mereka menghadapkan wajah-wajah mereka ke Baitullah.\""},{"p":"Muslim","n":800,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي نَحْوَ بَيْتِ الْمَقْدِسِ فَنَزَلَتْ{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَاهَا فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }فَمَرَّ رَجُلٌ مِنْ بَنِي سَلِمَةَ وَهُمْ رُكُوعٌ فِي صَلَاةِ الْفَجْرِ وَقَدْ صَلَّوْا رَكْعَةً فَنَادَى أَلَا إِنَّ الْقِبْلَةَ قَدْ حُوِّلَتْ فَمَالُوا كَمَا هُمْ نَحْوَ الْقِبْلَةِ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abi Syaibah] telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] \"Bahwa Rasulullah shallallahu'alaihiwasallam dahulu shalat menghadap Baitul Maqdis, lalu turunlah ayat, 'Sungguh kami telah melihat wajahmu menengadah ke langit, maka sungguh kami palingkan wajahmu ke kiblat yang kamu ridhai, maka palingkanlah wajahmu ke arah masjid al-Haram.' (QS. Albaqarah 144), Lalu seorang laki-laki dari Bani Salimah berjalan, sedangkan mereka dalam keadaan rukuk dalam shalat shubuh, dan mereka telah melakukan shalat satu raka'at, lalu dia memanggil, 'Ketahuilah, sesungguhnya kiblat telah diganti, maka mereka berpaling sebagaimana mereka menghadap kiblat'.\""},{"p":"Muslim","n":967,"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي يُونُسَ مَوْلَى عَائِشَةَ أَنَّهُ قَالَ أَمَرَتْنِي عَائِشَةُ أَنْ أَكْتُبَ لَهَا مُصْحَفًا وَقَالَتْ إِذَا بَلَغْتَ هَذِهِ الْآيَةَ فَآذِنِّي{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى }فَلَمَّا بَلَغْتُهَا آذَنْتُهَافَأَمْلَتْ عَلَيَّ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى }وَصَلَاةِ الْعَصْرِ{ وَقُومُوا لِلَّهِ قَانِتِينَ }قَالَتْ عَائِشَةُ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] katanya; aku menyetorkan hapalanku kepada [Malik] dari [Zaid bin Aslam] dari [Alqa'qa' bin Hakim] dari [Abu Yunus] mantan budak Aisyah, katanya; [Aisyah] pernah memrintahkanku untuk menulis mushaf. Lalu dia berpesan; \"Jika sampai ayat ini \"Jagalah oleh kalian seluruh shalat yang ada dan shalat wustha\" (QS. Albaqarah 238), maka beritahukanlah kepadaku, \" Ketika aku sampai ayat itu, aku lalu memberitahukan kepadanya, seketika itu pula dia mendiktekan kepadaku \"Jagalah oleh kalian seluruh shalat yang ada dan shalat wustha, \" yatiu shalat ashar, \"Dan berdirilah kepada Allah dengan penuh kepatuhan\" (QS. Albaqarah 283), kata Aisyah; aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam."},{"p":"Muslim","n":968,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا الْفُضَيْلُ بْنُ مَرْزُوقٍ عَنْ شَقِيقِ بْنِ عُقْبَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَنَزَلَتْ هَذِهِ الْآيَةُ{ حَافِظُوا عَلَى الصَّلَوَاتِ }وَصَلَاةِ الْعَصْرِ فَقَرَأْنَاهَا مَا شَاءَ اللَّهُ ثُمَّ نَسَخَهَا اللَّهُ فَنَزَلَتْ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى }فَقَالَ رَجُلٌ كَانَ جَالِسًا عِنْدَ شَقِيقٍ لَهُ هِيَ إِذَنْ صَلَاةُ الْعَصْرِ فَقَالَ الْبَرَاءُ قَدْ أَخْبَرْتُكَ كَيْفَ نَزَلَتْ وَكَيْفَ نَسَخَهَا اللَّهُ وَاللَّهُ أَعْلَمُقَالَ مُسْلِم وَرَوَاهُ الْأَشْجَعِيُّ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ شَقِيقِ بْنِ عُقْبَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ قَرَأْنَاهَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَانًا بِمِثْلِ حَدِيثِ فُضَيْلِ بْنِ مَرْزُوقٍ","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] telah mengabarkan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Al Fudlail bin Marzuq] dari [Syaqiq bin 'Uqbah] dari [Al Barra` bin 'Azib] katanya; \"Jagalah oleh kalian seluruh shalat yang ada\" ayat ini turun ketika shalat ashar, maka kami membacanya sekehendak Allah beberapa lama, kemudian Allah memansukhkannya hingga turun ayat \"Jagalah oleh kalian seluruh shalat yang ada dan shalat wustha\" (QS. Albaqarah 238), Maka seseorang yang ketika itu duduk bersama Fudlail bin Marzuq berkata pada Syaqiq \"Shalat wustha yang dimaksud adalah shalat ashar, \" Lalu Al Barra` berkomentar; aku telah mengabarkan kepadamu bagaimana ayat itu turun dan bagaimana Allah memansukhkannya, dan Allah dzat yang lebih tahu.\" Muslim mengatakan; Dan hadis itu diriwayatkan pula oleh [Al Asyja'i] dari [Sufyan Ats Tsauri] dari [Al Aswad bin Qais] dari [Syaqiq bin 'Uqbah] dari [Al Barra` bin 'Azib], kata Al Barra`, kami membacanya bersama Nabi shallallahu 'alaihi wasallam, beberapa lama semisal hadis Fudlail bin Marzuq."},{"p":"Muslim","n":1081,"ar":"و حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَهُوَ مُقْبِلٌ مِنْ مَكَّةَ إِلَى الْمَدِينَةِ عَلَى رَاحِلَتِهِ حَيْثُ كَانَ وَجْهُهُ قَالَ وَفِيهِ نَزَلَتْ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }و حَدَّثَنَاه أَبُو كُرَيْبٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ وَابْنُ أَبِي زَائِدَةَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي كُلُّهُمْ عَنْ عَبْدِ الْمَلِكِ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَفِي حَدِيثِ ابْنِ مُبَارَكٍ وَابْنِ أَبِي زَائِدَةَ ثُمَّ تَلَا ابْنُ عُمَرَ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }وَقَالَ فِي هَذَا نَزَلَتْ","trj":"Dan telah menceritakan kepadaku ['Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Yahya bin Said] dari [Abdul Malik bin Abu Sulaiman] katanya; telah menceritakan kepada kami [Said bin Jubair] dari [Ibnu Umar] katanya; Rasulullah shallallahu 'alaihi wasallam pernah shalat diatas kendarannya ke arah mana saja beliau menghadap, yaitu ketika berangkat dari Makkah menuju Madinah. Dan pada saat itu diturunkan pula ayat \" Kearah manapun engkau menghadap, maka engkau menghadap wajah Allah QS. Albaqarah; 115, Telah menceritakan kepada kami [Abu Kuraib] telah mengabarkan kepada kami [Ibnu Al Mubarak] dan [Ibnu Zaidah] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku], semuanya dari [Abdul Malik] dengan sanad seperti ini, namun dalam hadis Ibnu Al Mubarak dan Ibnu Abi Zaidah disebutkan; \"Kemudian Ibnu Umar membacakan ayat \"Kearah manapun engkau menghadap, maka engkau menghadap wajah Allah. QS. Albaqarah; 115, Dia lalu berkata; \"Tentang masalah inilah ayat ini diturunkan.\""},{"p":"Muslim","n":1141,"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْفَزَارِيُّ يَعْنِي مَرْوَانَ بْنَ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ حَكِيمٍ الْأَنْصَارِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }الْآيَةَ الَّتِي فِي الْبَقَرَةِ وَفِي الْآخِرَةِ مِنْهُمَا{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Fazari yaitu Marwan bin Muawiyah] dari [Utsman bin Hakim Al Anshari], katanya; telah menceritakan kepadaku [Said bin Yasar] bahwa [Ibnu Abbas] mengabarinya; bahwa dalam dua raka'at fajar, tepatnya di raka'at pertama, Rasulullah shallallahu 'alaihi wasallam membaca \"Katakanlah, kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" QS. Albaqarah 136, dan pada rakaat kedua membaca \"Kami beriman kepada Allah, dan saksikanlah bahwa kami orang muslim.\" QS. Ali Imran 52."},{"p":"Muslim","n":1210,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ جَرِيرٍ كُلُّهُمْ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَافْتَتَحَ الْبَقَرَةَ فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَةِ ثُمَّ مَضَى فَقُلْتُ يُصَلِّي بِهَا فِي رَكْعَةٍ فَمَضَى فَقُلْتُ يَرْكَعُ بِهَا ثُمَّ افْتَتَحَ النِّسَاءَ فَقَرَأَهَا ثُمَّ افْتَتَحَ آلَ عِمْرَانَ فَقَرَأَهَا يَقْرَأُ مُتَرَسِّلًا إِذَا مَرَّ بِآيَةٍ فِيهَا تَسْبِيحٌ سَبَّحَ وَإِذَا مَرَّ بِسُؤَالٍ سَأَلَ وَإِذَا مَرَّ بِتَعَوُّذٍ تَعَوَّذَ ثُمَّ رَكَعَ فَجَعَلَ يَقُولُ سُبْحَانَ رَبِّيَ الْعَظِيمِ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَامَ طَوِيلًا قَرِيبًا مِمَّا رَكَعَ ثُمَّ سَجَدَ فَقَالَ سُبْحَانَ رَبِّيَ الْأَعْلَى فَكَانَ سُجُودُهُ قَرِيبًا مِنْ قِيَامِهِقَالَ وَفِي حَدِيثِ جَرِيرٍ مِنْ الزِّيَادَةِ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا لَكَ الْحَمْدُ","trj":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Mu'awiyah] -dalam jalur lain- Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim] semuanya dari [Jarir] mereka semua dari [Al A'masy] -dalam jalur lain- telah menceritakan kepada kami [Ibnu Numair] -dan lafazh ini adalah darinya- telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Sa'id bin Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] ia berkata; Pada suatu malam, saya shalat (Qiyamul Lail) bersama Rasulullah shallallahu 'alaihi wasallam, lalu beliau mulai membaca surat Al Baqarah. Kemudian saya pun berkata (dalam hati bahwa beliau) akan ruku' pada ayat yang ke seratus. Kemudian (seratus ayat pun) berlalu, lalu saya berkata (dalam hati bahwa) beliau akan shalat dengan (surat itu) dalam satu raka'at. Namun (surat Al Baqarah pun) berlalu, maka saya berkata (dalam hati bahwa) beliau akan segera sujud. Ternyata beliau melanjutkan dengan mulai membaca surat An Nisa` hingga selesai membacanya. Kemudian beliau melanjutkan ke surat Ali Imran hingga selesai hingga beliau selesai membacanya. Bila beliau membaca ayat tasbih, beliau bertasbih dan bila beliau membaca ayat yang memerintahkan untuk memohon, beliau memohon, dan bila beliau membaca ayat ta'awwudz (ayat yang memerintahkan untuk memohon perlindungan) beliau memohon perlindungan. Kemudian beliau ruku'. Dalam ruku', beliau membaca: \"SUBHAANA RABBIYAL 'AZHIIM (Maha Suci Tuhanku yang Maha Agung).\" Dan lama beliau ruku' hampir sama dengan berdirinya. Kemudian beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH (Maha Mendengar Allah akan orang yang memuji-Nya).\" Kemudian beliau berdiri dan lamanya berdiri lebih kurang sama dengan lamanya ruku'. Sesudah itu beliau sujud, dan dalam sujud beliau membaca: \"SUBHAANA RABBIYAL A'LAA (Maha Suci Tuhanku Yang Maha Tinggi).\" Lama beliau sujud hampir sama dengan lamanya berdiri. Sementara di dalam hadits Jarir terdapat tambahan; Beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH RABBANAA LAKAL HAMDU (Allah Maha Mendengar akan orang yang memuji-Nya, Ya Tuhan kami bagi-Mu segala puji).\""},{"p":"Muslim","n":1219,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ الْقَارِيُّ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَجْعَلُوا بُيُوتَكُمْ مَقَابِرَ إِنَّ الشَّيْطَانَ يَنْفِرُ مِنْ الْبَيْتِ الَّذِي تُقْرَأُ فِيهِ سُورَةُ الْبَقَرَةِ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman Al Qariy] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian jadikan rumah-rumah kalian sebagai kuburan, sesungguhnya syetan itu akan lari dari rumah yang di dalamnya dibacakan surat Al Baqarah.\""},{"p":"Muslim","n":1256,"ar":"حَدَّثَنِي الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو تَوْبَةَ وَهُوَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ زَيْدٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ يَقُولُ حَدَّثَنِي أَبُو أُمَامَةَ الْبَاهِلِيُّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اقْرَءُوا الْقُرْآنَ فَإِنَّهُ يَأْتِي يَوْمَ الْقِيَامَةِ شَفِيعًا لِأَصْحَابِهِ اقْرَءُوا الزَّهْرَاوَيْنِ الْبَقَرَةَ وَسُورَةَ آلِ عِمْرَانَ فَإِنَّهُمَا تَأْتِيَانِ يَوْمَ الْقِيَامَةِ كَأَنَّهُمَا غَمَامَتَانِ أَوْ كَأَنَّهُمَا غَيَايَتَانِ أَوْ كَأَنَّهُمَا فِرْقَانِ مِنْ طَيْرٍ صَوَافَّ تُحَاجَّانِ عَنْ أَصْحَابِهِمَا اقْرَءُوا سُورَةَ الْبَقَرَةِ فَإِنَّ أَخْذَهَا بَرَكَةٌ وَتَرْكَهَا حَسْرَةٌ وَلَا تَسْتَطِيعُهَا الْبَطَلَةُقَالَ مُعَاوِيَةُ بَلَغَنِي أَنَّ الْبَطَلَةَ السَّحَرَةُ و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا يَحْيَى يَعْنِي ابْنَ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّهُ قَالَ وَكَأَنَّهُمَا فِي كِلَيْهِمَا وَلَمْ يَذْكُرْ قَوْلَ مُعَاوِيَةَ بَلَغَنِي","trj":"Telah menceritakan kepadaku [Al Hasan bin Ali Al Hulwani] telah menceritakan kepada kami [Abu Taubah] ia adalah Ar Rabi' bin Nafi', telah menceritakan kepada kami [Mu'awiyah] yakni Ibnu Sallam, dari [Zaid] bahwa ia mendengar [Abu Sallam] berkata, telah menceritakan kepadaku [Abu Umamah Al Bahili] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah Al Qur`an, karena ia akan datang memberi syafa'at kepada para pembacanya pada hari kiamat nanti. Bacalah Zahrawain, yakni surat Al Baqarah dan Ali Imran, karena keduanya akan datang pada hari kiamat nanti, seperti dua tumpuk awan menaungi pembacanya, atau seperti dua kelompok burung yang sedang terbang dalam formasi hendak membela pembacanya. Bacalah Al Baqarah, karena dengan membacanya akan memperoleh barokah, dan dengan tidak membacanya akan menyebabkan penyesalan, dan pembacanya tidak dapat dikuasai (dikalahkan) oleh tukang-tukang sihir.\" Mu'awiyah berkata; \"Telah sampai (khabar) kepadaku bahwa, Al Bathalah adalah tukang-tukang sihir.\" Dan telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Yahya] yakni Ibnu Hassan, Telah menceritakan kepada kami [Mu'awiyah] dengan isnad ini, hanya saja ia mentatakan; \"Wa Ka`annahumaa fii Kilaihimaa.\" dan ia tidak menyebutkan ungkapan Mu'awiyah, \"Telah sampai (khabar) padaku.\""},{"p":"Muslim","n":1257,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مُحَمَّدِ بْنِ مُهَاجِرٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْجُرَشِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ قَالَ سَمِعْتُ النَّوَّاسَ بْنَ سَمْعَانَ الْكِلَابِيَّ يَقُولُاسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُؤْتَى بِالْقُرْآنِ يَوْمَ الْقِيَامَةِ وَأَهْلِهِ الَّذِينَ كَانُوا يَعْمَلُونَ بِهِ تَقْدُمُهُ سُورَةُ الْبَقَرَةِ وَآلُ عِمْرَانَ وَضَرَبَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَمْثَالٍ مَا نَسِيتُهُنَّ بَعْدُ قَالَ كَأَنَّهُمَا غَمَامَتَانِ أَوْ ظُلَّتَانِ سَوْدَاوَانِ بَيْنَهُمَا شَرْقٌ أَوْ كَأَنَّهُمَا حِزْقَانِ مِنْ طَيْرٍ صَوَافَّ تُحَاجَّانِ عَنْ صَاحِبِهِمَا","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Yazid bin Abdu Rabbih] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Muhammad bin Muhajir] dari [Al Walid bin Abdurrahman Al Jurasyi] dari [Jubair bin Nufair] ia berkata, saya mendengar [An Nawwas bin Sam'an Al Kilabi] berkata; Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Al Qur`an akan didatangkan pada hari kiamat bersama Ahlinya yang telah beramal dengannya, dan yang pertama kali adalah surat Al Baqarah dan Ali Imran.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan tiga permisalan terkait dengan keduanya, aku tidak akan melupakannya setelah itu. yakni: \"Seperti dua tumpuk awan hitam yang diantara keduanya terdapat cahaya, atau seperti dua kelompok burung yang sedang terbang dalam formasi hendak membela pembacanya.\""},{"p":"Muslim","n":1258,"ar":"حَدَّثَنَا حَسَنُ بْنُ الرَّبِيعِ وَأَحْمَدُ بْنُ جَوَّاسٍ الْحَنْفِيُّ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَمَّارِ بْنِ رُزَيْقٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَيْنَمَا جِبْرِيلُ قَاعِدٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ نَقِيضًا مِنْ فَوْقِهِ فَرَفَعَ رَأْسَهُ فَقَالَ هَذَا بَابٌ مِنْ السَّمَاءِ فُتِحَ الْيَوْمَ لَمْ يُفْتَحْ قَطُّ إِلَّا الْيَوْمَ فَنَزَلَ مِنْهُ مَلَكٌ فَقَالَ هَذَا مَلَكٌ نَزَلَ إِلَى الْأَرْضِ لَمْ يَنْزِلْ قَطُّ إِلَّا الْيَوْمَ فَسَلَّمَ وَقَالَ أَبْشِرْ بِنُورَيْنِ أُوتِيتَهُمَا لَمْ يُؤْتَهُمَا نَبِيٌّ قَبْلَكَ فَاتِحَةُ الْكِتَابِ وَخَوَاتِيمُ سُورَةِ الْبَقَرَةِ لَنْ تَقْرَأَ بِحَرْفٍ مِنْهُمَا إِلَّا أُعْطِيتَهُ","trj":"Telah menceritakan kepada kami [Hasan bin Rabi'] dan [Ahmad bin Jawwas Al Hanfi] keduanya berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Ammar bin Ruzaiq] dari [Abdullah bin Isa] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; Ketika malaikat Jibril sedang duduk di samping Nabi shallallahu 'alaihi wasallam tiba-tiba ia mendengar suara pintu dibuka dari arah atas kepalanya. Lalu malaikat Jibril berkata: \"Itu adalah suara salah satu pintu langit yang dibuka, sebelumnya ia belum pernah dibuka sama sekali kecuali pada hari ini.\" Lalu keluarlah daripadanya malaikat. Jibril berkata: \"Ini adalah malaikat yang hendak turun ke bumi, sebelumnya ia belum pernah turun ke bumi sama sekali kecuali pada hari ini saja.\" Lalu ia memberi salam dan berkata: \"Bergembiralah atas dua cahaya yang diberikan kepadamu dan belum pernah diberikan kepada seorang Nabipun sebelummu, yaitu pembuka Al Kitab (surat Al Fatihah) dan penutup surat Al Baqarah. Tidaklah kamu membaca satu huruf dari kedua surat itu kecuali pasti akan diberikan kepadamu.\""},{"p":"Muslim","n":1259,"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ لَقِيتُ أَبَا مَسْعُودٍ عِنْدَ الْبَيْتِفَقُلْتُ حَدِيثٌ بَلَغَنِي عَنْكَ فِي الْآيَتَيْنِ فِي سُورَةِ الْبَقَرَةِ فَقَالَ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآيَتَانِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ مَنْ قَرَأَهُمَا فِي لَيْلَةٍ كَفَتَاهُو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ كِلَاهُمَا عَنْ مَنْصُورٍ بِهَذَا الْإِسْنَادِ","trj":"Dan telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] ia berkata; Saya menjumpai [Abu Mas'ud] di Baitullah, maka saya pun berkata, \"Ada satu hadits dari Anda yang telah sampai kepadaku tentang dua ayat yang terdapat di dalam surat Al Baqarah.\" Abu Mas'ud berkata; Ya, Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Siapa yang membaca kedua ayat itu, yakni akhir dari surat Al Baqarah, niscaya keduanya akan memeliharanya dari bencana.\" Dan telah menceritakannya kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] -dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] keduanya berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] keduanya dari [Manshur] dengan isnad ini."},{"p":"Muslim","n":1260,"ar":"و حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ أَخْبَرَنَا ابْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَلْقَمَةَ بْنِ قَيْسٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ هَاتَيْنِ الْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُقَالَ عَبْدُ الرَّحْمَنِ فَلَقِيتُ أَبَا مَسْعُودٍ وَهُوَ يَطُوفُ بِالْبَيْتِ فَسَأَلْتُهُ فَحَدَّثَنِي بِهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنِي عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى يَعْنِي ابْنَ يُونُسَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ جَمِيعًا عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَعَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصٌ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","trj":"Dan telah menceritakan kepada kami [Minjab bin Harits At Tamimi] telah mengabarkan kepada kami [Ibnu Mushir] dari [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Alqamah bin Qais] dari [Abu Mas'ud Al Anshari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca dua ayat ini, yakni dari akhir surat Al Baqarah di suatu malam, maka keduanya akan menjaganya dari bencana.\" Abdurrahman berkata; Saya menjumpai Abu Mas'ud yang sedang melakukan thawaf di Baitullah, maka saya bertanya kepadanya. Maka ia pun menceritakannya kepadaku dari Nabi shallallahu 'alaihi wasallam. Dan telah menceritakan kepadaku [Ali bin Khasyram] telah mengabarkan kepada kami [Isa] yakni Ibnu Yunus. -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] semuanya dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dan [Abdurrahman bin Yazid] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam semisalnya. -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hafsh] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam semisalnya."},{"p":"Muslim","n":1430,"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَانْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَامَ قِيَامًا طَوِيلًا قَدْرَ نَحْوِ سُورَةِ الْبَقَرَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ وَقَدْ انْجَلَتْ الشَّمْسُ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَاذْكُرُوا اللَّهَ قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ هَذَا ثُمَّ رَأَيْنَاكَ كَفَفْتَ فَقَالَ إِنِّي رَأَيْتُ الْجَنَّةَ فَتَنَاوَلْتُ مِنْهَا عُنْقُودًا وَلَوْ أَخَذْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا وَرَأَيْتُ النَّارَ فَلَمْ أَرَ كَالْيَوْمِ مَنْظَرًا قَطُّ وَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ قَالُوا بِمَ يَا رَسُولَ اللَّهِ قَالَ بِكُفْرِهِنَّ قِيلَ أَيَكْفُرْنَ بِاللَّهِ قَالَ بِكُفْرِ الْعَشِيرِ وَبِكُفْرِ الْإِحْسَانِ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّو حَدَّثَنَاه مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا إِسْحَقُ يَعْنِي ابْنَ عِيسَى أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ فِي هَذَا الْإِسْنَادِ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ ثُمَّ رَأَيْنَاكَ تَكَعْكَعْتَ","trj":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Hafsh bin Maisarah] telah menceritakan kepadaku [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Ibnu Abbas] ia berkata; Pernah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam menunaikan shalat dan para sahabat pun ikut menyertainya. Kemudian beliau berdiri sangat lama kira-kira selama pembacaan surat Al Baqarah, lalu beliau ruku' dengan ruku' yang sangat lama. Kemudian beliau bangkit (dari ruku') dan berdiri dengan sangat lama namun tidak selama berdirinya yang pertama, lalu beliau ruku' lama sekali, namun tidak selama ruku'nya yang pertama, kemudian beliau sujud. setelah itu, beliau berdiri kembali dan berdirinya sangat lama, namun tidak selama berdirinya yang pertama. Lalu beliau ruku' dengan ruku' yang lama pula, namun tidak selama ruku'nya yang pertama. Kemudian beliau bangkit dan berdiri sangat lama, namun tidak sebagaimana berdirinya yang pertama, lalu beliau ruku' sangat lama, tetapi tidak selama ruku'nya yang pertama. Kemudian beliau sujud, hingga kemudian beliau beranjak (setelah usai menunaikan shalat) sementara matahari telah terang kembali. Maka beliau pun bersabda: \"Sesungguhnya matahari dan bulan adalah dua ayat dari ayat-ayat Allah. Tidaklah terjadi gerhana pada keduanya karena kematian seseorang atau pun kelahirannya. Jika kalian melihatnya, maka berdzikirlah kepada Allah.\" Para sahabat berkata, \"Wahai Rasulullah, kami melihat Anda sepertinya mendapatkan sesuatu di tempat Anda berdiri ini, dan kami juga melihat Anda menahan kedua tangan.\" Maka beliau pun menjelaskan: \"Sesungguhnya saya telah melihat surga, lalu saya mendapati satu tandan, sekiranya saya mengambilnya, niscaya kalian akan makan darinya selama dunia ini ada. Kemudian saya juga melihat neraka, maka saya belum pernah melihat pemandangan yang dahsyat seperti hari ini, dan saya melihat bahwa kebanyakan penghuninya adalah kaum wanita.\" Para sahabat bertanya, \"Apakah penyebabnya wahai Rasulullah?\" beliau menjawab: \"Lantaran kekufuran mereka.\" kemudian ditanyakan lagi kepada beliau: \"Apakah mereka kufur kepada Allah?\" beliau menjawab: \"Yaitu kufur (tidak menerima) kelebihan suami, dan mengkufuri kebaikannya. Sekiranya kamu berbuat baik kepada salah seorang dari mereka sepanjang masa, lalu ia mendapati satu keburukan darimu, niscaya ia akan mengatakan, 'Saya tidak pernah mendapati satu kebaikan pun darimu.'\" Dan telah menceritakannya kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Ishaq] yakni Ibnu Isa, telah mengabarkan kepada kami [Malik] dari [Zaid bin Aslam] dalam isnad ini semisalnya. Hanya saja ia menyebutkan; \"Kemudian kami melihat Anda menahan diri sejenak.\""},{"p":"Muslim","n":1825,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بَكْرٌ يَعْنِي ابْنَ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَعَلَى الَّذِينَ يُطِيقُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ }كَانَ مَنْ أَرَادَ أَنْ يُفْطِرَ وَيَفْتَدِيَ حَتَّى نَزَلَتْ الْآيَةُ الَّتِي بَعْدَهَا فَنَسَخَتْهَا","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Bakr bin Manshur] dari [Amru bin Harits] dari [Bukair] dari [Yazid] Maula Salamah, dari [Salamah bin Al Akwa'] ia berkata; Ketika turun ayat; \"…dan wajib bagi orang-orang yang berat menjalankannya (jika mereka tidak berpuasa) membayar fidyah, (yaitu): memberi makan seorang miskin…\". (QS. Albaqarah 184), banyak orang yang menginginkan untuk tetap makan (tidak berpuasa) dan hanya membayar fidyah, sampai turun ayat setelahnya dan iapun saya me-nasakh-nya."},{"p":"Muslim","n":1826,"ar":"حَدَّثَنِي عَمْرُو بْنُ سَوَّادٍ الْعَامِرِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَكُنَّا فِي رَمَضَانَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَاءَ صَامَ وَمَنْ شَاءَ أَفْطَرَ فَافْتَدَى بِطَعَامِ مِسْكِينٍ حَتَّى أُنْزِلَتْ هَذِهِ الْآيَةُ{ فَمَنْ شَهِدَ مِنْكُمْ الشَّهْرَ فَلْيَصُمْهُ }","trj":"Telah menceritakan kepadaku [Amru bin Sawwad Al 'Amiri] telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepada kami [Amru bin Harits] dari [Bukair bin Al Asyajj] dari [Yazid] Maula Salamah bin Al Akwa', dari [Salamah Al Akwa'] radliallahu 'anhu, bahwa ia berkata; Dulu, ketika kami memasuki bulan Ramadlan pada masa Rasulullah shallallahu 'alaihi wasallam siapa saja yang ingin, maka ia berpuasa dan siapa yang tidak suka, maka ia akan berbuka dengan syarat membayar fidyah, peritstiwa itu terus terjadi hingga turunnya ayat: \"Karena itu, barangsiapa di antara kamu hadir (di negeri tempat tinggalnya) di bulan itu, Maka hendaklah ia berpuasa pada bulan itu.\" (QS. Albaqarah 185)."},{"p":"Muslim","n":1955,"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَفِيَّ أُنْزِلَتْ هَذِهِ الْآيَةُ{ فَمَنْ كَانَ مِنْكُمْ مَرِيضًا أَوْ بِهِ أَذًى مِنْ رَأْسِهِ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ فَأَتَيْتُهُ فَقَالَ ادْنُهْ فَدَنَوْتُ فَقَالَ ادْنُهْ فَدَنَوْتُ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُؤْذِيكَ هَوَامُّكَ قَالَ ابْنُ عَوْنٍ وَأَظُنُّهُ قَالَ نَعَمْ قَالَ فَأَمَرَنِي بِفِدْيَةٍ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ مَا تَيَسَّرَ","trj":"Dan Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu Adi] dari [Ibnu Aun] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Ka'ab bin Ujrah] radliallahu 'anhu, ia berkata; Kepadakulah ayat ini diturunkan; \"Jika ada di antaramu yang sakit atau ada gangguan di kepalanya (lalu ia bercukur), Maka wajiblah atasnya berfid-yah, yaitu: berpuasa atau bersedekah atau berkorban.\" (QS. Albaqarah; 196), Saya mendatangi beliau, dan beliau bersabda: \"Dekatkanlah ia.\" Saya pun mendekat. Beliau berkata lagi: \"Dekatkanlah ia.\" Saya pun lebih mendekat lagi, kemudian Nabi shallallahu 'alaihi wasallam bertanya: \"Apakah kutu dikepalamu itu mengganggumu?\" Ibnu Aun berkata; Saya menduga bahwa ia menjawab, \"Ya.\" Ka'ab bin Ujrah berkata; Lalu beliau pun memerintahkanku untuk membayar fidyah berupa puasa atau sedekah atau berkurban sesuai kemampuan."},{"p":"Muslim","n":1956,"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا سَيْفٌ قَالَ سَمِعْتُ مُجَاهِدًا يَقُولُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى حَدَّثَنِي كَعْبُ بْنُ عُجْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَفَ عَلَيْهِ وَرَأْسُهُ يَتَهَافَتُ قَمْلًا فَقَالَ أَيُؤْذِيكَ هَوَامُّكَ قُلْتُ نَعَمْ قَالَ فَاحْلِقْ رَأْسَكَ قَالَ فَفِيَّ نَزَلَتْ هَذِهِ الْآيَةُ{ فَمَنْ كَانَ مِنْكُمْ مَرِيضًا أَوْ بِهِ أَذًى مِنْ رَأْسِهِ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ ثَلَاثَةَ أَيَّامٍ أَوْ تَصَدَّقْ بِفَرَقٍ بَيْنَ سِتَّةِ مَسَاكِينَ أَوْ انْسُكْ مَا تَيَسَّرَ","trj":"Dan Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Saif] ia berkata, saya mendengar [Mujahid] berkata, telah menceritakan kepadaku [Abdurrahman bin Abu Laila] telah menceritakan kepadaku [Ka'ab bin Ujrah] radliallahu 'anhu katanya; Bahwa ketika ia sedang ihram, Rasulullah shallallahu 'alaihi wasallam berdiri di dekatnya, sedangkan kutu berjatuhan dari kepadalanya. Maka beliau pun bertanya: \"Apakah kutumu itu mengganggumu?\" saya menjawab, \"Ya.\" Beliau bersabda: \"Cukurlah rambutmu.\" Ka'ab berkata; Maka kepadakulah ayat ini diturunkan: \"… atau ada gangguan di kepalanya (lalu ia bercukur), Maka wajiblah atasnya berfid-yah, yaitu: berpuasa atau bersedekah atau berkorban.\" (QS. Albaqarah; 196), Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Berpuasalah tiga hari, atau bersedekahlah kepada enam orang miskin atau berkurban dengan sesuatu yang mudah di dapatkan.\""},{"p":"Muslim","n":1959,"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ قَالَقَعَدْتُ إِلَى كَعْبٍ رَضِيَ اللَّهُ عَنْهُ وَهُوَ فِي الْمَسْجِدِ فَسَأَلْتُهُ عَنْ هَذِهِ الْآيَةِ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }فَقَالَ كَعْبٌ رَضِيَ اللَّهُ عَنْهُ نَزَلَتْ فِيَّ كَانَ بِي أَذًى مِنْ رَأْسِي فَحُمِلْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي فَقَالَ مَا كُنْتُ أُرَى أَنَّ الْجَهْدَ بَلَغَ مِنْكَ مَا أَرَى أَتَجِدُ شَاةً فَقُلْتُ لَا فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَفِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ }قَالَ صَوْمُ ثَلَاثَةِ أَيَّامٍ أَوْ إِطْعَامُ سِتَّةِ مَسَاكِينَ نِصْفَ صَاعٍ طَعَامًا لِكُلِّ مِسْكِينٍ قَالَ فَنَزَلَتْ فِيَّ خَاصَّةً وَهِيَ لَكُمْ عَامَّةً","trj":"Dan Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] - [Ibnul Mutsanna] berkata- Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Ashbahani] dari [Abdullah bin Ma'qil] ia berkata; Saya duduk bersama [Ka'ab radliallahu 'anhu] yang saat itu ia sedang berada di masjid. Lalu saya bertanya kepadanya tentang ayat ini; \"Maka wajiblah atasnya berfid-yah, yaitu: berpuasa atau bersedekah atau berkorban.\" (QS. Albaqarah; 196), Maka Ka'ab bin Ujrah radliallahu 'anhu menjawab; Ayat itu turun berkenaan dengan diriku. Aku pernah menderita sakit di kulit kepalaku (ketika sedang ihram), lalu aku dibawa menghadap Rasulullah shallallahu 'alaihi wasallam, sedangkan kutu telah bertebaran di wajahku. Maka beliau bersabda: \"Aku tidak pernah melihat penderitaan seperti yang menimpamu. Apakah kamu mampu mendapatkan seekor kambing?\" aku menjawab, \"Tidak.\" Maka turunlah ayat ini; \"Maka wajiblah atasnya berfid-yah, yaitu: berpuasa atau bersedekah atau berkorban.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau begitu, berpuasalah tiga hari, atau berilah makan kepada enam orang miskin, yakni setengah sha' untuk setiap orangnya.\" Ka'ab bin Ujrah berkata; Ayat tersebut turun khusus berkenaan dengan diriku, namun berlaku umum untuk kalian semua."},{"p":"Muslim","n":1960,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ زَكَرِيَّاءَ بْنِ أَبِي زَائِدَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَصْبَهَانِيِّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مَعْقِلٍ حَدَّثَنِي كَعْبُ بْنُ عُجْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّهُ خَرَجَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْرِمًا فَقَمِلَ رَأْسُهُ وَلِحْيَتُهُ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَيْهِ فَدَعَا الْحَلَّاقَ فَحَلَقَ رَأْسَهُ ثُمَّ قَالَ لَهُ هَلْ عِنْدَكَ نُسُكٌ قَالَ مَا أَقْدِرُ عَلَيْهِ فَأَمَرَهُ أَنْ يَصُومَ ثَلَاثَةَ أَيَّامٍ أَوْ يُطْعِمَ سِتَّةَ مَسَاكِينَ لِكُلِّ مِسْكِينَيْنِ صَاعٌ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِيهِ خَاصَّةً{ فَمَنْ كَانَ مِنْكُمْ مَرِيضًا أَوْ بِهِ أَذًى مِنْ رَأْسِهِ }ثُمَّ كَانَتْ لِلْمُسْلِمِينَ عَامَّةً","trj":"Dan Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dari [Zakaria bin Abu Za`idah] telah menceritakan kepada kami [Abdurrahman Al Ashbahani] telah menceritakan kepadaku [Abdullah bin Ma'qil] telah menceritakan kepadaku [Ka'ab bin Ujrah] radliallahu 'anhu katanya; Ia pernah pergi haji bersama-sama dengan Nabi shallallahu 'alaihi wasallam, sedangkan kepala dan jenggotnya penuh dengan kutu. Kemudian hal itu sampai sampai kepada Nabi shallallahu 'alaihi wasallam, dan beliau pun mengutus seseorang keapdanya. Lalu beliau memanggil tukang cukur untuk mencukur rambutnya. Akhirnya tukang cukur itu pun mencukur rambut Ka'ab bin Ujrah. Sesudah itu, beliau bertanya: \"Apakah kamu mempunyai Nusuk (hewan kurban)?\" ia menjawab, \"Saya tidak sanggup melakukannya.\" Maka beliau pun memerintahkannya untuk berpuasa tiga hari, atau memberi makan kepada enam orang miskin, yakni satu Sha' untuk setiap orangnya. Kemudian Allah menurunkan ayat yang khusus berkenaan dengan peristiwa itu; \"Jika ada di antaramu yang sakit atau ada gangguan di kepalanya (lalu ia bercukur), \" (QS. Albaqarah; 196) dan hukumnya kemudian menjadi umum bagi kaum muslimin."},{"p":"Muslim","n":2101,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ حُصَيْنٍ عَنْ كَثِيرِ بْنِ مُدْرِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَقَالَ عَبْدُ اللَّهِ وَنَحْنُ بِجَمْعٍ سَمِعْتُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ يَقُولُ فِي هَذَا الْمَقَامِ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ","trj":"Dan Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] Telah menceritakan kepada kami [Abul Ahwash] dari [Hushain] dari [Katsir bin Mudrik] dari [Abdurrahman bin Yazid] ia berkata; [Abdullah] berkata saat kami berada di Jam'; Aku telah mendengar seorang yang telah diturunkan kepadanya surat Al Baqarah, yakni di tempat ini membaca: \"LABBAIKA ALLAHUMMA LABBAIKA (Aku penuhi panggilan-Mu, Ya Allah aku penuhi panggilan-Mu).\""},{"p":"Muslim","n":2102,"ar":"و حَدَّثَنَا سُرَيْجُ بْنُ يُونُسَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ عَنْ كَثِيرِ بْنِ مُدْرِكٍ الْأَشْجَعِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَأَنَّ عَبْدَ اللَّهِ لَبَّى حِينَ أَفَاضَ مِنْ جَمْعٍ فَقِيلَ أَعْرَابِيٌّ هَذَا فَقَالَ عَبْدُ اللَّهِ أَنَسِيَ النَّاسُ أَمْ ضَلُّوا سَمِعْتُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ يَقُولُ فِي هَذَا الْمَكَانِ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَو حَدَّثَنَاه حَسَنٌ الْحُلْوَانِيُّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا سُفْيَانُ عَنْ حُصَيْنٍ بِهَذَا الْإِسْنَادِ","trj":"Dan Telah menceritakan kepada kami [Suraij bin Yunus] Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Hushain] dari [Katsir bin Mudrik Al Asyja'i] dari [Abdurrahman bin Yazid] bahwasanya; [Abdullah] membaca talbiyah (mulai ihram) saat ia berangkat dari Jam', lalu dikatakanlah kepadanya, \"Ini adalah seorang A'rabi.\" Maka Abdullah pun berkata, \"Apakah orang-orang telah lupa, ataukah mereka telah sesat. Aku telah mendengar seorang yang telah diturunkan surat Al Baqarah kepadanya di tempat ini, ia membaca: \"LABBAIKA ALLAHUMMA LABBAIKA (Aku penuhi panggilan-Mu, Ya Allah aku penuhi panggilan-Mu).\" Dan Telah menceritakannya kepada kami [Hasan Al Hulwani] Telah menceritakan kepada kami [Yahya bin Adam] Telah menceritakan kepada kami [Sufyan] dari [Hushain] dengan isnad ini."},{"p":"Muslim","n":2103,"ar":"و حَدَّثَنِيهِ يُوسُفُ بْنُ حَمَّادٍ الْمَعْنِيُّ حَدَّثَنَا زِيَادٌ يَعْنِي الْبَكَّائِيَّ عَنْ حُصَيْنٍ عَنْ كَثِيرِ بْنِ مُدْرِكٍ الْأَشْجَعِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ وَالْأَسْوَدِ بْنِ يَزِيدَ قَالَا سَمِعْنَا عَبْدَ اللَّهِ بْنَ مَسْعُودٍيَقُولُ بِجَمْعٍ سَمِعْتُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ هَاهُنَا يَقُولُ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ ثُمَّ لَبَّى وَلَبَّيْنَا مَعَهُ","trj":"Dan telah menceritakannya kepadaku [Yusuf bin Hammad Al Ma'ni] Telah menceritakan kepada kami [Ziyad Al Bakka`i] dari [Hushain] dari [Katsir bin Mudrik Al Asyja'i] dari [Abdurrahman bin Yazid] dan [Al Aswad bin Yazid] keduanya berkata, kami mendengar [Abdullah bin Mas'ud] berkata di Jam'; Aku mendengar seorang yang telah diturunkan kepadanya surat Al Baqarah di tempat ini membaca: \"LABBAIKA ALLAHUMMA LABBAIKA (Aku penuhi panggilan-Mu, Ya Allah aku penuhi panggilan-Mu).\" Sesudah itu, ia membaca talbiyah, dan kami pun ikut bertalbiyah (memulai Ihram)."},{"p":"Muslim","n":2129,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ رَمَى عَبْدُ اللَّهِ بْنُ مَسْعُودٍ جَمْرَةَ الْعَقَبَةِ مِنْ بَطْنِ الْوَادِي بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ قَالَ فَقِيلَ لَهُ إِنَّ أُنَاسًا يَرْمُونَهَا مِنْ فَوْقِهَافَقَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ هَذَا وَالَّذِي لَا إِلَهَ غَيْرُهُ مَقَامُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid] ia berkata; [Abdullah bin Mas'ud] melempar Jamrah Aqabah dari dalam lembah dengan tujuh butir kerikil. Dan setiap kali melempar satu kerikil diiringinya dengan tabkir. Kemudian dikatakanlah kepadanya, \"Sesungguhnya orang-orang melempar Jamrah dari atas lembah.\" Maka Abdullah bin Mas'ud berkata, \"Demi Dzat yang tidak ada Tuhan yang berhak disembah selain-Nya, inilah tempat berdirinya seorang yang diturunkan kepadanya surat Al Baqarah.\""},{"p":"Muslim","n":2130,"ar":"و حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ أَخْبَرَنَا ابْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ الْحَجَّاجَ بْنَ يُوسُفَ يَقُولُ وَهُوَ يَخْطُبُ عَلَى الْمِنْبَرِ أَلِّفُوا الْقُرْآنَ كَمَا أَلَّفَهُ جِبْرِيلُ السُّورَةُ الَّتِي يُذْكَرُ فِيهَا الْبَقَرَةُ وَالسُّورَةُ الَّتِي يُذْكَرُ فِيهَا النِّسَاءُ وَالسُّورَةُ الَّتِي يُذْكَرُ فِيهَا آلُ عِمْرَانَ قَالَ فَلَقِيتُ إِبْرَاهِيمَ فَأَخْبَرْتُهُ بِقَوْلِهِ فَسَبَّهُ وَقَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَأَنَّهُ كَانَ مَعَ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ فَأَتَى جَمْرَةَ الْعَقَبَةِ فَاسْتَبْطَنَ الْوَادِي فَاسْتَعْرَضَهَا فَرَمَاهَا مِنْ بَطْنِ الْوَادِي بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ قَالَ فَقُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنَّ النَّاسَ يَرْمُونَهَا مِنْ فَوْقِهَا فَقَالَ هَذَا وَالَّذِي لَا إِلَهَ غَيْرُهُ مَقَامُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِو حَدَّثَنِي يَعْقُوبُ الدَّوْرَقِيُّ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ كِلَاهُمَا عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ الْحَجَّاجَ يَقُولُ لَا تَقُولُوا سُورَةُ الْبَقَرَةِ وَاقْتَصَّا الْحَدِيثَ بِمِثْلِ حَدِيثِ ابْنِ مُسْهِرٍ","trj":"Dan Telah menceritakan kepada kami [Minjab bin Harits At Tamimi] telah mengabarkan kepada kami [Ibnu Mushir] dari [Al A'masy] ia berkata, saya mendengar Al Hajjaj bin Yusuf berkata saat ia sedang berkhutbah di atas mimbar, \"Biasakanlah membaca Al Qur`an sebagaimana yang dibacakan oleh Jibril, (yaitu) surah yang disebutkan di dalamnya Al Baqarah, An Nisa`, dan Ali Imram. Al A'masy berkata; Kemudian aku temui [Ibrahim], lalu aku sampaikan ucapan Al Hajjaj bin Yusuf itu, lalu ia mencelanya. Ibrahim berkata; [Abdurrahman bin Yazid] telah menceritakan kepadaku bahwasanya, ia pernah bersama [Abdullah bin Mas'ud], lalu ia menuju ke Jumratul 'Aqabah. Ia menuju ke tengah lembah dengan tujuh buah kerikil sambil diiringi membaca takbir pada setiap kali lantaran kerikil tersebut.\" Al A'masy berkata; Aku pun bertanya, \"Wahai Abu Abdurrahman, orang-orang pada melontar Jamrah dari atas?\" Ia menjawab, \"Demi Dzat yang tidak Tuhan yang berhak disembah selain-Nya, inilah tempat (melempar Jamrah) seorang yang telah diturunkan surat Al Baqarah kepadanya.\" Dan telah menceritakan kepadaku [Ya'qub Ad Dauraqi] Telah menceritakan kepada kami [Ibnu Abu Za`idah] -dalam riwayat lain- Dan Telah menceritakan kepada kami [Ibnu Abu Umar] Telah menceritakan kepada kami [Sufyan] keduanya dari [Al A'masy] ia berkata, saya mendengar Al Hajjaj berkata; \"Janganlah kalian mengatakan surat Al Baqarah…\" ia pun mengisahkan hadits sebagaimana haditsnya Ibnu Mushir."},{"p":"Muslim","n":2131,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ أَنَّهُ حَجَّ مَعَ عَبْدِ اللَّهِ قَالَ فَرَمَى الْجَمْرَةَ بِسَبْعِ حَصَيَاتٍ وَجَعَلَ الْبَيْتَ عَنْ يَسَارِهِ وَمِنًى عَنْ يَمِينِهِوَقَالَ هَذَا مَقَامُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِو حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّهُ قَالَ فَلَمَّا أَتَى جَمْرَةَ الْعَقَبَةِ","trj":"Dan Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] Telah menceritakan kepada kami [Ghundar] dari [Syu'bah] -dalam riwayat lain- Dan Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] keduanya berkata, Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Abdurrahman bin Yazid] bahwa ia pernah menunaikan haji bersama [Abdullah]. Kemudian Abdullah pun melempar Jamrah Aqabah dengan tujuh butir kerikil. (Posisinya), ia menempatkan Baitullah di sebelah kirinya sedangkan Mina di sebelah kanannya. Dan ia pun berkata, \"Inilah tempat (melempar Jamrah) orang yang telah diturunkan surat Al Baqarah kepadanya.\" Dan Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Syu'bah] dengan Isnad ini, hanya saja ia menyebutkan; \"Dan ketika sampai di Jamrah Aqabah.\""},{"p":"Muslim","n":2132,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْمُحَيَّاةِ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَاللَّفْظُ لَهُ أَخْبَرَنَا يَحْيَى بْنُ يَعْلَى أَبُو الْمُحَيَّاةِ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ قِيلَ لِعَبْدِ اللَّهِ إِنَّ نَاسًا يَرْمُونَ الْجَمْرَةَ مِنْ فَوْقِ الْعَقَبَةِ قَالَ فَرَمَاهَا عَبْدُ اللَّهِ مِنْ بَطْنِ الْوَادِي ثُمَّقَالَ مِنْ هَا هُنَا وَالَّذِي لَا إِلَهَ غَيْرُهُ رَمَاهَا الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","trj":"Dan Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] Telah menceritakan kepada kami [Abul Muhayyat] -dalam riwayat lain- Dan Telah menceritakan kepada kami [Yahya bin Yahya] -lafazh juga miliknya- telah mengabarkan kepada kami [Yahya bin Ya'la Abul Muhayyat] dari [Salamah bin Kuhail] dari [Abdurrahman bin Yazid] ia berkata; Pernah dikatakan kepada [Abdullah], \"Sesungguhnya orang-orang pada melontar Jamrah dari atas 'Aqabah?\" Namun Abdullah kemudian melempar dari dalam lembah, dan ia pun berkata, \"Dari sinilah (tempatnya melempar) -Demi Dzat yang tidak ada Tuhan yang berhak disembah selain-Nya- seorang yang telah diturunkan surat Al Baqarah padanya.\""},{"p":"Muslim","n":2731,"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ زُهَيْرٌ حَدَّثَنَا إِسْحَقُ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاقْتَرَأَهُنَّ عَلَى النَّاسِ ثُمَّ نَهَى عَنْ التِّجَارَةِ فِي الْخَمْرِ","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim], [Zuhair] berkata; telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Abu Ad Dluha] dari [Masruq] dari [Aisyah] dia berkata, \"Ketika turun ayat akhir dari surat Al Baqarah, maka Rasulullah shallallahu 'alaihi wasallam keluar dan membacakannya kepada orang-orang, kemudian beliau melarang jual beli khamer.\""},{"p":"Muslim","n":2732,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لِأَبِي كُرَيْبٍ قَالَ إِسْحَقُ أَخْبَرَنَا وَقَالَ الْآخَرَانِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْلَمَّا أُنْزِلَتْ الْآيَاتُ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي الرِّبَا قَالَتْ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَسْجِدِ فَحَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] dan [Ishaq bin Ibrahim] dan ini adalah lafadz Abu Kuraib -Ishaq berkata; telah mengabarkan kepada kami, sedangkan yang dua berkata; telah menceritakan kepada kami- [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari ['Aisyah] dia berkata, \"Tatkala akhir ayat dari surat Al Baqarah yang mengenai riba turun, \" dia melanjutkan, \"Maka Rasulullah shallallahu 'alaihi wasallam keluar menuju masjid dan mengharamkan jual beli khamer.\""},{"p":"Muslim","n":4210,"ar":"قَالَ ابْنُ شِهَابٍ وَقَالَ ابْنُ الْمُسَيَّبِ إِنَّ أَبَا هُرَيْرَةَ قَالَ يَقُولُونَ إِنَّ أَبَا هُرَيْرَةَ قَدْ أَكْثَرَ وَاللَّهُ الْمَوْعِدُ وَيَقُولُونَ مَا بَالُ الْمُهَاجِرِينَ وَالْأَنْصَارِ لَا يَتَحَدَّثُونَ مِثْلَ أَحَادِيثِهِ وَسَأُخْبِرُكُمْ عَنْ ذَلِكَ إِنَّ إِخْوَانِي مِنْ الْأَنْصَارِ كَانَ يَشْغَلُهُمْ عَمَلُ أَرَضِيهِمْ وَإِنَّ إِخْوَانِي مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ الصَّفْقُ بِالْأَسْوَاقِ وَكُنْتُ أَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مِلْءِ بَطْنِي فَأَشْهَدُ إِذَا غَابُوا وَأَحْفَظُ إِذَا نَسُوا وَلَقَدْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا أَيُّكُمْ يَبْسُطُ ثَوْبَهُ فَيَأْخُذُ مِنْ حَدِيثِي هَذَا ثُمَّ يَجْمَعُهُ إِلَى صَدْرِهِ فَإِنَّهُ لَمْ يَنْسَ شَيْئًا سَمِعَهُ فَبَسَطْتُ بُرْدَةً عَلَيَّ حَتَّى فَرَغَ مِنْ حَدِيثِهِ ثُمَّ جَمَعْتُهَا إِلَى صَدْرِي فَمَا نَسِيتُ بَعْدَ ذَلِكَ الْيَوْمِ شَيْئًا حَدَّثَنِي بِهِ وَلَوْلَا آيَتَانِ أَنْزَلَهُمَا اللَّهُ فِي كِتَابِهِ مَا حَدَّثْتُ شَيْئًا أَبَدًا{ إِنَّ الَّذِينَ يَكْتُمُونَ مَا أَنْزَلْنَا مِنْ الْبَيِّنَاتِ وَالْهُدَى }إِلَى آخِرِ الْآيَتَيْنِو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا أَبُو الْيَمَانِ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَ إِنَّكُمْ تَقُولُونَ إِنَّ أَبَا هُرَيْرَةَ يُكْثِرُ الْحَدِيثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ حَدِيثِهِمْ","trj":"Berkata [Ibnu Syihab]; dan berkata [Ibnu Al Musayyab] bahwa [Abu Hurairah] pernah berkata; 'Orang-orang mengatakan bahwasanya Abu Hurairah banyak meriwayatkan hadits. Allah Subhanahu wa Ta'ala memberinya kesempatan bersama Rasulullah Shallallahu'alaihiwasallam.' Orang-orang berkata; 'Mengapa orang-orang Muhajirin dan Anshar tidak meniwayatkan hadits sebanyak riwayat Abu Hurairah?\" Saya (Abu Hurairah) akan memberitahu kalian tentang hal ini: Saudara-saudara saya dan kaum Anshar sibuk bertani dan saudara-saudara saya dan kaum Muhajirin sibuk berjual beli di pasar. Sementara saya senantiasa menyertai Rasulullah shallallahu 'alaihi wasallam, hingga saya lebih banyak mendengar sabda beliau. Saya hadir ketika mereka, para sahabat dari kaum Anshar dan Muhajirin, tidak hadir dan saya hapal ketika mereka lupa.\" Pada suatu hari, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah di antara kalian yang sudi membentangkan bajunya untuk menampung sabdaku ini? Setelah itu, ia tempelkan bajunya itu ke dadanya, karena dengan begitu ia tidak akan pernah melupakan satu hadits pun yang pernah ia dengar dariku.\" Mendengar pernyataan Rasulullah itu, maka saya bentangkan kain selendang saya hingga Rasulullah selesai bersabda, Kemudian saya tempelkan selendang tersebut ke dada saya. Semenjak itu, saya tidak pernah melupakan satu hadits pun yang beliau sabdakan kepada saya. Seandainya tidak ada dua ayat Al Qur an yang diturunkan Allah, tentu saya tidak akan pernah menyampaikan satu hadits pun yang pernah saya dengar. Kedua ayat tersebut adalah: 'Sesungguhnya orang-orang yang menyembunyikan apa yang telah Kami turunkan berupa keterangan-keterangan yang jelas dan petunjuk setelah Kami menerangkannya kepada manusia dalam Al Qur'an, maka, mereka itu akan dilaknat Allah dan dilaknat pula oleh semua makhluk yang bisa melaknat, kecuali mereka yang bertaubat dan mengadakan perbaikan serta menerangkan kebenaran, maka terhadap mereka itulah aku menerima taubatnya dan Aku Maha Penerima taubat lagi Maha penyayang' (QS. Albaqarah 159). Dan telah menceritakan kepada kami ['Abdullah bin 'Abdur Rahman Ad Darimi]; Telah mengabarkan kepada kami [Abu Yaman] dari [Syu'aib] dari [Az Zuhri]; Telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdur Rahman] bahwa [Abu Hurairah] berkata; Sesungguhnya kalian mengatakan, mengapa Abu Hurairah banyak mengafal Hadits dari Rasulullah shallallahu 'alaihi wasallam..dan seterusnya dengan Hadits yang serupa."},{"p":"Muslim","n":4631,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا سُلَيْمَانُ وَهُوَ ابْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ مِنَّا رَجُلٌ مِنْ بَنِي النَّجَّارِ قَدْ قَرَأَ الْبَقَرَةَ وَآلَ عِمْرَانَ وَكَانَ يَكْتُبُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَ هَارِبًا حَتَّى لَحِقَ بِأَهْلِ الْكِتَابِ قَالَ فَرَفَعُوهُ قَالُوا هَذَا قَدْ كَانَ يَكْتُبُ لِمُحَمَّدٍ فَأُعْجِبُوا بِهِ فَمَا لَبِثَ أَنْ قَصَمَ اللَّهُ عُنُقَهُ فِيهِمْ فَحَفَرُوا لَهُ فَوَارَوْهُ فَأَصْبَحَتْ الْأَرْضُ قَدْ نَبَذَتْهُ عَلَى وَجْهِهَا ثُمَّ عَادُوا فَحَفَرُوا لَهُ فَوَارَوْهُ فَأَصْبَحَتْ الْأَرْضُ قَدْ نَبَذَتْهُ عَلَى وَجْهِهَا ثُمَّ عَادُوا فَحَفَرُوا لَهُ فَوَارَوْهُ فَأَصْبَحَتْ الْأَرْضُ قَدْ نَبَذَتْهُ عَلَى وَجْهِهَا فَتَرَكُوهُ مَنْبُوذًا","trj":"Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu An Nadhr] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas bin Malik] dia berkata; \"Dulu ada seorang sahabat laki-laki dari Bani Najjar. Sahabat tersebut telah menghafal surah Al Baqarah dan surah Ali Imran. Selain itu, ia juga pernah menjadi juru tulis Rasulullah shallallahu 'alaihi wasallam. Hingga pada suatu hari ia melarikan diri dan bergabung dengan Ahli Kitab.\" Anas berkata; 'Ternyata orang-orang Ahli Kitab memuliakan dan menghormatinya. Mereka berkata; 'Sesungguhnya orang laki-laki ini pernah menjadi juru tulis Muhammad.' Maka semakin tambah hormatnya mereka kepada orang laki-laki itu. Tak lama kemudian, orang itu meninggal dunia di tengah-tengah orang-orang Ahli Kitab. Lalu mereka menggali tanah untuk menguburkannya. Tetapi kemudian, bumi malah memuntahkan mayatnya ke atas. Mereka menggali tanah lagi untuk menguburkannya. Tetapi kemudian bumi malah memuntahkan mayatnya ke atas. Mereka menggali tanah lagi untuk menguburkannya. Tetapi kemudian bumi malah memuntahkan mayatnya ke atas, hingga mereka membiarkannya tergeletak."},{"p":"Nasa'i","n":285,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِثٍ عَنْ أَنَسٍقَالَ كَانَتْ الْيَهُودُ إِذَا حَاضَتْ الْمَرْأَةُ مِنْهُمْ لَمْ يُؤَاكِلُوهُنَّ وَلَمْ يُشَارِبُوهُنَّ وَلَمْ يُجَامِعُوهُنَّ فِي الْبُيُوتِ فَسَأَلُوا نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى }الْآيَةَ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُؤَاكِلُوهُنَّ وَيُشَارِبُوهُنَّ وَيُجَامِعُوهُنَّ فِي الْبُيُوتِ وَأَنْ يَصْنَعُوا بِهِنَّ كُلَّ شَيْءٍ مَا خَلَا الْجِمَاعَ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Sulaiman bin Harb] dia berkata; Telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] dia berkata; Bahwa orang Yahudi apabila ada istri mereka sedang haid, maka mereka tidak mengajak makan bersama, tidak mempergaulinya, dan tidak berkumpul bersamanya di rumah. Mereka bertanya kepada Nabi Allah shallallahu 'alaihi wasallam tentang hal itu? Lalu Allah Azza wa Jalla menurunkan ayat \" Mereka bertanya kepadamu tentang haid. Katakanlah, (Hai Muhammad) bahwa itu adalah penyakit… (Qs. Al-Baqarah (2): 222) lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan mereka untuk ikut makan bersama, mempergaulinya, berkumpul dengan mereka di rumah, dan untuk berbuat apa saja selain bersetubuh. "},{"p":"Nasa'i","n":446,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا أُسْرِيَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتُهِيَ بِهِ إِلَى سِدْرَةِ الْمُنْتَهَى وَهِيَ فِي السَّمَاءِ السَّادِسَةِ وَإِلَيْهَا يَنْتَهِي مَا عُرِجَ بِهِ مِنْ تَحْتِهَا وَإِلَيْهَا يَنْتَهِي مَا أُهْبِطَ بِهِ مِنْ فَوْقِهَا حَتَّى يُقْبَضَ مِنْهَا قَالَ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ فَرَاشٌ مِنْ ذَهَبٍ فَأُعْطِيَ ثَلَاثًا الصَّلَوَاتُ الْخَمْسُ وَخَوَاتِيمُ سُورَةِ الْبَقَرَةِ وَيُغْفَرُ لِمَنْ مَاتَ مِنْ أُمَّتِهِ لَا يُشْرِكُ بِاللَّهِ شَيْئًا الْمُقْحِمَاتُ","trj":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Yahya bin Adam] dia berkata; Telah menceritakan kepada kami [Malik bin Mighwal] dari [Zubair bin 'Adi] dari [Thalhah bin Musharrif] dari [Murrah] dari [Abdulah] dia berkata; \" Ketika Rasulullah shallallahu 'alaihi wasallam diisra'kan beliau sampai ke Sidratul Muntaha, yaitu satu tempat di langit yang ke enam dan sampai di situlah berakhirnya semua yang naik dari bawah dan sampai di situ pula semua yang turun dari atas hingga dapat terpegang. Nabi shallallahu 'alaihi wasallam kemudian membacakan ayat: \"Ketika Sidratul Muntaha diliputi oleh sesuatu yang meliputinya\" (Qs. An-Najm (53): 16) Rasulullah shallallahu 'alaihi wasallam bersabda: \" (Yang meliputi Sidratul Muntaha) adalah kupu-kupu dari emas, lalu aku diberi tiga hal, yaitu shalat lima waktu, akhir-akhir surat Al Baqarah, dan orang yang mati dari umatku diampuni, asalkan tidak menyekutukan Allah Azza Wa Jalla dengan sesuatupun.\" "},{"p":"Nasa'i","n":825,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُكَانَ مُعَاذٌ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَرْجِعُ إِلَى قَوْمِهِ يَؤُمُّهُمْ فَأَخَّرَ ذَاتَ لَيْلَةٍ الصَّلَاةَ وَصَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ رَجَعَ إِلَى قَوْمِهِ يَؤُمُّهُمْ فَقَرَأَ سُورَةَ الْبَقَرَةِ فَلَمَّا سَمِعَ رَجُلٌ مِنْ الْقَوْمِ تَأَخَّرَ فَصَلَّى ثُمَّ خَرَجَ فَقَالُوا نَافَقْتَ يَا فُلَانُ فَقَالَ وَاللَّهِ مَا نَافَقْتُ وَلَآتِيَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُخْبِرُهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ مُعَاذًا يُصَلِّي مَعَكَ ثُمَّ يَأْتِينَا فَيَؤُمُّنَا وَإِنَّكَ أَخَّرْتَ الصَّلَاةَ الْبَارِحَةَ فَصَلَّى مَعَكَ ثُمَّ رَجَعَ فَأَمَّنَا فَاسْتَفْتَحَ بِسُورَةِ الْبَقَرَةِ فَلَمَّا سَمِعْتُ ذَلِكَ تَأَخَّرْتُ فَصَلَّيْتُ وَإِنَّمَا نَحْنُ أَصْحَابُ نَوَاضِحَ نَعْمَلُ بِأَيْدِينَا فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ اقْرَأْ بِسُورَةِ كَذَا وَسُورَةِ كَذَا","trj":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr] dia berkata; aku mendengar [Jabir bin Abdullah] dia berkata; \"Mua'dz shalat bersama Nabi Shallallahu'alihiwasallam, kemudian ia kembali kepada kaumnya dan mengimami shalat mereka di malam hari dan ia (Mua'dz) memanjangkan shalatnya. Kemudian Muadz shalat bersama Rasulullah, lalu ia kembali kepada kaumnya dan mengimami shalat mereka, dan ia membaca surat Al Baqarah. Ketika salah seorang kaumnya mendengar Muadz lama dalam shalat, ia keluar dari shalat dan shalat sendiri, maka kaumnya berkata kepadanya, 'Kamu munafik wahai fulan'. Orang itu menjawab, 'Demi Allah, aku tidak munafik. Aku akan mendatangi dan menceritakan hal ini pada Nabi Shallallahu'alihiwasallam. Lalu orang itu mendatangi Nabi Shallallahu'alaihi wasallam dan berkata, 'Wahai Rasulullah, Muadz shalat bersama Anda. kemudian ia kembali dan mengimami shalat kami. Anda melamakan shalat kemarin malam, lalu Muadz shalat dengan Anda, kemudian dia kembali dan mengimami kami, dan ia memulai shalat dengan membaca surat Albaqarah. Ketika aku mendengarnya membaca surat Albaqarah. maka aku mundur dan shalat sendiri, karena kami pekerja keras yang bekerja dengan tangan kami. Rasulullah Shallallahu'alaihi wasallam lalu bersabda, 'Wahai Muadz, apakah kamu ingin menimbulkan fitnah? Bacalah surat ini dan surat ini (maksudnya surat yang pendek) '.\""},{"p":"Nasa'i","n":902,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَمَّارِ بْنِ رُزَيْقٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ جِبْرِيلُ عَلَيْهِ السَّلَام إِذْ سَمِعَ نَقِيضًا فَوْقَهُ فَرَفَعَ جِبْرِيلُ عَلَيْهِ السَّلَام بَصَرَهُ إِلَى السَّمَاءِ فَقَالَ هَذَا بَابٌ قَدْ فُتِحَ مِنْ السَّمَاءِ مَا فُتِحَ قَطُّ قَالَ فَنَزَلَ مِنْهُ مَلَكٌ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبْشِرْ بِنُورَيْنِ أُوتِيتَهُمَا لَمْ يُؤْتَهُمَا نَبِيٌّ قَبْلَكَ فَاتِحَةِ الْكِتَابِ وَخَوَاتِيمِ سُورَةِ الْبَقَرَةِ لَمْ تَقْرَأْ حَرْفًا مِنْهُمَا إِلَّا أُعْطِيتَهُ","trj":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak Al Mukharrimi] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari ['Ammar bin Ruzaiq] dari [Abdullah bin 'Isa] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; \"Tatkala Rasulullah Shallallallahu'alaihi wasallam bersama malaikat Jibril, tiba-tiba beliau mendengar suara dari atasnya, maka Jibril mengangkat pandangannya ke langit, kemudian berkata, 'Pintu ini telah dibuka dari langit, yang sebelumnya belum pernah dibuka'.\" Ibnu Abbasn berkata; \"Lalu turun malaikat dan datang kepada Nabi Shallallahu'alaihi wasallam, lantas berkata. 'Berbahagialah dengan dua cahaya yang diberikan kepadamu, dan dua cahaya tersebut belum pernah diberikan kepada seorang nabi shallallahu 'alaihi wasallam pun sebelummu, yakni: Fatihah Al Kitab dan akhir surat Al Baqarah. Kamu tidak membaca satu hurufpun dari keduanya kecuali kamu pasti akan diberi'.\""},{"p":"Nasa'i","n":933,"ar":"أَخْبَرَنِي عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا الْآيَةَ الَّتِي فِي الْبَقَرَةِ{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }إِلَى آخِرِ الْآيَةِ وَفِي الْأُخْرَى{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] dia berkata; Telah menceritakan kepada kami [Utsman bin Hakim] dia berkata; Telah mengabarkan kepadaku [Sa'id bin Yasar] bahwa [Ibnu Abbas] Telah mengabarkan kepadanya, Rasulullah Shallallallahu'alaihi wasallam membaca (ayat) pada dua rakaat shalat Subuh. Pada rakaat pertama beliau membaca ayat dalam surat Al Baqarah, \"Katakanlah (Hai orang-orang mukmin), 'Kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" (Qs. Al Baqarah (2): 136) sampai akhir ayat tersebut, sedangkan pada rakaat kedua beliau membaca, \"Kami telah beriman dan saksikanlah (wahai rasul) bahwa sesungguhnya kami adalah orang-orang yang patut (kepada seruanmu) (Qs. Al Maa'idah (5): 111).\""},{"p":"Nasa'i","n":972,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرٍ قَالَمَرَّ رَجُلٌ مِنْ الْأَنْصَارِ بِنَاضِحَيْنِ عَلَى مُعَاذٍ وَهُوَ يُصَلِّي الْمَغْرِبَ فَافْتَتَحَ بِسُورَةِ الْبَقَرَةِ فَصَلَّى الرَّجُلُ ثُمَّ ذَهَبَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَفَتَّانٌ يَا مُعَاذُ أَفَتَّانٌ يَا مُعَاذُ أَلَّا قَرَأْتَ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَالشَّمْسِ وَضُحَاهَا وَنَحْوِهِمَا","trj":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Muharib bin Ditsar] dari [Jabir] dia berkata; \"Ada seorang laki-laki Anshar melewati Mu'adz dengan membawa dua tempat minum unta, padahal Mu'adz sedang shalat Maghrib. Dia memulai shalat Maghrib dengan membaca surat Al Baqarah. Laki-laki tersebut shalat kemudian pergi, dan hal tersebut sampai kepada Rasulullah Shallallahu'alaihi wasallam, maka beliau Shallallallahu'alaihi wasallam lalu bersabda; ' Wahai Mu'adz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? Wahai Mu'adz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? Kenapa kamu tidak mau membaca Sabbihisma rabbikal a'laa (Qs. Al A'laa) dan Wasysamsi wadluhaha (Qs. Asy-Syamsy), atau yang sejenisnya? '"},{"p":"Nasa'i","n":997,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ الْعَلَاءِ بْنِ الْمُسَيَّبِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ طَلْحَةَ بْنِ يَزِيدَ عَنْ حُذَيْفَةَ وَالْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ الْبَقَرَةَ وَآلَ عِمْرَانَ وَالنِّسَاءَ فِي رَكْعَةٍ لَا يَمُرُّ بِآيَةِ رَحْمَةٍ إِلَّا سَأَلَ وَلَا بِآيَةِ عَذَابٍ إِلَّا اسْتَجَارَ","trj":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari [Hafsh bin ghiyats] dari [Al A'la bin Al Musayyab] dari [Amr bin Murrah] dari [Thalhah bin Yazid] dari [Hudzaifah] dan [Al A'masy] dari [Sa'd bin Ubaidah] dari [Al Mustawrid Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] bahwa Nabi Shallallallahu'alaihi wasallam pernah membaca surat Al Baqarah, Ali 'Imraan, dan An-Nisaa' dalam satu rakaat. Beliau Shallallallahu'alaihi wasallam tidak melewati (membaca) ayat yang berkenaan dengan rahmat kecuali beliau berdoa, dan tidak melewati (membaca) ayat yang berkenaan dengan adzab kecuali beliau memohon perlindungan kepada-Nya. "},{"p":"Nasa'i","n":1037,"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ يَعْنِي النَّسَائِيَّ قَالَ حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ مُعَاوِيَةَ يَعْنِي ابْنَ صَالِحٍ عَنْ ابْنِ قَيْسٍ الْكِنْدِيِّ وَهُوَ عَمْرُو بْنُ قَيْسٍ قَالَ سَمِعْتُ عَاصِمَ بْنَ حُمَيْدٍ قَالَ سَمِعْتُ عَوْفَ بْنَ مَالِكٍ يَقُولُقُمْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَلَمَّا رَكَعَ مَكَثَ قَدْرَ سُورَةِ الْبَقَرَةِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ","trj":"Telah mengabarkan kepada kami ['Amr bin Manshur An Nasaai] dia berkata; telah menceritakan kepada kami [Adam bin Abu Iyas] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Mu'awiyah bin Shalih] dari ['Amru bin Qais Al Kindi] dia berkata; aku mendengar ['Ashim bin Humaid] berkata; aku mendengar ['Auf bin Malik] berkata; \"Suatu malam aku pernah shalat bersama Rasulullah Shallallahu'alaihi wasallam, dan ketika ruku' beliau berdiam seukuran seseorang membaca surat Al Baqarah. Saat ruku' beliau membaca, 'Subhaana dzil jabaruuti wal malaakuti wal kibriyaai wal 'adzamati (Maha Suci Dzat yang mempunyai hak memaksa dan kekuasaan, serta yang memiliki kesombongan dan keagungan) '.\""},{"p":"Nasa'i","n":1115,"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ سَوَّارٍ قَالَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَمْرِو بْنِ قَيْسٍ الْكِنْدِيِّ أَنَّهُ سَمِعَ عَاصِمَ بْنَ حُمَيْدٍ يَقُولُ سَمِعْتُ عَوْفَ بْنَ مَالِكٍ يَقُولُقُمْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَدَأَ فَاسْتَاكَ وَتَوَضَّأَ ثُمَّ قَامَ فَصَلَّى فَبَدَأَ فَاسْتَفْتَحَ مِنْ الْبَقَرَةِ لَا يَمُرُّ بِآيَةِ رَحْمَةٍ إِلَّا وَقَفَ وَسَأَلَ وَلَا يَمُرُّ بِآيَةِ عَذَابٍ إِلَّا وَقَفَ يَتَعَوَّذُ ثُمَّ رَكَعَ فَمَكَثَ رَاكِعًا بِقَدْرِ قِيَامِهِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ سَجَدَ بِقَدْرِ رُكُوعِهِ يَقُولُ فِي سُجُودِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ قَرَأَ آلَ عِمْرَانَ ثُمَّ سُورَةً ثُمَّ سُورَةً فَعَلَ مِثْلَ ذَلِكَ","trj":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Al Hasan bin Sawwar] dia berkata; telah menceritakan kepada kami [Laits bin Sa'ad] dari [Mu'awiyah bin Shalih] dari ['Amr bin Qais Al Kindi] bahwasanya dia mendengan ['Ashim bin Humaid] berkata; aku mendengar ['Auf bin Malik] berkata; \"Aku pernah bangun bersama Nabi Shallallahu'alaihi wasallam, lalu beliau mulai bersiwak dan berwudhu. Kemudian beliau berdiri dan shalat. Beliau mengawali shalatnya dengan membaca surat Al Baqarah. Beliau tidak melewati ayat tentang rahmat kecuali beliau berhenti dan memohon (rahmat). Beliau juga tidak melewati ayat tentang adzab kecuali beliau berhenti dan berlindung darinya. Kemudian beliau ruku' hingga ia tenang dalam keadaan ruku' seukuran berdirinya, sambil membaca: 'Subhana dzil jabaruuti wal malakuuti wal kibriyaai wal 'adzamati (Maha Suci Dzat yang mempunyai hak memaksa dan kekuasaan, serta yang memiliki kesombongan dan keagungan) ' saat ruku'. Lantas beliau Shallallahu'alaihiwasallam sujud seukuran ruku'nya tadi dengan membaca: 'Subhana dzil jabaruuti wal malakuuti wal kibriyaai wal 'adzamati'. Kemudian beliau membaca surat Ali 'Imran, kemudian surat lainnya, dan beliau juga melakukan hal yang sama - di rakaat berikutnya -.\" "},{"p":"Nasa'i","n":1116,"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَاسْتَفْتَحَ بِسُورَةِ الْبَقَرَةِ فَقَرَأَ بِمِائَةِ آيَةٍ لَمْ يَرْكَعْ فَمَضَى قُلْتُ يَخْتِمُهَا فِي الرَّكْعَتَيْنِ فَمَضَى قُلْتُ يَخْتِمُهَا ثُمَّ يَرْكَعُ فَمَضَى حَتَّى قَرَأَ سُورَةَ النِّسَاءِ ثُمَّ قَرَأَ سُورَةَ آلِ عِمْرَانَ ثُمَّ رَكَعَ نَحْوًا مِنْ قِيَامِهِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ سُبْحَانَ رَبِّيَ الْعَظِيمِ سُبْحَانَ رَبِّيَ الْعَظِيمِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا لَكَ الْحَمْدُ وَأَطَالَ الْقِيَامَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ يَقُولُ فِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى سُبْحَانَ رَبِّيَ الْأَعْلَى سُبْحَانَ رَبِّيَ الْأَعْلَى لَا يَمُرُّ بِآيَةِ تَخْوِيفٍ أَوْ تَعْظِيمٍ لِلَّهِ عَزَّ وَجَلَّ إِلَّا ذَكَرَهُ","trj":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Al A'masy] dari [Sa'ad bin 'Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] dia berkata; \"Pada suatu malam aku mengerjakan shalat bersama Rasulullah Shallallahu'alaihiwasallam, beliau mulai dengan membaca surat Al Baqarah. Beliau telah membaca seratus ayat dan belum ruku lalu tetap membacanya.\" Hudzaifah berkata; \"Beliau menyelesaikannya pada dua rakaat, lantas berlalu.\" Hudzaifah berkata lagi; \"Beliau menyelesaikannya kemudian ruku' dan terus berlalu hinggga beliau membaca surat An-Nisaa', kemudian membaca surat Ali 'Imraan, lalu ruku' yang lamanya seperti berdiri. Saat ruku' beliau mengucapkan, 'Subhana rabbiyal 'adzimi, subhana rabbiyal 'adzimi, subhana rabbiyal 'adzimi (Maha suci Tuhan-ku yang Maha Agung) '. Lalu beliau mengangkat kepala sambil mengucapkan, 'Sami'allahu liman hamidah rabbana lakal hamdu (Allah Maha mendengar orang yang memuji-Nya, segala puji untuk-Mu) '. Beliau memperpanjang berdirinya kemudian sujud, dan beliau memperlama sujudnya sambil mengucapkan, 'Subhana rabbiyal a'laa, subhana rabbiyal a'laa, subhana rabbiyal a'laa (Maha Suci Tuhanku yang Maha Tinggi) '. Beliau Shallallahu'alaihiwasallam tidak melalui ayat ancaman atau pengagungan Allah Azza wa Jalla kecuali beliau Shallallahu'alaihiwasallam berdzikir kepada-Nya.\""},{"p":"Nasa'i","n":1199,"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ قَالَ حَدَّثَنِي الْحَارِثُ بْنُ شُبَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكَانَ الرَّجُلُ يُكَلِّمُ صَاحِبَهُ فِي الصَّلَاةِ بِالْحَاجَةِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نَزَلَتْ هَذِهِ الْآيَةُ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَقُومُوا لِلَّهِ قَانِتِينَ }فَأُمِرْنَا بِالسُّكُوتِ","trj":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dia berkata; telah menceritakan kepada kami [Al Harits bin Syubail] dari [Abu 'Amr Asy Syaibani] dari [Zaid bin Arqam] dia berkata; \"Pada masa Rasulullah Shalallah 'Alaihi Wa Sallam ada seorang laki-laki yang berbicara dalam shalat dengan temannya untuk suatu keperluan, lalu turunlah ayat ini, 'Peliharalah segala shalat(mu), dan (peliharalah) shalat wustha. Berdirilah karena Allah (dalam shalatmu) dengan khusyu'. (Qs. Al Baqarah (2): 238) Lalu kami disuruh diam (saat) shalat.\""},{"p":"Nasa'i","n":1454,"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو حَفْصَةَ مَوْلَى عَائِشَةَ أَنَّ عَائِشَةَ أَخْبَرَتْهُ أَنَّهُلَمَّا كَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَأَمَرَ فَنُودِيَ أَنَّ الصَّلَاةَ جَامِعَةٌ فَقَامَ فَأَطَالَ الْقِيَامَ فِي صَلَاتِهِ قَالَتْ عَائِشَةُ فَحَسِبْتُ قَرَأَ سُورَةَ الْبَقَرَةِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَامَ مِثْلَ مَا قَامَ وَلَمْ يَسْجُدْ ثُمَّ رَكَعَ فَسَجَدَ ثُمَّ قَامَ فَصَنَعَ مِثْلَ مَا صَنَعَ رَكْعَتَيْنِ وَسَجْدَةً ثُمَّ جَلَسَ وَجُلِّيَ عَنْ الشَّمْسِ","trj":"Telah mengabarkan kepada kami [Abu Bakr bin Ishaq] dia berkata; Telah menceritakan kepada kami [Abu Zaid Sa'id bin Ar-Rabi'] dia berkata; Telah menceritakan kepada kami ['Ali bin Al Mubarak] dari [Yahya bin Abu Katsir] dia berkata; Telah menceritakan kepadaku [Abu Hafshah] -budak 'Aisyah- bahwasanya ['Aisyah] mengabarkan kepadanya bahwa pada masa Rasulullah shallallahu 'alaihi wasallam terjadi gerhana matahari, maka beliau berwudlu lalu memerintahkan untuk menyeru, 'Ash-Shalatul Jami'ah'. Lalu beliau berdiri dan memperlama berdirinya saat shalat.\" Kemudian Aisyah berkata; 'Aku memperkirakan beliau membaca surah Al-Baqarah, kemudian beliau ruku' dengan ruku' yang lama, lalu mengucapakan Sami' Allahu Liman Hamidah. Kemudian beliau berdiri seperti berdirinya semula tanpa sujud, lalu ruku' lagi dan sujud lagi. Kemudian berdiri dan berbuat seperti yang diperbuat pada dua ruku' dan satu kali sujud yang pertama. Lantas beliau duduk, sedangkan matahari telah terang.'"},{"p":"Nasa'i","n":1460,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَخَسَفَتْ الشَّمْسُ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَامَ قِيَامًا طَوِيلًا قَرَأَ نَحْوًا مِنْ سُورَةِ الْبَقَرَةِ قَالَ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَاذْكُرُوا اللَّهَ عَزَّ وَجَلَّ قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ هَذَا ثُمَّ رَأَيْنَاكَ تَكَعْكَعْتَ قَالَ إِنِّي رَأَيْتُ الْجَنَّةَ أَوْ أُرِيتُ الْجَنَّةَ فَتَنَاوَلْتُ مِنْهَا عُنْقُودًا وَلَوْ أَخَذْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا وَرَأَيْتُ النَّارَ فَلَمْ أَرَ كَالْيَوْمِ مَنْظَرًا قَطُّ وَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ قَالُوا لِمَ يَا رَسُولَ اللَّهِ قَالَ بِكُفْرِهِنَّ قِيلَ يَكْفُرْنَ بِاللَّهِ قَالَ يَكْفُرْنَ الْعَشِيرَ وَيَكْفُرْنَ الْإِحْسَانَ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّ","trj":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; Telah menceritakan kepada kami [Ibnul Qasim] dari [Malik] dia berkata; Telah menceritakan kepadaku [Zaid bin Aslam] dari ['Atha bin Yasar] dari ['Abdullah bin 'Abbas] dia berkata; \"Telah terjadi gerhana matahari, maka Rasulullah shallallahu 'alaihi wasallam shalat bersama orang-orang. Beliau berdiri lama dengan membaca surat yang sepadan dengan surah Al Baqarah.\" Kemudian Abdullah berkata lagi; 'Kemudian beliau ruku' dengan ruku' yang lama, lalu mengangkat kepalanya dan berdiri (lagi), tapi lebih singkat dari yang pertama. Kemudian ruku' dengan ruku' yang lama tapi lebih singkat dari ruku' yang pertama. Lalu beliau mengangkat (kepalanya) dan berdiri lagi dengan lama, namun lebih singkat dari yang pertama. Kemudian beliau ruku' dengan ruku' yang lama, namun lebih singkat dari ruku' yang pertama. Lalu beliau sujud dan pergi sedangkan matahari telah terang. Setelah itu beliau shallallahu 'alaihi wasallam bersabda: 'Matahari dan Bulan adalah dua tanda diantara tanda-tanda kebesaran Allah Ta'ala. Keduanya tidak mengalami gerhana karena kematian atau kelahiran seseorang. Jika kalian melihat gerhana tersebut, maka berdzikirlah kepada Allah Azza Wa Jalla.' Para sahabat berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, kami melihat engkau menggapai sesuatu pada posisimu ini, kemudian kami melihatmu juga mundur? ' Beliau bersabda: 'Aku melihat surga -atau diperlihatkan kepadaku surga. Seandainya aku mengambil sesuatu dari surga, maka kamu pasti akan memakannya, lalu tak akan tersisa lagi dunia ini. Aku juga melihat neraka. Aku belum melihat pandangan yang lebih menakutkan dari ini dan aku melihat kebanyakan penghuninya adalah wanita.' Para sahabat berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, kenapa bisa begitu? ' Beliau menjawab: 'Karena kekufuran mereka'. -Dalam riwayat lain: Karena mereka kufur kepada Allah? - Beliau meneruskan lagi: 'Mereka juga kufur terhadap kebaikan suami dan kufur terhadap kebaikan. Seandainya kamu berbuat baik kepada salah seorang dari mereka (wanita) sepanjang masa, Lalu dia melihat suatu (keburukan) pada dirimu', Maka dia akan berkata: 'Aku tidak melihat suatu kebaikanpun pada dirimu! '"},{"p":"Nasa'i","n":1614,"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَافْتَتَحَ الْبَقَرَةَ فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَةِ فَمَضَى فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَتَيْنِ فَمَضَى فَقُلْتُ يُصَلِّي بِهَا فِي رَكْعَةٍ فَمَضَى فَافْتَتَحَ النِّسَاءَ فَقَرَأَهَا ثُمَّ افْتَتَحَ آلَ عِمْرَانَ فَقَرَأَهَا يَقْرَأُ مُتَرَسِّلًا إِذَا مَرَّ بِآيَةٍ فِيهَا تَسْبِيحٌ سَبَّحَ وَإِذَا مَرَّ بِسُؤَالٍ سَأَلَ وَإِذَا مَرَّ بِتَعَوُّذٍ تَعَوَّذَ ثُمَّ رَكَعَ فَقَالَ سُبْحَانَ رَبِّيَ الْعَظِيمِ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَكَانَ قِيَامُهُ قَرِيبًا مِنْ رُكُوعِهِ ثُمَّ سَجَدَ فَجَعَلَ يَقُولُ سُبْحَانَ رَبِّيَ الْأَعْلَى فَكَانَ سُجُودُهُ قَرِيبًا مِنْ رُكُوعِهِ","trj":"Telah mengabarkan kepada kami [Al Husain bin Manshur] dia berkata; telah menceritakan kepada kami ['Abdullah bin Numair] dia berkata; telah menceritakan kepada kami [Al A'masy] dari [Sa'd bin 'Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] dia berkata; \"Aku pernah shalat dengan Rasulullah shallallahu 'alaihi wasallam pada suatu malam, beliau memulainya dengan membaca surah Al Baqarah. Lalu aku berkata dalam hatiku; -Mungkin- beliau akan ruku' pada ayat ke seratus. Namun beliau malah meneruskannya'. Aku berkata dalam hatiku, '-Mungkin- beliau akan ruku' saat dua ratus ayat, namun beliau malah meneruskannya'. Aku berkata dalam hatiku, 'Beliau shalat dengan surat Al Baqarah dalam satu rakaat. Kemudian beliau meneruskan (shalatnya), dan memulainya dengan membaca surah An Nisaa'. Beliau membacanya (hingga selesai), kemudian memulai lagi dengan surah Ali 'Imraan, dan beliau membacanya (hingga selesai) dengan perlahan-perlahan. Jika beliau menjumpai ayat tasbih maka beliau bertasbih (memuji Allah), jika beliau menjumpai ayat yang menganjurkan untuk meminta maka beliau pun meminta (kepada Allah), dan jika beliau menjumpai ayat yang berkenaan dengan memohon perlindungan maka beliau memohon perlindungan. Kemudian beliau ruku dengan membaca subhana rabbiyal 'azhimi (Maha Suci Tuhanku yang Maha Agung), yang (karenanya) ruku beliau sama dengan (lamanya) berdiri. Kemudian beliau mengangkat kepalanya, lalu mengucapkan Sami'allahu liman Hamidah (Allah Maha Mendengar orang yang memuji-Nya). Dan (lamanya) berdiri beliau sama dengan (lamanya) beliau ruku'. Kemudian beliau sujud dengan membaca subhana rabbiyal a'laa (Maha Suci Tuhanku Yang Maha Tinggi). Sujud beliau sama dengan (lamanya) ruku' beliau.\""},{"p":"Nasa'i","n":2095,"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ تَعَالَى{ حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }قَالَ هُوَ سَوَادُ اللَّيْلِ وَبَيَاضُ النَّهَارِ","trj":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Jarir] dari [Mutharrif] dari [Asy Sya'bi] dari ['Adi bin Hatim] bahwa ia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang firman Allah Ta'ala: \" Hingga terang bagimu benang putih dan benang hitam.\" (Qs. Al Baqarah 2: 187) Beliau bersabda: \"Yaitu hitamnya malam dan putihnya siang.\""},{"p":"Nasa'i","n":2905,"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ فِي حَدِيثِهِ عَنْ أَبِي الْأَحْوَصِ عَنْ حُصَيْنٍ عَنْ كَثِيرٍ وَهُوَ ابْنُ مُدْرِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ قَالَ ابْنُ مَسْعُودٍ وَنَحْنُ بِجَمْعٍسَمِعْتُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ يَقُولُ فِي هَذَا الْمَكَانِ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ","trj":"Telah mengabarkan kepada kami [Hannad bin As Sari] dalam haditsnya dari [Abu Al Ahwash] dari [Hushain] dari [Katsir yaitu Ibnu Mudrik] dari [Abdur Rahman bin Yazid], ia berkata; [Ibnu Mas'ud] berkata sedang kami berada di Muzdalifah; saya telah mendengar orang yang kepadanya diturunkan Surat Al Baqarah mengucapkan di tempat ini: LABBAIKALLAAHUMMA LABBAIK.\""},{"p":"Nasa'i","n":2929,"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي مُحَيَّاةَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَبْدِ الرَّحْمَنِ يَعْنِي ابْنَ يَزِيدَ قَالَقِيلَ لِعَبْدِ اللَّهِ بْنِ مَسْعُودٍ إِنَّ نَاسًا يَرْمُونَ الْجَمْرَةَ مِنْ فَوْقِ الْعَقَبَةِ قَالَ فَرَمَى عَبْدُ اللَّهِ مِنْ بَطْنِ الْوَادِي ثُمَّ قَالَ مِنْ هَا هُنَا وَالَّذِي لَا إِلَهَ غَيْرُهُ رَمَى الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","trj":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Muhayyah] dari [Salamah bin Kuhail] dari [Abdur Rahman yaitu Ibnu Yazid], ia berkata; dikatakan kepada Abdullah bin Mas'ud; Ada orang-orang yang melempar jumrah dari atas Aqabah. Abdur Rahman berkata; lalu [Abdullah bin Mas'ud] melempar dari tengah bukit kemudian berkata; demi Dzat yang tidak ada tuhan yang berhak disembah selainnya, orang yang diturunkan kepadanya Surat Al Baqarah pernah melempar dari sini. "},{"p":"Nasa'i","n":2930,"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ وَمَالِكُ بْنُ الْخَلِيلِ قَالَا حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ الْحَكَمِ وَمَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَرَمَى عَبْدُ اللَّهِ الْجَمْرَةَ بِسَبْعِ حَصَيَاتٍ جَعَلَ الْبَيْتَ عَنْ يَسَارِهِ وَعَرَفَةَ عَنْ يَمِينِهِ وَقَالَ هَا هُنَا مَقَامِ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِقَالَ أَبُو عَبْد الرَّحْمَنِ مَا أَعْلَمُ أَحَدًا قَالَ فِي هَذَا الْحَدِيثِ مَنْصُورٌ غَيْرَ ابْنِ أَبِي عَدِيٍّ وَاللَّهُ تَعَالَى أَعْلَمُ","trj":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad Az Za'farani] dan [Malik bin Al Khalil] mereka berkata; telah menceritakan kepada kami [Ibnu Abi Adi] dari [Syu'bah] dari [Al Hakam] dan [Manshur] dari [Ibrahim] dari [Abdur Rahman bin Yazid], ia berkata; [Abdullah] telah melempar jumrah dengan tujuh kerikil, ia menjadikan Ka'bah di sebelah kirinya dan Arafah di sebelah kanannya, dan ia berkata; di sinilah tempat berdiri orang yang diturunkan kepadanya Surat Al Baqarah. Abu Abdur Rahman berkata; saya tidak mengetahui seorangpun yang berbicara mengenai hadis ini. Manshur bukanlah Ibnu Abi Adi, wallahu ta'ala a'lam."},{"p":"Nasa'i","n":2931,"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى عَنْ هُشَيْمٍ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ قَالَرَأَيْتُ ابْنَ مَسْعُودٍ رَمَى جَمْرَةَ الْعَقَبَةِ مِنْ بَطْنِ الْوَادِي ثُمَّ قَالَ هَا هُنَا وَالَّذِي لَا إِلَهَ غَيْرُهُ مَقَامُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","trj":"Telah mengabarkan kepada kami [Mujahid bin Musa] dari [Husyaim] dari [Mughirah] dari [Ibrahim], ia berkata; telah menceritakan kepada kami [Abdur Rahman bin Yazid], ia berkata; saya melihat [Ibnu Mas'ud] melempar Jumrah Aqabah, dari tengah bukit kemudian berkata; demi Dzat yang tidak ada tuhan yang berhak disembah selain-Nya, di sinilah tempat berdiri orang yang kepadanya diturunkan Surat Al Baqarah. "},{"p":"Nasa'i","n":2932,"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا ابْنُ أَبِي زَائِدَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ سَمِعْتُ الْحَجَّاجَ يَقُولُ لَا تَقُولُوا سُورَةَ الْبَقَرَةِ قُولُوا السُّورَةَ الَّتِي يُذْكَرُ فِيهَا الْبَقَرَةُ فَذَكَرْتُ ذَلِكَ لِإِبْرَاهِيمَ فَقَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَأَنَّهُ كَانَ مَعَ عَبْدِ اللَّهِ حِينَ رَمَى جَمْرَةَ الْعَقَبَةِ فَاسْتَبْطَنَ الْوَادِيَ وَاسْتَعْرَضَهَا يَعْنِي الْجَمْرَةَ فَرَمَاهَا بِسَبْعِ حَصَيَاتٍ وَكَبَّرَ مَعَ كُلِّ حَصَاةٍ فَقُلْتُ إِنَّ أُنَاسًا يَصْعَدُونَ الْجَبَلَ فَقَالَ هَا هُنَا وَالَّذِي لَا إِلَهَ غَيْرُهُ رَأَيْتُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ رَمَى","trj":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah memberitakan kepada kami [Ibnu Abi Zaidah], ia berkata; telah menceritakan kepada kami [Al A'masy], saya mendengar Al Hajjaj berkata; janganlah kalian mengatakan; surat Al Baqarah, katakanlah Surat yang disebutkan padanya sapi. Maka saya sebutkan hal tersebut kepada [Ibrahim], lalu ia berkata; telah mengabarkan kepadaku [Abdur Rahman bin Yazid] bahwa ia bersama [Abdullah] ketika melempar jumrah Aqabah, lalu ia berada ditengah bukit dan menghadap kepadanya yaitu jumrah, lalu melemparnya dengan tujuh kerikil, dan bertakbir bersamaan dengan setiap kerikil. Lalu saya katakan; sesungguhnya orang-orang menaiki gunung lalu ia berkata; demi Dzat yang tidak ada tuhan yang berhak disembah selain-Nya, di sinilah saya melihat orang yang diturunkan kepadanya Surat Al Baqarah melempar jumrah."},{"p":"Nasa'i","n":3350,"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ أَنْبَأَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ }وَقَالَ{ وَاللَّائِي يَئِسْنَ مِنْ الْمَحِيضِ مِنْ نِسَائِكُمْ إِنْ ارْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَاثَةُ أَشْهُرٍ }فَنُسِخَ مِنْ ذَلِكَ قَالَ تَعَالَى وَإِنْ{ طَلَّقْتُمُوهُنَّ مِنْ قَبْلِ أَنْ تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ali bin Al Husain bin Waqid] ia berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah memberitakan kepada kami [Yazid bin An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai ayat: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 101), dan firman Allah '(menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh (hapus) dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru') ', (Qs. Al Baqarah: 228). Dan firman: '(Dan perempuan-perempuan yang tidak haid lagi (monopause) di antara perempuan-perempuanmu jika kamu ragu-ragu (tentang masa iddahnya), Maka masa iddah mereka adalah tiga bulan) ' (Qs. Ath Thallaaq: 40), lalu dinasakh dari hal tersebut, firman Allah Ta'ala: '(Kemudian kamu ceraikan mereka sebelum kamu mencampurinya Maka sekali-sekali tidak wajib atas mereka 'iddah bagimu yang kamu minta menyempurnakannya) ' (Qs. Al Ahzaab: 49)."},{"p":"Nasa'i","n":3387,"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى السِّجْزِيُّ خَيَّاطُ السُّنَّةِ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ أَخْبَرَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ }نُسِخَ ذَلِكَ بِآيَةِ الْمِيرَاثِ مِمَّا فُرِضَ لَهَا مِنْ الرُّبُعِ وَالثُّمُنِ وَنَسَخَ أَجَلَ الْحَوْلِ أَنْ جُعِلَ أَجَلُهَا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya As Sijzi Khayyath As Sunnah] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah memberitakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(Dan orang-orang yang akan meninggal dunia di antara kamu dan meninggalkan isteri, hendaklah berwasiat untuk isteri-isterinya, (yaitu) diberi nafkah hingga setahun lamanya dan tidak disuruh pindah (dari rumahnya) ' (Qs. Al Baqarah: 240), telah dihapus dengan ayat mengenai ayat warisan di antara yang ditetapkan baginya dari seperempat dan seperdelapan, dan Allah juga menghapus masa 'iddah satu tahun dan dijadikan empat bulan sepuluh hari.\""},{"p":"Nasa'i","n":3388,"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ }قَالَ نَسَخَتْهَا{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا }","trj":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari ['Ikrimah] mengenai firman Allah 'azza wajalla: '(Dan orang-orang yang akan meninggal dunia di antara kamu dan meninggalkan isteri, hendaklah berwasiat untuk isteri-isterinya, (yaitu) diberi nafkah hingga setahun lamanya dan tidak disuruh pindah (dari rumahnya) ' (Qs. Al Baqarah: 240). 'Ikrimah berkata, \"Ayat tersebut dihapus oleh ayat: '(Orang-orang yang meninggal dunia di antaramu dengan meninggalkan isteri-isteri (hendaklah para isteri itu) menangguhkan dirinya (ber'iddah) empat bulan sepuluh hari) ' (Qs. Al Baqarah: 234)."},{"p":"Nasa'i","n":3398,"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ إِلَى قَوْلِهِ إِنْ أَرَادُوا إِصْلَاحًا }وَذَلِكَ بِأَنَّ الرَّجُلَ كَانَ إِذَا طَلَّقَ امْرَأَتَهُ فَهُوَ أَحَقُّ بِرَجْعَتِهَا وَإِنْ طَلَّقَهَا ثَلَاثًا فَنَسَخَ ذَلِكَ وَقَالَ{ الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ }","trj":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman Allah: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 1o1), dan firman Allah: '(Allah menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru'. Tidak boleh mereka menyembunyikan apa yang diciptakan Allah dalam rahimnya, jika mereka beriman kepada Allah dan hari akhirat. Dan suami-suaminya berhak merujukinya dalam masa menanti itu, jika mereka (para suami) menghendaki ishlah) ' (Qs. Al Baqarah: 228). Hal itu karena jika seorang laki-laki mencerai isterinya, maka ia lebih berhak untuk kembali kepadanya walaupun telah mencerainya tiga kali, kemudian Allah menghapus hal tersebut dan berfirman: '(Talak (yang dapat dirujuki) dua kali. Setelah itu boleh rujuk lagi dengan cara yang ma'ruf atau menceraikan dengan cara yang baik) ' (Qs. Al Baqarah: 229)."},{"p":"Nasa'i","n":3509,"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","trj":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."},{"p":"Nasa'i","n":3510,"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عِمْرَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ كَانَ يَكُونُ فِي حَجْرِ الرَّجُلِ الْيَتِيمُ فَيَعْزِلُ لَهُ طَعَامَهُ وَشَرَابَهُ وَآنِيَتَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَإِنْ تُخَالِطُوهُمْ فَإِخْوَانُكُمْ }فِي الدِّينِ فَأَحَلَّ لَهُمْ خُلْطَتَهُمْ","trj":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Imran bin 'Uyainah] berkata; telah menceritakan kepada kami ['Atha bin As Saib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] mengenaii firman Allah: '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ia berkata, \"Dahulu terdapat seorang anak yatim dalam pemeliharaan seorang laki-laki, kemudian laki-laki tersebut menjauhi makanan serta minuman dan bejananya, sehingga hal tersebut terasa berat bagi orang-orang muslim. Kemudian Allah 'azza wajalla menurunkan ayat: '(dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu) ' (Qs. Al Baqarah: 220), yaitu seagama, maka Allah pun menghalalkan bagi mereka untuk bergaul dengan mereka.\""},{"p":"Nasa'i","n":5180,"ar":"أَخْبَرَنَا أَبُو بَكْرٍ أَحْمَدُ بْنُ مُحَمَّدِ بْنِ إِسْحَقَ السُّنِّيُّ قِرَاءَةً عَلَيْهِ فِي بَيْتِهِ قَالَ أَنْبَأَنَا الْإِمَامُ أَبُو عَبْدِ الرَّحْمَنِ أَحْمَدُ بْنُ شُعَيْبٍ النَّسَائِيُّ رَحِمَهُ اللَّهُ تَعَالَى قَالَ أَنْبَأَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَكَانَ مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقَامَ الصَّلَاةَ نَادَى لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شَافِيًا فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْمَائِدَةِ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَلَمَّا بَلَغَ فَهَلْ أَنْتُمْ مُنْتَهُونَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ انْتَهَيْنَا انْتَهَيْنَا","trj":"Telah mengabarkan kepada kami Abu Bakr Ahmad bin Muhammad bin Ishaq As Sunni -dengan membaca dihadapannya di rumah miliknya- ia berkata; telah memberitakan kepada kami Imam Abu Abdurrahman Ahmad bin Syu'aib An Nasa`i rahimahullahu Ta'ala, ia berkata; telah memberitakan kepada kami [Abu Dawud] ia berkata; telah menceritakan kepada kami [Ubaidullah bin Musa] ia berkata; telah memberitakan kepada kami [Isra'il] dari [Abu Ishaq] dari [Abu Maisarah] dari [Umar radliallahu 'anhu] ia berkata; \"Ketika turun ayat yang mengharamkan khamer, Umar berdoa; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat Al Baqarah. Lalu Umar dipanggil dan ayat tersebut dibacakan kepadanya. Umar lalu berdoa lagi; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat An Nisa`: 'Hai orang-orang yang beriman, janganlah kamu shalat sedang kamu dalam keadaan mabuk…'. Jika waktu shalat tiba, penyeru Rasulullah shallallahu 'alaihi wasallam biasa menyerukan 'Janganlah kamu shalat, sedangkan kami dalam keadaan mabuk'. Lalu Umar dipanggil dan ayat tersebut dibacakan kepadanya. Setelah itu Umar berdoa lagi; \"Ya Allah, berilah penjelasan kepada kami tentang khamer dengan penjelasan yang memadahi!\" Maka turunlah ayat yang terdapat dalam surat Al Maidah. Umar pun dipanggil dan ayat tersebut dibacakan kepadanya, ketika sampai, Maka berhentilah kamu (dari mengerjakan pekerjaan itu, Lantas Umar radliallahu 'anhu berkata; \"Kami berhenti, kami berhenti!.\""},{"p":"Tirmidzi","n":514,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ فَأَطَالَ الْقِرَاءَةَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِرَاءَةَ هِيَ دُونَ الْأُولَى ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَسَجَدَ ثُمَّ فَعَلَ مِثْلَ ذَلِكَ فِي الرَّكْعَةِ الثَّانِيَةِقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهَذَا الْحَدِيثِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ يَرَوْنَ صَلَاةَ الْكُسُوفِ أَرْبَعَ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍ قَالَ الشَّافِعِيُّ يَقْرَأُ فِي الرَّكْعَةِ الْأُولَى بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ سُورَةِ الْبَقَرَةِ سِرًّا إِنْ كَانَ بِالنَّهَارِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ بِتَكْبِيرٍ وَثَبَتَ قَائِمًا كَمَا هُوَ وَقَرَأَ أَيْضًا بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ آلِ عِمْرَانَ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ سَجَدَ سَجْدَتَيْنِ تَامَّتَيْنِ وَيُقِيمُ فِي كُلِّ سَجْدَةٍ نَحْوًا مِمَّا أَقَامَ فِي رُكُوعِهِ ثُمَّ قَامَ فَقَرَأَ بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ سُورَةِ النِّسَاءِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ بِتَكْبِيرٍ وَثَبَتَ قَائِمًا ثُمَّ قَرَأَ نَحْوًا مِنْ سُورَةِ الْمَائِدَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ تَشَهَّدَ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] bahwa dia berkata, telah terjadi gerhana pada masa Rasulullah shallallahu 'alaihi wasallam, kemudian Rasulullah shallallahu 'alaihi wasallam shalat bersama manusia dengan memanjangkan bacaan shalat, beliau kemudian ruku' dan memanjangkan ruku'nya, lalu beliau mengangkat kepala dan memanjangkan bacaan shalat, namun tidak seperti (lebih singkat) dari yang pertama. Kemudian beliau ruku' dan memanjangkan ruku'nya namun tidak seperti yang pertama. Kemudian beliau mengangkat kepala lalu sujud, kemudian beliau melakukan seperti itu diraka'at kedua. Abu Isa berkata, ini adalah hadits hasan shahih, dengan hadits ini pula Syafi'i, Ahamad dan Ishaq berpendapat bahwa shalat gerhana itu empat kali ruku' dan empat kali sujud. Syafi'i berkata, pada raka'at pertama membaca surat Al Fatehah dan surat yang sepadan dengan surat Al Baqarah. Beliau membaca dengan suara pelan jika di siang hari (gerhana matahari), kemudian ruku' yang panjang seperti membaca bacaan, kemudian mengangkat kepala dengan mengucapkan takbir dan berdiri sebagaimana mestinya, kemudian membaca surat Al Fatihah lagi dan membaca surat yang sepadan dengan surat Ali Imran, lalu memanjangkan ruku'nya seperti ketika membaca bacaan. Kemudian mengangat kepala, lantas membaca sami'allahu liman hamidah, kemudian sujud dua kali dengan sempurna. Setiap sujud beliau berhenti sebagaimana berhenti ketika ruku', kemudian berdiri sambil membaca Al Fatehah dan surat yang sepadan dengan surat An Nisaa', kemudian memanjangan ruku' seperti membaca bacaan. Kemudian mengangkat kepala dengan mengucapkan takbir, lantas berdiri dengan membaca bacaan yang sepadan dengan surat Al Maidah, kemudian memanjangkan ruku'nya seperti ketika membaca bacaan. Kemudian mengangkat kepala dan membaca sami'allahu liman hamidah, kemudian sujud dua kali lalu membaca tahiyyat dan salam."},{"p":"Tirmidzi","n":595,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ مَدُّوَيْهِ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ عَنْ شَرِيكٍ عَنْ أَبِي حَمْزَةَ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ قَالَتْ سَأَلْتُ أَوْسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الزَّكَاةِ فَقَالَ إِنَّ فِي الْمَالِ لَحَقًّا سِوَى الزَّكَاةِ ثُمَّ تَلَا هَذِهِ الْآيَةَ الَّتِي فِي الْبَقَرَةِ{ لَيْسَ الْبِرَّ أَنْ تُوَلُّوا وُجُوهَكُمْ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Muhammad bin Ahmad bin Madduwaih] telah menceritakan kepada kami [Al Aswad bin 'Amir] dari [Syarik] dari [Abu Hamzah] dari [Asy Sya'bi] dari [Fathimah binti Qais] dia berkata, saya bertanya kepada Nabi Shalallahu 'alaihi wa salam tentang zakat, lalu beliau bersabda: \"Sesungguhnya pada harta ada kewajiban/hak (untuk dikeluarkan) selain zakat.\" Kemudian beliau membaca firman Allah Ta'ala yang terdapat dalam surat Al Baqarah: \"Bukanlah menghadapkan wajahmu ke arah timur dan barat itu suatu kebajikan…(ayat) \""},{"p":"Tirmidzi","n":825,"ar":"حَدَّثَنَا يُوسُفُ بْنُ عِيسَى حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ جَامِعِ بْنِ شَدَّادٍ أَبِي صَخْرَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَلَمَّا أَتَى عَبْدُ اللَّهِ جَمْرَةَ الْعَقَبَةِ اسْتَبْطَنَ الْوَادِيَ وَاسْتَقْبَلَ الْقِبْلَةَ وَجَعَلَ يَرْمِي الْجَمْرَةَ عَلَى حَاجِبِهِ الْأَيْمَنِ ثُمَّ رَمَى بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ ثُمَّ قَالَ وَاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ مِنْ هَاهُنَا رَمَى الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِحَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ الْمَسْعُودِيِّ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ وَفِي الْبَاب عَنْ الْفَضْلِ بْنِ عَبَّاسٍ وَابْنِ عَبَّاسٍ وَابْنِ عُمَرَ وجَابِرٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ مَسْعُودٍ حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ يَخْتَارُونَ أَنْ يَرْمِيَ الرَّجُلُ مِنْ بَطْنِ الْوَادِي بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ وَقَدْ رَخَّصَ بَعْضُ أَهْلِ الْعِلْمِ إِنْ لَمْ يُمْكِنْهُ أَنْ يَرْمِيَ مِنْ بَطْنِ الْوَادِي رَمَى مِنْ حَيْثُ قَدَرَ عَلَيْهِ وَإِنْ لَمْ يَكُنْ فِي بَطْنِ الْوَادِي","trj":"Telah menceritakan kepada kami [Yusuf bin Isa] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al Mas'udi] dari [Jami' bin Syaddad Abu Shahrah] dari [Abdurrahman bin Yazid] berkata; \"Setelah [Abdullah] sampai ke tempat Jumrah 'Aqabah, dia masuk ke dalam lembah lalu menghadap Ka'bah. Diapun mulai melempar jumrah di atas pelipis sebelah kanan, melempar tujuh butir kerikil dan bertakbir pada setiap kerikil. Lalu berkata; 'Demi Allah, yang tidak ada ilah selainNYA dari sinilah orang yang diturunkan padanya surat Al Baqarah melempar jumrah.\" Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Al Mas'udi] dengan sanad yang sama seperti hadits di atas. (Abu Isa At Tirmidzi) berkata; \"Hadits semakna diriwayatkan dari Al Fadl bin Abbas, Ibnu Abbas, Ibnu Umar dan Jabir.\" Abu 'Isa berkata; \"Hadits Ibnu mas'ud merupakan hadits hasan shahih serta diamalkan oleh para ulama. Mereka berpendapat; hendaknya seorang laki-laki melempar jumrah dari dasar Al Wadi dengan tujuh kerikil, seraya bertakbir pada setiap kerikil. Sebagian ulama membolehkan, jika tidak memungkinkan untuk melempar dari dasar Al Wadi, dengan melempar dari mana saja dia mampu walau tidak di dasar Al Wadi.\""},{"p":"Tirmidzi","n":1493,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ عَمِّهِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَى رَجُلَيْنِ مِنْ الْمُسْلِمِينَ بِرَجُلٍ مِنْ الْمُشْرِكِينَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَمُّ أَبِي قِلَابَةَ هُوَ أَبُو الْمُهَلَّبِ وَاسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو وَيُقَالُ مُعَاوِيَةُ بْنُ عَمْرٍو وَأَبُو قِلَابَةَ اسْمُهُ عَبْدُ اللَّهِ بْنُ زَيْدٍ الْجَرْمِيُّ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ أَنَّ لِلْإِمَامِ أَنْ يَمُنَّ عَلَى مَنْ شَاءَ مِنْ الْأُسَارَى وَيَقْتُلَ مَنْ شَاءَ مِنْهُمْ وَيَفْدِي مَنْ شَاءَ وَاخْتَارَ بَعْضُ أَهْلِ الْعِلْمِ الْقَتْلَ عَلَى الْفِدَاءِ و قَالَ الْأَوْزَاعِيُّ بَلَغَنِي أَنَّ هَذِهِ الْآيَةَ مَنْسُوخَةٌ قَوْلُهُ تَعَالَى{ فَإِمَّا مَنًّا بَعْدُ وَإِمَّا فِدَاءً }نَسَخَتْهَا{ وَاقْتُلُوهُمْ حَيْثُ ثَقِفْتُمُوهُمْ }حَدَّثَنَا بِذَلِكَ هَنَّادٌ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ الْأَوْزَاعِيِّ قَالَ إِسْحَقُ بْنُ مَنْصُورٍ قُلْتُ لِأَحْمَدَ إِذَا أُسِرَ الْأَسِيرُ يُقْتَلُ أَوْ يُفَادَى أَحَبُّ إِلَيْكَ قَالَ إِنْ قَدَرُوا أَنْ يُفَادُوا فَلَيْسَ بِهِ بَأْسٌ وَإِنْ قُتِلَ فَمَا أَعْلَمُ بِهِ بَأْسًا قَالَ إِسْحَقُ الْإِثْخَانُ أَحَبُّ إِلَيَّ إِلَّا أَنْ يَكُونَ مَعْرُوفًا فَأَطْمَعُ بِهِ الْكَثِيرَ","trj":"Telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Pamannya] dari [Imran bin Khushain] berkata, \"Nabi shallallahu 'alaihi wasallam menebus dua orang laki-laki muslim dengan seorang laki-laki kafir.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Paman Abu Qilabah adalah Abul Muhallab, dan nama aslinya adalah 'Abdurrahman bin Amru, atau sering dipanggil juga dengan nama Mu'awiyah bin Amru. Sedangkan Abu Qilabah namanya adalah Abdullah bin Zaid Al Jarmi. Kebanyakan ahli ilmu dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan selainnya beramal dengan hadits ini. Yaitu, seorang Imam (Khalifah) mempunyai hak untuk memberi pengampunan kepada siapa yang ia kehendaki dari orang-orang kafir yang tertawan, membunuhnya atau meminta tebusan. Tetapi sebagian ahli ilmu memilih untuk membunuh mereka daripada meminta tebusan. Al Auza'I berkata, \"Telah sampai kepadaku bahwa ayat ini: '(kamu boleh membebaskan mereka atau menerima tebusan..) -Qs. Muhammad: 4- telah dihapus oleh firman-Nya; '(Dan bunuhlah mereka di mana saja kamu jumpai mereka..) ' -Qs. Al Baqarah; 191- Seperti itulah Hannad menceritakan kepada kami, ia berkata; Ibnul Mubarak menceritakan kepada kami dari Al Auza'i. Ishaq bin Manshur berkata, \"Aku bertanya kepada Ahmad, \"Jika ada musuh yang tertawan, maka yang engkau sukai; dibunuh atau dibebaskan dengan tebusan?\" Ia menjawab, \"Jika mereka mampu memberi tebusan maka tidak apa-apa, dan jika dibunuh menurutku juga tidak apa-apa. Ishaq mengatakan; Musuh ditawan lebih aku sukai, "},{"p":"Tirmidzi","n":2734,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَطَاءٍ مَوْلَى أَبِي أَحْمَدَ عَنْ أَبِي هُرَيْرَةَ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْثًا وَهُمْ ذُو عَدَدٍ فَاسْتَقْرَأَهُمْ فَاسْتَقْرَأَ كُلَّ رَجُلٍ مِنْهُمْ مَا مَعَهُ مِنْ الْقُرْآنِ فَأَتَى عَلَى رَجُلٍ مِنْهُمْ مِنْ أَحْدَثِهِمْ سِنًّا فَقَالَ مَا مَعَكَ يَا فُلَانُ قَالَ مَعِي كَذَا وَكَذَا وَسُورَةُ الْبَقَرَةِ قَالَ أَمَعَكَ سُورَةُ الْبَقَرَةِ فَقَالَ نَعَمْ قَالَ فَاذْهَبْ فَأَنْتَ أَمِيرُهُمْ فَقَالَ رَجُلٌ مِنْ أَشْرَافِهِمْ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا مَنَعَنِي أَنْ أَتَعَلَّمَ سُورَةَ الْبَقَرَةِ إِلَّا خَشْيَةَ أَلَّا أَقُومَ بِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَلَّمُوا الْقُرْآنَ وَاقْرَءُوهُ فَإِنَّ مَثَلَ الْقُرْآنِ لِمَنْ تَعَلَّمَهُ فَقَرَأَهُ وَقَامَ بِهِ كَمَثَلِ جِرَابٍ مَحْشُوٍّ مِسْكًا يَفُوحُ رِيحُهُ فِي كُلِّ مَكَانٍ وَمَثَلُ مَنْ تَعَلَّمَهُ فَيَرْقُدُ وَهُوَ فِي جَوْفِهِ كَمَثَلِ جِرَابٍ وُكِئَ عَلَى مِسْكٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَاهُ اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَطَاءٍ مَوْلَى أَبِي أَحْمَدَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِي هُرَيْرَةَ حَدَّثَنَا قُتَيْبَةُ عَنْ اللَّيْثِ فَذَكَرَهُ","trj":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Hulwani] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Abdul Hamid bin Ja'far] dari [Sa'id Al Maqburi] dari [Atha`] bekas budak milik Abu Ahmad dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengutus rombongan para sahabat dalam jumlah banyak, beliau meminta kepada mereka untuk membaca, beliau meminta setiap orang dari mereka untuk membacakan apa yang dia hafal dari Al Qur`an, beliau datang kepada seseorang yang paling muda umurnya di antara mereka dan bertanya: \"Apa yang kamu hafal dari Al Qur`an wahai Fulan?\" dia menjawab; \"Saya hafal ini dan ini dan surat Al Baqarah, \" beliau bertanya: \"Apakah kamu hafal surat Al Baqarah?\" dia menjawab; \"Ya, \" beliau bersabda kepadanya: \"Pergilah dan kamu yang jadi imam bagi mereka, \" Seseorang yang paling terkemuka di antara mereka berkata; \"Demi Allah wahai Rasulullah, tidak ada yang menghalangiku untuk mempelajari surat Al Baqarah selain karena aku takut tidak dapat mengamalkannya, \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pelajarilah Al Qur`an dan bacalah, karena perumpamaan Al Qur`an bagi orang yang mempelajarinya kemudian membacanya seperti kantong yang penuh dengan minyak wangi, dimana wanginya semerbak ke setiap tempat, dan perumpamaan orang yang mempelajarinya kemudian tidur (tidak mengamalkannya) padahal Al Qur`an ada di hatinya seperti kantong yang berisi minyak wangi namun terikat.\" Abu Isa berkata; Hadits ini hasan, [Laits bin Sa'ad] telah meriwayatkannya dari [Sa'id Al Maqburi] dari [Atha`] budak milik Abu Ahmad, dari Nabi shallallahu 'alaihi wasallam secara mursal, dan di dalam hadits tersebut, tidak disebutkan dari Abu Hurairah. Telah menceritakan kepada kami [Qutaibah] dari [Laits] kemudian dia menyebutkan hadits."},{"p":"Tirmidzi","n":2735,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَجْعَلُوا بُيُوتَكُمْ مَقَابِرَ وَإِنَّ الْبَيْتَ الَّذِي تُقْرَأُ فِيهِ الْبَقَرَةُ لَا يَدْخُلُهُ الشَّيْطَانُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menjadikan rumah-rumah kalian seperti kuburan, sesungguhnya syetan tidak memasuki rumah yang dibacakan didalamnya surat Al Baqarah.\" Abu Isa berkata; Hadits ini hasan shahih."},{"p":"Tirmidzi","n":2736,"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا حُسَيْنٌ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ حَكِيمِ بْنِ جُبَيْرٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِكُلِّ شَيْءٍ سَنَامٌ وَإِنَّ سَنَامَ الْقُرْآنِ سُورَةُ الْبَقَرَةِ وَفِيهَا آيَةٌ هِيَ سَيِّدَةُ آيِ الْقُرْآنِ هِيَ آيَةُ الْكُرْسِيِّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ حَكِيمِ بْنِ جُبَيْرٍ وَقَدْ تَكَلَّمَ شُعْبَةُ فِي حَكِيمِ بْنِ جُبَيْرٍ وَضَعَّفَهُ","trj":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Husain Al Ju'fi] dari [Za`idah] dari [Hakim bin Jubair] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap sesuatu memiliki puncak, dan puncaknya Al Qur`an adalah surat Al Baqarah, di dalamnya terdapat ayat yang merupakan tuannya ayat-ayat dalam Al Qur`an yaitu ayat kursi.\" Abu Isa berkata; Hadits ini gharib, kami tidak mengetahuinya kecuali dari hadits Hakim bin Jubair, sementara Syu'bah mempermasalahkan tentang Hakim bin Jubair dan melemahkannya.\""},{"p":"Tirmidzi","n":2739,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ مَنْصُورِ بْنِ الْمُعْتَمِرِ عَنْ إِبْرَاهِيمَ بْنِ يَزِيدَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ الْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari [Mandhur bin Al Mu'tamir] dari [Ibrahim bin Yazid] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud Al Anshari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membaca dua ayat terakhir dari surat Al Baqarah pada malam hari, maka keduanya akan mencukupinya.\" Abu Isa berkata; Hadits ini hasan shahih."},{"p":"Tirmidzi","n":2740,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَشْعَثَ بْنِ عَبْدِ الرَّحْمَنِ الْجَرْمِيِّ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ الْجَرْمِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ كَتَبَ كِتَابًا قَبْلَ أَنْ يَخْلُقَ السَّمَوَاتِ وَالْأَرْضَ بِأَلْفَيْ عَامٍ أَنْزَلَ مِنْهُ آيَتَيْنِ خَتَمَ بِهِمَا سُورَةَ الْبَقَرَةِ وَلَا يُقْرَأَانِ فِي دَارٍ ثَلَاثَ لَيَالٍ فَيَقْرَ��ُهَا شَيْطَانٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","trj":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Asy'ats bin Abdurrahman Al Jarmi] dari [Abu Qilabah] dari [Abu Al Asy'ats Al Jarmi] dari [Nu'man bin Basyir] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya Allah telah menulis kitab (Al Qur`an) sejak dua ribu tahun sebelum menciptakan langit dan bumi, Allah menurunkan dua ayat darinya sebagai penutup surat Al Baqarah, tidaklah keduanya dibaca dalam rumah selama tiga malam setan akan mendekatinya.\" Abu Isa berkata; Hadits ini hasan gharib."},{"p":"Tirmidzi","n":2741,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ أَخْبَرَنَا هِشَامُ بْنُ إِسْمَعِيلَ أَبُو عَبْدِ الْمَلِكِ الْعَطَّارِ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سُلَيْمَانَ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ حَدَّثَهُمْ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ نَوَّاسِ بْنِ سَمْعَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَأْتِي الْقُرْآنُ وَأَهْلُهُ الَّذِينَ يَعْمَلُونَ بِهِ فِي الدُّنْيَا تَقْدُمُهُ سُورَةُ الْبَقَرَةِ وَآلُ عِمْرَانَ قَالَ نَوَّاسٌ وَضَرَبَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَمْثَالٍ مَا نَسِيتُهُنَّ بَعْدُ قَالَ تَأْتِيَانِ كَأَنَّهُمَا غَيَابَتَانِ وَبَيْنَهُمَا شَرْقٌ أَوْ كَأَنَّهُمَا غَمَامَتَانِ سَوْدَاوَانِ أَوْ كَأَنَّهُمَا ظُلَّةٌ مِنْ طَيْرٍ صَوَافَّ تُجَادِلَانِ عَنْ صَاحِبِهِمَاوَفِي الْبَاب عَنْ بُرَيْدَةَ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَمَعْنَى هَذَا الْحَدِيثِ عِنْدَ أَهْلِ الْعِلْمِ أَنَّهُ يَجِيءُ ثَوَابُ قِرَاءَتِهِ كَذَا فَسَّرَ بَعْضُ أَهْلِ الْعِلْمِ هَذَا الْحَدِيثَ وَمَا يُشْبِهُ هَذَا مِنْ الْأَحَادِيثِ أَنَّهُ يَجِيءُ ثَوَابُ قِرَاءَةِ الْقُرْآنِ وَفِي حَدِيثِ النَّوَّاسِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَدُلُّ عَلَى مَا فَسَّرُوا إِذْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ الَّذِينَ يَعْمَلُونَ بِهِ فِي الدُّنْيَا فَفِي هَذَا دَلَالَةٌ أَنَّهُ يَجِيءُ ثَوَابُ الْعَمَلِ","trj":"Telah menceritakan kepada kami [Muhammad bin Isma'il] telah menceritakan kepada kami [Hisyam bin Isma'il Abu Abdul Malik Al Athar] telah mengabarkan kepada kami [Muhammad bin Syu'aib] telah menceritakan kepada kami [Ibrahim bin Sulaiman] dari [Al Walid bin Abdurrahman] dari [Jubair bin Nufair] dari [Nawwas bin Sam'an] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Al Qur`an akan datang pada hari Qiyamat bersama pemiliknya yang mengamalkannya di dunia, didahului oleh surat Al Baqarah dan Ali Imran, \" Nawwas berkata; Rasulullah shallallahu 'alaihi wasallam membuat perumpamaan untuk keduanya (surat Al Baqarah dan Ali Imran) dengan tiga perumpamaan yang aku tidak akan melupakan selamanya, beliau bersabda: \"Keduanya akan datang seperti dua awan, yang di antara keduanya ada cahaya, atau keduanya seperti dua awan tebal, atau keduanya seperti sekawanan burung yang membentangkan sayapnya, lalu keduanya berhujah untuk pemiliknya.\" Dan dalam bab ini, ada hadits dari Buraidah dan Abu Umamah. Abu Isa berkata; Dari jalur ini, hadits ini gharib, adapun makna hadits ini menurut ahli ilmu adalah akan datang pahala membacanya seperti ini, sebagian ahli ilmu menafsirkan hadits ini dan yang hadits serupa bahwa pahala membaca Al Qur`an akan datang, dan dalam hadits An Nawwas dari Nabi shallallahu 'alaihi wasallam ada dalil yang menunjukkan atas apa yang mereka tafsirkan, dimana Nabi shallallahu 'alaihi wasallam bersabda: \"Dan para pemiliknya yang mengamalkannya di dunia.\" Hadits ini menunjukkan pahala amal akan datang."},{"p":"Tirmidzi","n":2811,"ar":"وَبِهَذَا الْإِسْنَادِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ فَبَدَّلَ الَّذِينَ ظَلَمُوا قَوْلًا غَيْرَ الَّذِي قِيلَ لَهُمْ }قَالَ قَالُوا حَبَّةٌ فِي شَعْرَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Dan dengan sanad ini (Yaitu; Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah]) dari Nabi shallallahu 'alaihi wasallam: \"Lalu orang-orang yang zhalim mengganti perintah dengan (mengerjakan) yang tidak diperintahkan kepada mereka.\" QS Al-Baqarah: 59, Beliau bersabda: \"Mereka berkata; biji dalam rambut.\" Abu Isa berkata; Hadits ini hasan shahih."},{"p":"Tirmidzi","n":2812,"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَشْعَثُ السَّمَّانُ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ أَبِيهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فِي لَيْلَةٍ مُظْلِمَةٍ فَلَمْ نَدْرِ أَيْنَ الْقِبْلَةُ فَصَلَّى كُلُّ رَجُلٍ مِنَّا عَلَى حِيَالِهِ فَلَمَّا أَصْبَحْنَا ذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَشْعَثَ السَّمَّانِ أَبِي الرَّبِيعِ عَنْ عَاصِمِ بْنِ عُبَيْدِ اللَّهِ وَأَشْعَثُ يُضَعَّفُ فِي الْحَدِيثِ","trj":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Asy'ats As Samman] dari ['Ashim bin 'Ubaidullah] dari [Abdullah bin 'Amir bin Rabi'ah] dari [Ayahnya] ia berkata; Kami bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan di malam yang gelap, kami tidak tahu mana kiblat, masing-masing dari kami shalat menghadap sesuai arahnya. Di pagi harinya, kami menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, lalu turunlah ayat: \"Maka kemanapun kamu menghadap di situlah wajah Allah.\" QS Al-Baqarah: 115"},{"p":"Tirmidzi","n":2813,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ قَال سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ تَطَوُّعًا أَيْنَمَا تَوَجَّهَتْ بِهِ وَهُوَ جَاءٍ مِنْ مَكَّةَ إِلَى الْمَدِينَةِثُمَّ قَرَأَ ابْنُ عُمَرَ هَذِهِ الْآيَةَ{ وَلِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ }الْآيَةَ فَقَالَ ابْنُ عُمَرَ فَفِي هَذَا أُنْزِلَتْ هَذِهِ الْآيَةُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى عَنْ قَتَادَةَ أَنَّهُ قَالَ فِي هَذِهِ الْآيَةِ{ وَلِلَّهِ الْمَشْرِقُ وَالْمَغْرِبُ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ قَتَادَةُ هِيَ مَنْسُوخَةٌ نَسَخَهَا قَوْلُهُ{ فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }أَيْ تِلْقَاءَهُ حَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ وَيُرْوَى عَنْ مُجَاهِدٍ فِي هَذِهِ الْآيَةِ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }قَالَ فَثَمَّ قِبْلَةُ اللَّهِ حَدَّثَنَا بِذَلِكَ أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ النَّضْرِ بْنِ عَرَبِيٍّ عَنْ مُجَاهِدٍ بِهَذَا","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Abdul Malik bin Abu Sulaiman] ia berkata; Aku mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Umar] ia berkata; Nabi shallallahu 'alaihi wasallam pernah shalat sunnah di atas kendaraan beliau kemana pun kendaraan beliau menghadap, ketika itu beliau pergi dari Makkah menuju Madinah. Setelah itu Ibnu Umar membaca ayat ini: \"Dan kepunyaan Allah-lah timur dan barat.\" QS Al-Baqarah: 115. Ibnu Umar berkata; \"Berkenaan dengan peristiwa itulah, ayat ini turun.\" Abu Isa berkata; Hadits ini hasan shahih. Diriwayatkan dari Qatadah, ia berkata tentang ayat ini: Dan kepunyaan Allah-lah timur dan barat, maka kemanapun kamu menghadap di situlah wajah Allah.\" QS Al-Baqarah: 115 Qatadah berkata; Ayat ini mansukhah, dinasakh dengan firman Allah, \"Palingkanlah mukamu ke arah Masjidil Haram.\" QS Al-Baqarah: 144 yaitu arahnya. Telah menceritakan kepada kami yang demikian itu Muhammad bin Abdul Malik bin Abu Asy Syawarib, telah menceritakan kepada kami Yazid bin Zurai' dari Sa'id dari Qatadah. Dan diriwayatkan pula dari Mujahid tentang ayat ini: \"Maka kemanapun kamu menghadap, di situlah wajah Allah.\" QS Al-Baqarah: 115, ia berkata; \"Di sanalah kiblat Allah.\" Telah menceritakan kepada kami seperti itu Muhammad bin Al Ala` telah menceritakan kepada kami Waki' dari An Nadlr bin Arabi dari Mujahid seperti itu."},{"p":"Tirmidzi","n":2814,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُقُلْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ اتَّخَذْتَ مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى فَنَزَلَتْ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Humaid Ath Thawil] dari [Anas] ia berkata; [Umar bin Al Khaththab] radliallahu 'anhu berkata; Aku berkata kepada Rasulullah shallallahu 'alaihi wasallam; \"Andai anda menjadikan sebagaian maqam untuk tempat shalat.\" Kemudian turunlah ayat: \"Dan jadikanlah sebahagian maqam Ibrahim tempat shalat.\" QS Al-Baqarah: 125. Abu Isa berkata; Hadits ini hasan shahih. Dalam hal ini, ada hadits serupa dari Ibnu Umar."},{"p":"Tirmidzi","n":2815,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ{ وَكَذَلِكَ جَعَلْنَاكُمْ أُمَّةً وَسَطًا }قَالَ عَدْلًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abu Muawiyah] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam tentang firman Allah: \"Dan demikian (pula) Kami telah menjadikan kamu (umat Islam), umat yang adil dan pilihan agar kamu menjadi saksi atas (perbuatan) manusia.\" QS Al-Baqarah: 143, beliau bersabda: \"Adil.\" Abu Isa berkata; Hadits ini hasan shahih."},{"p":"Tirmidzi","n":2816,"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ صَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ أَوْ سَبْعَةَ عَشَرَ شَهْرًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ أَنْ يُوَجَّهَ إِلَى الْكَعْبَةِ فَأَنْزَلَ اللَّهُ{ قَدْ نَرَى تَقَلُّبَ وَجْهِكَ فِي السَّمَاءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَاهَا فَوَلِّ وَجْهَكَ شَطْرَ الْمَسْجِدِ الْحَرَامِ }فَوُجِّهَ نَحْوَ الْكَعْبَةِ وَكَانَ يُحِبُّ ذَلِكَ فَصَلَّى رَجُلٌ مَعَهُ الْعَصْرَ قَالَ ثُمَّ مَرَّ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ وَهُمْ رُكُوعٌ فِي صَلَاةِ الْعَصْرِ نَحْوَ بَيْتِ الْمَقْدِسِ فَقَالَ هُوَ يَشْهَدُ أَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ قَدْ وُجِّهَ إِلَى الْكَعْبَةِ قَالَ فَانْحَرَفُوا وَهُمْ رُكُوعٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ","trj":"Telah menceritakan kepada kami [Hannad] telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari [Al Bara` bin Azib] ia berkata; \"Setibanya Rasulullah shallallahu 'alaihi wasallam di Madinah, beliau shalat menghadap ke Baitul Maqdis selama enam belas atau tujuh belas bulan, namun Rasulullah shallallahu 'alaihi wasallam ingin menghadap ka'bah, maka Allah menurunkan ayat: \"Sungguh Kami (sering) melihat mukamu menengadah ke langit, maka sungguh kami akan memalingkan kamu ke kiblat yang kamu sukai. Palingkanlah mukamu ke arah Masjidil Haram.\" QS Al-Baqarah: 144. Kemudian beliau menghadapkan mukanya ke arah Ka'bah, dan beliau sangat menyukainya, lalu seseorang shalat ashar bersama beliau. Setelah itu ia melintasi suatu kaum dari sahabat Anshar, mereka tengah ruku' dalam shalat ashar sambil menghadap Baitul Maqdis.\" Barra` berkata; Sahabat tersebut bersaksi bahwa ia pernah shalat ashar bersama Rasulullah shallallahu 'alaihi wasallam dan beliau telah dihadapkan ke Ka'bah. Barra` berkata; \"Mereka pun mengalihkan wajahnya dalam keadaan ruku'.\" Abu Isa berkata; Hadits ini hasan shahih. [Sufyan Ats Tsauri] juga meriwayatkannya dari [Abu Ishaq]."},{"p":"Tirmidzi","n":2818,"ar":"حَدَّثَنَا هَنَّادٌ وَأَبُو عَمَّارٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا وُجِّهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْكَعْبَةِ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ بِإِخْوَانِنَا الَّذِينَ مَاتُوا وَهُمْ يُصَلُّونَ إِلَى بَيْتِ الْمَقْدِسِ فَأَنْزَلَ اللَّهُ تَعَالَى{ وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ }الْآيَةَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Hannad] dan [Abu 'Ammar] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Isra'il] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; \"Saat Nabi shallallahu 'alaihi wasallam dialihkan ke arah Ka'bah, orang-orang berkata; \"Wahai Rasulullah, bagaimana dengan saudara-saudara kami yang telah meninggal, sementara mereka shalat menghadap Baitul Maqdis?\" Maka turunlah ayat: \"Dan Allah tidaklah menyia-nyiakan keimananmu.\" QS Al-Baqarah: 143. Abu Isa berkata; Hadits ini hasan shahih."},{"p":"Tirmidzi","n":2819,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ عَنْ سُفْيَانَ عَنْ عَاصِمٍ الْأَحْوَلِ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ عَنْ الصَّفَا وَالْمَرْوَةِ فَقَالَكَانَا مِنْ شَعَائِرِ الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ أَمْسَكْنَا عَنْهُمَا فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }قَالَ هُمَا تَطَوُّعٌ{ وَمَنْ تَطَوَّعَ خَيْرًا فَإِنَّ اللَّهَ شَاكِرٌ عَلِيمٌ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Yazid bin Abu Hakim] dari [Sufyan] dari ['Ashim Al Ahwal] ia berkata; Aku bertanya kepada [Anas bin Malik] tentang Shafa dan Marwah, ia menjawab: \"Keduanya termasuk syi'ar jahiliyah. Saat Islam datang, kami menahan diri dari keduanya, namun Allah Tabaraka wa Ta'ala menurunkan ayat: \"Sesungguhnya Shafaa dan Marwa adalah sebahagian dari syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'i antara keduanya.\" QS Al-Baqarah: 158, ia berkata; \"Keduanya sunnah.\"Dan barangsiapa yang mengerjakan suatu kebajikan dengan kerelaan hati, maka Sesungguhnya Allah Maha mensyukuri kebaikan lagi Maha Mengetahui.\" Abu Isa berkata; Hadits ini hasan shahih."},{"p":"Tirmidzi","n":2822,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }أَوْ{ مَنْ ذَا الَّذِي يُقْرِضُ اللَّهَ قَرْضًا حَسَنًا }قَالَ أَبُو طَلْحَةَ وَكَانَ لَهُ حَائِطٌ فَقَالَ يَا رَسُولَ اللَّهِ حَائِطِي لِلَّهِ وَلَوْ اسْتَطَعْتُ أَنْ أُسِرَّهُ لَمْ أُعْلِنْهُ فَقَالَ اجْعَلْهُ فِي قَرَابَتِكَ أَوْ أَقْرَبِيكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكِ","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdullah bin Bakr As Sahmani] telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata; \"Ketika turun ayat Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebahagian harta yang kamu cintai.\" QS Ali 'Imran: 92 atau Siapakah yang mau memberi pinjaman kepada Allah, pinjaman yang baik (menafkahkan hartanya di jalan Allah). QS Al-Baqarah: 245, kemudian Abu Thalhah, yang memiliki kebun berkata; \"Wahai Rasulullah, saya (infakkan) kebun saya ini di jalan Allah. Dan sekiranya saya mampu untuk menyembunyikannya tentu saya tidak menyatakannya. lalu beliau mengatakan \"Berikanlah kepada kerabat atau orang yang terdekat denganmu!\" Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan [Malik bin Anas] telah meriwayatkan dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] "},{"p":"Tirmidzi","n":2845,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ أَبِي مَيْسَرَةَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَاللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ }الْآيَةَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ ثُمَّ قَالَ اللَّهُمَّ بَيِّنَ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَنَزَلَتْ الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ إِلَى قَوْلِهِ فَهَلْ أَنْتُمْ مُنْتَهُونَ }فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ انْتَهَيْنَا انْتَهَيْنَاقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ إِسْرَائِيلَ هَذَا الْحَدِيثُ مُرْسَلٌ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي مَيْسَرَةَ عَمْرِو بْنِ شُرَحْبِيلَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانَ شِفَاءٍ فَذَكَرَ نَحْوَهُ وَهَذَا أَصَحُّ مِنْ حَدِيثِ مُحَمَّدِ بْنِ يُوسُفَ","trj":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] telah mengabarkan kepada kami [Muhammad bin Yusuf] telah mengabarkan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari ['Amru bin Syurahbil Abu Maisarah] dari [Umar bin Al Khaththab] ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Baqarah; Mereka bertanya kepadamu tentang khamer dan judi. QS Al Baqarah: 219, lalu Umar dipanggil dan dibacakan kepadanya. Setelah itu ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat An Nisa` Hai orang-orang yang beriman, janganlah kamu mendekati shalat sedang kamu mabuk QS An Nisa`: 43. Selanjutnya ia berdoa; \"Ya Allah, berilah kami penjelasan tentang khamer dengan penjelasan yang memadai.\" Lalu turunlah ayat yang ada dalam surat Al Mai`idah Sesungguhnya syaitan itu bermaksud hendak menimbulkan permusuhan dan kebencian di antara kamu lantaran (meminum) khamar dan berjudi itu, -sampai firmanNya- maka berhentilah kamu (dari mengerjakan pekerjaan itu) QS Al Ma`idah: 91. Umar lalu berkata; \"Kami berhenti, kami berhenti.\" Abu Isa berkata; Hadits ini juga diriwayatkan dari Isra`il secara mursal. Telah menceritakan kepada kami [Muhammad bin Al Ala`] telah menceritakan kepada kami [Waki'] dari [Isra`il] dari [Abu Ishaq] dari [Abu Maisarah 'Amru bin Syurahbil] bahwa [Umar bin Al Khaththab] berkata; \"Ya Allah, Ya Allah, berilah kami penjelasan tentang khamar dengan penjelasan yang memadai.\" Lalu ia menyebutkan seperti di atas, namun hadits ini lebih shahih dari hadits Muhammad bin Yusuf."},{"p":"Tirmidzi","n":3027,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مُرَّةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا بَلَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِدْرَةَ الْمُنْتَهَى قَالَ انْتَهَى إِلَيْهَا مَا يَعْرُجُ مِنْ الْأَرْضِ وَمَا يَنْزِلُ مِنْ فَوْقٍ قَالَ فَأَعْطَاهُ اللَّهُ عِنْدَهَا ثَلَاثًا لَمْ يُعْطِهِنَّ نَبِيًّا كَانَ قَبْلَهُ فُرِضَتْ عَلَيْهِ الصَّلَاةُ خَمْسًا وَأُعْطِيَ خَوَاتِيمَ سُورَةِ الْبَقَرَةِ وَغُفِرَ لِأُمَّتِهِ الْمُقْحِمَاتُ مَا لَمْ يُشْرِكُوا بِاللَّهِ شَيْئًاقَالَ ابْنُ مَسْعُودٍ{ إِذْ يَغْشَى السِّدْرَةَ مَا يَغْشَى }قَالَ السِّدْرَةُ فِي السَّمَاءِ السَّادِسَةِ قَالَ سُفْيَانُ فَرَاشٌ مِنْ ذَهَبٍ وَأَشَارَ سُفْيَانُ بِيَدِهِ فَأَرْعَدَهَا و قَالَ غَيْرُ مَالِكِ بْنِ مِغْوَلٍ إِلَيْهَا يَنْتَهِي عِلْمُ الْخَلْقِ لَا عِلْمَ لَهُمْ بِمَا فَوْقَ ذَلِكَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ibnu Abi Umar] telah menceritakan kepada kami [Sufyan] dari [Malik bin Mighwal] dari [Thalhah bin Musharrif] dari [Murrah] dari [Abdullah] berkata: Saat Rasulullah Shallallahu 'alaihi wa Salam sampai Shidratul Muntaha, beliau bersabda: \"Kesanalah berakhirnya sesuatu yang naik dari bumi dan yang turun dari atas.\" Lalu Allah memberi beliau tiga hal disana yang belum pernah diberikan kepada seorang nabi pun sebelum beliau; shalat lima waktu diwajibkan atas beliau, beiau diberi penutup-penutup surat al Baqarah dan dosa-dosa besar diampuni untuk ummatnya selama tidak menyekutukan Allah dengan sesuatu pun.\" Ibnu Mas'ud berkata: \"Ketika Sidratil Muntaha diliputi oleh sesuatu yang meliputinya.\" (An Najm: 16) ia berkata: Sidrah berada dilangit keenam. Sufyan berkata: Hamparan dari emas. Ia berisyarat dengan tangannya lalu menggoyang-goyangnya. Selain Malik bin Mighwal berkata: Disanalah berakhirnya ilmu makhluk, mereka tidak mengetahui apa yang ada diatasnya. Abu Isa berkata: Hadits ini hasan shahih."},{"p":"Tirmidzi","n":3224,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ الْقَدَّاحِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ آلِ عِمْرَانَ{ الم اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidullah bin Abu Ziyad Al Qaddah] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Nama Allah Allah yang paling agung ada dalam kedua ayat ini, yaitu: \"Dan Tuhanmu adalah Tuhan Yang Maha Esa; tidak ada Tuhan melainkan Dia Yang Maha Pemurah lagi Maha Penyayang\", (QS. Albaqarah 163) dan permulaan Surat Ali Imran; \"Alif laam miim. Allah, tidak ada Tuhan (yang berhak disembah) melainkan Dia. Yang hidup kekal lagi terus menerus mengurus makhluk-Nya.\" (QS.Ali Imran 1-2), Abu Isa berkata; hadits ini adalah hadits hasan shahih."},{"p":"Tirmidzi","n":3313,"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ أَنَا عِنْدَ ظَنِّ عَبْدِي بِي وَأَنَا مَعَهُ حِينَ يَذْكُرُنِي فَإِنْ ذَكَرَنِي فِي نَفْسِهِ ذَكَرْتُهُ فِي نَفْسِي وَإِنْ ذَكَرَنِي فِي مَلَإٍ ذَكَرْتُهُ فِي مَلَإٍ خَيْرٍ مِنْهُمْ وَإِنْ اقْتَرَبَ إِلَيَّ شِبْرًا اقْتَرَبْتُ مِنْهُ ذِرَاعًا وَإِنْ اقْتَرَبَ إِلَيَّ ذِرَاعًا اقْتَرَبْتُ إِلَيْهِ بَاعًا وَإِنْ أَتَانِي يَمْشِي أَتَيْتُهُ هَرْوَلَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى عَنْ الْأَعْمَشِ فِي تَفْسِيرِ هَذَا الْحَدِيثِ مَنْ تَقَرَّبَ مِنِّي شِبْرًا تَقَرَّبْتُ مِنْهُ ذِرَاعًا يَعْنِي بِالْمَغْفِرَةِ وَالرَّحْمَةِ وَهَكَذَا فَسَّرَ بَعْضُ أَهْلِ الْعِلْمِ هَذَا الْحَدِيثَ قَالُوا إِنَّمَا مَعْنَاهُ يَقُولُ إِذَا تَقَرَّبَ إِلَيَّ الْعَبْدُ بِطَاعَتِي وَمَا أَمَرْتُ أُسْرِعُ إِلَيْهِ بِمَغْفِرَتِي وَرَحْمَتِي وَرُوِيَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَنَّهُ قَالَ فِي هَذِهِ الْآيَةِ{ فَاذْكُرُونِي أَذْكُرْكُمْ }قَالَ اذْكُرُونِي بِطَاعَتِي أَذْكُرْكُمْ بِمَغْفِرَتِي حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى وَعَمْرُو بْنُ هَاشِمٍ الرَّمْلِيُّ عَنْ ابْنِ لَهِيعَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ بِهَذَا","trj":"Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Ibnu Numair] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman; Aku bersama dengan persangkaan hamba-Ku kepada-Ku, dan Aku akan bersamanya selama ia berdzikir (berdoa) kepada-Ku. Jika ia mengingat-Ku dalam dirinya maka Aku akan mengingatnya dalam diri-Ku, jika ia mengingat-Ku dalam sekumpulan orang maka Aku akan mengingatnya dalam sekumpulan yang lebih baik dan lebih bagus dari mereka. Jika ia mendekat kepada-Ku satu jengkal maka Aku akan mendekat kepadanya satu hasta, jika ia mendekat kepada-Ku satu hasta maka Aku akan mendekat kepadanya satu depa, dan jika ia mendatangi-Ku dengan berjalan maka Aku akan mendatanginya dengan berlari.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih, dan telah di riwayatkan pula dari Al A'masy mengenai tafsir hadits ini, yaitu; \"Barang siapa mendekat kepada-Ku sejengkal, maka Aku akan mendekat kepadanya sehasta.\" Maknanya dengan ampunan dan rahmat. Seperti inilah sebagian ulama menafsiri hadits ini, mereka mengatakan; hanyasanya maknanya adalah, Allah berfirman \"Apabila hamba-Ku mendekat kepada-Ku dengan keta'atan kepada-Ku, dan apa yang Aku perintahkan, maka Aku akan bersegera kepadanya dengan ampunan-Ku dan rahmat-Ku.\" Dan diriwayatkan dari Said bin Jubair bahwa dia berkata tentang ayat ini; \"Karena itu, ingatlah kamu kepada-Ku niscaya Aku ingat (pula) kepadamu.\" (QS Al Baqarah; 152) katanya; \"Ingatlah kepada-Ku dengan keta'atan kepada-Ku, maka Aku akan mengingatmu dengan ampunan-Ku.\" Telah menceritakan kepada kami Abd bin Humaid dia berkata; telah menceritakan kepada kami Al Hasan bin Musa dan 'Amru bin Hasyim Ar Ramli dari Ibnu Lahi'ah dari 'Atha` bin Yasar dari Sa'id bin Jubair dengan hadits ini.\""}]};
